# Safe print wrapper: write UTF-8 bytes to the underlying buffer when possible
import builtins
_orig_print = builtins.print
def _safe_print(*args, sep=' ', end='\n', file=None, flush=False):
    try:
        text = sep.join(map(str, args)) + end
        out = file if file is not None else sys.stdout
        buf = getattr(out, 'buffer', None)
        if buf is not None:
            try:
                buf.write(text.encode('utf-8', errors='replace'))
                if flush:
                    buf.flush()
                return
            except Exception:
                pass
        # Fallback to original print
        _orig_print(*args, sep=sep, end=end, file=out, flush=flush)
    except Exception:
        try:
            _orig_print(*args, sep=sep, end=end, file=file if file is not None else sys.stdout, flush=flush)
        except Exception:
            pass

builtins.print = _safe_print

