def _handle_sigint(sig, frame):
    try:
        print("[SIGNAL] SIGINT received — requesting graceful shutdown...")
    except Exception:
        pass
    stop_event.set()
    try:
        # After setting our stop flag, let Python raise KeyboardInterrupt
        # so existing `except KeyboardInterrupt:` handlers still run.
        py_signal.default_int_handler(sig, frame)
    except Exception:
        # If re-raising the default handler fails for any reason,
        # just continue with the stop_event set.
        pass

# Register SIGINT handler so Ctrl+C sets `stop_event`
try:
    py_signal.signal(py_signal.SIGINT, _handle_sigint)
except Exception:
    # Some environments may not support signal registration
    pass

    # NOTE: Many type errors in this file are due to type annotations and do not affect runtime.
