# Sleep helper that wakes frequently to check `stop_event` so Ctrl+C is respected
def interruptible_sleep(seconds, step=0.5):
    """Sleep in small increments and abort early if `stop_event` is set.
    - `seconds`: total time to sleep
    - `step`: check interval in seconds (default 0.5s)
    - Resets stop_event after sleep so Ctrl+C just skips current cycle, not exits
    """
    try:
        if seconds is None or seconds <= 0:
            return
        waited = 0.0
        was_interrupted = False
        while waited < float(seconds):
            if stop_event.is_set():
                was_interrupted = True
                break
            to_sleep = min(step, float(seconds) - waited)
            pytime.sleep(to_sleep)
            waited += to_sleep
        
        # If interrupted by Ctrl+C, reset the event so loop continues (not exits)
        if was_interrupted:
            stop_event.clear()
            print("[SLEEP] Ctrl+C detected: Skipping sleep, continuing to next cycle...")
    except Exception:
        # Best-effort; on any error, fall back to a normal sleep
        try:
            pytime.sleep(seconds)
        except Exception:
            pass

# Backwards-compatibility alias: some older files call `sleep_interruptible`
def sleep_interruptible(seconds, step=0.5):
    """Compatibility wrapper for older code that used `sleep_interruptible`.
    Delegates to `interruptible_sleep` which respects `stop_event`.
    """
    return interruptible_sleep(seconds, step=step)

