# 🔒 CRITICAL SAFETY: Direction Normalizer
# ============================================================================
def normalize_direction(d):
    """
    Convert all direction formats to canonical "buy" or "sell".
    Prevents silent bugs from direction name mismatches.
    """
    if d is None:
        raise ValueError("Direction cannot be None")
    
    d = str(d).lower().strip()
    
    # Normalize to "buy"
    if d in ("bullish", "buy", "long", "up", "uptrend"):
        return "buy"
    
    # Normalize to "sell"
    if d in ("bearish", "sell", "short", "down", "downtrend"):
        return "sell"
    
    # Invalid
    raise ValueError(f"Invalid direction: {d} (expected: buy/sell/bullish/bearish/long/short)")

# =========================================================================
# ML vs HTF Signal Arbitration
# =========================================================================
def ml_htf_allows_trade(htf_bias: str, ml_signal: str, ml_confidence: float) -> bool:
    """
    Enforce a clear hierarchy: HTF bias leads. If ML opposes HTF, require
    strong confidence. Returns True if the ML signal is allowed to proceed.
    """
    try:
        if not ml_signal or ml_signal not in ("buy", "sell"):
            return False
        htf = (htf_bias or "").lower()
        ml_dir = ml_signal.lower()

        # If HTF bias is unknown, allow only high-confidence ML
        if htf not in ("bullish", "bearish"):
            return ml_confidence >= MIN_ML_CONFIDENCE

        # Aligned case: HTF and ML in same direction ✅
        if (htf == "bullish" and ml_dir == "buy") or (htf == "bearish" and ml_dir == "sell"):
            return ml_confidence >= MIN_ML_CONFIDENCE

        # ❌ STRICT: Counter case: HTF and ML disagree → BLOCK IMMEDIATELY
        # ML cannot override HTF bias. Ever.
        # (If you want counter-trend trades, implement explicit counter-trend gate, not exceptions here)
        logging.debug(f"[ML OVERRIDE BLOCKED] HTF {htf.upper()} vs ML {ml_dir.upper()} - entry rejected")
        return False
    except Exception:
        return False

