CRITICAL_SYSTEMS = {
    "liquidity_engine": False,
    "decision_tree": False,
    "hybrid_sltp": False,
    "anti_revenge": False,
    "smc_trader": False
}

def mark_system_ok(system_name):
    """Mark a critical system as operational."""
    if system_name in CRITICAL_SYSTEMS:
        CRITICAL_SYSTEMS[system_name] = True

def trading_safe():
    """
    Hard gate: NO TRADE if any critical system failed.
    
    Returns: (is_safe: bool, failed_systems: list)
    """
    failed = [name for name, ok in CRITICAL_SYSTEMS.items() if not ok]
    is_safe = len(failed) == 0
    return is_safe, failed

def require_trading_safe(context: dict):
    """
    Check trading safety before execution.
    If unsafe, return None (no trade).
    """
    is_safe, failed = trading_safe()
    
    if not is_safe:
        symbol = context.get("symbol", "UNKNOWN")
        print(f"[TRADE BLOCKED] {symbol}: Critical systems down: {failed}")
        return None
    
    return True

# ============================================================================
# 🔒 CRITICAL SAFETY: Max SL Distance Protection (news volatility)
# ============================================================================
MAX_RISK_ATR = {
    "XAUUSD": 3.5,  # ✅ INCREASED: 2.5→3.5 (more room for wicks)
    "DEFAULT": 3.0  # ✅ INCREASED: 2.0→3.0 (wider SL = fewer whipsaws)
}

MIN_SL_ATR = {
    "XAUUSD": 1.5,  # ✅ Minimum SL: 1.5× ATR (avoid tight SL = instant loss)
    "DEFAULT": 1.2  # ✅ Minimum SL: 1.2× ATR for forex
}

def validate_sl_distance(symbol: str, entry_price: float, sl_price: float, atr: float):
    """
    Enforce both MAX and MIN SL distance from entry.
    
    Problems solved:
    1. MAX_RISK_ATR: Prevents oversized SL (news volatility)
    2. MIN_SL_ATR: Prevents tight SL (whipsaws, stops hit)
    
    Rule: MIN_SL_ATR × ATR <= SL_distance <= MAX_RISK_ATR × ATR
    
    Returns: (is_valid: bool, reason: str)
    """
    if atr <= 0:
        return False, "ATR must be positive"
    
    actual_distance = abs(entry_price - sl_price)
    
    # Check MIN SL distance
    min_risk_atr = MIN_SL_ATR.get(symbol, MIN_SL_ATR["DEFAULT"])
    min_sl_distance = min_risk_atr * atr
    
    if actual_distance < min_sl_distance:
        return False, f"SL too tight: {actual_distance:.5f} < {min_sl_distance:.5f} (need >= {min_risk_atr}× ATR) - WHIPSAW RISK"
    
    # Check MAX SL distance
    max_risk_atr = MAX_RISK_ATR.get(symbol, MAX_RISK_ATR["DEFAULT"])
    max_sl_distance = max_risk_atr * atr
    
    if actual_distance > max_sl_distance:
        return False, f"SL too far: {actual_distance:.5f} > {max_sl_distance:.5f} (max {max_risk_atr}× ATR) - OVERSIZED RISK"
    
    return True, f"SL distance OK ({actual_distance/atr:.2f}× ATR)"

