    def liquidity_sweep_high(df, lookback=30, symbol=""):
        """Advanced: Detect if price swept above recent high with rejection"""
        try:
            if df is None or len(df) < lookback + 2:
                return False
            highs = df['high'].values
            closes = df['close'].values
            lows = df['low'].values
            
            # Find recent high (previous lookback bars)
            prev_high = np.max(highs[:-1]) if len(highs) > 1 else highs[-1]
            current_high = highs[-1]
            current_close = closes[-1]
            current_low = lows[-1]
            
            # SWEEP UP: Current high > recent high, BUT current close < current high (rejection)
            sweep_detected = current_high > prev_high and current_close < current_high
            return bool(sweep_detected)
        except Exception as e:
            return False
    
    def liquidity_sweep_low(df, lookback=30, symbol=""):
        """Advanced: Detect if price swept below recent low with rejection"""
        try:
            if df is None or len(df) < lookback + 2:
                return False
            lows = df['low'].values
            closes = df['close'].values
            highs = df['high'].values
            
            # Find recent low (previous lookback bars)
            prev_low = np.min(lows[:-1]) if len(lows) > 1 else lows[-1]
            current_low = lows[-1]
            current_close = closes[-1]
            current_high = highs[-1]
            
            # SWEEP DOWN: Current low < recent low, BUT current close > current low (rejection)
            sweep_detected = current_low < prev_low and current_close > current_low
            return bool(sweep_detected)
        except Exception as e:
            return False
    
    def sweep_reentry_confirmed(df, direction="buy", lookback=30):
        """Advanced: Verify sweep was followed by recovery in correct direction"""
        try:
            if df is None or len(df) < lookback + 3:
                return False
            
            closes = df['close'].values
            highs = df['high'].values
            lows = df['low'].values
            
            if len(closes) < 4:
                return False
            
            # Get last 3 bars
            bar_highs = highs[-4:]
            bar_lows = lows[-4:]
            
            if direction.lower() == "buy":
                # BUY: Need sweep low, then closes higher
                sweep_bar_low = np.min(bar_lows[:3])
                recovery = closes[-1] > closes[-2] > sweep_bar_low
                return bool(recovery)
            else:  # sell
                # SELL: Need sweep high, then closes lower
                sweep_bar_high = np.max(bar_highs[:3])
                recovery = closes[-1] < closes[-2] < sweep_bar_high
                return bool(recovery)
        except Exception:
            return False
    
    def swing_high(df, lookback=20, bars_on_each_side=1):
        """Advanced: Find swing high in data"""
        try:
            if df is None or len(df) < lookback + 2 * bars_on_each_side + 1:
                return None
            highs = df['high'].values
            # Find highest point surrounded by lower bars
            for i in range(len(highs) - bars_on_each_side - 1, max(0, len(highs) - lookback), -1):
                is_swing = True
                for j in range(1, bars_on_each_side + 1):
                    if i - j >= 0 and highs[i] <= highs[i - j]:
                        is_swing = False
                        break
                    if i + j < len(highs) and highs[i] <= highs[i + j]:
                        is_swing = False
                        break
                if is_swing:
                    return float(highs[i])
            return None
        except Exception:
            return None
    
    def swing_low(df, lookback=20, bars_on_each_side=1):
        """Advanced: Find swing low in data"""
        try:
            if df is None or len(df) < lookback + 2 * bars_on_each_side + 1:
                return None
            lows = df['low'].values
            # Find lowest point surrounded by higher bars
            for i in range(len(lows) - bars_on_each_side - 1, max(0, len(lows) - lookback), -1):
                is_swing = True
                for j in range(1, bars_on_each_side + 1):
                    if i - j >= 0 and lows[i] >= lows[i - j]:
                        is_swing = False
                        break
                    if i + j < len(lows) and lows[i] >= lows[i + j]:
                        is_swing = False
                        break
                if is_swing:
                    return float(lows[i])
            return None
        except Exception:
            return None
    
