    def is_external_bos(df, direction="buy", h1_df=None):
        """
        ✅ Filter 1: Block internal BOS, require break of major swing (H1/M15)
        
        External BOS = Price breaks a significant swing formed on HTF (H1/D1)
        Internal BOS = Price breaks a small swing on LTF (noise)
        
        Args:
            df: DataFrame with OHLC + 'high', 'low'
            direction: "buy" or "sell"
            h1_df: Optional H1 data for major swing confirmation
        
        Returns:
            (is_external, has_major_swing, details)
        """
        try:
            if df is None or len(df) < 30:
                return (False, False, {"reason": "insufficient_data"})
            
            highs = df['high'].values
            lows = df['low'].values
            
            # For BUY: need break of a swing high that lasted multiple candles (not 1-2)
            # For SELL: need break of a swing low that lasted multiple candles
            
            if direction == "buy":
                # Find swing high that was holds for at least 5 candles
                current_price = highs[-1]
                lookback_distances = []
                
                for lookback in [10, 15, 20]:
                    if lookback < len(highs):
                        historical_high = max(highs[-lookback:])
                        # Swing high must have been "significant" (held for multiple bars)
                        swing_age = 0
                        for i in range(len(highs) - lookback - 1, len(highs) - 1):
                            if highs[i] == historical_high or highs[i] > highs[-1]:
                                swing_age += 1
                        
                        if swing_age >= 3:  # Must hold for at least 3 candles
                            lookback_distances.append({
                                'lookback': lookback,
                                'swing_high': historical_high,
                                'age': swing_age,
                                'is_major': lookback >= 15
                            })
                
                if not lookback_distances:
                    return (False, False, {"reason": "no_major_swing_high"})
                
                # Prefer furthest lookback (largest swing)
                major_swing = max(lookback_distances, key=lambda x: x['lookback'])
                has_major = major_swing['is_major']
                
                return (current_price > major_swing['swing_high'], has_major, {
                    "swing_high": major_swing['swing_high'],
                    "lookback": major_swing['lookback'],
                    "age_bars": major_swing['age'],
                    "is_external": has_major
                })
            
            else:  # direction == "sell"
                current_price = lows[-1]
                lookback_distances = []
                
                for lookback in [10, 15, 20]:
                    if lookback < len(lows):
                        historical_low = min(lows[-lookback:])
                        swing_age = 0
                        for i in range(len(lows) - lookback - 1, len(lows) - 1):
                            if lows[i] == historical_low or lows[i] < lows[-1]:
                                swing_age += 1
                        
                        if swing_age >= 3:
                            lookback_distances.append({
                                'lookback': lookback,
                                'swing_low': historical_low,
                                'age': swing_age,
                                'is_major': lookback >= 15
                            })
                
                if not lookback_distances:
                    return (False, False, {"reason": "no_major_swing_low"})
                
                major_swing = max(lookback_distances, key=lambda x: x['lookback'])
                has_major = major_swing['is_major']
                
                return (current_price < major_swing['swing_low'], has_major, {
                    "swing_low": major_swing['swing_low'],
                    "lookback": major_swing['lookback'],
                    "age_bars": major_swing['age'],
                    "is_external": has_major
                })
        
        except Exception as e:
            return (False, False, {"reason": f"error: {str(e)}"})
    
    def check_premium_discount_filter(df, direction="buy", equilibrium_method="50_range"):
        """
        ✅ Filter 2: Premium/Discount filter
        
        BUY: Only buy if price < equilibrium (discount)
        SELL: Only sell if price > equilibrium (premium)
        
        This blocks selling into weakness and buying into strength.
        
        Args:
            df: DataFrame with OHLC
            direction: "buy" or "sell"
            equilibrium_method: "50_range" (default), "sma", or "pivot"
        
        Returns:
            (is_premium_discount_valid, current_price, equilibrium, details)
        """
        try:
            if df is None or len(df) < 20:
                return (True, 0, 0, {"reason": "insufficient_data", "allowed": True})
            
            current_price = df['close'].iloc[-1]
            highs = df['high'].values
            lows = df['low'].values
            range_lookback = 20
            
            if equilibrium_method == "50_range":
                # 50% of recent range
                recent_high = max(highs[-range_lookback:])
                recent_low = min(lows[-range_lookback:])
                equilibrium = (recent_high + recent_low) / 2
            else:
                # Default to 50% range
                recent_high = max(highs[-range_lookback:])
                recent_low = min(lows[-range_lookback:])
                equilibrium = (recent_high + recent_low) / 2
            
            if direction == "buy":
                # BUY allowed if price < equilibrium (discount)
                is_valid = current_price < equilibrium
                return (is_valid, current_price, equilibrium, {
                    "price_below_equilibrium": is_valid,
                    "discount_amount": equilibrium - current_price,
                    "discount_pct": ((equilibrium - current_price) / equilibrium * 100) if equilibrium > 0 else 0
                })
            
            else:  # direction == "sell"
                # SELL allowed if price > equilibrium (premium)
                is_valid = current_price > equilibrium
                return (is_valid, current_price, equilibrium, {
                    "price_above_equilibrium": is_valid,
                    "premium_amount": current_price - equilibrium,
                    "premium_pct": ((current_price - equilibrium) / equilibrium * 100) if equilibrium > 0 else 0
                })
        
        except Exception as e:
            return (True, 0, 0, {"reason": f"error: {str(e)}", "allowed": True})
    
    def check_strength_score_filter(bos_strength_score, min_strength=70):
        """
        ✅ Filter 3: Strength score filter - tighten BOS confirmation
        
        Only allow trades if strength_score >= 70 (instead of 60)
        
        Args:
            bos_strength_score: Score from BOS detection (0-100)
            min_strength: Minimum required strength (default 70)
        
        Returns:
            (is_strong_enough, score, deficit, details)
        """
        try:
            is_valid = bos_strength_score >= min_strength
            deficit = max(0, min_strength - bos_strength_score)
            
            return (is_valid, bos_strength_score, deficit, {
                "score": bos_strength_score,
                "min_required": min_strength,
                "passed": is_valid,
                "confidence": "🟢 HIGH" if bos_strength_score >= 80 else ("🟡 MEDIUM" if bos_strength_score >= 70 else "🔴 LOW")
            })
        except Exception as e:
            return (False, 0, min_strength, {"error": str(e), "passed": False})
    
    def check_consolidation_filter(df, max_range_atr=2.0, atr_period=14):
        """
        ✅ Filter 4: Block trades in consolidation
        
        If range_size < ATR * 2, price is consolidating (too quiet to trade)
        
        Args:
            df: DataFrame with OHLC
            max_range_atr: ATR multiplier threshold (default 2.0)
            atr_period: Period for ATR calculation
        
        Returns:
            (is_good_volatility, range_size, atr, details)
        """
        try:
            if df is None or len(df) < atr_period + 5:
                return (True, 0, 0, {"reason": "insufficient_data", "allowed": True})
            
            highs = df['high'].values
            lows = df['low'].values
            closes = df['close'].values
            
            # ATR calculation
            tr_values = []
            for i in range(1, len(closes)):
                tr = max(
                    highs[i] - lows[i],
                    abs(highs[i] - closes[i-1]),
                    abs(lows[i] - closes[i-1])
                )
                tr_values.append(tr)
            
            atr = np.mean(tr_values[-atr_period:]) if tr_values else 0.0001
            
            # Recent range size (last 20 candles)
            recent_high = max(highs[-20:])
            recent_low = min(lows[-20:])
            range_size = recent_high - recent_low
            
            # Is consolidating if range < ATR * multiplier
            is_consolidating = range_size < (atr * max_range_atr)
            is_valid = not is_consolidating  # Invert: we want good volatility
            
            return (is_valid, range_size, atr, {
                "range_size": range_size,
                "atr": atr,
                "threshold": atr * max_range_atr,
                "is_consolidating": is_consolidating,
                "ratio": range_size / (atr * max_range_atr) if atr > 0 else 0,
                "passed": is_valid
            })
        
        except Exception as e:
            return (True, 0, 0, {"reason": f"error: {str(e)}", "allowed": True})
    
    def apply_all_trading_filters(df, symbol, bos_strength_score, direction="buy", h1_df=None):
        """
        🎯 MASTER FILTER: Apply all 4 trading filters to validate BOS entry
        
        Filters:
        1. External BOS only (major swing from H1/M15, not noise)
        2. Premium/Discount (BUY < equilibrium, SELL > equilibrium)
        3. Strength score (>= 70, up from 60)
        4. Consolidation blocker (range >= 2× ATR)
        
        Returns:
            (all_filters_pass, filter_results_dict)
        """
        try:
            results = {
                "all_passed": True,
                "filters": {},
                "rejection_reason": None,
                "confidence_boost": 0.0
            }
            
            # ✅ Filter 1: External BOS
            external_bos, has_major, ext_details = is_external_bos(df, direction=direction, h1_df=h1_df)
            results["filters"]["external_bos"] = {
                "passed": external_bos and has_major,
                "details": ext_details
            }
            if not (external_bos and has_major):
                results["all_passed"] = False
                results["rejection_reason"] = f"❌ Internal BOS detected (no major swing) - {ext_details.get('reason', 'unknown')}"
                print(f"[FILTER 1 BLOCKED] {symbol} {direction}: {results['rejection_reason']}")
            else:
                print(f"[FILTER 1 ✅] {symbol}: External BOS confirmed (lookback {ext_details.get('lookback')} bars)")
            
            # ✅ Filter 2: Premium/Discount
            prem_disc_valid, price, eq, prem_details = check_premium_discount_filter(df, direction=direction)
            results["filters"]["premium_discount"] = {
                "passed": prem_disc_valid,
                "price": price,
                "equilibrium": eq,
                "details": prem_details
            }
            if not prem_disc_valid:
                results["all_passed"] = False
                if direction == "buy":
                    reason = f"❌ Price above equilibrium (no discount) - Price {price:.5f} > Eq {eq:.5f}"
                else:
                    reason = f"❌ Price below equilibrium (no premium) - Price {price:.5f} < Eq {eq:.5f}"
                results["rejection_reason"] = reason
                print(f"[FILTER 2 BLOCKED] {symbol} {direction}: {reason}")
            else:
                discount = prem_details.get("discount_pct", prem_details.get("premium_pct", 0))
                print(f"[FILTER 2 ✅] {symbol}: {'Discount' if direction == 'buy' else 'Premium'} {abs(discount):.1f}%")
            
            # ✅ Filter 3: Strength Score
            strength_valid, score, deficit, strength_details = check_strength_score_filter(
                bos_strength_score, min_strength=70
            )
            results["filters"]["strength_score"] = {
                "passed": strength_valid,
                "score": score,
                "details": strength_details
            }
            if not strength_valid:
                results["all_passed"] = False
                results["rejection_reason"] = f"❌ BOS strength too weak - {score}/100 (need 70+, deficit {deficit})"
                print(f"[FILTER 3 BLOCKED] {symbol}: {results['rejection_reason']}")
            else:
                confidence = strength_details.get("confidence", "")
                print(f"[FILTER 3 ✅] {symbol}: BOS Strength {score}/100 ({confidence})")
                # Add confidence boost for high strength scores
                if score >= 80:
                    results["confidence_boost"] += 0.1
            
            # ✅ Filter 4: Consolidation
            vol_valid, range_sz, atr, vol_details = check_consolidation_filter(df, max_range_atr=2.0)
            results["filters"]["consolidation"] = {
                "passed": vol_valid,
                "range_size": range_sz,
                "atr": atr,
                "details": vol_details
            }
            if not vol_valid:
                results["all_passed"] = False
                ratio = vol_details.get("ratio", 0)
                results["rejection_reason"] = f"❌ Price consolidating (range {ratio:.2f}× threshold) - blocked"
                print(f"[FILTER 4 BLOCKED] {symbol}: {results['rejection_reason']}")
            else:
                ratio = vol_details.get("ratio", 1)
                print(f"[FILTER 4 ✅] {symbol}: Good volatility (range {ratio:.2f}× threshold)")
            
            return (results["all_passed"], results)
        
        except Exception as e:
            print(f"[FILTER ERROR] {symbol}: {e}")
            return (False, {"all_passed": False, "error": str(e)})
    
    # ═══════════════════════════════════════════════════════════════════
    # 🎯 UNIVERSAL BOS & LIQUIDITY (Normalized for All Symbols)
    # ═══════════════════════════════════════════════════════════════════
    
    def universal_detect_bullish_bos(df, lookback=20):
        """
        UNIVERSAL BULLISH BOS DETECTION
        
        Definition: Candle CLOSE > Last Swing High (no wick, no "almost")
        Works on: Any symbol (Forex, Gold, Indices, Crypto)
        Returns: bool
        """
        try:
            if df is None or len(df) < lookback + 2:
                return False
            
            closes = df['close'].values
            highs = df['high'].values
            
            # Find last swing high: Higher than 2 bars on EACH side
            last_swing_high = None
            for i in range(len(highs) - 3, max(0, len(highs) - lookback - 1), -1):
                if (highs[i] > highs[i-1] and highs[i] > highs[i-2] and 
                    highs[i] > highs[i+1] and highs[i] > highs[i+2]):
                    last_swing_high = highs[i]
                    break
            
            if last_swing_high is None:
                return False
            
            # CLOSE must be BEYOND (not wick, not "almost")
            return closes[-1] > last_swing_high
        except Exception:
            return False
    
    def universal_detect_bearish_bos(df, lookback=20):
        """
        UNIVERSAL BEARISH BOS DETECTION
        
        Definition: Candle CLOSE < Last Swing Low (no wick, no "almost")
        Works on: Any symbol (Forex, Gold, Indices, Crypto)
        Returns: bool
        """
        try:
            if df is None or len(df) < lookback + 2:
                return False
            
            closes = df['close'].values
            lows = df['low'].values
            
            # Find last swing low: Lower than 2 bars on EACH side
            last_swing_low = None
            for i in range(len(lows) - 3, max(0, len(lows) - lookback - 1), -1):
                if (lows[i] < lows[i-1] and lows[i] < lows[i-2] and 
                    lows[i] < lows[i+1] and lows[i] < lows[i+2]):
                    last_swing_low = lows[i]
                    break
            
            if last_swing_low is None:
                return False
            
            # CLOSE must be BEYOND (not wick, not "almost")
            return closes[-1] < last_swing_low
        except Exception:
            return False
    
    def universal_liquidity_sweep(df, lookback=30):
        """
        UNIVERSAL LIQUIDITY SWEEP DETECTION
        
        Definition: Price touches previous high/low AND closes back inside range
        
        Returns: {
            'sweep_type': 'bullish'|'bearish'|None,
            'triggered': True|False,
            'level': float (the level swept),
            'reclaimed': True|False (closed back inside)
        }
        """
        try:
            if df is None or len(df) < lookback + 2:
                return {'sweep_type': None, 'triggered': False, 'level': None, 'reclaimed': False}
            
            recent_df = df.iloc[-lookback:]
            highs = recent_df['high'].values
            lows = recent_df['low'].values
            closes = recent_df['close'].values
            
            current_high = highs[-1]
            current_low = lows[-1]
            current_close = closes[-1]
            
            # Find previous range (bar -2 to -lookback)
            prev_highs = highs[:-1]
            prev_lows = lows[:-1]
            prev_range_high = np.max(prev_highs)
            prev_range_low = np.min(prev_lows)
            
            result = {'sweep_type': None, 'triggered': False, 'level': None, 'reclaimed': False}
            
            # BULLISH SWEEP: Current low < prev range low AND close > prev range low
            if current_low < prev_range_low and current_close > prev_range_low:
                result['sweep_type'] = 'bullish'
                result['triggered'] = True
                result['level'] = prev_range_low
                result['reclaimed'] = True
                return result
            
            # BEARISH SWEEP: Current high > prev range high AND close < prev range high
            if current_high > prev_range_high and current_close < prev_range_high:
                result['sweep_type'] = 'bearish'
                result['triggered'] = True
                result['level'] = prev_range_high
                result['reclaimed'] = True
                return result
            
            return result
        except Exception:
            return {'sweep_type': None, 'triggered': False, 'level': None, 'reclaimed': False}

    # Legacy fallback functions (now call universal versions)
