_detect_bullish_bos_impl = globals().get("detect_bullish_bos")
_detect_bearish_bos_impl = globals().get("detect_bearish_bos")

def detect_bullish_bos(highs, lows, closes, lookback=20):
    """Normalized BOS check (accepts lookback kw regardless of import signature)."""
    try:
        if _detect_bullish_bos_impl is None:
            return False
        return _detect_bullish_bos_impl(highs, lows, closes, lookback)
    except TypeError:
        # Fallback for 2-arg signature: (current_close, last_swing_high)
        try:
            if len(highs) < lookback + 1 or len(closes) == 0:
                return False
            last_swing_high = max(highs[-(lookback + 1):])
            return _detect_bullish_bos_impl(closes[-1], last_swing_high)
        except Exception:
            return False
    except Exception:
        return False

def detect_bearish_bos(highs, lows, closes, lookback=20):
    """Normalized BOS check (accepts lookback kw regardless of import signature)."""
    try:
        if _detect_bearish_bos_impl is None:
            return False
        return _detect_bearish_bos_impl(highs, lows, closes, lookback)
    except TypeError:
        # Fallback for 2-arg signature: (current_close, last_swing_low)
        try:
            if len(lows) < lookback + 1 or len(closes) == 0:
                return False
            last_swing_low = min(lows[-(lookback + 1):])
            return _detect_bearish_bos_impl(closes[-1], last_swing_low)
        except Exception:
            return False
    except Exception:
        return False
