    def detect_bullish_choch(df, lookback=30):
        """Advanced: Detect Change of Character - bullish"""
        try:
            if df is None or len(df) < lookback + 2:
                return None
            lows = df['low'].values
            highs = df['high'].values
            # ChoCH = Higher Low + Break of previous high
            recent_lows = lows[-lookback:]
            recent_highs = highs[-lookback:]
            current_low = lows[-1]
            current_high = highs[-1]
            prev_high = np.max(recent_highs[:-1]) if len(recent_highs) > 1 else 0
            # Check for HL (higher low)
            two_ago_low = lows[-2] if len(lows) >= 2 else lows[-1]
            higher_low = current_low > two_ago_low
            bos_up = current_high > prev_high
            return (higher_low and bos_up)
        except Exception:
            return None
    
    def detect_bearish_choch(df, lookback=30):
        """Advanced: Detect Change of Character - bearish"""
        try:
            if df is None or len(df) < lookback + 2:
                return None
            lows = df['low'].values
            highs = df['high'].values
            # ChoCH = Lower High + Break of previous low
            recent_lows = lows[-lookback:]
            recent_highs = highs[-lookback:]
            current_low = lows[-1]
            current_high = highs[-1]
            prev_low = np.min(recent_lows[:-1]) if len(recent_lows) > 1 else 999999
            # Check for LH (lower high)
            two_ago_high = highs[-2] if len(highs) >= 2 else highs[-1]
            lower_high = current_high < two_ago_high
            bos_down = current_low < prev_low
            return (lower_high and bos_down)
        except Exception:
            return None
    
    def bullish_fvg(df, lookback=30):
        """Advanced: Fair Value Gap - bullish (gap up, lower candle low)"""
        try:
            if df is None or len(df) < 4:
                return False
            highs = df['high'].values
            lows = df['low'].values
            closes = df['close'].values
            if len(highs) < 3:
                return False
            # Bullish FVG: Gap up between bar 2 and 3
            # Bar 1 close > Bar 2 low, Bar 2 close < Bar 1 high, creates gap
            bar3_low = lows[-1]
            bar2_high = highs[-2]
            bar1_low = lows[-3] if len(lows) >= 3 else lows[-1]
            # Simple FVG: there's an imbalance (gap)
            fvg = bar2_high > bar3_low and bar1_low < bar3_low
            return bool(fvg)
        except Exception:
            return False
    
    def bearish_fvg(df, lookback=30):
        """Advanced: Fair Value Gap - bearish (gap down, higher candle high)"""
        try:
            if df is None or len(df) < 4:
                return False
            highs = df['high'].values
            lows = df['low'].values
            if len(lows) < 3:
                return False
            # Bearish FVG: Gap down between bar 2 and 3
            bar3_high = highs[-1]
            bar2_low = lows[-2]
            bar1_high = highs[-3] if len(highs) >= 3 else highs[-1]
            # Simple FVG: there's an imbalance (gap)
            fvg = bar2_low < bar3_high and bar1_high > bar3_high
            return bool(fvg)
        except Exception:
            return False
    
    def get_fvg_bounds(df, direction="up"):
        """Advanced: Get FVG zone boundaries"""
        try:
            if df is None or len(df) < 3:
                return None
            highs = df['high'].values
            lows = df['low'].values
            if direction == "up":
                # Bullish FVG bounds
                return {"low": lows[-1], "high": highs[-2], "type": "bullish"}
            else:
                # Bearish FVG bounds
                return {"low": lows[-2], "high": highs[-1], "type": "bearish"}
        except Exception:
            return None
    
    def detect_fvg_after_structure(df, bos_direction=None):
        """Advanced: Check for FVG in direction after BOS"""
        try:
            if df is None or len(df) < 4:
                return None
            if bos_direction and bos_direction.lower() == "up":
                return bullish_fvg(df)
            elif bos_direction and bos_direction.lower() == "down":
                return bearish_fvg(df)
            # Check both
            bullish = bullish_fvg(df)
            bearish = bearish_fvg(df)
            if bullish:
                return "bullish"
            if bearish:
                return "bearish"
            return None
        except Exception:
            return None
    
    def calculate_entry_zone(df, price, direction="buy", atr=0.001):
        """Advanced: Calculate entry zone around price"""
        try:
            if df is None or price <= 0 or atr <= 0:
                return {}
            buffer = atr * 0.5
            return {
                "zone_high": float(price + buffer),
                "zone_low": float(price - buffer),
                "zone_mid": float(price),
                "atr": float(atr),
                "direction": direction
            }
        except Exception:
            return {}
    
    def price_in_entry_zone(current_price, zone):
        """Advanced: Check if price is within zone"""
        try:
            if not zone or not isinstance(zone, dict):
                return False
            zone_low = float(zone.get("zone_low", -999999))
            zone_high = float(zone.get("zone_high", 999999))
            return zone_low <= current_price <= zone_high
        except Exception:
            return False
    
    def bullish_engulfing(df):
        """Advanced: Bullish engulfing pattern"""
        try:
            if df is None or len(df) < 2:
                return False
            opens = df['open'].values
            closes = df['close'].values
            # Current bar closes above previous open, previous bar was down
            prev_close = closes[-2] if len(closes) >= 2 else closes[-1]
            prev_open = opens[-2] if len(opens) >= 2 else opens[-1]
            curr_close = closes[-1]
            curr_open = opens[-1]
            # Bullish engulfing: current close > prev open, current open < prev close
            engulf = curr_close > prev_open and curr_open < prev_close and curr_close > curr_open
            return bool(engulf)
        except Exception:
            return False
    
    def bearish_engulfing(df):
        """Advanced: Bearish engulfing pattern"""
        try:
            if df is None or len(df) < 2:
                return False
            opens = df['open'].values
            closes = df['close'].values
            # Current bar closes below previous open, previous bar was up
            prev_close = closes[-2] if len(closes) >= 2 else closes[-1]
            prev_open = opens[-2] if len(opens) >= 2 else opens[-1]
            curr_close = closes[-1]
            curr_open = opens[-1]
            # Bearish engulfing: current close < prev open, current open > prev close
            engulf = curr_close < prev_open and curr_open > prev_close and curr_open > curr_close
            return bool(engulf)
        except Exception:
            return False
    
    def is_displacement_candle(df):
        """Advanced: Check if candle has strong displacement (body > 60% of range)"""
        try:
            if df is None or len(df) < 1:
                return False
            highs = df['high'].values
            lows = df['low'].values
            opens = df['open'].values
            closes = df['close'].values
            
            candle_range = highs[-1] - lows[-1]
            if candle_range <= 0:
                return False
            body = abs(closes[-1] - opens[-1])
            displacement_ratio = body / candle_range
            return displacement_ratio >= 0.60
        except Exception:
            return False
    
    def has_volume_expansion(df, multiplier=1.3):
        """Advanced: Check if current volume is expanded vs average"""
        try:
            if df is None or len(df) < 20:
                return False
            volumes = df['tick_volume'].values if 'tick_volume' in df.columns else df['volume'].values if 'volume' in df.columns else np.ones(len(df))
            avg_vol = np.mean(volumes[-21:-1]) if len(volumes) > 20 else np.mean(volumes)
            current_vol = volumes[-1]
            return current_vol > (avg_vol * multiplier)
        except Exception:
            return False
    
    def validate_entry_confirmation(df, direction="buy"):
        """Advanced: Validate entry confirmation"""
        try:
            if df is None or len(df) < 2:
                return {'entry_confirmed': False, 'reason': 'Insufficient data'}
            
            confirms = []
            if bullish_engulfing(df) and direction.lower() == "buy":
                confirms.append("bullish_engulfing")
            if bearish_engulfing(df) and direction.lower() == "sell":
                confirms.append("bearish_engulfing")
            if is_displacement_candle(df):
                confirms.append("displacement")
            if has_volume_expansion(df):
                confirms.append("volume_expansion")
            
            confirmed = len(confirms) >= 2
            return {'entry_confirmed': confirmed, 'confirms': confirms, 'count': len(confirms)}
        except Exception:
            return {'entry_confirmed': False, 'reason': 'Error in validation'}
    
    def execute_sweep_to_entry_workflow(df, direction="buy"):
        """Advanced: Execute workflow from sweep detection to entry"""
        try:
            if df is None:
                return {'executed': False, 'reason': 'No data'}
            
            sweep = False
            if direction.lower() == "buy":
                sweep = liquidity_sweep_low(df)
            else:
                sweep = liquidity_sweep_high(df)
            
            if sweep:
                confirmed = validate_entry_confirmation(df, direction)
                if confirmed['entry_confirmed']:
                    return {'executed': True, 'type': 'sweep_entry', 'direction': direction}
            
            return {'executed': False}
        except Exception:
            return {'executed': False}

