# =============================================================================
# ADVANCED M15 BOS DETECTION - GLOBAL FUNCTION (PROFESSIONAL GRADE)
# =============================================================================

def detect_advanced_m15_bos(df_m15, direction=None, min_displacement=None, symbol=""):
    """
    ADVANCED M15 BOS DETECTION - Professional Grade
    
    Requirements for valid M15 BOS:
    1. Price closes BEYOND last significant swing (not just touches)
    2. Volume expansion (1.3x avg) on break candle
    3. Displacement requirement (candle body > 0.6 * range)
    4. False break filter (previous failed breaks rejected)
    5. Structure strength scoring (0-100)
    6. Multi-swing lookback (finds strongest swing in 20-50 bars)
    
    Returns: (bos_detected: bool, bos_direction: str, strength_score: int, break_level: float, details: dict)
    """
    try:
        if df_m15 is None or len(df_m15) < 50:
            return (False, None, 0, 0.0, {"reason": "Insufficient M15 data"})
        
        highs = df_m15['high'].values
        lows = df_m15['low'].values
        closes = df_m15['close'].values
        opens = df_m15['open'].values
        volumes = df_m15['tick_volume'].values if 'tick_volume' in df_m15.columns else df_m15['volume'].values if 'volume' in df_m15.columns else np.ones(len(df_m15))
        
        current_close = closes[-1]
        current_open = opens[-1]
        current_high = highs[-1]
        current_low = lows[-1]
        current_volume = volumes[-1]
        
        # Calculate average volume (last 20 bars)
        avg_volume = np.mean(volumes[-21:-1]) if len(volumes) > 20 else np.mean(volumes)
        
        # 1. FIND SIGNIFICANT SWING HIGHS (multi-period lookback)
        swing_highs = []
        for lookback in [10, 20, 30, 50]:
            if len(highs) < lookback + 5:
                continue
            for i in range(len(highs) - 5, max(len(highs) - lookback, 0), -1):
                if i < 2 or i >= len(highs) - 2:
                    continue
                # Swing high: higher than 2 bars on each side
                if (highs[i] > highs[i-1] and highs[i] > highs[i-2] and 
                    highs[i] > highs[i+1] and highs[i] > highs[i+2]):
                    swing_highs.append({'price': highs[i], 'index': i, 'lookback': lookback})
                    break  # Take first (most recent) for this lookback
        
        # 2. FIND SIGNIFICANT SWING LOWS (multi-period lookback)
        swing_lows = []
        for lookback in [10, 20, 30, 50]:
            if len(lows) < lookback + 5:
                continue
            for i in range(len(lows) - 5, max(len(lows) - lookback, 0), -1):
                if i < 2 or i >= len(lows) - 2:
                    continue
                # Swing low: lower than 2 bars on each side
                if (lows[i] < lows[i-1] and lows[i] < lows[i-2] and 
                    lows[i] < lows[i+1] and lows[i] < lows[i+2]):
                    swing_lows.append({'price': lows[i], 'index': i, 'lookback': lookback})
                    break  # Take first (most recent) for this lookback
        
        if not swing_highs and not swing_lows:
            return (False, None, 0, 0.0, {"reason": "No significant swings found"})
        
        # 3. CHECK BULLISH BOS (close above swing high)
        bullish_bos = False
        bullish_strength = 0
        bullish_level = 0.0
        bullish_details = {}
        
        if swing_highs and (direction is None or direction == "buy"):
            # Use the strongest (furthest lookback) swing high
            strongest_swing = max(swing_highs, key=lambda x: x['lookback'])
            swing_high_price = strongest_swing['price']
            swing_high_idx = strongest_swing['index']
            
            # CLOSE must be BEYOND swing high (not just touch)
            if current_close > swing_high_price:
                # Volume confirmation (1.3x average)
                volume_ok = current_volume > avg_volume * 1.3
                
                # Displacement (body > 60% of range)
                candle_range = current_high - current_low
                candle_body = abs(current_close - current_open)
                displacement_ok = candle_body > 0.6 * candle_range if candle_range > 0 else False
                
                # False break filter: check if price has tried and failed before
                false_breaks = 0
                for i in range(swing_high_idx + 1, len(highs) - 1):
                    if highs[i] > swing_high_price and closes[i] < swing_high_price:
                        false_breaks += 1
                false_break_ok = false_breaks < 2  # Allow max 1 false break
                
                # Minimum displacement (optional, ATR-based)
                min_disp_ok = True
                if min_displacement is not None:
                    break_distance = current_close - swing_high_price
                    min_disp_ok = break_distance >= min_displacement
                
                # Calculate strength score (0-100)
                score = 0
                if volume_ok: score += 30
                if displacement_ok: score += 25
                if false_break_ok: score += 25
                if min_disp_ok: score += 10
                # Bonus for strong close (top 30% of candle)
                if current_close > current_low + 0.7 * candle_range:
                    score += 10
                
                # ✅ FILTER 3: BOS confirmed if score >= 85 (STRICT - no weak BOS allowed)
                MIN_BOS_STRENGTH = 85
                if score >= MIN_BOS_STRENGTH:
                    bullish_bos = True
                    bullish_strength = score
                    bullish_level = swing_high_price
                    bullish_details = {
                        "swing_high": swing_high_price,
                        "break_close": current_close,
                        "break_distance": current_close - swing_high_price,
                        "volume_ratio": current_volume / avg_volume if avg_volume > 0 else 0,
                        "displacement": candle_body / candle_range if candle_range > 0 else 0,
                        "false_breaks": false_breaks,
                        "strength_score": score,
                        "swing_lookback": strongest_swing['lookback']
                    }
        
        # 4. CHECK BEARISH BOS (close below swing low)
        bearish_bos = False
        bearish_strength = 0
        bearish_level = 0.0
        bearish_details = {}
        
        if swing_lows and (direction is None or direction == "sell"):
            # Use the strongest (furthest lookback) swing low
            strongest_swing = max(swing_lows, key=lambda x: x['lookback'])
            swing_low_price = strongest_swing['price']
            swing_low_idx = strongest_swing['index']
            
            # CLOSE must be BEYOND swing low (not just touch)
            if current_close < swing_low_price:
                # Volume confirmation (1.3x average)
                volume_ok = current_volume > avg_volume * 1.3
                
                # Displacement (body > 60% of range)
                candle_range = current_high - current_low
                candle_body = abs(current_close - current_open)
                displacement_ok = candle_body > 0.6 * candle_range if candle_range > 0 else False
                
                # False break filter: check if price has tried and failed before
                false_breaks = 0
                for i in range(swing_low_idx + 1, len(lows) - 1):
                    if lows[i] < swing_low_price and closes[i] > swing_low_price:
                        false_breaks += 1
                false_break_ok = false_breaks < 2  # Allow max 1 false break
                
                # Minimum displacement (optional, ATR-based)
                min_disp_ok = True
                if min_displacement is not None:
                    break_distance = swing_low_price - current_close
                    min_disp_ok = break_distance >= min_displacement
                
                # Calculate strength score (0-100)
                score = 0
                if volume_ok: score += 30
                if displacement_ok: score += 25
                if false_break_ok: score += 25
                if min_disp_ok: score += 10
                # Bonus for strong close (bottom 30% of candle)
                if current_close < current_high - 0.7 * candle_range:
                    score += 10
                
                # ✅ FILTER 3: BOS confirmed if score >= 85 (STRICT - no weak BOS allowed)
                MIN_BOS_STRENGTH = 85
                if score >= MIN_BOS_STRENGTH:
                    bearish_bos = True
                    bearish_strength = score
                    bearish_level = swing_low_price
                    bearish_details = {
                        "swing_low": swing_low_price,
                        "break_close": current_close,
                        "break_distance": swing_low_price - current_close,
                        "volume_ratio": current_volume / avg_volume if avg_volume > 0 else 0,
                        "displacement": candle_body / candle_range if candle_range > 0 else 0,
                        "false_breaks": false_breaks,
                        "strength_score": score,
                        "swing_lookback": strongest_swing['lookback']
                    }
        
        # 5. RETURN STRONGEST BOS (bullish vs bearish)
        if bullish_bos and bearish_bos:
            # Both detected - return stronger one
            if bullish_strength >= bearish_strength:
                print(f"[M15 BOS ✅] {symbol} BULLISH — Strength: {bullish_strength}/100 | Break: {bullish_level:.5f} | Vol: {bullish_details['volume_ratio']:.1f}x | Disp: {bullish_details['displacement']:.0%}")
                return (True, "bullish", bullish_strength, bullish_level, bullish_details)
            else:
                print(f"[M15 BOS ✅] {symbol} BEARISH — Strength: {bearish_strength}/100 | Break: {bearish_level:.5f} | Vol: {bearish_details['volume_ratio']:.1f}x | Disp: {bearish_details['displacement']:.0%}")
                return (True, "bearish", bearish_strength, bearish_level, bearish_details)
        elif bullish_bos:
            print(f"[M15 BOS ✅] {symbol} BULLISH — Strength: {bullish_strength}/100 | Break: {bullish_level:.5f} | Vol: {bullish_details['volume_ratio']:.1f}x | Disp: {bullish_details['displacement']:.0%}")
            return (True, "bullish", bullish_strength, bullish_level, bullish_details)
        elif bearish_bos:
            print(f"[M15 BOS ✅] {symbol} BEARISH — Strength: {bearish_strength}/100 | Break: {bearish_level:.5f} | Vol: {bearish_details['volume_ratio']:.1f}x | Disp: {bearish_details['displacement']:.0%}")
            return (True, "bearish", bearish_strength, bearish_level, bearish_details)
        else:
            return (False, None, 0, 0.0, {"reason": "No valid M15 BOS detected (score < 70 - MIN_BOS_STRENGTH requirement)"})
    
    except Exception as e:
        print(f"[M15 BOS ERROR] {symbol}: {e}")
        return (False, None, 0, 0.0, {"reason": f"Error: {str(e)}"})

