try:
    from anti_revenge_filter import get_anti_revenge_filter
except Exception as e:
    print(f"[WARNING] Could not import anti_revenge_filter: {e}")
    # Fallback: FUNCTIONAL ANTI-REVENGE FILTER IMPLEMENTATION
    class DummyAntiRevenge:
        """Advanced Anti-Revenge Filter with Session Memory"""
        def __init__(self):
            self.sl_hits = {}  # symbol -> [timestamps]
            self.trades_by_session = {}  # session_key -> count
            self.last_session_reset = pytime.time()
            self.session_duration = 3600  # 1 hour
        
        def record_sl_hit(self, symbol, timestamp=None):
            """Record that SL was hit for a symbol"""
            try:
                if symbol not in self.sl_hits:
                    self.sl_hits[symbol] = []
                self.sl_hits[symbol].append(timestamp or pytime.time())
                # Keep only last 24 hours
                cutoff = pytime.time() - 86400
                self.sl_hits[symbol] = [t for t in self.sl_hits[symbol] if t > cutoff]
            except Exception:
                pass
        
        def can_enter_after_sl(self, symbol, min_bars_after_sl=3):
            """Check if we can enter after SL was hit"""
            try:
                if symbol not in self.sl_hits or not self.sl_hits[symbol]:
                    return (True, "NO_RECENT_SL")
                time_since_sl = pytime.time() - self.sl_hits[symbol][-1]
                # Need at least 3 minutes after SL before re-entering
                min_time_gap = 180
                if time_since_sl < min_time_gap:
                    return (False, f"SL_COOLDOWN: {int(min_time_gap - time_since_sl)}s remaining")
                return (True, "COOLDOWN_PASSED")
            except Exception:
                return (True, "ERROR - ALLOWING")
        
        def add_trade(self, symbol, timestamp=None):
            """Record a trade execution"""
            try:
                session_key = self._get_session_key()
                if session_key not in self.trades_by_session:
                    self.trades_by_session[session_key] = 0
                self.trades_by_session[session_key] += 1
            except Exception:
                pass
        
        def get_session_trade_count(self):
            """Get trades in current session"""
            try:
                session_key = self._get_session_key()
                return self.trades_by_session.get(session_key, 0)
            except Exception:
                return 0
        
        def is_session_limit_reached(self, max_trades_per_session=20):
            """Check if session trade limit exceeded"""
            try:
                count = self.get_session_trade_count()
                return count >= max_trades_per_session
            except Exception:
                return False
        
        def reset_session(self):
            """Reset session counters"""
            try:
                self.last_session_reset = pytime.time()
                session_key = self._get_session_key()
                if session_key in self.trades_by_session:
                    del self.trades_by_session[session_key]
            except Exception:
                pass
        
        def should_check_session_reset(self):
            """Check if session should be reset (based on time)"""
            try:
                time_elapsed = pytime.time() - self.last_session_reset
                # Reset every hour
                return time_elapsed > self.session_duration
            except Exception:
                return False
        
        def _get_session_key(self):
            """Generate session key based on current time"""
            try:
                now = datetime.now()
                return f"{now.year}-{now.month}-{now.day}-{now.hour}"
            except Exception:
                return "default_session"
    
    def get_anti_revenge_filter(): return DummyAntiRevenge()

