# --- CANONICAL SMC ENTRY FUNCTION ---
def main_smc_entry(context):
    """
    Canonical SMC entry logic.
    Returns trade dict or None.
    """
    symbol = context["symbol"]
    price = context["current_price"]

    # 1️⃣ Liquidity sweep is mandatory
    sweep = context.get("liquidity_sweep")
    if not sweep:
        return None

    swept_side = sweep["side"]  # 'buy' or 'sell'

    # 2️⃣ BOS must confirm reversal or continuation intent
    bos = context.get("bos")
    if not bos:
        return None

    # Direction logic
    if swept_side == "sell" and bos["direction"] != "bullish":
        return None
    if swept_side == "buy" and bos["direction"] != "bearish":
        return None

    direction = bos["direction"]

    # 3️⃣ POS / POI must exist
    pos = context.get("pos_zone")
    if not pos:
        return None

    pos_low = pos["low"]
    pos_high = pos["high"]

    # Price must be inside POS
    if not (pos_low <= price <= pos_high):
        return None

    # 4️⃣ Use SMC+Fib for SL/TP calculation (UPGRADED with sweep SL support)
    df = context.get("df")
    atr = context.get("atr", 0.001)
    model_name = context.get("entry_model", "HYDRA")
    sweep_sl_override = context.get("sweep_sl_override")  # From sweep+retest detection
    
    if df is None or len(df) < 100:
        return None  # Need sufficient data for SMC+Fib
    
    idx = len(df) - 1
    trade_direction = "buy" if direction == "bullish" else "sell"
    
    # ⭐ Use ENHANCED SL/TP calculation with sweep override support
    try:
        stop_loss, target, rr_ratio = calculate_smc_fib_sl_tp_with_sweep_override(
            entry_price=price,
            df=df,
            idx=idx,
            direction=trade_direction,
            atr=atr,
            model_name=model_name,
            sweep_sl_override=sweep_sl_override,
            features=context  # Pass full context for additional feature extraction
        )
        
        if stop_loss is None or target is None or rr_ratio < 2.0:
            return None  # SMC+Fib failed or insufficient R:R
    except Exception as e:
        print(f"[SMC_ENTRY] {symbol}: SMC+Fib calculation failed: {e}")
        return None

    # ✅ Trade approved
    return {
        "symbol": symbol,
        "direction": direction,
        "entry": price,
        "stop_loss": stop_loss,
        "take_profit": target,
        "rr": round(rr_ratio, 2),  # Use SMC+Fib R:R
        "reason": "SMC+Fib: Structure SL → Fib extension TP",
        "pos_type": pos["type"],
        "swept_side": swept_side
    }

def build_smc_context(symbol, current_price, df_m15, df_h4, atr, htf_trend="neutral"):
    """
    Build SMC context from available data.
    """
    context = {
        "symbol": symbol,
        "htf_trend": htf_trend,
        "current_price": current_price,
        "atr": atr,
        "buy_side_liquidity": [],
        "sell_side_liquidity": [],
        "liquidity_sweep": None,
        "bos": None,
        "pos_zone": None
    }

    # Try to detect liquidity levels (simplified)
    if df_m15 is not None and len(df_m15) > 20:
        highs = df_m15['high'].tail(20).values
        lows = df_m15['low'].tail(20).values
        context["buy_side_liquidity"] = [max(highs)]  # Nearest resistance
        context["sell_side_liquidity"] = [min(lows)]   # Nearest support

    # Try to detect sweep (simplified - last wick beyond structure)
    if df_m15 is not None and len(df_m15) > 5:
        last_candle = df_m15.iloc[-1]
        prev_high = df_m15['high'].iloc[-2]
        prev_low = df_m15['low'].iloc[-2]
        if last_candle['high'] > prev_high:
            context["liquidity_sweep"] = {"side": "sell", "level": prev_high, "timestamp": last_candle.name}
        elif last_candle['low'] < prev_low:
            context["liquidity_sweep"] = {"side": "buy", "level": prev_low, "timestamp": last_candle.name}

    # Try to detect BOS (simplified - break of structure)
    if df_m15 is not None and len(df_m15) > 10:
        recent_high = df_m15['high'].tail(10).max()
        recent_low = df_m15['low'].tail(10).min()
        if current_price > recent_high:
            context["bos"] = {"direction": "bullish", "level": recent_high, "timestamp": df_m15.index[-1]}
        elif current_price < recent_low:
            context["bos"] = {"direction": "bearish", "level": recent_low, "timestamp": df_m15.index[-1]}

    # Try to detect POS (simplified - recent range)
    if df_m15 is not None and len(df_m15) > 5:
        recent_high = df_m15['high'].tail(5).max()
        recent_low = df_m15['low'].tail(5).min()
        context["pos_zone"] = {"low": recent_low, "high": recent_high, "type": "order_block"}

    return context

# --- TRADE INTENT OBJECT ---
class TradeIntent:
    """
    Captures the complete reasoning behind a trade decision.
    Saved before execution and updated after closure.
    """
    def __init__(self, symbol, direction, model_type, trend_state, rr, sl_reason, tp_reason, 
                 filters_passed, filters_blocked, entry_price=None, confidence=0.0, ticket=None):
        self.symbol = symbol
        self.direction = direction
        self.model_type = model_type
        self.trend_state = trend_state
        self.rr = rr
        self.sl_reason = sl_reason
        self.tp_reason = tp_reason
        self.filters_passed = filters_passed  # list of passed filters
        self.filters_blocked = filters_blocked  # list of blocked filters
        self.entry_price = entry_price
        self.confidence = confidence
        self.ticket = ticket
        self.timestamp_created = datetime.now(timezone.utc)
        self.timestamp_closed = None
        self.exit_reason = None
        self.pnl = None
    
    def to_dict(self):
        return {
            "symbol": self.symbol,
            "direction": self.direction,
            "model_type": self.model_type,
            "trend_state": self.trend_state,
            "rr": self.rr,
            "sl_reason": self.sl_reason,
            "tp_reason": self.tp_reason,
            "filters_passed": self.filters_passed,
            "filters_blocked": self.filters_blocked,
            "entry_price": self.entry_price,
            "confidence": self.confidence,
            "ticket": self.ticket,
            "timestamp_created": self.timestamp_created.isoformat(),
            "timestamp_closed": self.timestamp_closed.isoformat() if self.timestamp_closed else None,
            "exit_reason": self.exit_reason,
            "pnl": self.pnl
        }
    
    def save(self, filename="trade_intents.json"):
        """Append to JSON file"""
        try:
            intents = []
            if os.path.exists(filename):
                with open(filename, 'r') as f:
                    intents = json.load(f)
            intents.append(self.to_dict())
            with open(filename, 'w') as f:
                json.dump(intents, f, indent=2)
        except Exception as e:
            print(f"[TRADE INTENT] Failed to save: {e}")
    
    def update_closed(self, exit_reason, pnl, filename="trade_intents.json"):
        """Update the last intent with closure info"""
        self.timestamp_closed = datetime.now()
        self.exit_reason = exit_reason
        self.pnl = pnl
        self.save(filename)

