def apply_strict_sl_tp_rules(symbol, model_type, direction, entry_price, sl_input=None, tp_input=None,
                             sweep_low=None, sweep_high=None, displacement_low=None, displacement_high=None,
                             pullback_low=None, pullback_high=None, spread=0.0001, max_risk_points=100,
                             rr_target=3.0, trend_strength=0.5, verbose=True):
    """
    Apply strict TP/SL decision tree rules. Overrides pre-calculated SL/TP with decision-tree values.
    
    Args:
        symbol: Trading symbol (for logging)
        model_type: "CHoCH_REVERSAL" or "BOS_CONTINUATION"
        direction: "buy" or "sell"
        entry_price: Entry level
        sl_input, tp_input: Existing SL/TP (ignored; decision tree creates new ones)
        sweep_low/high: Liquidity sweep levels (for CHoCH)
        displacement_low/high: Displacement candle levels
        pullback_low/high: Pullback/OB zone levels (for BOS)
        spread: Current bid-ask spread
        max_risk_points: Max allowed risk in pips
        rr_target: Risk/reward ratio
        verbose: Print decision tree log
        
    Returns:
        dict with keys: "sl", "tp", "risk", "status", "error_reason"
        On success: status="SUCCESS"
        On error: status="REJECTED", error_reason=reason
    """
    # Assert direction is locked and valid
    assert direction in ("buy", "sell"), f"Direction must be 'buy' or 'sell', got: {direction}"
    
    try:
        # Create trade setup
        setup = TradeSetup(
            model=model_type,
            direction=direction,
            entry_price=entry_price,
            sweep_low=sweep_low,
            sweep_high=sweep_high,
            displacement_low=displacement_low,
            displacement_high=displacement_high,
            pullback_low=pullback_low,
            pullback_high=pullback_high,
            spread=spread,
            max_risk_points=max_risk_points,
            rr_target=rr_target,
            symbol=symbol,
            trend_strength=trend_strength
        )
        
        # Execute decision tree (raw logic)
        result = setup.execute_decision_tree()

        # Log if requested
        if verbose:
            log_decision_tree(result, symbol=symbol)

        # If decision tree rejected already, just pass that through
        if result["status"] != "SUCCESS":
            return {
                "status": "REJECTED",
                "sl": None,
                "tp": None,
                "risk": None,
                "error_reason": result.get("error", "Unknown error"),
            }

        # ──────────────────────────────────────────────────────────────
        # HYBRID SL/TP INJECTION (Structure + ATR + Liquidity RR filter)
        # ──────────────────────────────────────────────────────────────
        try:
            # Use the locked direction from signal creation
            if direction not in ("buy", "sell"):
                direction = direction.lower()
            if direction not in ("buy", "sell"):
                raise ValueError(f"Invalid direction: {direction}")

            # Get current price as entry reference
            tick = safe_symbol_info_tick(symbol)
            if not tick:
                raise RuntimeError("No tick data available for entry price")
            current_price = float(tick.ask if direction == "buy" else tick.bid)

            # Load M15 data (use your existing historical loader if available)
            try:
                df_m15 = load_historical_buffer_live(symbol, bars=300, timeframe="M15")
            except Exception as e:
                raise RuntimeError(f"Failed to load M15 data: {e}")

            sl_tp_info = build_sl_tp_for_entry(
                df_m15=df_m15,
                symbol=symbol,
                direction=direction,
                entry_price=current_price,
                atr_multiplier=1.2,   # 1.1–1.3 range
                buffer_atr=0.15,      # 0.1–0.2 ATR buffer
                min_rr=2.0,
                use_auto_scaling_tp=True,
            )

            if not sl_tp_info.get("accept_trade", False):
                logging.info(f"[HYBRID_SLTP] Trade rejected by RR/liquidity filter for {symbol}: {sl_tp_info.get('debug')}")
                return {
                    "status": "REJECTED",
                    "sl": None,
                    "tp": None,
                    "risk": None,
                    "error_reason": "Hybrid SL/TP filter rejected trade (RR < 2 or data issue)",
                }

            sl = sl_tp_info["sl"]
            tp = sl_tp_info["tp"]
            tp1 = sl_tp_info["tp1"]
            tp2 = sl_tp_info["tp2"]
            rr = sl_tp_info["rr"]
            risk_per_unit = sl_tp_info["risk_per_unit"]

            logging.info(
                f"[HYBRID_SLTP] {symbol} {direction.upper()} entry={current_price:.3f} "
                f"SL={sl:.3f} TP={tp:.3f} RR={rr:.2f} "
                f"TP1={tp1 if tp1 is not None else 'n/a'} TP2={tp2 if tp2 is not None else 'n/a'}"
            )

            # You can store tp1/tp2 for later partial-close logic by attaching to result
            result["tp1"] = tp1
            result["tp2"] = tp2
            result["rr"] = rr

            # Return SUCCESS with the HYBRID sl/tp replacing the raw decision-tree ones
            return {
                "status": "SUCCESS",
                "sl": sl,
                "tp": tp,
                "risk": risk_per_unit,  # risk per unit; your lot sizing will use this with account risk
                "error_reason": None,
            }

        except Exception as e:
            logging.error(f"[HYBRID_SLTP_ERROR] {symbol}: {e}")
            # Fallback: if hybrid logic fails, keep original decision-tree SL/TP so bot can still trade
            return {
                "status": "SUCCESS",
                "sl": result["sl"],
                "tp": result["tp"],
                "risk": result["risk"],
                "error_reason": None,
            }

    except Exception as e:
        logging.error(f"[DECISION_TREE_ERROR] {symbol}: {e}")
        return {
            "status": "REJECTED",
            "sl": None,
            "tp": None,
            "risk": None,
            "error_reason": str(e),
        }


