def integrate_scorer_decision(context: dict, execute_trade: callable, symbol: str = None, min_score: float = None):
    """Integrate `bot_scorer_v1.decide_trade` into this bot.

    Args:
        context: dict of signals used by the scorer (see bot_scorer_v1 doc).
        execute_trade: callable(symbol, direction, confidence, metadata) - your executor.
        symbol: optional trading symbol passed to executor.
        min_score: optional override for minimum score required.

    Returns:
        Decision object from scorer or None.
    """
    try:
        # Import locally to avoid hard dependency at module-import time
        from bot_scorer_v1 import decide_trade
    except Exception as e:
        logging.error(f"[SCORER_IMPORT_ERROR] could not import bot_scorer_v1: {e}")
        return None

    try:
        decision = decide_trade(context, min_score=min_score)
    except Exception as e:
        logging.error(f"[SCORER_EVAL_ERROR] error evaluating scorer: {e}")
        return None

    if not decision:
        # No trade recommended
        return None

    # Forward to executor
    try:
        execute_trade(symbol, decision.direction, decision.confidence, decision.metadata)
    except Exception as e:
        logging.error(f"[SCORER_EXECUTE_ERROR] executor raised: {e}")

    return decision

