import pandas as pd

# ──────────────────────────────────────────────────────────────────────────────
# ATR + HYBRID STRUCTURE/ATR SL & LIQUIDITY-ALIGNED TP (M15, GOLD-FOCUSED)
# ──────────────────────────────────────────────────────────────────────────────

def compute_atr(df: pd.DataFrame, period: int = 14) -> float:
    """
    Simple ATR implementation using high/low/close.
    df: M15 DataFrame with columns ['high', 'low', 'close'].
    Returns last ATR value (float). Falls back to std(close) if needed.
    """
    try:
        if df is None or len(df) < period + 2:
            # Fallback to volatility estimate
            return float(df["close"].rolling(14).std().iloc[-1]) if "close" in df else 0.5
        high = df["high"]
        low = df["low"]
        close = df["close"]
        prev_close = close.shift(1)
        tr1 = high - low
        tr2 = (high - prev_close).abs()
        tr3 = (low - prev_close).abs()
        tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
        atr_series = tr.rolling(period, min_periods=period).mean()
        atr = float(atr_series.iloc[-1])
        if atr <= 0 or pd.isna(atr):
            raise ValueError("ATR invalid")
        return atr
    except Exception:
        try:
            return float(df["close"].rolling(14).std().iloc[-1])
        except Exception:
            return 0.5  # conservative default for gold (in dollars)


def _find_recent_swing(df: pd.DataFrame, use_low: bool = True, max_lookback: int = 50):
    """
    Generic swing finder using existing swing_low/swing_high helpers if available.
    Returns (swing_price: float | None).
    """
    if df is None or len(df) < 5:
        return None
    window = df.iloc[-max_lookback:].copy()
    highs = window["high"].values
    lows = window["low"].values
    closes = window["close"].values

    try:
        if use_low:
            mask = swing_low(highs, lows, closes)
        else:
            mask = swing_high(highs, lows, closes)
        # mask can be array-like or single index
        if hasattr(mask, "__len__") and len(mask) == len(window):
            idxs = [i for i, v in enumerate(mask) if v]
            if not idxs:
                return None
            idx_local = idxs[-1]
        else:
            idx_local = int(mask)
    except Exception:
        # fallback naive swing
        idx_local = None
        if use_low:
            for i in range(1, len(window) - 1):
                if lows[i] < lows[i - 1] and lows[i] < lows[i + 1]:
                    idx_local = i
        else:
            for i in range(1, len(window) - 1):
                if highs[i] > highs[i - 1] and highs[i] > highs[i + 1]:
                    idx_local = i
        if idx_local is None:
            return None

    if use_low:
        return float(window.iloc[idx_local]["low"])
    else:
        return float(window.iloc[idx_local]["high"])


def get_recent_swing_low_m15(df_m15: pd.DataFrame, max_lookback: int = 50) -> float | None:
    """Return most recent valid M15 swing low or None."""
    return _find_recent_swing(df_m15, use_low=True, max_lookback=max_lookback)


def get_recent_swing_high_m15(df_m15: pd.DataFrame, max_lookback: int = 50) -> float | None:
    """Return most recent valid M15 swing high or None."""
    return _find_recent_swing(df_m15, use_low=False, max_lookback=max_lookback)


def compute_hybrid_sl(
    direction: str,
    entry_price: float,
    atr_m15: float,
    last_swing_low: float | None = None,
    last_swing_high: float | None = None,
    df_m15: pd.DataFrame | None = None,
    atr_multiplier: float = 1.2,
    buffer_atr: float = 0.15,
) -> float:
    """
    Hybrid SL logic (structure + ATR).
    BUY:
      1) structural_sl = last_swing_low - buffer_atr * ATR
      2) atr_sl = entry - atr_multiplier * ATR
      SL = min(structural_sl, atr_sl)
    SELL:
      1) structural_sl = last_swing_high + buffer_atr * ATR
      2) atr_sl = entry + atr_multiplier * ATR
      SL = max(structural_sl, atr_sl)
    If structure missing, fall back to pure ATR SL.
    """
    direction = direction.lower()
    risk_atr = max(atr_m15, 0.1)  # safety floor for gold

    if direction == "buy":
        atr_sl = float(entry_price) - atr_multiplier * risk_atr
        # Prefer sweep low if available (FIX #4). Falls back to last_swing_low.
        structural_ref = None
        try:
            if df_m15 is not None:
                sweep_info = has_bullish_sweep_reclaim(df_m15, entry_price, max_lookback=50)
                if sweep_info and sweep_info.get("passed") and sweep_info.get("sweep_low") is not None:
                    structural_ref = float(sweep_info.get("sweep_low"))
        except Exception:
            structural_ref = None

        if structural_ref is None:
            structural_ref = last_swing_low

        if structural_ref is not None:
            structural_sl = float(structural_ref) - buffer_atr * risk_atr
            return min(structural_sl, atr_sl)
        return atr_sl
    elif direction == "sell":
        atr_sl = float(entry_price) + atr_multiplier * risk_atr
        # Prefer sweep high if available (FIX #4). Falls back to last_swing_high.
        structural_ref = None
        try:
            if df_m15 is not None:
                sweep_info = has_bearish_sweep_reclaim(df_m15, entry_price, max_lookback=50)
                if sweep_info and sweep_info.get("passed") and sweep_info.get("sweep_high") is not None:
                    structural_ref = float(sweep_info.get("sweep_high"))
        except Exception:
            structural_ref = None

        if structural_ref is None:
            structural_ref = last_swing_high

        if structural_ref is not None:
            structural_sl = float(structural_ref) + buffer_atr * risk_atr
            return max(structural_sl, atr_sl)
        return atr_sl
    else:
        raise ValueError(f"Unknown direction: {direction}")


def compute_rr(direction: str, entry_price: float, sl: float, tp: float) -> float:
    """RR = (TP − Entry) / (Entry − SL) with sign-aware logic for buy/sell."""
    direction = direction.lower()
    if direction == "buy":
        risk = entry_price - sl
        reward = tp - entry_price
    else:  # sell
        risk = sl - entry_price
        reward = entry_price - tp
    if risk <= 0:
        return 0.0
    return float(reward / risk)


def _is_forex_symbol(symbol: str) -> bool:
    """
    Very simple FX detector.
    Adjust list as needed for your broker (add indices/crypto if you want them treated differently).
    """
    if not symbol:
        return False
    s = symbol.upper()
    # Common metals / CFDs to EXCLUDE from forex logic
    non_fx = ("XAU", "XAG", "OIL", "WTI", "BRENT", "US500", "NAS100", "DE40", "JP225")
    if any(tag in s for tag in non_fx):
        return False
    # Simple heuristic: FX pairs are usually 6 letters, no digits
    return len(s) == 6 and s.isalpha()

def _round_liquidity_level_gold(price: float) -> float:
    """
    Round gold price to nearest 0 or 50 (e.g. 2384 → 2385, 2387 → 2390).
    Assumes price is in dollars (not points).
    """
    # Many brokers quote XAUUSD with 2 or 3 decimals; operate on whole dollars
    whole = round(price)
    # nearest 0 or 50
    remainder = whole % 50
    if remainder < 25:
        lvl = whole - remainder
    else:
        lvl = whole + (50 - remainder)
    return float(lvl)


def _round_liquidity_level_fx(price: float, pip_size: float = 0.0001, step_pips: int = 25) -> float:
    """
    Round FX price to nearest `step_pips` block.
      - pip_size = 0.0001 for most majors, 0.01 for JPY pairs.
      - step_pips = 25 ⇒ 0, 25, 50, 75 pip grid.
    """
    try:
        pip_price = price / pip_size
        step = float(step_pips)
        rounded_pips = round(pip_price / step) * step
        return rounded_pips * pip_size
    except Exception:
        return float(price)


def find_nearest_liquidity_tp(
    df_m15: pd.DataFrame,
    symbol: str,
    direction: str,
    entry_price: float,
    sl: float,
    min_rr: float = 2.0,
    max_rr: float = 5.0,
) -> dict:
    """
    Liquidity-aligned TP selection:

      Priority:
        1) Previous session high/low
        2) Equal highs/lows
        3) Untested M15 swing high/low
        4) Round numbers (00 / 50 for gold, 25–50pip grid for FX)

    Constraints:
        - Must give RR >= min_rr
    Returns:
      {
        "accepted": bool,
        "tp": float | None,
        "rr": float | None,
        "reason": str,
        "levels_considered": [...]
      }
    """
    direction = direction.lower()
    levels = []
    reason = ""
    df = df_m15.copy()

    # --- symbol-specific tuning (FX vs Gold/CFD) ---
    is_fx = _is_forex_symbol(symbol)
    # FX usually smaller ATR, so demand slightly higher min RR by default
    if is_fx and min_rr < 2.5:
        min_rr = 2.5

    if df is None or len(df) < 20:
        return {"accepted": False, "tp": None, "rr": None, "reason": "not_enough_m15_bars", "levels_considered": []}

    # 1) Previous session high/low (simple: previous day)
    try:
        df["date"] = pd.to_datetime(df["time"]).dt.date if "time" in df else df.index.date
        last_date = df["date"].iloc[-1]
        prev_session = df[df["date"] < last_date]
        if len(prev_session) > 0:
            prev_high = float(prev_session["high"].max())
            prev_low = float(prev_session["low"].min())
            if direction == "buy":
                levels.append(("prev_session_high", prev_high))
            else:
                levels.append(("prev_session_low", prev_low))
    except Exception:
        pass

    # 2) Equal highs / lows (simple: near-equal recent extremes)
    try:
        window = df.tail(80)
        tolerance = compute_atr(df) * 0.1  # equal = within 0.1 ATR
        if direction == "buy":
            highs = window["high"]
            max_high = highs.max()
            # any other highs within tolerance of max_high => equal highs zone
            eq_highs = highs[(max_high - highs).abs() <= tolerance]
            if len(eq_highs) >= 2:
                levels.append(("equal_highs", float(eq_highs.mean())))
        else:
            lows = window["low"]
            min_low = lows.min()
            eq_lows = lows[(lows - min_low).abs() <= tolerance]
            if len(eq_lows) >= 2:
                levels.append(("equal_lows", float(eq_lows.mean())))
    except Exception:
        pass

    # 3) Untested M15 swing high/low (most recent swing in direction)
    try:
        if direction == "buy":
            swing_price = get_recent_swing_high_m15(df)
            if swing_price is not None and swing_price > entry_price:
                levels.append(("swing_high", swing_price))
        else:
            swing_price = get_recent_swing_low_m15(df)
            if swing_price is not None and swing_price < entry_price:
                levels.append(("swing_low", swing_price))
    except Exception:
        pass

    # 4) Round numbers (symbol-aware)
    try:
        if is_fx:
            # Heuristic pip size: treat JPY pairs as 0.01, others as 0.0001
            s = symbol.upper() if symbol else ""
            pip_size = 0.01 if s.endswith("JPY") else 0.0001
            round_level = _round_liquidity_level_fx(entry_price, pip_size=pip_size, step_pips=25)
        else:
            round_level = _round_liquidity_level_gold(entry_price)

        if direction == "buy":
            if round_level <= entry_price:
                # push to next block
                if is_fx:
                    # +25 pips
                    round_level = _round_liquidity_level_fx(entry_price + 25 * (0.01 if pip_size == 0.01 else 0.0001),
                                                            pip_size=pip_size,
                                                            step_pips=25)
                else:
                    round_level += 50.0
        else:
            if round_level >= entry_price:
                if is_fx:
                    round_level = _round_liquidity_level_fx(entry_price - 25 * (0.01 if pip_size == 0.01 else 0.0001),
                                                            pip_size=pip_size,
                                                            step_pips=25)
                else:
                    round_level -= 50.0

        levels.append(("round_number", round_level))
    except Exception:
        pass

    # Evaluate levels in order, choose the closest that satisfies RR
    evaluated = []
    chosen_tp = None
    chosen_rr = None
    for label, lvl in levels:
        rr = compute_rr(direction, entry_price, sl, lvl)
        evaluated.append((label, float(lvl), rr))
        if rr >= min_rr:
            chosen_tp = float(lvl)
            chosen_rr = rr
            reason = f"chosen_{label}_rr_{rr:.2f}"
            break

    if chosen_tp is None:
        return {
            "accepted": False,
            "tp": None,
            "rr": None,
            "reason": "nearest_liquidity_rr_below_min",
            "levels_considered": evaluated,
        }

    # Cap RR if excessively far (optional safety)
    if chosen_rr > max_rr:
        # clamp TP to max_rr line:
        risk = abs(entry_price - sl)
        if direction == "buy":
            chosen_tp = entry_price + max_rr * risk
        else:
            chosen_tp = entry_price - max_rr * risk
        chosen_rr = max_rr
        reason += "_clamped_to_max_rr"

    return {
        "accepted": True,
        "tp": chosen_tp,
        "rr": chosen_rr,
        "reason": reason,
        "levels_considered": evaluated,
    }


def build_sl_tp_for_entry(
    df_m15: pd.DataFrame,
    symbol: str,
    direction: str,
    entry_price: float,
    atr_multiplier: float = 1.2,
    buffer_atr: float = 0.15,
    min_rr: float = 2.0,
    use_auto_scaling_tp: bool = True,
) -> dict:
    """
    High-level wrapper implementing the full logic:

      1) Compute ATR (M15).
      2) Find last M15 swing low/high.
      3) Build hybrid SL (structure + ATR).
      4) Find liquidity-aligned TP with RR >= min_rr.
      5) Optionally output TP1/TP2 for scaled exits (1:2 & 1:3 RR).

    Returns:
      {
        "accept_trade": bool,
        "sl": float | None,
        "tp": float | None,
        "rr": float | None,
        "tp1": float | None,
        "tp2": float | None,
        "risk_per_unit": float | None,
        "debug": dict
      }
    """
    direction = direction.lower()
    debug = {}

    # --- symbol-aware tuning ---
    is_fx = _is_forex_symbol(symbol)
    if is_fx:
        # For FX: slightly wider ATR SL and structural buffer, higher min RR
        if atr_multiplier < 1.5:
            atr_multiplier = 1.5
        if buffer_atr < 0.25:
            buffer_atr = 0.25
        if min_rr < 2.5:
            min_rr = 2.5

    try:
        atr_m15 = compute_atr(df_m15)
        debug["atr_m15"] = atr_m15

        last_swing_low = get_recent_swing_low_m15(df_m15)
        last_swing_high = get_recent_swing_high_m15(df_m15)
        debug["last_swing_low"] = last_swing_low
        debug["last_swing_high"] = last_swing_high

        sl = compute_hybrid_sl(
            direction=direction,
            entry_price=entry_price,
            atr_m15=atr_m15,
            last_swing_low=last_swing_low,
            last_swing_high=last_swing_high,
            df_m15=df_m15,
            atr_multiplier=atr_multiplier,
            buffer_atr=buffer_atr,
        )
        debug["hybrid_sl"] = sl

        liq_tp_info = find_nearest_liquidity_tp(
            df_m15=df_m15,
            symbol=symbol,
            direction=direction,
            entry_price=entry_price,
            sl=sl,
            min_rr=min_rr,
        )
        debug["liquidity_tp_info"] = liq_tp_info

        if not liq_tp_info.get("accepted", False):
            # trade should be skipped if nearest liquidity doesn’t give RR >= min_rr
            return {
                "accept_trade": False,
                "sl": None,
                "tp": None,
                "rr": None,
                "tp1": None,
                "tp2": None,
                "risk_per_unit": None,
                "debug": debug,
            }

        tp = float(liq_tp_info["tp"])
        rr = float(liq_tp_info["rr"])

        # risk per unit (in price units)
        if direction == "buy":
            risk = entry_price - sl
        else:
            risk = sl - entry_price
        risk = float(abs(risk))
        debug["risk"] = risk

        if risk <= 0:
            return {
                "accept_trade": False,
                "sl": None,
                "tp": None,
                "rr": None,
                "tp1": None,
                "tp2": None,
                "risk_per_unit": None,
                "debug": debug,
            }

        # Auto-scaling TP zones
        if use_auto_scaling_tp:
            tp1_rr = 2.0
            tp2_rr = 3.0
            if direction == "buy":
                tp1 = entry_price + tp1_rr * risk
                tp2 = entry_price + tp2_rr * risk
            else:
                tp1 = entry_price - tp1_rr * risk
                tp2 = entry_price - tp2_rr * risk
        else:
            tp1 = None
            tp2 = None

        return {
            "accept_trade": True,
            "sl": float(sl),
            "tp": float(tp),
            "rr": rr,
            "tp1": float(tp1) if tp1 is not None else None,
            "tp2": float(tp2) if tp2 is not None else None,
            "risk_per_unit": risk,
            "debug": debug,
        }

    except Exception as e:
        debug["error"] = str(e)
        return {
            "accept_trade": False,
            "sl": None,
            "tp": None,
            "rr": None,
            "tp1": None,
            "tp2": None,
            "risk_per_unit": None,
            "debug": debug,
        }

# ──────────────────────────────────────────────────────────────────────────────
# SWEEP → RECLAIM ENTRY FILTERS (BUY + SELL)
# ──────────────────────────────────────────────────────────────────────────────

def find_recent_pullback_low(df: pd.DataFrame, max_lookback: int = 30):
    if df is None or len(df) < 5:
        return None, None
    window = df.iloc[-max_lookback:].copy()
    lows = window["low"].values
    try:
        mask = swing_low(window["high"].values, lows, window["close"].values)
        if hasattr(mask, "__len__") and len(mask) == len(window):
            swing_indices = [i for i, v in enumerate(mask) if v]
            if not swing_indices:
                return None, None
            idx_local = swing_indices[-1]
        else:
            idx_local = int(mask)
    except Exception:
        idx_local = None
        for i in range(1, len(window) - 1):
            if lows[i] < lows[i - 1] and lows[i] < lows[i + 1]:
                idx_local = i
        if idx_local is None:
            return None, None
    idx_global = window.index[idx_local]
    return idx_global, float(window.loc[idx_global, "low"])


def find_recent_pullback_high(df: pd.DataFrame, max_lookback: int = 30):
    if df is None or len(df) < 5:
        return None, None
    window = df.iloc[-max_lookback:].copy()
    highs = window["high"].values
    try:
        mask = swing_high(highs, window["low"].values, window["close"].values)
        if hasattr(mask, "__len__") and len(mask) == len(window):
            swing_indices = [i for i, v in enumerate(mask) if v]
            if not swing_indices:
                return None, None
            idx_local = swing_indices[-1]
        else:
            idx_local = int(mask)
    except Exception:
        idx_local = None
        for i in range(1, len(window) - 1):
            if highs[i] > highs[i - 1] and highs[i] > highs[i + 1]:
                idx_local = i
        if idx_local is None:
            return None, None
    idx_global = window.index[idx_local]
    return idx_global, float(window.loc[idx_global, "high"])


def has_bullish_sweep_reclaim(df: pd.DataFrame, current_price: float, max_lookback: int = 30) -> dict:
    """ADVANCED BULLISH SWEEP + RECLAIM DETECTION
    Detects: full sweeps, partial sweeps, wick sweeps, structure sweeps"""
    result = {
        "passed": False,
        "pullback_idx": None,
        "pullback_low": None,
        "sweep_low": None,
        "reclaim_close": None,
        "sweep_row_idx": None,
        "sweep_type": None,
        "reason": "",
    }

    if df is None or len(df) < 5:
        result["reason"] = "not_enough_bars"
        return result

    try:
        recent_df = df.iloc[-max_lookback:].copy()
        
        # STRATEGY 1: Classic swing low
        pullback_idx, pullback_low = find_recent_pullback_low(df, max_lookback=max_lookback)
        
        # STRATEGY 2: Use structure low if no pullback found
        if pullback_idx is None:
            recent_lows = recent_df["low"].values
            min_idx = len(recent_lows) - 1 - np.argmin(recent_lows[::-1])
            pullback_low = float(recent_lows[min_idx])
            pullback_idx = recent_df.index[min_idx]
        
        result["pullback_idx"] = pullback_idx
        result["pullback_low"] = pullback_low

        df_after = df.loc[pullback_idx:]
        if len(df_after) < 3:
            return result

        sweep_row_idx = None
        sweep_low_price = None
        sweep_type = None

        # Look for different types of sweeps
        for idx, row in df_after.iloc[1:].iterrows():
            current_low = float(row["low"])
            current_close = float(row["close"])
            
            # FULL SWEEP: Breaks swing low completely
            if current_low < pullback_low and sweep_row_idx is None:
                sweep_row_idx = idx
                sweep_low_price = current_low
                sweep_type = "full_sweep"
                break
            
            # PARTIAL SWEEP: 99.5%+ of level (just barely below)
            elif sweep_row_idx is None and current_low < pullback_low * 0.9995:
                sweep_row_idx = idx
                sweep_low_price = current_low
                sweep_type = "partial_sweep"
                break

        # WICK SWEEP: Low breaks but close closes above
        if sweep_row_idx is None:
            for idx, row in df_after.iloc[1:].iterrows():
                if float(row["low"]) < pullback_low and float(row["close"]) > pullback_low:
                    sweep_row_idx = idx
                    sweep_low_price = float(row["low"])
                    sweep_type = "wick_sweep"
                    break

        if sweep_row_idx is None:
            result["reason"] = "no_sweep_detected"
            return result

        result["sweep_low"] = sweep_low_price
        result["sweep_row_idx"] = sweep_row_idx
        result["sweep_type"] = sweep_type

        # RECLAIM: Multiple strategies
        reclaim_close = None
        df_reclaim = df.loc[sweep_row_idx:]

        # Strategy A: Immediate close above
        for idx, row in df_reclaim.iterrows():
            if float(row["close"]) > pullback_low:
                reclaim_close = float(row["close"])
                break

        # Strategy B: Current price above
        if reclaim_close is None and current_price is not None:
            if float(current_price) > pullback_low:
                reclaim_close = float(current_price)

        # Strategy C: Wick above (high touches above even if close below)
        if reclaim_close is None:
            for idx, row in df_reclaim.iloc[:10].iterrows():
                if float(row["high"]) > pullback_low:
                    reclaim_close = float(row["high"])
                    break

        if reclaim_close is None:
            result["reason"] = "no_reclaim_detected"
            return result

        result["reclaim_close"] = reclaim_close
        result["reason"] = f"ok_{sweep_type}"
        result["passed"] = True
        return result

    except Exception as e:
        result["reason"] = f"error: {str(e)}"
        return result


def has_bearish_sweep_reclaim(df: pd.DataFrame, current_price: float, max_lookback: int = 30) -> dict:
    """ADVANCED BEARISH SWEEP + RECLAIM DETECTION
    Detects: full sweeps, partial sweeps, wick sweeps, structure sweeps"""
    result = {
        "passed": False,
        "pullback_idx": None,
        "pullback_high": None,
        "sweep_high": None,
        "reclaim_close": None,
        "sweep_row_idx": None,
        "sweep_type": None,
        "reason": "",
    }

    if df is None or len(df) < 5:
        result["reason"] = "not_enough_bars"
        return result

    try:
        recent_df = df.iloc[-max_lookback:].copy()
        
        # STRATEGY 1: Classic swing high
        pullback_idx, pullback_high = find_recent_pullback_high(df, max_lookback=max_lookback)
        
        # STRATEGY 2: Use structure high if no pullback found
        if pullback_idx is None:
            recent_highs = recent_df["high"].values
            max_idx = len(recent_highs) - 1 - np.argmax(recent_highs[::-1])
            pullback_high = float(recent_highs[max_idx])
            pullback_idx = recent_df.index[max_idx]
        
        result["pullback_idx"] = pullback_idx
        result["pullback_high"] = pullback_high

        df_after = df.loc[pullback_idx:]
        if len(df_after) < 3:
            return result

        sweep_row_idx = None
        sweep_high_price = None
        sweep_type = None

        # Look for different types of sweeps
        for idx, row in df_after.iloc[1:].iterrows():
            current_high = float(row["high"])
            current_close = float(row["close"])
            
            # FULL SWEEP: Breaks swing high completely
            if current_high > pullback_high and sweep_row_idx is None:
                sweep_row_idx = idx
                sweep_high_price = current_high
                sweep_type = "full_sweep"
                break
            
            # PARTIAL SWEEP: 99.95%+ of level (just barely above)
            elif sweep_row_idx is None and current_high > pullback_high * 1.0005:
                sweep_row_idx = idx
                sweep_high_price = current_high
                sweep_type = "partial_sweep"
                break

        # WICK SWEEP: High breaks but close closes below
        if sweep_row_idx is None:
            for idx, row in df_after.iloc[1:].iterrows():
                if float(row["high"]) > pullback_high and float(row["close"]) < pullback_high:
                    sweep_row_idx = idx
                    sweep_high_price = float(row["high"])
                    sweep_type = "wick_sweep"
                    break

        if sweep_row_idx is None:
            result["reason"] = "no_sweep_detected"
            return result

        result["sweep_high"] = sweep_high_price
        result["sweep_row_idx"] = sweep_row_idx
        result["sweep_type"] = sweep_type

        # RECLAIM: Multiple strategies
        reclaim_close = None
        df_reclaim = df.loc[sweep_row_idx:]

        # Strategy A: Immediate close below
        for idx, row in df_reclaim.iterrows():
            if float(row["close"]) < pullback_high:
                reclaim_close = float(row["close"])
                break

        # Strategy B: Current price below
        if reclaim_close is None and current_price is not None:
            if float(current_price) < pullback_high:
                reclaim_close = float(current_price)

        # Strategy C: Wick below (low touches below even if close above)
        if reclaim_close is None:
            for idx, row in df_reclaim.iloc[:10].iterrows():
                if float(row["low"]) < pullback_high:
                    reclaim_close = float(row["low"])
                    break

        if reclaim_close is None:
            result["reason"] = "no_reclaim_detected"
            return result

        result["reclaim_close"] = reclaim_close
        result["reason"] = f"ok_{sweep_type}"
        result["passed"] = True
        return result

    except Exception as e:
        result["reason"] = f"error: {str(e)}"
        return result
    return result


def displacement_close_beyond_prev_high(df_m15: pd.DataFrame, sweep_row_idx, direction: str, lookahead: int = None, tolerance_pct: float = 0.0) -> bool:
    """
    After a sweep row index, require that a subsequent M15 closed candle closes beyond
    the previous M15 extreme (high for BUY, low for SELL) by an optional tolerance.
    `lookahead` limits how many bars to scan after the sweep (None = unlimited).
    `tolerance_pct` is relative (e.g. 0.001 = 0.1%). Returns True if displacement-close found.
    """
    try:
        if df_m15 is None or len(df_m15) < 5:
            return False
        # locate integer position of sweep row in df_m15 index
        try:
            pos = df_m15.index.get_loc(sweep_row_idx)
        except Exception:
            pos = None
            for i, idx in enumerate(df_m15.index):
                if idx == sweep_row_idx:
                    pos = i
                    break
            if pos is None:
                return False

        # previous extreme before sweep
        if pos <= 0:
            return False
        prev_segment = df_m15.iloc[:pos]
        if direction == "buy":
            prev_extreme = float(prev_segment["high"].max())
            threshold = prev_extreme * (1.0 + float(tolerance_pct or 0.0))
            start = pos + 1
            end = len(df_m15) if lookahead is None else min(len(df_m15), pos + 1 + int(lookahead))
            for i in range(start, end):
                if float(df_m15["close"].iloc[i]) > threshold:
                    return True
            return False
        else:
            prev_extreme = float(prev_segment["low"].min())
            threshold = prev_extreme * (1.0 - float(tolerance_pct or 0.0))
            start = pos + 1
            end = len(df_m15) if lookahead is None else min(len(df_m15), pos + 1 + int(lookahead))
            for i in range(start, end):
                if float(df_m15["close"].iloc[i]) < threshold:
                    return True
            return False
    except Exception:
        return False


def assess_volatility_regime(df_m15: pd.DataFrame, lookback: int = 100, atr_period: int = 14, low_pct: float = 20.0, high_pct: float = 80.0):
    """
    Assess volatility regime on M15 using ATR percentile over recent history.
    Returns dict: {'regime': 'quiet'|'normal'|'wild', 'atr': float, 'low_thresh': float, 'high_thresh': float, 'percentile': float}
    """
    try:
        import numpy as _np
        if df_m15 is None or len(df_m15) < atr_period + 2:
            return {"regime": "unknown", "atr": 0.0, "low_thresh": 0.0, "high_thresh": 0.0, "percentile": 0.0}
        atr_series = df_m15['close'].rolling(atr_period).std().dropna()
        if atr_series.empty:
            return {"regime": "unknown", "atr": 0.0, "low_thresh": 0.0, "high_thresh": 0.0, "percentile": 0.0}
        hist = atr_series.tail(min(len(atr_series), int(lookback)))
        current_atr = float(atr_series.iloc[-1])
        low_thresh = float(_np.percentile(hist, float(low_pct)))
        high_thresh = float(_np.percentile(hist, float(high_pct)))
        # percentile of current ATR relative to hist
        perc = float((_np.sum(hist < current_atr) / float(len(hist))) * 100.0)
        if current_atr <= low_thresh:
            regime = 'quiet'
        elif current_atr >= high_thresh:
            regime = 'wild'
        else:
            regime = 'normal'
        return {"regime": regime, "atr": current_atr, "low_thresh": low_thresh, "high_thresh": high_thresh, "percentile": perc}
    except Exception:
        return {"regime": "unknown", "atr": 0.0, "low_thresh": 0.0, "high_thresh": 0.0, "percentile": 0.0}


