def enforce_lot_cap(symbol, lot):
    """
    ✅ GLOBAL LOT ENFORCER: Caps lot size at SYMBOL_MAX_LOT[symbol]
    **NEVER EXCEEDS** your configured maximum, regardless of dynamic scaling.
    
    Usage: lot = enforce_lot_cap(symbol, lot)
    """
    try:
        base_sym = symbol.upper().split('.')[0]
        max_allowed = SYMBOL_MAX_LOT.get(base_sym, MAX_LOT_SIZE)
        capped_lot = min(float(lot), float(max_allowed))
        if capped_lot < lot:
            # Silently cap (don't spam logs, but it's enforced)
            pass
        return capped_lot
    except Exception:
        return float(lot)

