# Broker symbol aliases: map canonical symbol -> broker-specific name
# Example: many brokers expose gold as "GOLD" or "gold" instead of XAUUSD
# You can override this via your `config` object by setting `BROKER_SYMBOL_ALIASES`.
BROKER_SYMBOL_ALIASES = getattr(config, 'BROKER_SYMBOL_ALIASES', {'XAUUSD': 'GOLD'}) if 'config' in globals() and config else {'XAUUSD': 'GOLD'}

def _normalize_alias_name(name: str) -> str:
    """Normalize a symbol/alias for comparison (upper-case, strip common suffixes)."""
    if not name:
        return ''
    n = str(name).upper()
    # remove common suffixes/prefixes used by some brokers
    for suf in ('.M', '.PRO', '.ECN', '.MINI', '.STD', '.FX', '.I', '.R', '.S'):
        if n.endswith(suf):
            n = n[:-len(suf)]
    for pre in ('FX.', 'CFD.', 'PRO.', 'ECN.', 'MINI.', 'STD.'):
        if n.startswith(pre):
            n = n[len(pre):]
    return n

# --- Symbol canonicalization + opposite-position guard ---
def _canonical_symbol(sym):
    """Return canonical symbol name used for comparison (e.g. XAUUSD, EURUSD)."""
    try:
        s = _normalize_alias_name(sym).upper()
        if '.' in s:
            s = s.split('.')[0]
        try:
            rev = {v.upper(): k.upper() for k, v in BROKER_SYMBOL_ALIASES.items()}
            if s in rev:
                s = rev[s]
        except Exception:
            pass
        if s == 'GOLD':
            s = 'XAUUSD'
        return s
    except Exception:
        return str(sym).upper()

def generate_ema_crossover_signal(df, fast_period=20, slow_period=50):
    """
    Generate EMA 20/50 crossover signals (backtest validated: 50% win rate with filters).
    
    Returns:
        dict: {
            'signal': 'buy' | 'sell' | 'none',
            'confidence': 0.0-1.0,
            'reason': str,
            'ema_fast': float,
            'ema_slow': float
        }
    """
    try:
        if df is None or len(df) < max(fast_period, slow_period) + 2:
            return {'signal': 'none', 'confidence': 0.0, 'reason': 'Insufficient data', 'ema_fast': 0, 'ema_slow': 0}
        
        # Calculate EMAs
        ema_fast = df['close'].ewm(span=fast_period, adjust=False).mean()
        ema_slow = df['close'].ewm(span=slow_period, adjust=False).mean()
        
        # Check for crossover
        current_fast = ema_fast.iloc[-1]
        current_slow = ema_slow.iloc[-1]
        prev_fast = ema_fast.iloc[-2]
        prev_slow = ema_slow.iloc[-2]
        
        signal = 'none'
        confidence = 0.0
        reason = 'No crossover'
        
        # Bullish crossover: fast crosses above slow
        if current_fast > current_slow and prev_fast <= prev_slow:
            signal = 'buy'
            # Confidence based on separation and momentum
            separation = abs(current_fast - current_slow) / current_slow * 100
            momentum = (current_fast - prev_fast) / prev_fast * 100
            confidence = min(0.95, 0.65 + (separation * 2) + (momentum * 0.5))
            reason = f"EMA {fast_period} crossed above EMA {slow_period} (separation: {separation:.2f}%, momentum: {momentum:.2f}%)"
        
        # Bearish crossover: fast crosses below slow
        elif current_fast < current_slow and prev_fast >= prev_slow:
            signal = 'sell'
            # Confidence based on separation and momentum
            separation = abs(current_fast - current_slow) / current_slow * 100
            momentum = abs(current_fast - prev_fast) / prev_fast * 100
            confidence = min(0.95, 0.65 + (separation * 2) + (momentum * 0.5))
            reason = f"EMA {fast_period} crossed below EMA {slow_period} (separation: {separation:.2f}%, momentum: {momentum:.2f}%)"
        
        return {
            'signal': signal,
            'confidence': confidence,
            'reason': reason,
            'ema_fast': current_fast,
            'ema_slow': current_slow
        }
    
    except Exception as e:
        return {'signal': 'none', 'confidence': 0.0, 'reason': f'Error: {e}', 'ema_fast': 0, 'ema_slow': 0}

def has_open_opposite_position(symbol, direction):
    """
    True if an open position exists for the same canonical symbol in the opposite direction.
    direction: 'buy' or 'sell'
    """
    try:
        base = _canonical_symbol(symbol)
        positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else [])
        if not positions:
            return False
        for p in positions:
            p_sym = getattr(p, 'symbol', None) or getattr(p, 'name', '')
            if _canonical_symbol(p_sym) != base:
                continue
            p_type = getattr(p, 'type', None)
            if p_type is None:
                continue
            # mt5.ORDER_TYPE_BUY == 0, ORDER_TYPE_SELL == 1
            try:
                buy_type = getattr(mt5, 'ORDER_TYPE_BUY', 0)
                sell_type = getattr(mt5, 'ORDER_TYPE_SELL', 1)
                if int(p_type) == int(buy_type):
                    p_dir = 'buy'
                elif int(p_type) == int(sell_type):
                    p_dir = 'sell'
                else:
                    p_dir = None
            except Exception:
                p_dir = None
            if p_dir and p_dir != direction:
                return True
        return False
    except Exception:
        return False

