# Tracks last structure direction per symbol and enforces:
# 1. One-direction rule: Once bias set → only that direction allowed
# 2. Cooldown: 1 trade per structure leg
# 3. Kill switch: If opposite structure break → flatten & stop trading

SYMBOL_BIAS_TRACKER = {}  # Format: {symbol: {'bias': 'buy'/'sell', 'last_trade_time': datetime, 'leg_count': int}}

def set_symbol_bias(symbol, direction):
    """Set or update symbol bias direction (thread-safe)."""
    global SYMBOL_BIAS_TRACKER
    with SYMBOL_BIAS_LOCK:  # ⚠️ THREAD-SAFE: Acquire lock before modifying
        now = datetime.now()
        
        if symbol not in SYMBOL_BIAS_TRACKER:
            SYMBOL_BIAS_TRACKER[symbol] = {'bias': direction, 'last_trade_time': now, 'leg_count': 1}
        else:
            # Check if direction changed (kill switch trigger)
            if SYMBOL_BIAS_TRACKER[symbol]['bias'] != direction:
                SYMBOL_BIAS_TRACKER[symbol] = {'bias': direction, 'last_trade_time': now, 'leg_count': 1}
            else:
                SYMBOL_BIAS_TRACKER[symbol]['leg_count'] += 1
                SYMBOL_BIAS_TRACKER[symbol]['last_trade_time'] = now

def check_bias_and_cooldown(symbol, direction, cooldown_minutes=30):
    """
    Check if trade allowed based on one-direction rule and cooldown.
    
    ✅ FIX 5: BIAS PERSISTENCE
    - Bias only resets when HTF BOS breaks or opposite structure confirmed
    - Not per loop, but stays until structural reason to change
    
    Returns: (bool, str) - (is_allowed, reason)
    """
    # Only block if there is actually an open position in the opposite direction
    try:
        if has_open_opposite_position(symbol, direction):
            return False, f"Opposite entry blocked: open position exists for {symbol} in the opposite direction of {direction}"
    except Exception:
        pass  # If position check fails, do not block
    return True, None

