def get_pip_value(symbol, price=None, lot=1.0):
    """Return approximate pip value in account currency per lot for given symbol.
    This is a heuristic mapping used for lot-sizing calculations.

    Args:
        symbol: instrument symbol, e.g. 'XAUUSD'.
        price:  optional, kept for backwards compatibility (ignored).
        lot:    lot size to scale pip value by (default 1.0).
    """
    s = str(symbol).upper()
    # XAU/XAG approximate pip (point) value per lot in USD-equivalent
    if s.startswith('XAU') or s.startswith('XAG'):
        return 1.0 * float(lot)
    # JPY pairs: pip = 0.01; value per lot slightly different
    if 'JPY' in s:
        return 9.1 * float(lot)
    # Default for most forex majors (pip 0.0001)
    return 10.0 * float(lot)

def calculate_lot_size(balance, equity, symbol, stop_loss_pips=None, risk_pct=None):
    """Compute lot size using equity (preferred) or balance fallback.
    - `stop_loss_pips` should be the stop size in pips (int/float). If None, conservative defaults are used.
    - `risk_pct` overrides global MAX_RISK_PER_TRADE_PCT if provided.
    Returns a float lot size rounded to the broker step (uses `round_lot_to_step`).
    
    KEY: Uses SYMBOL_MAX_LOT as the base for dynamic scaling (NOT risk-based calculation).
    Dynamic sizing scales FROM this base by confluence/RR, never going below it.
    """
    try:
        # ✅ Get the static lot from SYMBOL_MAX_LOT as the PRIMARY base
        try:
            base = symbol.upper().split('.')[0]
        except Exception:
            base = symbol.upper()
        base_lot = SYMBOL_MAX_LOT.get(base, MAX_LOT_SIZE)
        
        # Return this as the primary lot (dynamic sizing will scale from this in other functions)
        return round_lot_to_step(float(base_lot), symbol)
        
    except Exception:
        return 0.01
        return round_lot_to_step(lot, symbol)
    except Exception:
        return 0.01

def calculate_margin_required(symbol, lot_size, price=None):
    """Calculate required margin for a given lot size and symbol."""
    try:
        if mt5 is None:
            return 0.0
        
        # Get symbol info for margin calculation
        sym_info = mt5.symbol_info(symbol)
        if sym_info is None:
            return 0.0
        
        # Use current price if not provided
        if price is None:
            price = sym_info.ask if sym_info.ask > 0 else sym_info.bid
        
        # Get account info for leverage
        acct = mt5.account_info()
        if acct is None:
            leverage = 100  # default fallback
        else:
            leverage = acct.leverage if acct.leverage > 0 else 100
        
        # Calculate contract size
        contract_size = getattr(sym_info, 'trade_contract_size', 100000)
        
        # Required margin = (lot_size * contract_size * price) / leverage
        margin_required = (lot_size * contract_size * price) / leverage
        
        return margin_required
    except Exception as e:
        logging.debug(f"[MARGIN_CALC] Error calculating margin for {symbol}: {e}")
        return 0.0

def adjust_lot_for_margin(symbol, initial_lot, price=None, max_margin_pct=0.90):
    """
    Automatically reduce lot size if margin requirement exceeds available margin.
    
    Args:
        symbol: Trading symbol
        initial_lot: Desired lot size from risk calculation
        price: Entry price (None = use current market price)
        max_margin_pct: Maximum % of free margin to use (default 90%)
    
    Returns:
        Adjusted lot size that fits within margin limits
    """
    try:
        if mt5 is None:
            return initial_lot
        
        acct = mt5.account_info()
        if acct is None:
            return initial_lot
        
        free_margin = acct.margin_free
        if free_margin <= 0:
            print(f"[MARGIN_ADJUST] {symbol} — No free margin available (${free_margin:.2f})")
            return 0.0
        
        # Calculate margin required for initial lot
        margin_required = calculate_margin_required(symbol, initial_lot, price)
        
        if margin_required == 0.0:
            return initial_lot
        
        # Maximum margin we're allowed to use
        max_allowed_margin = free_margin * max_margin_pct
        
        if margin_required <= max_allowed_margin:
            # No adjustment needed
            return initial_lot
        
        # Calculate adjusted lot size to fit within margin limits
        # margin_required / initial_lot = margin_per_lot
        # adjusted_lot = max_allowed_margin / margin_per_lot
        margin_per_lot = margin_required / initial_lot
        adjusted_lot = max_allowed_margin / margin_per_lot
        
        # Round to broker step
        adjusted_lot = round_lot_to_step(adjusted_lot, symbol)
        
        # Ensure it's above minimum
        sym_info = mt5.symbol_info(symbol)
        if sym_info:
            min_lot = getattr(sym_info, 'volume_min', 0.01)
            if adjusted_lot < min_lot:
                print(f"[MARGIN_ADJUST] {symbol} — Adjusted lot {adjusted_lot:.4f} below broker minimum {min_lot}. Trade skipped.")
                return 0.0
        
        print(f"[MARGIN_ADJUST] {symbol} — Reduced lot from {initial_lot:.4f} → {adjusted_lot:.4f} (Margin: ${margin_required:.2f} → ${margin_per_lot * adjusted_lot:.2f}, Free: ${free_margin:.2f})")
        return adjusted_lot
        
    except Exception as e:
        logging.error(f"[MARGIN_ADJUST] Error adjusting lot for {symbol}: {e}")
        return initial_lot

