# ═══════════════════════════════════════════════════════════════════════════════
# ONE-TIME CONFIRMATION FRAMEWORK
# Ensures a setup triggers confirmation only ONCE, preventing multiple entry signals
# STEP 1: Detect SETUP (setup_active = true when liquidity sweep or HTF level touch)
# STEP 2: Wait for CONFIRMATION (one-time trigger on confirmation signal)
# STEP 3: Lock & Store (confirmation_seen = true, stop looking for new confirmations)
# STEP 4: Entry Execution (place the trade, reset state)
# ═══════════════════════════════════════════════════════════════════════════════

# Global state: per-symbol confirmation tracking
# Structure: {
#     "symbol": {
#         "setup_active": bool,          # True when liquidity sweep or HTF level detected
#         "confirmation_seen": bool,      # True when confirmation detected (locked state)
#         "setup_price": float,           # Price when setup was triggered
#         "setup_time": datetime,         # Time when setup was triggered
#         "setup_candle_index": int,      # Candle index when setup was triggered
#         "confirmation_price": float,    # Price when confirmation was detected
#         "confirmation_time": datetime,  # Time when confirmation was detected
#         "confirmation_candle_index": int, # Candle index when confirmation locked
#         "confirmation_expiry_candle": int, # Candle index where confirmation expires
#         "setup_direction": str,         # "long" or "short" intent based on setup
#         "confirmation_reason": str,     # Reason why confirmation triggered
#         "structure_level": float,       # Pre-marked structure level (support/resistance)
#         "entry_triggered": bool,        # True when entry has been executed
#         "entry_time": datetime,         # Time when trade was entered
#         "entry_price": float,           # Actual entry price (may differ from confirmation)
#     }
# }
confirmation_state_per_symbol = {}

def initialize_confirmation_state_for_symbol(symbol):
    """Initialize or reset confirmation state for a symbol (thread-safe)."""
    with CONFIRMATION_STATE_LOCK:  # ⚠️ THREAD-SAFE: Acquire lock
        if symbol not in confirmation_state_per_symbol:
            confirmation_state_per_symbol[symbol] = {
                'setup_active': False,
                'confirmation_seen': False,
                'setup_price': None,
                'setup_time': None,
                'setup_candle_index': None,
                'confirmation_price': None,
                'confirmation_time': None,
                'confirmation_candle_index': None,
                'confirmation_expiry_candle': None,
                'setup_direction': None,
                'confirmation_reason': None,
                'structure_level': None,
                'entry_triggered': False,
                'entry_time': None,
                'entry_price': None,
        }

def set_setup_active(symbol, direction, price, reason="", structure_level=None):
    """
    STEP 1: Detect the SETUP
    Called when liquidity sweep happens or price touches HTF level.
    Sets setup_active = true, but only if no active setup exists.
    
    Args:
        symbol: Trading symbol
        direction: "long" or "short"
        price: Current price when setup triggered
        reason: Explanation of why setup was triggered
        structure_level: Optional pre-marked support/resistance level for confirmation check
    """
    initialize_confirmation_state_for_symbol(symbol)
    state = confirmation_state_per_symbol[symbol]
    
    # Only activate if not already active
    if not state['setup_active']:
        state['setup_active'] = True
        state['setup_direction'] = direction
        state['setup_price'] = float(price)
        state['setup_time'] = datetime.now()
        state['setup_candle_index'] = None  # Will be set when we have df context
        state['confirmation_seen'] = False  # Reset confirmation for new setup
        state['confirmation_price'] = None
        state['confirmation_time'] = None
        state['confirmation_candle_index'] = None
        state['confirmation_reason'] = None
        state['structure_level'] = float(structure_level) if structure_level else None
        
        print(f"[SETUP ACTIVE] {symbol} | Direction: {direction.upper()} | Price: {price:.5f} | Structure Level: {structure_level:.5f if structure_level else 'N/A'} | Reason: {reason}")
        return True
    else:
        print(f"[SETUP EXISTS] {symbol} | Setup already active at {state['setup_price']:.5f}, ignoring new setup signal")
        return False

def set_confirmation_locked(symbol, price, reason="", candle_index=None, timeframe="M15", expiry_candles=2):
    """
    STEP 2 & 3: Wait for CONFIRMATION and lock it
    Called when confirmation signal is detected (price action, volatility, volume, etc.)
    Stores confirmation and prevents new confirmations from being detected.
    
    STEP 3️⃣: Entry Trigger Rules
    - Entry must happen within N candles, or setup expires
    - Default: 2 candles (M5/M15), 1 candle (H1+)
    
    ⚠️ CRITICAL: Once this is called, no more confirmation checks are performed
    until the state is reset after entry execution.
    
    Args:
        symbol: Trading symbol
        price: Confirmation entry price
        reason: Explanation of confirmation (e.g., "Engulfing close", "Structure break")
        candle_index: Index of the candle where confirmation occurred
        timeframe: Timeframe being used (for expiry calculation)
        expiry_candles: How many candles until confirmation expires
    """
    initialize_confirmation_state_for_symbol(symbol)
    state = confirmation_state_per_symbol[symbol]
    
    # Only lock if setup is active and confirmation not yet seen
    if state['setup_active'] and not state['confirmation_seen']:
        state['confirmation_seen'] = True
        state['confirmation_price'] = float(price)
        state['confirmation_time'] = datetime.now()
        state['confirmation_candle_index'] = candle_index
        state['confirmation_reason'] = reason
        
        # STEP 4️⃣: Calculate expiry (prevents infinite waiting)
        # Expiry is set to: current_candle + expiry_candles
        if candle_index is not None:
            state['confirmation_expiry_candle'] = candle_index + expiry_candles
        
        time_since_setup = (state['confirmation_time'] - state['setup_time']).total_seconds() if state['setup_time'] else 0
        candle_info = f" Candle: {candle_index}" if candle_index is not None else ""
        expiry_info = f" (expires at candle {state['confirmation_expiry_candle']})" if state['confirmation_expiry_candle'] else ""
        print(f"[CONFIRMATION LOCKED ✓] {symbol} | Direction: {state['setup_direction'].upper()} | Entry: {price:.5f} | Time since setup: {time_since_setup:.1f}s{candle_info} | Reason: {reason}{expiry_info}")
        print(f"                         ⚠️  STOP checking for new confirmations - entry must occur within {expiry_candles} candles!")
        return True
    else:
        if not state['setup_active']:
            print(f"[CONFIRMATION IGNORED] {symbol} | No active setup to confirm")
        elif state['confirmation_seen']:
            print(f"[CONFIRMATION IGNORED] {symbol} | Confirmation already locked at {state['confirmation_price']:.5f}")
        return False

def get_confirmation_state(symbol):
    """
    Query the current confirmation state for a symbol.
    Returns the state dict or None if not initialized.
    """
    initialize_confirmation_state_for_symbol(symbol)
    return confirmation_state_per_symbol.get(symbol)

def has_locked_confirmation(symbol):
    """Check if a symbol has a confirmed, locked entry ready to execute."""
    state = get_confirmation_state(symbol)
    return state['confirmation_seen'] and state['setup_active']

def reset_confirmation_state(symbol, reason=""):
    """
    STEP 4: Entry Execution / Setup Reset
    Call this after trade is placed or when setup is invalidated.
    Resets the state so the bot can detect a new setup.
    """
    initialize_confirmation_state_for_symbol(symbol)
    with CONFIRMATION_STATE_LOCK:  # ⚠️ THREAD-SAFE: Acquire lock
        state = confirmation_state_per_symbol[symbol]
        
        old_direction = state['setup_direction']
        old_setup_price = state['setup_price']
        
        state['setup_active'] = False
        state['confirmation_seen'] = False
        state['setup_price'] = None
        state['setup_time'] = None
        state['confirmation_price'] = None
        state['confirmation_time'] = None
        state['setup_direction'] = None
        state['confirmation_reason'] = None
        
        print(f"[CONFIRMATION RESET] {symbol} | Previous setup: {old_direction.upper() if old_direction else 'N/A'} @ {old_setup_price:.5f if old_setup_price else 'N/A'} | Reason: {reason}")

def check_confirmation_expiry(symbol, current_candle_index):
    """
    STEP 4️⃣: Expiry Rule (CRITICAL - prevents infinite waiting)
    
    Checks if confirmation has expired based on time/candles.
    If entry doesn't happen within N candles:
    - M5/M15: 1-3 candles (default 2)
    - H1: 1-2 candles (default 1)
    - H4+: 1 candle
    
    Args:
        symbol: Trading symbol
        current_candle_index: Current candle index from the dataframe
    
    Returns:
        (expired, candles_remaining)
    """
    state = get_confirmation_state(symbol)
    
    if not state['confirmation_seen']:
        return False, None  # No confirmation to expire
    
    if state['confirmation_expiry_candle'] is None:
        return False, None  # No expiry set
    
    # Check if we've exceeded the expiry candle
    if current_candle_index >= state['confirmation_expiry_candle']:
        print(f"[CONFIRMATION EXPIRED ⏱️] {symbol} | Confirmation locked at candle {state['confirmation_candle_index']}, expired at candle {state['confirmation_expiry_candle']}")
        print(f"                          No entry occurred within allowed window. Resetting...")
        reset_confirmation_state(symbol, reason="Confirmation expired - no entry within allowed candles")
        return True, 0
    
    candles_remaining = state['confirmation_expiry_candle'] - current_candle_index
    return False, candles_remaining

def mark_entry_triggered(symbol, entry_price):
    """
    STEP 4️⃣: Entry Execution
    Called when the trade is actually placed after confirmation.
    Records the entry time and price.
    
    Args:
        symbol: Trading symbol
        entry_price: Actual entry price
    
    Returns:
        True if entry was successfully recorded
    """
    state = get_confirmation_state(symbol)
    
    if not state['confirmation_seen']:
        print(f"[ENTRY BLOCKED] {symbol} | No locked confirmation to enter")
        return False
    
    # Record entry
    state['entry_triggered'] = True
    state['entry_time'] = datetime.now()
    state['entry_price'] = float(entry_price)
    
    price_diff = entry_price - state['confirmation_price']
    time_since_confirm = (state['entry_time'] - state['confirmation_time']).total_seconds() if state['confirmation_time'] else 0
    
    print(f"[ENTRY EXECUTED] {symbol} | Confirmed at {state['confirmation_price']:.5f}, Entered at {entry_price:.5f} (diff: {price_diff:.5f}) | {time_since_confirm:.1f}s after confirmation")
    return True

def get_candles_since_confirmation(symbol):
    """
    Get number of candles since confirmation was locked.
    Useful for checking if entry window is closing.
    
    Returns:
        candles_since_confirmation (int) or None if not confirmed
    """
    state = get_confirmation_state(symbol)
    if not state['confirmation_seen']:
        return None
    
    if state['confirmation_candle_index'] is None:
        return None
    
    # This would be called with current_candle_index from df
    # For now, just return the state info
    return state['confirmation_candle_index']

def is_entry_window_open(symbol, current_candle_index, max_candles=2):
    """
    Check if entry window is still open.
    Entry must happen within max_candles of confirmation.
    
    Args:
        symbol: Trading symbol
        current_candle_index: Current candle from dataframe
        max_candles: Maximum candles to wait (1-3 depending on timeframe)
    
    Returns:
        (window_open, candles_remaining)
    """
    state = get_confirmation_state(symbol)
    
    if not state['confirmation_seen']:
        return False, None
    
    if state['confirmation_candle_index'] is None:
        return False, None
    
    candles_since = current_candle_index - state['confirmation_candle_index']
    candles_remaining = max_candles - candles_since
    
    if candles_since > max_candles:
        # Window closed - expire the confirmation
        check_confirmation_expiry(symbol, current_candle_index)
        return False, 0
    
    return True, candles_remaining

def check_setup_invalidation(symbol, current_price, invalidation_distance_pips=50):
    """
    Check if the current setup should be invalidated (price moved too far away).
    Useful for time-decaying setups or when price breaks setup structure.
    invalidation_distance_pips: how many pips away to invalidate (adjust per symbol)
    """
    state = get_confirmation_state(symbol)
    if not state['setup_active']:
        return False  # No setup to invalidate
    
    if state['setup_direction'] == 'long':
        # For long setup, invalidate if price breaks below setup by too much
        pip_size = 0.0001 if 'JPY' not in symbol else 0.01
        invalidation_price = state['setup_price'] - (invalidation_distance_pips * pip_size)
        if current_price < invalidation_price:
            print(f"[SETUP INVALIDATED] {symbol} | Long setup at {state['setup_price']:.5f} broken. Price {current_price:.5f} < Invalidation {invalidation_price:.5f}")
            reset_confirmation_state(symbol, reason="Price broke setup structure")
            return True
    
    elif state['setup_direction'] == 'short':
        # For short setup, invalidate if price breaks above setup by too much
        pip_size = 0.0001 if 'JPY' not in symbol else 0.01
        invalidation_price = state['setup_price'] + (invalidation_distance_pips * pip_size)
        if current_price > invalidation_price:
            print(f"[SETUP INVALIDATED] {symbol} | Short setup at {state['setup_price']:.5f} broken. Price {current_price:.5f} > Invalidation {invalidation_price:.5f}")
            reset_confirmation_state(symbol, reason="Price broke setup structure")
            return True
    
    return False

def print_confirmation_status_all_symbols(symbols=None):
    """Debug: Print confirmation state for all or specified symbols."""
    if symbols is None:
        symbols = list(confirmation_state_per_symbol.keys())
    
    if not symbols:
        print("[CONFIRMATION STATUS] No symbols tracked yet")
        return
    
    print("\n" + "="*100)
    print("[CONFIRMATION STATUS] Current state for all symbols")
    print("="*100)
    
    for symbol in symbols:
        state = get_confirmation_state(symbol)
        if state:
            status = "✓ CONFIRMED" if state['confirmation_seen'] else ("⚠ SETUP ACTIVE" if state['setup_active'] else "○ IDLE")
            setup_info = f" Setup: {state['setup_direction'].upper() if state['setup_direction'] else 'N/A'} @ {state['setup_price']:.5f}" if state['setup_price'] else ""
            confirm_info = f" Confirm: {state['confirmation_price']:.5f}" if state['confirmation_price'] else ""
            print(f"  {symbol:15} {status:20} {setup_info} {confirm_info}")
    
    print("="*100 + "\n")

# ═══════════════════════════════════════════════════════════════════════════════
# SETUP & CONFIRMATION DETECTION HELPERS
# These functions integrate with the one-time confirmation framework
# ═══════════════════════════════════════════════════════════════════════════════

def detect_and_activate_setup(symbol, df, direction):
    """
    Detect liquidity sweep or HTF level touch to ACTIVATE a setup.
    This triggers STEP 1 of the confirmation framework.
    
    Returns: (setup_detected, reason_string)
    """
    if df is None or df.empty or len(df) < 20:
        return False, "Insufficient data"
    
    try:
        current_price = df['close'].iloc[-1]
        
        # Check for liquidity sweep (HTF highs/lows being swept)
        try:
            # Use existing detect_liquidity_sweep if available
            sweep_detected = detect_liquidity_sweep(df, lookback=20)
            if sweep_detected:
                return True, "Liquidity sweep detected on HTF"
        except Exception:
            pass
        
        # Check for price touching recent HTF highs/lows
        try:
            htf_high = df['high'].tail(50).max()
            htf_low = df['low'].tail(50).min()
            
            pip_size = 0.0001 if 'JPY' not in symbol else 0.01
            touch_distance = 10 * pip_size  # Within 10 pips
            
            if direction.lower() == 'long' and abs(current_price - htf_low) < touch_distance:
                return True, "Price touched recent HTF low (setup for long)"
            elif direction.lower() == 'short' and abs(current_price - htf_high) < touch_distance:
                return True, "Price touched recent HTF high (setup for short)"
        except Exception:
            pass
        
        # Check for order block at price level
        try:
            recent_candles = df.tail(20)
            recent_range = recent_candles['high'].max() - recent_candles['low'].min()
            
            if direction.lower() == 'long':
                # Look for recent low that's now acting as support
                recent_lows = recent_candles['low'].nsmallest(3).values
                if len(recent_lows) > 0 and abs(current_price - recent_lows[0]) < recent_range * 0.05:
                    return True, "Price at recent order block low"
            else:
                # Look for recent high that's now acting as resistance
                recent_highs = recent_candles['high'].nlargest(3).values
                if len(recent_highs) > 0 and abs(current_price - recent_highs[0]) < recent_range * 0.05:
                    return True, "Price at recent order block high"
        except Exception:
            pass
        
        return False, "No setup detected"
    
    except Exception as e:
        return False, f"Setup detection error: {str(e)}"

def detect_and_lock_confirmation(symbol, df, setup_direction, structure_level=None):
    """
    STEP 2: Detect confirmation signal to LOCK the setup.
    This triggers STEP 2-3 of the confirmation framework.
    
    Objective, Binary confirmation checks (non-repeating):
    ✓ Engulfing candle CLOSE (bullish/bearish)
    ✓ Close beyond fixed structure level
    ✓ Close above/below pre-marked level
    
    Each check is:
    - OBJECTIVE: No ambiguity, clear yes/no
    - BINARY: Either happens or doesn't
    - NON-REPEATING: Once locked, no more checks
    
    Returns: (confirmation_detected, reason_string, candle_index)
    """
    if df is None or df.empty or len(df) < 5:
        return False, "Insufficient data for confirmation", None
    
    try:
        current_price = df['close'].iloc[-1]
        candle_index = len(df) - 1  # Current candle index
        
        # ═══════════════════════════════════════════════════════════════════
        # CONFIRMATION CHECK 1: ENGULFING CANDLE (OBJECTIVE & BINARY)
        # ═══════════════════════════════════════════════════════════════════
        if len(df) >= 2:
            prev_candle = df.iloc[-2]
            curr_candle = df.iloc[-1]
            
            # BULLISH ENGULFING: Current candle fully contains previous candle AND closes above it
            if setup_direction.lower() == 'long':
                # Binary check: is current candle a bullish engulfing?
                bullish_engulfing = (
                    curr_candle['close'] > prev_candle['close'] and  # Current closes ABOVE previous close
                    curr_candle['open'] < prev_candle['open'] and    # Current opens BELOW previous open
                    curr_candle['close'] > prev_candle['high'] and   # Current close ABOVE previous high
                    curr_candle['low'] < prev_candle['low']          # Current low BELOW previous low
                )
                if bullish_engulfing:
                    return True, f"✓ Bullish engulfing CLOSE @ {current_price:.5f}", candle_index
                
                # Alternative: Simpler bullish breakout (close above previous high with expansion)
                simple_bullish = (
                    curr_candle['close'] > prev_candle['high'] and
                    curr_candle['high'] > prev_candle['high'] and
                    (curr_candle['high'] - curr_candle['low']) > (prev_candle['high'] - prev_candle['low']) * 0.8
                )
                if simple_bullish:
                    return True, f"✓ Bullish close beyond structure (break of high) @ {current_price:.5f}", candle_index
            
            # BEARISH ENGULFING: Current candle fully contains previous candle AND closes below it
            elif setup_direction.lower() == 'short':
                # Binary check: is current candle a bearish engulfing?
                bearish_engulfing = (
                    curr_candle['close'] < prev_candle['close'] and  # Current closes BELOW previous close
                    curr_candle['open'] > prev_candle['open'] and    # Current opens ABOVE previous open
                    curr_candle['close'] < prev_candle['low'] and    # Current close BELOW previous low
                    curr_candle['high'] > prev_candle['high']        # Current high ABOVE previous high
                )
                if bearish_engulfing:
                    return True, f"✓ Bearish engulfing CLOSE @ {current_price:.5f}", candle_index
                
                # Alternative: Simpler bearish breakout (close below previous low with expansion)
                simple_bearish = (
                    curr_candle['close'] < prev_candle['low'] and
                    curr_candle['low'] < prev_candle['low'] and
                    (curr_candle['high'] - curr_candle['low']) > (prev_candle['high'] - prev_candle['low']) * 0.8
                )
                if simple_bearish:
                    return True, f"✓ Bearish close beyond structure (break of low) @ {current_price:.5f}", candle_index
        
        # ═══════════════════════════════════════════════════════════════════
        # CONFIRMATION CHECK 2: CLOSE BEYOND FIXED STRUCTURE LEVEL
        # ═══════════════════════════════════════════════════════════════════
        if structure_level is not None:
            if setup_direction.lower() == 'long':
                # For long: close must be ABOVE the structure level
                if current_price > structure_level:
                    distance = current_price - structure_level
                    return True, f"✓ Close ABOVE structure level {structure_level:.5f} by {distance:.5f} @ {current_price:.5f}", candle_index
            
            elif setup_direction.lower() == 'short':
                # For short: close must be BELOW the structure level
                if current_price < structure_level:
                    distance = structure_level - current_price
                    return True, f"✓ Close BELOW structure level {structure_level:.5f} by {distance:.5f} @ {current_price:.5f}", candle_index
        
        # ═══════════════════════════════════════════════════════════════════
        # CONFIRMATION CHECK 3: CLOSE ABOVE/BELOW PRE-MARKED SUPPORT/RESISTANCE
        # ═══════════════════════════════════════════════════════════════════
        try:
            # Find recent swing high/low (pre-marked levels from order blocks, previous structure)
            if len(df) >= 20:
                recent_highs = df['high'].tail(20).nlargest(3).values
                recent_lows = df['low'].tail(20).nsmallest(3).values
                
                if setup_direction.lower() == 'long':
                    # Look for close above a recent high (resistance break)
                    if len(recent_highs) > 1:
                        second_highest = recent_highs[1]
                        if current_price > second_highest:
                            distance = current_price - second_highest
                            return True, f"✓ Close above pre-marked resistance {second_highest:.5f} by {distance:.5f}", candle_index
                
                elif setup_direction.lower() == 'short':
                    # Look for close below a recent low (support break)
                    if len(recent_lows) > 1:
                        second_lowest = recent_lows[1]
                        if current_price < second_lowest:
                            distance = second_lowest - current_price
                            return True, f"✓ Close below pre-marked support {second_lowest:.5f} by {distance:.5f}", candle_index
        except Exception:
            pass
        
        # No confirmation detected
        return False, "Awaiting objective confirmation signal", None
    
    except Exception as e:
        return False, f"Confirmation detection error: {str(e)}", None

def check_and_process_confirmation_for_symbol(symbol, df, timeframe="M15", max_candles_to_entry=2):
    """
    Main integration point: Check setup status and process confirmations.
    Call this in your main trading loop for each symbol.
    
    FLOW:
    1. Check for confirmation expiry (STEP 4️⃣)
    2. If locked confirmation exists → check entry window → ready to enter
    3. If no setup → detect setup (STEP 1️⃣)
    4. If setup active → detect confirmation (STEP 2-3️⃣)
    5. Once confirmed → entry ready, state locked (with expiry)
    
    Args:
        symbol: Trading symbol
        df: Price dataframe (must have at least 20 candles)
        timeframe: "M5", "M15", "H1", etc. (for expiry calculation)
        max_candles_to_entry: Max candles to wait for entry (default 2 for M15, 1 for H1+)
    
    Returns: (should_enter, entry_direction, entry_price, entry_reason, candles_remaining)
    """
    if df is None or df.empty or len(df) < 20:
        return False, None, None, "Insufficient data", None
    
    current_price = df['close'].iloc[-1]
    current_candle_index = len(df) - 1
    state = get_confirmation_state(symbol)
    
    # ═══════════════════════════════════════════════════════════════════
    # CHECK 1: Expiry (prevents infinite waiting) ⏱️
    # ═══════════════════════════════════════════════════════════════════
    expired, candles_remaining = check_confirmation_expiry(symbol, current_candle_index)
    if expired:
        state = get_confirmation_state(symbol)  # Refresh after reset
    
    # ═══════════════════════════════════════════════════════════════════
    # CHECK 2: Setup invalidation (price broke structure)
    # ═══════════════════════════════════════════════════════════════════
    check_setup_invalidation(symbol, current_price, invalidation_distance_pips=50)
    
    # ═══════════════════════════════════════════════════════════════════
    # CHECK 3: Entry window (confirmation must trigger within N candles)
    # ═══════════════════════════════════════════════════════════════════
    if state['confirmation_seen']:
        entry_window_open, candles_left = is_entry_window_open(
            symbol, current_candle_index, max_candles=max_candles_to_entry
        )
        
        if not entry_window_open:
            # Entry window has closed
            return False, None, None, f"Entry window closed (max {max_candles_to_entry} candles expired)", 0
        
        # Entry window still open - ready to enter!
        if has_locked_confirmation(symbol):
            return True, state['setup_direction'], state['confirmation_price'], \
                   f"✓ Entry window open ({candles_left} candles remaining)", candles_left
    
    # ═══════════════════════════════════════════════════════════════════
    # DETECT NEW SETUP (STEP 1️⃣)
    # ═══════════════════════════════════════════════════════════════════
    if not state['setup_active']:
        # Try both long and short directions
        for test_direction in ['long', 'short']:
            setup_found, setup_reason = detect_and_activate_setup(symbol, df, test_direction)
            if setup_found:
                set_setup_active(symbol, test_direction, current_price, reason=setup_reason)
                state = get_confirmation_state(symbol)  # Refresh state
                break
    
    # ═══════════════════════════════════════════════════════════════════
    # DETECT CONFIRMATION (STEP 2-3️⃣) - with expiry
    # ═══════════════════════════════════════════════════════════════════
    if state['setup_active'] and not state['confirmation_seen']:
        confirm_found, confirm_reason, confirm_candle_idx = detect_and_lock_confirmation(
            symbol, df, state['setup_direction'], 
            structure_level=state['structure_level'],
            timeframe=timeframe,
            expiry_candles=max_candles_to_entry
        )
        if confirm_found:
            set_confirmation_locked(
                symbol, current_price, reason=confirm_reason, 
                candle_index=confirm_candle_idx,
                timeframe=timeframe,
                expiry_candles=max_candles_to_entry
            )
            # Return immediately after confirmation is locked
            return True, state['setup_direction'], current_price, confirm_reason, max_candles_to_entry
    
    # No entry ready yet
    candles_remaining = None
    if state['setup_active']:
        status = f"Setup active (awaiting confirmation)"
    else:
        status = "No active setup"
    
    return False, None, None, status, candles_remaining

