# ═══════════════════════════════════════════════════════════════════════════════
# NEWS-OPENED TRADES TRACKING & AGGRESSIVE TRAILING STOP MANAGEMENT
# Applies quick trailing stops to trades opened near economic news events
# ═══════════════════════════════════════════════════════════════════════════════

# Global dict to track which trades were opened near news events
news_opened_trades = {}  # {ticket: {'symbol': str, 'entry_time': datetime, 'entry_price': float}}

def mark_trade_opened_near_news(ticket, symbol, entry_price):
    """Mark a trade ticket as being opened near a news event for aggressive trailing."""
    try:
        news_opened_trades[ticket] = {
            'symbol': symbol,
            'entry_time': datetime.now(),
            'entry_price': float(entry_price),
            'direction': None,
            'initial_sl': None,
            'max_profit_points': 0.0
        }
        print(f"[NEWS TRADE] Trade {ticket} ({symbol}) marked for aggressive trailing. Entry={entry_price}")
    except Exception as e:
        print(f"[NEWS TRADE ERROR] Failed to mark trade {ticket}: {e}")

def apply_aggressive_trailing_for_news_trades():
    """
    Apply quick/aggressive trailing stops to trades opened near news.
    Locks in profits immediately and minimizes losses if trade goes wrong.
    Called every tick/candle during main trading loop.
    """
    if not news_opened_trades:
        return
    
    try:
        positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
        if not positions:
            # Clean up closed trades
            closed_tickets = [t for t in news_opened_trades.keys() if not any(p.ticket == t for p in positions or [])]
            for t in closed_tickets:
                del news_opened_trades[t]
            return
        
        for pos in positions:
            if pos.ticket not in news_opened_trades:
                continue
            
            news_info = news_opened_trades[pos.ticket]
            symbol = pos.symbol
            
            # Get current tick data
            tick = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
            if not tick:
                continue
            
            # Calculate current profit in points
            if pos.type == mt5.ORDER_TYPE_BUY:
                current_price = tick.bid
                profit_points = (current_price - pos.price_open) * 10000  # Approx points (adjust for your symbol)
                current_profit = current_price - pos.price_open
            else:  # SELL
                current_price = tick.ask
                profit_points = (pos.price_open - current_price) * 10000
                current_profit = pos.price_open - current_price
            
            # Track maximum profit reached during this trade
            if profit_points > news_info['max_profit_points']:
                news_info['max_profit_points'] = profit_points
            
            # Get ATR for dynamic trailing calculation
            df = get_price_data(symbol)
            if df is None or df.empty or len(df) < 14:
                atr = 0.0005  # Default if ATR calculation fails
            else:
                atr = calculate_atr(df)
            
            # AGGRESSIVE TRAILING LOGIC FOR NEWS TRADES
            # Use tighter trailing than normal trades to capture quick wins
            
            new_sl = None
            
            if pos.type == mt5.ORDER_TYPE_BUY:
                # For BUY: if in profit, trail SL aggressively upward (0.5 ATR behind)
                if current_profit > 0:
                    # Aggressive trail: 0.5 ATR or 2 pips, whichever is smaller
                    trail_distance = min(atr * 0.5, 0.0002)
                    new_sl = current_price - trail_distance
                    
                    # Never let SL go below entry (break-even floor)
                    new_sl = max(new_sl, pos.price_open)
                    
                    # Only move SL up, never down
                    if pos.sl is None or new_sl > pos.sl:
                        modify_result = safe_order_modify(pos.ticket, pos.price_open, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, pos.price_open, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                        if modify_result:
                            print(f"[NEWS TRAILING] {symbol} BUY {pos.ticket}: SL aggressively trailed to {new_sl:.5f} (in profit +{profit_points:.0f} pts)")
                
                # If trade goes against us quickly, widen SL slightly to avoid whipsaws
                elif current_profit < -0.0001:  # Small loss
                    # Allow only 1.5x original risk for news trades
                    original_risk = abs(pos.price_open - pos.sl) if pos.sl else atr * 1.5
                    max_loss = original_risk * 1.5
                    max_sl = pos.price_open - max_loss
                    
                    if pos.sl is None or pos.sl < max_sl:
                        new_sl = max_sl
                        modify_result = safe_order_modify(pos.ticket, pos.price_open, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, pos.price_open, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                        if modify_result:
                            print(f"[NEWS PROTECTION] {symbol} BUY {pos.ticket}: SL set to limit losses to {max_loss:.5f} (in drawdown {profit_points:.0f} pts)")
            
            else:  # SELL order
                # For SELL: if in profit, trail SL aggressively downward
                if current_profit > 0:
                    trail_distance = min(atr * 0.5, 0.0002)
                    new_sl = current_price + trail_distance
                    
                    # Never let SL go above entry
                    new_sl = min(new_sl, pos.price_open)
                    
                    # Only move SL down, never up
                    if pos.sl is None or new_sl < pos.sl:
                        modify_result = safe_order_modify(pos.ticket, pos.price_open, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, pos.price_open, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                        if modify_result:
                            print(f"[NEWS TRAILING] {symbol} SELL {pos.ticket}: SL aggressively trailed to {new_sl:.5f} (in profit +{profit_points:.0f} pts)")
                
                # If trade goes against us, protect with tighter stops
                elif current_profit < -0.0001:
                    original_risk = abs(pos.sl - pos.price_open) if pos.sl else atr * 1.5
                    max_loss = original_risk * 1.5
                    max_sl = pos.price_open + max_loss
                    
                    if pos.sl is None or pos.sl > max_sl:
                        new_sl = max_sl
                        modify_result = safe_order_modify(pos.ticket, pos.price_open, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, pos.price_open, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                        if modify_result:
                            print(f"[NEWS PROTECTION] {symbol} SELL {pos.ticket}: SL set to limit losses to {max_loss:.5f} (in drawdown {profit_points:.0f} pts)")
    
    except Exception as e:
        print(f"[NEWS TRAILING ERROR] {e}")
# --- Utility: Round lot size to valid step for a symbol ---
def round_lot_to_step(lot, symbol):
    """
    Rounds the lot size to the nearest valid step for the given symbol.
    Includes diagnostics to detect when broker limits are capping lot sizes.
    Respects BROKER_VOLUME_MAX_OVERRIDE to bypass restrictive broker limits.
    """
    symbol_info = mt5.symbol_info(symbol)
    if symbol_info is None:
        return round(lot, 2)
    lot_step = symbol_info.volume_step
    min_lot = symbol_info.volume_min
    max_lot = symbol_info.volume_max

    # Check if there's a broker override for this symbol
    try:
        base_sym = symbol.upper().split('.')[0]
        if base_sym in BROKER_VOLUME_MAX_OVERRIDE:
            override_max = BROKER_VOLUME_MAX_OVERRIDE[base_sym]
            if override_max > max_lot:
                print(f"[LOT_OVERRIDE] {symbol}: Using override max_lot={override_max} instead of broker max={max_lot}")
                max_lot = override_max
    except Exception:
        pass

    # Diagnostic: if lot is being capped to <= 0.1, log it
    if lot > max_lot and max_lot <= 0.1:
        print(f"[LOT_DIAGNOSTIC] {symbol}: Calculated lot={lot:.4f}, but broker/config max_lot={max_lot}, min_lot={min_lot}, step={lot_step}")
        print(f"[LOT_DIAGNOSTIC]   >> To increase lot size, add '{base_sym}': 1.0 (or higher) to BROKER_VOLUME_MAX_OVERRIDE in bot config")

    # Clamp and round
    lot = max(min_lot, min(lot, max_lot))
    if lot_step > 0:
        # Some brokers require lot = min_lot + n * lot_step
        steps = round((lot - min_lot) / lot_step)
        lot = min_lot + (steps * lot_step)
    
    # Dynamic decimal precision based on volume_step
    # volume_step=0.01 -> 2 decimals, volume_step=0.001 -> 3 decimals, etc.
    if lot_step >= 0.01:
        decimals = 2
    elif lot_step >= 0.001:
        decimals = 3
    elif lot_step >= 0.0001:
        decimals = 4
    else:
        decimals = 5
    
    lot = round(lot, decimals)

    # Final validation: ensure lot is within bounds after rounding
    if lot < min_lot:
        lot = min_lot
    if lot > max_lot:
        lot = max_lot

    return lot

# --- Utility: Ensure SL/TP for XAUUSD are not too close to entry ---
def adjust_xauusd_sl_tp(entry, sl, tp, signal):
    """
    For XAUUSD, ensure SL and TP are not too close to entry.
    If too close, widen them to give the trade breathing room.
    """
    min_sl_dist = 2.0  # $2 minimum SL distance for XAUUSD
    min_tp_dist = 2.0  # $2 minimum TP distance for XAUUSD

    if signal == "buy":
        if sl is not None and (entry - sl) < min_sl_dist:
            sl = entry - min_sl_dist
        if tp is not None and (tp - entry) < min_tp_dist:
            tp = entry + min_tp_dist
    elif signal == "sell":
        if sl is not None and (sl - entry) < min_sl_dist:
            sl = entry + min_sl_dist
        if tp is not None and (entry - tp) < min_tp_dist:
            tp = entry - min_tp_dist
    return sl, tp

def print_broker_lot_limits(symbols=None):
    """
    Diagnostic function to print broker's lot size limits for symbols.
    Call this to diagnose why lot sizes are capped to 0.1 or other values.
    
    Args:
        symbols: List of symbol strings. If None, checks common FX pairs.
    """
    if symbols is None:
        symbols = ['EURUSD.m', 'GBPUSD.m', 'AUDUSD.m', 'XAUUSD.m']
    
    print("\n" + "="*80)
    print("[DIAGNOSTIC] Broker Lot Size Limits")
    print("="*80)
    for symbol in symbols:
        try:
            si = mt5.symbol_info(symbol)
            if si is None:
                print(f"{symbol:15} | NOT FOUND in broker")
            else:
                print(f"{symbol:15} | min_lot={si.volume_min:8.4f} | max_lot={si.volume_max:8.4f} | step={si.volume_step:8.6f}")
        except Exception as e:
            print(f"{symbol:15} | ERROR: {e}")
    
    print(f"\nCurrent config:")
    print(f"  MAX_LOT_SIZE: {MAX_LOT_SIZE}")
    print(f"  SYMBOL_MAX_LOT: {SYMBOL_MAX_LOT}")
    print(f"  BROKER_VOLUME_MAX_OVERRIDE: {BROKER_VOLUME_MAX_OVERRIDE}")
    print("="*80 + "\n")

def cleanup_closed_news_trades():
    """Remove closed trades from news tracking dict."""
    try:
        positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
        if positions:
            active_tickets = {p.ticket for p in positions}
            closed_tickets = [t for t in list(news_opened_trades.keys()) if t not in active_tickets]
            for ticket in closed_tickets:
                trade_info = news_opened_trades.pop(ticket)
                symbol = trade_info.get('symbol')
                entry_price = float(trade_info.get('entry_price', 0)) if trade_info.get('entry_price') is not None else 0.0
                direction = trade_info.get('direction')
                # Attempt to get current market price as exit price
                exit_price = None
                try:
                    tick = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
                    if tick:
                        exit_price = float(tick.bid) if direction == 'buy' or direction is None else float(tick.ask)
                except Exception:
                    exit_price = None

                pnl = None
                try:
                    if exit_price is not None and entry_price:
                        if direction == 'buy':
                            pnl = exit_price - entry_price
                        elif direction == 'sell':
                            pnl = entry_price - exit_price
                        else:
                            # If direction unknown, compute absolute change as fallback
                            pnl = exit_price - entry_price
                except Exception:
                    pnl = None

                # Persist trade result into trade memory if we computed a pnl
                try:
                    setup = 'news'
                    if pnl is not None:
                        record_trade_result(symbol, setup, pnl)
                        # Update learning modules
                        on_trade_closed(symbol, {'entry_price': entry_price, 'exit_price': exit_price, 'news_trade': True}, pnl)
                except Exception:
                    pass

                print(f"[NEWS TRADE CLOSED] {symbol} ticket {ticket} - Max profit: {trade_info.get('max_profit_points', 0):.0f} pts")
    except Exception as e:
        print(f"[NEWS CLEANUP ERROR] {e}")

# ═══════════════════════════════════════════════════════════════════════════════
# UNIFIED TRADE DECISION ENGINE
# All analysis systems communicate through this coordinator before opening trades
# ═══════════════════════════════════════════════════════════════════════════════

def detect_regime(df, rsi=None, volatility=None):
    """
    Classify market regime based on volatility, ATR/price and RSI.
    Returns one of: 'choppy', 'exhaustion', 'volatile', 'trending', 'unknown'.
    """
    try:
        price = df['close'].iloc[-1]

        # Use ATR proxy from std dev of close, 14‑period
        atr_val = df['close'].rolling(14).std().iloc[-1]

        # Choppy / low volatility regime
        if price > 0 and atr_val / price < 0.0005:
            return "choppy"

        # Trend exhaustion via RSI
        if rsi is not None and (rsi > 75 or rsi < 25):
            return "exhaustion"

        # Volatility spike regime
        if volatility is None:
            if len(df) >= 20:
                volatility = df['close'].rolling(20).std().iloc[-1]
            else:
                volatility = atr_val

        long_term_std_mean = df['close'].rolling(100).std().mean()
        if long_term_std_mean and volatility > 2 * long_term_std_mean:
            return "volatile"

        return "trending"
    except Exception:
        return "unknown"


class TradeDecisionContext:
    """Container for all analysis data so filters can read each other's results."""
    def __init__(self, symbol, signal, ml_confidence, features, df):
        self.symbol = symbol
        self.signal = signal
        self.ml_confidence = ml_confidence
        self.features = features
        self.df = df
        self.price = df['close'].iloc[-1]
        self.timestamp = datetime.now()
        
        # Results from each analysis system (populated as we go)
        # Initialize as empty dicts to avoid None-subscriptable errors when analyzing
        self.htf_analysis = {}
        self.fvg_analysis = {}
        self.momentum_analysis = {}
        self.volume_analysis = {}
        self.ensemble_votes = {}
        self.risk_analysis = {}
        self.regime_analysis = {}
        
        # Final decision
        self.should_trade = False
        self.reason = ""
        self.trade_quality_score = 0.0
        self.blocking_filters = []
        self.supporting_filters = []

def analyze_htf_trend(context):
    """
    Advanced HTF trend filter: multi-timeframe, multi-indicator, regime-aware.
    Blocks trades on trend conflict, exhaustion, or choppy regime.
    """
    df = context.df
    features = context.features
    signal = context.signal

    # --- Multi-timeframe analysis ---
    def get_htf_bias(df, tf="H4"):
        try:
            # Resample to HTF
            htf_df = df.copy()
            if tf == "H4":
                htf_df = df.resample('4H', on='timestamp').agg({'open':'first','high':'max','low':'min','close':'last','volume':'sum'}).dropna()
            elif tf == "D1":
                htf_df = df.resample('1D', on='timestamp').agg({'open':'first','high':'max','low':'min','close':'last','volume':'sum'}).dropna()
            # EMA ribbon
            ema21 = htf_df['close'].ewm(span=21).mean()
            ema50 = htf_df['close'].ewm(span=50).mean()
            ema200 = htf_df['close'].ewm(span=200).mean()
            if ema21.iloc[-1] > ema50.iloc[-1] > ema200.iloc[-1]:
                return "bullish"
            elif ema21.iloc[-1] < ema50.iloc[-1] < ema200.iloc[-1]:
                return "bearish"
            else:
                return "neutral"
        except Exception:
            return "neutral"

    htf_bias_h4 = get_htf_bias(df, "H4")
    htf_bias_d1 = get_htf_bias(df, "D1")
    htf_bias = features.get("htf_bias", htf_bias_h4)
    # --- Indicator consensus ---
    ema_ribbon_status = features.get("ema_ribbon_status", "neutral")
    structure = features.get("structure", "unknown")
    macd = features.get("macd", 0)
    macd_signal = features.get("macd_signal", 0)
    rsi = features.get("rsi", 50)
    atr = features.get("atr", 0.001)
    volatility = df['close'].rolling(20).std().iloc[-1] if len(df) >= 20 else atr

    # --- Regime detection (global helper) ---
    regime = detect_regime(df, rsi=rsi, volatility=volatility)

    # --- Alignment logic ---
    alignment = False
    reason = ""
    confidence = 0.0
    htf_agree = (htf_bias_h4 == htf_bias_d1) and htf_bias_h4 in ("bullish", "bearish")
    macd_agree = (macd > macd_signal and signal == "buy") or (macd < macd_signal and signal == "sell")
    
    # ⚡ FIX #3: RSI AS FILTER ONLY (not entry trigger) ⚡
    # RSI should BLOCK bad trades, not CREATE entries
    # - Don't BUY when RSI < 30 (oversold = bounce risk, bad entry)
    # - Don't SELL when RSI > 70 (overbought = pullback risk, bad entry)
    # - RSI 30-70 range = allow based on other factors
    rsi_boost = 0.0
    rsi_reason = ""
    if signal == "buy":
        if rsi < 30:
            # Oversold = risky for BUY (likely bounce coming)
            rsi_boost = -0.20
            rsi_reason = f"RSI {rsi:.0f} OVERSOLD (block BUY, bounce risk)"
        else:
            # RSI >= 30 = normal range, allow based on other factors
            rsi_boost = 0.0
            rsi_reason = f"RSI {rsi:.0f} normal (filter allows)"
    else:  # sell
        if rsi > 70:
            # Overbought = risky for SELL (likely pullback coming)
            rsi_boost = -0.20
            rsi_reason = f"RSI {rsi:.0f} OVERBOUGHT (block SELL, pullback risk)"
        else:
            # RSI <= 70 = normal range, allow based on other factors
            rsi_boost = 0.0
            rsi_reason = f"RSI {rsi:.0f} normal (filter allows)"
    
    structure_ok = (structure in ["HH", "HL"] and signal == "buy") or (structure in ["LL", "LH"] and signal == "sell")

    # RELAXED: Allow trades in difficult regimes with lower confidence
    if regime in ("choppy", "exhaustion", "volatile"):
        alignment = True  # Changed from False
        reason = f"HTF regime is {regime.upper()} but allowing with caution"
        confidence = 0.3  # Changed from 0.1
    elif not htf_agree:
        alignment = False
        reason = f"HTF timeframes disagree: H4={htf_bias_h4}, D1={htf_bias_d1}"
        confidence = 0.2
    elif (signal == "buy" and htf_bias_h4 == "bullish" and macd_agree and structure_ok):
        alignment = True
        reason = "HTF trend STRONGLY ALIGNED for BUY (H4, MACD, structure). RSI soft-checked."
        confidence = min(0.95, 0.85 + rsi_boost)  # RSI soft boost/penalty
    elif (signal == "sell" and htf_bias_h4 == "bearish" and macd_agree and structure_ok):
        alignment = True
        reason = "HTF trend STRONGLY ALIGNED for SELL (H4, MACD, structure). RSI soft-checked."
        confidence = min(0.95, 0.85 + rsi_boost)  # RSI soft boost/penalty
    elif htf_bias_h4 == signal or htf_bias_d1 == signal:
        alignment = True
        reason = f"HTF trend ALIGNED ({htf_bias_h4}/{htf_bias_d1}) with {signal}. RSI: {rsi_reason}"
        confidence = max(0.3, min(0.7, 0.65 + rsi_boost))  # RSI can adjust confidence
    elif htf_bias_h4 == "neutral" or htf_bias_d1 == "neutral":
        # RELAXED: Allow trades with neutral HTF if other factors are strong
        alignment = True
        reason = f"HTF neutral but allowing {signal} with caution. RSI: {rsi_reason}"
        confidence = max(0.2, min(0.5, 0.4 + rsi_boost))  # Lower confidence for neutral HTF
        reason = "HTF trend is NEUTRAL"
        confidence = 0.5
    else:
        alignment = False
        reason = f"HTF trend CONFLICT: H4={htf_bias_h4}, D1={htf_bias_d1}, signal={signal}"
        confidence = 0.2

    context.htf_analysis = {
        "aligned": alignment,
        "htf_bias_h4": htf_bias_h4,
        "htf_bias_d1": htf_bias_d1,
        "ema_ribbon": ema_ribbon_status,
        "structure": structure,
        "macd": macd,
        "macd_signal": macd_signal,
        "rsi": rsi,
        "atr": atr,
        "volatility": volatility,
        "regime": regime,
        "confidence": confidence,
        "reason": reason
    }

    if alignment is False:
        context.blocking_filters.append(f"HTF_CONFLICT: {reason}")
    elif alignment is True:
        context.supporting_filters.append(f"HTF: {reason}")

def check_pullback_rule(context):
    """
    PULLBACK RULE: After BOS/impulse, require MICRO PULLBACK for entry.
    
    ⚡ FIX #2: Wait for pullback AFTER signal detection
    Don't chase the impulse → enter on pullback retracement
    
    Rules:
    - DETECT signal: Last impulse high/low with strong body (> 60% range)
    - CALCULATE pullback: last_impulse_high - (0.3 to 0.7 × impulse_body)
    - ENTRY ONLY: Price retraces TO pullback_level with rejection candle
    - BUY: After impulse high, pullback zone = 50-70% retrace of body
    - SELL: After impulse low, pullback zone = 50-70% retrace of body
    - Allow entry when price taps FVG within pullback zone
    
    Returns: (pullback_valid, retrace_percent, pullback_reason)
    """
    try:
        bos = context.features.get("bos")
        if bos is None:
            return False, 0.0, "NO_BOS_SIGNAL"
        
        # Get impulse details from last significant candle
        df = context.df
        if len(df) < 3:
            return False, 0.0, "NOT_ENOUGH_CANDLES"
        
        # Find the last BOS candle (impulse that created the break)
        last_impulse = None
        last_impulse_idx = None
        for i in range(len(df) - 2, max(0, len(df) - 80), -1):
            candle = df.iloc[i]
            body = abs(candle['close'] - candle['open'])
            range_val = candle['high'] - candle['low']
            if range_val > 0 and body / range_val > 0.6:  # Strong impulse body
                last_impulse = candle
                last_impulse_idx = i
                break
        
        if last_impulse is None:
            return False, 0.0, "NO_IMPULSE_FOUND"
        
        # Calculate retracement zone
        impulse_body = abs(last_impulse['close'] - last_impulse['open'])
        impulse_high = last_impulse['high']
        impulse_low = last_impulse['low']
        current_price = context.price
        
        # ⚡ MICRO PULLBACK ENTRY: Calculate pullback zones and check rejection ⚡
        # --- Rule 2: Momentum filter ---
        # Require a strong bullish impulse that breaks prior bearish structure and CLOSES above a key level.
        if bos == "buy":
            # After impulse high, pullback should be 50-70% of body
            pullback_50 = impulse_high - 0.5 * impulse_body
            pullback_70 = impulse_high - 0.7 * impulse_body
            
            # --- Momentum / BOS / Key-level checks before allowing any BUY ---
            # Find recent swing highs to detect break-of-structure
            swing_highs = []
            try:
                highs = df['high'].values
                for j in range(1, len(highs)-1):
                    if highs[j] > highs[j-1] and highs[j] > highs[j+1]:
                        swing_highs.append(highs[j])
            except Exception:
                swing_highs = []

            # Require last_impulse to break the previous swing high (BOS) and close above a key POI
            prev_swing_high = swing_highs[-2] if len(swing_highs) >= 2 else None
            poi_level = context.features.get('poi') if isinstance(context.features, dict) else None

            # Check BOS (must have previous swing to break)
            if prev_swing_high is None:
                return False, 0.0, "NO_PREV_SWING_TO_BREAK"

            try:
                impulse_close = float(last_impulse['close'])
            except Exception:
                impulse_close = None

            if impulse_close is None or impulse_close <= prev_swing_high:
                return False, 0.0, "IMPULSE_DID_NOT_BREAK_STRUCTURE"

            # Require close above POI or previous swing high (key level)
            key_level = poi_level if poi_level is not None else prev_swing_high
            if impulse_close <= key_level:
                return False, 0.0, "IMPULSE_DID_NOT_CLOSE_ABOVE_KEY_LEVEL"

            # Optional: require strong follow-through momentum (last impulse close > previous candle high)
            try:
                if last_impulse_idx is not None and last_impulse_idx - 1 >= 0:
                    if float(last_impulse['close']) <= float(df['high'].iloc[last_impulse_idx - 1]):
                        return False, 0.0, "IMPULSE_NO_FOLLOW_THROUGH_MOMENTUM"
            except Exception:
                pass

            # Check if price is in pullback zone
            if pullback_70 <= current_price <= pullback_50:
                retrace_pct = ((impulse_high - current_price) / impulse_body * 100) if impulse_body > 0 else 0
                
                # ⚡ ADDITIONAL CHECK: Require rejection candle at pullback ⚡
                # Last candle must show lower wick rejection (price rejected pulling further down)
                try:
                    last_c = df.iloc[-1] if len(df) > 0 else None
                    if last_c is not None:
                        c_body = abs(last_c['close'] - last_c['open'])
                        c_lower_wick = min(last_c['close'], last_c['open']) - last_c['low']
                        c_range = last_c['high'] - last_c['low']
                        if c_range > 0 and c_body > 0:
                            # Strong rejection: lower wick > 2x body (absorbed sellers at pullback)
                            if c_lower_wick > 2.0 * c_body:
                                return True, retrace_pct, f"BUY_PULLBACK_REJECTION: {retrace_pct:.1f}% retrace + strong lower wick (wick {c_lower_wick/c_body:.1f}x body)"
                            # Moderate: just price in zone with acceptable pullback
                            elif c_body > 0:
                                return True, retrace_pct, f"BUY_PULLBACK: {retrace_pct:.1f}% retrace in zone"
                except Exception:
                    return True, retrace_pct, f"BUY_PULLBACK: {retrace_pct:.1f}% retrace in zone"
            
            # Allow entry if price tapped FVG and bounced
            entry_zone = context.fvg_analysis.get("entry_zone", {})
            if isinstance(entry_zone, dict):
                zone_low = entry_zone.get("low", 0)
                if zone_low > 0 and current_price >= zone_low * 0.995:  # Tapped FVG
                    retrace_pct = ((impulse_high - current_price) / impulse_body * 100) if impulse_body > 0 else 0
                    return True, retrace_pct, f"BUY_FVG_TAP: Price tapped FVG at {retrace_pct:.1f}%"
        
        elif bos == "sell":
            # After impulse low, pullback should be 50-70% of body
            pullback_50 = impulse_low + 0.5 * impulse_body
            pullback_70 = impulse_low + 0.7 * impulse_body
            
            # Check if price is in pullback zone
            if pullback_50 <= current_price <= pullback_70:
                retrace_pct = ((current_price - impulse_low) / impulse_body * 100) if impulse_body > 0 else 0
                
                # ⚡ ADDITIONAL CHECK: Require rejection candle at pullback ⚡
                # Last candle must show upper wick rejection (price rejected pulling further up)
                try:
                    last_c = df.iloc[-1] if len(df) > 0 else None
                    if last_c is not None:
                        c_body = abs(last_c['close'] - last_c['open'])
                        c_upper_wick = last_c['high'] - max(last_c['close'], last_c['open'])
                        c_range = last_c['high'] - last_c['low']
                        if c_range > 0 and c_body > 0:
                            # Strong rejection: upper wick > 2x body (absorbed buyers at pullback)
                            if c_upper_wick > 2.0 * c_body:
                                return True, retrace_pct, f"SELL_PULLBACK_REJECTION: {retrace_pct:.1f}% retrace + strong upper wick (wick {c_upper_wick/c_body:.1f}x body)"
                            # Moderate: just price in zone with acceptable pullback
                            elif c_body > 0:
                                return True, retrace_pct, f"SELL_PULLBACK: {retrace_pct:.1f}% retrace in zone"
                except Exception:
                    return True, retrace_pct, f"SELL_PULLBACK: {retrace_pct:.1f}% retrace in zone"
            
            # --- Momentum / BOS / Key-level checks for SELL ---
            swing_lows = []
            try:
                lows = df['low'].values
                for j in range(1, len(lows)-1):
                    if lows[j] < lows[j-1] and lows[j] < lows[j+1]:
                        swing_lows.append(lows[j])
            except Exception:
                swing_lows = []

            prev_swing_low = swing_lows[-2] if len(swing_lows) >= 2 else None
            poi_level = context.features.get('poi') if isinstance(context.features, dict) else None

            if prev_swing_low is None:
                return False, 0.0, "NO_PREV_SWING_TO_BREAK"

            try:
                impulse_close = float(last_impulse['close'])
            except Exception:
                impulse_close = None

            if impulse_close is None or impulse_close >= prev_swing_low:
                return False, 0.0, "IMPULSE_DID_NOT_BREAK_STRUCTURE"

            key_level = poi_level if poi_level is not None else prev_swing_low
            if impulse_close >= key_level:
                return False, 0.0, "IMPULSE_DID_NOT_CLOSE_BELOW_KEY_LEVEL"

            try:
                if last_impulse_idx is not None and last_impulse_idx - 1 >= 0:
                    if float(last_impulse['close']) >= float(df['low'].iloc[last_impulse_idx - 1]):
                        return False, 0.0, "IMPULSE_NO_FOLLOW_THROUGH_MOMENTUM"
            except Exception:
                pass

            # Allow entry if price tapped FVG and bounced
            entry_zone = context.fvg_analysis.get("entry_zone", {})
            if isinstance(entry_zone, dict):
                zone_high = entry_zone.get("high", 0)
                if zone_high > 0 and current_price <= zone_high * 1.005:  # Tapped FVG
                    retrace_pct = ((current_price - impulse_low) / impulse_body * 100) if impulse_body > 0 else 0
                    return True, retrace_pct, f"SELL_FVG_TAP: Price tapped FVG at {retrace_pct:.1f}%"
        
        return False, 0.0, f"PULLBACK_INCOMPLETE: Price outside 50-70% zone"
    
    except Exception as e:
        return False, 0.0, f"PULLBACK_CHECK_ERROR: {str(e)}"


def check_htf_demand_reaction(context):
    """
    HTF FILTER: Only allow BUY if H4 is bullish OR reacting from demand zone.
    Only allow SELL if H4 is bearish OR reacting from supply zone.
    
    Rules:
    - Get H4 trend from EMA alignment
    - Check if price is near recent swing low (demand) or high (supply)
    - For buy: H4 bullish OR price near demand + bouncing
    - For sell: H4 bearish OR price near supply + bouncing
    
    Returns: (htf_ok, reason)
    """
    try:
        signal = context.signal
        htf_analysis = context.htf_analysis
        df = context.df
        
        if not isinstance(htf_analysis, dict):
            return False, "NO_HTF_ANALYSIS"
        
        htf_bias = htf_analysis.get("htf_bias_h4", "neutral")
        current_price = context.price

        # Helper: compute simple EMA-based bias for a given timeframe
        def get_tf_bias(df, tf="H1"):
            try:
                tf_df = df.copy()
                if tf == "H1":
                    tf_df = df.resample('1H', on='timestamp').agg({'open':'first','high':'max','low':'min','close':'last','volume':'sum'}).dropna()
                elif tf == "M30":
                    tf_df = df.resample('30T', on='timestamp').agg({'open':'first','high':'max','low':'min','close':'last','volume':'sum'}).dropna()
                else:
                    return "neutral"
                ema21 = tf_df['close'].ewm(span=21).mean()
                ema50 = tf_df['close'].ewm(span=50).mean()
                ema200 = tf_df['close'].ewm(span=200).mean()
                if ema21.iloc[-1] > ema50.iloc[-1] > ema200.iloc[-1]:
                    return "bullish"
                elif ema21.iloc[-1] < ema50.iloc[-1] < ema200.iloc[-1]:
                    return "bearish"
                else:
                    return "neutral"
            except Exception:
                return "neutral"

        # Helper: find simple pivot swing highs/lows (3-bar pivot)
        def find_swing_points(df):
            highs = df['high'].values
            lows = df['low'].values
            swing_highs = []  # list of values
            swing_lows = []
            for i in range(1, len(highs)-1):
                try:
                    if highs[i] > highs[i-1] and highs[i] > highs[i+1]:
                        swing_highs.append(highs[i])
                    if lows[i] < lows[i-1] and lows[i] < lows[i+1]:
                        swing_lows.append(lows[i])
                except Exception:
                    continue
            return swing_highs, swing_lows

        # Compute H1/M30 bias for rule 1
        h1_bias = get_tf_bias(df, "H1")
        m30_bias = get_tf_bias(df, "M30")
        
        # Get recent swing levels (last 50 bars)
        if len(df) >= 50:
            recent_highs = df['high'].iloc[-50:].values
            recent_lows = df['low'].iloc[-50:].values
            swing_high = recent_highs.max()
            swing_low = recent_lows.min()
        else:
            swing_high = df['high'].max()
            swing_low = df['low'].min()
        
        pip_size = 0.0001 if "JPY" not in context.symbol else 0.01
        demand_zone_threshold = 15 * pip_size  # Within 15 pips of swing low
        supply_zone_threshold = 15 * pip_size  # Within 15 pips of swing high
        
        if signal == "buy":
            # Rule 1: Only allow BUY if H1 or M30 structure is bullish
            if h1_bias == "bullish" or m30_bias == "bullish":
                return True, f"BUY_HTF_BULLISH: H1/M30 trend bullish ({h1_bias}/{m30_bias})"

            # OR allow BUY if price breaks & CLOSES above the last lower high
            swing_highs, swing_lows = find_swing_points(df)
            if len(swing_highs) >= 2:
                last = swing_highs[-1]
                prev = swing_highs[-2]
                # last lower high pattern
                if last < prev:
                    last_lower_high = last
                    # require the most recent close to be above that swing high
                    try:
                        last_close = df.iloc[-1]['close']
                        prev_close = df.iloc[-2]['close']
                        if last_close > last_lower_high and prev_close <= last_lower_high:
                            return True, f"BUY_BREAKOUT: Close above last lower high {last_lower_high:.5f}"
                    except Exception:
                        pass

            # Fallback: allow buy if H4 bullish or reacting from demand zone (existing behavior)
            if htf_bias == "bullish":
                return True, f"BUY_HTF_BULLISH_FALLBACK: H4 bullish"

            # Check if price is bouncing from demand (near recent low)
            if current_price <= swing_low + demand_zone_threshold:
                if len(df) >= 2:
                    recent_move = df.iloc[-1]['close'] - df.iloc[-2]['close']
                    if recent_move > 0:
                        return True, f"BUY_DEMAND_REACTION: Price near swing low, bouncing up"

            return False, f"BUY_BLOCKED: No H1/M30 bullish structure or breakout"
        
        elif signal == "sell":
            # Rule 1: Only allow SELL if H1 or M30 structure is bearish
            if h1_bias == "bearish" or m30_bias == "bearish":
                return True, f"SELL_HTF_BEARISH: H1/M30 trend bearish ({h1_bias}/{m30_bias})"

            # OR allow SELL if price breaks & CLOSES below the last higher low
            swing_highs, swing_lows = find_swing_points(df)
            if len(swing_lows) >= 2:
                last = swing_lows[-1]
                prev = swing_lows[-2]
                # last higher low pattern
                if last > prev:
                    last_higher_low = last
                    try:
                        last_close = df.iloc[-1]['close']
                        prev_close = df.iloc[-2]['close']
                        if last_close < last_higher_low and prev_close >= last_higher_low:
                            return True, f"SELL_BREAKDOWN: Close below last higher low {last_higher_low:.5f}"
                    except Exception:
                        pass

            # Fallback: allow sell if H4 bearish or reacting from supply zone (existing behavior)
            if htf_bias == "bearish":
                return True, f"SELL_HTF_BEARISH_FALLBACK: H4 bearish"

            # Check if price is rejecting from supply (near recent high)
            if current_price >= swing_high - supply_zone_threshold:
                if len(df) >= 2:
                    recent_move = df.iloc[-1]['close'] - df.iloc[-2]['close']
                    if recent_move < 0:
                        return True, f"SELL_SUPPLY_REACTION: Price near swing high, rejecting down"

            return False, f"SELL_BLOCKED: No H1/M30 bearish structure or breakdown"
        
        return False, "UNKNOWN_SIGNAL"
    
    except Exception as e:
        return False, f"HTF_DEMAND_CHECK_ERROR: {str(e)}"


def check_entry_tf_confirmation(context):
    """
    ENTRY TF REFINEMENT: Prioritize REJECTION-BASED ENTRY over continuation.
    
    ⚡ KEY RULE: Price rejection at level with increasing momentum = ENTRY TRIGGER
    NOT: Price continuing past level = avoid chasing
    
    Rules:
    - BUY: Price touches level (high > zone), CLOSES BELOW with lower wick > 2.5x body = REJECTION
    - SELL: Price touches level (low < zone), CLOSES ABOVE with upper wick > 2.5x body = REJECTION
    - Alternative: Strong momentum at level (engulfing + volume spike)
    
    Returns: (entry_tf_valid, confirmation_type, confidence_boost)
    """
    try:
        signal = context.signal
        df = context.df  # Should contain M5/M15 data
        current_price = context.price
        
        if len(df) < 3:
            return False, "NOT_ENOUGH_CANDLES", 0.0
        
        last = df.iloc[-1]
        prev = df.iloc[-2]
        
        # ⚡ REJECTION CANDLE DETECTION (Core Entry Signal) ⚡
        def is_rejection_candle(candle, signal_type):
            """
            Check if candle shows REJECTION: opposite wick > 2.5x body
            = Price tested level and got rejected = ENTRY SIGNAL
            """
            body = abs(candle['close'] - candle['open'])
            total = candle['high'] - candle['low']
            if total <= 0:
                return False, 0.0
            
            body_ratio = body / total
            upper_wick = candle['high'] - max(candle['close'], candle['open'])
            lower_wick = min(candle['close'], candle['open']) - candle['low']
            
            if signal_type == "buy":
                # Bullish rejection: lower wick > 2.5x body (absorbed selling)
                if lower_wick > 2.5 * body and body_ratio < 0.4:
                    return True, lower_wick / body if body > 0 else 3.0
            else:  # sell
                # Bearish rejection: upper wick > 2.5x body (absorbed buying)
                if upper_wick > 2.5 * body and body_ratio < 0.4:
                    return True, upper_wick / body if body > 0 else 3.0
            
            return False, 0.0
        
        # Check for level test on M5
        recent_highs = df['high'].iloc[-10:-1].max()
        recent_lows = df['low'].iloc[-10:-1].min()
        
        if signal == "buy":
            # ⚡ PRIMARY ENTRY: BUY = Price rejects FROM HIGH with LOWER WICK ⚡
            # Price high tested recent highs (=level test), last candle shows REJECTION
            if last['high'] > recent_highs:  # Price tested the level
                is_rejection, rejection_strength = is_rejection_candle(last, "buy")
                if is_rejection:
                    # ✅ REJECTION ENTRY: Price touched level, got rejected upward with strong wick
                    return True, f"BUY_REJECTION_{rejection_strength:.1f}x", 0.25  # +25% confidence (BEST)
                
                # SECONDARY: Strong momentum candle at level (engulfing + volume)
                if last['close'] > last['open']:  # Bullish
                    if last['open'] < prev['close'] and last['close'] > prev['open']:  # Engulfing
                        last_vol = last.get('tick_volume', 0)
                        prev_vol = prev.get('tick_volume', 1)
                        if last_vol > prev_vol * 1.2:  # Volume expansion
                            return True, "BUY_ENGULFING_VOL_SPIKE", 0.18  # +18% confidence
                        return True, "BUY_LEVEL_ENGULFING", 0.15  # +15% confidence
                
                # TERTIARY: Level test with BOS (weakest acceptable)
                # Only if no rejection/engulfing detected
                return True, "BUY_LEVEL_BOS", 0.08  # +8% confidence (weakest)
            else:
                # NOT AT LEVEL - don't enter on continuation
                return False, "NO_LEVEL_TEST_BUY", 0.0
        
        elif signal == "sell":
            # ⚡ PRIMARY ENTRY: SELL = Price rejects FROM LOW with UPPER WICK ⚡
            # Price low tested recent lows (=level test), last candle shows REJECTION
            if last['low'] < recent_lows:  # Price tested the level
                is_rejection, rejection_strength = is_rejection_candle(last, "sell")
                if is_rejection:
                    # ✅ REJECTION ENTRY: Price touched level, got rejected downward with strong wick
                    return True, f"SELL_REJECTION_{rejection_strength:.1f}x", 0.25  # +25% confidence (BEST)
                
                # SECONDARY: Strong momentum candle at level (engulfing + volume)
                if last['close'] < last['open']:  # Bearish
                    if last['open'] > prev['close'] and last['close'] < prev['open']:  # Engulfing
                        last_vol = last.get('tick_volume', 0)
                        prev_vol = prev.get('tick_volume', 1)
                        if last_vol > prev_vol * 1.2:  # Volume expansion
                            return True, "SELL_ENGULFING_VOL_SPIKE", 0.18  # +18% confidence
                        return True, "SELL_LEVEL_ENGULFING", 0.15  # +15% confidence
                
                # TERTIARY: Level test with BOS (weakest acceptable)
                # Only if no rejection/engulfing detected
                return True, "SELL_LEVEL_BOS", 0.08  # +8% confidence (weakest)
            else:
                # NOT AT LEVEL - don't enter on continuation
                return False, "NO_LEVEL_TEST_SELL", 0.0
        
        return False, "UNKNOWN_SIGNAL", 0.0
    
    except Exception as e:
        return False, f"ENTRY_TF_CHECK_ERROR: {str(e)}", 0.0


def analyze_fvg_zone(context):
    """
    Enhanced FVG analysis with price action confirmation.
    
    FVG Quality Scoring:
    - High quality + liquidity swept + price in zone = STRONG BUY signal
    - High quality + in zone = SUPPORTING factor
    - Detected but out of zone = SOFT BLOCK (depends on other factors)
    - No FVG = Lower confidence only
    
    Price Action Confirmation:
    - Pin bar / engulfing within zone = Strong confirmation
    - Close on side of trade = Moderate confirmation
    - Wick into zone = Weak confirmation
    """
    # Populate SMC/ICT features so downstream logic can use them
    try:
        populate_smc_ict_features(context)
    except Exception:
        # best-effort; if detectors missing or fail, continue without SMC features
        pass

    fvg_detected = context.features.get("fvg_detected", False)
    entry_zone = context.features.get("entry_zone", None)
    fvg_quality = context.features.get("fvg_quality", False)
    liquidity_swept = context.features.get("liquidity_swept", False)
    confirmation = context.features.get("confirmation", False)
    bos = context.features.get("bos", None)  # Break of Structure direction

    # Ensure filter lists exist on context
    if not hasattr(context, 'blocking_filters'):
        context.blocking_filters = []
    if not hasattr(context, 'supporting_filters'):
        context.supporting_filters = []

    in_zone = False
    zone_quality = 0.0
    zone_distance = 999.0  # Distance from price to zone (how far away)
    reason = ""

    # --- Auto-detect price-action confirmation if not already provided ---
    def detect_price_confirmation(ctx, zone):
        try:
            if zone is None or not isinstance(zone, dict):
                return False, ""
            last = ctx.df.iloc[-1]
            prev = ctx.df.iloc[-2] if len(ctx.df) >= 2 else last
            zone_low = zone.get("low")
            zone_high = zone.get("high")
            mid = (zone_low + zone_high) / 2.0
            # Engulfing (directional)
            bullish_engulf = (last['close'] > last['open'] and prev['close'] < prev['open'] and last['close'] > prev['open'] and last['open'] < prev['close'])
            bearish_engulf = (last['close'] < last['open'] and prev['close'] > prev['open'] and last['close'] < prev['open'] and last['open'] > prev['close'])
            # Pin bar: small body with long opposite wick entering zone
            body = abs(last['close'] - last['open'])
            upper_wick = last['high'] - max(last['close'], last['open'])
            lower_wick = min(last['close'], last['open']) - last['low']
            wick_ratio = 0
            if body > 0:
                wick_ratio = max(upper_wick, lower_wick) / body
            pin_buy = (lower_wick > 2.5 * body and last['low'] <= zone_high and last['low'] >= zone_low)
            pin_sell = (upper_wick > 2.5 * body and last['high'] >= zone_low and last['high'] <= zone_high)
            # Close on side of trade
            close_buy_side = last['close'] >= mid
            close_sell_side = last['close'] <= mid
            # Combine into confirmation depending on intended direction (use BOS if present)
            conf = False
            conf_reasons = []
            # If price inside zone, check strong patterns
            if zone_low <= last['low'] <= zone_high or zone_low <= last['close'] <= zone_high or zone_low <= last['high'] <= zone_high:
                if bullish_engulf:
                    conf = True
                    conf_reasons.append('bullish_engulf')
                if bearish_engulf:
                    conf = True
                    conf_reasons.append('bearish_engulf')
                if pin_buy:
                    conf = True
                    conf_reasons.append('pin_buy')
                if pin_sell:
                    conf = True
                    conf_reasons.append('pin_sell')
                # Prioritize strong patterns (engulf / pin). Close-on-side alone is weak
                if bullish_engulf:
                    conf = True
                    conf_reasons.append('bullish_engulf')
                if bearish_engulf:
                    conf = True
                    conf_reasons.append('bearish_engulf')
                if pin_buy:
                    conf = True
                    conf_reasons.append('pin_buy')
                if pin_sell:
                    conf = True
                    conf_reasons.append('pin_sell')

                # Allow close-side to count only when accompanied by a strong wick/pattern
                if close_buy_side and (pin_buy or bullish_engulf or wick_ratio >= 1.5):
                    conf = True
                    conf_reasons.append('close_buy_side_strong')
                if close_sell_side and (pin_sell or bearish_engulf or wick_ratio >= 1.5):
                    conf = True
                    conf_reasons.append('close_sell_side_strong')
            return conf, ",".join(conf_reasons)
        except Exception:
            return False, ""

    auto_conf, auto_conf_reasons = detect_price_confirmation(context, entry_zone)
    if auto_conf and not confirmation:
        confirmation = True
        # persist detected confirmation for downstream logic
        context.features['confirmation'] = True
        context.features['confirmation_reasons'] = auto_conf_reasons

    # Require BOS confirmation before allowing high confidence or entry
    bos_confirmed = bos is not None and bos == context.signal

    if not bos_confirmed:
        reason = "BOS NOT CONFIRMED - BLOCKING ENTRY"
        zone_quality = 0.0
        context.blocking_filters.append("NO_BOS_CONFIRMATION")
        context.fvg_analysis = {
            "aligned": False,
            "bos_confirmed": False,
            "zone_quality": zone_quality,
            "reason": reason
        }
        return


    if not fvg_detected:
        reason = "No FVG detected"
        zone_quality = 0.3
    else:
        reason = "FVG DETECTED"
        zone_quality = 0.5

        # Boost quality based on FVG characteristics
        if fvg_quality:
            reason += " (High Quality)"
            zone_quality = 0.7

        if liquidity_swept:
            reason += " + Liquidity Swept"
            zone_quality = 0.85  # Very strong signal

        # Check if price is in entry zone (CRITICAL for entry)
        if entry_zone and isinstance(entry_zone, dict):
            zone_low = entry_zone.get("low")
            zone_high = entry_zone.get("high")
            if zone_low and zone_high:
                # Calculate proximity to zone
                if context.price < zone_low:
                    zone_distance = zone_low - context.price
                elif context.price > zone_high:
                    zone_distance = context.price - zone_high
                else:
                    zone_distance = 0.0

                if zone_low <= context.price <= zone_high:
                    in_zone = True
                    reason += " + PRICE IN ZONE"
                    zone_quality = min(0.98, zone_quality + 0.20)  # Major boost

                    # Add confirmation bonus
                    if confirmation:
                        reason += " + CONFIRMATION"
                        zone_quality = min(1.0, zone_quality + 0.15)  # Massive boost
                else:
                    # Price NOT in zone - check how close
                    pip_size = 0.01 if "JPY" in context.symbol else 0.0001
                    max_distance = 10 * pip_size  # Allow 10 pips away for "close enough"
                    
                    if zone_distance <= max_distance:
                        # CLOSE to zone = Still tradeable with caution
                        reason += f" (Price {zone_distance/pip_size:.1f} pips from zone)"
                        zone_quality = 0.50  # Neutral - not blocking but not strong
                    else:
                        # FAR from zone = Skip this setup
                        reason += f" (Price too far: {zone_distance/pip_size:.1f} pips)"
                        zone_quality = 0.2  # Very weak
    
    context.fvg_analysis = {
        "detected": fvg_detected,
        "quality": zone_quality,
        "in_zone": in_zone,
        "entry_zone": entry_zone,
        "zone_distance_pips": zone_distance,
        "confirmation": confirmation,
        "bos": bos,
        "reason": reason
    }

    # Additional safeguard: require entry-timeframe confirmation (M5/M15)
    try:
        entry_tf_ok, entry_tf_reason, entry_tf_conf = check_entry_tf_confirmation(context)
        context.fvg_analysis['entry_tf'] = {'ok': entry_tf_ok, 'reason': entry_tf_reason, 'confidence': entry_tf_conf}
        if not entry_tf_ok:
            context.blocking_filters.append(f"ENTRY_TF_FAILED:{entry_tf_reason}")
            return
    except Exception:
        # If check fails, be conservative and block
        context.blocking_filters.append("ENTRY_TF_CHECK_ERROR")
        return
    
    # Decision logic based on FVG state
    # ⚡ PRIORITY SHIFT: REJECTION > CONTINUATION ⚡
    # Entry on rejection (price touches zone then closes away with momentum) = BEST
    # Entry on continuation (price just closes in zone) = weaker confirmation
    if fvg_detected:
        if in_zone and confirmation:
            # === STRONGEST: Price in zone + REJECTION PATTERN ===
            # Check if last candle shows rejection (opposite wick > 2x body)
            try:
                last_c = context.df.iloc[-1] if hasattr(context, 'df') and context.df is not None and len(context.df) > 0 else None
                if last_c is not None:
                    o, c, h, l = last_c.get('open', 0), last_c.get('close', 0), last_c.get('high', 0), last_c.get('low', 0)
                    body = abs(c - o)
                    if context.signal == "buy":
                        # Bullish rejection: lower wick > 2x body (absorbed selling)
                        lower_wick = min(o, c) - l
                        if lower_wick > 2.0 * body and body > 0:
                            context.supporting_filters.append(f"FVG_CONFIRMED: {reason} (REJECTION ENTRY - PRIME: Lower wick {lower_wick:.5f} > 2x body {body:.5f})")
                        else:
                            context.supporting_filters.append(f"FVG_CONFIRMED: {reason} (Price in zone + confirmation)")
                    elif context.signal == "sell":
                        # Bearish rejection: upper wick > 2x body (absorbed buying)
                        upper_wick = h - max(o, c)
                        if upper_wick > 2.0 * body and body > 0:
                            context.supporting_filters.append(f"FVG_CONFIRMED: {reason} (REJECTION ENTRY - PRIME: Upper wick {upper_wick:.5f} > 2x body {body:.5f})")
                        else:
                            context.supporting_filters.append(f"FVG_CONFIRMED: {reason} (Price in zone + confirmation)")
                else:
                    context.supporting_filters.append(f"FVG_CONFIRMED: {reason}")
            except Exception:
                context.supporting_filters.append(f"FVG_CONFIRMED: {reason}")
        elif in_zone:
            # MODERATE: Price in zone but waiting for rejection (DON'T enter on continuation)
            context.supporting_filters.append(f"FVG_IN_ZONE_AWAITING_REJECTION: {reason} (Wait for rejection candle with wick > 2x body)")
        elif zone_distance <= (10 * (0.01 if "JPY" in context.symbol else 0.0001)):
            # MODERATE: Close to zone, might wait or trade cautiously
            pass  # Don't block, let other factors decide
        else:
            # WEAK: Far from zone = likely skip
            context.blocking_filters.append(f"FVG_FAR_FROM_ZONE: {reason}")
    else:
        # No FVG = lower confidence but not blocking
        pass

    # Structured logging for debugging entry decisions
    try:
        logging.info(f"[ENTRY_DECISION] {getattr(context,'symbol',None)} price={getattr(context,'price',None)} fvg={context.fvg_analysis} features_keys={list(context.features.keys())} blocking={context.blocking_filters} supporting={context.supporting_filters}")
    except Exception:
        pass


def populate_smc_ict_features(context):
    """
    ADVANCED SMC/ICT Feature Detection with Signal Alignment Validation.
    Populates context.features with high-confidence trading signals.
    
    Ensures:
    - BOS, CHOCH, Liquidity Sweep, FVG are properly validated
    - No conflicting signals are passed downstream
    - All signals aligned with price action and volume
    """
    df = context.df
    features = context.features

    # Default-safe initializations
    features.setdefault('CHOCH', False)
    features.setdefault('bos', None)
    features.setdefault('BSL', False)
    features.setdefault('SSL', False)
    features.setdefault('bsl_level', None)
    features.setdefault('ssl_level', None)
    features.setdefault('inducement', False)
    features.setdefault('inducement_details', {})
    features.setdefault('ob_detected', False)
    features.setdefault('ob_details', {})
    features.setdefault('poi', None)
    features.setdefault('poi_details', {})
    features.setdefault('lower_poi', None)
    features.setdefault('lq_sweep_high', False)
    features.setdefault('lq_sweep_low', False)
    features.setdefault('lq_sweep_details', {})
    features.setdefault('liquidity_swept', False)
    features.setdefault('signal_validation', {})

    # 1) DETECT BOS (Break of Structure) - ADVANCED
    try:
        is_bullish = context.signal == 'buy'
        bos_result = detect_bos(df, is_bullish, window=3)
        if bos_result in ["bullish", "bearish"]:
            # Validate BOS is actually aligned with signal
            if (is_bullish and bos_result == "bullish") or (not is_bullish and bos_result == "bearish"):
                features['bos'] = bos_result
                features['bos_strength'] = "confirmed"
            else:
                features['bos'] = None  # Conflicting BOS direction
        else:
            features['bos'] = None
    except Exception as e:
        features['bos'] = None

    # 2) DETECT CHOCH (Change of Character) - ADVANCED
    try:
        is_bullish = context.signal == 'buy'
        choch_result = detect_sibi_bisi(df, is_bullish, window=3)
        if choch_result in ["bullish", "bearish"]:
            if (is_bullish and choch_result == "bullish") or (not is_bullish and choch_result == "bearish"):
                features['CHOCH'] = True
                features['choch_direction'] = choch_result
            else:
                features['CHOCH'] = False
        else:
            features['CHOCH'] = False
    except Exception as e:
        features['CHOCH'] = False

    # 3) DETECT LIQUIDITY SWEEP - ADVANCED
    try:
        sweep_result = detect_liquidity_sweep(df, lookback=20, types=("swing", "equal"))
        features['liquidity_swept'] = bool(sweep_result)
        
        if features['liquidity_swept']:
            # Record which type of sweep was detected
            if 'swing' in ("swing", "equal"):
                features['lq_sweep_type'] = "swing"
            features['liquidity_sweep_confirmed'] = True
        else:
            features['liquidity_sweep_confirmed'] = False
    except Exception as e:
        features['liquidity_swept'] = False
        features['liquidity_sweep_confirmed'] = False

    # 4) DETECT FVG (Fair Value Gap) - ADVANCED
    try:
        fvg_result = detect_fvg(df, htf_bias=None, zone_low=None, zone_high=None)
        
        if fvg_result:
            features['fvg_detected'] = True
            features['fvg_info'] = fvg_result
            features['fvg_direction'] = fvg_result.get('direction')
            features['fvg_confidence'] = fvg_result.get('confidence', 0.5)
            features['fvg_strength'] = fvg_result.get('displacement_strength', 'weak')
            
            # FVG is only valid if confidence is acceptable
            if features['fvg_confidence'] < 0.6:
                features['fvg_detected'] = False
        else:
            features['fvg_detected'] = False
            features['fvg_info'] = None
            features['fvg_confidence'] = 0.0
    except Exception as e:
        features['fvg_detected'] = False
        features['fvg_info'] = None

    # 5) SIGNAL ALIGNMENT VALIDATION - CRITICAL
    try:
        bos_confirmed = features.get('bos') is not None
        choch_confirmed = features.get('CHOCH', False)
        liquidity_swept = features.get('liquidity_swept', False)
        fvg_detected = features.get('fvg_detected', False)
        
        is_valid, confidence_score, blocking_reasons = validate_signal_alignment(
            df, context.signal, bos_confirmed, choch_confirmed, liquidity_swept, fvg_detected
        )
        
        features['signal_validation'] = {
            'is_valid': is_valid,
            'confidence': confidence_score,
            'blocking_reasons': blocking_reasons,
            'bos_confirmed': bos_confirmed,
            'choch_confirmed': choch_confirmed,
            'liquidity_swept': liquidity_swept,
            'fvg_detected': fvg_detected
        }
        
        # CRITICAL: If validation fails, block entry
        if not is_valid:
            for reason in blocking_reasons:
                context.features.setdefault('blocking_filters', []).append(f"SIGNAL_ALIGNMENT: {reason}")
    
    except Exception as e:
        features['signal_validation'] = {'is_valid': False, 'error': str(e)}

    # 6) Order block detection (heuristic) - Using validated BOS/CHOCH
    try:
        last_close = df['close'].iloc[-2]
        last_open = df['open'].iloc[-2]
        body = abs(last_close - last_open)
        range_ = df['high'].iloc[-2] - df['low'].iloc[-2]
        last_volume = df['tick_volume'].iloc[-2] if 'tick_volume' in df else 0
        avg_volume = df['tick_volume'].iloc[-22:-2].mean() if 'tick_volume' in df and len(df) > 22 else 0
        
        is_large_candle = (range_>0 and body > 0.6 * range_)
        is_volume_spike = (avg_volume>0 and last_volume > avg_volume * 1.2)
        upper_wick = df['high'].iloc[-2] - max(last_close, last_open)
        lower_wick = min(last_close, last_open) - df['low'].iloc[-2]
        wick_reject = lower_wick > body * 0.5 or upper_wick > body * 0.5
        
        ob_detected = False
        if context.signal == 'buy' and last_close > last_open and is_large_candle and is_volume_spike and lower_wick > body*0.5:
            ob_detected = True
        if context.signal == 'sell' and last_close < last_open and is_large_candle and is_volume_spike and upper_wick > body*0.5:
            ob_detected = True
        
        features['ob_detected'] = ob_detected
        features['ob_details'] = {
            'body': body, 'range': range_, 'last_volume': last_volume, 'avg_volume': avg_volume,
            'is_large_candle': is_large_candle, 'is_volume_spike': is_volume_spike, 'wick_reject': wick_reject
        }
    except Exception:
        features['ob_detected'] = False

    # 7) Inducement detection (heuristic) so basically it has to be with validation       
    try:
        lookback = 10
        closes = df['close'].iloc[-lookback:]
        momentum = abs(closes.iloc[-1] - closes.iloc[-2]) > (0.5 * closes.std() if closes.std()>0 else 0)
        inducement = False
        
        if context.signal == 'buy':
            inducement = (closes.min() == closes.iloc[-1]) and momentum
        elif context.signal == 'sell':
            inducement = (closes.max() == closes.iloc[-1]) and momentum
        
        features['inducement'] = bool(inducement)
        features['inducement_details'] = {'momentum': momentum, 'closes_sample': closes.tolist()}
    except Exception:
        features['inducement'] = False

    # 8) POI detection (simple EMA + candle)
    try:
        poi_price = df['low'].iloc[-2] if context.signal == 'buy' else df['high'].iloc[-2]
        ema50 = df['close'].ewm(span=50, adjust=False).mean().iloc[-2]
        ema200 = df['close'].ewm(span=200, adjust=False).mean().iloc[-2]
        ema_ok = (context.signal == 'buy' and ema50 > ema200) or (context.signal == 'sell' and ema50 < ema200)
        candle_ok = (df['close'].iloc[-2] > df['open'].iloc[-2]) if context.signal == 'buy' else (df['close'].iloc[-2] < df['open'].iloc[-2])
        
        if poi_price is not None and ema_ok and candle_ok:
            features['poi'] = poi_price
            features['poi_details'] = {'ema50': ema50, 'ema200': ema200, 'ema_ok': ema_ok, 'candle_ok': candle_ok}
        else:
            features['poi'] = None
            features['poi_details'] = {'ema50': ema50, 'ema200': ema200, 'ema_ok': ema_ok, 'candle_ok': candle_ok}
    except Exception:
        features['poi'] = None

    # 9) Lower-timeframe POI refinement (M5)
    try:
        if 'get_price_data' in globals():
            df_m5 = get_price_data(context.symbol, timeframe="M5", bars=50)
            if df_m5 is not None and len(df_m5) >= 5:
                lower_poi = df_m5['low'].iloc[-2] if context.signal == 'buy' else df_m5['high'].iloc[-2]
                features['lower_poi'] = lower_poi
            else:
                features['lower_poi'] = None
        else:
            features['lower_poi'] = None
    except Exception:
        features['lower_poi'] = None

    # 10) SUMMARY: Log all detected signals for debugging
    features['smc_detection_summary'] = {
        'bos_detected': features.get('bos') is not None,
        'choch_detected': features.get('CHOCH', False),
        'liquidity_swept': features.get('liquidity_swept', False),
        'fvg_detected': features.get('fvg_detected', False),
        'ob_detected': features.get('ob_detected', False),
        'validation_passed': features.get('signal_validation', {}).get('is_valid', False),
        'confidence_score': features.get('signal_validation', {}).get('confidence', 0.0)
    }




    pass


def analyze_momentum_confluence(context):
    """Check if momentum indicators support ML signal."""
    rsi = context.features.get("rsi", 50)
    macd = context.features.get("macd", 0)
    macd_signal = context.features.get("macd_signal", 0)
    
    momentum_supports = False
    momentum_conflicts = False
    reason = ""
    confidence = 0.5
    
    if context.signal == "buy":
        if rsi > 50 and macd > macd_signal:
            momentum_supports = True
            reason = f"RSI({rsi:.0f}) > 50 & MACD bullish"
            confidence = 0.8
        elif rsi > 70:
            momentum_conflicts = True
            reason = f"RSI({rsi:.0f}) OVERBOUGHT"
            confidence = 0.2
        elif rsi < 30:
            momentum_supports = True
            reason = f"RSI({rsi:.0f}) OVERSOLD → Reversal setup"
            confidence = 0.7
    elif context.signal == "sell":
        if rsi < 50 and macd < macd_signal:
            momentum_supports = True
            reason = f"RSI({rsi:.0f}) < 50 & MACD bearish"
            confidence = 0.8
        elif rsi < 30:
            momentum_conflicts = True
            reason = f"RSI({rsi:.0f}) OVERSOLD"
            confidence = 0.2
        elif rsi > 70:
            momentum_supports = True
            reason = f"RSI({rsi:.0f}) OVERBOUGHT → Reversal setup"
            confidence = 0.7
    
    context.momentum_analysis = {
        "supports": momentum_supports,
        "conflicts": momentum_conflicts,
        "rsi": rsi,
        "macd_delta": macd - macd_signal,
        "confidence": confidence,
        "reason": reason
    }
    
    if momentum_supports:
        context.supporting_filters.append(f"MOMENTUM: {reason}")
    elif momentum_conflicts:
        context.blocking_filters.append(f"MOMENTUM: {reason}")

def analyze_volume_confirmation(context):
    """Check if volume supports the move."""
    recent_vol = context.features.get("volume", 0)
    avg_vol = context.features.get("volume_avg_20", 0)
    volume_spike = context.features.get("volume_spike", False)
    tick_volume = context.df.get('tick_volume', None) if hasattr(context, 'df') else None
    
    volume_strong = False
    reason = ""
    confidence = 0.5
    
    if volume_spike:
        volume_strong = True
        reason = "VOLUME SPIKE detected"
        confidence = 0.8
    elif recent_vol > 1.2 * avg_vol if avg_vol > 0 else False:
        volume_strong = True
        reason = f"Volume above average ({recent_vol:.0f} > {1.2*avg_vol:.0f})"
        confidence = 0.7
    else:
        reason = "Volume normal or below average"
        confidence = 0.4
    
    context.volume_analysis = {
        "strong": volume_strong,
        "recent_vol": recent_vol,
        "avg_vol": avg_vol,
        "spike": volume_spike,
        "confidence": confidence,
        "reason": reason
    }
    
    if volume_strong:
        context.supporting_filters.append(f"VOLUME: {reason}")

