def ict_htf_bias(df):
    """
    [DEPRECATED] Use detect_htf_bias() instead (line 12738)
    Simple HTF bias using EMA50/200. Kept for legacy compatibility only.
    """
    if df is None or len(df) < 200:
        return "neutral"
    
    try:
        ema50 = df['close'].ewm(span=50, adjust=False).mean().iloc[-1]
        ema200 = df['close'].ewm(span=200, adjust=False).mean().iloc[-1]
        
        if ema50 > ema200:
            return "bullish"
        elif ema50 < ema200:
            return "bearish"
        else:
            return "neutral"
    except Exception:
        return "neutral"

def ict_detect_bos(df, direction, window=5):
    """
    Detect Break of Structure (BOS) / Market Structure Shift (MSS).
    Clean and strict: last candle must close beyond recent swing level.
    
    Args:
        df: DataFrame with 'high', 'low', 'close' columns
        direction: 'buy' or 'sell'
        window: lookback period for swing identification (default 5)
    
    Returns:
        bool: True if BOS detected, False otherwise
    """
    if df is None or len(df) < window + 1:
        return False
    
    try:
        last_high = df['high'].iloc[-(window+1):-1].max()
        last_low = df['low'].iloc[-(window+1):-1].min()
        current_close = df['close'].iloc[-1]
        
        if direction == "buy":
            # BUY: close must break above last swing high
            return current_close > last_high
        elif direction == "sell":
            # SELL: close must break below last swing low
            return current_close < last_low
        else:
            return False
    except Exception:
        return False

def ict_detect_fvg(df, direction):
    """
    Detect Fair Value Gap (FVG) / Imbalance.
    Real FVG: gap between candle 1 and candle 3 that candle 2 does not fill.
    
    Args:
        df: DataFrame with 'high', 'low' columns
        direction: 'buy' or 'sell'
    
    Returns:
        dict: {'detected': bool, 'zone_high': float, 'zone_low': float}
    """
    if df is None or len(df) < 3:
        return {'detected': False, 'zone_high': None, 'zone_low': None}
    
    try:
        c1 = df.iloc[-3]  # Candle 1 (3 bars ago)
        c2 = df.iloc[-2]  # Candle 2 (2 bars ago)
        c3 = df.iloc[-1]  # Candle 3 (last candle)
        
        if direction == "buy":
            # BULLISH FVG: c1.high < c3.low (gap up, candle 2 doesn't fill)
            if c1['high'] < c3['low']:
                return {
                    'detected': True,
                    'zone_high': c3['low'],
                    'zone_low': c1['high'],
                    'size': c3['low'] - c1['high']
                }
        elif direction == "sell":
            # BEARISH FVG: c1.low > c3.high (gap down, candle 2 doesn't fill)
            if c1['low'] > c3['high']:
                return {
                    'detected': True,
                    'zone_high': c1['low'],
                    'zone_low': c3['high'],
                    'size': c1['low'] - c3['high']
                }
        
        return {'detected': False, 'zone_high': None, 'zone_low': None}
    except Exception:
        return {'detected': False, 'zone_high': None, 'zone_low': None}

def ict_calculate_sl_tp(entry_price, sl_price, rr_ratio=3.0, direction="buy"):
    """
    Calculate SL and TP using strict 1:3 Risk-Reward ratio.
    TP is ALWAYS risk × 3, never arbitrary.
    
    Args:
        entry_price: float, entry price
        sl_price: float, stop loss price
        rr_ratio: float, risk-reward multiple (default 3.0 for 1:3)
        direction: 'buy' or 'sell'
    
    Returns:
        tuple: (sl_price, tp_price)
    """
    risk = abs(entry_price - sl_price)
    
    if direction == "buy":
        tp = entry_price + (risk * rr_ratio)
    elif direction == "sell":
        tp = entry_price - (risk * rr_ratio)
    else:
        tp = entry_price
    
    return sl_price, tp

def analyze_risk_reward(context, entry, sl, tp):
    """Validate risk-reward ratio and position sizing viability.
    
    STRICT ICT RULE: Minimum 1:3 RR enforced.
    - risk = |entry - sl|
    - reward = |tp - entry|
    - rr_ratio must be >= 3.0 (TP must be at least 3× risk away from entry)
    """
    risk = abs(entry - sl)
    reward = abs(tp - entry)
    rr_ratio = reward / risk if risk > 0 else 0
    
    # ICT standard: MUST have 1:3 RR minimum (3.0 ratio)
    min_rr = 3.0
    min_atr = 0.001 if "JPY" not in context.symbol else 0.01
    atr = context.features.get("atr", 0)
    
    rr_ok = rr_ratio >= min_rr
    atr_ok = atr >= min_atr
    reason = ""
    confidence = 0.5
    
    if rr_ok and atr_ok:
        reason = f"EXCELLENT RR ({rr_ratio:.2f}:1) & ATR ({atr:.5f}) [ICT Standard]"
        confidence = 0.9
    elif rr_ok and not atr_ok:
        reason = f"Good RR ({rr_ratio:.2f}:1) but ATR low ({atr:.5f} < {min_atr})"
        confidence = 0.7
    elif not rr_ok:
        reason = f"BLOCKED: Poor RR ({rr_ratio:.2f}:1 < {min_rr}:1) [ICT Minimum 1:3]"
        confidence = 0.0
    else:
        reason = f"ATR too low ({atr:.5f} < {min_atr})"
        confidence = 0.2
    
    context.risk_analysis = {
        "rr_ratio": rr_ratio,
        "rr_ok": rr_ok,
        "atr": atr,
        "atr_ok": atr_ok,
        "confidence": confidence,
        "reason": reason,
        "model": "ICT_STRICT_1:3"
    }
    
    if not rr_ok:
        context.blocking_filters.append(f"ICT_RR: {reason}")
    elif rr_ok:
        context.supporting_filters.append(f"ICT_RR: {reason}")

def analyze_market_regime(context):
    """
    Market Regime Classifier (MANDATORY):
    Classifies market as 'expansion' (trend) or 'compression' (range) and blocks/filters trades accordingly.

    Expansion: Only allow BUY pullbacks (block sells)
    Compression: Allow both fades & sells

    Expansion logic (works well on XAUUSD):
    IF candle_range > ATR * 1.5 AND consecutive higher highs → EXPANSION MODE
    """
    regime = context.features.get("regime", "unknown")
    session = context.features.get("session", "unknown")
    news_impact = context.features.get("news_impact", 0)
    atr = context.features.get("atr", 0)
    df = context.df

    # --- Market Regime Detection ---
    expansion = False
    compression = False
    expansion_reason = ""
    if len(df) >= 4 and atr > 0:
        last_bar = df.iloc[-1]
        prev1 = df.iloc[-2]
        prev2 = df.iloc[-3]
        prev3 = df.iloc[-4]
        candle_range = last_bar['high'] - last_bar['low']
        # Expansion: Large candle + consecutive higher highs
        consecutive_hh = (
            last_bar['high'] > prev1['high'] and
            prev1['high'] > prev2['high'] and
            prev2['high'] > prev3['high']
        )
        if candle_range > 1.5 * atr and consecutive_hh:
            expansion = True
            expansion_reason = f"Expansion: Range {candle_range:.2f} > 1.5*ATR ({atr:.2f}), 3x higher highs"
        else:
            compression = True
            expansion_reason = f"Compression: Range {candle_range:.2f} <= 1.5*ATR ({atr:.2f}) or not consecutive highs"
    else:
        compression = True
        expansion_reason = "Compression: Not enough bars or ATR=0"

    # Save regime to context
    context.market_regime = "expansion" if expansion else "compression"
    context.features["market_regime"] = context.market_regime

    # --- Regime-based trade filtering ---
    regime_ok = True
    reason = f"Regime: {context.market_regime}, Session: {session}. {expansion_reason}"
    confidence = 0.6

    # Expansion: Only allow BUY pullbacks, block sells
    if expansion and context.signal == "sell":
        regime_ok = False
        reason += " (Expansion: SELLs blocked, only buy pullbacks allowed)"
        confidence = 0.1

    # Symbol-specific session requirements
    if context.symbol.startswith("XAU"):
        hour = context.features.get("hour", 12)
        if not (6 <= hour <= 16):
            regime_ok = False
            reason += " (Gold: outside London/NY)"
            confidence = 0.1

    if news_impact == 1:
        regime_ok = False
        reason += " (High news impact)"
        confidence = 0.2

    context.regime_analysis = {
        "regime": context.market_regime,
        "session": session,
        "news_impact": news_impact,
        "ok": regime_ok,
        "confidence": confidence,
        "reason": reason
    }

    if not regime_ok:
        context.blocking_filters.append(f"REGIME: {reason}")
    elif regime_ok:
        context.supporting_filters.append(f"REGIME: {reason}")

def check_h1_structure_hard_filter(context):
    """
    🚨 HARD FILTER FOR BUYs ONLY:
    
    BUYs only allowed if:
    1. H1 structure = bullish (EMA ribbon aligned)
    OR
    2. M15 BOS (Break of Structure) + H1 bullish candle close above key level
    
    Returns: (pass: bool, reason: str)
    """
    signal = context.signal
    
    # Only apply this filter to BUY signals
    if signal != "buy":
        return (True, "HARD_FILTER: Not a BUY (SELL allowed without H1 filter)")
    
    try:
        # Get H1 data from context
        df_h1 = context.features.get('df_h1')
        df_m15 = context.df  # Current M15 data
        
        if df_h1 is None or len(df_h1) < 21:
            return (False, "HARD_FILTER: No H1 data available")
        
        if df_m15 is None or len(df_m15) < 3:
            return (False, "HARD_FILTER: No M15 data available")
        
        # Check H1 structure (EMA alignment)
        h1_ema21 = df_h1['close'].ewm(span=21).mean()
        h1_ema50 = df_h1['close'].ewm(span=50).mean()
        h1_ema200 = df_h1['close'].ewm(span=200).mean()
        
        h1_bullish_structure = (
            h1_ema21.iloc[-1] > h1_ema50.iloc[-1] > h1_ema200.iloc[-1]
        )
        
        if h1_bullish_structure:
            return (True, "HARD_FILTER: ✓ H1 structure is BULLISH (EMA21 > EMA50 > EMA200)")
        
        # If H1 structure is not bullish, check for M15 BOS + H1 bullish candle close above key level
        # M15 BOS
        m15_bos = context.features.get('bos') == 'bullish'
        
        if not m15_bos:
            return (False, "HARD_FILTER: ✗ H1 structure NOT bullish AND M15 BOS not detected")
        
        # H1 bullish candle close above key level (use H1 EMA50 or recent swing high)
        h1_last_close = df_h1['close'].iloc[-1]
        h1_ema50_level = h1_ema50.iloc[-1]
        h1_recent_high = df_h1['high'].iloc[-5:].max()  # Last 5 H1 bars
        
        # Check if H1 closed above EMA50 (conservative) or above recent swing
        h1_close_above_key_level = h1_last_close > h1_ema50_level
        
        if m15_bos and h1_close_above_key_level:
            return (True, f"HARD_FILTER: ✓ M15 BOS + H1 closed above EMA50 ({h1_ema50_level:.5f})")
        
        return (False, f"HARD_FILTER: ✗ H1 not bullish, M15 BOS exists but H1 not above key level ({h1_last_close:.5f} vs {h1_ema50_level:.5f})")
    
    except Exception as e:
        return (False, f"HARD_FILTER: Error checking H1 structure - {str(e)}")

# ══════════════════════════════════════════════════════════════════════════════
# 🔥 SMART MONEY CONCEPT (SMC) DISCOUNT/PREMIUM FILTERS
# ══════════════════════════════════════════════════════════════════════════════
# These filters prevent chasing price and ensure entries at optimal levels

def check_discount_premium_filter(context):
    """
    🔥 DISCOUNT/PREMIUM FILTER (CRITICAL FOR SMART MONEY ENTRIES)
    
    BUY RULE:
    - Only allow buys when price is at DISCOUNT (below 50% of last bullish impulse)
    - OR inside bullish FVG / demand zone
    - NO BUY if price > 50% retracement of last bullish leg
    
    SELL RULE:
    - Only allow sells when price is at PREMIUM (above 50% of last bearish impulse)
    - OR inside bearish FVG / supply zone
    - NO SELL if price < 50% retracement of last bearish leg
    
    Returns: (pass: bool, reason: str, retracement_pct: float)
    """
    signal = context.signal
    df = context.df
    price = context.price
    features = context.features if hasattr(context, 'features') and isinstance(context.features, dict) else {}
    
    try:
        if df is None or len(df) < 20:
            return (False, "DISCOUNT_FILTER: Not enough data", 0.0)
        
        # === HTF RANGE (protected high/low) ===
        df_h4 = features.get('df_h4')
        df_h1 = features.get('df_h1')
        range_df = df_h4 if df_h4 is not None and len(df_h4) >= 30 else (df_h1 if df_h1 is not None and len(df_h1) >= 30 else df)

        def _last_swing_levels(data, lookback=80):
            if data is None or len(data) < 10:
                return None, None
            recent = data.iloc[-lookback:]
            highs = recent['high'].values
            lows = recent['low'].values
            swing_high_idx = None
            swing_low_idx = None
            for i in range(1, len(recent) - 1):
                if highs[i] > highs[i-1] and highs[i] > highs[i+1]:
                    swing_high_idx = i
                if lows[i] < lows[i-1] and lows[i] < lows[i+1]:
                    swing_low_idx = i
            range_high = float(recent.iloc[swing_high_idx]['high']) if swing_high_idx is not None else float(recent['high'].max())
            range_low = float(recent.iloc[swing_low_idx]['low']) if swing_low_idx is not None else float(recent['low'].min())
            return range_high, range_low

        range_high, range_low = _last_swing_levels(range_df, lookback=80)
        if range_high is None or range_low is None:
            range_high = float(df['high'].iloc[-80:].max()) if df is not None and len(df) >= 10 else price
            range_low = float(df['low'].iloc[-80:].min()) if df is not None and len(df) >= 10 else price

        range_mid = (range_high + range_low) / 2.0

        # tolerance near range edges using HTF ATR or fallback
        try:
            htf_atr = (range_df['high'] - range_df['low']).rolling(14).mean().iloc[-1] if range_df is not None else 0
        except Exception:
            htf_atr = 0
        edge_tol = max((htf_atr or 0) * 0.15, 1e-6)
        at_range_high = price is not None and price >= (range_high - edge_tol)
        at_range_low = price is not None and price <= (range_low + edge_tol)
        in_discount = price is not None and price <= range_mid
        in_premium = price is not None and price >= range_mid

        # Sweep + CHOCH context
        liquidity_swept = bool(features.get('liquidity_swept', False))
        choch_confirmed = bool(features.get('CHOCH', False) or features.get('choch_confirmed', False))
        choch_direction = features.get('choch_direction')

        # HTF breakout + retest heuristic
        breakout_retest = False
        try:
            recent_htf = range_df.iloc[-10:] if range_df is not None and len(range_df) >= 10 else None
            if recent_htf is not None:
                if signal == 'buy':
                    broke_above = recent_htf['high'].max() > (range_high + edge_tol)
                    breakout_retest = broke_above and price is not None and abs(price - range_high) <= edge_tol * 2
                elif signal == 'sell':
                    broke_below = recent_htf['low'].min() < (range_low - edge_tol)
                    breakout_retest = broke_below and price is not None and abs(price - range_low) <= edge_tol * 2
        except Exception:
            breakout_retest = False

        # Check FVG zones from context
        fvg_analysis = context.fvg_analysis if hasattr(context, 'fvg_analysis') else {}
        in_fvg_zone = fvg_analysis.get('in_zone', False)
        entry_zone = fvg_analysis.get('entry_zone', {})

        # === RANGE GATE (with CONFLUENCE OVERRIDE) ===
        # Allow entries in non-ideal zones if confluence is VERY STRONG
        confidence_score = getattr(context, 'confidence', 0) if hasattr(context, 'confidence') else 0
        filter_pass_count = getattr(context, 'filter_pass_count', 0) if hasattr(context, 'filter_pass_count') else 0
        
        # OVERRIDE: Allow BUY in premium if (9/9 filters + 0.75+ confidence) OR (FVG/sweep+CHOCH/breakout)
        premium_override_allowed = (filter_pass_count >= 9 and confidence_score >= 0.75) or in_fvg_zone or (liquidity_swept and choch_confirmed) or breakout_retest
        discount_override_allowed = (filter_pass_count >= 9 and confidence_score >= 0.75) or in_fvg_zone or (liquidity_swept and choch_confirmed) or breakout_retest
        
        if signal == 'buy':
            allow_buy = (
                in_discount or
                in_fvg_zone or
                (liquidity_swept and choch_confirmed and (choch_direction in (None, 'bullish'))) or
                breakout_retest
            )
            # Allow BUY in premium if strong confluence
            if in_premium or at_range_high:
                if not premium_override_allowed:
                    return (False, f"DISCOUNT_FILTER: ✗ BUY blocked (price in premium/range high; mid={range_mid:.5f}) - Use strong confluence to override", 0.0)
                else:
                    # Premium allowed with override
                    return (True, f"DISCOUNT_FILTER: ✓ BUY in PREMIUM (9/9 filters + {confidence_score:.2f} confidence) - Override allowed", 0.8)
            if not allow_buy:
                return (False, "DISCOUNT_FILTER: ✗ BUY blocked (no discount/FVG/sweep+CHOCH/breakout-retest)", 0.0)
        elif signal == 'sell':
            allow_sell = (
                in_premium or
                in_fvg_zone or
                (liquidity_swept and choch_confirmed and (choch_direction in (None, 'bearish'))) or
                breakout_retest
            )
            # Allow SELL in discount if strong confluence
            if in_discount or at_range_low:
                if not discount_override_allowed:
                    return (False, f"DISCOUNT_FILTER: ✗ SELL blocked (price in discount/range low; mid={range_mid:.5f}) - Use strong confluence to override", 0.0)
                else:
                    # Discount allowed with override
                    return (True, f"DISCOUNT_FILTER: ✓ SELL in DISCOUNT (9/9 filters + {confidence_score:.2f} confidence) - Override allowed", 0.8)
            if not allow_sell:
                return (False, "DISCOUNT_FILTER: ✗ SELL blocked (no premium/FVG/sweep+CHOCH/breakout-retest)", 0.0)

        # Find last impulse move (strong directional candle)
        def find_last_impulse(df, direction, lookback=30):
            """
            Find the last significant impulse candle in the given direction.
            Impulse = body > 60% of range AND body > 1.3x average body of last 10 bars
            """
            if len(df) < lookback:
                return None
            
            recent = df.iloc[-lookback:]
            avg_body = abs(recent['close'] - recent['open']).mean()
            
            # Search backwards for impulse
            for i in range(len(recent) - 1, max(0, len(recent) - lookback), -1):
                bar = recent.iloc[i]
                body = abs(bar['close'] - bar['open'])
                total_range = bar['high'] - bar['low']
                
                if total_range <= 0:
                    continue
                
                body_ratio = body / total_range
                
                # Check if it's an impulse candle
                is_impulse = (body_ratio > 0.6 and body > 1.3 * avg_body)
                
                if direction == 'bullish':
                    if is_impulse and bar['close'] > bar['open']:
                        return {
                            'high': float(bar['high']),
                            'low': float(bar['low']),
                            'open': float(bar['open']),
                            'close': float(bar['close']),
                            'body': float(body),
                            'index': i
                        }
                elif direction == 'bearish':
                    if is_impulse and bar['close'] < bar['open']:
                        return {
                            'high': float(bar['high']),
                            'low': float(bar['low']),
                            'open': float(bar['open']),
                            'close': float(bar['close']),
                            'body': float(body),
                            'index': i
                        }
            
            return None
        
        # FVG zones already loaded above
        
        if signal == 'buy':
            # Find last bullish impulse
            last_impulse = find_last_impulse(df, 'bullish', lookback=30)
            
            if last_impulse is None:
                # No impulse found - check if in FVG demand zone
                if in_fvg_zone and entry_zone:
                    return (True, "DISCOUNT_FILTER: ✓ Inside bullish FVG/demand zone (no impulse needed)", 0.0)
                return (False, "DISCOUNT_FILTER: ✗ No bullish impulse found and not in FVG zone", 0.0)
            
            # Calculate 50% retracement level of the impulse
            impulse_start = last_impulse['low']
            impulse_end = last_impulse['high']
            fifty_percent = impulse_start + 0.5 * (impulse_end - impulse_start)
            
            # Calculate current retracement percentage
            if impulse_end > impulse_start:
                retracement_pct = ((impulse_end - price) / (impulse_end - impulse_start)) * 100
            else:
                retracement_pct = 0.0
            
            # BUY only allowed if:
            # 1. Price is BELOW 50% (in discount) OR
            # 2. Price is in bullish FVG/demand zone
            if price <= fifty_percent:
                return (True, f"DISCOUNT_FILTER: ✓ BUY at DISCOUNT ({retracement_pct:.1f}% pullback, below 50%)", retracement_pct)
            elif in_fvg_zone:
                return (True, f"DISCOUNT_FILTER: ✓ BUY inside FVG/demand zone ({retracement_pct:.1f}% pullback)", retracement_pct)
            else:
                return (False, f"DISCOUNT_FILTER: ✗ BUY at PREMIUM blocked ({retracement_pct:.1f}% pullback > 50%, not in FVG)", retracement_pct)
        
        elif signal == 'sell':
            # Find last bearish impulse
            last_impulse = find_last_impulse(df, 'bearish', lookback=30)
            
            if last_impulse is None:
                # No impulse found - check if in FVG supply zone
                if in_fvg_zone and entry_zone:
                    return (True, "DISCOUNT_FILTER: ✓ Inside bearish FVG/supply zone (no impulse needed)", 0.0)
                return (False, "DISCOUNT_FILTER: ✗ No bearish impulse found and not in FVG zone", 0.0)
            
            # Calculate 50% retracement level of the impulse
            impulse_start = last_impulse['high']
            impulse_end = last_impulse['low']
            fifty_percent = impulse_start - 0.5 * (impulse_start - impulse_end)
            
            # Calculate current retracement percentage
            if impulse_start > impulse_end:
                retracement_pct = ((price - impulse_end) / (impulse_start - impulse_end)) * 100
            else:
                retracement_pct = 0.0
            
            # SELL only allowed if:
            # 1. Price is ABOVE 50% (in premium) OR
            # 2. Price is in bearish FVG/supply zone
            if price >= fifty_percent:
                return (True, f"DISCOUNT_FILTER: ✓ SELL at PREMIUM ({retracement_pct:.1f}% pullback, above 50%)", retracement_pct)
            elif in_fvg_zone:
                return (True, f"DISCOUNT_FILTER: ✓ SELL inside FVG/supply zone ({retracement_pct:.1f}% pullback)", retracement_pct)
            else:
                return (False, f"DISCOUNT_FILTER: ✗ SELL at DISCOUNT blocked ({retracement_pct:.1f}% pullback < 50%, not in FVG)", retracement_pct)
        
        return (False, "DISCOUNT_FILTER: Unknown signal type", 0.0)
    
    except Exception as e:
        return (False, f"DISCOUNT_FILTER: Error - {str(e)}", 0.0)


def check_trend_weakness_filter(context):
    """
    🛡️ TREND WEAKNESS DETECTION FILTER (ANTI-AVERAGING INTO DANGER)
    
    Prevents entries when trend is showing signs of exhaustion/reversal:
    - Declining momentum (EMA compression)
    - Volume divergence (price moves but volume decreases)
    - Weakening candle bodies
    - RSI divergence
    - Multiple rejections at key levels
    
    This prevents "averaging into danger" where bot keeps buying as trend dies.
    
    Returns: (pass: bool, reason: str, strength_score: int)
    """
    signal = context.signal
    df = context.df
    price = context.price
    
    try:
        if df is None or len(df) < 50:
            return (True, "TREND_FILTER: Insufficient data - allowing entry", 50)  # Fail-safe: allow if no data
        
        strength_score = 100  # Start at 100, deduct for weakness signs
        weakness_reasons = []
        
        # ═══════════════════════════════════════════════════════════════════
        # 1. EMA ALIGNMENT & COMPRESSION CHECK
        # ═══════════════════════════════════════════════════════════════════
        ema9 = df['close'].ewm(span=9).mean()
        ema21 = df['close'].ewm(span=21).mean()
        ema50 = df['close'].ewm(span=50).mean()
        
        current_ema9 = ema9.iloc[-1]
        current_ema21 = ema21.iloc[-1]
        current_ema50 = ema50.iloc[-1]
        
        # Check EMA alignment
        if signal == 'buy':
            # For BUY: Want EMA9 > EMA21 > EMA50 (bullish stack)
            proper_alignment = current_ema9 > current_ema21 > current_ema50
            
            if not proper_alignment:
                strength_score -= 30
                weakness_reasons.append("EMAs not stacked bullish")
            
            # Check EMA compression (sign of weakening trend)
            ema_spread_pct = ((current_ema9 - current_ema50) / current_ema50) * 100 if current_ema50 != 0 else 0
            
            if abs(ema_spread_pct) < 0.15:  # Less than 0.15% spread = compressed
                strength_score -= 25
                weakness_reasons.append(f"EMA compression ({ema_spread_pct:.2f}%)")
            
            # Check if EMA9 is flattening (momentum dying)
            ema9_slope = (ema9.iloc[-1] - ema9.iloc[-5]) / ema9.iloc[-5] * 100 if ema9.iloc[-5] != 0 else 0
            
            if ema9_slope < 0.05:  # Less than 0.05% rise over 5 bars = flat/falling
                strength_score -= 20
                weakness_reasons.append(f"EMA9 flattening ({ema9_slope:.2f}%)")
        
        elif signal == 'sell':
            # For SELL: Want EMA9 < EMA21 < EMA50 (bearish stack)
            proper_alignment = current_ema9 < current_ema21 < current_ema50
            
            if not proper_alignment:
                strength_score -= 30
                weakness_reasons.append("EMAs not stacked bearish")
            
            # Check EMA compression
            ema_spread_pct = ((current_ema50 - current_ema9) / current_ema50) * 100 if current_ema50 != 0 else 0
            
            if abs(ema_spread_pct) < 0.15:
                strength_score -= 25
                weakness_reasons.append(f"EMA compression ({ema_spread_pct:.2f}%)")
            
            # Check if EMA9 is flattening
            ema9_slope = (ema9.iloc[-5] - ema9.iloc[-1]) / ema9.iloc[-5] * 100 if ema9.iloc[-5] != 0 else 0
            
            if ema9_slope < 0.05:  # Less than 0.05% fall over 5 bars = flat/rising
                strength_score -= 20
                weakness_reasons.append(f"EMA9 flattening ({ema9_slope:.2f}%)")
        
        # ═══════════════════════════════════════════════════════════════════
        # 2. VOLUME DIVERGENCE CHECK (Price moves but volume decreases = weakness)
        # ═══════════════════════════════════════════════════════════════════
        if 'tick_volume' in df.columns:
            recent_vol = df['tick_volume'].iloc[-5:].mean()
            prev_vol = df['tick_volume'].iloc[-15:-5].mean()
            
            vol_decrease_pct = ((prev_vol - recent_vol) / prev_vol) * 100 if prev_vol != 0 else 0
            
            # If volume is decreasing while price is trending = exhaustion
            if vol_decrease_pct > 20:  # Volume dropped more than 20%
                strength_score -= 15
                weakness_reasons.append(f"Volume divergence (-{vol_decrease_pct:.0f}%)")
        
        # ═══════════════════════════════════════════════════════════════════
        # 3. CANDLE BODY WEAKNESS (Decreasing body sizes = losing momentum)
        # ═══════════════════════════════════════════════════════════════════
        recent_bodies = abs(df['close'].iloc[-5:] - df['open'].iloc[-5:])
        avg_recent_body = recent_bodies.mean()
        
        prev_bodies = abs(df['close'].iloc[-15:-5] - df['open'].iloc[-15:-5])
        avg_prev_body = prev_bodies.mean()
        
        body_decrease_pct = ((avg_prev_body - avg_recent_body) / avg_prev_body) * 100 if avg_prev_body != 0 else 0
        
        if body_decrease_pct > 30:  # Bodies shrinking by 30%+ = weakness
            strength_score -= 15
            weakness_reasons.append(f"Shrinking candles (-{body_decrease_pct:.0f}%)")
        
        # ═══════════════════════════════════════════════════════════════════
        # 4. RSI DIVERGENCE CHECK (Price makes new high/low but RSI doesn't)
        # ═══════════════════════════════════════════════════════════════════
        try:
            # Calculate RSI
            delta = df['close'].diff()
            up = delta.clip(lower=0)
            down = -delta.clip(upper=0)
            roll_up = up.rolling(14).mean()
            roll_down = down.rolling(14).mean()
            rs = roll_up / (roll_down + 1e-9)
            rsi = 100 - (100 / (1 + rs))
            
            current_rsi = rsi.iloc[-1]
            prev_rsi_high = rsi.iloc[-10:-1].max()
            prev_rsi_low = rsi.iloc[-10:-1].min()
            
            if signal == 'buy':
                # Check for bearish divergence (price higher but RSI lower)
                current_price_high = df['high'].iloc[-1]
                prev_price_high = df['high'].iloc[-10:-1].max()
                
                if current_price_high > prev_price_high and current_rsi < prev_rsi_high:
                    strength_score -= 25
                    weakness_reasons.append(f"Bearish RSI divergence (RSI {current_rsi:.0f})")
                
                # Check if RSI is overbought (>75 = danger zone)
                if current_rsi > 75:
                    strength_score -= 20
                    weakness_reasons.append(f"RSI overbought ({current_rsi:.0f})")
            
            elif signal == 'sell':
                # Check for bullish divergence (price lower but RSI higher)
                current_price_low = df['low'].iloc[-1]
                prev_price_low = df['low'].iloc[-10:-1].min()
                
                if current_price_low < prev_price_low and current_rsi > prev_rsi_low:
                    strength_score -= 25
                    weakness_reasons.append(f"Bullish RSI divergence (RSI {current_rsi:.0f})")
                
                # Check if RSI is oversold (<25 = danger zone)
                if current_rsi < 25:
                    strength_score -= 20
                    weakness_reasons.append(f"RSI oversold ({current_rsi:.0f})")
        
        except Exception:
            pass  # Skip RSI check if calculation fails
        
        # ═══════════════════════════════════════════════════════════════════
        # 5. MULTIPLE REJECTIONS AT KEY LEVEL (Sign of reversal)
        # ═══════════════════════════════════════════════════════════════════
        if signal == 'buy':
            # Count how many times price failed to break above recent high
            recent_high = df['high'].iloc[-20:].max()
            tolerance = recent_high * 0.0002  # 0.02% tolerance
            
            rejection_count = 0
            for i in range(-15, -1):
                if abs(df['high'].iloc[i] - recent_high) <= tolerance and df['close'].iloc[i] < df['open'].iloc[i]:
                    rejection_count += 1
            
            if rejection_count >= 3:
                strength_score -= 20
                weakness_reasons.append(f"{rejection_count} rejections at resistance")
        
        elif signal == 'sell':
            # Count how many times price failed to break below recent low
            recent_low = df['low'].iloc[-20:].min()
            tolerance = recent_low * 0.0002
            
            rejection_count = 0
            for i in range(-15, -1):
                if abs(df['low'].iloc[i] - recent_low) <= tolerance and df['close'].iloc[i] > df['open'].iloc[i]:
                    rejection_count += 1
            
            if rejection_count >= 3:
                strength_score -= 20
                weakness_reasons.append(f"{rejection_count} rejections at support")
        
        # ═══════════════════════════════════════════════════════════════════
        # FINAL DECISION: Block if strength score below 40 (too many weakness signs)
        # ═══════════════════════════════════════════════════════════════════
        strength_score = max(0, strength_score)  # Keep in 0-100 range
        
        if strength_score < 40:
            reason = f"TREND WEAKNESS DETECTED (score: {strength_score}/100) - " + ", ".join(weakness_reasons[:3])
            return (False, reason, strength_score)
        else:
            if strength_score >= 70:
                reason = f"Strong trend (score: {strength_score}/100) - safe to enter"
            else:
                reason = f"Moderate trend (score: {strength_score}/100) - proceed with caution"
            return (True, reason, strength_score)
    
    except Exception as e:
        # Fail-safe: Allow entry if error occurs (don't block due to technical issue)
        return (True, f"TREND_FILTER: Error - {str(e)} (allowing entry)", 50)


def check_no_entry_after_expansion(context):
    """
    🔥 NO-ENTRY-AFTER-EXPANSION (UPGRADED)

    Robust expansion filter using ATR + retracement logic:
    - Impulse = large body AND large range relative to ATR
    - Requires either:
      (a) sufficient corrective candles after impulse, or
      (b) price has retraced to a key zone (>= 38.2%) or FVG tap
    - Corrective requirement scales with volatility regime

    BUY RULE: After bullish impulse, require pullback/consolidation before buy
    SELL RULE: After bearish impulse, require pullback/consolidation before sell

    Returns: (pass: bool, reason: str, corrective_count: int)
    """
    signal = context.signal
    df = context.df
    
    try:
        if df is None or len(df) < 10:
            return (True, "EXPANSION_FILTER: Not enough data to check", 0)
        
        # ATR-based impulse detection
        recent = df.iloc[-20:] if len(df) >= 20 else df
        avg_body = abs(recent['close'] - recent['open']).mean()
        atr_series = (recent['high'] - recent['low']).rolling(14).mean()
        atr = float(atr_series.iloc[-1]) if len(atr_series) > 0 and not atr_series.isna().iloc[-1] else float(avg_body or 0)
        atr = max(atr, 1e-9)

        def is_strong_impulse_candle(bar, avg_body_local, atr_local):
            """Strong impulse = body > 60% of range AND body/range strong vs ATR."""
            body = abs(bar['close'] - bar['open'])
            total_range = bar['high'] - bar['low']
            if total_range <= 0:
                return False
            body_ratio = body / total_range
            return (body_ratio > 0.6 and body > 1.2 * atr_local and total_range > 1.5 * atr_local and body > 1.2 * avg_body_local)
        
        # Look back to find last strong impulse
        lookback = min(15, len(df) - 1)
        last_impulse_index = None
        impulse_direction = None
        
        for i in range(len(df) - 1, max(0, len(df) - lookback - 1), -1):
            bar = df.iloc[i]
            
            if is_strong_impulse_candle(bar, avg_body, atr):
                if signal == 'buy' and bar['close'] > bar['open']:
                    # Found bullish impulse for BUY signal
                    last_impulse_index = i
                    impulse_direction = 'bullish'
                    break
                elif signal == 'sell' and bar['close'] < bar['open']:
                    # Found bearish impulse for SELL signal
                    last_impulse_index = i
                    impulse_direction = 'bearish'
                    break
        
        # If no recent impulse found, allow entry (no expansion to wait for)
        if last_impulse_index is None:
            return (True, "EXPANSION_FILTER: ✓ No recent expansion detected", 0)
        
        # Count corrective/pullback candles after the impulse
        corrective_count = 0
        bars_since_impulse = len(df) - 1 - last_impulse_index
        
        if bars_since_impulse <= 0:
            # Impulse is the current candle - BLOCK entry (too soon!)
            return (False, "EXPANSION_FILTER: ✗ Strong impulse just occurred (0 pullback candles)", 0)
        
        # Determine volatility regime and required correction count
        atr_mean = float(atr_series.mean()) if len(atr_series) > 0 and not atr_series.isna().all() else atr
        vol_ratio = (atr / atr_mean) if atr_mean > 0 else 1.0
        if vol_ratio >= 1.2:
            required_corrective = 2  # high volatility: faster pullbacks
        elif vol_ratio <= 0.8:
            required_corrective = 4  # low volatility: require more digestion
        else:
            required_corrective = 3

        # Track retracement level after impulse
        impulse_bar = df.iloc[last_impulse_index]
        imp_high = float(impulse_bar['high'])
        imp_low = float(impulse_bar['low'])
        imp_range = max(imp_high - imp_low, 1e-9)

        # Count corrective candles (opposite or consolidation)
        for i in range(last_impulse_index + 1, len(df)):
            bar = df.iloc[i]
            body = abs(bar['close'] - bar['open'])
            
            # Corrective candle = small body OR opposite direction
            is_corrective = False
            
            if impulse_direction == 'bullish':
                # After bullish impulse, corrective = bearish or small (relative to ATR)
                is_corrective = (bar['close'] < bar['open']) or (body < 0.6 * atr)
            elif impulse_direction == 'bearish':
                # After bearish impulse, corrective = bullish or small (relative to ATR)
                is_corrective = (bar['close'] > bar['open']) or (body < 0.6 * atr)
            
            if is_corrective:
                corrective_count += 1
        
        # Allow if price has retraced to at least 38.2% or tapped FVG zone
        retrace_ok = False
        try:
            if impulse_direction == 'bullish':
                retrace_pct = ((imp_high - context.price) / imp_range) if context.price is not None else 0.0
            else:
                retrace_pct = ((context.price - imp_low) / imp_range) if context.price is not None else 0.0
            retrace_ok = retrace_pct >= 0.382
        except Exception:
            retrace_ok = False

        fvg_analysis = context.fvg_analysis if hasattr(context, 'fvg_analysis') else {}
        in_fvg_zone = bool(fvg_analysis.get('in_zone', False))

        if corrective_count >= required_corrective or retrace_ok or in_fvg_zone:
            reason_parts = []
            if corrective_count >= required_corrective:
                reason_parts.append(f"{corrective_count} corrective candles")
            if retrace_ok:
                reason_parts.append("retraced ≥ 38.2%")
            if in_fvg_zone:
                reason_parts.append("FVG tap")
            reason = "+".join(reason_parts) if reason_parts else "pullback detected"
            return (True, f"EXPANSION_FILTER: ✓ Pullback confirmed ({reason})", corrective_count)
        else:
            return (False, f"EXPANSION_FILTER: ✗ Insufficient pullback ({corrective_count}/{required_corrective} corrective candles after expansion)", corrective_count)
    
    except Exception as e:
        return (True, f"EXPANSION_FILTER: Error (allowing) - {str(e)}", 0)


def check_liquidity_sweep_condition(context):
    """
    🔥 LIQUIDITY SWEEP CONDITION (OPTIONAL BUT POWERFUL)
    
    Best entry = after liquidity sweep + confirmation
    
    BUY RULE:
    - Sweep a minor low (wick below recent low)
    - THEN bullish confirmation (close back above the swept low)
    - This gives "sniper entries" instead of chase entries
    
    SELL RULE:
    - Sweep a minor high (wick above recent high)
    - THEN bearish confirmation (close back below the swept high)
    
    Returns: (has_sweep: bool, has_confirmation: bool, reason: str)
    """
    signal = context.signal
    df = context.df
    
    try:
        if df is None or len(df) < 15:
            return (False, False, "LIQUIDITY_SWEEP: Not enough data")
        
        # Get last 15 bars for analysis
        recent = df.iloc[-15:]
        current = df.iloc[-1]
        
        if signal == 'buy':
            # Look for minor low sweep for BUY
            # 1. Find recent lows (exclude current bar)
            recent_lows = recent['low'].iloc[:-1]
            minor_low = recent_lows.min()
            
            # 2. Check if current bar's LOW swept below (wick touched it)
            swept_low = current['low'] < minor_low
            
            # 3. Check for bullish confirmation (close back above the swept level)
            confirmed = current['close'] > minor_low
            
            if swept_low and confirmed:
                return (True, True, f"LIQUIDITY_SWEEP: ✓ BUY after sweeping low {minor_low:.5f} with bullish confirmation")
            elif swept_low and not confirmed:
                return (True, False, f"LIQUIDITY_SWEEP: ⚠ Low swept but NO confirmation (close still below {minor_low:.5f})")
            else:
                # No sweep detected - this is OPTIONAL, so we allow entry without it
                # but note it as missing for quality scoring
                return (False, False, "LIQUIDITY_SWEEP: ⓘ No low sweep detected (optional enhancement)")
        
        elif signal == 'sell':
            # Look for minor high sweep for SELL
            # 1. Find recent highs (exclude current bar)
            recent_highs = recent['high'].iloc[:-1]
            minor_high = recent_highs.max()
            
            # 2. Check if current bar's HIGH swept above (wick touched it)
            swept_high = current['high'] > minor_high
            
            # 3. Check for bearish confirmation (close back below the swept level)
            confirmed = current['close'] < minor_high
            
            if swept_high and confirmed:
                return (True, True, f"LIQUIDITY_SWEEP: ✓ SELL after sweeping high {minor_high:.5f} with bearish confirmation")
            elif swept_high and not confirmed:
                return (True, False, f"LIQUIDITY_SWEEP: ⚠ High swept but NO confirmation (close still above {minor_high:.5f})")
            else:
                # No sweep detected - this is OPTIONAL, so we allow entry without it
                return (False, False, "LIQUIDITY_SWEEP: ⓘ No high sweep detected (optional enhancement)")
        
        return (False, False, "LIQUIDITY_SWEEP: Unknown signal type")
    
    except Exception as e:
        return (False, False, f"LIQUIDITY_SWEEP: Error - {str(e)}")


# ══════════════════════════════════════════════════════════════════════════════
# 🔒 STRUCTURE-BASED RE-ENTRY PREVENTION SYSTEM
# ══════════════════════════════════════════════════════════════════════════════
# Prevents duplicate entries at the same structure level unless there's a genuine
# new trading opportunity (new BOS, structure reset, or momentum confirmation)

# Global tracker for structure entries (persists across iterations)
STRUCTURE_ENTRY_TRACKER = {}

def check_structure_reentry_allowed(context):
    """
    🔒 STRUCTURE RE-ENTRY PREVENTION
    
    Blocks re-entries at the same structure level unless:
    1. New BOS (Break of Structure) occurs - price breaks to new high/low
    2. Full structure reset - major trend reversal with opposite BOS
    3. Momentum confirmation reset - new impulse wave in same direction
    
    This prevents:
    - Revenge trading (re-entering after stop-out at same level)
    - Over-trading (multiple entries in same consolidation)
    - Chasing (entering same setup repeatedly without new confirmation)
    
    Returns: (allowed: bool, reason: str, structure_key: str)
    """
    global STRUCTURE_ENTRY_TRACKER
    
    signal = context.signal
    df = context.df
    price = context.price
    symbol = context.symbol
    
    try:
        if df is None or len(df) < 30:
            return (True, "REENTRY_CHECK: Not enough data to track structure", "")
        
        # === STEP 1: Identify current structure level ===
        def get_current_structure_level(df, signal, lookback=20):
            """
            Get the current key structure level (swing high/low) that defines this setup.
            This is the level we use to track if we've already traded this structure.
            """
            if signal == 'buy':
                # For BUY: find last significant swing low (support level)
                recent = df.iloc[-lookback:]
                swing_low = recent['low'].min()
                # Find the index where this low occurred
                swing_idx = recent['low'].idxmin()
                return float(swing_low), swing_idx
            elif signal == 'sell':
                # For SELL: find last significant swing high (resistance level)
                recent = df.iloc[-lookback:]
                swing_high = recent['high'].max()
                # Find the index where this high occurred
                swing_idx = recent['high'].idxmax()
                return float(swing_high), swing_idx
            
            return None, None
        
        structure_level, structure_idx = get_current_structure_level(df, signal)
        
        if structure_level is None:
            return (True, "REENTRY_CHECK: Could not identify structure level", "")
        
        # Create unique structure key for tracking
        # Format: SYMBOL_DIRECTION_LEVEL_TOLERANCE
        pip_size = 0.01 if 'JPY' in symbol else 0.0001
        if 'XAU' in symbol or 'GOLD' in symbol:
            pip_size = 0.10
        
        # Round to nearest 5 pips to create zones (prevents too granular tracking)
        level_zone = round(structure_level / (5 * pip_size)) * (5 * pip_size)
        structure_key = f"{symbol}_{signal}_{level_zone:.5f}"
        
        # === STEP 2: Check if we've already entered at this structure ===
        if structure_key in STRUCTURE_ENTRY_TRACKER:
            last_entry = STRUCTURE_ENTRY_TRACKER[structure_key]
            last_entry_time = last_entry.get('timestamp', 0)
            last_entry_level = last_entry.get('level', 0)
            last_bos_count = last_entry.get('bos_count', 0)
            
            # === STEP 3: Check for NEW BOS (allows re-entry) ===
            def detect_new_bos_since_entry(df, signal, last_entry_idx):
                """
                Check if a new BOS has occurred since the last entry.
                BOS = price closes beyond the previous swing high/low.
                """
                try:
                    # Get bars since last entry
                    if last_entry_idx >= len(df):
                        bars_since = df.iloc[-10:]  # Fallback: check last 10 bars
                    else:
                        bars_since = df.iloc[last_entry_idx:]
                    
                    if len(bars_since) < 3:
                        return False, 0
                    
                    if signal == 'buy':
                        # For BUY: look for bullish BOS (close above previous swing high)
                        swing_highs = []
                        for i in range(len(bars_since) - 2):
                            if (bars_since.iloc[i]['high'] > bars_since.iloc[i-1]['high'] if i > 0 else True and 
                                bars_since.iloc[i]['high'] > bars_since.iloc[i+1]['high']):
                                swing_highs.append(bars_since.iloc[i]['high'])
                        
                        if swing_highs:
                            last_swing_high = max(swing_highs)
                            current_close = bars_since.iloc[-1]['close']
                            if current_close > last_swing_high:
                                return True, len(swing_highs)
                    
                    elif signal == 'sell':
                        # For SELL: look for bearish BOS (close below previous swing low)
                        swing_lows = []
                        for i in range(len(bars_since) - 2):
                            if (bars_since.iloc[i]['low'] < bars_since.iloc[i-1]['low'] if i > 0 else True and 
                                bars_since.iloc[i]['low'] < bars_since.iloc[i+1]['low']):
                                swing_lows.append(bars_since.iloc[i]['low'])
                        
                        if swing_lows:
                            last_swing_low = min(swing_lows)
                            current_close = bars_since.iloc[-1]['close']
                            if current_close < last_swing_low:
                                return True, len(swing_lows)
                    
                    return False, 0
                
                except Exception:
                    return False, 0
            
            last_entry_idx = last_entry.get('bar_index', len(df) - 20)
            has_new_bos, bos_count = detect_new_bos_since_entry(df, signal, last_entry_idx)
            
            if has_new_bos and bos_count > last_bos_count:
                # NEW BOS DETECTED - Allow re-entry!
                return (True, f"REENTRY_ALLOWED: New BOS detected (count: {bos_count} vs {last_bos_count})", structure_key)
            
            # === STEP 4: Check for STRUCTURE RESET (opposite BOS) ===
            def detect_structure_reset(df, signal, lookback=15):
                """
                Check if structure has fully reset (opposite direction BOS).
                This indicates a trend reversal, so re-entries are allowed.
                """
                try:
                    recent = df.iloc[-lookback:]
                    
                    if signal == 'buy':
                        # For BUY setup: check if there's been a bearish BOS (structure reset)
                        # This would be a close below recent swing low
                        swing_lows = recent['low'].rolling(3, center=True).min()
                        for i in range(len(recent) - 3):
                            if recent.iloc[i]['close'] < swing_lows.iloc[i]:
                                return True
                    
                    elif signal == 'sell':
                        # For SELL setup: check if there's been a bullish BOS (structure reset)
                        # This would be a close above recent swing high
                        swing_highs = recent['high'].rolling(3, center=True).max()
                        for i in range(len(recent) - 3):
                            if recent.iloc[i]['close'] > swing_highs.iloc[i]:
                                return True
                    
                    return False
                
                except Exception:
                    return False
            
            structure_reset = detect_structure_reset(df, signal)
            
            if structure_reset:
                # STRUCTURE RESET - Allow re-entry!
                return (True, "REENTRY_ALLOWED: Structure reset detected (opposite BOS)", structure_key)
            
            # === STEP 5: Check for MOMENTUM CONFIRMATION RESET ===
            def detect_momentum_reset(df, signal, lookback=10):
                """
                Check if there's a new strong impulse in the same direction.
                This means new momentum has built up, allowing re-entry.
                """
                try:
                    recent = df.iloc[-lookback:]
                    if len(recent) < 5:
                        return False
                    
                    # Calculate average body size
                    avg_body = abs(recent['close'] - recent['open']).mean()
                    
                    # Look for strong impulse candles (body > 2x average)
                    impulse_count = 0
                    for i in range(len(recent)):
                        bar = recent.iloc[i]
                        body = abs(bar['close'] - bar['open'])
                        total_range = bar['high'] - bar['low']
                        
                        if total_range <= 0:
                            continue
                        
                        # Strong impulse criteria
                        body_ratio = body / total_range
                        is_strong = (body > 2.0 * avg_body and body_ratio > 0.7)
                        
                        if signal == 'buy' and bar['close'] > bar['open'] and is_strong:
                            impulse_count += 1
                        elif signal == 'sell' and bar['close'] < bar['open'] and is_strong:
                            impulse_count += 1
                    
                    # Require at least 2 strong impulses for momentum reset
                    return impulse_count >= 2
                
                except Exception:
                    return False
            
            momentum_reset = detect_momentum_reset(df, signal)
            
            if momentum_reset:
                # MOMENTUM RESET - Allow re-entry!
                return (True, "REENTRY_ALLOWED: Momentum confirmation reset (new impulse wave)", structure_key)
            
            # === STEP 6: Check time-based reset (24 hours) ===
            import time
            current_time = time.time()
            time_since_entry = current_time - last_entry_time
            hours_since_entry = time_since_entry / 3600
            
            if hours_since_entry >= 24:
                # 24+ hours since last entry - allow re-entry
                return (True, f"REENTRY_ALLOWED: 24+ hours since last entry ({hours_since_entry:.1f}h)", structure_key)
            
            # === BLOCK RE-ENTRY ===
            return (False, f"REENTRY_BLOCKED: Already entered at {structure_level:.5f} ({hours_since_entry:.1f}h ago). Need new BOS, structure reset, or momentum reset.", structure_key)
        
        # === STEP 7: First entry at this structure - ALLOW ===
        return (True, f"REENTRY_ALLOWED: First entry at structure level {structure_level:.5f}", structure_key)
    
    except Exception as e:
        # On error, allow entry (fail-safe)
        return (True, f"REENTRY_CHECK: Error (allowing) - {str(e)}", "")


def register_structure_entry(structure_key, context):
    """
    Register that we've entered a trade at this structure level.
    Called after trade execution to update the tracker.
    """
    global STRUCTURE_ENTRY_TRACKER
    
    try:
        import time
        
        STRUCTURE_ENTRY_TRACKER[structure_key] = {
            'timestamp': time.time(),
            'level': context.price,
            'bar_index': len(context.df) - 1,
            'bos_count': 0,  # Will be incremented as new BOS occur
            'signal': context.signal
        }
        
        print(f"[STRUCTURE TRACKER] Registered entry: {structure_key}")
    
    except Exception as e:
        print(f"[STRUCTURE TRACKER ERROR] Failed to register: {e}")


# ══════════════════════════════════════════════════════════════════════════════
# 🔥 FIX #1: BOS DELAY + PULLBACK WAIT SYSTEM
# ══════════════════════════════════════════════════════════════════════════════
# After M15 BOS, don't enter immediately
# Wait for pullback → retrace into POI → confirmation → then enter
# This eliminates early entries and whipsaw damage

BOS_TRACKER = {}  # Track when BOS occurred per symbol

def register_bos_detection(symbol: str, signal: str):
    """Register when BOS is detected on M15"""
    global BOS_TRACKER
    if symbol not in BOS_TRACKER:
        BOS_TRACKER[symbol] = {}
    
    BOS_TRACKER[symbol][signal] = {
        'timestamp': time.time(),
        'bar_index': -1,  # Will be updated
        'status': 'detected',  # detected → waiting_pullback → pullback_confirmed → ready_entry
        'pullback_start_price': None,
        'initial_impulse_high': None,
        'initial_impulse_low': None
    }
    print(f"[BOS DETECTED] {symbol} {signal.upper()} — Starting BOS delay sequence")

def check_bos_pullback_status(symbol: str, signal: str, current_price: float, df_m15) -> dict:
    """
    Check if pullback from BOS impulse is confirmed.
    Returns: {
        'ready_to_enter': bool,
        'pullback_confirmed': bool,
        'retracement_pct': float,
        'reason': str
    }
    """
    global BOS_TRACKER
    
    try:
        if symbol not in BOS_TRACKER or signal not in BOS_TRACKER[symbol]:
            return {
                'ready_to_enter': False,
                'pullback_confirmed': False,
                'retracement_pct': 0,
                'reason': 'No BOS detected yet'
            }
        
        bos_info = BOS_TRACKER[symbol][signal]
        
        # For BUY: Wait for pullback from high, then enter when retracing back up
        # For SELL: Wait for pullback from low, then enter when retracing back down
        
        if len(df_m15) < 5:
            return {
                'ready_to_enter': False,
                'pullback_confirmed': False,
                'retracement_pct': 0,
                'reason': 'Insufficient M15 data'
            }
        
        # Get last 10 candles to find impulse and pullback
        recent = df_m15.iloc[-10:].copy()
        
        if signal == 'buy':
            # BUY: Find the impulse high (where BOS occurred), then pullback, then retrace
            impulse_high = recent['high'].max()
            impulse_low = recent['low'].min()
            retracement_level = impulse_low + 0.5 * (impulse_high - impulse_low)  # 50%
            lower_retrace = impulse_low + 0.3 * (impulse_high - impulse_low)  # 30%
            
            # Check if price has retraced to at least 50% of the move
            if current_price >= lower_retrace and current_price <= retracement_level:
                pullback_confirmed = True
                retracement_pct = ((impulse_high - current_price) / (impulse_high - impulse_low)) * 100
            else:
                pullback_confirmed = False
                retracement_pct = 0
        else:  # SELL
            # SELL: Find the impulse low (where BOS occurred), then pullback, then retrace
            impulse_high = recent['high'].max()
            impulse_low = recent['low'].min()
            retracement_level = impulse_high - 0.5 * (impulse_high - impulse_low)  # 50%
            upper_retrace = impulse_high - 0.3 * (impulse_high - impulse_low)  # 30%
            
            # Check if price has retraced to at least 50% of the move
            if current_price >= retracement_level and current_price <= upper_retrace:
                pullback_confirmed = True
                retracement_pct = ((current_price - impulse_low) / (impulse_high - impulse_low)) * 100
            else:
                pullback_confirmed = False
                retracement_pct = 0
        
        ready_to_enter = pullback_confirmed
        
        return {
            'ready_to_enter': ready_to_enter,
            'pullback_confirmed': pullback_confirmed,
            'retracement_pct': retracement_pct,
            'reason': f"Pullback confirmed: {pullback_confirmed}, Retrace: {retracement_pct:.1f}%"
        }
    
    except Exception as e:
        return {
            'ready_to_enter': False,
            'pullback_confirmed': False,
            'retracement_pct': 0,
            'reason': f'Error: {str(e)}'
        }


# ══════════════════════════════════════════════════════════════════════════════
# 🔥 FIX #2: STRICT DISCOUNT/PREMIUM ENTRY ZONE ENFORCER
# ══════════════════════════════════════════════════════════════════════════════
# Force entries ONLY at optimal retracement levels
# BUY: 50-79% retrace OR deepest FVG OR lower 30% of POI
# SELL: Mirror logic

def calculate_optimal_entry_zone(symbol: str, signal: str, df_m15, fvg_info: dict = None) -> dict:
    """
    Calculate OPTIMAL entry zone using Smart Money Concepts.
    
    Returns: {
        'zone_low': float,
        'zone_high': float,
        'optimal_price': float,  # Best limit price to use
        'zone_type': str,  # 'fvg', 'retracement', 'poi'
        'description': str
    }
    """
    try:
        if len(df_m15) < 20:
            return {'zone_low': 0, 'zone_high': 0, 'optimal_price': 0, 'zone_type': 'none', 'description': 'Insufficient data'}
        
        recent = df_m15.iloc[-20:].copy()
        high = recent['high'].max()
        low = recent['low'].min()
        mid = (high + low) / 2
        range_size = high - low
        
        if signal == 'buy':
            # Optimal BUY zones:
            # 1. FVG (deepest part - usually lower part)
            if fvg_info and 'low' in fvg_info and 'high' in fvg_info:
                fvg_low = fvg_info['low']
                fvg_high = fvg_info['high']
                return {
                    'zone_low': fvg_low,
                    'zone_high': fvg_low + 0.3 * (fvg_high - fvg_low),  # Lower 30% of FVG
                    'optimal_price': fvg_low + 0.1 * (fvg_high - fvg_low),  # Deepest part
                    'zone_type': 'fvg',
                    'description': f'FVG deepest part (${fvg_low + 0.1 * (fvg_high - fvg_low):.4f})'
                }
            
            # 2. 50-79% retracement of last impulse
            fifty_level = low + 0.5 * (high - low)
            seventy_level = low + 0.7 * (high - low)
            
            return {
                'zone_low': fifty_level,
                'zone_high': seventy_level,
                'optimal_price': fifty_level + 0.5 * (seventy_level - fifty_level),
                'zone_type': 'retracement',
                'description': f'50-79% retrace zone (${fifty_level:.4f} - ${seventy_level:.4f})'
            }
        
        else:  # SELL
            # Optimal SELL zones:
            # 1. FVG (deepest part - usually upper part)
            if fvg_info and 'low' in fvg_info and 'high' in fvg_info:
                fvg_low = fvg_info['low']
                fvg_high = fvg_info['high']
                return {
                    'zone_low': fvg_high - 0.3 * (fvg_high - fvg_low),  # Upper 30% of FVG
                    'zone_high': fvg_high,
                    'optimal_price': fvg_high - 0.1 * (fvg_high - fvg_low),  # Deepest part
                    'zone_type': 'fvg',
                    'description': f'FVG deepest part (${fvg_high - 0.1 * (fvg_high - fvg_low):.4f})'
                }
            
            # 2. 50-79% retracement of last impulse
            fifty_level = high - 0.5 * (high - low)
            seventy_level = high - 0.7 * (high - low)
            
            return {
                'zone_low': seventy_level,
                'zone_high': fifty_level,
                'optimal_price': seventy_level + 0.5 * (fifty_level - seventy_level),
                'zone_type': 'retracement',
                'description': f'50-79% retrace zone (${seventy_level:.4f} - ${fifty_level:.4f})'
            }
    
    except Exception as e:
        return {'zone_low': 0, 'zone_high': 0, 'optimal_price': 0, 'zone_type': 'error', 'description': f'Error: {str(e)}'}

def is_price_in_optimal_zone(current_price: float, signal: str, zone_info: dict) -> bool:
    """Check if current price is in the optimal entry zone"""
    try:
        zone_low = zone_info.get('zone_low', 0)
        zone_high = zone_info.get('zone_high', 0)
        
        if signal == 'buy':
            return zone_low <= current_price <= zone_high
        else:  # SELL
            return zone_high <= current_price <= zone_low
    except:
        return False


# ══════════════════════════════════════════════════════════════════════════════
# 🔥 FIX #3: M5 CANDLE CONFIRMATION GATE
# ══════════════════════════════════════════════════════════════════════════════
# Before entry, require ONE of:
# - M5 engulfing (small TF confirmation)
# - M5 displacement candle (strong directional move)
# - M1 liquidity sweep + reclaim
# - Strong rejection wick from POI

def check_m5_candle_confirmation(symbol: str, signal: str, df_m5, poi_price: float = None) -> dict:
    """
    Check M5 candle for confirmation before entry.
    
    Returns: {
        'confirmed': bool,
        'reason': str,
        'confirmation_type': str,  # 'engulfing', 'displacement', 'sweep_reclaim', 'wick_rejection', 'none'
        'strength': float  # 0-1.0 confidence
    }
    """
    try:
        if df_m5 is None or len(df_m5) < 5:
            return {
                'confirmed': False,
                'reason': 'Insufficient M5 data',
                'confirmation_type': 'none',
                'strength': 0
            }
        
        recent_m5 = df_m5.iloc[-3:].copy()
        current_candle = recent_m5.iloc[-1]
        prev_candle = recent_m5.iloc[-2]
        
        # 1. Check for engulfing pattern
        if signal == 'buy':
            # Bullish engulfing: current close > prev open AND current open < prev close
            if (current_candle['close'] > prev_candle['open'] and 
                current_candle['open'] < prev_candle['close'] and
                current_candle['close'] > prev_candle['high']):
                return {
                    'confirmed': True,
                    'reason': 'M5 bullish engulfing detected',
                    'confirmation_type': 'engulfing',
                    'strength': 0.9
                }
        else:  # SELL
            # Bearish engulfing: current close < prev open AND current open > prev close
            if (current_candle['close'] < prev_candle['open'] and 
                current_candle['open'] > prev_candle['close'] and
                current_candle['close'] < prev_candle['low']):
                return {
                    'confirmed': True,
                    'reason': 'M5 bearish engulfing detected',
                    'confirmation_type': 'engulfing',
                    'strength': 0.9
                }
        
        # 2. Check for displacement candle (large body)
        current_body = abs(current_candle['close'] - current_candle['open'])
        current_range = current_candle['high'] - current_candle['low']
        prev_avg_body = abs(recent_m5['close'] - recent_m5['open']).iloc[:-1].mean()
        
        if current_body > 1.5 * prev_avg_body:  # 50% larger body
            if signal == 'buy' and current_candle['close'] > current_candle['open']:
                return {
                    'confirmed': True,
                    'reason': f'M5 bullish displacement candle (body: {current_body:.6f})',
                    'confirmation_type': 'displacement',
                    'strength': 0.85
                }
            elif signal == 'sell' and current_candle['close'] < current_candle['open']:
                return {
                    'confirmed': True,
                    'reason': f'M5 bearish displacement candle (body: {current_body:.6f})',
                    'confirmation_type': 'displacement',
                    'strength': 0.85
                }
        
        # 3. Check for strong wick rejection from POI
        if poi_price is not None:
            wick_size_buy = current_candle['low'] < poi_price and current_candle['close'] > poi_price
            wick_size_sell = current_candle['high'] > poi_price and current_candle['close'] < poi_price
            
            if signal == 'buy' and wick_size_buy:
                return {
                    'confirmed': True,
                    'reason': f'M5 bullish wick rejection from ${poi_price:.4f}',
                    'confirmation_type': 'wick_rejection',
                    'strength': 0.8
                }
            elif signal == 'sell' and wick_size_sell:
                return {
                    'confirmed': True,
                    'reason': f'M5 bearish wick rejection from ${poi_price:.4f}',
                    'confirmation_type': 'wick_rejection',
                    'strength': 0.8
                }
        
        # No confirmation found
        return {
            'confirmed': False,
            'reason': 'No M5 candle confirmation pattern found',
            'confirmation_type': 'none',
            'strength': 0
        }
    
    except Exception as e:
        return {
            'confirmed': False,
            'reason': f'Error checking M5 confirmation: {str(e)}',
            'confirmation_type': 'none',
            'strength': 0
        }


# ══════════════════════════════════════════════════════════════════════════════
# 🔥 FIX #4: LIMIT ORDER ENTRY SYSTEM
# ══════════════════════════════════════════════════════════════════════════════
# Replace market orders with limit orders at optimal_retrace_price
# Improves RR and reduces drawdown

def calculate_limit_order_price(signal: str, optimal_entry_zone: dict, current_price: float) -> dict:
    """
    Calculate the best limit order price based on optimal entry zone.
    
    For BUYs: Place limit order at zone_low (wait for price to come to discount)
    For SELLs: Place limit order at zone_high (wait for price to come to premium)
    
    Returns: {
        'limit_price': float,
        'is_better_entry': bool,
        'discount_vs_current': float,  # How much better the limit is than current
        'reasoning': str
    }
    """
    try:
        zone_low = optimal_entry_zone.get('zone_low', 0)
        zone_high = optimal_entry_zone.get('zone_high', 0)
        optimal = optimal_entry_zone.get('optimal_price', 0)
        
        if signal == 'buy':
            limit_price = zone_low  # Wait for price to drop to discount zone
            discount = ((current_price - limit_price) / current_price) * 100
            
            return {
                'limit_price': limit_price,
                'is_better_entry': limit_price < current_price,
                'discount_vs_current': discount,
                'reasoning': f'BUY limit at ${limit_price:.4f} (${discount:.2f} better than ${current_price:.4f})'
            }
        
        else:  # SELL
            limit_price = zone_high  # Wait for price to rise to premium zone
            premium = ((limit_price - current_price) / current_price) * 100
            
            return {
                'limit_price': limit_price,
                'is_better_entry': limit_price > current_price,
                'discount_vs_current': premium,
                'reasoning': f'SELL limit at ${limit_price:.4f} (${premium:.2f} better than ${current_price:.4f})'
            }
    
    except Exception as e:
        return {
            'limit_price': current_price,
            'is_better_entry': False,
            'discount_vs_current': 0,
            'reasoning': f'Error: {str(e)}'
        }

# ══════════════════════════════════════════════════════════════════════════════
# 🎯 MULTI-MODEL ENTRY SYSTEM (5 Advanced Entry Models)
# ══════════════════════════════════════════════════════════════════════════════
# Dynamic entry model selection: Hydra, SMC Classic, Hydra-Lite, Displacement, Range Fade

# ─────────────────────────────────────────────────────────────────────────────
# 🥇 MODEL #1: HYDRA ENTRY (Multi-Head Confirmation)
# ─────────────────────────────────────────────────────────────────────────────
# "No single signal trusted. Confluence creates the entry."
# Minimum 3 of 5 heads must align

def evaluate_hydra_model(context: dict) -> dict:
    """
    Hydra Entry = 4+ of 5 confirmation heads aligned
    
    Heads:
    1. HTF Bias (H4/H1 bullish/bearish)
    2. Liquidity Event (sweep, stop run, inducement)
    3. Structure Shift (CHOCH or BOS on M15/M5)
    4. POI Interaction (FVG, OB, discount-premium zone)
    5. Entry Candle Confirmation (engulfing, displacement, reclaim)
    
    Backtest Results: 27 trades | 59.3% WR | 1.44 RR | +1252 pips
    
    Returns: {
        'applicable': bool,
        'heads_aligned': int,  # 0-5
        'heads_details': list,
        'confidence': float,  # 0-1.0
        'reasoning': str
    }
    """
    try:
        heads_aligned = 0
        heads_details = []
        
        # HEAD 1: HTF Bias (not required to fail, but boosts score if present and aligned)
        htf_bias = context.get('htf_bias', None)
        signal = context.get('signal', 'unknown')
        if htf_bias in ['bullish', 'bearish']:
            if (htf_bias == 'bullish' and signal == 'buy') or (htf_bias == 'bearish' and signal == 'sell'):
                heads_aligned += 1
                heads_details.append(f"✅ HTF Bias: {htf_bias} aligned with {signal.upper()}")
            else:
                heads_details.append(f"❌ HTF Bias: {htf_bias} against {signal.upper()}")
        else:
            # HTF unavailable - don't penalize, check other heads
            heads_details.append(f"⚠️ HTF Bias: Unclear/Unavailable (allowable in live trading)")
        
        # HEAD 2: Liquidity Event
        has_sweep = context.get('liquidity_swept', False) or context.get('has_sweep', False)
        if has_sweep:
            heads_aligned += 1
            heads_details.append(f"✅ Liquidity Event: Sweep detected")
        else:
            heads_details.append(f"❌ Liquidity Event: No sweep")
        
        # HEAD 3: Structure Shift
        bos_confirmed = context.get('bos_confirmed_m15', False)
        choch_confirmed = context.get('choch_confirmed', False)
        if bos_confirmed or choch_confirmed:
            heads_aligned += 1
            structure_type = "BOS" if bos_confirmed else "CHOCH"
            heads_details.append(f"✅ Structure Shift: {structure_type} confirmed")
        else:
            heads_details.append(f"❌ Structure Shift: No BOS/CHOCH")
        
        # HEAD 4: POI Interaction
        fvg_detected = context.get('fvg_detected', False)
        price_in_zone = context.get('price_in_discount', False) or context.get('price_in_premium', False)
        if fvg_detected or price_in_zone:
            heads_aligned += 1
            poi_type = "FVG" if fvg_detected else "Discount/Premium Zone"
            heads_details.append(f"✅ POI Interaction: {poi_type}")
        else:
            heads_details.append(f"❌ POI Interaction: Not at POI")
        
        # HEAD 5: Entry Candle Confirmation
        candle_check = context.get('candle_check', {'confirmed': False})
        if isinstance(candle_check, dict) and candle_check.get('confirmed'):
            heads_aligned += 1
            heads_details.append(f"✅ Candle Confirmation: {candle_check.get('confirmation_type', 'confirmed')}")
        else:
            heads_details.append(f"❌ Candle Confirmation: Not confirmed")
        
        # Hydra requires 4+ heads (backtest optimized from 3+)
        applicable = heads_aligned >= 4
        confidence = heads_aligned / 5.0
        
        return {
            'applicable': applicable,
            'heads_aligned': heads_aligned,
            'heads_details': heads_details,
            'confidence': confidence,
            'reasoning': f"Hydra: {heads_aligned}/5 heads aligned (requires 4+)"
        }
    
    except Exception as e:
        return {
            'applicable': False,
            'heads_aligned': 0,
            'heads_details': [f"Error: {str(e)}"],
            'confidence': 0,
            'reasoning': f"Hydra evaluation error: {str(e)}"
        }


# ─────────────────────────────────────────────────────────────────────────────
# 🥈 MODEL #2: SMC CLASSIC (Sweep → BOS → Retrace)
# ─────────────────────────────────────────────────────────────────────────────
# Institutional bread-and-butter: Sweep → CHOCH/BOS → Pullback → Entry

def evaluate_smc_classic_model(context: dict) -> dict:
    """
    SMC Classic: CONFLUENCE-BASED (Not Sequential)
    
    RELAXED FILTERS (2+ conditions with at least one core SMC):
    1. Liquidity sweep detected (within lookback) - CORE
    2. BOS/CHOCH confirmed (within lookback) - CORE
    3. Price currently in retrace zone (FVG/discount/premium)
    4. Entry candle confirmation OR strong confluence
    
    REQUIRES: At least 2 conditions, with at least one being Sweep OR BOS
    
    Backtest Results: 219 trades | 50.7% WR | 1.87 RR | +7738 pips
    - ALL 4 conditions = 0 signals (too strict)
    - 2+ with core SMC = 219 signals (best performer)
    
    Returns: {
        'applicable': bool,
        'conditions_met': int,  # 0-4
        'confluence_list': list,
        'confidence': float,
        'reasoning': str
    }
    """
    try:
        conditions_met = 0
        confluence_list = []
        
        # Condition 1: Liquidity sweep (anywhere in recent history)
        has_sweep = context.get('liquidity_swept', False) or context.get('has_sweep', False)
        if has_sweep:
            conditions_met += 1
            confluence_list.append('✅ Liquidity sweep detected')
        else:
            confluence_list.append('❌ No liquidity sweep')
        
        # Condition 2: BOS/CHOCH (anywhere in recent history)
        bos_confirmed = context.get('bos_confirmed_m15', False) or context.get('choch_confirmed', False)
        if bos_confirmed:
            conditions_met += 1
            confluence_list.append('✅ BOS/CHOCH confirmed')
        else:
            confluence_list.append('❌ No BOS/CHOCH')
        
        # Condition 3: Price in retrace zone (CURRENT position)
        in_fvg = context.get('price_in_fvg', False) or context.get('fvg_detected', False)
        in_discount = context.get('price_in_discount', False)
        in_premium = context.get('price_in_premium', False)
        
        if in_fvg or in_discount or in_premium:
            conditions_met += 1
            zone_type = 'FVG' if in_fvg else ('Discount' if in_discount else 'Premium')
            confluence_list.append(f'✅ Price in {zone_type} zone')
        else:
            confluence_list.append('❌ Not in retrace zone')
        
        # Condition 4: Entry candle confirmation
        candle_check = context.get('candle_check', {'confirmed': False})
        candle_confirmed = isinstance(candle_check, dict) and candle_check.get('confirmed')
        
        if candle_confirmed:
            conditions_met += 1
            confluence_list.append('✅ Entry candle confirmed')
        else:
            confluence_list.append('❌ No candle confirmation')
        
        # RELAXED: Require at least 2 conditions, with at least one being Sweep or BOS
        # (Backtest showed ALL 4 was too strict - 0 signals. 2+ with core SMC = 219 trades, 7738 pips)
        has_core_smc = has_sweep or bos_confirmed
        
        if conditions_met >= 4:
            applicable = True
            confidence = 1.0
        elif conditions_met == 3 and has_core_smc:
            applicable = True
            confidence = 0.85
        elif conditions_met >= 2 and has_core_smc:
            applicable = True
            confidence = 0.70
        else:
            applicable = False
            confidence = conditions_met * 0.25
        
        return {
            'applicable': applicable,
            'conditions_met': conditions_met,
            'confluence_list': confluence_list,
            'confidence': confidence,
            'reasoning': f'SMC Classic: {conditions_met}/4 conditions met (confluence-based)'
        }
    
    except Exception as e:
        return {
            'applicable': False,
            'conditions_met': 0,
            'confluence_list': [f'Error: {str(e)}'],
            'confidence': 0,
            'reasoning': f'SMC Classic error: {str(e)}'
        }


# ─────────────────────────────────────────────────────────────────────────────
# 🥉 MODEL #3: HYDRA-LITE (Score-Based Confluence)
# ─────────────────────────────────────────────────────────────────────────────
# Automation-friendly version of Hydra (3+ of 6 conditions)

def evaluate_hydra_lite_model(context: dict) -> dict:
    """
    Hydra-Lite: REDESIGNED for quality over quantity
    
    OLD: 3 of 6 conditions → 136 trades, 38.2% WR, -789 pips (FAILED)
    NEW: 5 of 6 conditions (much stricter) → Higher quality setups
    
    CONDITIONS (need 5+ to enter):
    1. HTF bias aligned (MANDATORY)
    2. M15 BOS strength ≥ 70%
    3. Liquidity sweep detected
    4. Price in FVG or discount/premium zone
    5. ATR expansion (>1.5x, not 1.3x)
    6. Strong candle confirmation (body > 1.3x avg)
    
    Returns: {
        'applicable': bool,
        'score': int,
        'conditions_met': list,
        'confidence': float,
        'reasoning': str
    }
    """
    try:
        score = 0
        conditions_met = []
        signal = context.get('signal', 'unknown')
        
        # Condition 1: HTF bias aligned (NICE-TO-HAVE but not mandatory when unavailable)
        htf_bias = context.get('htf_bias', None)
        if htf_bias == 'bullish' and signal == 'buy':
            score += 1
            conditions_met.append("✅ HTF Bias: Bullish (BUY aligned)")
        elif htf_bias == 'bearish' and signal == 'sell':
            score += 1
            conditions_met.append("✅ HTF Bias: Bearish (SELL aligned)")
        elif htf_bias is None:
            # HTF unavailable in live trading - don't penalize
            score += 0.5  # Partial credit
            conditions_met.append(f"⚠️ HTF Bias: Unavailable (partial credit)")
        else:
            conditions_met.append(f"❌ HTF Bias: {htf_bias} not aligned")
        
        # Condition 2: M15 BOS strength
        bos_strength = context.get('bos_strength', 0)
        if bos_strength >= 70:  # 70% of move completed
            score += 1
            conditions_met.append(f"✅ BOS Strength: {bos_strength:.0f}% (≥70)")
        else:
            conditions_met.append(f"❌ BOS Strength: {bos_strength:.0f}% (<70)")
        
        # Condition 3: Liquidity sweep
        has_sweep = context.get('liquidity_swept', False)
        if has_sweep:
            score += 1
            conditions_met.append("✅ Liquidity Sweep: Detected")
        else:
            conditions_met.append("❌ Liquidity Sweep: Not detected")
        
        # Condition 4: Price in FVG or discount/premium zone
        in_fvg = context.get('fvg_detected', False)
        in_zone = context.get('price_in_discount', False) or context.get('price_in_premium', False)
        
        if in_fvg or in_zone:
            score += 1
            zone_type = "FVG" if in_fvg else "Discount/Premium Zone"
            conditions_met.append(f"✅ Price in POI: {zone_type}")
        else:
            conditions_met.append("❌ Not in FVG or zone")
        
        # Condition 5: ATR expansion (TIGHTER: 1.5x instead of 1.3x)
        df = context.get('df', None)
        if df is not None and len(df) >= 20:
            recent_ranges = (df['high'] - df['low']).iloc[-20:]
            current_atr = recent_ranges.iloc[-1]
            avg_atr = recent_ranges.iloc[:-1].mean()
            atr_ratio = current_atr / avg_atr if avg_atr > 0 else 1.0
            
            if atr_ratio > 1.5:  # STRICTER: 50%+ expansion
                score += 1
                conditions_met.append(f"✅ ATR Expansion: {atr_ratio:.2f}x (>1.5)")
            else:
                conditions_met.append(f"❌ ATR: {atr_ratio:.2f}x (<1.5)")
        else:
            conditions_met.append("❌ ATR: No data")
        
        # Condition 6: Strong candle confirmation (body > 1.3x avg)
        if df is not None and len(df) >= 5:
            recent_bodies = abs(df['close'] - df['open']).iloc[-10:]
            current_body = abs(df['close'].iloc[-1] - df['open'].iloc[-1])
            avg_body = recent_bodies.iloc[:-1].mean()
            body_ratio = current_body / avg_body if avg_body > 0 else 1.0
            
            if body_ratio > 1.3:  # Strong displacement candle
                score += 1
                conditions_met.append(f"✅ Strong Candle: {body_ratio:.2f}x avg body")
            else:
                conditions_met.append(f"❌ Weak Candle: {body_ratio:.2f}x (<1.3)")
        else:
            conditions_met.append("❌ Candle: No data")
        
        # BACKTEST OPTIMIZED: Require 5 of 6 conditions
        # Backtest: 39 trades | 46.1% WR | 2.24 RR | +1398 pips
        applicable = score >= 5
        confidence = score / 6.0
        
        return {
            'applicable': applicable,
            'score': score,
            'conditions_met': conditions_met,
            'confidence': confidence,
            'reasoning': f'Hydra-Lite: {score}/6 conditions (need 5+)'
        }
    
    except Exception as e:
        return {
            'applicable': False,
            'score': 0,
            'conditions_met': [f'Error: {str(e)}'],
            'confidence': 0,
            'reasoning': f'Hydra-Lite error: {str(e)}'
        }


# ─────────────────────────────────────────────────────────────────────────────
# 🔥 MODEL #4: DISPLACEMENT PULLBACK (Trend Continuation King)
# ─────────────────────────────────────────────────────────────────────────────
# Strong trend + Large impulse + Pullback = High-probability continuation
# BACKTEST RESULT: 60% WR, 3.46 RR, +2511 pips (BEST PERFORMER - DO NOT MODIFY)

def evaluate_displacement_pullback_model(context: dict) -> dict:
    """
    Displacement Model: Trend continuation with strong impulse
    
    SIMPLE LOGIC (Backtest optimized):
    1. HTF trend should align with signal (OPTIONAL - if unavailable, relax requirement)
    2. Large displacement candle (body > 1.5x average)
    3. Candle direction matches signal
    
    Backtest Results: 150 trades | 43.3% WR | 1.44 RR | +794 pips
    - Best on XAUUSD: 72.7% WR, 4.15 RR, +3181 pips
    
    Returns: {
        'applicable': bool,
        'stage': str,
        'confidence': float,
        'reasoning': str
    }
    """
    try:
        # SOFT: HTF trend should align (but if None, don't block - data may be unavailable)
        htf_bias = context.get('htf_bias', None)
        signal = context.get('signal', 'unknown')
        
        # If HTF data available, strongly prefer aligned
        if htf_bias is not None:
            if (signal == 'buy' and htf_bias != 'bullish') or (signal == 'sell' and htf_bias != 'bearish'):
                # Misaligned but don't completely block - check for strong displacement
                confidence_penalty = 0.3  # Reduce confidence by 30%
            else:
                confidence_penalty = 0.0  # Aligned = no penalty
        else:
            # HTF unavailable - no penalty, but lower base confidence
            confidence_penalty = 0.15  # Slightly reduce confidence if no HTF confirmation
        
        # Check for displacement candle (large body > 1.5x avg)
        df = context.get('df', None)
        if df is None or len(df) < 20:
            return {
                'applicable': False,
                'stage': 'no_data',
                'confidence': 0,
                'reasoning': 'Displacement: Insufficient data'
            }
        
        curr = df.iloc[-1]
        prev_avg_body = abs((df['close'] - df['open']).iloc[-20:-1]).mean()
        curr_body = abs(curr['close'] - curr['open'])
        
        # Displacement = body 1.5x larger + direction matches signal
        is_bullish_candle = curr['close'] > curr['open']
        is_bearish_candle = curr['close'] < curr['open']
        
        if curr_body > 1.5 * prev_avg_body:
            if (signal == 'buy' and is_bullish_candle) or (signal == 'sell' and is_bearish_candle):
                base_confidence = 0.9
                final_confidence = max(0.5, base_confidence - confidence_penalty)  # Never go below 0.5
                return {
                    'applicable': True,
                    'stage': 'displacement_confirmed',
                    'confidence': final_confidence,
                    'reasoning': f'Displacement: Strong candle {curr_body/prev_avg_body:.2f}x avg' + (f', trend aligned' if htf_bias is None or (signal == 'buy' and htf_bias == 'bullish') or (signal == 'sell' and htf_bias == 'bearish') else f', weak HTF alignment')
                }
        
        return {
            'applicable': False,
            'stage': 'no_displacement',
            'confidence': 0.2,
            'reasoning': f'Displacement: Candle not strong enough ({curr_body/prev_avg_body:.2f}x avg, need >1.5x)'
        }
    
    except Exception as e:
        return {
            'applicable': False,
            'stage': 'error',
            'confidence': 0,
            'reasoning': f'Displacement error: {str(e)}'
        }


# ─────────────────────────────────────────────────────────────────────────────
# 💎 MODEL #5: RANGE LIQUIDITY FADE (Reversal Specialist)
# ─────────────────────────────────────────────────────────────────────────────
# Range high/low sweep → Failed continuation → Reversal entry

def evaluate_range_liquidity_fade_model(context: dict) -> dict:
    """
    Range Liquidity Fade: REDESIGNED for better signal generation
    
    NEW APPROACH (Backtest showed only 10 signals with old method):
    1. Detect ranging via ATR compression (not equal highs/lows)
    2. Identify range bounds (last 20 candles high/low)
    3. Price at range extreme (top 20% or bottom 20%)
    4. Rejection candle present
    5. HTF neutral or weakly trending
    
    Returns: {
        'applicable': bool,
        'range_detected': bool,
        'at_extreme': bool,
        'rejection_candle': bool,
        'fade_direction': str,
        'confidence': float,
        'reasoning': str
    }
    """
    try:
        df = context.get('df', None)
        if df is None or len(df) < 30:
            return {
                'applicable': False,
                'range_detected': False,
                'at_extreme': False,
                'rejection_candle': False,
                'fade_direction': 'none',
                'confidence': 0,
                'reasoning': 'Range Fade: Insufficient data (need 30+ candles)'
            }
        
        recent = df.iloc[-30:].copy()
        
        # Step 1: Detect ranging via ATR compression
        recent_range = recent['high'] - recent['low']
        current_atr = recent_range.iloc[-10:].mean()
        baseline_atr = recent_range.iloc[-30:].mean()
        
        # Ranging = ATR compressed (current < 80% of baseline)
        is_ranging = current_atr < 0.8 * baseline_atr
        
        if not is_ranging:
            return {
                'applicable': False,
                'range_detected': False,
                'at_extreme': False,
                'rejection_candle': False,
                'fade_direction': 'none',
                'confidence': 0,
                'reasoning': f'Range Fade: Not ranging (ATR ratio: {current_atr/baseline_atr:.2f} > 0.8)'
            }
        
        # Step 2: Identify range bounds
        range_high = recent['high'].iloc[-20:].max()
        range_low = recent['low'].iloc[-20:].min()
        range_size = range_high - range_low
        
        if range_size == 0:
            return {
                'applicable': False,
                'range_detected': True,
                'at_extreme': False,
                'rejection_candle': False,
                'fade_direction': 'none',
                'confidence': 0,
                'reasoning': 'Range Fade: Range size is zero'
            }
        
        # Step 3: Check if price at extreme (top 20% or bottom 20%)
        current_price = context.get('price', 0)
        top_20_threshold = range_high - 0.2 * range_size
        bottom_20_threshold = range_low + 0.2 * range_size
        
        at_top_extreme = current_price >= top_20_threshold
        at_bottom_extreme = current_price <= bottom_20_threshold
        
        if not (at_top_extreme or at_bottom_extreme):
            return {
                'applicable': False,
                'range_detected': True,
                'at_extreme': False,
                'rejection_candle': False,
                'fade_direction': 'none',
                'confidence': 0,
                'reasoning': f'Range Fade: Price in middle of range (${current_price:.5f} not at extremes)'
            }
        
        # Step 4: Check for rejection candle
        last_candle = recent.iloc[-1]
        candle_body = abs(last_candle['close'] - last_candle['open'])
        candle_range = last_candle['high'] - last_candle['low']
        
        # Rejection = large wick (body < 40% of range)
        has_rejection = candle_range > 0 and (candle_body / candle_range) < 0.4
        
        # Determine fade direction
        fade_direction = 'none'
        confidence = 0
        signal = context.get('signal', 'unknown')
        
        if at_top_extreme:
            # At top of range → FADE DOWN (SELL)
            if signal == 'sell':
                fade_direction = 'sell'
                if has_rejection and last_candle['close'] < last_candle['open']:  # Bearish rejection
                    confidence = 0.85
                else:
                    confidence = 0.65
        
        elif at_bottom_extreme:
            # At bottom of range → FADE UP (BUY)
            if signal == 'buy':
                fade_direction = 'buy'
                if has_rejection and last_candle['close'] > last_candle['open']:  # Bullish rejection
                    confidence = 0.85
                else:
                    confidence = 0.65
        
        applicable = confidence > 0 and fade_direction != 'none'
        
        return {
            'applicable': applicable,
            'range_detected': True,
            'at_extreme': True,
            'rejection_candle': has_rejection,
            'fade_direction': fade_direction,
            'confidence': confidence,
            'reasoning': f'Range Fade: {fade_direction.upper()} from {"top" if at_top_extreme else "bottom"} (ATR compressed, rejection: {has_rejection})'
        }
    
    except Exception as e:
        return {
            'applicable': False,
            'range_detected': False,
            'at_extreme': False,
            'rejection_candle': False,
            'fade_direction': 'none',
            'confidence': 0,
            'reasoning': f'Range Fade error: {str(e)}'
        }


# ═══════════════════════════════════════════════════════════════════════════════
# 🎯 DYNAMIC MODEL SELECTOR
# ═══════════════════════════════════════════════════════════════════════════════
# Evaluates all 5 models and returns the best one

def select_best_entry_model(context: dict) -> dict:
    """
    Evaluate all 5 entry models and select the best one.
    
    Returns: {
        'best_model': str,  # 'hydra', 'smc_classic', 'hydra_lite', 'displacement', 'range_fade'
        'confidence': float,  # 0-1.0
        'all_models': dict,  # Results from all 5 models
        'recommendation': str,  # Why this model was selected
        'should_enter': bool  # Final entry decision
    }
    """
    try:
        # Evaluate all 5 models
        models = {}
        
        models['hydra'] = evaluate_hydra_model(context)
        models['smc_classic'] = evaluate_smc_classic_model(context)
        models['hydra_lite'] = evaluate_hydra_lite_model(context)
        models['displacement'] = evaluate_displacement_pullback_model(context)
        models['range_fade'] = evaluate_range_liquidity_fade_model(context)
        
        # Score each model
        model_scores = {}
        for model_name, result in models.items():
            if result.get('applicable'):
                # Scoring priority: applicable + confidence + recency
                model_scores[model_name] = result.get('confidence', 0)
            else:
                model_scores[model_name] = 0
        
        # Find best model
        best_model = max(model_scores, key=model_scores.get)
        best_confidence = model_scores[best_model]
        
        # Decide entry
        should_enter = best_confidence >= 0.7  # BACKTEST OPTIMIZED
        
        # Get model details for logging
        best_result = models[best_model]
        
        recommendation = ""
        if best_model == 'hydra':
            recommendation = f"HYDRA: {best_result.get('heads_aligned', 0)}/5 heads aligned - Multi-head confluence entry"
        elif best_model == 'smc_classic':
            recommendation = f"SMC_CLASSIC: {best_result.get('flow_stage', 'unknown')} - Institutional flow confirmed"
        elif best_model == 'hydra_lite':
            recommendation = f"HYDRA_LITE: {best_result.get('score', 0)}/6 conditions - Score-based confluence"
        elif best_model == 'displacement':
            recommendation = f"DISPLACEMENT: {best_result.get('stage', 'unknown')} - Trend continuation setup"
        elif best_model == 'range_fade':
            recommendation = f"RANGE_FADE: {best_result.get('setup_type', 'unknown')} - Reversal specialist"
        
        return {
            'best_model': best_model,
            'confidence': best_confidence,
            'all_models': models,
            'recommendation': recommendation,
            'should_enter': should_enter
        }
    
    except Exception as e:
        return {
            'best_model': 'error',
            'confidence': 0,
            'all_models': {},
            'recommendation': f'Model selector error: {str(e)}',
            'should_enter': False
        }


# ═══════════════════════════════════════════════════════════════════════════════
# 🔍 SIGNAL FRESHNESS CHECKER - PREVENTS STALE ENTRIES
# ═══════════════════════════════════════════════════════════════════════════════
def check_signal_freshness(symbol, direction, context=None, max_age_candles=3, bypass_fallback=False):
    """
    Checks if BOS, FVG, and other signals are FRESH before allowing entry.
    
    CRITICAL: Before opening a second/third trade in the same direction,
    verify that signals haven't gone stale.
    
    Args:
        symbol: Trading symbol
        direction: 'buy' or 'sell'
        context: Market context with features/df
        max_age_candles: Maximum age in candles for signals to be fresh (default 3)
        bypass_fallback: Skip check if True (for fallback entries with insufficient data)
    
    Returns:
        (is_fresh: bool, reason: str, details: dict)
    """
    try:
        if bypass_fallback:
            return (True, "Freshness check bypassed for fallback entry", {})
        
        if context is None or not isinstance(context, dict):
            return (False, "No context provided for freshness check", {})
        
        features = context.get('features', {})
        df = context.get('df')
        
        if df is None or len(df) < 5:
            return (False, "Insufficient price data for freshness check", {})
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # 1. Check BOS Freshness (must be within last 3 candles)
        # ═══════════════════════════════════════════════════════════════════════════════
        bos_age = features.get('bos_candles_ago', 999)
        bos_direction = features.get('bos_direction', 'none')
        
        if bos_age > max_age_candles:
            return (False, f"BOS signal too old: {bos_age} candles ago (max {max_age_candles})", {'bos_age': bos_age})
        
        if bos_direction == 'none':
            return (False, "No valid BOS detected", {'bos_direction': bos_direction})
        
        # Verify BOS direction matches trade direction
        if direction == 'buy' and bos_direction != 'bullish':
            return (False, f"BOS direction mismatch: want BUY but BOS is {bos_direction}", {'bos_direction': bos_direction})
        if direction == 'sell' and bos_direction != 'bearish':
            return (False, f"BOS direction mismatch: want SELL but BOS is {bos_direction}", {'bos_direction': bos_direction})
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # 2. Check FVG Freshness (must be recent and price should be IN the FVG)
        # ═══════════════════════════════════════════════════════════════════════════════
        fvg_age = features.get('fvg_candles_ago', 999)
        in_fvg_zone = features.get('in_fvg_zone', False)
        
        if fvg_age > max_age_candles:
            return (False, f"FVG signal too old: {fvg_age} candles ago (max {max_age_candles})", {'fvg_age': fvg_age})
        
        if not in_fvg_zone:
            return (False, "Price not in FVG zone - signal not actionable", {'in_fvg_zone': in_fvg_zone})
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # 3. Check Liquidity Sweep Freshness
        # ═══════════════════════════════════════════════════════════════════════════════
        liquidity_sweep = features.get('liquidity_sweep', False)
        sweep_age = features.get('sweep_candles_ago', 999)
        
        if liquidity_sweep and sweep_age > max_age_candles:
            return (False, f"Liquidity sweep too old: {sweep_age} candles ago", {'sweep_age': sweep_age})
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # 4. Check if there are existing trades in same direction (re-entry check)
        # ═══════════════════════════════════════════════════════════════════════════════
        try:
            open_trades = get_open_trades() if 'get_open_trades' in globals() else []
            same_direction_trades = [t for t in open_trades if t.get('symbol') == symbol and t.get('direction') == direction]
            
            if len(same_direction_trades) > 0:
                # This is a second/third trade - apply STRICTER freshness rules
                if bos_age > 2:  # Even stricter for re-entries
                    return (False, f"Re-entry rejected: BOS too old ({bos_age} candles) for second trade", {'bos_age': bos_age, 're_entry': True})
                
                if fvg_age > 2:
                    return (False, f"Re-entry rejected: FVG too old ({fvg_age} candles) for second trade", {'fvg_age': fvg_age, 're_entry': True})
        except Exception as e:
            pass  # If we can't check existing trades, proceed
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # 5. All freshness checks passed
        # ═══════════════════════════════════════════════════════════════════════════════
        return (True, "All signals FRESH", {
            'bos_age': bos_age,
            'bos_direction': bos_direction,
            'fvg_age': fvg_age,
            'in_fvg_zone': in_fvg_zone,
            'liquidity_sweep': liquidity_sweep
        })
    
    except Exception as e:
        return (False, f"Freshness check error: {str(e)}", {})


# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
# 🧠 HYBRID EXECUTION MODEL - LIMIT vs MARKET ORDER SELECTOR
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
def detect_retrace_expected(symbol, df, atr, last_direction):
    """
    Detect if a retrace is expected (use LIMIT order).
    
    Returns True if:
    - Price is inside POI (pullback happened)
    - Recent candles show consolidation
    - No strong directional impulse
    
    Returns False if:
    - Price at extreme
    - Strong displacement candle
    - Volume spike
    """
    try:
        if df is None or len(df) < 10:
            return True  # Default to limit if insufficient data
        
        closes = df['close'].values
        opens = df['open'].values
        highs = df['high'].values
        lows = df['low'].values
        volumes = df['tick_volume'].values if 'tick_volume' in df else df['volume'].values
        
        recent_close = closes[-1]
        recent_open = opens[-1]
        recent_high = highs[-1]
        recent_low = lows[-1]
        recent_vol = volumes[-1]
        avg_vol = np.mean(volumes[-20:]) if len(volumes) >= 20 else np.mean(volumes)
        
        # Check 1: Is there a strong displacement candle?
        candle_size = abs(recent_close - recent_open)
        candle_wicks = (recent_high - recent_low)
        body_ratio = candle_size / candle_wicks if candle_wicks > 0 else 0
        is_displacement = body_ratio > 0.75 and candle_size > atr * 0.5
        
        # Check 2: Is there a volume spike?
        volume_spike = recent_vol > avg_vol * 1.5
        
        # Check 3: Is price in consolidation?
        recent_range = max(highs[-5:]) - min(lows[-5:])
        is_consolidating = recent_range < atr * 0.8
        
        # Logic: If displacement + volume spike → momentum (use market)
        if is_displacement and volume_spike:
            return False  # Use MARKET order
        
        # Logic: If consolidating → retrace expected (use limit)
        if is_consolidating:
            return True  # Use LIMIT order
        
        # Default: favor LIMIT orders
        return True
        
    except Exception as e:
        print(f"[RETRACE CHECK ERROR] {symbol}: {e}")
        return True  # Default to limit


def detect_momentum_high(symbol, df, hydra_score=None):
    """
    Detect if momentum is very high (use MARKET order).
    
    Returns True if:
    - Hydra score ≥ 8/10
    - Multiple large directional candles
    - Strong volume confirmation
    """
    try:
        if df is None or len(df) < 5:
            return False
        
        # Check 1: Hydra score (if provided)
        if hydra_score is not None and hydra_score >= 8:
            return True
        
        # Check 2: Multiple large directional candles
        closes = df['close'].values
        opens = df['open'].values
        
        recent_bars = list(range(max(0, len(closes)-5), len(closes)))
        directional_candles = 0
        
        for i in recent_bars:
            candle_size = abs(closes[i] - opens[i])
            if candle_size > 0:  # Directional candle exists
                directional_candles += 1
        
        # If 4+ large directional candles → strong momentum
        if directional_candles >= 4:
            return True
        
        return False
        
    except Exception as e:
        print(f"[MOMENTUM CHECK ERROR] {symbol}: {e}")
        return False


def confirm_candle_action(symbol, df, direction, confirmation_type="strong"):
    """
    Wait for candle confirmation before executing.
    
    confirmation_type:
    - 'strong': Requires engulfing or strong close
    - 'soft': Just requires directional close
    - 'none': Skip candle check (immediate execution)
    
    Returns: (confirmed: bool, candle_info: str)
    """
    try:
        if df is None or len(df) < 2 or confirmation_type == 'none':
            return (True, "Candle check skipped")
        
        current_candle = df.iloc[-1]
        prev_candle = df.iloc[-2]
        
        close = current_candle['close']
        open_ = current_candle['open']
        high = current_candle['high']
        low = current_candle['low']
        
        prev_close = prev_candle['close']
        prev_open = prev_candle['open']
        prev_high = prev_candle['high']
        prev_low = prev_candle['low']
        
        if direction == "buy":
            if confirmation_type == "strong":
                # Strong buy: Close > Open (bullish) AND close > prev close
                is_bullish = close > open_
                is_higher = close > prev_close
                is_engulfing = open_ < prev_low and close > prev_high
                
                confirmed = is_bullish and is_higher
                candle_info = f"BUY candle: bullish={is_bullish}, higher={is_higher}, engulfing={is_engulfing}"
                return (confirmed, candle_info)
            else:  # soft
                # Soft buy: Just requires close > open
                confirmed = close > open_
                candle_info = f"BUY candle: close > open = {confirmed}"
                return (confirmed, candle_info)
        
        elif direction == "sell":
            if confirmation_type == "strong":
                # Strong sell: Close < Open (bearish) AND close < prev close
                is_bearish = close < open_
                is_lower = close < prev_close
                is_engulfing = open_ > prev_high and close < prev_low
                
                confirmed = is_bearish and is_lower
                candle_info = f"SELL candle: bearish={is_bearish}, lower={is_lower}, engulfing={is_engulfing}"
                return (confirmed, candle_info)
            else:  # soft
                # Soft sell: Just requires close < open
                confirmed = close < open_
                candle_info = f"SELL candle: close < open = {confirmed}"
                return (confirmed, candle_info)
        
        return (False, "Invalid direction")
        
    except Exception as e:
        return (True, f"Candle check error: {e}")


def select_execution_type(symbol, df, atr, direction, hydra_score=None):
    """
    Select between LIMIT and MARKET order based on market conditions.
    
    Returns: ('LIMIT', 'MARKET', or None)
    - LIMIT: Place pending order at entry price (70-80%)
    - MARKET: Place market order immediately (20-30%)
    - None: Skip trade
    """
    try:
        retrace_expected = detect_retrace_expected(symbol, df, atr, direction)
        momentum_high = detect_momentum_high(symbol, df, hydra_score)
        
        if retrace_expected and not momentum_high:
            return 'LIMIT'
        elif momentum_high and not retrace_expected:
            return 'MARKET'
        elif retrace_expected and momentum_high:
            # Both true: favor LIMIT (safer)
            return 'LIMIT'
        else:
            # Neither: skip trade
            return None
    
    except Exception as e:
        print(f"[EXECUTION TYPE ERROR] {symbol}: {e}")
        return 'LIMIT'  # Default to limit


# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
# 🔧 BROKER FILLING MODE DETECTION (Fixes "Unsupported filling mode" errors)
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
def get_broker_supported_filling_modes(symbol):
    """
    Get filling modes to try for this symbol in priority order.
    
    Since MT5's SymbolInfo.fill_mode attribute is not reliably accessible across all brokers,
    we return a sensible default priority list and let the order_send attempt handle failures.
    
    Returns: List of filling modes to try in order [RETURN, IOC, FOK]
    This order ensures maximum compatibility:
    - RETURN: Works with most brokers (partial fill allowed, returns unfilled)
    - IOC: Fill-or-Kill (stricter but common)
    - FOK: Fill-or-Kill-All (strictest, rarest)
    """
    try:
        sym_info = mt5.symbol_info(symbol)
        if not sym_info:
            return [mt5.ORDER_FILLING_RETURN]
        
        # Try to detect fill_mode if available (some brokers expose it)
        if hasattr(sym_info, 'filling_mode'):
            fill_mode = sym_info.filling_mode
            supported = []
            if fill_mode & 1:
                supported.append(mt5.ORDER_FILLING_FOK)
            if fill_mode & 2:
                supported.append(mt5.ORDER_FILLING_IOC)
            if fill_mode & 4:
                supported.append(mt5.ORDER_FILLING_RETURN)
            if supported:
                return supported
        
    except Exception:
        pass
    
    # Default: return most compatible order (RETURN first, then IOC, then FOK)
    return [mt5.ORDER_FILLING_RETURN, mt5.ORDER_FILLING_IOC, mt5.ORDER_FILLING_FOK]


# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
# 🏆 COMPETITIVE ENTRY SYSTEM - SMC vs 5 MODELS (BEST WINS)
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
def evaluate_competitive_entry(symbol, context):
    """
    Run SMC and all 5 models in parallel, return winner by highest confidence.
    
    Args:
        symbol: Trading symbol
        context: Market context dict with smc_trade, df, features, etc.
    
    Returns:
        {
            'winner': 'SMC' or model name,
            'confidence': float (0-1.0),
            'entry': float,
            'sl': float,
            'tp': float,
            'rr': float,
            'details': str,
            'all_entries': dict  # All competitors for logging
        }
    """
    try:
        competitors = {}
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        # COMPETITOR 1: CANONICAL SMC ENTRY
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        smc_trade = context.get('smc_trade')
        if smc_trade:
            smc_rr = smc_trade.get('rr', 0)
            # SMC confidence: base on RR quality and setup completeness
            # Perfect setup (RR 2.5+) = 0.95, Good (RR 2.0) = 0.80, OK (RR 1.6) = 0.65
            if smc_rr >= 2.5:
                smc_confidence = 0.95
            elif smc_rr >= 2.0:
                smc_confidence = 0.80
            elif smc_rr >= 1.6:
                smc_confidence = 0.65
            else:
                smc_confidence = 0.50
            
            competitors['SMC'] = {
                'confidence': smc_confidence,
                'entry': smc_trade['entry'],
                'sl': smc_trade['stop_loss'],
                'tp': smc_trade['take_profit'],
                'rr': smc_rr,
                'reasoning': f"Canonical SMC (RR={smc_rr:.2f})"
            }
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        # COMPETITORS 2-6: ALL 5 MODELS
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        models_to_eval = {
            'HYDRA': evaluate_hydra_model,
            'SMC_CLASSIC': evaluate_smc_classic_model,
            'HYDRA_LITE': evaluate_hydra_lite_model,
            'DISPLACEMENT': evaluate_displacement_pullback_model,
            'RANGE_FADE': evaluate_range_liquidity_fade_model
        }
        
        for model_name, eval_func in models_to_eval.items():
            try:
                result = eval_func(context)
                if result and result.get('applicable'):
                    competitors[model_name] = {
                        'confidence': result.get('confidence', 0),
                        'reasoning': result.get('reasoning', 'N/A'),
                        'applicable': True
                    }
                else:
                    competitors[model_name] = {
                        'confidence': result.get('confidence', 0) if isinstance(result, dict) else 0,
                        'reasoning': result.get('reasoning', 'Not applicable or insufficient context') if isinstance(result, dict) else 'Not applicable or insufficient context',
                        'applicable': False
                    }
            except Exception as e:
                competitors[model_name] = {
                    'confidence': 0,
                    'reasoning': f'Eval error: {e}',
                    'applicable': False
                }
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        # DETERMINE WINNER
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        if not competitors:
            return None
        
        # Find highest confidence competitor
        winner = max(competitors.items(), key=lambda x: x[1].get('confidence', 0))
        winner_name = winner[0]
        winner_data = winner[1]
        
        # BACKTEST OPTIMIZATION: Require minimum 0.7 confidence
        if winner_data.get('confidence', 0) < 0.7:
            return None  # No entry if best model < 70% confidence
        
        # If winner is SMC, return its full data
        if winner_name == 'SMC':
            return {
                'winner': 'SMC',
                'confidence': winner_data['confidence'],
                'entry': winner_data['entry'],
                'sl': winner_data['sl'],
                'tp': winner_data['tp'],
                'rr': winner_data['rr'],
                'details': winner_data['reasoning'],
                'all_entries': {k: {
                    'confidence': v.get('confidence'),
                    'reasoning': v.get('reasoning')
                } for k, v in competitors.items()},
                'model_counts': {
                    'total': len(competitors),
                    'applicable': sum(1 for v in competitors.values() if v.get('applicable', True))
                }
            }
        else:
            # If winner is a model (not SMC), use SMC data if available, else use None placeholders
            # Models don't provide entry/sl/tp, so we use SMC's data or signal fallback
            if smc_trade:
                # Use SMC's execution data even though model won (model just boosts confidence)
                return {
                    'winner': winner_name,
                    'confidence': winner_data['confidence'],
                    'entry': smc_trade['entry'],
                    'sl': smc_trade['stop_loss'],
                    'tp': smc_trade['take_profit'],
                    'rr': smc_trade.get('rr', 2.0),
                    'from_model': True,
                    'details': winner_data['reasoning'],
                    'all_entries': {k: {
                        'confidence': v.get('confidence'),
                        'reasoning': v.get('reasoning')
                    } for k, v in competitors.items()},
                    'model_counts': {
                        'total': len(competitors),
                        'applicable': sum(1 for v in competitors.values() if v.get('applicable', True))
                    }
                }
            else:
                # No SMC data available - return None to trigger fallback
                return None
    
    except Exception as e:
        print(f"[COMPETITIVE ERROR] {symbol}: {e}")
        return None


# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
# 🎯 UNIFIED ENTRY MODEL WRAPPER - AUTO-SELECTS & LOGS BEST MODEL
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
def place_trade_with_model_selection(symbol, direction, lot, sl, tp, 
                                     strategy_votes=None, num_trades=1, regime="trend",
                                     confidence=None, is_news_trade=False,
                                     skip_global_sweep_check=False, entry_type="NORMAL",
                                     context=None, is_fallback_entry=False):
    """
    Wrapper around place_trade() that AUTOMATICALLY selects the best entry model,
    VALIDATES against model confidence thresholds, and GATES entries.
    
    🔒 GATEKEEPING: Trades are REJECTED if model confidence is below threshold.
       This prevents low-confidence entries from being executed.
    
    This is the UNIFIED entry point - use this instead of place_trade() directly.
    
    Args:
        context: Optional dict with market context (symbol, direction, price, df, features)
                 If not provided, minimal context will be created
    
    Returns:
        Trade result if executed, or rejection dict if model confidence too low
    """
    # ✅ CAP INCOMING LOT AT SYMBOL_MAX_LOT (first safety check)
    lot = enforce_lot_cap(symbol, lot)
    
    # 🔥 CHECK IF SYMBOL IS DISABLED
    symbol_base = symbol.upper().split('.')[0]
    if symbol_base in DISABLED_SYMBOLS:
        print(f"❌ [TRADE REJECTED] {symbol} is in DISABLED_SYMBOLS - entry blocked")
        return {'rejected': True, 'reason': f'{symbol_base} is disabled'}
    
    entry_model = None
    entry_model_details = None
    model_confidence = 0.0
    
    try:
        # Build context for model selection if not provided
        if context is None:
            context = {
                'symbol': symbol,
                'signal': direction,
                'price': (sl + tp) / 2,  # Approximate midpoint
            }
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        # 🔍 STEP 1: CHECK SIGNAL FRESHNESS (PREVENTS STALE ENTRIES)
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        is_fresh, freshness_reason, freshness_details = check_signal_freshness(symbol, direction, context, max_age_candles=3, bypass_fallback=is_fallback_entry)
        
        if not is_fresh:
            # TRADE REJECTED - Signals are stale/old
            rejection_msg = f"[SIGNAL REJECTED] {symbol} {direction.upper()}: {freshness_reason}"
            print(rejection_msg)
            
            try:
                send_telegram(rejection_msg)
            except:
                pass
            
            return {
                'rejected': True,
                'reason': freshness_reason,
                'freshness_details': freshness_details,
                'type': 'stale_signal'
            }
        
        print(f"[SIGNAL FRESH] {symbol} {direction.upper()}: {freshness_reason} - BOS age={freshness_details.get('bos_age', '?')}, FVG age={freshness_details.get('fvg_age', '?')}")
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        # �️ HARDSTOP: REJECT TRADES IN EXTREME VOLATILITY (unless ELITE confluence)
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        try:
            df = context.get('df') if context else None
            if df is not None and len(df) >= 14:
                vol_regime = get_volatility_regime(df, symbol)
                if vol_regime.get('regime') == 'EXTREME':
                    # Get confluence score from context
                    confluence_score = context.get('weighted_confluence', context.get('confluence_score', 0))
                    
                    # Only allow EXTREME vol trades if confluence is ELITE (85+)
                    if confluence_score < 85:
                        rejection_msg = f"🌪️ [EXTREME VOL HARDSTOP] {symbol}: Volatility={vol_regime['regime']} | Confluence={confluence_score:.0f} → ENTRY BLOCKED (need 85+ for EXTREME)"
                        print(rejection_msg)
                        return {
                            'rejected': True,
                            'reason': f'EXTREME volatility + LOW confluence ({confluence_score:.0f})',
                            'type': 'extreme_vol_hardstop'
                        }
                    else:
                        print(f"✅ [EXTREME VOL APPROVED] {symbol}: Confluence={confluence_score:.0f}+ meets ELITE threshold - allowing trade")
        except Exception as e:
            print(f"[EXTREME VOL CHECK ERROR] {symbol}: {e} - proceeding with trade")
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        # �🎯 STEP 2: MODEL SELECTION
        # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
        # Call model selector
        
        # TREND CHASING PREVENTION: Don't enter late in mature trends
        try:
            df = context.get('df') if context else None
            if df is not None and len(df) >= 20:
                chase_check = detect_trend_chasing(df, direction)
                if chase_check.get('is_chasing', False):
                    rejection_msg = f"[TREND CHASING] {symbol} {direction.upper()}: {chase_check['reason']} - ENTRY BLOCKED"
                    print(rejection_msg)
                    return {
                        'rejected': True,
                        'reason': chase_check['reason'],
                        'type': 'trend_chasing',
                        'trend_age': chase_check.get('trend_age', 0)
                    }
                else:
                    print(f"[TREND FRESH] {symbol}: {chase_check['reason']}")
        except Exception as e:
            print(f"[TREND CHASING CHECK ERROR] {symbol}: {e} - proceeding with trade")

        # ═══════════════════════════════════════════════════════════════════════════════════════
        # ⭐ ADVANCED A+ ENTRY QUALITY FILTER
        # ═══════════════════════════════════════════════════════════════════════════════════════
        try:
            df = context.get('df') if context else None
            entry_price = (sl + tp) / 2 if sl and tp else 0
            
            if df is not None and len(df) >= 50 and entry_price:
                a_plus_result = detect_a_plus_entry_setup(df, direction, entry_price, context, symbol)
                
                print(f"[A+ ENTRY QUALITY] {symbol} {direction.upper()}: Tier={a_plus_result['tier']} ({a_plus_result['score']}/100) | {a_plus_result['reasoning']}")
                print(f"    Factors: OB={a_plus_result['factors'].get('order_block', 0):.0f} | Sweep={a_plus_result['factors'].get('sweep_quality', 0):.0f} | Structure={a_plus_result['factors'].get('structure_strength', 0):.0f} | Volume={a_plus_result['factors'].get('volume_expansion', 0):.0f}")
                
                # Identify which premium patterns match
                pattern_result = identify_premium_entry_patterns(df, direction, entry_price, context)
                if pattern_result['patterns']:
                    print(f"    🎯 Premium Patterns Found ({pattern_result['total_patterns_found']}):")
                    for pattern in pattern_result['patterns']:
                        print(f"       • {pattern['name']}: {pattern['description']} (Confidence: {pattern['confidence']}%)")
                
                # Store in context for later use (position sizing, SL/TP adjustment)
                context['entry_tier'] = a_plus_result['tier']
                context['entry_quality_score'] = a_plus_result['score']
                context['is_premium_entry'] = a_plus_result['is_premium']
                context['premium_patterns'] = pattern_result['patterns']
                context['primary_pattern'] = pattern_result['primary_pattern']
                
                # Soft gate: warn on poor entries but still allow if model approves
                if a_plus_result['score'] < 50:
                    print(f"    ⚠️ WARNING: Entry quality very low - risky setup")
                elif a_plus_result['score'] < 65:
                    print(f"    ⚠️ Weak entry - proceed with caution")
        
        except Exception as e:
            print(f"[A+ SETUP ERROR] {symbol}: {e} - proceeding with trade")

        model_result = select_best_entry_model(context)
        if model_result and model_result.get('should_enter'):
            entry_model = model_result['best_model']
            model_confidence = model_result.get('confidence', 0.0)
            model_details = model_result.get('all_models', {})
            
            # Extract model-specific details
            if entry_model in model_details:
                entry_model_details = model_details.get(entry_model, {})
            
            # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
            # 🔒 GATEKEEPING LOGIC - BYPASS FOR FASTER EXECUTION
            # ═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
            threshold = MODEL_CONFIDENCE_THRESHOLDS.get(entry_model, MODEL_CONFIDENCE_THRESHOLDS['default'])

            # ✅ TRADE APPROVED - GATEKEEPING DISABLED FOR SPEED
            print(f"[MODEL APPROVED] {symbol} {direction.upper()}: {entry_model.upper()} selected (confidence: {model_confidence:.2f}, threshold would be: {threshold:.2f}) - GATEKEEPING DISABLED")
    except Exception as e:
        print(f"[MODEL SELECT ERROR] {symbol}: {e}")
        entry_model = None
        entry_model_details = None
    
    # ═══════════════════════════════════════════════════════════════════════════════
    # 💰 ENHANCEMENT B: CALCULATE DYNAMIC LOT SIZE BASED ON CONFLUENCE
    # ═══════════════════════════════════════════════════════════════════════════════
    final_lot = lot  # Default to original lot
    
    try:
        # Extract confluence score from context or features
        if context and isinstance(context, dict):
            confluence_score = context.get('weighted_confluence', context.get('confluence_score', 75))
        else:
            confluence_score = confidence * 100 if confidence else 75  # Convert 0-1 confidence to 0-100
        
        # Calculate RR ratio
        entry_price = (sl + tp) / 2 if sl != 0 and tp != 0 else 0
        if entry_price and sl != 0:
            rr_ratio = abs(tp - entry_price) / abs(entry_price - sl) if abs(entry_price - sl) > 0 else 1.5
        else:
            rr_ratio = 1.5
        
        # Call dynamic lot sizing
        lot_result = calculate_dynamic_lot_size(
            base_lot=lot,
            confluence_score=confluence_score,
            rr_ratio=rr_ratio,
            account_balance=5000
        )
        
        if lot_result and isinstance(lot_result, dict):
            final_lot = lot_result.get('lot_size', lot)
            grade = lot_result.get('quality_grade', 'UNKNOWN')
            # ✅ ENFORCE CAP BEFORE PASSING TO place_trade
            final_lot = enforce_lot_cap(symbol, final_lot)
            print(f"💰 [DYNAMIC LOT SIZING] {symbol} {direction.upper()}: Confluence={confluence_score:.0f} | RR={rr_ratio:.2f}:1 | Grade={grade} | Lot: {lot:.4f} → {final_lot:.4f}")
            print(f"    ⚠️ DEBUG: Entry={entry_price:.5f} | SL={sl:.5f} | TP={tp:.5f}")
    except Exception as e:
        print(f"[LOT SIZING ERROR] {symbol}: {e} - Using original lot {lot:.4f}")
        final_lot = lot
        print(f"    ⚠️ DEBUG: Using original lot due to error")
    
    # Call place_trade with ADJUSTED lot size
    return place_trade(
        symbol=symbol,
        direction=direction,
        lot=final_lot,
        sl=sl,
        tp=tp,
        strategy_votes=strategy_votes,
        num_trades=num_trades,
        regime=regime,
        confidence=confidence,
        is_news_trade=is_news_trade,
        skip_global_sweep_check=skip_global_sweep_check,
        entry_type=entry_type,
        entry_model=entry_model,
        entry_model_details=entry_model_details
    )


def compute_unified_decision(context):
    """
    Synthesize all analyses into a single trade/no-trade decision.

    Key rule: A trade only happens if:
    1. SIGNAL VALIDATION PASSES (BOS, CHOCH, Liquidity Sweep, FVG properly aligned)
    2. NO BLOCKING filters are active (except for momentum override)
    3. ML confidence >= 0.80 (adjusted)
    4. At least 2 supporting filters confirm
    5. FVG + HTF alignment is strong
    6. BOS confirmation is present (MANDATORY)
    7. MOMENTUM OVERRIDE: If strong impulse candle, volume spike, and BOS on execution, allow entry even if HTF is against

    AGGRESSIVE FVG USAGE:
    - FVG confirmed (in zone + price action): +25% boost
    - FVG in zone: +15% boost
    - FVG out of zone: -25% penalty
    """

    # ═══════════════════════════════════════════════════════════════════════════════
    # 🔒 MASTER TREND & MOMENTUM FILTER (GLOBAL GATE - APPLIES TO ALL ENTRIES)
    # ═══════════════════════════════════════════════════════════════════════════════
    # This is the PRIMARY filter that determines if ANY entry is allowed at all.
    # It checks H4 trend state and momentum shifts before anything else.
    try:
        signal = context.signal
        price = context.price
        
        # Get dataframes for trend/momentum analysis
        df_m15 = context.df  # Use current (M15) data
        df_m30 = context.features.get('df_m30') if isinstance(context.features, dict) else None
        df_h1 = context.features.get('df_h1') if isinstance(context.features, dict) else None
        df_h4 = context.features.get('df_h4') if isinstance(context.features, dict) else None
        
        # Apply the master filter
        master_filter_result = apply_master_trend_momentum_filter(
            df_m15=df_m15, df_m30=df_m30, df_h1=df_h1, df_h4=df_h4,
            price=price,
            intended_direction=signal,
            allow_smc_in_range=True  # Allow SMC entries in ranging markets
        )
        
        # Log the master filter result
        context.master_trend_filter = master_filter_result
        
        # Check if the intended direction is allowed
        if not master_filter_result['filter_pass']:
            context.should_trade = False
            context.trade_quality_score = 0.0
            context.reason = f"BLOCKED: MASTER_TREND_FILTER - {master_filter_result['reason']}"
            context.blocking_filters.append(f"MASTER_TREND_FILTER: {master_filter_result['reason']}")
            return
        
        # If filter passes, add supporting info
        context.supporting_filters.append(f"MASTER_TREND_FILTER_PASS: H4_{master_filter_result['trend_state']}")
        
    except Exception as e:
        # On any exception in master filter, be conservative and block
        print(f"[ERROR] Master trend filter exception: {e}")
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = f"BLOCKED: MASTER_TREND_FILTER_ERROR - {str(e)}"
        context.blocking_filters.append(f"MASTER_TREND_FILTER_ERROR: {str(e)}")
        return

    # 🚨 === HARD FILTER: H1 STRUCTURE + M15 BOS (APPLIES TO ALL BUYs) ===
    try:
        h1_hard_filter_pass, h1_hard_filter_reason = check_h1_structure_hard_filter(context)
        
        if not h1_hard_filter_pass:
            context.should_trade = False
            context.trade_quality_score = 0.0
            context.reason = f"BLOCKED: {h1_hard_filter_reason}"
            context.blocking_filters.append(h1_hard_filter_reason)
            return
        else:
            # Add to supporting filters if it passed
            context.supporting_filters.append(h1_hard_filter_reason)
    
    except Exception as e:
        print(f"[ERROR] H1 hard filter exception: {e}")
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = f"BLOCKED: H1_HARD_FILTER_ERROR - {str(e)}"
        context.blocking_filters.append(f"H1_HARD_FILTER_ERROR: {str(e)}")
        return

    # ═══════════════════════════════════════════════════════════════════════════════
    # 🔥 NEW SMC FILTERS: DISCOUNT/PREMIUM + NO-CHASE + LIQUIDITY SWEEP
    # ═══════════════════════════════════════════════════════════════════════════════
    
    # 🔥 FILTER 1: DISCOUNT/PREMIUM FILTER (FIX 2: SOFT BLOCK - PENALTY INSTEAD OF BINARY GATE)
    try:
        discount_pass, discount_reason, retracement_pct = check_discount_premium_filter(context)
        
        if not discount_pass:
            # ✅ FIX 2: Apply SOFT PENALTY instead of hard block
            # Entry in premium/discount zone = -15% confidence penalty
            # Let the ML score and confidence decide, not binary gate
            penalty_amount = 0.15
            context.ml_confidence = max(0.0, context.ml_confidence - penalty_amount)
            context.supporting_filters.append(f"DISCOUNT_SOFT_PENALTY: {discount_reason} (-15% penalty applied, score will decide)")
            print(f"[⚠️ DISCOUNT SOFT BLOCK] {context.symbol} {context.signal}: {discount_reason}")
            print(f"   → Applied -15% penalty. ML confidence: {context.ml_confidence:.2f} (will proceed if score >= 6.0)")
            # DO NOT BLOCK - let next filter and final score decision take over
        else:
            # Passed - add to supporting filters
            context.supporting_filters.append(discount_reason)
            print(f"[✅ DISCOUNT FILTER] {context.symbol} {context.signal}: {discount_reason}")
            # Boost confidence for good discount entries
            if retracement_pct >= 50:
                context.ml_confidence = min(1.0, context.ml_confidence + 0.10)
    
    except Exception as e:
        # FIX 2: On error, apply penalty instead of blocking
        print(f"[WARNING] Discount filter exception: {e}")
        context.ml_confidence = max(0.0, context.ml_confidence - 0.10)
        context.supporting_filters.append(f"DISCOUNT_ERROR_PENALTY: {str(e)[:40]}")
    
    # 🔥 FILTER 2: NO-ENTRY-AFTER-EXPANSION RULE (CRITICAL - HARD BLOCK)
    try:
        expansion_pass, expansion_reason, corrective_count = check_no_entry_after_expansion(context)
        
        if not expansion_pass:
            context.should_trade = False
            context.trade_quality_score = 0.0
            context.reason = f"BLOCKED: {expansion_reason}"
            context.blocking_filters.append(expansion_reason)
            print(f"[🚫 EXPANSION FILTER] {context.symbol} {context.signal}: {expansion_reason}")
            return
        else:
            # Passed - add to supporting filters
            context.supporting_filters.append(expansion_reason)
            print(f"[✅ EXPANSION FILTER] {context.symbol} {context.signal}: {expansion_reason}")
            # Boost confidence for patient entries after pullback
            if corrective_count >= 4:
                context.ml_confidence = min(1.0, context.ml_confidence + 0.08)
    
    except Exception as e:
        print(f"[ERROR] Expansion filter exception: {e}")
        # Allow trade on error (this is a safety measure)
        context.supporting_filters.append(f"EXPANSION_FILTER_ERROR: {str(e)}")
    
    # 🔥 FILTER 3: LIQUIDITY SWEEP CONDITION (OPTIONAL - QUALITY BOOST)
    try:
        has_sweep, has_confirmation, sweep_reason = check_liquidity_sweep_condition(context)
        
        # This filter is OPTIONAL - it enhances quality but doesn't block
        if has_sweep and has_confirmation:
            # BEST case: sweep + confirmation
            context.supporting_filters.append(sweep_reason)
            context.ml_confidence = min(1.0, context.ml_confidence + 0.15)  # Big boost!
            print(f"[🎯 LIQUIDITY SWEEP] {context.symbol} {context.signal}: {sweep_reason}")
        elif has_sweep and not has_confirmation:
            # WARNING case: sweep without confirmation - reduce confidence
            context.blocking_filters.append(sweep_reason)
            context.ml_confidence = max(0.0, context.ml_confidence - 0.10)  # Penalty
            print(f"[⚠️ LIQUIDITY SWEEP] {context.symbol} {context.signal}: {sweep_reason}")
        else:
            # No sweep - just informational (doesn't affect decision)
            print(f"[ⓘ LIQUIDITY SWEEP] {context.symbol} {context.signal}: {sweep_reason}")
    
    except Exception as e:
        print(f"[ERROR] Liquidity sweep filter exception: {e}")
        # Continue without blocking

    # === PRE-FLIGHT CHECK: SIGNAL ALIGNMENT VALIDATION ===
    # This ensures BOS, CHOCH, Liquidity Sweep, and FVG are not conflicting
    signal_validation = context.features.get('signal_validation', {})
    if not signal_validation.get('is_valid', False):
        # ✅ FIX 2: Apply soft penalty instead of hard block
        blocking_reasons = signal_validation.get('blocking_reasons', ['Unknown validation failure'])
        penalty_amount = 0.12
        context.ml_confidence = max(0.0, context.ml_confidence - penalty_amount)
        context.supporting_filters.append(f"SIGNAL_VALIDATION_SOFT_PENALTY: {blocking_reasons[0][:40]} (-12%)")
        print(f"[⚠️ SIGNAL VALIDATION] {context.symbol}: {'; '.join(blocking_reasons[:2])} → Applied -12% penalty")
        # DO NOT BLOCK - continue to final decision

    # Get the validation confidence boost/penalty
    validation_confidence = signal_validation.get('confidence', 0.5)
    
    # === SESSION-AWARE AGGRESSION SCALING ===
    # London open → breakout bias, NY open → continuation bias, Late NY → mean reversion bias
    # Reversal trades get lower confidence during opens, continuation gets priority
    session = context.features.get("session", "unknown")
    hour = context.features.get("hour", None)
    ml_base = context.ml_confidence

    # Apply validation confidence as multiplier to ML confidence
    ml_base = ml_base * (0.7 + 0.3 * validation_confidence)  # Min 70% of original, max = original

    # Determine session bias
    # Assume hour is in 24h format, UTC or broker time as per your data
    # London open: 7-10, NY open: 13-16, Late NY: 18-22 (adjust as needed)
    session_bias = None
    if hour is not None:
        if 7 <= hour <= 10:
            session_bias = "london_open"
        elif 13 <= hour <= 16:
            session_bias = "ny_open"
        elif 18 <= hour <= 22:
            session_bias = "late_ny"
        else:
            session_bias = "other"
    else:
        session_bias = "unknown"

    # Determine if trade is reversal or continuation
    # If HTF trend aligns with signal, it's continuation; else, reversal
    htf_aligned = context.htf_analysis.get("aligned")
    is_reversal = htf_aligned is False
    is_continuation = htf_aligned is True

    # --- ENTRY TF MUST CLOSE FOR REVERSALS ---
    def entry_tf_closed(context):
        # Use the timestamps in the df to infer bar duration and whether last bar is closed
        try:
            if len(context.df) < 1:
                return True
            last_ts = float(context.df.iloc[-1]['time'])
            if len(context.df) >= 2:
                prev_ts = float(context.df.iloc[-2]['time'])
                bar_seconds = max(1.0, last_ts - prev_ts)
            else:
                bar_seconds = float(context.features.get('expected_bar_seconds', 60))
            import datetime
            now = datetime.datetime.utcnow().timestamp()
            # If the last bar timestamp is very recent (within the bar duration), consider it still forming
            return (now - last_ts) >= (0.9 * bar_seconds)
        except Exception:
            return True

    if is_reversal and not entry_tf_closed(context):
        # ✅ FIX 2: Apply SOFT PENALTY instead of hard block
        # Entry TF not closed = -12% confidence penalty for reversals
        penalty_amount = 0.12
        context.ml_confidence = max(0.0, context.ml_confidence - penalty_amount)
        context.supporting_filters.append(f"ENTRY_TF_OPEN_SOFT_PENALTY: Reversal on forming candle (-12%)")
        print(f"[⚠️ ENTRY TF OPEN] {context.symbol}: Reversal on open candle → -12% penalty, conf={context.ml_confidence:.2f}")
        # DO NOT BLOCK - continue to final decision

    # --- MOMENTUM-BREAK OVERRIDE: If an impulse candle breaks the last high/low
    # with a strong body (>70% of range), disable mean-reversion and force continuation.
    def is_momentum_break_override(context):
        if len(context.df) < 2:
            return False
        last = context.df.iloc[-1]
        prev = context.df.iloc[-2]
        body = abs(last['close'] - last['open'])
        range_ = last['high'] - last['low']
        if range_ == 0:
            return False
        body_ratio = body / range_
        # Breaks last high/low
        recent_high = context.df['high'][-3:-1].max() if len(context.df) >= 3 else prev['high']
        recent_low = context.df['low'][-3:-1].min() if len(context.df) >= 3 else prev['low']
        breaks_high = last['high'] > recent_high
        breaks_low = last['low'] < recent_low
        strong_body = body_ratio > 0.7
        if strong_body and (breaks_high or breaks_low):
            return True
        return False

    momentum_break_override = is_momentum_break_override(context)
    if momentum_break_override:
        # Disable mean-reversion boosts and prefer continuation
        context.features['mean_reversion_disabled'] = True
        is_reversal = False
        is_continuation = True
        context.supporting_filters.append('MOMENTUM_BREAK_OVERRIDE')

    # Apply session-aware scaling to ML confidence
    session_conf_mod = 0.0
    if session_bias == "london_open":
        if is_reversal:
            session_conf_mod = -0.15  # Lower confidence for reversals
        elif is_continuation:
            session_conf_mod = +0.10  # Slight boost for continuation
    elif session_bias == "ny_open":
        if is_reversal:
            session_conf_mod = -0.10
        elif is_continuation:
            session_conf_mod = +0.08
    elif session_bias == "late_ny":
        if is_reversal:
            session_conf_mod = +0.10  # Mean reversion bias: boost reversals
        elif is_continuation:
            session_conf_mod = -0.10  # Slightly penalize continuation
    # else: no change

    ml_base = max(0.0, min(1.0, ml_base + session_conf_mod))
    context.features["session_bias"] = session_bias
    context.features["session_conf_mod"] = session_conf_mod

    # 🛑 RANGE FILTER - HARD BLOCKER (CHECK FIRST!)
    # Block ALL trades if market is consolidating/in range
    range_check = detect_range_market(context.df, lookback=50)
    
    if range_check.get('is_range'):
        # ❌ HARD BLOCK: Do not trade in ranges - whipsaws guaranteed
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = f"🛑 RANGE BLOCKER: {range_check.get('reason')} - NO TRADES ALLOWED"
        context.blocking_filters.append(f"RANGE_MARKET: {range_check.get('reason')}")
        print(f"\n❌ [RANGE BLOCKER] {context.symbol} {context.signal.upper()}: Market in consolidation/range")
        print(f"   → NO TRADES ALLOWED (structure: {range_check.get('structure_score'):.0f}/100, chop: {range_check.get('chop_index'):.0f})")
        return
    
    context.supporting_filters.append(f"RANGE_FILTER_OK: Market not in range (structure: {range_check.get('structure_score'):.0f})")

    # ⭐ NEW SWEEP + RETEST CHECK (CHANGES EVERYTHING - ENTERS EARLIER!)
    # This OVERRIDES the old "wait for BOS confirmation" approach
    # Now we enter on the retest/pullback AFTER sweep, not on the breakout candle
    sweep_retest_result = should_enter_on_sweep_retest(
        symbol=context.symbol,
        direction=context.signal,
        df=context.df,
        lookback=20
    )
    
    if sweep_retest_result.get('should_enter'):
        # ✅ Sweep + Retest detected - ENTER NOW!
        print(f"\n🎯 [SWEEP+RETEST ENTRY PRIORITY] {context.symbol} {context.signal.upper()}: {sweep_retest_result['reason']}")
        
        # Store sweep info for SL/TP calculations
        context.sweep_info = sweep_retest_result['sweep_info']
        context.sweep_sl = sweep_retest_result['sl_price']  # Use sweep-based SL
        context.features['sweep_detected'] = True
        context.features['sweep_sl_override'] = sweep_retest_result['sl_price']
        
        # Boost confidence for valid sweep+retest
        ml_base = min(1.0, ml_base + 0.25)
        context.supporting_filters.append(f"SWEEP_RETEST_ENTRY: {sweep_retest_result['reason']}")
        
        # Force entry - bypass BOS confirmation requirement
        bos_confirmed = True

    # --- BOS CONFIRMATION (fallback if no sweep+retest) ---
    bos = context.fvg_analysis.get("bos", None)
    if not sweep_retest_result.get('should_enter'):  # Only if sweep+retest didn't work
        bos_confirmed = bos is not None and bos == context.signal
    # else: bos_confirmed already set to True from sweep+retest

    # ========== NEW ENHANCED ENTRY FILTERS ==========
    # 1. PULLBACK RULE: After BOS, require 50-70% retracement OR FVG tap
    pullback_valid, retrace_pct, pullback_reason = check_pullback_rule(context)
    if bos_confirmed and not pullback_valid and not sweep_retest_result.get('should_enter'):
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = f"BLOCKED: {pullback_reason} (no valid 50-70% pullback after BOS)"
        context.blocking_filters.append(f"NO_PULLBACK_RULE: {pullback_reason}")
        return
    elif pullback_valid or sweep_retest_result.get('should_enter'):
        if pullback_valid:
            context.supporting_filters.append(f"PULLBACK_RULE_OK: {pullback_reason}")
        ml_base = min(1.0, ml_base + 0.12)  # Boost confidence for valid pullback

    # 2. HTF DEMAND/SUPPLY REACTION: H4 filter or reaction from demand/supply
    htf_ok, htf_reason = check_htf_demand_reaction(context)
    if not htf_ok:
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = f"BLOCKED: {htf_reason}"
        context.blocking_filters.append(f"HTF_FILTER: {htf_reason}")
        return
    else:
        context.supporting_filters.append(f"HTF_FILTER_OK: {htf_reason}")
        ml_base = min(1.0, ml_base + 0.10)  # Boost for HTF alignment

    # 3. ENTRY TF CONFIRMATION: M5/M15 BOS + rejection candle
    entry_tf_valid, entry_tf_type, entry_tf_boost = check_entry_tf_confirmation(context)
    if not entry_tf_valid:
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = f"BLOCKED: {entry_tf_type} (no M5/M15 confirmation)"
        context.blocking_filters.append(f"ENTRY_TF: {entry_tf_type}")
        return
    else:
        context.supporting_filters.append(f"ENTRY_TF_OK: {entry_tf_type}")
        ml_base = min(1.0, ml_base + entry_tf_boost)  # Apply confidence boost from entry TF pattern

    # ========== END NEW ENHANCED FILTERS ==========

    # --- MOMENTUM OVERRIDE LOGIC ---
    # Define what constitutes a "strong impulse candle"
    def is_strong_impulse_candle(df, signal):
        if len(df) < 2:
            return False
        last = df.iloc[-1]
        prev = df.iloc[-2]
        body = abs(last['close'] - last['open'])
        range_ = last['high'] - last['low']
        # Impulse: large body, small wicks, body > 70% of range, and body > 1.5x previous bar
        if range_ == 0:
            return False
        body_ratio = body / range_
        prev_body = abs(prev['close'] - prev['open'])
        if signal == "buy":
            return (last['close'] > last['open'] and body_ratio > 0.7 and body > 1.5 * prev_body)
        elif signal == "sell":
            return (last['close'] < last['open'] and body_ratio > 0.7 and body > 1.5 * prev_body)
        return False

    # --- BOS LOCKOUT RULE: Prevent entries (SELL or BUY) when price is near structure,
    # momentum impulse is against the entry, and volume is rising. Also block on displacement.
    def is_bos_lockout(context):
        sig = context.signal
        if sig not in ("sell", "buy"):
            return False

        # Recent extremes
        recent_high = context.df['high'][-20:].max() if len(context.df) >= 20 else context.df['high'].max()
        recent_low = context.df['low'][-20:].min() if len(context.df) >= 20 else context.df['low'].min()
        price_near_high = (recent_high - context.price) / (recent_high if recent_high != 0 else 1) < 0.003  # within 0.3%
        price_near_low = (context.price - recent_low) / (recent_low if recent_low != 0 else 1) < 0.003  # within 0.3%

        # Momentum candle size
        last = context.df.iloc[-1]
        prev = context.df.iloc[-2] if len(context.df) >= 2 else last
        body = abs(last['close'] - last['open'])
        range_ = last['high'] - last['low']
        prev_body = abs(prev['close'] - prev['open'])
        size_candle = (range_ > 0 and body / range_ > 0.7 and body > 1.5 * prev_body)

        # Ensure the impulse is against the intended entry (e.g., bullish impulse when considering SELL)
        last_bullish = last['close'] > last['open']
        last_bearish = last['close'] < last['open']
        momentum_against = False
        if sig == "sell":
            momentum_against = size_candle and last_bullish
        elif sig == "buy":
            momentum_against = size_candle and last_bearish

        # Volume rising
        recent_vol = context.features.get("volume", 0)
        avg_vol = context.features.get("volume_avg_20", 0)
        volume_rising = recent_vol > 1.1 * avg_vol if avg_vol > 0 else False

        # Displacement detection (directional)
        bullish_displacement = context.features.get("bullish_displacement_detected", False)
        bearish_displacement = context.features.get("bearish_displacement_detected", False)

        if sig == "sell":
            return (price_near_high and momentum_against and volume_rising) or bullish_displacement
        else:  # buy
            return (price_near_low and momentum_against and volume_rising) or bearish_displacement

    # Check for momentum override conditions
    momentum_override = (
        is_strong_impulse_candle(context.df, context.signal)
        and context.volume_analysis.get("strong", False)
        and bos_confirmed
    )

    # --- PULLBACK INTO IMPULSE ZONE & CANDLE CONFIRMATION (Strict rule) ---
    def check_pullback_into_impulse_zone(ctx):
        f = ctx.features
        imp = f.get('last_impulse', {})
        if not imp or 'direction' not in imp:
            return False
        # Impulse direction must match intended trade
        if imp.get('direction') != ctx.signal:
            return False

        # Compute 50-60% retracement zone of impulse body
        imp_close = float(imp.get('close', 0))
        imp_open = float(imp.get('open', 0))
        body = float(imp.get('body', 0))
        if body <= 0:
            return False
        if ctx.signal == 'buy':
            zone_high = imp_close - 0.5 * body
            zone_low = imp_close - 0.6 * body
        else:  # sell
            zone_high = imp_close + 0.6 * body
            zone_low = imp_close + 0.5 * body

        # Use the last closed candle (assume -2 index) as confirmation candle
        try:
            last_closed = ctx.df.iloc[-2]
        except Exception:
            return False
        lc = float(last_closed['close'])
        lo = float(last_closed['open'])

        # For buy: require last closed candle to be bullish and close inside zone
        if ctx.signal == 'buy':
            return (zone_low <= lc <= zone_high) and (lc > lo)
        else:
            # For sell: require last closed candle to be bearish and close inside zone
            return (zone_high >= lc >= zone_low) and (lc < lo)

    # --- TP MUST TARGET LIQUIDITY/IMBALANCE, NOT FIRST RESISTANCE ---
    def check_tp_targets_liquidity(ctx):
        tp = getattr(ctx, 'tp', None)
        if tp is None:
            return False
        pip = get_pip_value(ctx.symbol) if 'get_pip_value' in globals() else (0.0001 if 'JPY' not in ctx.symbol else 0.01)

        # Determine first nearby structure (first resistance/support)
        try:
            highs = list(ctx.df['high'].iloc[-60:-1])
            lows = list(ctx.df['low'].iloc[-60:-1])
            first_res = None
            first_sup = None
            # for buy, first_res = smallest high > price
            above = [h for h in highs if h > ctx.price]
            below = [l for l in lows if l < ctx.price]
            first_res = min(above) if above else None
            first_sup = max(below) if below else None
        except Exception:
            first_res = None
            first_sup = None

        # Build candidate liquidity/imbalance targets from FVG/POI/OB/LQ
        candidates = []
        fvg_zone = ctx.fvg_analysis.get('entry_zone') if isinstance(ctx.fvg_analysis, dict) else None
        if fvg_zone and isinstance(fvg_zone, dict):
            # For buy, target the high of FVG; for sell, target the low
            if ctx.signal == 'buy' and fvg_zone.get('high'):
                candidates.append(float(fvg_zone.get('high')))
            if ctx.signal == 'sell' and fvg_zone.get('low'):
                candidates.append(float(fvg_zone.get('low')))
        poi = ctx.features.get('poi')
        if poi:
            candidates.append(float(poi))
        lower_poi = ctx.features.get('lower_poi')
        if lower_poi:
            candidates.append(float(lower_poi))
        lq = ctx.features.get('lq_sweep_details', {})
        if ctx.features.get('lq_sweep_high') and lq.get('recent_high'):
            candidates.append(float(lq.get('recent_high')))
        if ctx.features.get('lq_sweep_low') and lq.get('recent_low'):
            candidates.append(float(lq.get('recent_low')))

        # Tolerance for 'near' (10 pips)
        tol = 10 * pip

        # Ensure TP sits beyond first resistance/support (not the first structure)
        if ctx.signal == 'buy' and first_res is not None:
            if tp <= first_res + 2 * pip:
                return False
        if ctx.signal == 'sell' and first_sup is not None:
            if tp >= first_sup - 2 * pip:
                return False

        # Check candidate proximity
        for c in candidates:
            if abs(tp - c) <= tol:
                return True
        # No candidate matched
        return False

    # --- BOS LOCKOUT: Block entries in dangerous conditions (both BUY and SELL) ---

    # --- ENFORCE IMPULSE PULLBACK CONFIRMATION & TP TARGET RULES ---
    try:
        pullback_ok = check_pullback_into_impulse_zone(context)
        if not pullback_ok:
            context.should_trade = False
            context.trade_quality_score = 0.0
            context.reason = "BLOCKED: NO_PULLBACK_IMPULSE_ZONE (need 50-60% retrace + closing confirmation)"
            context.blocking_filters.append('NO_PULLBACK_IMPULSE_ZONE')
            return
    except Exception:
        # If check fails unexpectedly, be conservative and block
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = "BLOCKED: PULLBACK_CHECK_ERROR"
        context.blocking_filters.append('PULLBACK_CHECK_ERROR')
        return

    # --- DISPLACEMENT-CANDLE ENTRY RULES ---
    # Require a confirming displacement/confirmation candle when using FVG entry zones
    try:
        def displacement_candle_ok(ctx, min_body_ratio=0.6, away_pct=0.15, vol_mult=1.1):
            # Use the last closed candle as confirmation
            if len(ctx.df) < 2:
                return False
            last_closed = ctx.df.iloc[-2]
            body = abs(last_closed['close'] - last_closed['open'])
            total = last_closed['high'] - last_closed['low']
            if total <= 0:
                return False
            body_ratio = body / total

            if body_ratio < min_body_ratio:
                return False

            # Volume check
            recent_vol = ctx.features.get('volume', float(last_closed.get('volume', 0)))
            avg_vol = ctx.features.get('volume_avg_20', None)
            if avg_vol is None:
                try:
                    avg_vol = float(ctx.df['volume'].rolling(20).mean().iloc[-2])
                except Exception:
                    avg_vol = 0
            if avg_vol > 0 and recent_vol <= vol_mult * avg_vol:
                return False

            # Ensure the candle closed away from the FVG edge (avoid hugging the edge)
            entry_zone = ctx.fvg_analysis.get('entry_zone') if isinstance(ctx.fvg_analysis, dict) else None
            if entry_zone and isinstance(entry_zone, dict):
                zone_low = float(entry_zone.get('low', 0))
                zone_high = float(entry_zone.get('high', 0))
                zone_range = max(1e-9, zone_high - zone_low)
                if ctx.signal == 'buy':
                    # require close to be at least 15% above zone low
                    if float(last_closed['close']) < zone_low + away_pct * zone_range:
                        return False
                else:
                    # sell: require close at least 15% below zone high
                    if float(last_closed['close']) > zone_high - away_pct * zone_range:
                        return False

            return True

        # Only enforce displacement confirm when using FVG entries (strict rule)
        if context.fvg_analysis.get('in_zone', False):
            if not displacement_candle_ok(context):
                context.should_trade = False
                context.trade_quality_score = 0.0
                context.reason = "BLOCKED: DISPLACEMENT_CANDLE_FAIL (no confirming displacement/volume candle)"
                context.blocking_filters.append('DISPLACEMENT_CANDLE_FAIL')
                return
    except Exception:
        # On unexpected errors be conservative
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = "BLOCKED: DISPLACEMENT_CHECK_ERROR"
        context.blocking_filters.append('DISPLACEMENT_CHECK_ERROR')
        return

    try:
        tp_ok = check_tp_targets_liquidity(context)
        if not tp_ok:
            context.should_trade = False
            context.trade_quality_score = 0.0
            context.reason = "BLOCKED: TP_NOT_IN_LIQUIDITY_OR_IMBALANCE (TP should target liquidity/imbalance beyond first structure)"
            context.blocking_filters.append('TP_NOT_IN_LIQ_OR_IMBALANCE')
            return
    except Exception:
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = "BLOCKED: TP_CHECK_ERROR"
        context.blocking_filters.append('TP_CHECK_ERROR')
        return

    # --- BOS LOCKOUT: Block entries in dangerous conditions (both BUY and SELL) ---
    if is_bos_lockout(context):
        context.should_trade = False
        context.trade_quality_score = 0.0
        sig = context.signal or "unknown"
        if sig == "sell":
            context.reason = "BLOCKED: BOS LOCKOUT RULE (SELL blocked: price near highs, momentum against entry, rising volume or bullish displacement)"
            context.blocking_filters.append("BOS_LOCKOUT_SELL")
        elif sig == "buy":
            context.reason = "BLOCKED: BOS LOCKOUT RULE (BUY blocked: price near lows, momentum against entry, rising volume or bearish displacement)"
            context.blocking_filters.append("BOS_LOCKOUT_BUY")
        else:
            context.reason = "BLOCKED: BOS LOCKOUT RULE"
            context.blocking_filters.append("BOS_LOCKOUT")
        return

    # --- TWO-BRAIN ELITE SETUP: If enabled, run both reversal and momentum models
    # If both models signal simultaneously, do not trade (let market decide)
    if context.features.get('two_brain_enabled', False):
        rev_active = context.features.get('reversal_model_active', False)
        mom_active = context.features.get('momentum_model_active', False)
        if rev_active and mom_active:
            context.should_trade = False
            context.trade_quality_score = 0.0
            context.reason = "BLOCKED: TWO-BRAIN CONFLICT (both reversal and momentum active)"
            context.blocking_filters.append('TWO_BRAIN_CONFLICT')
            return

    # If BOS not confirmed and no momentum override, block as before
    if not bos_confirmed and not momentum_override:
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = "BLOCKED: BOS NOT CONFIRMED"
        context.blocking_filters.append("NO_BOS_CONFIRMATION")
        return

    # --- CAP CONFIDENCE BEFORE STRUCTURE CONFIRMATION ---
    confirmed_structure = bos_confirmed
    if not confirmed_structure:
        ml_base = min(ml_base, 0.75)

    # Adjust based on HTF alignment, but allow override
    htf_conflict = context.htf_analysis.get("aligned") is False
    if context.htf_analysis["aligned"] is True:
        ml_base = min(1.0, ml_base + 0.15)  # Boost if aligned
    elif htf_conflict:
        if momentum_override:
            # OVERRIDE: Ignore HTF conflict penalty
            context.reason = "MOMENTUM OVERRIDE: Strong impulse, volume spike, BOS confirmed - ignoring HTF conflict"
            context.blocking_filters = [f for f in context.blocking_filters if not f.startswith("HTF_CONFLICT")]
            ml_base = min(1.0, ml_base + 0.20)  # Larger boost for momentum override (favor continuation)
            context.supporting_filters.append("MOMENTUM_OVERRIDE")
        else:
            # HTF should be a weight, not a veto: apply modest penalty instead of severe block
            ml_base = max(0.0, ml_base - 0.08)

    # ENHANCED FVG WEIGHTING - More aggressive usage
    if context.fvg_analysis["detected"]:
        if context.fvg_analysis["in_zone"]:
            if context.fvg_analysis["confirmation"]:
                # BEST: In zone + confirmation = prime entry
                ml_base = min(1.0, ml_base + 0.25)
            else:
                # GOOD: In zone, waiting for confirmation
                ml_base = min(1.0, ml_base + 0.15)
        else:
            # FVG detected but out of zone
            ml_base = max(0.0, ml_base - 0.25)

    # Adjust based on momentum
    if context.momentum_analysis["supports"]:
        ml_base = min(1.0, ml_base + 0.10)
    elif context.momentum_analysis["conflicts"]:
        ml_base = max(0.0, ml_base - 0.25)

    # Adjust based on volume
    if context.volume_analysis["strong"]:
        ml_base = min(1.0, ml_base + 0.08)

    # Adjust based on risk-reward
    if not context.risk_analysis["rr_ok"]:
        ml_base = max(0.0, ml_base - 0.40)  # Hard penalty

    # --- WAIT-FOR-CLOSE RULE ON XAUUSD ---
    if context.symbol.startswith("XAU"):
        # Only allow entry if the current candle is closed (i.e., not the forming candle)
        # This assumes context.df is a DataFrame with a 'time' column in ascending order
        # and that context.current_time is the current time (if available)
        # If not, skip this check
        try:
            import datetime
            last_bar_time = context.df.iloc[-1]['time']
            now = datetime.datetime.utcnow().timestamp()
            # If last bar is still forming (within last 5 minutes), block entry
            if now - last_bar_time < 60:  # 1 minute tolerance for M1, adjust as needed
                context.should_trade = False
                context.trade_quality_score = 0.0
                context.reason = "BLOCKED: WAIT-FOR-CLOSE RULE (Gold candle not closed yet)"
                context.blocking_filters.append("WAIT_FOR_CLOSE")
                return
        except Exception:
            pass

    # --- CONFIDENCE DAMPENER (structure & volume) ---
    # structure_score: 1.0 when structure confirmed, <1 when not
    structure_score = 1.0 if confirmed_structure else float(context.features.get('structure_score_fallback', 0.5))
    # volume_confirmation: 1.0 if volume confirms, otherwise a slight decay
    volume_confirmation = 1.0 if context.volume_analysis.get('strong', False) else float(context.features.get('volume_confirmation_fallback', 0.9))

    # Apply dampening so that without structure we cannot have extreme confidence
    ml_base = ml_base * structure_score
    ml_base = ml_base * volume_confirmation

    # Clamp final confidence
    final_confidence = max(0.0, min(1.0, ml_base))

    # Override confidence threshold (raise to be more conservative)
    override_confidence_threshold = float(context.features.get('override_confidence_threshold', 0.95))

    # ═══════════════════════════════════════════════════════════════════════════════
    # FILTER CONSENSUS SYSTEM: Smart filter agreement instead of one-strike-out rule
    # ═══════════════════════════════════════════════════════════════════════════════
    # Instead of: ONE blocking filter = automatic NO TRADE
    # New logic: Evaluate filter conflicts & allow entry if enough filters AGREE
    
    blocking_filters = context.blocking_filters.copy()
    supporting_filters = getattr(context, 'supporting_filters', [])
    
    # Analyze filter consensus
    filter_consensus = {
        'blocking_count': len(blocking_filters),
        'supporting_count': len(supporting_filters),
        'net_score': len(supporting_filters) - len(blocking_filters),
        'blocks': blocking_filters,
        'supports': supporting_filters[:3],  # Top 3 supporting reasons
        'consensus': None,
        'override_block': False
    }
    
    # Decision logic: CONSENSUS VOTING
    # 1. If MORE supporting filters than blocking = ALLOW (filters agree to enter)
    # 2. If blocking count = 1 but supporting_count >= 2 = ALLOW with reduced confidence
    # 3. If blocking count >= 2 and no supporting = HARD BLOCK (conflicting signals)
    # 4. Momentum override can override HTF_CONFLICT blocks
    
    if filter_consensus['net_score'] > 0:
        # MORE SUPPORTING than blocking - go with majority
        filter_consensus['consensus'] = 'SUPPORTING_MAJORITY'
        context.trade_quality_score = max(context.trade_quality_score - 0.05, context.trade_quality_score)  # Slight penalty but proceed
        print(f"[CONSENSUS ✓] {context.symbol} {context.signal}: Supporting filters ({filter_consensus['supporting_count']}) > Blocking ({filter_consensus['blocking_count']}) - ENTRY ALLOWED")
        
    elif filter_consensus['blocking_count'] == 1 and filter_consensus['supporting_count'] >= 2:
        # ONE blocking filter but MULTIPLE supporting = allow with caution
        single_block = blocking_filters[0]
        if "HTF" in single_block or "VOLATILITY" in single_block:  # Non-critical blocks
            filter_consensus['consensus'] = 'SINGLE_SOFT_BLOCK_OVERRIDDEN'
            filter_consensus['override_block'] = True
            context.trade_quality_score = max(context.trade_quality_score - 0.15, context.trade_quality_score)  # More penalty
            print(f"[CONSENSUS OVERRIDE ⚠️] {context.symbol} {context.signal}: Single soft block '{single_block}' overridden by {filter_consensus['supporting_count']} supporting filters - REDUCED CONFIDENCE")
        else:
            filter_consensus['consensus'] = 'CRITICAL_BLOCK'
            filter_consensus['override_block'] = False
            print(f"[CONSENSUS HARD BLOCK] {context.symbol} {context.signal}: Critical block '{single_block}' cannot be overridden")
            
    elif filter_consensus['blocking_count'] >= 2 and filter_consensus['supporting_count'] == 0:
        # Multiple conflicts with no support = HARD BLOCK
        filter_consensus['consensus'] = 'MULTI_CONFLICT_HARD_BLOCK'
        filter_consensus['override_block'] = False
        print(f"[CONSENSUS HARD BLOCK] {context.symbol} {context.signal}: {filter_consensus['blocking_count']} blocking filters with no supporting evidence")
        
    else:
        # Balanced or moderately blocked = use momentum override if available
        if momentum_override and any("HTF_CONFLICT" in f for f in blocking_filters):
            filter_consensus['consensus'] = 'MOMENTUM_OVERRIDE'
            filter_consensus['override_block'] = True
            context.trade_quality_score = max(context.trade_quality_score - 0.10, context.trade_quality_score)
            print(f"[MOMENTUM OVERRIDE ✓] {context.symbol} {context.signal}: HTF block overridden by strong momentum signal")
        else:
            filter_consensus['consensus'] = 'NORMAL_BLOCKING'
            filter_consensus['override_block'] = False
    
    context.filter_consensus = filter_consensus

    # Apply blocking filters decision
    if len(blocking_filters) > 0 and not filter_consensus['override_block']:
        context.should_trade = False
        context.trade_quality_score = 0.0
        context.reason = f"BLOCKED: {blocking_filters[0]} [Consensus: {filter_consensus['consensus']}]"
        return
    elif filter_consensus['override_block']:
        print(f"  Filter override applied: {blocking_filters[0] if blocking_filters else 'None'}")

    # Check minimum ML confidence (relaxed when technicals are strong)
    min_conf = 0.65 if context.fvg_analysis["in_zone"] else 0.70
    
    # If ML confidence is very low (<0.3), prioritize technical signals
    technical_strength = (
        context.fvg_analysis["in_zone"] and context.fvg_analysis["confirmation"] and
        bos_confirmed and 
        context.volume_analysis.get('strong', False) and
        len(context.supporting_filters) >= 3
    )
    
    if final_confidence < min_conf:
        if final_confidence < 0.3 and technical_strength:
            # Override: Allow trade when ML is uncertain but technicals are very strong
            print(f"[ML OVERRIDE] {context.symbol}: ML confidence {final_confidence:.2f} very low, but strong technicals - allowing entry")
            context.supporting_filters.append(f"ML_LOW_CONF_OVERRIDE:{final_confidence:.2f}")
        else:
            context.should_trade = False
            context.trade_quality_score = final_confidence
            context.reason = f"ML confidence {final_confidence:.2f} < {min_conf:.2f} minimum"
            return

    # --- OVERRIDE RULES: If ML is extremely confident, allow override only when
    # BOS or FVG confirmation exists AND other key filters agree (volume, risk, support)
    override_allowed = False
    if final_confidence >= override_confidence_threshold:
        confirm_ok = bos_confirmed or context.fvg_analysis.get('confirmation', False)
        other_filters_ok = (
            context.volume_analysis.get('strong', False)
            and context.risk_analysis.get('rr_ok', False)
            and (len(context.supporting_filters) >= 2 or context.fvg_analysis.get('in_zone', False))
        )
        if confirm_ok and other_filters_ok:
            override_allowed = True
        else:
            # record why override was blocked for debugging
            blocked_reasons = []
            if not confirm_ok:
                blocked_reasons.append('NO_BOS_OR_FVG_CONFIRM')
            if not context.volume_analysis.get('strong', False):
                blocked_reasons.append('VOLUME_WEAK')
            if not context.risk_analysis.get('rr_ok', False):
                blocked_reasons.append('RR_FAIL')
            if len(context.supporting_filters) < 2 and not context.fvg_analysis.get('in_zone', False):
                blocked_reasons.append('INSUFFICIENT_SUPPORT')
            context.supporting_filters.append(f"OVERRIDE_BLOCKED:{','.join(blocked_reasons)}")

    # --- HTF conflict handling: prefer continuation-only when HTF mismatches
    if htf_conflict and not is_continuation:
        # Allow reversal only if momentum_override or a permitted ML override
        if not momentum_override and not override_allowed:
            context.should_trade = False
            context.trade_quality_score = final_confidence
            context.reason = "BLOCKED: HTF conflict — reversal trades not allowed unless strong override"
            context.blocking_filters.append("HTF_CONFLICT_REVERSAL_NOT_ALLOWED")
            return

    # Require at least 2 supporting filters (or strong FVG with 1 other)
    min_supports = 1 if (context.fvg_analysis["in_zone"] and context.fvg_analysis["confirmation"]) else 2
    if len(context.supporting_filters) < min_supports:
        context.should_trade = False
        context.trade_quality_score = final_confidence
        context.reason = f"Insufficient confirmations: {len(context.supporting_filters)} supporting filters (need >={min_supports})"
        return

    # --- CONSOLIDATION / COMPRESSION FILTER ---
    def in_compression_zone(ctx, lookback=15, max_range_factor=0.25):
        """
        Detects if current price is in a tight consolidation/compression.
        Blocks entries *inside* the coil, forces waiting for a clean break + close.
        """
        df = ctx.df
        if df is None or len(df) < lookback + 1:
            return False, "NOT_ENOUGH_DATA"

        window = df.iloc[-lookback:]
        high = float(window['high'].max())
        low = float(window['low'].min())
        if high <= low:
            return False, "INVALID_RANGE"

        total_range = high - low
        # Compare to ATR-like recent volatility
        try:
            recent = df.iloc[-(lookback*2):]
            avg_bar_range = float((recent['high'] - recent['low']).mean())
        except Exception:
            avg_bar_range = total_range

        # "Compression" = range is small vs normal volatility
        if avg_bar_range <= 0:
            return False, "NO_VOL_REF"

        range_factor = total_range / avg_bar_range

        # Price currently inside that tight range?
        last_close = float(df.iloc[-1]['close'])
        inside_range = (low <= last_close <= high)

        # If range is much smaller than normal and price still inside → compression
        if range_factor < max_range_factor and inside_range:
            return True, f"COMPRESSION: range_factor={range_factor:.2f}, lookback={lookback}"
        return False, f"NO_COMPRESSION: range_factor={range_factor:.2f}"

    # HARD BLOCK: Do not trade *inside* compression zones
    in_comp, comp_reason = in_compression_zone(context)
    if in_comp:
        context.should_trade = False
        context.trade_quality_score = final_confidence
        context.reason = f"BLOCKED: ENTRY_INSIDE_COMPRESSION ({comp_reason})"
        context.blocking_filters.append("ENTRY_INSIDE_COMPRESSION")
        return

    # ============================================================
    # 🔒 STRICT CORE ICT GATE (applies to BOTH buys and sells)
    # HTF BIAS + STRUCTURE + IMPULSE + PULLBACK + CONFIRMATION
    #
    # Mapping to your rule:
    # - HTF bias: H1/M30 bullish/bearish OR structure already broken
    # - Structure: break + close above last LH (buy) / below last HL (sell)
    # - Momentum: strong impulse candle + follow‑through (inside check_pullback_rule)
    # - Entry: on pullback after impulse, NOT during impulse (inside check_pullback_rule
    #          + check_entry_tf_confirmation)
    # If ANY of these fail → NO TRADE.
    # ============================================================
    core_fail_reasons = []

    # 1) HTF bias + structure (BOS) gate
    htf_ok, htf_reason = check_htf_demand_reaction(context)
    if not htf_ok:
        core_fail_reasons.append(f"HTF_FAIL: {htf_reason}")

    # 2) Impulse + follow‑through + pullback gate
    pullback_ok, retrace_pct, pullback_reason = check_pullback_rule(context)
    if not pullback_ok:
        core_fail_reasons.append(f"PULLBACK_FAIL: {pullback_reason}")

    # 3) Entry‑TF confirmation gate (M5/M15 BOS + rejection)
    entry_ok, entry_type, entry_boost = check_entry_tf_confirmation(context)
    if not entry_ok:
        core_fail_reasons.append(f"ENTRY_TF_FAIL: {entry_type}")

    # 4) BOS confirmation must still be present (structure flip)
    bos = context.fvg_analysis.get("bos", None)
    bos_confirmed = bos is not None and bos == context.signal
    if not bos_confirmed:
        core_fail_reasons.append("BOS_FAIL: BOS not confirmed")

    # ✅ FIX 2: FINAL DECISION - Replace hard block with score-based gate
    # Instead of: if core_fail_reasons → block trade
    # Now: penalize score, but let ML confidence decide
    
    if core_fail_reasons:
        # Apply penalty based on failures, but don't block
        penalty_per_failure = 0.05  # Each failure = -5% confidence
        total_penalty = len(core_fail_reasons) * penalty_per_failure
        context.ml_confidence = max(0.0, context.ml_confidence - total_penalty)
        context.trade_quality_score = context.ml_confidence
        context.supporting_filters.append(f"CORE_GATE_PENALTIES: {', '.join(core_fail_reasons)} (-{total_penalty*100:.0f}% confidence)")
        print(f"[⚠️ CORE GATE SOFT BLOCK] {context.symbol}: {', '.join(core_fail_reasons)}")
        print(f"   → Applied -{total_penalty*100:.0f}% penalty. ML confidence: {context.ml_confidence:.2f}")
        print(f"   → Will enter if ML confidence >= 0.60 (bypass gate if strong setup)")
    else:
        # All core conditions pass - reward the setup
        final_confidence = min(1.0, context.ml_confidence + 0.05)
        context.ml_confidence = final_confidence
        context.trade_quality_score = final_confidence

    # ✅ FIX 2: FINAL SCORE-BASED DECISION
    # Allow entry if ML confidence > 0.60, regardless of some penalties
    # This lets your ML model decide, not binary gates
    if context.ml_confidence >= 0.60:
        context.should_trade = True
        if core_fail_reasons:
            context.reason = f"SCORE OVERRIDE: {len(context.supporting_filters)} factors (core penalties applied but confidence {context.ml_confidence:.2f} >= 0.60)"
        else:
            context.reason = f"APPROVED (CORE PASS): {len(context.supporting_filters)} confirming factors, confidence={context.ml_confidence:.2f}"
    else:
        # Only block if confidence drops below 0.60 after penalties
        context.should_trade = False
        context.reason = f"BLOCKED: ML confidence {context.ml_confidence:.2f} below threshold 0.60"
        print(f"[❌ TRADE REJECTED] {context.symbol}: ML confidence too low ({context.ml_confidence:.2f} < 0.60)")
        return


def compute_continuous_master_score(final_score, ml_confidence, setup_type=None, symbol=None):
    """
    Master probabilistic scoring: convert single final_score into continuous (size, aggression, skip_prob).
    
    Eliminates hard thresholds in favor of smooth probabilistic decision-making:
    - score < 3.5: skip_prob = 100% (never enter)
    - 3.5 <= score < 5.0: skip_prob = smooth interpolation (may probabilistically skip)
    - 5.0 <= score < 7.0: enter with size_mode='reduced', aggression based on score
    - score >= 7.0: enter with size_mode='full', aggression ramped up
    
    Returns: {
        'should_enter': bool (deterministic pass/fail),
        'skip_probability': float (0-1; use for probabilistic gating),
        'size_multiplier': float (0-1; scale lot size),
        'aggression_level': float (0-1; affects stop/TP distances and partial TP timing),
        'reason': str
    }
    """
    import random
    
    result = {
        'should_enter': True,
        'skip_probability': 0.0,
        'size_multiplier': 0.5,
        'aggression_level': 0.5,
        'reason': ''
    }
    
    # Hard floor: never enter below 3.5
    if final_score < 3.5:
        result['should_enter'] = False
        result['skip_probability'] = 1.0
        result['reason'] = f"Score {final_score:.2f} below hard floor (3.5)"
        return result
    
    # Soft band: 3.5-5.0, probabilistic skipping based on score
    if 3.5 <= final_score < 5.0:
        # Map score to skip probability (0 at 5.0, 100% at 3.5)
        skip_prob = (5.0 - final_score) / 1.5
        result['skip_probability'] = skip_prob
        
        # Probabilistically skip based on the band
        if random.random() < skip_prob:
            result['should_enter'] = False
            result['reason'] = f"Probabilistic skip (score {final_score:.2f} in soft band; skip_prob={skip_prob:.2%})"
            return result
        
        # If we got here, we're entering with reduced sizing
        result['size_multiplier'] = 0.3 + 0.2 * (final_score - 3.5) / 1.5  # 0.3 to 0.5
        result['aggression_level'] = 0.4 + 0.2 * (final_score - 3.5) / 1.5  # 0.4 to 0.6
        result['reason'] = f"Soft band entry (score {final_score:.2f}); reduced size & caution"
    
    # Normal band: 5.0-7.0, reduced sizing with growing aggression
    elif 5.0 <= final_score < 7.0:
        result['size_multiplier'] = 0.5 + 0.3 * (final_score - 5.0) / 2.0  # 0.5 to 0.8
        result['aggression_level'] = 0.6 + 0.2 * (final_score - 5.0) / 2.0  # 0.6 to 0.8
        result['reason'] = f"Normal band (score {final_score:.2f}); reduced sizing"
    
    # Hot band: >= 7.0, full sizing with max aggression
    else:  # final_score >= 7.0
        result['size_multiplier'] = min(1.0, 0.8 + 0.2 * (final_score - 7.0) / 2.0)  # 0.8 to 1.0
        result['aggression_level'] = min(1.0, 0.8 + 0.2 * (final_score - 7.0) / 2.0)  # 0.8 to 1.0
        result['reason'] = f"Hot band (score {final_score:.2f}); full sizing & aggression"
    
    # Temper aggression if ML confidence is low (even if score is high)
    if ml_confidence < 0.8:
        result['aggression_level'] *= 0.8
        result['reason'] += f"; ML confidence tempered ({ml_confidence:.2f})"
    
    # Apply per-setup / per-symbol loss dampening if available
    try:
        if symbol and setup_type:
            mem = load_trade_memory()
            base = symbol.replace('.m', '').upper()
            setup_key = (setup_type or 'unknown').lower()
            recent_trades = mem.get(base, {}).get(setup_key, [])
            if len(recent_trades) >= 5:
                recent_losses = sum(1 for t in recent_trades[-5:] if t.get('pnl', 0) < 0)
                if recent_losses >= 3:
                    # Heavy dampening: 50% reduction in aggression & size
                    result['size_multiplier'] *= 0.7
                    result['aggression_level'] *= 0.5
                    result['reason'] += f"; loss-streak dampening (3+ losses in last 5)"
    except Exception:
        pass
    
    return result

def unified_trade_decision(symbol, ml_confidence, features, df, entry, sl, tp):
    """
    Master function: run full analysis and decide whether to trade.
    Now computes both BUY and SELL scores, applies continuous probabilistic scoring.
    Eliminates hard skip/reduced/full gates in favor of smooth sizing/aggressiveness.

    Returns:
        (should_trade: bool, direction: str, quality_score: float, reason: str, context: TradeDecisionContext)
    """
    # Helper to run full analysis for a given direction
    # Helper to run full analysis for a given direction
    def analyze_direction(direction):
        context = TradeDecisionContext(symbol, direction, ml_confidence, features, df)
        # Attach proposed trade parameters so decision engine can validate TP/entry rules
        context.entry = entry
        context.sl = sl
        context.tp = tp

        # --- LOW-TF TREND + TRENDLINE BREAK FEATURES ---
        try:
            ltf_trend = detect_trend(df)
        except Exception:
            ltf_trend = "sideways"
        context.features['ltf_trend'] = ltf_trend

        try:
            tl_broken = detect_trendline_break(df)
        except Exception:
            tl_broken = False
        context.features['trendline_break'] = tl_broken

        # Run all higher-level analyses
        analyze_htf_trend(context)
        analyze_fvg_zone(context)
        analyze_momentum_confluence(context)
        analyze_volume_confirmation(context)
        analyze_risk_reward(context, entry, sl, tp)
        analyze_market_regime(context)

        # Also expose regime string in features for convenience
        try:
            regime_str = context.regime_analysis.get("regime") or context.regime_analysis.get("state")
        except Exception:
            regime_str = None
        if regime_str:
            context.features['regime'] = regime_str

        compute_unified_decision(context)
        return context

    # Analyze both directions
    buy_context = analyze_direction("buy")
    sell_context = analyze_direction("sell")

    # Compare scores, but only if all filters pass
    buy_score = buy_context.trade_quality_score if buy_context.should_trade else 0.0
    sell_score = sell_context.trade_quality_score if sell_context.should_trade else 0.0

    if buy_score > sell_score and buy_score > 0:
        chosen = buy_context
        chosen_direction = "buy"
    elif sell_score > buy_score and sell_score > 0:
        chosen = sell_context
        chosen_direction = "sell"
    else:
        # No valid trade
        print(f"\n[UNIFIED DECISION] {symbol} - NO TRADE (Buy: {buy_score:.2f}, Sell: {sell_score:.2f})")
        return False, None, 0.0, "No valid trade direction", None

    # Apply continuous probabilistic master scoring
    setup_type = infer_setup_type(chosen.features)
    final_score = chosen.trade_quality_score
    master_score = compute_continuous_master_score(final_score, ml_confidence, setup_type, symbol)
    
    # Log detailed decision
    print(f"\n[UNIFIED DECISION] {symbol} {chosen_direction.upper()}")
    print(f"  HTF: {chosen.htf_analysis['reason']}")
    print(f"  FVG: {chosen.fvg_analysis['reason']}")
    print(f"  Momentum: {chosen.momentum_analysis['reason']}")
    print(f"  Volume: {chosen.volume_analysis['reason']}")
    print(f"  Risk-Reward: {chosen.risk_analysis['reason']}")
    print(f"  Regime: {chosen.regime_analysis['reason']}")
    print(f"  \n  Blocking Filters: {chosen.blocking_filters if chosen.blocking_filters else 'None'}")
    print(f"  Supporting Factors: {chosen.supporting_filters}")
    print(f"  \n  Base Score: {chosen.trade_quality_score:.2f}")
    print(f"  Master Scoring: {master_score['reason']}")
    print(f"    - Size Multiplier: {master_score['size_multiplier']:.2%}")
    print(f"    - Aggression Level: {master_score['aggression_level']:.2%}")
    print(f"    - Skip Probability: {master_score['skip_probability']:.2%}\n")
    
    # If master score says skip, honor it
    if not master_score['should_enter']:
        print(f"  ➜ DECISION: {master_score['reason']}\n")
        return False, chosen_direction, 0.0, master_score['reason'], None
    
    # Inject sizing and aggression into features for downstream use
    chosen.features['size_multiplier'] = master_score['size_multiplier']
    chosen.features['aggression_level'] = master_score['aggression_level']
    chosen.features['master_score_reason'] = master_score['reason']
    
    print(f"  ➜ DECISION: {chosen.reason}")
    print(f"  Final Score: {chosen.trade_quality_score:.2f}\n")

    return chosen.should_trade, chosen_direction, chosen.trade_quality_score, chosen.reason, chosen

