# PRICE ACTION CONFIRMATION WITHIN FVG ZONES
# ═══════════════════════════════════════════════════════════════════════════════

def detect_fvg_entry_confirmation(df, entry_zone, signal_direction, lookback=5):
    """
    Detect price action confirmation patterns within FVG entry zone.
    
    Confirmations checked:
    1. Pin Bar / Hammer: Long wick on entry side, small body
    2. Engulfing: Current bar engulfs previous bar
    3. Bullish/Bearish Close: Close on the correct side
    4. Consolidation: Multiple bars coiling within zone
    
    Returns:
        (has_confirmation: bool, confirmation_type: str, strength: float 0-1)
    """
    if len(df) < 2 or entry_zone is None:
        return False, "None", 0.0
    
    zone_low = entry_zone.get("low")
    zone_high = entry_zone.get("high")
    if not zone_low or not zone_high:
        return False, "None", 0.0
    
    recent_bars = df.iloc[-lookback:]
    last_bar = df.iloc[-1]
    prev_bar = df.iloc[-2] if len(df) >= 2 else None
    
    # Check if price is actually in zone
    if not (zone_low <= last_bar['close'] <= zone_high):
        return False, "None", 0.0
    
    confirmation_strength = 0.0
    confirmation_type = "None"
    
    # 1. Check for Pin Bar / Hammer
    if signal_direction == "buy":
        # Hammer: long lower wick, small body in zone
        lower_wick = last_bar['low']
        body_top = last_bar['close']
        body_bottom = last_bar['open']
        body_size = abs(body_top - body_bottom)
        total_range = last_bar['high'] - last_bar['low']
        
        if total_range > 0:
            wick_ratio = (body_bottom - lower_wick) / total_range
            body_ratio = body_size / total_range
            
            if wick_ratio > 0.6 and body_ratio < 0.3 and body_top > zone_low:
                confirmation_type = "PIN_BAR_BUY"
                confirmation_strength = 0.8
    
    elif signal_direction == "sell":
        # Shooting Star: long upper wick, small body in zone
        upper_wick = last_bar['high']
        body_bottom = min(last_bar['open'], last_bar['close'])
        body_top = max(last_bar['open'], last_bar['close'])
        body_size = abs(body_top - body_bottom)
        total_range = last_bar['high'] - last_bar['low']
        
        if total_range > 0:
            wick_ratio = (upper_wick - body_top) / total_range
            body_ratio = body_size / total_range
            
            if wick_ratio > 0.6 and body_ratio < 0.3 and body_bottom < zone_high:
                confirmation_type = "PIN_BAR_SELL"
                confirmation_strength = 0.8
    
    # 2. Check for Engulfing
    if prev_bar is not None and confirmation_strength < 0.7:
        if signal_direction == "buy":
            # Bullish engulfing: current bar opens below and closes above previous
            if (last_bar['open'] < prev_bar['close'] and 
                last_bar['close'] > prev_bar['open']):
                confirmation_type = "ENGULFING_BUY"
                confirmation_strength = 0.75
        
        elif signal_direction == "sell":
            # Bearish engulfing: current bar opens above and closes below previous
            if (last_bar['open'] > prev_bar['open'] and 
                last_bar['close'] < prev_bar['close']):
                confirmation_type = "ENGULFING_SELL"
                confirmation_strength = 0.75
    
    # 3. Check for directional close
    if confirmation_strength < 0.5:
        if signal_direction == "buy" and last_bar['close'] > (zone_low + zone_high) / 2:
            confirmation_type = "BULLISH_CLOSE"
            confirmation_strength = 0.6
        elif signal_direction == "sell" and last_bar['close'] < (zone_low + zone_high) / 2:
            confirmation_type = "BEARISH_CLOSE"
            confirmation_strength = 0.6
    
    has_confirmation = confirmation_strength >= 0.6
    return has_confirmation, confirmation_type, confirmation_strength

def detect_approaching_fvg_zone(df, entry_zone, signal_direction, max_distance_pips=10):
    """
    Detect if price is approaching FVG entry zone and likely to enter soon.
    
    This is useful for:
    1. Pre-positioning orders before zone entry
    2. Increasing conviction when price approaches
    3. Warning when zone might be missed (price moving away)
    
    Returns:
        (approaching: bool, distance_pips: float, direction_correct: bool, eta_bars: int)
    """
    if len(df) < 5 or entry_zone is None:
        return False, 999.0, False, 999
    
    zone_low = entry_zone.get("low")
    zone_high = entry_zone.get("high")
    if not zone_low or not zone_high:
        return False, 999.0, False, 999
    
    pip_size = 0.01 if (len(df) > 0 and "JPY" in df.get('symbol', [''])[0]) else 0.0001
    last_close = df.iloc[-1]['close']
    
    # Calculate distance to zone
    if last_close < zone_low:
        distance_pips = (zone_low - last_close) / pip_size
        approaching_direction = "up"
    elif last_close > zone_high:
        distance_pips = (last_close - zone_high) / pip_size
        approaching_direction = "down"
    else:
        # Already in zone
        return True, 0.0, True, 0
    
    # Check if price is moving in the right direction
    price_3_bars_ago = df.iloc[-4]['close'] if len(df) >= 4 else last_close
    direction_correct = (approaching_direction == "up" and last_close > price_3_bars_ago) or \
                       (approaching_direction == "down" and last_close < price_3_bars_ago)
    
    # Estimate bars until zone entry (simple linear projection)
    recent_move = abs(last_close - price_3_bars_ago) / pip_size
    if recent_move > 0:
        eta_bars = int(distance_pips / (recent_move / 3))
    else:
        eta_bars = 999
    
    # Determine if "approaching" (close enough and moving correctly)
    approaching = (distance_pips <= max_distance_pips) and direction_correct
    
    return approaching, distance_pips, direction_correct, eta_bars

