# ADVANCED INSTITUTIONAL ZONE DETECTION
# ═══════════════════════════════════════════════════════════════════════════════
# Detects WHERE INSTITUTIONS BUY and SELL based on professional trading footprints
# NOT on how "expensive" the price looks, but on real supply/demand imbalances

def detect_institutional_zones(df, symbol, lookback=50, threshold_sensitivity=0.7):
    """
    ADVANCED INSTITUTIONAL ZONE DETECTION
    
    Identifies zones where large institutional players accumulate (BUY) or dump (SELL)
    based on order flow, volume patterns, and price rejection mechanics.
    
    threshold_sensitivity: 0.0-1.0 (lower = stricter, fewer signals; higher = more lenient, more signals)
    - 0.3 = Very strict (only strongest institutional signals)
    - 0.5 = Normal (balanced sensitivity)
    - 0.7 = Standard (default, good for most conditions)
    - 0.9 = Very lenient (more signals, potentially more false positives)
    
    Returns dict with:
    {
        'institutional_buy_zones': [(low, high, strength), ...],  # Where they accumulate
        'institutional_sell_zones': [(low, high, strength), ...], # Where they dump
        'current_action': 'accumulating' | 'distributing' | 'consolidating',
        'strength_score': 0-100,  # How confident we are
        'recommendation': 'buy_here' | 'sell_here' | 'neutral'
    }
    """
    if df is None or len(df) < lookback:
        return {
            'institutional_buy_zones': [],
            'institutional_sell_zones': [],
            'current_action': 'unknown',
            'strength_score': 0,
            'recommendation': 'neutral'
        }
    
    try:
        result = {
            'institutional_buy_zones': [],
            'institutional_sell_zones': [],
            'current_action': 'consolidating',
            'strength_score': 0,
            'recommendation': 'neutral'
        }
        
        pip_size = 0.01 if "JPY" in symbol else 0.0001
        recent = df.iloc[-lookback:].copy()
        
        # Adjust thresholds based on sensitivity
        # Lower sensitivity = higher thresholds (stricter)
        # Higher sensitivity = lower thresholds (more lenient)
        wick_multiplier = 2.0 / threshold_sensitivity  # 6.67 at 0.3, 2.86 at 0.7, 2.22 at 0.9
        volume_multiplier = 1.3 / (threshold_sensitivity * 0.7)  # 3.09 at 0.3, 2.45 at 0.7, 1.59 at 0.9
        supply_demand_vol_mult = 1.2 / (threshold_sensitivity * 0.6)  # 3.33 at 0.3, 2.86 at 0.7, 1.85 at 0.9
        accumulation_threshold = 0.7 / threshold_sensitivity  # 2.33 at 0.3, 1.0 at 0.7, 0.78 at 0.9
        
        # 1️⃣ DETECT ORDER BLOCKS (Where institutions got trapped/flipped)
        # Order Block = Price bounced hard + high volume rejection
        buy_order_blocks = []
        sell_order_blocks = []
        
        for i in range(2, len(recent) - 1):
            curr = recent.iloc[i]
            prev = recent.iloc[i-1]
            prev_prev = recent.iloc[i-2]
            next_bar = recent.iloc[i+1] if i+1 < len(recent) else None
            
            # BUY ORDER BLOCK: Deep wick down + strong close + volume spike + price rejected higher
            lower_wick = min(curr['open'], curr['close']) - curr['low']
            body = abs(curr['close'] - curr['open'])
            avg_vol = recent['tick_volume'].rolling(10).mean().iloc[i]
            
            if (lower_wick > body * wick_multiplier and  # Large lower wick (rejection) - sensitivity adjusted
                curr['close'] > curr['open'] and  # Bullish close
                curr['tick_volume'] > avg_vol * volume_multiplier and  # Volume spike - sensitivity adjusted
                next_bar is not None and next_bar['close'] > curr['close']):  # Price rejected higher
                
                buy_order_blocks.append({
                    'low': curr['low'],
                    'high': curr['high'],
                    'strength': min(1.0, (lower_wick / (curr['high'] - curr['low'])) * (curr['tick_volume'] / (avg_vol + 1e-9)))
                })
            
            # SELL ORDER BLOCK: Deep wick up + strong close + volume spike + price rejected lower
            upper_wick = curr['high'] - max(curr['open'], curr['close'])
            
            if (upper_wick > body * wick_multiplier and  # Large upper wick (rejection) - sensitivity adjusted
                curr['close'] < curr['open'] and  # Bearish close
                curr['tick_volume'] > avg_vol * volume_multiplier and  # Volume spike - sensitivity adjusted
                next_bar is not None and next_bar['close'] < curr['close']):  # Price rejected lower
                
                sell_order_blocks.append({
                    'low': curr['low'],
                    'high': curr['high'],
                    'strength': min(1.0, (upper_wick / (curr['high'] - curr['low'])) * (curr['tick_volume'] / (avg_vol + 1e-9)))
                })
        
        result['institutional_buy_zones'] = buy_order_blocks
        result['institutional_sell_zones'] = sell_order_blocks
        
        # 2️⃣ DETECT SUPPLY/DEMAND ZONES (Price rejections at levels)
        # Supply zone: Price rejected downward (institutional selling pressure)
        # Demand zone: Price rejected upward (institutional buying support)
        
        supply_zones = []
        demand_zones = []
        
        for i in range(2, len(recent) - 1):
            curr = recent.iloc[i]
            prev = recent.iloc[i-1]
            
            # SUPPLY ZONE: High touched, rejected down hard
            if (curr['high'] > recent['high'].iloc[max(0, i-5):i].max() and  # Price makes new high
                curr['close'] < curr['open'] and  # Bearish candle
                curr['close'] < (curr['open'] + curr['high']) / 2 and  # Close in bottom half
                curr['tick_volume'] > recent['tick_volume'].rolling(10).mean().iloc[i] * supply_demand_vol_mult):  # Volume - sensitivity adjusted
                
                strength = abs(curr['close'] - curr['high']) / (curr['high'] - curr['low'] + 1e-9)
                supply_zones.append({
                    'level': curr['high'],
                    'zone': (curr['high'] - (curr['high'] - curr['low']) * 0.5, curr['high']),
                    'strength': min(1.0, strength * 1.5)
                })
            
            # DEMAND ZONE: Low touched, rejected up hard
            if (curr['low'] < recent['low'].iloc[max(0, i-5):i].min() and  # Price makes new low
                curr['close'] > curr['open'] and  # Bullish candle
                curr['close'] > (curr['open'] + curr['low']) / 2 and  # Close in top half
                curr['tick_volume'] > recent['tick_volume'].rolling(10).mean().iloc[i] * supply_demand_vol_mult):  # Volume - sensitivity adjusted
                
                strength = abs(curr['close'] - curr['low']) / (curr['high'] - curr['low'] + 1e-9)
                demand_zones.append({
                    'level': curr['low'],
                    'zone': (curr['low'], curr['low'] + (curr['high'] - curr['low']) * 0.5),
                    'strength': min(1.0, strength * 1.5)
                })
        
        # 3️⃣ DETECT CURRENT INSTITUTIONAL ACTIVITY
        # Accumulation: Buying pressure, wicks down rejected, volume increasing on buys
        # Distribution: Selling pressure, wicks up rejected, volume increasing on sells
        
        recent_10 = recent.iloc[-10:]
        bullish_candles = sum(1 for i in range(len(recent_10)) if recent_10.iloc[i]['close'] > recent_10.iloc[i]['open'])
        bearish_candles = len(recent_10) - bullish_candles
        
        avg_vol_recent = recent_10['tick_volume'].mean()
        bullish_vol = recent_10[recent_10['close'] > recent_10['open']]['tick_volume'].mean()
        bearish_vol = recent_10[recent_10['close'] <= recent_10['open']]['tick_volume'].mean()
        
        accumulation_score = (bullish_candles / 10.0) * (bullish_vol / (avg_vol_recent + 1e-9))
        distribution_score = (bearish_candles / 10.0) * (bearish_vol / (avg_vol_recent + 1e-9))
        
        # Sensitivity-adjusted thresholds for accumulation/distribution detection
        accum_threshold = accumulation_threshold
        
        if accumulation_score > distribution_score * accum_threshold:
            result['current_action'] = 'accumulating'
            result['recommendation'] = 'buy_here'
            result['strength_score'] = min(100, accumulation_score * 100)
        elif distribution_score > accumulation_score * accum_threshold:
            result['current_action'] = 'distributing'
            result['recommendation'] = 'sell_here'
            result['strength_score'] = min(100, distribution_score * 100)
        else:
            result['current_action'] = 'consolidating'
            result['recommendation'] = 'neutral'
            result['strength_score'] = 50
        
        # 4️⃣ LIQUIDITY SWEEP DETECTION (Institutions shaking out retail)
        # Sweep up then down = institutions clearing buys, time to sell
        # Sweep down then up = institutions clearing shorts, time to buy
        
        last_3 = recent.iloc[-3:]
        last_high = recent['high'].iloc[-10:].max()
        last_low = recent['low'].iloc[-10:].min()
        
        # Liquidity sweep up then reversal down
        if (last_3.iloc[0]['high'] >= last_high and  # Swept up to clear buys
            last_3.iloc[-1]['close'] < last_3.iloc[0]['close']):  # Reversed down
            result['recommendation'] = 'sell_here'
            result['strength_score'] = max(result['strength_score'], 75)
        
        # Liquidity sweep down then reversal up
        if (last_3.iloc[0]['low'] <= last_low and  # Swept down to clear shorts
            last_3.iloc[-1]['close'] > last_3.iloc[0]['close']):  # Reversed up
            result['recommendation'] = 'buy_here'
            result['strength_score'] = max(result['strength_score'], 75)
        
        return result
    
    except Exception as e:
        return {
            'institutional_buy_zones': [],
            'institutional_sell_zones': [],
            'current_action': 'error',
            'strength_score': 0,
            'recommendation': 'neutral',
            'error': str(e)
        }

