# ═══════════════════════════════════════════════════════════════════════════════
# MASTER ENTRY ORCHESTRATOR - COORDINATES ALL FILTERS & SMC CHECKS
# ═══════════════════════════════════════════════════════════════════════════════

def master_entry_orchestrator(symbol, direction, price_data, context=None, 
                             enforce_smc=True, allow_smc_override=True):
    """
    MASTER ENTRY ORCHESTRATOR: Complete entry validation pipeline.
    
    This function coordinates ALL filters and checks in the correct order:
    1. Structure Gate (MANDATORY BOS check)
    2. Counter-Trend Safety Check  
    3. Master Trend & Momentum Filter (with SMC compatibility)
    4. H1 Hard Filter
    5. SMC/ICT Entry Validation (if enabled)
    6. Risk & Session Filters
    7. Final Entry Execution
    
    Args:
        symbol: Trading symbol
        direction: 'buy' or 'sell'
        price_data: Dict with timeframe data {'m15': df, 'h1': df, 'h4': df, etc.}
        context: Trading context dict (optional)
        enforce_smc: If True, requires SMC checks to pass
        allow_smc_override: If True, allows SMC to override some filters
        
    Returns:
        Dict with execution results and detailed reasoning
    """
    
    result = {
        'execute': False,
        'reason': 'Entry blocked: Validation failed',
        'confidence': 0.0,
        'filters_passed': [],
        'filters_failed': [],
        'smc_details': None,
        'entry_price': None,
        'sl_price': None,
        'tp_price': None,
        'lot_size': 0.0,
        'trade_result': None
    }
    
    try:
        # Extract dataframes
        df_m15 = price_data.get('m15') or price_data.get('M15')
        df_h1 = price_data.get('h1') or price_data.get('H1') 
        df_h4 = price_data.get('h4') or price_data.get('H4')
        df_m30 = price_data.get('m30') or price_data.get('M30')
        current_price = price_data.get('price') or price_data.get('close', 0)
        
        if not df_m15 or len(df_m15) < 50:
            result['reason'] = 'Insufficient M15 data for analysis'
            return result
            
        print(f"\n[MASTER ENTRY] {symbol} {direction.upper()} - Starting validation pipeline...")
        
        # === STEP 1: VOLATILITY FILTER (BTCUSD CHOPPY MARKET BLOCK) ===
        print(f"[STEP 1] Volatility Filter Check...")
        vol_tradable, vol_reason = is_symbol_tradable_now(symbol, df_m15)
        if not vol_tradable:
            result['reason'] = f"Volatility Filter: {vol_reason}"
            result['filters_failed'].append('VOLATILITY_FILTER')
            print(f"[STEP 1] ✗ Volatility filter BLOCKED: {vol_reason}")
            return result
        result['filters_passed'].append('VOLATILITY_FILTER')
        print(f"[STEP 1] ✓ Volatility filter passed: {vol_reason}")
        
        # === STEP 2: STRUCTURE GATE (MANDATORY) ===
        print(f"[STEP 2] Structure Gate Check...")
        if not structure_allows_trade(df_m15, direction, symbol):
            result['reason'] = f"Structure Gate: No confirmed BOS in {direction} direction"
            result['filters_failed'].append('STRUCTURE_GATE')
            return result
        result['filters_passed'].append('STRUCTURE_GATE')
        print(f"[STEP 2] ✓ Structure Gate passed")
        
        # === STEP 3: COUNTER-TREND SAFETY CHECK ===
        print(f"[STEP 3] Counter-Trend Safety Check...")
        ct_check = check_counter_trend_rules(symbol, direction, current_price, df_h1, df_m15)
        if ct_check.get("is_counter_trend", False) and not ct_check.get("is_safe", True):
            result['reason'] = f"Counter-Trend Safety: {ct_check.get('reason', 'Unsafe counter-trend setup')}"
            result['filters_failed'].append('COUNTER_TREND_SAFETY')
            return result
        result['filters_passed'].append('COUNTER_TREND_SAFETY')
        print(f"[STEP 3] ✓ Counter-trend safety passed")
        
        # === STEP 4: MASTER TREND & MOMENTUM FILTER ===
        print(f"[STEP 4] Master Trend & Momentum Filter...")
        master_filter = apply_master_trend_momentum_filter(
            df_m15=df_m15, df_m30=df_m30, df_h1=df_h1, df_h4=df_h4,
            price=current_price, intended_direction=direction.upper(),
            allow_smc_in_range=allow_smc_override
        )
        
        if not master_filter['filter_pass']:
            result['reason'] = f"Master Filter: {master_filter['reason']}"
            result['filters_failed'].append('MASTER_TREND_FILTER')
            return result
        result['filters_passed'].append('MASTER_TREND_FILTER')
        print(f"[STEP 4] ✓ Master filter passed (Trend: {master_filter['trend_state']})")
        
        # === STEP 5: H1 HARD FILTER ===
        print(f"[STEP 5] H1 Hard Filter Check...")
        h1_hard_pass, h1_hard_reason = check_h1_structure_hard_filter(context or {})
        if not h1_hard_pass:
            result['reason'] = f"H1 Hard Filter: {h1_hard_reason}"
            result['filters_failed'].append('H1_HARD_FILTER')
            return result
        result['filters_passed'].append('H1_HARD_FILTER')
        print(f"[STEP 5] ✓ H1 hard filter passed")
        
        # === STEP 5.1: ADVANCED ENTRY FILTERS (NEW) ===
        print(f"[STEP 5.1] Running 5 advanced entry quality filters...")
        
        # Filter 1: Location Filter (Premium/Discount Zones)
        location_valid, location_reason, zone_type = filter_location_premium_zone(
            df_m15, direction, current_price, symbol
        )
        
        if not location_valid:
            result['reason'] = f"Location Filter: {location_reason}"
            result['filters_failed'].append('LOCATION_ZONE_FILTER')
            print(f"[STEP 5.1-A] ✗ Location filter BLOCKED: {location_reason}")
            return result
        result['filters_passed'].append('LOCATION_ZONE_FILTER')
        print(f"[STEP 5.1-A] ✓ Location filter passed: {location_reason}")
        
        # Filter 2: Big Move Chasing Prevention
        big_move_valid, big_move_reason, move_pips = filter_big_move_chasing(
            df_m15, symbol
        )
        
        if not big_move_valid:
            result['reason'] = f"Big Move Filter: {big_move_reason}"
            result['filters_failed'].append('BIG_MOVE_FILTER')
            print(f"[STEP 5.1-B] ✗ Big move filter BLOCKED: {big_move_reason}")
            return result
        result['filters_passed'].append('BIG_MOVE_FILTER')
        print(f"[STEP 5.1-B] ✓ Big move filter passed: {big_move_reason}")
        
        # Filter 3: Pullback Confirmation (Break → Pullback → Entry)
        pullback_valid, pullback_reason, pullback_depth = filter_pullback_confirmation(
            df_m15, direction
        )
        
        if not pullback_valid:
            result['reason'] = f"Pullback Filter: {pullback_reason}"
            result['filters_failed'].append('PULLBACK_FILTER')
            print(f"[STEP 5.1-C] ✗ Pullback filter BLOCKED: {pullback_reason}")
            return result
        result['filters_passed'].append('PULLBACK_FILTER')
        print(f"[STEP 5.1-C] ✓ Pullback filter passed: {pullback_reason}")
        
        # Filter 4: Liquidity Sweep Detection
        sweep_valid, sweep_reason, sweep_level = filter_liquidity_sweep_required(
            df_m15, symbol, direction
        )
        
        if not sweep_valid:
            result['reason'] = f"Liquidity Sweep Filter: {sweep_reason}"
            result['filters_failed'].append('LIQUIDITY_SWEEP_FILTER')
            print(f"[STEP 5.1-D] ✗ Liquidity sweep filter BLOCKED: {sweep_reason}")
            return result
        result['filters_passed'].append('LIQUIDITY_SWEEP_FILTER')
        print(f"[STEP 5.1-D] ✓ Liquidity sweep filter passed: {sweep_reason}")
        
        # === STEP 5.2: PRE-CALCULATE ENTRY PARAMETERS FOR RR VALIDATION ===
        print(f"[STEP 5.2] Pre-calculating entry parameters for RR validation...")
        
        try:
            atr = price_data.get('atr', 0.001)
            pip_size = 0.0001 if 'JPY' not in symbol.upper() else 0.01
            stop_pips = max(20, int(atr / pip_size))
            
            if direction.lower() == 'buy':
                temp_entry = current_price
                temp_sl = temp_entry - (stop_pips * pip_size)
                temp_tp = temp_entry + (stop_pips * pip_size * 2.5)  # Start with 2.5:1 for better RR
            else:
                temp_entry = current_price  
                temp_sl = temp_entry + (stop_pips * pip_size)
                temp_tp = temp_entry - (stop_pips * pip_size * 2.5)
        except:
            temp_entry = current_price
            temp_sl = current_price * 0.99 if direction.lower() == 'buy' else current_price * 1.01
            temp_tp = current_price * 1.02 if direction.lower() == 'buy' else current_price * 0.98
        
        # Filter 5: Minimum RR Validation
        rr_valid, rr_reason, rr_ratio, should_adjust = validate_minimum_rr(
            temp_entry, temp_sl, temp_tp, direction
        )
        
        if not rr_valid:
            if should_adjust:
                # Adjust TP higher to meet RR
                temp_tp = temp_entry + (2.0 * abs(temp_entry - temp_sl)) if direction.lower() == 'buy' else temp_entry - (2.0 * abs(temp_entry - temp_sl))
                rr_valid, rr_reason, rr_ratio, _ = validate_minimum_rr(temp_entry, temp_sl, temp_tp, direction)
                if rr_valid:
                    print(f"[STEP 5.2-E] ✓ Adjusted TP to meet RR minimum: {rr_reason}")
                    result['filters_passed'].append('RR_VALIDATION')
                else:
                    result['reason'] = f"RR Validation: {rr_reason} (unable to adjust TP)"
                    result['filters_failed'].append('RR_VALIDATION')
                    print(f"[STEP 5.2-E] ✗ RR validation BLOCKED: {rr_reason}")
                    return result
            else:
                result['reason'] = f"RR Validation: {rr_reason}"
                result['filters_failed'].append('RR_VALIDATION')
                print(f"[STEP 5.2-E] ✗ RR validation BLOCKED: {rr_reason}")
                return result
        
        result['filters_passed'].append('RR_VALIDATION')
        print(f"[STEP 5.2-E] ✓ RR validation passed: {rr_reason}")
        
        # === STEP 6: SMC/ICT ENTRY VALIDATION ===

        if enforce_smc:
            print(f"[STEP 6] SMC/ICT Entry Validation...")
            smc_result = execute_smc_entry_strict(
                symbol=symbol,
                price_data=price_data,
                direction=direction,
                entry_price=current_price,
                sl=0, tp=0, lot=0.01,  # Placeholder values for validation
                require_sweep=True,
                require_retrace=True, 
                require_micro=True
            )
            
            result['smc_details'] = smc_result[3]  # Details dict
            
            if not smc_result[0]:  # execute
                # Check if we can override with FVG confirmation
                fvg_override = False
                if allow_smc_override and price_data:
                    fvg_features = {
                        "fvg_detected": price_data.get("fvg_detected", True),
                        "bos": direction,
                        "liquidity_swept": price_data.get("liquidity_swept", True),
                        "htf_bias_aligned": price_data.get("htf_bias_aligned", True),
                        "fvg_quality": price_data.get("fvg_quality", True),
                        "entry_zone": price_data.get("entry_zone", {"low": current_price-0.001, "high": current_price+0.001}),
                        "price": current_price,
                    }
                    fvg_override = confirm_fvg_entry(**fvg_features)
                
                if not fvg_override:
                    result['reason'] = f"SMC Validation: {smc_result[1]}"
                    result['filters_failed'].append('SMC_VALIDATION')
                    return result
            
            result['confidence'] = smc_result[2] if smc_result[0] else 0.8  # FVG override confidence
            result['filters_passed'].append('SMC_VALIDATION')
            print(f"[STEP 6] ✓ SMC validation passed (Confidence: {result['confidence']:.2f})")
        
        # === STEP 7: RISK & SESSION FILTERS ===
        print(f"[STEP 7] Risk & Session Filters...")
        
        # Session filter
        session_ok = True
        try:
            session_ok = check_trading_session(symbol)
        except:
            session_ok = True
            
        if not session_ok:
            result['reason'] = "Session Filter: Trading not allowed in current session"
            result['filters_failed'].append('SESSION_FILTER')
            return result
            
        # Risk filter (basic check)
        risk_ok = True
        try:
            # Check account balance/risk
            if hasattr(mt5, 'account_info'):
                acct = mt5.account_info()
                if acct and acct.balance < 100:  # Minimum balance check
                    risk_ok = False
        except:
            pass
            
        if not risk_ok:
            result['reason'] = "Risk Filter: Insufficient account balance or risk limits exceeded"
            result['filters_failed'].append('RISK_FILTER')
            return result
            
        result['filters_passed'].extend(['SESSION_FILTER', 'RISK_FILTER'])
        print(f"[STEP 6] ✓ Risk & session filters passed")
        
        # === STEP 7: CALCULATE ENTRY PARAMETERS ===
        print(f"[STEP 7] Calculating entry parameters...")
        
        # Calculate SL/TP based on SMC levels or ATR
        try:
            # Use ATR for stop loss if available
            atr = price_data.get('atr', 0.001)
            pip_size = 0.0001 if 'JPY' not in symbol.upper() else 0.01
            stop_pips = max(20, int(atr / pip_size))
            
            if direction == 'buy':
                entry_price = current_price
                sl_price = entry_price - (stop_pips * pip_size)
                tp_price = entry_price + (stop_pips * pip_size * 2)  # 2:1 RR
            else:
                entry_price = current_price  
                sl_price = entry_price + (stop_pips * pip_size)
                tp_price = entry_price - (stop_pips * pip_size * 2)
                
            result['entry_price'] = entry_price
            result['sl_price'] = sl_price
            result['tp_price'] = tp_price
            
            # Calculate lot size
            result['lot_size'] = calculate_lot_size(
                balance=getattr(mt5.account_info() if mt5 else None, 'balance', 1000),
                equity=getattr(mt5.account_info() if mt5 else None, 'equity', 1000),
                symbol=symbol,
                stop_loss_pips=stop_pips
            )
            
        except Exception as e:
            print(f"[WARNING] Entry parameter calculation failed: {e}")
            # Use defaults
            result['entry_price'] = current_price
            result['sl_price'] = current_price * 0.99 if direction == 'buy' else current_price * 1.01
            result['tp_price'] = current_price * 1.02 if direction == 'buy' else current_price * 0.98
            result['lot_size'] = 0.01
        
        print(f"[STEP 7] ✓ Entry parameters calculated (Lot: {result['lot_size']}, SL: {result['sl_price']:.5f}, TP: {result['tp_price']:.5f})")
        
        # === STEP 8: EXECUTE TRADE ===
        print(f"[STEP 8] Executing trade...")
        
        try:
            trade_result = place_trade_with_smc_check(
                symbol=symbol,
                direction=direction,
                lot=result['lot_size'],
                sl=result['sl_price'],
                tp=result['tp_price'],
                price_data=price_data,
                enforce_smc=enforce_smc
            )
            
            if trade_result:
                result['execute'] = True
                result['reason'] = 'Trade executed successfully'
                result['trade_result'] = trade_result
                print(f"[STEP 8] ✓ Trade executed successfully")
            else:
                result['reason'] = 'Trade execution failed - likely blocked by final checks'
                result['filters_failed'].append('TRADE_EXECUTION')
                print(f"[STEP 8] ✗ Trade execution failed")
                
        except Exception as e:
            result['reason'] = f'Trade execution error: {str(e)}'
            result['filters_failed'].append('TRADE_EXECUTION_ERROR')
            print(f"[STEP 8] ✗ Trade execution error: {e}")
        
        return result
        
    except Exception as e:
        result['reason'] = f'Master orchestrator error: {str(e)}'
        result['filters_failed'].append('ORCHESTRATOR_ERROR')
        print(f"[MASTER ENTRY ERROR] {e}")
        return result


def enhanced_place_trade_with_filters(symbol, direction, price_data=None, context=None,
                                     enforce_smc=True, allow_smc_override=True):
    """
    ENHANCED TRADE PLACEMENT: Uses master entry orchestrator for complete validation.
    
    This is the new primary entry function that replaces direct place_trade() calls.
    """
    
    # Run complete validation pipeline
    validation_result = master_entry_orchestrator(
        symbol=symbol,
        direction=direction, 
        price_data=price_data or {},
        context=context,
        enforce_smc=enforce_smc,
        allow_smc_override=allow_smc_override
    )
    
    # Log results
    print(f"\n[TRADE VALIDATION COMPLETE] {symbol} {direction.upper()}")
    print(f"  Execute: {validation_result['execute']}")
    print(f"  Reason: {validation_result['reason']}")
    print(f"  Confidence: {validation_result['confidence']:.2f}")
    print(f"  Filters Passed: {', '.join(validation_result['filters_passed'])}")
    if validation_result['filters_failed']:
        print(f"  Filters Failed: {', '.join(validation_result['filters_failed'])}")
    
    return validation_result['trade_result'] if validation_result['execute'] else None

