# --- Utility: Always flatten features to avoid nested dicts ---
def flatten_features(features):
    flat = {}
    for k, v in features.items():
        if isinstance(v, dict):
            for subk, subv in v.items():
                flat[f"{k}_{subk}"] = subv
        else:
            flat[k] = v
    return flat    

