def save_bot_state_to_file():
    """
    Save current bot metrics to JSON file for dashboard to read.
    Called periodically during trading loop.
    """
    try:
        import MetaTrader5 as mt5
        
        if not mt5.initialize():
            print("[DASHBOARD] MT5 initialization failed for state save")
            return
        
        positions = mt5.positions_get() or []
        account = mt5.account_info()
        
        open_trades = []
        for pos in positions:
            open_trades.append({
                'id': pos.ticket,
                'symbol': pos.symbol,
                'type': 'BUY' if pos.type == 0 else 'SELL',
                'volume': pos.volume,
                'entry': pos.price_open,
                'current': pos.price_current,
                'pnl': pos.profit,
                'open_time': pos.time
            })
        
        daily_pnl = globals().get('daily_profit', 0.0) - globals().get('daily_loss', 0.0)
        
        state_data = {
            'running': True,
            'trading_paused': globals().get('TRADING_PAUSED', False),
            'last_update': datetime.now(timezone.utc).isoformat(),
            'total_trades': len(open_trades),
            'wins': len([t for t in open_trades if t['pnl'] > 0]),
            'losses': len([t for t in open_trades if t['pnl'] < 0]),
            'daily_pnl': daily_pnl,
            'account_balance': account.balance if account else 0.0,
            'equity': account.equity if account else 0.0,
            'open_trades': open_trades,
            'symbols': SYMBOLS,
            'active_symbols': list(SYMBOLS),
            'mt5_connected': True if account else False,
            'server': account.server if account else 'Unknown',
            'login': account.login if account else 0
        }
        
        with open(BOT_STATE_FILE, 'w') as f:
            json.dump(state_data, f, indent=2, default=str)
        # Also persist session trade counters so session limits survive restarts
        try:
            save_session_trades_to_file()
        except Exception:
            logging.debug("[DASHBOARD] Failed to persist session trades during state save.")
    except Exception as e:
        logging.debug(f"[DASHBOARD] Failed to save bot state: {e}")

