def get_symbol_base_lot(symbol):
    """
    Returns symbol-specific BASE lot size.
    
    These are the BASE lot sizes BEFORE risk scaling.
    Risk scaling (confidence-based) is applied ON TOP of these.
    
    Lot sizing logic:
    - XAUUSD (gold): 0.01 lot (lower pip value = smaller lot)
    - Forex (EUR, GBP, USD pairs): 0.05 lot (standard pip size = larger lot)
    
    Args:
        symbol (str): Trading symbol (e.g., 'EURUSD', 'XAUUSD.x')
    
    Returns:
        float: Base lot size for this symbol
    """
    try:
        base_symbol = symbol.upper().split('.')[0]  # Remove suffix (.m, .x, etc)
    except:
        base_symbol = symbol.upper()
    
    # Forex (standard) = 0.05 lot
    forex_symbols = {
        "EURUSD", "GBPUSD", "USDJPY", "AUDUSD", "NZDUSD", 
        "USDCAD", "USDCHF", "EURGBP", "EURJPY"
    }
    
    # Gold = 0.01 lot (higher pip value, lower lot)
    if base_symbol == "XAUUSD":
        return 0.01
    
    # Default to forex lot for any other major
    if base_symbol in forex_symbols:
        return 0.05
    
    # Default fallback: 0.02 (conservative)
    return 0.02

def calculate_risk_by_confidence(confidence):
    """
    Maps ML confidence score to risk percentage.
    
    Confidence Tiers:
    - 0.90+: A+ setup → 1.0% risk (full aggression)
    - 0.80-0.89: A setup → 0.7% risk (moderate aggression)  
    - 0.70-0.79: B setup → 0.5% risk (balanced)
    - Below 0.70: C/D setup → 0.3% risk (conservative)
    
    Returns: risk_pct (float, 0.003 to 0.010)
    """
    if confidence is None:
        return 0.02  # Default to 2.0% if no confidence (very aggressive sizing)
    
    confidence = float(confidence)
    
    if confidence >= 0.90:
        return 0.010    # 1.0% - Full throttle
    elif confidence >= 0.80:
        return 0.007    # 0.7% - High conviction
    elif confidence >= 0.70:
        return 0.02    # 2.0% - Very Aggressive
    else:
        return 0.003    # 0.3% - Conservative


def calculate_drawdown_lot_multiplier(max_loss_pct=0.0, max_loss_hard_pct=0.0):
    """
    Calculates lot size multiplier based on current drawdown.
    
    Anti-Martingale Strategy: Reduce lot size during drawdowns, increase during profits
    
    Drawdown Tiers:
    - 0% to -1%: 1.0x (normal)
    - -1% to -2%: 0.8x (mild drawdown)
    - -2% to -3%: 0.6x (moderate drawdown)
    - -3%+: 0.4x (severe drawdown)
    - Beyond hard limit: 0.0x (STOP TRADING)
    
    Args:
        max_loss_pct (float): Daily loss as % of account (negative value)
        max_loss_hard_pct (float): Hard limit as % (used for STOP condition)
    
    Returns:
        dict with 'multiplier' (0-1) and 'reason' (str)
    """
    try:
        # Convert to absolute values for easier comparison
        abs_loss_pct = abs(float(max_loss_pct)) if max_loss_pct else 0.0
        abs_hard_limit = abs(float(max_loss_hard_pct)) if max_loss_hard_pct else 0.03
        
        # ✅ STOP TRADING if hard limit breached
        if abs_loss_pct >= abs_hard_limit:
            return {
                'multiplier': 0.0,
                'reason': f'EMERGENCY STOP: Drawdown {abs_loss_pct:.2%} >= hard limit {abs_hard_limit:.2%}',
                'drawdown_pct': abs_loss_pct,
                'status': 'HALT'
            }
        
        # ✅ SEVERE DRAWDOWN: -3% or more
        if abs_loss_pct >= 0.03:
            return {
                'multiplier': 0.4,
                'reason': f'Severe drawdown {abs_loss_pct:.2%}: using 40% lot size (high risk)',
                'drawdown_pct': abs_loss_pct,
                'status': 'CAUTION'
            }
        
        # ✅ MODERATE DRAWDOWN: -2% to -3%
        if abs_loss_pct >= 0.02:
            return {
                'multiplier': 0.6,
                'reason': f'Moderate drawdown {abs_loss_pct:.2%}: using 60% lot size',
                'drawdown_pct': abs_loss_pct,
                'status': 'WARNING'
            }
        
        # ✅ MILD DRAWDOWN: -1% to -2%
        if abs_loss_pct >= 0.01:
            return {
                'multiplier': 0.8,
                'reason': f'Mild drawdown {abs_loss_pct:.2%}: using 80% lot size',
                'drawdown_pct': abs_loss_pct,
                'status': 'NORMAL'
            }
        
        # ✅ WINNING or BREAKEVEN: No drawdown
        if abs_loss_pct <= 0.0:
            return {
                'multiplier': 1.0,
                'reason': f'No drawdown ({max_loss_pct:.2%}): using 100% lot size',
                'drawdown_pct': abs_loss_pct,
                'status': 'NORMAL'
            }
        
        # Default (shouldn't reach here)
        return {
            'multiplier': 1.0,
            'reason': 'No drawdown data available',
            'drawdown_pct': 0.0,
            'status': 'NORMAL'
        }
        
    except Exception as e:
        print(f"[ERROR] calculate_drawdown_lot_multiplier: {e}")
        return {
            'multiplier': 1.0,
            'reason': f'Error calculating multiplier: {str(e)}',
            'drawdown_pct': 0.0,
            'status': 'ERROR'
        }


def calculate_lot_with_confidence_risk(balance, equity, symbol, sl_pips, confidence=None):
    """
    Calculate lot size using confidence-scaled risk instead of fixed risk %.
    
    Process:
    1. Get risk % from confidence level
    2. Calculate lot size based on risk % × account equity
    3. Clamp to symbol's max
    
    Returns: lot_size (float)
    """
    if balance <= 0 or not equity or equity <= 0:
        return 0.01
    
    # Step 1: Get confidence-based risk percentage
    risk_pct = calculate_risk_by_confidence(confidence)
    
    # Step 2: Calculate risk amount in account currency
    risk_amount = equity * risk_pct
    
    # Step 3: Get pip value for symbol
    pip_value = get_pip_value(symbol, lot=1.0)
    if pip_value <= 0:
        pip_value = 0.1  # Default fallback
    
    # Step 4: Calculate lot size = risk_amount / (sl_pips * pip_value)
    if sl_pips and sl_pips > 0:
        lot_size = risk_amount / (float(sl_pips) * pip_value)
    else:
        # Fallback: assume 50 pips SL if not provided
        lot_size = risk_amount / (50 * pip_value)
    
    # Step 5: Clamp to symbol limit
    try:
        base = symbol.upper().split('.')[0]
        sym_max = SYMBOL_MAX_LOT.get(base, MAX_LOT_SIZE)
    except Exception:
        sym_max = MAX_LOT_SIZE
    
    lot_size = min(max(lot_size, 0.01), float(sym_max))
    
    # Step 6: Round to valid step
    lot_size = round_lot_to_step(lot_size, symbol)
    
    return lot_size


