def get_confidence_tier(confidence):
    """
    Returns the confidence tier name for logging/analysis.
    
    Returns: tier_name: str ("A+", "A", "B", "C/D")
    """
    if confidence is None:
        return "UNKNOWN"
    confidence = float(confidence)
    if confidence >= 0.90:
        return "A+"
    elif confidence >= 0.80:
        return "A"
    elif confidence >= 0.70:
        return "B"
    else:
        return "C/D"


def log_trade_decision_with_confidence(symbol, direction, confidence, ml_model="unknown", atr=None, entry_reason=""):
    """
    Logs trading decision with confidence tier and risk information for analysis.
    
    Use this to track decision-making for:
    - Win rate per confidence tier
    - Model calibration
    - Risk scaling validation
    
    Example output:
    [TRADE DECISION] EURUSD BUY
      Confidence: 92.0% (A+) → Risk: 1.0%
      Model: HYDRA | Entry: FVG zone + BOS
      Expected Lot Size: 0.07 (for $5K account)
    """
    risk_pct = calculate_risk_by_confidence(confidence)
    tier = get_confidence_tier(confidence)
    
    log_msg = f"\n[TRADE DECISION] {symbol} {direction.upper()}"
    log_msg += f"\n  Confidence: {confidence*100:.1f}% ({tier}) → Risk: {risk_pct*100:.1f}%"
    log_msg += f"\n  Model: {ml_model} | Entry Reason: {entry_reason}"
    
    if atr is not None:
        log_msg += f"\n  ATR: {atr:.5f}"
    
    print(log_msg)
    
    # Could also write to file for analysis
    try:
        with open("confidence_decisions.log", "a") as f:
            f.write(f"{datetime.now().isoformat()} | {symbol} {direction} | Conf={confidence:.3f} | Tier={tier} | Risk={risk_pct:.1%}\n")
    except Exception:
        pass


def print_confidence_risk_matrix():
    """
    Print a nice matrix showing confidence → risk mapping for reference.
    
    Useful for understanding the tiers at a glance.
    """
    print("\n" + "="*70)
    print("CONFIDENCE-BASED RISK SCALING MATRIX")
    print("="*70)
    print(f"{'Confidence':<15} {'Tier':<8} {'Risk %':<12} {'Position Size (5K)':<20}")
    print("-"*70)
    
    test_confidences = [0.95, 0.87, 0.75, 0.65, 0.50]
    
    for conf in test_confidences:
        tier = get_confidence_tier(conf)
        risk = calculate_risk_by_confidence(conf)
        
        # Estimate position size for $5K account with 50 pip SL
        equity = 5000
        sl_pips = 50
        pip_value = 0.1  # Gold example
        lot = calculate_lot_with_confidence_risk(equity, equity, "XAUUSD", sl_pips, conf)
        
        print(f"{conf*100:>6.1f}%         {tier:<8} {risk*100:>6.1f}%       {lot:.3f} lot")
    
    print("="*70 + "\n")


