# DISPLACEMENT CANDLE BLOCK, BREAK-RECLAIM CONFIRMATION, AND ATR/VOLATILITY FILTERS
# ═══════════════════════════════════════════════════════════════════════════════

def detect_displacement_candle_block(df: pd.DataFrame, direction: str, atr_multiplier: float = 2.0, 
                                     volume_threshold: float = 1.2) -> dict:
    """
    Detects and blocks entries when price has moved too far from entry zones (displacement move).
    A displacement candle is a candle with:
    - Size > ATR * atr_multiplier
    - Volume > average volume * volume_threshold
    - Strong directional bias (little to no wick on entry side)
    
    Returns:
    {
        'is_displacement': bool - True if current candle is a displacement candle,
        'displacement_strength': float - 0.0 to 1.0, how strong the displacement is,
        'block_entry': bool - True if we should BLOCK entry (price has run too hard already),
        'reason': str - explanation of block reason
    }
    """
    if df is None or len(df) < 20:
        return {
            'is_displacement': False,
            'displacement_strength': 0.0,
            'block_entry': False,
            'reason': 'Insufficient data'
        }
    
    try:
        last = df.iloc[-1]
        prev = df.iloc[-2]
        
        # Calculate current candle metrics
        candle_size = abs(last['close'] - last['open'])
        candle_range = last['high'] - last['low']
        
        # Calculate ATR
        atr = compute_atr(df, period=14)
        
        # Calculate average volume
        avg_volume = df['volume'].tail(20).mean() if 'volume' in df.columns else 1000
        current_volume = last.get('volume', avg_volume)
        
        # === CHECK 1: Candle size relative to ATR ===
        if candle_size > atr * atr_multiplier:
            displacement_candle = True
            size_ratio = candle_size / atr
        else:
            displacement_candle = False
            size_ratio = candle_size / atr if atr > 0 else 0
        
        # === CHECK 2: Volume expansion ===
        if current_volume > avg_volume * volume_threshold:
            volume_expanded = True
            volume_ratio = current_volume / avg_volume if avg_volume > 0 else 1.0
        else:
            volume_expanded = False
            volume_ratio = current_volume / avg_volume if avg_volume > 0 else 1.0
        
        # === CHECK 3: Directional strength (minimal wick on entry side) ===
        is_bullish = last['close'] > last['open']
        is_bearish = last['close'] < last['open']
        
        if direction == "buy":
            # For bullish entries, we want a small upper wick
            upper_wick = last['high'] - max(last['close'], last['open'])
            lower_wick = min(last['close'], last['open']) - last['low']
            
            if candle_range > 0:
                wick_ratio = upper_wick / candle_range
                body_ratio = candle_size / candle_range
            else:
                wick_ratio = 0
                body_ratio = 0
            
            # Strong bullish move: large body, small upper wick, closed above open
            is_strong_directional = (is_bullish and body_ratio > 0.6 and wick_ratio < 0.3)
            
        else:  # direction == "sell"
            # For bearish entries, we want a small lower wick
            upper_wick = last['high'] - max(last['close'], last['open'])
            lower_wick = min(last['close'], last['open']) - last['low']
            
            if candle_range > 0:
                wick_ratio = lower_wick / candle_range
                body_ratio = candle_size / candle_range
            else:
                wick_ratio = 0
                body_ratio = 0
            
            # Strong bearish move: large body, small lower wick, closed below open
            is_strong_directional = (is_bearish and body_ratio > 0.6 and wick_ratio < 0.3)
        
        # === DISPLACEMENT DETECTION LOGIC ===
        is_displacement = displacement_candle and volume_expanded and is_strong_directional
        
        # Calculate displacement strength (0.0 to 1.0)
        strength_components = []
        if displacement_candle:
            strength_components.append(min(size_ratio / (atr_multiplier * 2), 1.0))  # Normalize to 1.0
        if volume_expanded:
            strength_components.append(min(volume_ratio / (volume_threshold * 2), 1.0))
        if is_strong_directional:
            strength_components.append(0.7)  # Strong directional bias adds 0.7
        
        displacement_strength = sum(strength_components) / len(strength_components) if strength_components else 0.0
        
        # === BLOCK ENTRY DECISION ===
        # Block entry if:
        # 1. Current candle is a strong displacement (strength > 0.7)
        # 2. OR price is extending far from recent support/resistance
        block_entry = False
        reason = "No displacement block"
        
        if displacement_strength > 0.7:
            block_entry = True
            reason = f"Strong displacement move detected (strength: {displacement_strength:.2f}). Price has run too hard — wait for pullback."
        elif displacement_strength > 0.5:
            block_entry = True
            reason = f"Moderate displacement move (strength: {displacement_strength:.2f}). Recommend waiting for reclamation."
        
        return {
            'is_displacement': is_displacement,
            'displacement_strength': float(displacement_strength),
            'block_entry': block_entry,
            'reason': reason
        }
        
    except Exception as e:
        print(f"[WARNING] Error in detect_displacement_candle_block: {e}")
        return {
            'is_displacement': False,
            'displacement_strength': 0.0,
            'block_entry': False,
            'reason': f'Error: {str(e)}'
        }


def detect_break_reclaim_confirmation(df: pd.DataFrame, direction: str, lookback: int = 20) -> dict:
    """
    Detects and confirms break-reclaim setups for stronger entries.
    A break-reclaim happens when:
    - Price breaks past a structural level (support/resistance)
    - Price then retraces back into the broken level (reclaims it)
    - Price breaks back out through the level
    
    This creates a confirmation that the level is being respected/tested before reversal.
    
    Returns:
    {
        'break_reclaim_detected': bool - True if break-reclaim pattern found,
        'break_price': float - Price where initial break occurred,
        'reclaim_zone_low': float - Lower bound of reclaim zone,
        'reclaim_zone_high': float - Upper bound of reclaim zone,
        'confirmation_strength': float - 0.0 to 1.0, how strong the confirmation is,
        'is_confirmed': bool - True if we're seeing confirmation (price backing breaking out again),
        'reason': str - explanation
    }
    """
    if df is None or len(df) < lookback + 3:
        return {
            'break_reclaim_detected': False,
            'break_price': None,
            'reclaim_zone_low': None,
            'reclaim_zone_high': None,
            'confirmation_strength': 0.0,
            'is_confirmed': False,
            'reason': 'Insufficient data'
        }
    
    try:
        recent = df.iloc[-lookback:].copy()
        last = df.iloc[-1]
        prev = df.iloc[-2]
        prev_prev = df.iloc[-3]
        
        # === STEP 1: Find recent swing high/low ===
        if direction == "buy":
            # Looking for break of swing low, then reclaim, then breakout
            swing_low_idx = recent['low'].idxmin()
            swing_low_price = recent.loc[swing_low_idx, 'low']
            
            # Check if we broke below swing low in the past
            broke_below = (recent['low'].iloc[:-3] < swing_low_price).any()
            
            if not broke_below:
                return {
                    'break_reclaim_detected': False,
                    'break_price': None,
                    'reclaim_zone_low': None,
                    'reclaim_zone_high': None,
                    'confirmation_strength': 0.0,
                    'is_confirmed': False,
                    'reason': 'No break detected below swing low'
                }
            
            break_price = swing_low_price
            
            # Find the break point in history
            break_bar_idx = None
            for i in range(len(recent) - 4, -1, -1):
                if recent.iloc[i]['low'] < break_price:
                    break_bar_idx = i
                    break
            
            if break_bar_idx is None:
                break_bar_idx = 0
            
            # After break, find if price reclaimed (came back above the level)
            post_break_bars = recent.iloc[break_bar_idx + 1:]
            reclaimed = (post_break_bars['close'] > break_price).any()
            
            if not reclaimed:
                return {
                    'break_reclaim_detected': False,
                    'break_price': break_price,
                    'reclaim_zone_low': None,
                    'reclaim_zone_high': None,
                    'confirmation_strength': 0.0,
                    'is_confirmed': False,
                    'reason': 'Break occurred but no reclaim detected'
                }
            
            # Current confirmation: is price now above the break level?
            is_confirmed = last['close'] > break_price
            
            # Calculate reclaim zone (area where price traded around the break level)
            reclaim_prices = post_break_bars[post_break_bars['close'] > break_price * 0.9975]['close']
            if len(reclaim_prices) > 0:
                reclaim_zone_low = break_price * 0.9995
                reclaim_zone_high = break_price * 1.0005 + (reclaim_prices.max() - break_price) * 0.5
            else:
                reclaim_zone_low = break_price
                reclaim_zone_high = break_price
            
        else:  # direction == "sell"
            # Looking for break of swing high, then reclaim, then breakout
            swing_high_idx = recent['high'].idxmax()
            swing_high_price = recent.loc[swing_high_idx, 'high']
            
            # Check if we broke above swing high in the past
            broke_above = (recent['high'].iloc[:-3] > swing_high_price).any()
            
            if not broke_above:
                return {
                    'break_reclaim_detected': False,
                    'break_price': None,
                    'reclaim_zone_low': None,
                    'reclaim_zone_high': None,
                    'confirmation_strength': 0.0,
                    'is_confirmed': False,
                    'reason': 'No break detected above swing high'
                }
            
            break_price = swing_high_price
            
            # Find the break point in history
            break_bar_idx = None
            for i in range(len(recent) - 4, -1, -1):
                if recent.iloc[i]['high'] > break_price:
                    break_bar_idx = i
                    break
            
            if break_bar_idx is None:
                break_bar_idx = 0
            
            # After break, find if price reclaimed (came back below the level)
            post_break_bars = recent.iloc[break_bar_idx + 1:]
            reclaimed = (post_break_bars['close'] < break_price).any()
            
            if not reclaimed:
                return {
                    'break_reclaim_detected': False,
                    'break_price': break_price,
                    'reclaim_zone_low': None,
                    'reclaim_zone_high': None,
                    'confirmation_strength': 0.0,
                    'is_confirmed': False,
                    'reason': 'Break occurred but no reclaim detected'
                }
            
            # Current confirmation: is price now below the break level?
            is_confirmed = last['close'] < break_price
            
            # Calculate reclaim zone (area where price traded around the break level)
            reclaim_prices = post_break_bars[post_break_bars['close'] < break_price * 1.0025]['close']
            if len(reclaim_prices) > 0:
                reclaim_zone_high = break_price * 1.0005
                reclaim_zone_low = break_price * 0.9995 - (break_price - reclaim_prices.min()) * 0.5
            else:
                reclaim_zone_low = break_price
                reclaim_zone_high = break_price
        
        # === STEP 2: Calculate confirmation strength ===
        # Strength increases if:
        # 1. Multiple reclaims detected
        # 2. Recent close is strongly above/below break level
        # 3. Volume is expanding
        
        confirmation_strength = 0.0
        if reclaimed:
            confirmation_strength = 0.5  # Base credit for reclaim
            
            if is_confirmed:
                confirmation_strength += 0.2  # Price is back above/below level
            
            # Check volume expansion
            avg_vol = df['volume'].tail(20).mean() if 'volume' in df.columns else 1000
            if last.get('volume', avg_vol) > avg_vol * 1.2:
                confirmation_strength += 0.15  # Volume expansion confirms
            
            # Check momentum
            if direction == "buy" and last['close'] > prev['close']:
                confirmation_strength += 0.1  # Bullish momentum
            elif direction == "sell" and last['close'] < prev['close']:
                confirmation_strength += 0.1  # Bearish momentum
        
        confirmation_strength = min(confirmation_strength, 1.0)
        
        return {
            'break_reclaim_detected': reclaimed,
            'break_price': float(break_price),
            'reclaim_zone_low': float(reclaim_zone_low),
            'reclaim_zone_high': float(reclaim_zone_high),
            'confirmation_strength': float(confirmation_strength),
            'is_confirmed': is_confirmed,
            'reason': f"Break-reclaim detected at {break_price:.2f}. Reclaim zone: {reclaim_zone_low:.2f}-{reclaim_zone_high:.2f}. Confirmed: {is_confirmed}"
        }
        
    except Exception as e:
        print(f"[WARNING] Error in detect_break_reclaim_confirmation: {e}")
        return {
            'break_reclaim_detected': False,
            'break_price': None,
            'reclaim_zone_low': None,
            'reclaim_zone_high': None,
            'confirmation_strength': 0.0,
            'is_confirmed': False,
            'reason': f'Error: {str(e)}'
        }


def validate_atr_volatility_filter(df: pd.DataFrame, direction: str, 
                                   min_atr_threshold: float = 0.3, 
                                   max_atr_threshold: float = 50.0,
                                   volatility_regime: str = 'auto') -> dict:
    """
    Validates entries based on ATR levels and volatility conditions.
    Prevents trading in both extremely low and extremely high volatility environments.
    
    Args:
        df: DataFrame with OHLCV data
        direction: 'buy' or 'sell'
        min_atr_threshold: Minimum ATR required for entry (prevents trading when market is dead)
        max_atr_threshold: Maximum ATR allowed for entry (prevents trading when volatility is extreme)
        volatility_regime: 'normal', 'low', or 'high' - influences thresholds
    
    Returns:
    {
        'atr_value': float - Current ATR value,
        'is_valid': bool - True if volatility is acceptable for trading,
        'volatility_regime': str - Current detected regime,
        'atr_ratio': float - ATR relative to average (>1 = expansion, <1 = contraction),
        'block_reason': str - Reason for blocking (if applicable),
        'confidence_boost': float - Confidence multiplier based on volatility (0.5 to 1.5)
    }
    """
    if df is None or len(df) < 30:
        return {
            'atr_value': 0.0,
            'is_valid': True,  # Default to valid on insufficient data
            'volatility_regime': 'unknown',
            'atr_ratio': 1.0,
            'block_reason': 'Insufficient data',
            'confidence_boost': 1.0
        }
    
    try:
        # Calculate current and average ATR
        current_atr = compute_atr(df, period=14)
        historical_atr = compute_atr(df.iloc[:-1], period=14) if len(df) > 14 else current_atr
        
        # Calculate 20-bar and 50-bar ATR for volatility regime detection
        atr_20 = compute_atr(df.tail(20), period=14) if len(df) >= 20 else current_atr
        atr_50 = compute_atr(df.tail(50), period=14) if len(df) >= 50 else current_atr
        
        # ATR ratio: current vs historical
        atr_ratio = current_atr / historical_atr if historical_atr > 0 else 1.0
        
        # === VOLATILITY REGIME DETECTION ===
        if volatility_regime == 'auto':
            if atr_ratio < 0.7:
                detected_regime = 'low'
            elif atr_ratio > 1.3:
                detected_regime = 'high'
            else:
                detected_regime = 'normal'
        else:
            detected_regime = volatility_regime

        # === VALIDATE AGAINST REGIME RULES ===
        # Strict blocking rules per user spec:
        # - Block if ATR ratio < 0.7 (dead/low volatility)
        # - Block if ATR ratio > 1.3 (extreme volatility spike)
        is_valid = True
        block_reason = ""
        confidence_boost = 1.0

        if detected_regime == 'low':
            is_valid = False
            block_reason = f"Market too quiet (ATR ratio: {atr_ratio:.3f} < 0.70). Avoid low volatility entries."
            confidence_boost = 0.7
        elif detected_regime == 'high':
            is_valid = False
            block_reason = f"Volatility too extreme (ATR ratio: {atr_ratio:.3f} > 1.30). Risk of spike moves."
            confidence_boost = 1.1
        else:
            # normal regime: apply min/max absolute ATR thresholds as additional guards
            if current_atr < min_atr_threshold:
                is_valid = False
                block_reason = f"ATR too low (ATR: {current_atr:.4f} < min threshold: {min_atr_threshold:.4f})."
            elif current_atr > max_atr_threshold:
                is_valid = False
                block_reason = f"ATR too high (ATR: {current_atr:.4f} > max threshold: {max_atr_threshold:.4f})."
        
        # === VOLATILITY EXPANSION BONUS ===
        if atr_ratio > 1.2:
            # Volatility is expanding - this is good for directional moves
            confidence_boost *= 1.2
        elif atr_ratio < 0.6:
            # Volatility is contracting significantly - increases false signal risk
            confidence_boost *= 0.8
        
        # Clamp confidence boost to reasonable range
        confidence_boost = max(0.5, min(confidence_boost, 1.5))
        
        return {
            'atr_value': float(current_atr),
            'is_valid': is_valid,
            'volatility_regime': detected_regime,
            'atr_ratio': float(atr_ratio),
            'block_reason': block_reason,
            'confidence_boost': float(confidence_boost)
        }
        
    except Exception as e:
        print(f"[WARNING] Error in validate_atr_volatility_filter: {e}")
        return {
            'atr_value': 0.0,
            'is_valid': True,  # Default to valid on error
            'volatility_regime': 'unknown',
            'atr_ratio': 1.0,
            'block_reason': f'Error: {str(e)}',
            'confidence_boost': 1.0
        }

