# SMC ENTRY MODEL INTEGRATION
# ═══════════════════════════════════════════════════════════════════════════════

def check_and_execute_entry_models(df, symbol, direction):
    """
    Check all SMC entry models for the given symbol and direction.
    If any model triggers, execute the trade logic.
    """
    # Preliminary: validate volatility regime first
    vol_check = validate_atr_volatility_filter(df, direction, min_atr_threshold=0.3, max_atr_threshold=50.0, volatility_regime='auto')
    if not vol_check['is_valid']:
        print(f"[FILTER] {symbol} {direction.upper()} | Volatility check FAILED: {vol_check['block_reason']}")
        return False

    entry_models = [
        ("liquidity_sweep_mss_fvg", entry_liquidity_sweep_mss_fvg),
        ("liquidity_sweep_bpr", entry_liquidity_sweep_bpr),
        ("smt_mss_ifvg", entry_smt_mss_ifvg),
        ("smt_mss_bb", entry_smt_mss_bb),
        ("liquidity_sweep_mss_bb_fvg", entry_liquidity_sweep_mss_bb_fvg),
    ]

    for model_name, model_func in entry_models:
        should_enter, reason, confidence, details = model_func(df, direction)
        if should_enter and confidence >= CONFIDENCE_THRESHOLD:
            # Guard: avoid opening opposite entries for the same canonical symbol
            if has_open_opposite_position(symbol, direction):
                print(f"[GUARD] Skipping {symbol} {direction.upper()} — opposite position already open")
                return False

            # === MANDATORY: Candle Confirmation Check ===
            candle_confirmed, candle_reason = is_entry_candle_valid({"symbol": symbol, "direction": direction, "df": df})
            if not candle_confirmed:
                print(f"[ENTRY BLOCKED] {symbol} {direction.upper()} | ❌ CANDLE CONFIRMATION FAILED - {candle_reason}")
                continue
            else:
                print(f"[ENTRY VALIDATED] {symbol} {direction.upper()} | ✓ Candle confirmation PASSED")

            # === MANDATORY: Location Confirmation Check ===
            current_price = df['close'].iloc[-1] if len(df) > 0 else 0
            location_valid = True
            location_check = details.get('location_ok')
            if location_check is not None and location_check is False:
                location_valid = False
            if not location_valid:
                print(f"[ENTRY BLOCKED] {symbol} {direction.upper()} | ❌ LOCATION CONFIRMATION FAILED - Price not in valid entry location")
                continue
            else:
                print(f"[ENTRY VALIDATED] {symbol} {direction.upper()} | ✓ Location confirmation PASSED")

            # Post-model: displacement check
            disp = detect_displacement_candle_block(df, direction, atr_multiplier=2.0, volume_threshold=1.2)
            if disp['block_entry']:
                print(f"[DISPLACEMENT_BLOCK] {symbol} {direction.upper()} | BLOCKED: {disp['reason']}")
                continue

            # Break-reclaim confirmation
            br = detect_break_reclaim_confirmation(df, direction, lookback=20)
            adjusted_conf = confidence
            # Boost if confirmed
            if br.get('is_confirmed'):
                adjusted_conf *= (1.0 + br.get('confirmation_strength', 0.0) * 0.2)

            # Apply volatility confidence boost
            adjusted_conf *= vol_check.get('confidence_boost', 1.0)

            # Penalize if displacement detected but not blocking
            if disp.get('is_displacement'):
                adjusted_conf *= 0.9

            adjusted_conf = min(adjusted_conf, 1.0)

            print(f"[ENTRY] {symbol} {direction.upper()} | Model: {model_name} | Reason: {reason}")
            print(f"        Base Confidence: {confidence:.2f} | Adjusted Confidence: {adjusted_conf:.2f}")
            print(f"        Details: {details}")
            print(f"        Validations: Volatility={vol_check['volatility_regime']}, Displacement={disp['is_displacement']}, BreakReclaim={br['break_reclaim_detected']}")

            # Place trade here (or call your trade execution function)
            # execute_trade(symbol, direction, adjusted_conf, details)
            return True

    return False

