def detect_mss(df, direction, lookback=20):
    """
    Detect Market Structure Shift (MSS).
    Returns: (mss: bool, mss_type: str, mss_strength: float)
    """
    if len(df) < lookback + 3:
        return False, None, 0.0

    highs = df['high'].iloc[-lookback:]
    lows = df['low'].iloc[-lookback:]
    closes = df['close'].iloc[-lookback:]
    mss = False
    mss_type = None
    mss_strength = 0.0

    if direction == "buy":
        # Look for break of previous swing high after a lower low
        swing_high = highs.max()
        swing_high_idx = highs.idxmax()
        # Confirm price broke above swing high recently
        if df['close'].iloc[-1] > swing_high and swing_high_idx < len(df) - 2:
            mss = True
            mss_type = "BULLISH_MSS"
            mss_strength = 0.8
    elif direction == "sell":
        # Look for break of previous swing low after a higher high
        swing_low = lows.min()
        swing_low_idx = lows.idxmin()
        if df['close'].iloc[-1] < swing_low and swing_low_idx < len(df) - 2:
            mss = True
            mss_type = "BEARISH_MSS"
            mss_strength = 0.8

    return mss, mss_type, mss_strength

def detect_bpr(df, direction, lookback=20):
    """
    Detect Breaker Block/BPR (Buy-side or Sell-side).
    Returns: (bpr: bool, bpr_level: float, bpr_strength: float)
    """
    if len(df) < lookback + 3:
        return False, None, 0.0

    bpr = False
    bpr_level = None
    bpr_strength = 0.0

    if direction == "buy":
        # Look for a down candle (breaker) followed by a strong up move
        for i in range(-lookback, -2):
            if df['close'].iloc[i] < df['open'].iloc[i]:
                # Next bar closes above high of breaker
                if df['close'].iloc[i+1] > df['high'].iloc[i]:
                    bpr = True
                    bpr_level = df['high'].iloc[i]
                    bpr_strength = 0.75
                    break
    elif direction == "sell":
        for i in range(-lookback, -2):
            if df['close'].iloc[i] > df['open'].iloc[i]:
                if df['close'].iloc[i+1] < df['low'].iloc[i]:
                    bpr = True
                    bpr_level = df['low'].iloc[i]
                    bpr_strength = 0.75
                    break

    return bpr, bpr_level, bpr_strength

def detect_smt(df, direction):
    """
    Detect SMT (Smart Money Technique / divergence-like structure).

    Returns something like: (has_smt, smt_type, smt_strength)
    """
    # Defensive guard: df may be None or too short
    if df is None:
        return False, None, 0.0

    # If lookback is defined later in the function, make sure it's set before we use it
    try:
        lookback  # noqa: F821
    except NameError:
        lookback = 20  # sensible default, adjust if your logic uses a specific value

    if len(df) < lookback + 3:
        return False, None, 0.0

    smt = False
    smt_type = None
    smt_strength = 0.0

    # Simulate: if last high is lower than previous, but last close is higher, call it a divergence
    if direction == "buy":
        if df['high'].iloc[-1] < df['high'].iloc[-2] and df['close'].iloc[-1] > df['close'].iloc[-2]:
            smt = True
            smt_type = "BULLISH_SMT"
            smt_strength = threshold
    elif direction == "sell":
        if df['low'].iloc[-1] > df['low'].iloc[-2] and df['close'].iloc[-1] < df['close'].iloc[-2]:
            smt = True
            smt_type = "BEARISH_SMT"
            smt_strength = threshold

    return smt, smt_type, smt_strength

def detect_ifvg(df, direction, lookback=15):
    """
    Detect Internal Fair Value Gap (IFVG).
    Returns: (ifvg: bool, ifvg_low: float, ifvg_high: float, ifvg_confirmed: bool)
    """
    if len(df) < lookback + 3:
        return False, None, None, False

    for i in range(-lookback, -2):
        # IFVG: gap between previous bar's high/low and next bar's low/high
        if direction == "buy":
            if df['low'].iloc[i+1] > df['high'].iloc[i]:
                return True, df['high'].iloc[i], df['low'].iloc[i+1], True
        elif direction == "sell":
            if df['high'].iloc[i+1] < df['low'].iloc[i]:
                return True, df['low'].iloc[i], df['high'].iloc[i+1], True

    return False, None, None, False

def detect_inverse_fvg_ict(df, min_gap=0.0001, lookback=20):
    """
    TRUE ICT INVERSE FVG DETECTION:
    1. Identifies liquidity sweep (stop hunt)
    2. Detects FVG created DURING the sweep displacement
    3. Confirms price reversal (BOS opposite to sweep)
    4. Validates price is filling FVG from OPPOSITE side (inverse fill)
    
    Returns:
        dict: {
            'detected': bool,
            'direction': 'buy'/'sell',  # Entry direction after inverse fill
            'fvg_zone_low': float,
            'fvg_zone_high': float,
            'sweep_side': 'high'/'low',
            'reversal_confirmed': bool,
            'inverse_fill_active': bool,
            'confidence': float
        }
    """
    if df is None or len(df) < lookback:
        return {'detected': False}
    
    try:
        # Step 1: Detect liquidity sweep in recent bars
        sweep_detected = False
        sweep_side = None
        sweep_idx = None
        
        # Look for sweep: price violates swing high/low then reverses
        for i in range(-lookback, -5):
            window = df.iloc[i-10:i+1] if i >= -lookback+10 else df.iloc[:i+1]
            if len(window) < 5:
                continue
            
            swing_high = window['high'].iloc[:-1].max()
            swing_low = window['low'].iloc[:-1].min()
            
            current_high = df['high'].iloc[i]
            current_low = df['low'].iloc[i]
            next_close = df['close'].iloc[i+1] if i < -1 else df['close'].iloc[-1]
            
            # High sweep: breaks high then closes below
            if current_high > swing_high and next_close < swing_high:
                sweep_detected = True
                sweep_side = 'high'
                sweep_idx = i
                break
            
            # Low sweep: breaks low then closes above  
            if current_low < swing_low and next_close > swing_low:
                sweep_detected = True
                sweep_side = 'low'
                sweep_idx = i
                break
        
        if not sweep_detected:
            return {'detected': False, 'reason': 'No liquidity sweep detected'}
        
        # Step 2: Detect FVG created DURING or RIGHT AFTER sweep
        fvg_detected = False
        fvg_low = None
        fvg_high = None
        fvg_idx = None
        
        # Check 3-5 bars after sweep for FVG formation
        for i in range(sweep_idx, min(sweep_idx + 5, -3)):
            c1 = df.iloc[i]
            c2 = df.iloc[i+1] 
            c3 = df.iloc[i+2]
            
            # Bullish FVG (for sell sweep reversal)
            if sweep_side == 'low' and c1['high'] < c3['low']:
                gap_size = c3['low'] - c1['high']
                if gap_size >= min_gap:
                    fvg_detected = True
                    fvg_low = c1['high']
                    fvg_high = c3['low']
                    fvg_idx = i
                    break
            
            # Bearish FVG (for buy sweep reversal)
            if sweep_side == 'high' and c1['low'] > c3['high']:
                gap_size = c1['low'] - c3['high']
                if gap_size >= min_gap:
                    fvg_detected = True
                    fvg_low = c3['high']
                    fvg_high = c1['low']
                    fvg_idx = i
                    break
        
        if not fvg_detected:
            return {'detected': False, 'reason': 'No FVG created after sweep'}
        
        # Step 3: Confirm reversal (BOS opposite to sweep)
        reversal_confirmed = False
        if fvg_idx is not None and fvg_idx < -3:
            post_fvg_bars = df.iloc[fvg_idx+3:]
            if len(post_fvg_bars) >= 2:
                # For sell sweep (low), need bullish BOS
                if sweep_side == 'low':
                    recent_high = df.iloc[fvg_idx-5:fvg_idx]['high'].max()
                    if any(post_fvg_bars['close'] > recent_high):
                        reversal_confirmed = True
                
                # For buy sweep (high), need bearish BOS
                elif sweep_side == 'high':
                    recent_low = df.iloc[fvg_idx-5:fvg_idx]['low'].min()
                    if any(post_fvg_bars['close'] < recent_low):
                        reversal_confirmed = True
        
        # Step 4: Check if price is currently filling FVG from INVERSE side
        current_price = df['close'].iloc[-1]
        inverse_fill_active = False
        
        # For sell sweep → bullish FVG → price should fill from below (inverse)
        if sweep_side == 'low' and fvg_low <= current_price <= fvg_high:
            # Check if price entered from below (inverse fill)
            prev_close = df['close'].iloc[-2]
            if prev_close < fvg_low:
                inverse_fill_active = True
        
        # For buy sweep → bearish FVG → price should fill from above (inverse)
        elif sweep_side == 'high' and fvg_low <= current_price <= fvg_high:
            # Check if price entered from above (inverse fill)
            prev_close = df['close'].iloc[-2]
            if prev_close > fvg_high:
                inverse_fill_active = True
        
        # Determine entry direction (opposite of sweep)
        entry_direction = 'buy' if sweep_side == 'low' else 'sell'
        
        # Calculate confidence based on components
        confidence = 0.0
        if sweep_detected:
            confidence += 0.30
        if fvg_detected:
            confidence += 0.25
        if reversal_confirmed:
            confidence += 0.25
        if inverse_fill_active:
            confidence += 0.20
        
        return {
            'detected': True,
            'direction': entry_direction,
            'fvg_zone_low': fvg_low,
            'fvg_zone_high': fvg_high,
            'sweep_side': sweep_side,
            'reversal_confirmed': reversal_confirmed,
            'inverse_fill_active': inverse_fill_active,
            'confidence': round(confidence, 2),
            'gap_size': fvg_high - fvg_low if fvg_high and fvg_low else 0,
            'reason': f'Inverse FVG: {sweep_side} sweep → FVG → {entry_direction} reversal'
        }
    
    except Exception as e:
        return {'detected': False, 'reason': f'Error: {str(e)}'}

def detect_bollinger_band_touch(df, direction, window=20, num_std=2):
    """
    Detect touch of Bollinger Band (BB).
    Returns: (bb_touch: bool, bb_side: str, bb_strength: float)
    """
    if len(df) < window + 2:
        return False, None, 0.0

    import numpy as np
    closes = df['close'].iloc[-window:]
    ma = closes.mean()
    std = closes.std()
    upper = ma + num_std * std
    lower = ma - num_std * std

    last_close = df['close'].iloc[-1]
    bb_touch = False
    bb_side = None
    bb_strength = 0.0

    if direction == "buy" and last_close <= lower:
        bb_touch = True
        bb_side = "lower"
        bb_strength = 0.8
    elif direction == "sell" and last_close >= upper:
        bb_touch = True
        bb_side = "upper"
        bb_strength = 0.8

    return bb_touch, bb_side, bb_strength

