def validate_signal_alignment(df, direction, bos_confirmed, choch_confirmed, liquidity_swept, fvg_detected):
    """
    CRITICAL VALIDATION FUNCTION: Ensures all trading signals are aligned and not conflicting.
    
    Prevents:
    - Conflicting BOS and CHOCH signals
    - Premature entries before liquidity swept
    - FVG entries without proper structure confirmation
    - False signals from single indicators
    
    Returns: (is_valid, confidence_score, blocking_reasons)
    """
    blocking_reasons = []
    confidence = 1.0
    
    if len(df) < 3:
        return False, 0.0, ["Insufficient data"]
    
    last = df.iloc[-1]
    prev = df.iloc[-2]
    
    # === CONFLICT CHECK 1: BOS vs CHOCH Alignment ===
    if bos_confirmed and choch_confirmed:
        # Both detected - should be in SAME direction
        if direction == "buy" and last['close'] < prev['close']:
            blocking_reasons.append("BOS bullish but CHOCH bearish - CONFLICT")
            return False, 0.0, blocking_reasons
        elif direction == "sell" and last['close'] > prev['close']:
            blocking_reasons.append("BOS bearish but CHOCH bullish - CONFLICT")
            return False, 0.0, blocking_reasons
        confidence -= 0.05  # Slight penalty for dual signal (might be over-signal)
    
    # === CONFLICT CHECK 2: BOS without Structure Break ===
    if bos_confirmed:
        # Verify actual break with body (not just wick)
        body = abs(last['close'] - last['open'])
        range_size = last['high'] - last['low']
        
        if range_size > 0:
            body_ratio = body / range_size
            if body_ratio < 0.5:
                blocking_reasons.append("BOS has weak body/range ratio - likely wick false break")
                return False, 0.0, blocking_reasons
        
        # Check momentum direction aligns
        if direction == "buy" and last['close'] < last['open']:
            blocking_reasons.append("BOS bullish but candle closing down - no momentum")
            return False, 0.0, blocking_reasons
        elif direction == "sell" and last['close'] > last['open']:
            blocking_reasons.append("BOS bearish but candle closing up - no momentum")
            return False, 0.0, blocking_reasons
        
        confidence += 0.2  # BOS is strong signal
    
    # === CONFLICT CHECK 3: Liquidity Sweep Requirements ===
    if liquidity_swept:
        # Sweep is valid only if followed by proper structure
        if not bos_confirmed and not choch_confirmed:
            blocking_reasons.append("Liquidity swept but no BOS/CHOCH follow-through")
            confidence -= 0.15
        else:
            confidence += 0.15  # Sweep + structure = strong setup
    else:
        # No sweep - typically need stronger structure confirmation
        if not bos_confirmed and not choch_confirmed:
            blocking_reasons.append("No liquidity sweep AND no BOS/CHOCH - weak setup")
            confidence -= 0.25
    
    # === CONFLICT CHECK 4: FVG Alignment ===
    if fvg_detected:
        # FVG detected - verify it's in correct direction
        fvg_info = detect_fvg(df)
        if fvg_info:
            if direction == "buy" and fvg_info['direction'] != "bullish":
                blocking_reasons.append("FVG direction (bearish) doesn't match signal (bullish)")
                return False, 0.0, blocking_reasons
            elif direction == "sell" and fvg_info['direction'] != "bearish":
                blocking_reasons.append("FVG direction (bullish) doesn't match signal (bearish)")
                return False, 0.0, blocking_reasons
            
            # Check FVG quality (confidence score)
            if fvg_info.get('confidence', 0) < 0.6:
                blocking_reasons.append(f"FVG confidence low ({fvg_info['confidence']:.2f})")
                confidence -= 0.1
            else:
                confidence += 0.2
    
    # === CONFLICT CHECK 5: Volume & Momentum Confirmation ===
    if len(df) > 1:
        has_volume = 'tick_volume' in df.columns or 'volume' in df.columns
        if has_volume:
            vol_col = 'tick_volume' if 'tick_volume' in df.columns else 'volume'
            avg_vol = df[vol_col].iloc[-20:-1].mean()
            last_vol = df[vol_col].iloc[-1]
            
            # Without volume spike, need stronger structure
            if last_vol < avg_vol * 0.8 and not (bos_confirmed and choch_confirmed):
                blocking_reasons.append("Low volume without strong BOS/CHOCH")
                confidence -= 0.1
        
        # Momentum: price moving in signal direction
        if direction == "buy" and last['close'] <= last['open']:
            blocking_reasons.append("Signal bullish but candle bearish")
            confidence -= 0.15
        elif direction == "sell" and last['close'] >= last['open']:
            blocking_reasons.append("Signal bearish but candle bullish")
            confidence -= 0.15
    
    # === FINAL DECISION ===
    is_valid = len(blocking_reasons) == 0 and confidence > 0.5
    confidence = max(0.0, min(confidence, 1.0))  # Clamp 0-1
    
    return is_valid, confidence, blocking_reasons

def entry_liquidity_sweep_mss_fvg(df, direction, **kwargs):
    """
    Entry model: Liquidity Sweep + MSS + FVG
    """
    details = {}
    swept, sweep_level, sweep_idx = require_previous_extreme_sweep(df, direction)
    details['liquidity_sweep'] = swept
    if not swept:
        return False, "No liquidity sweep", 0.0, details

    mss, mss_type, mss_strength = detect_mss(df, direction)
    details['mss'] = mss
    details['mss_type'] = mss_type
    details['mss_strength'] = mss_strength
    if not mss:
        return False, "No MSS", 0.0, details

    in_fvg, fvg_low, fvg_high, fvg_confirmed = detect_fvg_retrace(df, direction)
    details['fvg'] = fvg_confirmed
    details['fvg_low'] = fvg_low
    details['fvg_high'] = fvg_high
    if not fvg_confirmed:
        return False, "No FVG retrace", 0.0, details

    reason = "Liquidity sweep + MSS + FVG confirmed"
    confidence = 0.85
    return True, reason, confidence, details

