def get_model_sl_tp_multipliers(model_name):
    """Get SL/TP ATR multipliers for the winning model"""
    if model_name in MODEL_PROFILES:
        profile = MODEL_PROFILES[model_name]
        return profile['sl_atr'], profile['tp_atr']
    else:
        # Fallback to global defaults
        return SL_ATR_MULTIPLIER, TP_ATR_MULTIPLIER


def calculate_fib_extensions(entry_price, swing_low, swing_high, direction='buy'):
    """Calculate Fibonacci extension levels for TP targets (including 261.8%)"""
    range_size = swing_high - swing_low
    
    if direction == 'buy':
        # Extensions above swing_high
        fib_127 = swing_high + (range_size * 0.272)   # 127.2%
        fib_161 = swing_high + (range_size * 0.618)   # 161.8%
        fib_200 = swing_high + range_size             # 200%
        fib_261 = swing_high + (range_size * 1.618)   # 261.8%
    else:
        # Extensions below swing_low
        fib_127 = swing_low - (range_size * 0.272)
        fib_161 = swing_low - (range_size * 0.618)
        fib_200 = swing_low - range_size
        fib_261 = swing_low - (range_size * 1.618)
    
    return {
        '127': fib_127,
        '161': fib_161,
        '200': fib_200,
        '261': fib_261
    }


def find_structure_sl(df, idx, direction, atr, lookback=80):
    """
    ✅ FIXED: Find structure level for SL with PROPER buffer
    
    OLD: Used only 0.5 * ATR buffer → Too tight, stops hit by wicks
    NEW: Uses 1.5-2.0 * ATR buffer → Gives room for normal market noise
    """
    if idx < lookback or df is None or len(df) <= idx:
        return None
    
    recent = df.iloc[max(0, idx-lookback):idx].copy()
    if len(recent) == 0:
        return None
    
    if direction == 'buy' or direction.lower() == 'b':
        # Find lowest low in recent period (order block level)
        structure_level = recent['low'].min()
        # FIXED: Increased buffer from 0.5 * atr to 2.0 * atr
        # This prevents wicks from hitting SL immediately
        # Example: If ATR=100, SL is now 200 pips below lowest low instead of 50
        sl = structure_level - (2.0 * atr)
    else:
        # Find highest high for short
        structure_level = recent['high'].max()
        # FIXED: Same buffer increase for shorts
        sl = structure_level + (2.0 * atr)
    
    return sl


def find_opposing_liquidity(df, idx, direction, lookback=30):
    """Find opposing liquidity level - use recent swing extremes (30 bars)"""
    if idx < lookback or df is None or len(df) <= idx:
        return None
    
    recent = df.iloc[max(0, idx-lookback):idx].copy()
    if len(recent) == 0:
        return None
    
    if direction == 'buy' or direction.lower() == 'b':
        # For buys, opposing liquidity is recent highs
        return recent['high'].max()
    else:
        # For shorts, opposing liquidity is recent lows
        return recent['low'].min()


def get_best_tp_with_rr(entry_price, tp_candidates, direction, min_rr=2.0):
    """Select best TP from candidates that meets minimum R:R requirement"""
    if not tp_candidates or len(tp_candidates) == 0:
        return None
    
    best_tp = None
    best_rr = 0
    
    for tp in tp_candidates:
        if tp is None:
            continue
        
        if direction == 'buy' or direction.lower() == 'b':
            if tp <= entry_price:
                continue  # TP must be above entry
            distance = tp - entry_price
        else:
            if tp >= entry_price:
                continue  # TP must be below entry
            distance = entry_price - tp
        
        if distance > best_rr:
            best_rr = distance
            best_tp = tp
    
    return best_tp


def calculate_smc_fib_sl_tp_with_sweep_override(entry_price, df, idx, direction, atr, model_name='HYDRA', sweep_sl_override=None, features=None):
    """
    ⭐ ENHANCED SL/TP CALCULATION: Prioritizes sweep-based SL
    
    CHANGES EVERYTHING:
    - If sweep_sl_override provided (from sweep+retest entry) → USE IT (tighter SL, better RR)
    - Otherwise → Use traditional SMC Fib approach
    
    Args:
        entry_price: Current entry price
        df: Price dataframe
        idx: Current bar index
        direction: 'buy' or 'sell'
        atr: ATR value
        model_name: Model for fallback multipliers
        sweep_sl_override: OPTIONAL - Sweep-based SL from sweep+retest detection
        features: OPTIONAL - Features dict that might contain 'sweep_sl_override'
    
    Returns:
        (sl_price, tp_price, rr_ratio)
    """
    # Check if sweep SL is provided (from sweep+retest entry)
    sweep_sl = sweep_sl_override
    if sweep_sl is None and features:
        sweep_sl = features.get('sweep_sl_override')
    
    if sweep_sl is not None:
        # ✅ USE SWEEP-BASED SL (tighter, better RR)
        print(f"[⭐ SWEEP SL] Using sweep-based SL: {sweep_sl:.5f} (overrides structure/ATR)")
        sl = sweep_sl
        
        # Calculate R (risk distance)
        if direction == 'buy' or direction.lower() == 'b':
            risk = entry_price - sl
        else:
            risk = sl - entry_price
        
        if risk <= 0:
            # Fallback to structure if sweep SL is invalid
            return calculate_smc_fib_sl_tp(entry_price, df, idx, direction, atr, model_name)
        
        # Find TP using Fib or liquidity (same as normal, but with tighter SL)
        lookback_period = 100
        if idx >= lookback_period and df is not None and len(df) > idx:
            recent = df.iloc[max(0, idx-lookback_period):idx].copy()
            if len(recent) > 0:
                swing_low = recent['low'].min()
                swing_high = recent['high'].max()
            else:
                # Fallback
                sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
                if direction == 'buy' or direction.lower() == 'b':
                    tp = entry_price + (tp_mult * atr)
                else:
                    tp = entry_price - (tp_mult * atr)
                return sl, tp, (abs(tp - entry_price) / risk) if risk > 0 else 1.5
        else:
            # Limited data, use ATR for TP
            sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
            if direction == 'buy' or direction.lower() == 'b':
                tp = entry_price + (tp_mult * atr)
            else:
                tp = entry_price - (tp_mult * atr)
            return sl, tp, (abs(tp - entry_price) / risk) if risk > 0 else 1.5
        
        # Calculate Fib targets
        fibs = calculate_fib_extensions(entry_price, swing_low, swing_high, direction)
        
        # Get opposing liquidity
        opp_liquidity = find_opposing_liquidity(df, idx, direction, lookback=30)
        
        # PRIORITY: Fib 200 > 261 > 161 > Liquidity > 127
        if direction == 'buy' or direction.lower() == 'b':
            tp_candidates = [fibs.get('200'), fibs.get('261'), fibs.get('161'), opp_liquidity, fibs.get('127')]
        else:
            tp_candidates = [fibs.get('200'), fibs.get('261'), fibs.get('161'), opp_liquidity, fibs.get('127')]
        
        # Find first TP that meets 2.0x minimum RR (sweep SL is tight, should be easier to hit)
        tp = None
        achieved_rr = 0
        for candidate in tp_candidates:
            if candidate is None:
                continue
            
            if direction == 'buy' or direction.lower() == 'b':
                if candidate <= entry_price:
                    continue
                reward = candidate - entry_price
            else:
                if candidate >= entry_price:
                    continue
                reward = entry_price - candidate
            
            candidate_rr = reward / risk if risk > 0 else 0
            
            if candidate_rr >= 2.0:  # Lower threshold with tight SL
                tp = candidate
                achieved_rr = candidate_rr
                print(f"[⭐ SWEEP SL TP] Selected TP {tp:.5f} for RR {achieved_rr:.2f}:1 (sweep SL at {sl:.5f})")
                break
        
        if tp is None:
            # Fallback to ATR-based TP
            sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
            if direction == 'buy' or direction.lower() == 'b':
                tp = entry_price + (tp_mult * atr)
            else:
                tp = entry_price - (tp_mult * atr)
            achieved_rr = (abs(tp - entry_price) / risk) if risk > 0 else 1.5
        
        return sl, tp, achieved_rr
    
    else:
        # No sweep SL - use traditional SMC Fib approach
        return calculate_smc_fib_sl_tp(entry_price, df, idx, direction, atr, model_name)


def calculate_smc_fib_sl_tp(entry_price, df, idx, direction, atr, model_name='HYDRA'):
    """
    Calculate SL/TP using SMC structure + Fibonacci extensions (REDESIGNED FOR 2.5-4.0x R:R)
    
    This combines:
    1. Structure-based SL (order blocks, swing levels)
    2. Fib extension TPs (prioritize 200%, 261.8%, 161.8%)
    3. Opposing liquidity targets
    4. R:R validation (target 2.5-4.0x minimum)
    """
    
    # Get SL from structure (wider lookback for better structure)
    sl = find_structure_sl(df, idx, direction, atr, lookback=80)
    if sl is None:
        # Fallback to ATR-based
        sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
        if direction == 'buy' or direction.lower() == 'b':
            sl = entry_price - (sl_mult * atr)
        else:
            sl = entry_price + (sl_mult * atr)
        return sl, None, 1.5  # Return default with low confidence
    
    # Calculate R (risk distance)
    if direction == 'buy' or direction.lower() == 'b':
        risk = entry_price - sl
    else:
        risk = sl - entry_price
    
    # Prevent invalid SL
    if risk <= 0:
        sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
        if direction == 'buy' or direction.lower() == 'b':
            sl = entry_price - (sl_mult * atr)
            tp = entry_price + (tp_mult * atr)
        else:
            sl = entry_price + (sl_mult * atr)
            tp = entry_price - (tp_mult * atr)
        return sl, tp, tp_mult / sl_mult
    
    # Find swing high/low for Fib (wider lookback for meaningful swings)
    lookback_period = 100
    if idx >= lookback_period and df is not None and len(df) > idx:
        recent = df.iloc[max(0, idx-lookback_period):idx].copy()
        if len(recent) > 0:
            swing_low = recent['low'].min()
            swing_high = recent['high'].max()
        else:
            # Fallback to ATR
            sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
            if direction == 'buy' or direction.lower() == 'b':
                tp = entry_price + (tp_mult * atr)
            else:
                tp = entry_price - (tp_mult * atr)
            return sl, tp, 1.5
    else:
        # Fallback to ATR
        sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
        if direction == 'buy' or direction.lower() == 'b':
            tp = entry_price + (tp_mult * atr)
        else:
            tp = entry_price - (tp_mult * atr)
        return sl, tp, 1.5
    
    # Calculate Fib targets (including 261.8%)
    fibs = calculate_fib_extensions(entry_price, swing_low, swing_high, direction)
    
    # Get opposing liquidity (recent 30 bars)
    opp_liquidity = find_opposing_liquidity(df, idx, direction, lookback=30)
    
    # PRIORITY ORDER: Fib 200 > Fib 261 > Fib 161 > opposing liquidity > Fib 127
    # This targets wider TPs for better R:R
    if direction == 'buy' or direction.lower() == 'b':
        tp_candidates = [
            fibs.get('200'),   # Target 200% first (wider)
            fibs.get('261'),   # Then 261.8% (even wider)
            fibs.get('161'),   # Then 161.8%
            opp_liquidity,     # Opposing liquidity (recent high)
            fibs.get('127')    # Last resort: 127.2%
        ]
    else:
        tp_candidates = [
            fibs.get('200'),
            fibs.get('261'),
            fibs.get('161'),
            opp_liquidity,
            fibs.get('127')
        ]
    
    # Find first valid TP that meets MINIMUM 2.5x R:R
    tp = None
    achieved_rr = 0
    for candidate in tp_candidates:
        if candidate is None:
            continue
        
        # Check if valid direction
        if direction == 'buy' or direction.lower() == 'b':
            if candidate <= entry_price:
                continue
            reward = candidate - entry_price
        else:
            if candidate >= entry_price:
                continue
            reward = entry_price - candidate
        
        # Calculate R:R
        candidate_rr = reward / risk if risk > 0 else 0
        
        # Accept if meets minimum 2.5x R:R (targeting 2.5-4.0x range)
        if candidate_rr >= 2.5:
            tp = candidate
            achieved_rr = candidate_rr
            break
    
    # If no TP meets 2.5x R:R, try relaxed 2.0x minimum
    if tp is None:
        for candidate in tp_candidates:
            if candidate is None:
                continue
            
            if direction == 'buy' or direction.lower() == 'b':
                if candidate <= entry_price:
                    continue
                reward = candidate - entry_price
            else:
                if candidate >= entry_price:
                    continue
                reward = entry_price - candidate
            
            candidate_rr = reward / risk if risk > 0 else 0
            
            if candidate_rr >= 2.0:  # Relaxed minimum
                tp = candidate
                achieved_rr = candidate_rr
                break
    
    # If still no valid TP, fallback to ATR
    if tp is None:
        sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
        if direction == 'buy' or direction.lower() == 'b':
            tp = entry_price + (tp_mult * atr)
        else:
            tp = entry_price - (tp_mult * atr)
        actual_rr = risk / abs(tp - entry_price) if tp != entry_price else 1.0
        return sl, tp, actual_rr
    
    # NO ATR CAP - let Fib extensions reach natural targets
    # This is critical for achieving 2.5-4.0x R:R
    
    return sl, tp, achieved_rr


def execute_trade_with_smc_fib_sl_tp(symbol, direction, entry_price, df, atr, model_name='HYDRA', lot_size=0.02, use_smc_fib=True, sweep_sl_override=None):
    """
    Execute trade with SMC/Fib-based SL/TP or fallback to model-specific multipliers
    
    ⭐ ENHANCED: Supports sweep-based SL override
    
    Args:
        symbol: Trading pair
        direction: 'buy' or 'sell'
        entry_price: Entry price
        df: Price dataframe
        atr: ATR value at entry
        model_name: Name of winning model
        lot_size: Position size
        use_smc_fib: Use SMC/Fib if True, else use model profiles
        sweep_sl_override: Optional sweep-based SL (overrides structure-based SL)
    
    Returns:
        (sl, tp, rr_ratio) tuple or None if trade invalid
    """
    if use_smc_fib and df is not None and len(df) > 100:
        # ⭐ Use ENHANCED SL/TP calculation with sweep override support
        sl, tp, rr_ratio = calculate_smc_fib_sl_tp_with_sweep_override(
            entry_price, df, len(df)-1, direction, atr, model_name,
            sweep_sl_override=sweep_sl_override
        )
        
        # Validate R:R >= 2.0
        if rr_ratio < 2.0:
            print(f"  ⚠️  {symbol} SMC/Fib R:R {rr_ratio:.2f} < 2.0. Using model profiles instead.")
            # Fallback to model profiles
            use_smc_fib = False
    
    if not use_smc_fib or df is None or len(df) <= 100:
        # Fallback to model-specific profiles
        sl_mult, tp_mult = get_model_sl_tp_multipliers(model_name)
        if direction == 'buy' or direction.lower() == 'b':
            sl = entry_price - (sl_mult * atr)
            tp = entry_price + (tp_mult * atr)
        else:
            sl = entry_price + (sl_mult * atr)
            tp = entry_price - (tp_mult * atr)
        
        if direction == 'buy' or direction.lower() == 'b':
            rr_ratio = (tp - entry_price) / (entry_price - sl) if entry_price > sl else 1.0
        else:
            rr_ratio = (entry_price - tp) / (sl - entry_price) if sl > entry_price else 1.0
        
        print(f"  Using {model_name} profiles: SL/TP {sl_mult:.1f}x/{tp_mult:.1f}x ATR (R:R {rr_ratio:.2f})")
    else:
        print(f"  Using SMC/Fib SL/TP (R:R {rr_ratio:.2f})")
    
    return sl, tp, rr_ratio

