def get_trading_session():
    """
    Determine current trading session based on UTC time.
    Returns: 'Asian', 'London', 'NewYork', or 'SydneyClose'
    """
    from datetime import datetime, timezone
    
    now_utc = datetime.now(timezone.utc)
    hour_utc = now_utc.hour
    
    # Session times (UTC)
    # Asian: 21:00 - 09:00 UTC (9pm to 9am) = Tokyo/Singapore
    # London: 08:00 - 16:30 UTC
    # NewYork: 13:00 - 21:00 UTC (1pm to 9pm)
    # SydneyClose: 20:00 - 21:00 UTC
    
    if 8 <= hour_utc < 16:  # 8am-4pm UTC = London
        return "London"
    elif 13 <= hour_utc < 21:  # 1pm-9pm UTC = New York
        return "NewYork"
    elif hour_utc >= 20 or hour_utc < 1:  # 8pm-1am = Sydney close/Asian open
        return "Asian"
    else:
        return "Transition"

def is_volatility_ok(df, symbol, max_spread_pips=2.0, min_atr_multiplier=1.0):
    """
    VOLATILITY FILTER: Checks if current volatility is acceptable for entry.
    
    Rules:
    1. ATR > minimum threshold (prevents low-vol, choppy entries)
    2. Candle body > 30% of range (institutional move)
    3. Spread < maximum allowed (avoid wide spreads)
    
    Returns: (is_ok: bool, reason: str, metrics: dict)
    """
    
    if len(df) < 15:
        return False, "Insufficient data for volatility check", {}
    
    metrics = {}
    failures = []
    
    try:
        # 1. ATR CHECK
        atr = calculate_atr(df, 14)
        metrics['atr'] = atr
        min_atr_threshold = 0.0001 if symbol.endswith(('USD', 'EUR')) else 0.01  # Forex vs gold/crypto
        if atr < min_atr_threshold * min_atr_multiplier:
            failures.append(f"ATR ({atr:.6f}) below threshold ({min_atr_threshold * min_atr_multiplier:.6f})")
        
        # 2. CANDLE BODY CHECK (Last candle should show institutional conviction)
        last_candle = df.iloc[-1]
        body = abs(last_candle['close'] - last_candle['open'])
        candle_range = last_candle['high'] - last_candle['low']
        
        if candle_range > 0:
            body_ratio = body / candle_range
            metrics['body_ratio'] = body_ratio
            if body_ratio < 0.30:
                failures.append(f"Weak candle body ({body_ratio:.0%} < 30%)")
        
        # 3. SPREAD CHECK (from symbol_info if available)
        try:
            symbol_info = mt5.symbol_info(symbol)
            if symbol_info and hasattr(symbol_info, 'spread'):
                spread_points = symbol_info.spread
                pip_value = 10 if 'JPY' in symbol else 10000
                spread_pips = spread_points / pip_value
                metrics['spread_pips'] = spread_pips
                if spread_pips > max_spread_pips:
                    failures.append(f"Spread ({spread_pips:.1f}pips) > max ({max_spread_pips}pips)")
        except Exception:
            pass
        
        is_ok = len(failures) == 0
        reason = " | ".join(failures) if failures else "Volatility OK"
        
        return is_ok, reason, metrics
    
    except Exception as e:
        return False, f"Volatility check error: {e}", metrics

def is_impulse_candle(df, atr_value=None, max_impulse_multiple=1.5):
    """
    IMPULSE CANDLE FILTER: Detects if last candle is an impulse (too large = late entry).
    
    Rule: Skip if candle_range > 1.5 × ATR (high volatility spike = potential top/bottom)
    
    Returns: (is_impulse: bool, reason: str)
    """
    
    if len(df) < 15:
        return False, "Insufficient data"
    
    try:
        if atr_value is None:
            atr_value = calculate_atr(df, 14)
        
        last_candle = df.iloc[-1]
        candle_range = last_candle['high'] - last_candle['low']
        
        max_allowed_range = atr_value * max_impulse_multiple
        
        if candle_range > max_allowed_range:
            return True, f"IMPULSE: Range {candle_range:.6f} > {max_allowed_range:.6f} ({candle_range/atr_value:.1f}× ATR)"
        
        return False, f"Normal range: {candle_range:.6f} < {max_allowed_range:.6f}"
    
    except Exception as e:
        return False, f"Impulse check error: {e}"

def is_golden_entry_window(zone_touch_bar_index, current_bar_index, max_bars_after_touch=5):
    """
    GOLDEN ENTRY WINDOW: Ensures entry happens within 3-5 candles of zone touch.
    
    Rule: If more than 5 candles have passed since zone was touched → setup is dead.
    
    Returns: (is_valid: bool, bars_since_touch: int, reason: str)
    """
    
    if zone_touch_bar_index is None:
        return False, 0, "Zone never touched"
    
    bars_since_touch = current_bar_index - zone_touch_bar_index
    
    if bars_since_touch > max_bars_after_touch:
        return False, bars_since_touch, f"Dead setup: {bars_since_touch} candles passed (max: {max_bars_after_touch})"
    elif bars_since_touch <= 1:
        return False, bars_since_touch, f"Zone just touched, waiting for entry candle"
    else:
        return True, bars_since_touch, f"Golden window: {bars_since_touch}/{max_bars_after_touch} candles"

