# LATE-ENTRY DETECTION SYSTEM (Master Switch)
# ═══════════════════════════════════════════════════════════════════════════════

def detect_distance_from_zone(current_price, zone_high, zone_low, max_distance_pct=0.30):
    """
    DETECTOR 1: DISTANCE-FROM-ZONE
    
    Rule: If price moved > X% away from zone → entry is too late
    
    Args:
        current_price: Current market price
        zone_high: Entry zone high level
        zone_low: Entry zone low level
        max_distance_pct: Max allowed distance (0.30 = 30%)
    
    Returns: (is_late: bool, distance_pct: float, reason: str)
    """
    
    if zone_high <= zone_low:
        return False, 0.0, "Invalid zone"
    
    zone_mid = (zone_high + zone_low) / 2.0
    zone_range = zone_high - zone_low
    
    distance = abs(current_price - zone_mid)
    distance_pct = distance / zone_range if zone_range > 0 else 0.0
    
    is_late = distance_pct > max_distance_pct
    
    reason = f"Distance {distance_pct:.1%} {'>' if is_late else '<'} {max_distance_pct:.1%} threshold"
    
    return is_late, distance_pct, reason

def detect_rr_degradation(entry_price, sl_price, tp_price, min_rr=2.0):
    """
    DETECTOR 2: RR DEGRADATION
    
    Rule: If RR < minimum RR → entry is too late (reward too small relative to risk)
    
    Args:
        entry_price: Entry price
        sl_price: Stop loss price
        tp_price: Take profit price
        min_rr: Minimum acceptable RR ratio (default 2.0 = 1:2)
    
    Returns: (is_late: bool, rr_ratio: float, reason: str)
    """
    
    risk = abs(entry_price - sl_price)
    reward = abs(tp_price - entry_price)
    
    if risk <= 0:
        return True, 0.0, "Invalid SL (risk = 0)"
    
    rr_ratio = reward / risk if risk > 0 else 0.0
    
    is_late = rr_ratio < min_rr
    
    reason = f"RR {rr_ratio:.2f}:1 {'<' if is_late else '>'} {min_rr}:1 minimum"
    
    return is_late, rr_ratio, reason

def detect_time_decay(bars_since_zone_touch, timeframe_name="M15", max_bars_config=None):
    """
    DETECTOR 4: TIME-DECAY
    
    Rule: If more than N candles have passed since zone touch → setup expired
    
    Args:
        bars_since_zone_touch: Number of bars since zone was touched
        timeframe_name: "M1", "M5", "M15", "H1", etc.
        max_bars_config: Dict with timeframe -> max_bars. If None, uses defaults.
    
    Returns: (is_late: bool, bars_since: int, reason: str)
    """
    
    if bars_since_zone_touch is None:
        return False, 0, "Zone touch unknown"
    
    # Default max bars per timeframe
    defaults = {
        "M1": 5,    # 5 candles = 5 minutes
        "M5": 3,    # 3 candles = 15 minutes
        "M15": 2,   # 2 candles = 30 minutes
        "H1": 2,    # 2 candles = 2 hours
        "H4": 1,    # 1 candle = 4 hours
    }
    
    if max_bars_config:
        defaults.update(max_bars_config)
    
    max_bars = defaults.get(timeframe_name, 3)
    
    is_late = bars_since_zone_touch > max_bars
    
    reason = f"Setup age: {bars_since_zone_touch} candles {'>' if is_late else '<'} {max_bars} candle limit"
    
    return is_late, bars_since_zone_touch, reason

def detect_sl_expansion(sl_pips, max_allowed_sl_pips=50, symbol="EURUSD"):
    """
    DETECTOR 5: SL EXPANSION
    
    Rule: If SL distance > max allowed → entry is risky (late entries expand SL)
    
    Args:
        sl_pips: Stop loss distance in pips
        max_allowed_sl_pips: Maximum allowed SL distance (default 50 pips)
        symbol: Currency pair (for context)
    
    Returns: (is_late: bool, sl_pips: float, reason: str)
    """
    
    if sl_pips <= 0:
        return True, sl_pips, "Invalid SL (zero or negative)"
    
    is_late = sl_pips > max_allowed_sl_pips
    
    reason = f"SL {sl_pips:.1f}pips {'>' if is_late else '<'} {max_allowed_sl_pips}pips max"
    
    return is_late, sl_pips, reason

def detect_late_entry_master(
    current_price,
    zone_high,
    zone_low,
    entry_price,
    sl_price,
    tp_price,
    bars_since_zone_touch,
    sl_pips,
    timeframe="M15",
    symbol="EURUSD",
    # Configuration per timeframe
    distance_pct_config=None,
    min_rr_config=None,
    max_bars_config=None,
    max_sl_pips_config=None,
    atr_value=None,
    last_candle_range=None,
    impulse_multiplier_config=None
):
    """
    LATE-ENTRY MASTER DETECTOR: Combines all 5 detectors into final verdict.
    
    Returns: {
        'is_late': bool,
        'detectors_failed': list,
        'reasons': list,
        'distance': (is_late, pct, reason),
        'rr_degradation': (is_late, ratio, reason),
        'impulse_candle': (is_late, range, reason),
        'time_decay': (is_late, bars, reason),
        'sl_expansion': (is_late, pips, reason),
        'verdict': str
    }
    """
    
    # Default config per timeframe
    if distance_pct_config is None:
        distance_pct_config = {
            "M1": 0.30,
            "M5": 0.25,
            "M15": 0.20,
            "H1": 0.15,
        }
    
    if min_rr_config is None:
        min_rr_config = {
            "M1": 1.5,
            "M5": 2.0,
            "M15": 2.0,
            "H1": 1.5,
        }
    
    if max_bars_config is None:
        max_bars_config = {
            "M1": 5,
            "M5": 3,
            "M15": 2,
            "H1": 2,
        }
    
    if max_sl_pips_config is None:
        max_sl_pips_config = {
            "M1": 30,
            "M5": 40,
            "M15": 50,
            "H1": 100,
        }
    
    if impulse_multiplier_config is None:
        impulse_multiplier_config = {
            "M1": 1.5,
            "M5": 1.3,
            "M15": 1.2,
            "H1": 1.1,
        }
    
    results = {
        'is_late': False,
        'detectors_failed': [],
        'reasons': [],
        'distance': None,
        'rr_degradation': None,
        'impulse_candle': None,
        'time_decay': None,
        'sl_expansion': None,
        'verdict': 'UNKNOWN'
    }
    
    # DETECTOR 1: DISTANCE FROM ZONE
    max_dist = distance_pct_config.get(timeframe, 0.20)
    is_late_dist, dist_pct, dist_reason = detect_distance_from_zone(
        current_price, zone_high, zone_low, max_dist
    )
    results['distance'] = (is_late_dist, dist_pct, dist_reason)
    if is_late_dist:
        results['detectors_failed'].append("DISTANCE-FROM-ZONE")
        results['reasons'].append(f"❌ {dist_reason}")
    
    # DETECTOR 2: RR DEGRADATION
    min_rr = min_rr_config.get(timeframe, 1.5)
    is_late_rr, rr_ratio, rr_reason = detect_rr_degradation(
        entry_price, sl_price, tp_price, min_rr
    )
    results['rr_degradation'] = (is_late_rr, rr_ratio, rr_reason)
    if is_late_rr:
        results['detectors_failed'].append("RR-DEGRADATION")
        results['reasons'].append(f"❌ {rr_reason}")
    
    # DETECTOR 3: IMPULSE CANDLE
    is_late_impulse = False
    impulse_reason = "N/A"
    if atr_value is not None and last_candle_range is not None:
        impulse_mult = impulse_multiplier_config.get(timeframe, 1.2)
        is_late_impulse = last_candle_range > impulse_mult * atr_value
        impulse_reason = f"Candle range {last_candle_range:.6f} {'>' if is_late_impulse else '<'} {impulse_mult:.1f}× ATR ({impulse_mult * atr_value:.6f})"
    results['impulse_candle'] = (is_late_impulse, last_candle_range or 0, impulse_reason)
    if is_late_impulse:
        results['detectors_failed'].append("IMPULSE-CANDLE")
        results['reasons'].append(f"❌ {impulse_reason}")
    
    # DETECTOR 4: TIME DECAY
    is_late_time = False
    time_reason = "N/A"
    if bars_since_zone_touch is not None:
        is_late_time, bars_since, time_reason = detect_time_decay(
            bars_since_zone_touch, timeframe, max_bars_config
        )
    results['time_decay'] = (is_late_time, bars_since_zone_touch or 0, time_reason)
    if is_late_time:
        results['detectors_failed'].append("TIME-DECAY")
        results['reasons'].append(f"❌ {time_reason}")
    
    # DETECTOR 5: SL EXPANSION
    max_sl = max_sl_pips_config.get(timeframe, 50)
    is_late_sl, sl_check, sl_reason = detect_sl_expansion(
        sl_pips, max_sl, symbol
    )
    results['sl_expansion'] = (is_late_sl, sl_pips, sl_reason)
    if is_late_sl:
        results['detectors_failed'].append("SL-EXPANSION")
        results['reasons'].append(f"❌ {sl_reason}")
    
    # MASTER VERDICT
    results['is_late'] = any([is_late_dist, is_late_rr, is_late_impulse, is_late_time, is_late_sl])
    
    if results['is_late']:
        failed_count = len(results['detectors_failed'])
        results['verdict'] = f"🛑 LATE ENTRY: {failed_count} detector(s) triggered ({', '.join(results['detectors_failed'])})"
    else:
        results['verdict'] = "✅ ENTRY VALID: All late-entry detectors passed"
    
    return results

def validate_entry_hierarchical_4gate(symbol, direction, confidence, htf_bias_dir, df, smc_ict, spread=0.0, atr_value=None):
    """
    ═══════════════════════════════════════════════════════════════════════════════
    CLEAN HIERARCHICAL 4-GATE ENTRY VALIDATION (REPLACES 3-LAYER DEMOCRACY)
    ═══════════════════════════════════════════════════════════════════════════════
    
    🟢 HARD GATES (BLOCK immediately):
    
    GATE 1️⃣  (MASTER): HTF BIAS - Direction MUST align with HTF bias
    GATE 2️⃣  (STRUCTURE): MARKET STRUCTURE - BOS required (score >= 85)
    GATE 3️⃣  (LOCATION): ENTRY AT POI - Price must touch FVG/OB/POI (not mid-range)
    GATE 4️⃣  (RISK): SL/TP VALIDITY - RR > 1.5 AND MIN_SL ≤ distance ≤ MAX_SL
    
    ⚠️  TIMING GATES (BLOCK unless alignment):
    - Session check (London 8-12 UTC or New York 16-21 UTC)
    - News volatility filter
    - Liquidity check
    
    🔴 ADVISORY (printed but NOT blocking):
    - Spread check (only advisory unless confidence < 80%)
    - Volatility (informational only)
    
    Philosophy: Reject 80-90% of market conditions. Only "PERFECT" setups get traded.
    
    Returns: (approved: bool, gate_results: dict, reason: str)
    """
    
    gate_results = {
        'gate_1_htf_bias': {'passed': False, 'reason': ''},
        'gate_2_structure': {'passed': False, 'reason': ''},
        'gate_3_entry_zone': {'passed': False, 'reason': ''},
        'gate_4_risk': {'passed': False, 'reason': ''},
        'timing_checks': [],
        'advisory_notes': []
    }
    
    try:
        # ═══════════════════════════════════════════════════════════════════════════════
        # GATE 1: HTF BIAS (MASTER) - Direction alignment (highest priority)
        # ═══════════════════════════════════════════════════════════════════════════════
        htf_aligned = (
            (htf_bias_dir == 'bullish' and direction == 'buy') or
            (htf_bias_dir == 'bearish' and direction == 'sell') or
            (htf_bias_dir == 'neutral')  # Neutral doesn't block
        )
        
        if not htf_aligned and htf_bias_dir in ('bullish', 'bearish'):
            gate_results['gate_1_htf_bias'] = {
                'passed': False,
                'reason': f'HTF {htf_bias_dir.upper()} opposes {direction.upper()} entry'
            }
            return False, gate_results, f"❌ GATE 1 BLOCKED: HTF bias {htf_bias_dir} vs signal {direction}"
        
        gate_results['gate_1_htf_bias'] = {
            'passed': True,
            'reason': f'HTF {htf_bias_dir.upper()} aligns with {direction.upper()}'
        }
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # GATE 2: MARKET STRUCTURE - BOS ONLY (strict, no fallback)
        # ═══════════════════════════════════════════════════════════════════════════════
        bos_detected = bool(smc_ict.get('BOS'))
        
        # STRICT: BOS is the ONLY acceptable confirmation
        # NO sweep fallback, NO CHOCH fallback = structure must be proven
        if not bos_detected:
            gate_results['gate_2_structure'] = {
                'passed': False,
                'reason': 'BOS required but NOT detected (score < 85)'
            }
            return False, gate_results, f"❌ GATE 2 BLOCKED: NO VALID BOS - Entry rejected"
        
        gate_results['gate_2_structure'] = {
            'passed': True,
            'reason': f'BOS confirmed: {smc_ict.get("BOS", "").upper()}'
        }
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # GATE 3: ENTRY AT POI (Point of Interest) - Strict location requirement
        # ═══════════════════════════════════════════════════════════════════════════════
        # 🔴 HARD REQUIREMENT: Entry MUST be at POI, not mid-range
        # POI = FVG (6-step advanced detection), Order Block (confluence check), or Entry Zone (ATR-based)
        # Mid-range = no institutional zone = low probability = REJECT
        
        current_price = float(df['close'].iloc[-1])
        entry_zone_ok = False
        zone_type = None
        zone_info = {}
        
        # 1) Check ADVANCED FVG (6-validation: displacement + imbalance + structure + momentum + HTF + confidence)
        try:
            fvg_result = detect_fvg(df, htf_bias=htf_bias_dir)
            if fvg_result:
                fvg_low = float(fvg_result.get('zone_low', 0))
                fvg_high = float(fvg_result.get('zone_high', 0))
                if fvg_low < fvg_high and fvg_low <= current_price <= fvg_high:
                    entry_zone_ok = True
                    zone_type = 'FVG'
                    zone_info = {
                        'low': fvg_low, 
                        'high': fvg_high,
                        'confidence': fvg_result.get('confidence', 0.5),
                        'strength': fvg_result.get('strength', 0),
                        'validations': fvg_result.get('validations_passed', 0)
                    }
        except Exception as e:
            logging.debug(f"[GATE 3] FVG check error: {e}")
        
        # 2) Check ADVANCED Order Block (OB + FVG confluence)
        if not entry_zone_ok:
            try:
                ob_result = detect_breaker_block_fvg_confluence(df)
                if ob_result:
                    if isinstance(ob_result, dict):
                        ob_low = float(ob_result.get('low', 0) or ob_result.get('zone_low', 0))
                        ob_high = float(ob_result.get('high', 0) or ob_result.get('zone_high', 0))
                    else:
                        ob_low, ob_high = float(ob_result[0]), float(ob_result[1])
                    
                    if ob_low < ob_high and ob_low <= current_price <= ob_high:
                        entry_zone_ok = True
                        zone_type = 'OB'
                        zone_info = {'low': ob_low, 'high': ob_high, 'type': 'breaker_confluence'}
            except Exception as e:
                logging.debug(f"[GATE 3] OB check error: {e}")
        
        # 3) Check ATR-Based Entry Zone (POI: ±0.5x ATR from price)
        if not entry_zone_ok:
            try:
                poi_result = calculate_entry_zone(df)
                if poi_result and isinstance(poi_result, dict):
                    poi_low = float(poi_result.get('low', 0))
                    poi_high = float(poi_result.get('high', 0))
                    if poi_low < poi_high and poi_low <= current_price <= poi_high:
                        entry_zone_ok = True
                        zone_type = 'POI'
                        zone_info = {'low': poi_low, 'high': poi_high, 'method': poi_result.get('method', 'ATR')}
            except Exception as e:
                logging.debug(f"[GATE 3] POI check error: {e}")
        
        if not entry_zone_ok:
            gate_results['gate_3_entry_zone'] = {
                'passed': False,
                'reason': f'Price {current_price:.5f} NOT in institutional zone (FVG/OB/POI). Mid-range entry rejected.'
            }
            return False, gate_results, f"❌ GATE 3 BLOCKED: Entry not at POI - Price must be in FVG/OB/POI zone to ensure quality"
        
        gate_results['gate_3_entry_zone'] = {
            'passed': True,
            'reason': f'Price {current_price:.5f} confirmed in {zone_type} zone ({zone_info})'
        }
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # GATE 4: RISK MANAGEMENT - SL/TP validity (MIN ≤ distance ≤ MAX)
        # ═══════════════════════════════════════════════════════════════════════════════
        risk_ok = True
        risk_reason = "RR geometry valid"
        
        # Calculate ATR if not provided
        if atr_value is None or atr_value <= 0:
            try:
                atr_value = calculate_atr(df, 14)
            except Exception:
                atr_value = 0.0001  # Fallback minimum
        
        # Minimum ATR check (can't execute without volatility)
        if atr_value < 0.0001:
            risk_ok = False
            risk_reason = f"ATR critically low ({atr_value:.7f}), cannot compute valid SL"
        
        gate_results['gate_4_risk'] = {
            'passed': risk_ok,
            'reason': risk_reason
        }
        
        if not risk_ok:
            return False, gate_results, f"❌ GATE 4 BLOCKED: {risk_reason}"
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # TIMING GATES (Additional hard requirements - no exceptions)
        # ═══════════════════════════════════════════════════════════════════════════════
        timing_ok = True
        timing_reason = []
        
        # Session check: London (8-12 UTC) or New York (16-21 UTC) ONLY
        try:
            now_utc = datetime.now(timezone.utc)
            utc_hour = now_utc.hour
            
            london_session = 8 <= utc_hour < 12
            ny_session = 16 <= utc_hour < 21
            prefixed_session = london_session or ny_session
            
            # Gold and indices: avoid Asian session (2-7 UTC)
            if symbol.upper().startswith(('XAU', 'SPX', 'US100')):
                asian_session = 2 <= utc_hour < 7
                if asian_session:
                    timing_ok = False
                    timing_reason.append(f"Asian session {utc_hour}:00 - GOLD/INDICES blocked during Tokyo")
            
            if not prefixed_session and not timing_ok:
                gate_results['timing_checks'].append(
                    f"❌ Off-market session ({utc_hour}:00 UTC) - Only trade London 8-12 or NY 16-21"
                )
                return False, gate_results, f"❌ TIMING BLOCKED: Session {utc_hour}:00 UTC outside London/NY hours"
            elif not prefixed_session:
                gate_results['timing_checks'].append(
                    f"⚠️  Off-peak session ({utc_hour}:00 UTC) - Preferable hours: London 8-12, NY 16-21"
                )
        except Exception as e:
            gate_results['timing_checks'].append(f"⚠️ Session check error: {e}")
        
        # News volatility check (avoid 15 mins before major news)
        # NOTE: You would integrate real news calendar here
        # For now, just log this as advisory
        gate_results['timing_checks'].append("ℹ️  Check news calendar for major releases (15 min buffer)")
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # ADVISORY CHECKS (Not blocking, just informational)
        # ═══════════════════════════════════════════════════════════════════════════════
        
        # Advisory 1: Spread
        if spread > 0:
            if "JPY" in symbol.upper():
                max_spread = 0.08
            elif symbol.upper().startswith("XAU"):
                max_spread = 0.50
            else:
                max_spread = 0.0008
            
            if spread > max_spread:
                if confidence >= 0.80:
                    gate_results['advisory_notes'].append(
                        f"⚠️  Spread elevated ({spread:.5f} > {max_spread}) but allowed due to high confidence ({confidence:.0%})"
                    )
                else:
                    gate_results['advisory_notes'].append(
                        f"⚠️  Spread elevated ({spread:.5f} > {max_spread}) - consider waiting for better conditions"
                    )
        
        # ═══════════════════════════════════════════════════════════════════════════════
        # ALL 4 GATES PASSED - Entry Approved
        # ═══════════════════════════════════════════════════════════════════════════════
        reason = f"✅ ALL GATES PASSED | HTF:{htf_bias_dir.upper()} | BOS:{smc_ict.get('BOS', '?').upper()} | Zone:{zone_type}@{current_price:.5f} | RR:OK | Session:OK"
        return True, gate_results, reason
        
    except Exception as e:
        logging.error(f"[GATE ERROR] {symbol}: {e}", exc_info=True)
        return False, {'error': str(e)}, f"❌ ENTRY VALIDATION ERROR: {str(e)}"

def validate_entry_checklist(df, symbol, direction, smc_ict, ml_confidence, session="any", 
                             htf_bias_aligned=True, rr_ratio=2.0, min_rr=1.5,
                             zone_touched_bar_idx=None, atr_value=None):
    """
    CONSOLIDATED ENTRY CHECKLIST: Validates all 7 conditions before entry.
    
    The 7-Point Checklist:
    ✔ HTF bias confirmed (Layer 1)
    ✔ Price inside valid zone (Layer 2)
    ✔ RR ≥ 1:2
    ✔ Volatility OK
    ✔ Session OK
    ✔ Entry trigger candle closed
    ✔ Entry not late (≤ 5 candles)
    
    Returns: (entry_ok: bool, checks_passed: int/7, failures: list, details: dict)
    """
    
    checks = []
    failures = []
    details = {}
    
    # CHECK 1: HTF BIAS
    if htf_bias_aligned:
        checks.append("✅ HTF bias confirmed")
    else:
        checks.append("❌ HTF bias NOT confirmed")
        failures.append("HTF bias mismatch")
    
    # CHECK 2: PRICE IN VALID ZONE
    if smc_ict and (smc_ict.get('OB') or smc_ict.get('FVG') or smc_ict.get('POI')):
        checks.append("✅ Price in/near valid zone (FVG/OB/POI)")
    else:
        checks.append("⚠️  No SMC/ICT zone detected (price may be late)")
        # Not a hard failure but warning
    
    # CHECK 3: RISK/REWARD
    if rr_ratio >= min_rr:
        checks.append(f"✅ RR ratio {rr_ratio:.1f}:1 ≥ {min_rr}:1")
    else:
        checks.append(f"❌ RR ratio {rr_ratio:.1f}:1 < {min_rr}:1")
        failures.append(f"Low RR ({rr_ratio:.1f}:1 < {min_rr}:1)")
    
    # CHECK 4: VOLATILITY
    vol_ok, vol_reason, vol_metrics = is_volatility_ok(df, symbol)
    if vol_ok:
        checks.append("✅ Volatility OK")
    else:
        checks.append(f"❌ Volatility issue: {vol_reason}")
        failures.append(vol_reason)
    details['volatility'] = vol_metrics
    
    # CHECK 5: SESSION
    current_session = get_trading_session()
    if session == "any" or session.lower() in ("london", "newyork"):
        if current_session in ("London", "NewYork"):
            checks.append(f"✅ Session OK ({current_session})")
        else:
            checks.append(f"⚠️  Off-peak session ({current_session})")
            failures.append(f"Asian session ({current_session})")
    else:
        checks.append(f"⚠️  Session override: {current_session}")
    details['session'] = current_session
    
    # CHECK 6: IMPULSE CANDLE
    impulse, impulse_reason = is_impulse_candle(df, atr_value)
    if not impulse:
        checks.append("✅ Not an impulse candle")
    else:
        checks.append(f"❌ {impulse_reason}")
        failures.append(impulse_reason)
    
    # CHECK 7: GOLDEN ENTRY WINDOW
    if zone_touched_bar_idx is not None:
        window_ok, bars_since, window_reason = is_golden_entry_window(zone_touched_bar_idx, len(df)-1)
        if window_ok:
            checks.append(f"✅ Golden window active ({bars_since}/{5} candles)")
        else:
            checks.append(f"❌ {window_reason}")
            failures.append(window_reason)
        details['window'] = {'bars_since': bars_since, 'max_bars': 5}
    else:
        checks.append("⚠️  Zone touch bar index unknown")
    
    entry_ok = len(failures) == 0
    checks_passed = sum(1 for c in checks if c.startswith('✅'))
    
    return entry_ok, checks_passed, failures, checks, details

def detect_entry_zone(df, smc_ict, direction="buy", atr_value=None):
    """
    LAYER 2: DETECT ENTRY ZONE - Identifies valid entry locations (not just price).
    
    Returns multiple zone types in order of reliability:
    1. FVG (Fair Value Gap) - 50% of imbalance
    2. Order Block - Previous institutional zone
    3. Liquidity Sweep + Return - Sweep level with pullback
    4. Previous High/Low + Displacement
    
    Returns: {
        'zone_type': str (fvg|order_block|sweep_return|prev_level),
        'zone_low': float,
        'zone_high': float,
        'zone_level': float (mid-point),
        'distance_pips': float (from current price),
        'quality_score': float (0.0-1.0),
        'reason': str
    } or None if no valid zone
    """
    
    if len(df) < 20:
        return None
    
    current_price = df['close'].iloc[-1]
    best_zone = None
    
    try:
        # === ZONE 1: FVG (Most reliable institutional setup) ===
        fvg_info = detect_fvg(df)
        if fvg_info:
            fvg_direction = fvg_info.get('direction')
            fvg_gap_size = fvg_info.get('gap_size', 0)
            fvg_confidence = fvg_info.get('confidence', 0.5)
            
            if fvg_direction == direction and fvg_gap_size > 0:
                # Use 50% of imbalance as entry zone (optimal risk/reward)
                zone_level_offset = fvg_gap_size * 0.5
                
                if direction == 'buy':
                    # Buy FVG is usually below current price
                    zone_high = current_price
                    zone_low = current_price - zone_level_offset
                else:
                    # Sell FVG is usually above current price
                    zone_low = current_price
                    zone_high = current_price + zone_level_offset
                
                distance_pips = abs(zone_level_offset) / 0.0001 if '0001' in str(zone_level_offset) else abs(zone_level_offset)
                
                best_zone = {
                    'zone_type': 'fvg',
                    'zone_low': zone_low,
                    'zone_high': zone_high,
                    'zone_level': (zone_low + zone_high) / 2,
                    'distance_pips': distance_pips,
                    'quality_score': fvg_confidence,
                    'reason': f"FVG {direction.upper()}: {distance_pips:.0f} pips away (50% of {fvg_gap_size:.5f} imbalance), confidence={fvg_confidence:.0%}"
                }
    except Exception as e:
        pass
    
    try:
        # === ZONE 2: ORDER BLOCK (Institutional buy/sell zone) ===
        ob = smc_ict.get('OB')
        if ob and isinstance(ob, (tuple, list, dict)):
            if isinstance(ob, dict):
                ob_low = ob.get('low', 0)
                ob_high = ob.get('high', 0)
            else:
                ob_low, ob_high = ob[0], ob[1]
            
            # Check if order block aligns with direction
            ob_mid = (ob_low + ob_high) / 2
            if (direction == 'buy' and ob_mid < current_price) or (direction == 'sell' and ob_mid > current_price):
                distance_pips = abs(current_price - ob_mid) / 0.0001
                quality_score = 0.8
                
                zone = {
                    'zone_type': 'order_block',
                    'zone_low': ob_low,
                    'zone_high': ob_high,
                    'zone_level': ob_mid,
                    'distance_pips': distance_pips,
                    'quality_score': quality_score,
                    'reason': f"Order Block {direction.upper()}: {distance_pips:.0f} pips away (zone {ob_low:.5f}-{ob_high:.5f})"
                }
                
                if best_zone is None or quality_score > best_zone.get('quality_score', 0):
                    best_zone = zone
    except Exception as e:
        pass
    
    try:
        # === ZONE 3: LIQUIDITY SWEEP + RETURN (Institutional sweep + pullback) ===
        sweep_info = detect_liquidity_sweep(df)
        if sweep_info and sweep_info.get('swept'):
            sweep_level = sweep_info.get('sweep_level')
            if direction == 'buy' and sweep_level < current_price:
                # Bullish sweep: expect pullback to sweep level before entry
                distance_pips = (current_price - sweep_level) / 0.0001
                quality_score = 0.75
                zone_buffer = (current_price - sweep_level) * 0.1
                
                zone = {
                    'zone_type': 'sweep_return',
                    'zone_low': sweep_level,
                    'zone_high': sweep_level + zone_buffer,
                    'zone_level': sweep_level + zone_buffer * 0.5,
                    'distance_pips': distance_pips,
                    'quality_score': quality_score,
                    'reason': f"Sweep+Return {direction.upper()}: {distance_pips:.0f} pips to sweep level {sweep_level:.5f}"
                }
                
                if best_zone is None or quality_score > best_zone.get('quality_score', 0):
                    best_zone = zone
            elif direction == 'sell' and sweep_level > current_price:
                # Bearish sweep
                distance_pips = (sweep_level - current_price) / 0.0001
                quality_score = 0.75
                zone_buffer = (sweep_level - current_price) * 0.1
                
                zone = {
                    'zone_type': 'sweep_return',
                    'zone_low': sweep_level - zone_buffer,
                    'zone_high': sweep_level,
                    'zone_level': sweep_level - zone_buffer * 0.5,
                    'distance_pips': distance_pips,
                    'quality_score': quality_score,
                    'reason': f"Sweep+Return {direction.upper()}: {distance_pips:.0f} pips to sweep level {sweep_level:.5f}"
                }
                
                if best_zone is None or quality_score > best_zone.get('quality_score', 0):
                    best_zone = zone
    except Exception as e:
        pass
    
    try:
        # === ZONE 4: PREVIOUS HIGH/LOW + DISPLACEMENT ===
        lookback = 30
        if direction == 'buy':
            # Find previous swing high within lookback
            prev_high = df['high'].iloc[-lookback:].max()
            prev_high_idx = df['high'].iloc[-lookback:].idxmax()
            
            if prev_high < current_price:
                # Price above previous high - look for retest zone
                displacement = (current_price - prev_high) / 0.0001
                if atr_value:
                    atr_disp = displacement * 0.0001 / atr_value
                    quality_score = max(0.5, 1.0 - atr_disp * 0.2)  # Closer to ATR = lower score
                else:
                    quality_score = 0.65
                
                zone = {
                    'zone_type': 'prev_level',
                    'zone_low': prev_high * 0.99,
                    'zone_high': prev_high * 1.01,
                    'zone_level': prev_high,
                    'distance_pips': displacement,
                    'quality_score': quality_score,
                    'reason': f"Previous High {direction.upper()}: {displacement:.0f} pips above prev high {prev_high:.5f} (displacement mode)"
                }
                
                if best_zone is None or quality_score > best_zone.get('quality_score', 0):
                    best_zone = zone
        else:  # sell
            # Find previous swing low within lookback
            prev_low = df['low'].iloc[-lookback:].min()
            prev_low_idx = df['low'].iloc[-lookback:].idxmin()
            
            if prev_low > current_price:
                # Price below previous low - look for retest zone
                displacement = (prev_low - current_price) / 0.0001
                if atr_value:
                    atr_disp = displacement * 0.0001 / atr_value
                    quality_score = max(0.5, 1.0 - atr_disp * 0.2)
                else:
                    quality_score = 0.65
                
                zone = {
                    'zone_type': 'prev_level',
                    'zone_low': prev_low * 0.99,
                    'zone_high': prev_low * 1.01,
                    'zone_level': prev_low,
                    'distance_pips': displacement,
                    'quality_score': quality_score,
                    'reason': f"Previous Low {direction.upper()}: {displacement:.0f} pips below prev low {prev_low:.5f} (displacement mode)"
                }
                
                if best_zone is None or quality_score > best_zone.get('quality_score', 0):
                    best_zone = zone
    except Exception as e:
        pass
    
    return best_zone

def detect_entry_trigger(df, direction="buy"):
    """
    LAYER 3: ENTRY TRIGGER - Detects proper entry confirmation (prevents SL hits).
    
    Checks for ONE of these conditions:
    1. Candle close rejection (pin bar / hammer)
    2. Micro BOS on entry timeframe
    3. Engulfing candle
    4. Strong displacement candle (body > 60% range)
    
    Returns: (trigger_confirmed: bool, trigger_type: str, trigger_reason: str)
    """
    
    if len(df) < 5:
        return False, 'none', 'Insufficient data'
    
    current = df.iloc[-1]
    previous = df.iloc[-2]
    two_bars_back = df.iloc[-3]
    
    current_close = current['close']
    current_open = current['open']
    current_high = current['high']
    current_low = current['low']
    
    prev_close = previous['close']
    prev_open = previous['open']
    prev_high = previous['high']
    prev_low = previous['low']
    
    # === TRIGGER 1: CANDLE CLOSE REJECTION (Pin Bar / Hammer) ===
    # Long wick opposite to direction, small body on direction side
    body = abs(current_close - current_open)
    wick_up = current_high - max(current_close, current_open)
    wick_down = min(current_close, current_open) - current_low
    total_range = current_high - current_low
    
    if total_range > 0:
        body_ratio = body / total_range
        
        if direction == 'buy':
            # Hammer: long lower wick, small body closing up
            if wick_down > body * 2 and wick_down > total_range * 0.6 and current_close > current_open:
                return True, 'rejection', f"Hammer pattern: {wick_down:.5f} lower wick rejection, body {body_ratio:.0%}"
        else:
            # Inverted hammer / hanging man: long upper wick, small body closing down
            if wick_up > body * 2 and wick_up > total_range * 0.6 and current_close < current_open:
                return True, 'rejection', f"Inverted hammer: {wick_up:.5f} upper wick rejection, body {body_ratio:.0%}"
    
    # === TRIGGER 2: MICRO BOS ON ENTRY TIMEFRAME ===
    # Break of recent swing (last 3-5 candles)
    if direction == 'buy':
        # Bullish micro BOS: break above last 3 candles' highs
        micro_resistance = df['high'].iloc[-4:-1].max()
        if current_close > micro_resistance and current_close > prev_close:
            return True, 'micro_bos', f"Micro BOS: Break above {micro_resistance:.5f} (last 3 bars high)"
    else:
        # Bearish micro BOS: break below last 3 candles' lows
        micro_support = df['low'].iloc[-4:-1].min()
        if current_close < micro_support and current_close < prev_close:
            return True, 'micro_bos', f"Micro BOS: Break below {micro_support:.5f} (last 3 bars low)"
    
    # === TRIGGER 3: ENGULFING CANDLE ===
    # Current bar completely engulfs previous bar
    if direction == 'buy':
        # Bullish engulfing: current opens below prev close, closes above prev open
        if current_open < prev_close and current_close > prev_open and body > abs(prev_close - prev_open):
            engulf_ratio = body / abs(prev_close - prev_open)
            return True, 'engulfing', f"Bullish engulfing: {engulf_ratio:.1f}x previous bar size"
    else:
        # Bearish engulfing: current opens above prev close, closes below prev open
        if current_open > prev_close and current_close < prev_open and body > abs(prev_close - prev_open):
            engulf_ratio = body / abs(prev_close - prev_open)
            return True, 'engulfing', f"Bearish engulfing: {engulf_ratio:.1f}x previous bar size"
    
    # === TRIGGER 4: STRONG DISPLACEMENT CANDLE ===
    # Large body (>60% of range) in direction with momentum
    if direction == 'buy':
        # Bullish displacement: large green candle, closes in upper 60%
        if body_ratio > 0.60 and current_close > current_open and current_close > prev_close:
            return True, 'displacement', f"Strong bullish displacement: {body_ratio:.0%} body, closes upper {100-((current_high-current_close)/(current_high-current_low)*100):.0f}%"
    else:
        # Bearish displacement: large red candle, closes in lower 60%
        if body_ratio > 0.60 and current_close < current_open and current_close < prev_close:
            return True, 'displacement', f"Strong bearish displacement: {body_ratio:.0%} body, closes lower {((current_close-current_low)/(current_high-current_low)*100):.0f}%"
    
    # No trigger confirmed
    return False, 'none', "No valid entry trigger detected - wait for candle close confirmation"

def detect_htf_bias(df_h1=None, df_m15=None, signal_direction="buy"):
    """
    LAYER 1: HTF BIAS DETECTION - Prevents early entries without HTF confirmation.
    
    Detects higher timeframe trend bias using three methods:
    1. Higher High / Higher Low (bullish) vs Lower High / Lower Low (bearish)
    2. Price vs EMA 50/200
    3. Recent BOS direction
    
    Returns: (bias_direction: str, bias_strength: float, bias_reason: str)
    - bias_direction: 'bullish', 'bearish', or 'neutral'
    - bias_strength: 0.0-1.0 (1.0 = strong confirmation)
    - bias_reason: String explaining the bias source
    """
    
    bias_direction = 'neutral'
    bias_strength = 0.0
    bias_reasons = []
    
    # === METHOD 1: TREND FROM HIGHER HIGHS/LOWS (Most reliable) ===
    if df_h1 is not None and len(df_h1) >= 50:
        # Analyze last 50 candles on H1
        lookback = 50
        
        # Count higher highs and higher lows (bullish trend)
        higher_highs = 0
        higher_lows = 0
        lower_highs = 0
        lower_lows = 0
        
        for i in range(-lookback, -1):
            if i < -lookback + 1:  # Need previous candle to compare
                continue
            curr_high = df_h1['high'].iloc[i]
            prev_high = df_h1['high'].iloc[i-1]
            curr_low = df_h1['low'].iloc[i]
            prev_low = df_h1['low'].iloc[i-1]
            
            if curr_high > prev_high:
                higher_highs += 1
            else:
                lower_highs += 1
            
            if curr_low > prev_low:
                higher_lows += 1
            else:
                lower_lows += 1
        
        # Bullish: More higher highs AND higher lows
        bullish_count = higher_highs + higher_lows
        bearish_count = lower_highs + lower_lows
        
        if bullish_count > bearish_count * 1.3:  # 30% margin
            bias_direction = 'bullish'
            bias_strength = min(1.0, bullish_count / (bullish_count + bearish_count))
            bias_reasons.append(f"Higher Highs/Lows: {higher_highs} HH, {higher_lows} HL > {lower_highs} LH, {lower_lows} LL")
        elif bearish_count > bullish_count * 1.3:
            bias_direction = 'bearish'
            bias_strength = min(1.0, bearish_count / (bullish_count + bearish_count))
            bias_reasons.append(f"Lower Highs/Lows: {lower_highs} LH, {lower_lows} LL > {higher_highs} HH, {higher_lows} HL")
    
    # === METHOD 2: PRICE VS EMA 50/200 (Confirmation) ===
    if df_h1 is not None and len(df_h1) >= 200:
        try:
            # Calculate EMA 50 and EMA 200
            ema_50 = df_h1['close'].ewm(span=50, adjust=False).mean()
            ema_200 = df_h1['close'].ewm(span=200, adjust=False).mean()
            
            current_price = df_h1['close'].iloc[-1]
            current_ema_50 = ema_50.iloc[-1]
            current_ema_200 = ema_200.iloc[-1]
            
            # Bullish: Price above both EMAs, EMA50 above EMA200
            if current_price > current_ema_50 > current_ema_200:
                ema_bias = 'bullish'
                ema_strength = 1.0
            # Bearish: Price below both EMAs, EMA50 below EMA200
            elif current_price < current_ema_50 < current_ema_200:
                ema_bias = 'bearish'
                ema_strength = 1.0
            # Partial bullish: Price above EMA50
            elif current_price > current_ema_50:
                ema_bias = 'bullish'
                ema_strength = 0.6
            # Partial bearish: Price below EMA50
            elif current_price < current_ema_50:
                ema_bias = 'bearish'
                ema_strength = 0.6
            else:
                ema_bias = 'neutral'
                ema_strength = 0.0
            
            if ema_bias != 'neutral':
                bias_reasons.append(f"EMA50/200: Price {current_price:.5f} vs EMA50 {current_ema_50:.5f} vs EMA200 {current_ema_200:.5f} = {ema_bias.upper()}")
                # If no trend detected yet, use EMA bias
                if bias_direction == 'neutral':
                    bias_direction = ema_bias
                    bias_strength = ema_strength
                # If trend detected, boost strength if EMA agrees
                elif bias_direction == ema_bias:
                    bias_strength = min(1.0, bias_strength + ema_strength * 0.3)  # Boost existing bias
        except Exception as e:
            pass
    
    # === METHOD 3: RECENT BOS DIRECTION (Confirmation from M15) ===
    if df_m15 is not None and len(df_m15) >= 30:
        try:
            # Look for recent BOS on M15 (last 30 candles = 7.5 hours)
            for i in range(-30, -1):
                # Simple BOS: Recent swing low/high broken
                if i < -20:  # Look in last 20 candles
                    swing_high = df_m15['high'].iloc[i:i+5].max()
                    swing_low = df_m15['low'].iloc[i:i+5].min()
                    recent_high = df_m15['high'].iloc[-1]
                    recent_low = df_m15['low'].iloc[-1]
                    
                    # Bullish BOS: Recent break above swing high
                    if recent_high > swing_high and df_m15['close'].iloc[-1] > df_m15['open'].iloc[-1]:
                        bias_reasons.append(f"Recent M15 BOS: Bullish break above {swing_high:.5f}")
                        if bias_direction == 'neutral':
                            bias_direction = 'bullish'
                            bias_strength = 0.7
                        break
                    # Bearish BOS: Recent break below swing low
                    elif recent_low < swing_low and df_m15['close'].iloc[-1] < df_m15['open'].iloc[-1]:
                        bias_reasons.append(f"Recent M15 BOS: Bearish break below {swing_low:.5f}")
                        if bias_direction == 'neutral':
                            bias_direction = 'bearish'
                            bias_strength = 0.7
                        break
        except Exception as e:
            pass
    
    bias_reason = " | ".join(bias_reasons) if bias_reasons else "Insufficient data for HTF bias"
    
    return bias_direction, bias_strength, bias_reason

# ═══════════════════════════════════════════════════════════════════════════════
# ADVANCED RSI MOMENTUM CONFIRMATION SYSTEM
# ═══════════════════════════════════════════════════════════════════════════════
# Multi-level RSI analysis for reliable momentum verification
# ═══════════════════════════════════════════════════════════════════════════════

def calculate_advanced_rsi(df, period=14):
    """Calculate RSI using standard formula."""
    if len(df) < period:
        return None
    
    delta = df['close'].diff()
    gain = delta.where(delta > 0, 0).rolling(window=period).mean()
    loss = -delta.where(delta < 0, 0).rolling(window=period).mean()
    
    rs = gain / loss
    rsi = 100 - (100 / (1 + rs))
    return rsi.iloc[-1]


def detect_rsi_momentum_confirmation(df, direction, symbol=""):
    """
    🚀 ADVANCED RSI MOMENTUM CONFIRMATION - Multi-Level System
    
    BUY confirmation requires ANY of these RSI conditions:
    1. RSI crossover above 50 (bullish midline break)
    2. RSI divergence: price made lower low but RSI made higher low (bullish diverg)
    3. RSI exit from oversold (<30) with upward momentum
    4. RSI slope is positive (accelerating bullish momentum)
    5. RSI 50EMA (smoothed RSI) is above 50 (sustained bullish)
    
    SELL confirmation requires ANY of these RSI conditions:
    1. RSI crossover below 50 (bearish midline break)
    2. RSI divergence: price made higher high but RSI made lower high (bearish diverg)
    3. RSI exit from overbought (>70) with downward momentum
    4. RSI slope is negative (accelerating bearish momentum)
    5. RSI 50EMA (smoothed RSI) is below 50 (sustained bearish)
    
    Args:
        df: OHLCV DataFrame (M5 timeframe recommended)
        direction: 'buy' or 'sell'
        symbol: For logging
    
    Returns:
        {
            'momentum_confirmed': bool,
            'rsi_value': float,
            'rsi_signal': str,  # Description of which condition triggered
            'strength': float,  # 0.0 to 1.0 confidence score
            'reasons': [list of passing conditions],
            'failed_reasons': [list of failing conditions]
        }
    """
    
    result = {
        'momentum_confirmed': False,
        'rsi_value': None,
        'rsi_signal': '',
        'strength': 0.0,
        'reasons': [],
        'failed_reasons': []
    }
    
    try:
        if len(df) < 20:
            result['failed_reasons'].append('Insufficient data (< 20 candles)')
            return result
        
        # ═══ Calculate RSI variants ═══
        rsi_14 = calculate_advanced_rsi(df, period=14)
        rsi_7 = calculate_advanced_rsi(df, period=7)   # Fast RSI for momentum
        rsi_21 = calculate_advanced_rsi(df, period=21)  # Slow RSI for confirmation
        
        if rsi_14 is None:
            result['failed_reasons'].append('RSI calculation failed')
            return result
        
        result['rsi_value'] = rsi_14
        
        # ═══ Calculate RSI slope (momentum acceleration) ═══
        rsi_values = []
        for period in [14]:
            if len(df) >= period:
                delta = df['close'].diff()
                gain = delta.where(delta > 0, 0).rolling(window=period).mean()
                loss = -delta.where(delta < 0, 0).rolling(window=period).mean()
                rs = gain / loss
                rsi = 100 - (100 / (1 + rs))
                rsi_values = rsi.tail(3).values  # Last 3 RSI values
        
        rsi_slope = 0
        if len(rsi_values) >= 2:
            rsi_slope = rsi_values[-1] - rsi_values[-2]  # Current slope
        
        # ═══ Calculate smoothed RSI (50 EMA of RSI) ═══
        rsi_raw = []
        for i in range(len(df)):
            delta_i = df['close'].iloc[max(0, i-14):i+1].diff()
            gain_i = delta_i.where(delta_i > 0, 0).mean()
            loss_i = -delta_i.where(delta_i < 0, 0).mean()
            if loss_i != 0:
                rs_i = gain_i / loss_i
                rsi_i = 100 - (100 / (1 + rs_i))
            else:
                rsi_i = 50
            rsi_raw.append(rsi_i)
        
        rsi_df = pd.DataFrame({'rsi': rsi_raw})
        rsi_ema_50 = rsi_df['rsi'].ewm(span=50).mean().iloc[-1]
        
        # ═══ Detect RSI divergence ═══
        def detect_divergence(df_prices, df_rsi_vals, lookback=15):
            """Detect bullish/bearish divergence."""
            if len(df_prices) < lookback:
                return None
            
            recent_prices = df_prices['close'].tail(lookback).values
            recent_rsi = df_rsi_vals[-lookback:]
            
            # Find price extremes and RSI extremes
            price_low_idx = recent_prices.argmin()
            price_high_idx = recent_prices.argmax()
            rsi_low_idx = np.argmin(recent_rsi)
            rsi_high_idx = np.argmax(recent_rsi)
            
            # Bullish divergence: price lower low, but RSI higher low
            if price_low_idx > rsi_low_idx:  # Current low is more recent
                if recent_prices[price_low_idx] < recent_prices[rsi_low_idx]:
                    if recent_rsi[price_low_idx] > recent_rsi[rsi_low_idx]:
                        return 'bullish'
            
            # Bearish divergence: price higher high, but RSI lower high
            if price_high_idx > rsi_high_idx:  # Current high is more recent
                if recent_prices[price_high_idx] > recent_prices[rsi_high_idx]:
                    if recent_rsi[price_high_idx] < recent_rsi[rsi_high_idx]:
                        return 'bearish'
            
            return None
        
        divergence = detect_divergence(df, rsi_raw, lookback=15)
        
        # ═══ BUILD CONFIRMATION CONDITIONS ═══
        
        if direction.lower() == 'buy':
            # Condition 1: RSI crossover above 50 (bullish midline break)
            if len(rsi_values) >= 2:
                if rsi_values[-2] <= 50 and rsi_14 > 50:
                    result['reasons'].append('RSI crossover above 50 (bullish midline break)')
                    result['strength'] += 0.2
                else:
                    result['failed_reasons'].append(f'No RSI crossover above 50 (currently {rsi_14:.1f})')
            
            # Condition 2: Bullish divergence detected
            if divergence == 'bullish':
                result['reasons'].append('Bullish RSI divergence (price lower, RSI higher)')
                result['strength'] += 0.25
            else:
                result['failed_reasons'].append('No bullish RSI divergence')
            
            # Condition 3: RSI exiting oversold zone with upward momentum
            if rsi_14 > 30 and len(rsi_values) >= 2 and rsi_values[-2] <= 30:
                result['reasons'].append(f'RSI exiting oversold (<30) - now {rsi_14:.1f}')
                result['strength'] += 0.2
            elif rsi_14 > 30:
                result['failed_reasons'].append(f'RSI not exiting oversold (currently {rsi_14:.1f})')
            
            # Condition 4: RSI slope is positive (accelerating)
            if rsi_slope > 0.5:
                result['reasons'].append(f'RSI momentum accelerating (slope +{rsi_slope:.2f})')
                result['strength'] += 0.15
            elif rsi_slope > 0:
                result['failed_reasons'].append(f'RSI slope positive but weak ({rsi_slope:.2f})')
            else:
                result['failed_reasons'].append(f'RSI slope not positive ({rsi_slope:.2f})')
            
            # Condition 5: RSI EMA above 50 (sustained bullish)
            if rsi_ema_50 > 50:
                result['reasons'].append(f'RSI 50EMA above 50 (sustained bullish {rsi_ema_50:.1f})')
                result['strength'] += 0.2
            else:
                result['failed_reasons'].append(f'RSI 50EMA below 50 (currently {rsi_ema_50:.1f})')
            
            # Condition 6: Fast RSI (7) above Slow RSI (21) = momentum
            if rsi_7 is not None and rsi_21 is not None and rsi_7 > rsi_21:
                result['reasons'].append(f'Fast RSI ({rsi_7:.1f}) > Slow RSI ({rsi_21:.1f}) = momentum')
                result['strength'] += 0.15
            
        elif direction.lower() == 'sell':
            # Condition 1: RSI crossover below 50 (bearish midline break)
            if len(rsi_values) >= 2:
                if rsi_values[-2] >= 50 and rsi_14 < 50:
                    result['reasons'].append('RSI crossover below 50 (bearish midline break)')
                    result['strength'] += 0.2
                else:
                    result['failed_reasons'].append(f'No RSI crossover below 50 (currently {rsi_14:.1f})')
            
            # Condition 2: Bearish divergence detected
            if divergence == 'bearish':
                result['reasons'].append('Bearish RSI divergence (price higher, RSI lower)')
                result['strength'] += 0.25
            else:
                result['failed_reasons'].append('No bearish RSI divergence')
            
            # Condition 3: RSI exiting overbought zone with downward momentum
            if rsi_14 < 70 and len(rsi_values) >= 2 and rsi_values[-2] >= 70:
                result['reasons'].append(f'RSI exiting overbought (>70) - now {rsi_14:.1f}')
                result['strength'] += 0.2
            elif rsi_14 < 70:
                result['failed_reasons'].append(f'RSI not exiting overbought (currently {rsi_14:.1f})')
            
            # Condition 4: RSI slope is negative (accelerating)
            if rsi_slope < -0.5:
                result['reasons'].append(f'RSI momentum accelerating downward (slope {rsi_slope:.2f})')
                result['strength'] += 0.15
            elif rsi_slope < 0:
                result['failed_reasons'].append(f'RSI slope negative but weak ({rsi_slope:.2f})')
            else:
                result['failed_reasons'].append(f'RSI slope not negative ({rsi_slope:.2f})')
            
            # Condition 5: RSI EMA below 50 (sustained bearish)
            if rsi_ema_50 < 50:
                result['reasons'].append(f'RSI 50EMA below 50 (sustained bearish {rsi_ema_50:.1f})')
                result['strength'] += 0.2
            else:
                result['failed_reasons'].append(f'RSI 50EMA above 50 (currently {rsi_ema_50:.1f})')
            
            # Condition 6: Fast RSI (7) below Slow RSI (21) = momentum
            if rsi_7 is not None and rsi_21 is not None and rsi_7 < rsi_21:
                result['reasons'].append(f'Fast RSI ({rsi_7:.1f}) < Slow RSI ({rsi_21:.1f}) = momentum')
                result['strength'] += 0.15
        
        # ═══ DECISION: Need at least 2 conditions OR strength > 0.4 ═══
        conditions_met = len(result['reasons'])
        result['momentum_confirmed'] = (conditions_met >= 2) or (result['strength'] > 0.4)
        
        if result['momentum_confirmed']:
            result['rsi_signal'] = f"✅ MOMENTUM CONFIRMED ({conditions_met} condition(s) | strength {result['strength']:.1%})"
        else:
            result['rsi_signal'] = f"❌ Momentum insufficient ({conditions_met} condition(s) | strength {result['strength']:.1%})"
        
        return result
    
    except Exception as e:
        result['failed_reasons'].append(f'Exception: {str(e)}')
        return result


