# === UNIFIED GATEKEEPER FUNCTIONS ===
def is_ranging_market(df, atr, atr_threshold=0.6):
    recent = df.iloc[-20:]
    high = recent['high'].max()
    low = recent['low'].min()
    range_size = high - low
    if atr == 0:
        return True
    if range_size < atr * atr_threshold:
        return True
    bodies = abs(recent['close'] - recent['open'])
    avg_body = bodies.mean()
    if avg_body < atr * 0.2:
        return True
    return False

def validate_entry(df, direction, htf_trend, atr, confidence):
    score = 0
    if direction == "buy" and htf_trend == "bull":
        score += 2
    elif direction == "sell" and htf_trend == "bear":
        score += 2
    else:
        return False, "HTF trend conflict"
    # BOS (MANDATORY)
    if not detect_bos(df, is_bullish=(direction == "buy")):
        return False, "No BOS"
    score += 1
    # LIQUIDITY SWEEP (HIGH VALUE)
    sweep_high, sweep_low, _ = detect_liquidity_sweep(df)
    if direction == "buy" and sweep_low:
        score += 1
    elif direction == "sell" and sweep_high:
        score += 1
    # CONFIDENCE FILTER
    if confidence < 0.7:
        return False, "Low ML confidence"
    if score < 3:
        return False, "Low confluence"
    return True, "Valid structure entry"

def _pip_settings(symbol: str):
    """Return (pip_size, min_sl_pips, max_sl_pips) tuned per asset family."""
    sym = (symbol or "").upper()
    if "XAU" in sym or "XAG" in sym:
        return 0.1, 50, 400  # metals: larger pip and wider bounds
    if "JPY" in sym:
        return 0.01, 12, 120  # JPY pairs
    if sym.startswith(("NAS", "US30", "SPX", "GER", "UK")):
        return 1.0, 80, 800   # indices, rough defaults
    return 0.0001, 8, 80      # majors/minors FX


def calculate_sl_tp(entry, direction, df, atr, rr=2.0, symbol=None):
    """
    Volatility-adapted SL/TP with ATR but CLAMPED per-asset so EURUSD doesn't get
    “gold-sized” distances.

    SL Formula: max(structure_SL, ATR * 1.2) with ATR capped to max_sl_pips
    TP Formula: min(opposing_structure, entry + SL*RR) capped by structure
    """
    pip_size, min_sl_pips, max_sl_pips = _pip_settings(symbol)

    # Convert ATR to pips and clamp to sane range
    try:
        atr_pips = max(atr / pip_size, 0)
    except Exception:
        atr_pips = min_sl_pips
    atr_pips = min(max(atr_pips, min_sl_pips), max_sl_pips)
    atr_sl_pips = atr_pips * 1.2

    if direction == "buy":
        structure_low = df['low'].iloc[-10:].min()
        structure_sl = structure_low - (2 * pip_size)  # small buffer

        sl_distance = max(atr_sl_pips, min_sl_pips) * pip_size
        atr_sl = entry - sl_distance

        sl = max(structure_sl, atr_sl)

        opposing_structure = df['high'].iloc[-10:].max()
        rr_target = entry + (entry - sl) * rr
        tp = min(opposing_structure, rr_target)

    else:  # sell
        structure_high = df['high'].iloc[-10:].max()
        structure_sl = structure_high + (2 * pip_size)

        sl_distance = max(atr_sl_pips, min_sl_pips) * pip_size
        atr_sl = entry + sl_distance

        sl = max(structure_sl, atr_sl)

        opposing_structure = df['low'].iloc[-10:].min()
        rr_target = entry - (sl - entry) * rr
        tp = max(opposing_structure, rr_target)

    return round(sl, 5), round(tp, 5)

