SNIPER_MAX_SPREAD = 0.8        # dollars for XAU or pips-equivalent for FX — keep conservative
SNIPER_MAX_LOT = 0.1          # always open small when using sniper entry
SNIPER_USE_LIMIT_ON_RETEST = True
