import smtplib
from email.mime.text import MIMEText

def send_email(subject, body, to_email, from_email, smtp_server, smtp_port, smtp_user, smtp_password):
    msg = MIMEText(body)
    msg["Subject"] = subject
    msg["From"] = from_email
    msg["To"] = to_email
    try:
        with smtplib.SMTP_SSL(smtp_server, smtp_port) as server:
            server.login(smtp_user, smtp_password)
            server.sendmail(from_email, [to_email], msg.as_string())
    except Exception as e:
        print(f"[EMAIL ERROR] {e}")

import threading
from concurrent.futures import ThreadPoolExecutor, as_completed

ORDER_SEND_LOCK = threading.Lock()
ORDER_RETRY_LIMIT = 3
ORDER_RETRY_DELAY = 2  # seconds (will use exponential backoff)
ORDER_SEND_TIMEOUT = 10  # seconds timeout per attempt
TRADE_JOURNAL_FILE = "trade_journal.csv"

# Per-symbol cooldown tracking (symbol -> last trade time)
SYMBOL_COOLDOWN_MAP = {}
SYMBOL_COOLDOWN_MINUTES = 15  # min cooldown between trades per symbol
# Per-session trade counters: {(symbol, session_date): count}
SYMBOL_SESSION_TRADES = {}
MAX_TRADES_PER_SYMBOL_SESSION = getattr(config, 'max_trades_per_symbol_session', float('inf')) if config else float('inf')  # UNLIMITED

# File where per-session trade counters are persisted
SESSION_TRADES_FILE = getattr(config, 'SESSION_TRADES_FILE', 'session_trades.json') if config else 'session_trades.json'

# File where symbol cooldowns are persisted
SESSION_COOLDOWNS_FILE = getattr(config, 'SESSION_COOLDOWNS_FILE', 'symbol_cooldowns.json') if config else 'symbol_cooldowns.json'

# --- Session symbol control & rotation ---
# Max number of symbols to trade concurrently during a session (to avoid trading all symbols)
MAX_CONCURRENT_SYMBOLS = getattr(config, 'max_concurrent_symbols', 6) if config else 6
# Optional per-session allowed symbols mapping in config (e.g., {'London': ['EURUSD.m','GBPUSD.m'], 'Asian': [...]})
SESSION_ALLOWED_SYMBOLS = getattr(config, 'SESSION_ALLOWED_SYMBOLS', None) if config else None
# Optional per-session max concurrent symbols (overrides `MAX_CONCURRENT_SYMBOLS` when present)
SESSION_MAX_CONCURRENT = getattr(config, 'SESSION_MAX_CONCURRENT', {
    'Asian': 2,
    'London': 3,
    'New York': 3,
    'NY Reversal': 2,
    'Other': 2
}) if config else {
    'Asian': 2,
    'London': 3,
    'New York': 3,
    'NY Reversal': 2,
    'Other': 2
}
# If no explicit `SESSION_ALLOWED_SYMBOLS` provided in config, use a sensible default
if not SESSION_ALLOWED_SYMBOLS:
    SESSION_ALLOWED_SYMBOLS = {
        'Asian': ['XAUUSD.m', 'NZDUSD.m'],
        'London': ['EURUSD.m', 'GBPUSD.m', 'XAUUSD.m', 'USDJPY.m'],
        'New York': ['EURUSD.m', 'GBPUSD.m', 'XAUUSD.m', 'USDJPY.m', 'BTCUSD.m'],
        'NY Reversal': ['XAUUSD.m', 'EURUSD.m', 'USDJPY.m'],
        'Other': ['XAUUSD.m', 'EURUSD.m', 'GBPUSD.m', 'NZDUSD.m', 'USDJPY.m']
    }
# Rotation state file to persist rotation index between restarts
ROTATION_STATE_FILE = getattr(config, 'ROTATION_STATE_FILE', 'rotation_state.json') if config else 'rotation_state.json'

def load_rotation_state(path=None):
    path = path or ROTATION_STATE_FILE
    try:
        if os.path.exists(path):
            with open(path, 'r') as f:
                data = json.load(f)
                return int(data.get('index', 0))
    except Exception as e:
        logging.debug(f"[ROTATION] Failed to load rotation state: {e}")
    return 0

def save_rotation_state(index, path=None):
    path = path or ROTATION_STATE_FILE
    try:
        with open(path, 'w') as f:
            json.dump({'index': int(index)}, f)
    except Exception as e:
        logging.debug(f"[ROTATION] Failed to save rotation state: {e}")

# Rotation index (persisted)
ROTATION_INDEX = load_rotation_state()

def is_symbol_allowed_in_session(symbol, session_name):
    """Return True if symbol is allowed in the given session based on SESSION_ALLOWED_SYMBOLS config.
    If SESSION_ALLOWED_SYMBOLS is None, all symbols allowed by default."""
    if not SESSION_ALLOWED_SYMBOLS:
        return True
    try:
        allowed = SESSION_ALLOWED_SYMBOLS.get(session_name)
        if allowed is None:
            # If no mapping for this session, allow all
            return True
        return symbol in allowed
    except Exception:
        return True

def select_symbols_for_session(all_symbols, session_name, max_concurrent=None):
    """Return a list of symbols allowed to trade this session. Implements rotation and max concurrent limit."""
    global ROTATION_INDEX
    # Determine concurrency: explicit arg > per-session config > global default
    if max_concurrent is None:
        try:
            max_concurrent = int(SESSION_MAX_CONCURRENT.get(session_name, MAX_CONCURRENT_SYMBOLS))
        except Exception:
            max_concurrent = MAX_CONCURRENT_SYMBOLS
    # Filter by session mapping
    allowed_symbols = [s for s in all_symbols if is_symbol_allowed_in_session(s, session_name)]
    if not allowed_symbols:
        return []
    # If allowed count <= max_concurrent, return all
    if len(allowed_symbols) <= max_concurrent:
        return allowed_symbols
    # Use rotation index to pick a slice of symbols
    start = ROTATION_INDEX % len(allowed_symbols)
    selected = []
    i = start
    while len(selected) < max_concurrent:
        selected.append(allowed_symbols[i])
        i = (i + 1) % len(allowed_symbols)
    # Advance rotation index for next call and persist
    ROTATION_INDEX = (start + 1) % len(allowed_symbols)
    try:
        save_rotation_state(ROTATION_INDEX)
    except Exception:
        pass
    return selected

def _session_key(symbol, session_name=None):
    """Return a string session key for per-session counting: 'SYMBOL|YYYY-MM-DD' or 'SYMBOL|YYYY-MM-DD:SESSION'."""
    date_str = datetime.now(timezone.utc).strftime('%Y-%m-%d')
    if session_name:
        return f"{symbol}|{date_str}:{session_name}"
    return f"{symbol}|{date_str}"

def can_trade_symbol_session(symbol, session_name=None):
    """Return True if symbol hasn't exceeded per-session trade limit."""
    key = _session_key(symbol, session_name)
    return SYMBOL_SESSION_TRADES.get(key, 0) < MAX_TRADES_PER_SYMBOL_SESSION

def record_symbol_session_trade(symbol, session_name=None, persist=True):
    """Increment session trade count for symbol and optionally persist to disk."""
    key = _session_key(symbol, session_name)
    SYMBOL_SESSION_TRADES[key] = SYMBOL_SESSION_TRADES.get(key, 0) + 1
    if persist:
        try:
            save_session_trades_to_file()
        except Exception:
            logging.debug("[SESSION_TRADES] Failed to persist session trades to file.")

def save_session_trades_to_file(path=None):
    """Persist SYMBOL_SESSION_TRADES to a JSON file."""
    path = path or SESSION_TRADES_FILE
    try:
        with open(path, 'w') as f:
            json.dump(SYMBOL_SESSION_TRADES, f, indent=2, default=int)
    except Exception as e:
        logging.error(f"[SESSION_TRADES] Failed to save session trades to {path}: {e}")

def load_session_trades_from_file(path=None):
    """Load SYMBOL_SESSION_TRADES from JSON file if present."""
    global SYMBOL_SESSION_TRADES
    path = path or SESSION_TRADES_FILE
    try:
        if os.path.exists(path):
            with open(path, 'r') as f:
                data = json.load(f)
                # Ensure keys are strings and values are ints
                SYMBOL_SESSION_TRADES = {str(k): int(v) for k, v in data.items()}
    except Exception as e:
        logging.error(f"[SESSION_TRADES] Failed to load session trades from {path}: {e}")

# Load persisted session trades at startup
try:
    load_session_trades_from_file()
except Exception:
    pass


def save_symbol_cooldowns_to_file(path=None):
    """Persist SYMBOL_COOLDOWN_MAP to JSON file (timestamps as ISO strings)."""
    path = path or SESSION_COOLDOWNS_FILE
    try:
        out = {k: v.isoformat() if hasattr(v, 'isoformat') else str(v) for k, v in SYMBOL_COOLDOWN_MAP.items()}
        with open(path, 'w') as f:
            json.dump(out, f, indent=2)
    except Exception as e:
        logging.error(f"[COOLDOWN] Failed to save symbol cooldowns to {path}: {e}")


def load_symbol_cooldowns_from_file(path=None):
    """Load SYMBOL_COOLDOWN_MAP from JSON file and parse ISO timestamps."""
    global SYMBOL_COOLDOWN_MAP
    path = path or SESSION_COOLDOWNS_FILE
    try:
        if os.path.exists(path):
            with open(path, 'r') as f:
                data = json.load(f)
                parsed = {}
                for k, v in data.items():
                    try:
                        parsed[k] = datetime.fromisoformat(v)
                    except Exception:
                        parsed[k] = datetime.now(timezone.utc)
                SYMBOL_COOLDOWN_MAP = parsed
    except Exception as e:
        logging.error(f"[COOLDOWN] Failed to load symbol cooldowns from {path}: {e}")

# Load persisted symbol cooldowns at startup
try:
    load_symbol_cooldowns_from_file()
except Exception:
    pass

def log_trade_journal(entry):
    """
    Append a trade entry/exit to the trade journal CSV.
    """
    import csv
    import os
    # Safety check: return early if entry is None or not a dict
    if entry is None or not isinstance(entry, dict) or not entry:
        print("[WARNING] log_trade_journal called with None or empty dict, skipping.")
        return
    
    file_exists = os.path.isfile(TRADE_JOURNAL_FILE)
    with open(TRADE_JOURNAL_FILE, "a", newline="") as csvfile:
        writer = csv.DictWriter(csvfile, fieldnames=entry.keys())
        if not file_exists:
            writer.writeheader()
        writer.writerow(entry)

def log_order_request_verbose(order_request, response=None, attempt=0):
    """
    Log order request and response (if available) to stderr and trade_journal for auditing.
    """
    timestamp = datetime.now(timezone.utc).isoformat()
    log_entry = {
        'timestamp': timestamp,
        'type': 'order_request',
        'symbol': order_request.get('symbol', 'N/A'),
        'action': order_request.get('action', 'N/A'),
        'type_order': order_request.get('type', 'N/A'),
        'volume': order_request.get('volume', 0),
        'price': order_request.get('price', 0),
        'sl': order_request.get('sl', 0),
        'tp': order_request.get('tp', 0),
        'attempt': attempt,
        'retcode': getattr(response, 'retcode', 'N/A') if response else 'N/A',
        'response_comment': getattr(response, 'comment', 'N/A') if response else 'N/A',
        'response_order': getattr(response, 'order', 'N/A') if response else 'N/A'
    }
    # Log to stderr for real-time visibility
    logging.info(f"[ORDER] {json.dumps(log_entry)}")
    # Also log to CSV for persistence
    try:
        log_trade_journal(log_entry)
    except Exception as e:
        logging.error(f"[ORDER_LOG] Failed to write to journal: {e}")

def is_symbol_on_cooldown(symbol, cooldown_minutes=None):
    """
    Check if symbol is on cooldown after recent trade.
    Returns True if cooldown is active, False otherwise.
    """
    global SYMBOL_COOLDOWN_MAP
    cooldown_minutes = cooldown_minutes or SYMBOL_COOLDOWN_MINUTES
    if symbol not in SYMBOL_COOLDOWN_MAP:
        return False
    last_trade_time = SYMBOL_COOLDOWN_MAP[symbol]
    elapsed = (datetime.now(timezone.utc) - last_trade_time).total_seconds() / 60
    if elapsed < cooldown_minutes:
        logging.info(f"[COOLDOWN] {symbol} on cooldown for {cooldown_minutes - elapsed:.1f} more minutes")
        return True
    return False

def record_symbol_trade(symbol):
    """Record the current time as the last trade for this symbol."""
    global SYMBOL_COOLDOWN_MAP
    SYMBOL_COOLDOWN_MAP[symbol] = datetime.now(timezone.utc)
    # Persist cooldowns to disk so restarts keep cooldown state
    try:
        save_symbol_cooldowns_to_file()
    except Exception:
        logging.debug("[COOLDOWN] Failed to persist symbol cooldowns to file.")

def async_order_send(order_request):
    """
    Thread-safe, retrying wrapper for mt5.order_send with:
    - Timeout per attempt
    - Exponential backoff retry
    - Verbose logging of request/response
    - Explicit response code checking
    - Final max-entries safety check before sending
    - Volume validation before sending
    """
    # === VOLUME VALIDATION: Check lot size before sending ===
    try:
        symbol = order_request.get('symbol') if isinstance(order_request, dict) else None
        volume = order_request.get('volume') if isinstance(order_request, dict) else None
        
        if symbol and volume is not None and mt5:
            sym_info = mt5.symbol_info(symbol)
            if sym_info:
                min_lot = sym_info.volume_min
                max_lot = sym_info.volume_max
                lot_step = sym_info.volume_step
                
                # Check if volume is within valid range
                if volume < min_lot:
                    print(f"[VOLUME ERROR] {symbol}: Volume {volume:.4f} < min_lot {min_lot:.4f}. Adjusting to min_lot.")
                    order_request['volume'] = min_lot
                    volume = min_lot
                elif volume > max_lot:
                    print(f"[VOLUME ERROR] {symbol}: Volume {volume:.4f} > max_lot {max_lot:.4f}. Adjusting to max_lot.")
                    order_request['volume'] = max_lot
                    volume = max_lot
                
                # Check if volume matches lot_step precision
                if lot_step > 0:
                    # Calculate how many steps
                    steps = round(volume / lot_step)
                    corrected_volume = steps * lot_step
                    
                    # Determine correct decimal precision
                    if lot_step >= 0.01:
                        decimals = 2
                    elif lot_step >= 0.001:
                        decimals = 3
                    elif lot_step >= 0.0001:
                        decimals = 4
                    else:
                        decimals = 5
                    
                    corrected_volume = round(corrected_volume, decimals)
                    
                    if abs(corrected_volume - volume) > 0.00001:
                        print(f"[VOLUME FIX] {symbol}: Correcting volume {volume:.5f} -> {corrected_volume:.5f} (step={lot_step:.5f})")
                        order_request['volume'] = corrected_volume
                        volume = corrected_volume
                
                # Final validation
                if volume < min_lot or volume > max_lot:
                    print(f"[VOLUME REJECTED] {symbol}: Invalid volume {volume:.5f} (min={min_lot:.4f}, max={max_lot:.4f}, step={lot_step:.5f})")
                    class _InvalidVolume:
                        pass
                    res = _InvalidVolume()
                    res.retcode = 10014  # TRADE_RETCODE_INVALID_VOLUME
                    res.order = None
                    res.comment = f"Invalid volume: {volume:.5f} not in range [{min_lot:.4f}, {max_lot:.4f}]"
                    return res
    except Exception as e:
        print(f"[WARNING] Volume validation failed: {e}")
    
    # === FINAL SAFETY CHECK: Max entries before sending ===
    try:
        open_positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
        if open_positions is not None and len(open_positions) >= 5:
            print(f"[ORDER_BLOCKED] Max 10 entries already reached ({len(open_positions)} open). Order NOT sent.")
            # Return a fake failure response 
            class _MaxEntriesReached:
                pass
            res = _MaxEntriesReached()
            res.retcode = getattr(mt5, 'TRADE_RETCODE_REJECT', 10) if 'mt5' in globals() and mt5 else 10
            res.order = None
            res.comment = "Max entries reached - order blocked"
            return res
    except Exception as e:
        print(f"[WARNING] Could not verify max entries before sending: {e}")
    
    # --- MT5 diagnostic: if local terminal/account disallow automated trading, log and short-circuit ---
    def log_mt5_trade_allowed_status(symbol=None):
        """Log terminal/account/symbol trade_allowed flags to help diagnose retcode 10026 errors."""
        try:
            if mt5 is None:
                logging.error("[MT5 DIAG] MetaTrader5 module not available.")
                return
            ti = getattr(mt5, 'terminal_info', lambda: None)()
            ai = getattr(mt5, 'account_info', lambda: None)()
            si = None
            try:
                if symbol:
                    si = getattr(mt5, 'symbol_info', lambda s: None)(symbol)
            except Exception:
                si = None

            logging.error(f"[MT5 DIAG] terminal.trade_allowed={getattr(ti, 'trade_allowed', None)}, terminal.expert_enabled={getattr(ti, 'expert_enabled', None)}")
            logging.error(f"[MT5 DIAG] account.trade_allowed={getattr(ai, 'trade_allowed', None)}, account.login={getattr(ai, 'login', None)}, server={getattr(ai, 'server', None)}")
            logging.error(f"[MT5 DIAG] symbol({symbol}) trade_allowed={getattr(si, 'trade_allowed', None) if si else 'N/A'}, symbol_found={si is not None}")
        except Exception as e:
            logging.error(f"[MT5 DIAG] Failed to fetch trade flags: {e}")

    try:
        # If MT5 reports trading not allowed locally, avoid sending orders and surface diagnostics immediately
        if mt5 is not None:
            try:
                ti = mt5.terminal_info()
            except Exception:
                ti = None
            try:
                ai = mt5.account_info()
            except Exception:
                ai = None

            if (ti is not None and getattr(ti, 'trade_allowed', True) is False) or (ai is not None and getattr(ai, 'trade_allowed', True) is False):
                fake = type('R', (), {})()
                fake.retcode = 10026
                fake.order = None
                fake.comment = "LOCAL_TRADE_DISALLOWED"
                try:
                    log_order_request_verbose(order_request, response=fake, attempt=0)
                except Exception:
                    pass
                log_mt5_trade_allowed_status(order_request.get('symbol'))
                logging.critical("[ORDER_SEND] Local MT5 'trade_allowed' flag is False. Enable Expert Advisors / Allow automated trading in MT5 or contact your broker.")
                return fake
    except Exception:
        # defensive: if diagnostics fail, continue to normal send flow
        pass
    # Determine acceptable slippage (in price units) for this request
    max_slippage = None
    try:
        # Request-level override
        if isinstance(order_request, dict) and 'max_slippage' in order_request:
            max_slippage = float(order_request.get('max_slippage'))
        else:
            max_slippage = float(getattr(config, 'MAX_ACCEPTABLE_SLIPPAGE', 0.0005)) if 'config' in globals() and config else 0.0005
    except Exception:
        max_slippage = 0.0005

    # Respect dry-run mode: print the order_request and return a fake success response (simulate slippage)
    if 'DRY_RUN' in globals() and DRY_RUN:
        log_order_request_verbose(order_request, attempt=0)
        # Simulate spread/slippage: if price provided, add small slippage
        sim_slippage = 0.0
        try:
            # conservative slippage: 0.25 * spread or small default
            sym = order_request.get('symbol') if isinstance(order_request, dict) else None
            spread = get_spread(sym) if sym and 'get_spread' in globals() else 0.0
            sim_slippage = max(0.0, spread * 0.25, float(getattr(config, 'SIMULATED_SLIPPAGE', 0.0001)))
        except Exception:
            sim_slippage = float(getattr(config, 'SIMULATED_SLIPPAGE', 0.0001)) if 'config' in globals() and config else 0.0001
        print(f"[DRY_RUN] Would send order: {order_request} simulated_slippage={sim_slippage}")
        # If simulated slippage exceeds max_slippage, return a fake failure
        class _FakeRes:
            pass
        fake = _FakeRes()
        if sim_slippage > max_slippage:
            fake.retcode = getattr(mt5, 'TRADE_RETCODE_REQUOTE', 101) if 'mt5' in globals() and mt5 is not None else 101
            fake.order = None
            fake.comment = f"DRY_RUN_SLIPPAGE_TOO_HIGH ({sim_slippage})"
            log_order_request_verbose(order_request, response=fake, attempt=0)
            return fake
        fake.retcode = getattr(mt5, 'TRADE_RETCODE_DONE', 100) if 'mt5' in globals() and mt5 is not None else 100
        fake.order = None
        fake.comment = "DRY_RUN"
        log_order_request_verbose(order_request, response=fake, attempt=0)
        return fake
    
    if 'safe_order_send' in globals():
        res = safe_order_send(order_request, retries=ORDER_RETRY_LIMIT)
        log_order_request_verbose(order_request, response=res, attempt=0)
        return res
    
    # Manual retry loop with exponential backoff
    backoff_delay = ORDER_RETRY_DELAY
    for attempt in range(ORDER_RETRY_LIMIT):
        try:
            with ORDER_SEND_LOCK:
                # Set timeout on the order send
                res = None
                try:
                    # MT5 order_send is synchronous, timeout handling is difficult
                    # but we log at least
                    res = mt5.order_send(order_request) if mt5 else None
                except TimeoutError as te:
                    logging.error(f"[ORDER_SEND] Timeout on attempt {attempt+1}: {te}")
                    res = None
            
            # Log the request/response
            log_order_request_verbose(order_request, response=res, attempt=attempt+1)
            
            # Check response codes explicitly
            if res is not None:
                retcode = getattr(res, 'retcode', None)
                if retcode == mt5.TRADE_RETCODE_DONE:
                    logging.info(f"[ORDER_SEND] SUCCESS on attempt {attempt+1}. Order: {getattr(res, 'order', 'N/A')}")
                    return res
                elif retcode == 10026:
                    # AutoTrading disabled by server - critical error, do not retry
                    logging.critical(f"[ORDER_SEND] CRITICAL: AutoTrading disabled by server (retcode 10026).")
                    logging.critical(f"[ORDER_SEND] FIX: Enable Expert Advisors in MT5: Tools → Options → Expert Advisors tab → Check 'Allow automated trading'")
                    logging.critical(f"[ORDER_SEND] Also check: Account → Properties → Automated trading should be 'Enabled'")
                    return res  # Do not retry - this requires manual intervention
                elif retcode in (getattr(mt5, 'TRADE_RETCODE_TRADE_DISABLED', 10017), 10017):
                    # Trade disabled: either account or symbol not allowed for trading
                    logging.critical(f"[ORDER_SEND] CRITICAL: Trade disabled (retcode {retcode}). Symbol={order_request.get('symbol') if isinstance(order_request, dict) else None}")
                    try:
                        log_mt5_trade_allowed_status(order_request.get('symbol') if isinstance(order_request, dict) else None)
                    except Exception:
                        pass
                    print("[ORDER_SEND] Trade disabled: enable automated trading in MT5 terminal and ensure symbol trade_allowed=True")
                    return res  # Do not retry - manual intervention needed
                elif retcode in (mt5.TRADE_RETCODE_REQUOTE, mt5.TRADE_RETCODE_MARKET_CLOSED, 
                                 mt5.TRADE_RETCODE_INVALID_PRICE, mt5.TRADE_RETCODE_TIMEOUT):
                    # Retryable errors
                    logging.warning(f"[ORDER_SEND] Retryable error on attempt {attempt+1}: {retcode}. {getattr(res, 'comment', '')}")
                else:
                    # Non-retryable error
                    logging.error(f"[ORDER_SEND] Non-retryable error: {retcode}. {getattr(res, 'comment', '')}")
                    return res
            else:
                logging.error(f"[ORDER_SEND] Null response on attempt {attempt+1}")
        except Exception as e:
            logging.error(f"[ORDER_SEND] Exception on attempt {attempt+1}: {e}")
        
        if attempt < ORDER_RETRY_LIMIT - 1:
            logging.info(f"[ORDER_SEND] Waiting {backoff_delay}s before retry...")
            time.sleep(backoff_delay)
            backoff_delay *= 1.5  # exponential backoff
    
    logging.critical(f"[ORDER_SEND] All {ORDER_RETRY_LIMIT} retry attempts failed.")
    return None
def check_market_structure(price_data, direction, lookback=10):
    """
    Returns a dict with market structure clarity:
    - 'trend': 'bullish', 'bearish', or 'sideways'
    - 'bos': True if Break of Structure (BOS) detected
    - 'choch': True if Change of Character (CHoCH) detected
    - 'fvg_zone': 'premium', 'discount', or None
    - 'structure_ok': True if structure agrees with FVG direction
    """
    if price_data is None or len(price_data) < lookback + 3:
        return {"trend": None, "bos": False, "choch": False, "fvg_zone": None, "structure_ok": False}

    highs = price_data['high'].iloc[-lookback:]
    lows = price_data['low'].iloc[-lookback:]
    last = price_data.iloc[-1]
    prev = price_data.iloc[-2]
    prev2 = price_data.iloc[-3]

    # Trend detection
    if highs.iloc[-1] > highs.iloc[-2] and lows.iloc[-1] > lows.iloc[-2]:
        trend = "bullish"
    elif lows.iloc[-1] < lows.iloc[-2] and highs.iloc[-1] < highs.iloc[-2]:
        trend = "bearish"
    else:
        trend = "sideways"

    # BOS detection
    bos = False
    if direction == "buy":
        bos = last.high > prev.high
    elif direction == "sell":
        bos = last.low < prev.low

    # CHoCH detection (change of character: break in opposite direction)
    choch = False
    if direction == "buy":
        choch = last.low < prev2.low
    elif direction == "sell":
        choch = last.high > prev2.high

    # FVG zone (premium/discount)
    mid = (last.high + last.low) / 2
    fvg_zone = None
    if direction == "buy" and last.close < mid:
        fvg_zone = "discount"
    elif direction == "sell" and last.close > mid:
        fvg_zone = "premium"

    # Structure agrees with FVG direction?
    structure_ok = (trend == "bullish" and direction == "buy") or (trend == "bearish" and direction == "sell")

    return {
        "trend": trend,
        "bos": bos,
        "choch": choch,
        "fvg_zone": fvg_zone,
        "structure_ok": structure_ok
    }

def grade_fvg(price_data, fvg, htf_bias):
    """
    Grades FVG as A/B/C:
    - A: strong displacement, creates BOS, in line with HTF, in premium/discount, liquidity taken before
    - B: missing 1-2 criteria
    - C: weak FVG
    """
    if fvg is None or price_data is None or len(price_data) < 5:
        return "C"
    # 1. Strong displacement
    strong_disp = detect_displacement(price_data)
    # 2. Creates BOS
    last = price_data.iloc[-1]
    is_bullish = last.close > last.open
    bos = detect_bos(price_data, is_bullish)
    # 3. In line with HTF
    htf_ok = htf_bias_aligned(htf_bias, "buy" if is_bullish else "sell")
    # 4. In premium/discount
    in_zone = is_in_premium_discount(price_data, fvg, is_bullish)
    # 5. Liquidity taken before
    liquidity = detect_liquidity_sweep(price_data)
    score = sum([strong_disp, bos, htf_ok, in_zone, liquidity])
    if score == 5:
        return "A"
    elif score >= 3:
        return "B"
    else:
        return "C"

def is_in_premium_discount(price_data, fvg, is_bullish):
    """
    Checks if FVG is in premium (bearish) or discount (bullish) zone.
    """
    if price_data is None or fvg is None:
        return False
    last = price_data.iloc[-1]
    mid = (last.high + last.low) / 2
    fvg_mid = (fvg[0] + fvg[1]) / 2
    if is_bullish:
        return fvg_mid < mid  # Discount
    else:
        return fvg_mid > mid  # Premium

def get_session_name(dt):
    """
    Returns the session name for a given datetime (UTC).
    London: 07:00-16:00 UTC
    New York: 12:00-21:00 UTC
    Asian: 23:00-07:00 UTC
    NY Reversal: 16:00-18:00 UTC
    """
    hour = dt.hour
    if 7 <= hour < 16:
        return "London"
    elif 12 <= hour < 21:
        return "New York"
    elif 16 <= hour < 18:
        return "NY Reversal"
    elif hour >= 23 or hour < 7:
        return "Asian"
    else:
        return "Other"

# ═══════════════════════════════════════════════════════════════════════════════
# PROFESSIONAL SMC/ICT ENTRY FILTERS
# ═══════════════════════════════════════════════════════════════════════════════

def require_previous_extreme_sweep(price_data, direction, lookback=20):
    """
    FILTER 1: Require that price has swept the previous LOW (BUY) or HIGH (SELL).
    
    This is the PRE-TRADE confirmation:
    - BUY: Current low must be BELOW previous swing low (liquidity sweep)
    - SELL: Current high must be ABOVE previous swing high (liquidity sweep)
    
    Returns (swept: bool, sweep_level: float, swing_bar_index: int)
    """
    if price_data is None or len(price_data) < lookback + 2:
        return False, None, None
    
    recent = price_data.iloc[-lookback:]
    current_bar = price_data.iloc[-1]
    
    # Find the previous swing high/low (before current bar)
    if direction == "buy":
        # Find lowest low in recent bars (excluding current bar, looking back)
        swing_low = recent.iloc[:-1]['low'].min()
        swing_idx = recent.iloc[:-1]['low'].idxmin()
        # Check if current bar LOW swept below that swing low
        swept = current_bar['low'] < swing_low
        return swept, swing_low, swing_idx
    
    elif direction == "sell":
        # Find highest high in recent bars (excluding current bar, looking back)
        swing_high = recent.iloc[:-1]['high'].max()
        swing_idx = recent.iloc[:-1]['high'].idxmax()
        # Check if current bar HIGH swept above that swing high
        swept = current_bar['high'] > swing_high
        return swept, swing_high, swing_idx
    
    return False, None, None


def detect_fvg_retrace(price_data, direction, lookback=15):
    """
    FILTER 2: Detect that price has created a FVG and is now retracing BACK INTO it.
    
    This confirms the smart money structure:
    - BUY: Created bullish FVG (discount zone) → price pulled back into it for entry
    - SELL: Created bearish FVG (premium zone) → price pulled back into it for entry
    
    FVG = 3 consecutive candles where:
    - Candle 1 and 3 don't overlap (imbalance)
    - Candle 2 is between them
    
    Returns (in_retrace_zone: bool, fvg_low: float, fvg_high: float, fvg_confirmed: bool)
    """
    if price_data is None or len(price_data) < 5:
        return False, None, None, False
    
    recent = price_data.iloc[-lookback:]
    current_price = recent['close'].iloc[-1]
    
    # Scan for FVG: 3 consecutive bars with imbalance
    fvg_confirmed = False
    fvg_low = None
    fvg_high = None
    
    for i in range(len(recent) - 3):
        bar1 = recent.iloc[i]
        bar2 = recent.iloc[i + 1]
        bar3 = recent.iloc[i + 2]
        
        # Bullish FVG: bar1 high < bar3 low (discount imbalance)
        if direction == "buy":
            if bar1['high'] < bar3['low']:
                fvg_low = bar1['high']
                fvg_high = bar3['low']
                fvg_confirmed = True
                break
        
        # Bearish FVG: bar3 high < bar1 low (premium imbalance)
        elif direction == "sell":
            if bar3['high'] < bar1['low']:
                fvg_low = bar3['high']
                fvg_high = bar1['low']
                fvg_confirmed = True
                break
    
    # Check if price is retracing INTO the FVG zone
    in_retrace_zone = False
    if fvg_confirmed and fvg_low is not None and fvg_high is not None:
        in_retrace_zone = fvg_low <= current_price <= fvg_high
    
    return in_retrace_zone, fvg_low, fvg_high, fvg_confirmed


def get_micro_confirmation(price_data, direction, timeframe_bars=5):
    """
    FILTER 3: Get the FINAL MICRO-CONFIRMATION signal at entry point.
    
    This is the final structural trigger before opening trade:
    - Pin bar rejection (long wick opposite direction)
    - Bullish engulfing (buy direction)
    - Bearish engulfing (sell direction)
    - Hammer/Hanging man patterns
    - Strong close in entry direction
    
    Returns (has_confirmation: bool, confirmation_type: str, strength: float)
    """
    if price_data is None or len(price_data) < timeframe_bars + 1:
        return False, None, 0.0
    
    recent = price_data.iloc[-timeframe_bars:]
    current = price_data.iloc[-1]
    prev = price_data.iloc[-2]
    prev2 = price_data.iloc[-3] if len(price_data) >= 3 else None
    
    confirmation_type = None
    strength = 0.0
    
    if direction == "buy":
        # Pin Bar Bullish: long lower wick, small body, closes in upper half
        wick_length = prev['low'] - min(prev['open'], prev['close'])
        body_length = abs(prev['close'] - prev['open'])
        close_position = (prev['close'] - prev['low']) / (prev['high'] - prev['low']) if prev['high'] > prev['low'] else 0
        
        if wick_length > body_length * 2 and close_position > 0.6:
            confirmation_type = "Pin Bar Bullish"
            strength = min(1.0, wick_length / (prev['high'] - prev['low']))
        
        # Bullish Engulfing: prev bar down, current bar up, current closes above prev open
        elif prev['close'] < prev['open'] and current['close'] > prev['open']:
            confirmation_type = "Bullish Engulfing"
            strength = min(1.0, (current['close'] - prev['open']) / (current['high'] - current['low']) if current['high'] > current['low'] else 1.0)
        
        # Strong Close: current bar closes in top 25% of range
        close_pct = (current['close'] - current['low']) / (current['high'] - current['low']) if current['high'] > current['low'] else 0.5
        if close_pct > 0.75 and current['close'] > current['open']:
            confirmation_type = "Strong Close Buy"
            strength = close_pct
    
    elif direction == "sell":
        # Pin Bar Bearish: long upper wick, small body, closes in lower half
        wick_length = max(prev['open'], prev['close']) - prev['high']
        body_length = abs(prev['close'] - prev['open'])
        close_position = (prev['high'] - prev['close']) / (prev['high'] - prev['low']) if prev['high'] > prev['low'] else 0
        
        if wick_length > body_length * 2 and close_position > 0.6:
            confirmation_type = "Pin Bar Bearish"
            strength = min(1.0, wick_length / (prev['high'] - prev['low']))
        
        # Bearish Engulfing: prev bar up, current bar down, current closes below prev open
        elif prev['close'] > prev['open'] and current['close'] < prev['open']:
            confirmation_type = "Bearish Engulfing"
            strength = min(1.0, (prev['open'] - current['close']) / (current['high'] - current['low']) if current['high'] > current['low'] else 1.0)
        
        # Strong Close: current bar closes in bottom 25% of range
        close_pct = (current['high'] - current['close']) / (current['high'] - current['low']) if current['high'] > current['low'] else 0.5
        if close_pct > 0.75 and current['close'] < current['open']:
            confirmation_type = "Strong Close Sell"
            strength = close_pct
    
    has_confirmation = confirmation_type is not None
    return has_confirmation, confirmation_type, strength


def execute_smc_entry_strict(symbol, price_data, direction, entry_price, sl, tp, lot=0.01,
                             require_sweep=True, require_retrace=True, require_micro=True):
    """
    FILTER 4: STRICT SMC/ICT ENTRY EXECUTION - SEQUENTIAL CONFIRMATION CHAIN
    
    This is the INSTITUTIONAL-GRADE entry logic that chains:
    1. Sweep previous extreme (liquidity grab)
    2. BOS confirmation
    3. Retrace into FVG (pullback for entry)
    4. Micro-confirmation trigger (final structural signal)
    
    ALL 4 must pass for a trade to execute. This is what prop firms use.
    
    Returns (execute: bool, reason: str, confidence: float, details: dict)
    """
    details = {
        "sweep_check": {"passed": False, "level": None, "message": "Not checked"},
        "bos_check": {"passed": False, "message": "Not checked"},
        "retrace_check": {"passed": False, "fvg_low": None, "fvg_high": None, "message": "Not checked"},
        "micro_check": {"passed": False, "type": None, "strength": 0.0, "message": "Not checked"}
    }
    
    execute = False
    reason = "Entry blocked: Filters not passed"
    confidence = 0.0
    
    # --- CHECK 1: PREVIOUS EXTREME SWEEP (Liquidity Grab) ---
    if require_sweep:
        swept, sweep_level, swing_idx = require_previous_extreme_sweep(price_data, direction, lookback=20)
        details["sweep_check"]["passed"] = swept
        details["sweep_check"]["level"] = sweep_level
        
        if swept:
            details["sweep_check"]["message"] = f"✓ Sweep confirmed at {sweep_level:.5f}"
        else:
            details["sweep_check"]["message"] = "✗ No previous extreme sweep detected"
            return False, reason, 0.0, details
    
    # --- CHECK 2: BREAK OF STRUCTURE (BOS) ---
    ms = check_market_structure(price_data, direction, lookback=10)
    bos_passed = ms.get("bos", False)
    details["bos_check"]["passed"] = bos_passed
    
    if bos_passed:
        details["bos_check"]["message"] = "✓ BOS confirmed"
    else:
        details["bos_check"]["message"] = "✗ No Break of Structure"
        if require_sweep:  # Only block if sweep was required
            return False, reason, 0.0, details
    
    # --- CHECK 3: RETRACE INTO FVG (Pullback for Entry) ---
    if require_retrace:
        in_retrace, fvg_low, fvg_high, fvg_ok = detect_fvg_retrace(price_data, direction, lookback=15)
        details["retrace_check"]["passed"] = in_retrace
        details["retrace_check"]["fvg_low"] = fvg_low
        details["retrace_check"]["fvg_high"] = fvg_high
        
        if in_retrace and fvg_ok:
            details["retrace_check"]["message"] = f"✓ Retracing into FVG zone [{fvg_low:.5f} - {fvg_high:.5f}]"
        else:
            details["retrace_check"]["message"] = f"✗ Not in FVG retrace zone (FVG exists: {fvg_ok})"
            return False, reason, 0.0, details
    
    # --- CHECK 4: MICRO-CONFIRMATION (Final Trigger) ---
    if require_micro:
        has_micro, micro_type, micro_strength = get_micro_confirmation(price_data, direction, timeframe_bars=5)
        details["micro_check"]["passed"] = has_micro
        details["micro_check"]["type"] = micro_type
        details["micro_check"]["strength"] = micro_strength
        
        if has_micro:
            details["micro_check"]["message"] = f"✓ {micro_type} (strength: {micro_strength:.2f})"
        else:
            details["micro_check"]["message"] = "✗ No micro-confirmation pattern detected"
            return False, reason, 0.0, details
    
    # --- ALL FILTERS PASSED: EXECUTE ---
    execute = True
    reason = "SMC/ICT Entry Criteria Met: Sweep → BOS → Retrace → Micro"
    # Confidence = average of all check strengths
    all_checks = [
        details["sweep_check"]["passed"],
        details["bos_check"]["passed"],
        details["retrace_check"]["passed"],
        details["micro_check"]["passed"]
    ]
    confidence = sum(all_checks) / len(all_checks) + (details["micro_check"]["strength"] * 0.2)
    confidence = min(1.0, confidence)
    
    return execute, reason, confidence, details

