def gather_sniper_context(symbol, price_data, direction):
    """
    Centralized helper to gather enriched sniper entry context:
    Computes POI (order block), FVG targets, and low-timeframe M1 data.
    Returns dict with keys: poi, fvg, low_tf.
    Defensive: returns empty/None values if any helper fails.
    """
    context = {"poi": None, "fvg": None, "low_tf": None}
    
    # FVG targets from price_data
    try:
        if 'fvg_as_targets' in globals():
            fvg_list = fvg_as_targets(price_data)
            context["fvg"] = fvg_list[0]["fvg"] if fvg_list else None
    except Exception as e:
        logging.debug(f"[SNIPER CONTEXT] FVG extraction error: {e}")
    
    # POI via order block detection (prefer 15m variant)
    try:
        poi_val = None
        if 'detect_order_block_15m' in globals():
            try:
                poi_val = detect_order_block_15m(price_data)
            except Exception:
                poi_val = None
        if poi_val is None and 'detect_order_block' in globals():
            try:
                poi_val = detect_order_block(price_data, context["fvg"], direction)
            except Exception:
                try:
                    poi_val = detect_order_block(price_data)
                except Exception:
                    poi_val = None
        context["poi"] = poi_val
    except Exception as e:
        logging.debug(f"[SNIPER CONTEXT] POI detection error: {e}")
    
    # Low-timeframe M1 data for refined entry checks
    try:
        if 'get_price_data' in globals() and 'mt5' in globals():
            try:
                context["low_tf"] = get_price_data(symbol, timeframe=mt5.TIMEFRAME_M1, bars=15)
            except Exception as e:
                logging.debug(f"[SNIPER CONTEXT] M1 data fetch error: {e}")
    except Exception as e:
        logging.debug(f"[SNIPER CONTEXT] Low-timeframe error: {e}")
    
    return context

# Replace existing sniper_entry_checklist with this scoring-based version
def sniper_entry_checklist(symbol, direction, price_data, htf_bias, poi, fvg, low_tf_data,
                          rr=None, session=None, news_ok=True, ml_confidence=None):
    """
    Scoring-based checklist. Returns (allow:bool, score:int, checklist:dict).
    Each check adds configurable points. Final allow is score >= MIN_SCORE.
    """
    # Configurable thresholds (override via config)
    MIN_BARS_REQUIRED = config.get('min_bars_required', 60)   # previously 200
    MIN_SCORE = config.get('sniper_min_score', 6)
    weights = {
        "HTF Bias": 2,
        "POI/FVG": 2,
        "LTF Confirmation": 2,
        "BOS/CHOCH": 1,
        "Displacement": 1,
        "FVG Fill/Return": 1,
        "Liquidity Sweep": 1,
        "ATR OK": 1,
        "Spread OK": 1,
        "Session OK": 1,
        "News OK": 1,
        "RR OK": 1,
        "Volume Spike": 1,
        "ATR Quantile": 1,
        "Order Block": 1,
        "FVG Confirmed": 1
    }

    checklist = {}
    score = 0

    # Minimum bars
    if price_data is None or len(price_data) < MIN_BARS_REQUIRED:
        checklist["Enough Bars for Clarity"] = False
        return False, 0, checklist

    # HTF bias
    htf_ok = htf_bias_aligned(htf_bias, direction)
    checklist["HTF Bias"] = htf_ok
    if htf_ok: score += weights["HTF Bias"]

    # No-trade zone filter (chop/unclear regime)
    regime = None
    try:
        if 'detect_regime' in globals():
            regime = detect_regime(price_data)
    except Exception:
        regime = None
    if regime in ("chop", "unclear", "no-trade"):
        checklist["No-Trade Zone"] = False
        return False, score, checklist
    else:
        checklist["No-Trade Zone"] = True

    # Previous extreme sweep (liquidity grab)
    sweep_ok = False
    try:
        sweep_ok, sweep_level, swing_idx = require_previous_extreme_sweep(price_data, direction, lookback=20)
    except Exception as e:
        sweep_ok = False
    checklist["Liquidity Grab"] = sweep_ok
    if sweep_ok:
        score += 1  # You can add to weights if you want to make it configurable



    # POI or FVG presence / price inside zone (soft)
    in_poi_zone = False
    if poi and isinstance(poi, dict):
        low = float(poi.get("low", -1e9)); high = float(poi.get("high", 1e9))
        last_price = price_data['close'].iloc[-1]
        in_poi_zone = low <= last_price <= high
    elif fvg and isinstance(fvg, (tuple, list)) and len(fvg) == 2:
        fvg_low, fvg_high = min(fvg), max(fvg)
        last_price = price_data['close'].iloc[-1]
        in_poi_zone = fvg_low <= last_price <= fvg_high
    checklist["POI/FVG"] = in_poi_zone
    if in_poi_zone: score += weights["POI/FVG"]

    # Low-timeframe confirmation (engulfing/pin etc)
    ltf_ok = detect_refined_entry(low_tf_data)
    checklist["LTF Confirmation"] = ltf_ok
    if ltf_ok: score += weights["LTF Confirmation"]

    # Micro confirmation (pin bar, engulfing, strong close)
    micro_ok = False
    try:
        micro_ok, micro_type, micro_strength = get_micro_confirmation(low_tf_data if low_tf_data is not None else price_data, direction, timeframe_bars=5)
    except Exception as e:
        micro_ok = False
    checklist["Micro Confirmation"] = micro_ok
    if micro_ok:
        score += 1  # Add to weights if you want

    # BOS/CHOCH structure confirmation
    ms = check_market_structure(price_data, direction)
    structure_ok = ms.get("bos", False) or ms.get("choch", False) or ms.get("structure_ok", False)
    checklist["BOS or CHOCH"] = structure_ok
    if structure_ok: score += weights["BOS/CHOCH"]

    # Displacement detection (soft)
    displacement = detect_displacement(price_data)
    checklist["Displacement"] = displacement
    if displacement: score += weights["Displacement"]

    # FVG fill / return to POI (soft)
    fvg_filled = False
    if fvg:
        fvg_filled = detect_fvg_fill(price_data, fvg)
    return_ok = detect_return_to_poi(price_data, poi, fvg=fvg)
    checklist["FVG/Return"] = fvg_filled or return_ok
    if fvg_filled or return_ok: score += weights["FVG Fill/Return"]

    # FVG retrace (fresh FVG, price retracing into it)
    fvg_retrace_ok = False
    try:
        fvg_retrace_ok, fvg_low, fvg_high, fvg_confirmed = detect_fvg_retrace(price_data, direction, lookback=15)
    except Exception as e:
        fvg_retrace_ok = False
    checklist["FVG Retrace"] = fvg_retrace_ok
    if fvg_retrace_ok:
        score += 1  # Add to weights if you want

    # Liquidity sweep (soft)
    liq = detect_liquidity_sweep(price_data)
    checklist["Liquidity Sweep"] = liq
    if liq: score += weights["Liquidity Sweep"]

    # Volume spike check: avoid news-impulsive moves
    volume_ok = True
    try:
        if 'volume' in price_data.columns and len(price_data) >= 15:
            vol_spike = volume_spike_15m(price_data, spike_mult=1.7, window=15)
            volume_ok = vol_spike  # Prefer volume spike (confirms move, not noise)
            checklist["Volume Spike"] = volume_ok
            if volume_ok: score += weights.get("Volume Spike", 1)
    except Exception as e:
        logging.debug(f"[CHECKLIST] Volume spike check error: {e}")
        checklist["Volume Spike"] = False
    
    # ATR quantile check: avoid extremes (top 5-10% of volatility = news risk)
    atr_quantile_ok = True
    try:
        atr = (price_data['high'] - price_data['low']).rolling(window=14).mean().iloc[-1]
        atr_history = (price_data['high'] - price_data['low']).rolling(window=14).mean()
        atr_90th = atr_history.quantile(0.90)
        atr_quantile_ok = atr <= atr_90th  # Not in top 10% of volatility
        checklist["ATR Quantile"] = atr_quantile_ok
        if atr_quantile_ok: score += weights.get("ATR Quantile", 1)
        # Large candle filter: last candle not >2x ATR
        last_candle_range = price_data['high'].iloc[-1] - price_data['low'].iloc[-1]
        large_candle_ok = last_candle_range < 2.0 * atr
        checklist["No Large Candle"] = large_candle_ok
        if not large_candle_ok:
            return False, score, checklist
    except Exception as e:
        logging.debug(f"[CHECKLIST] ATR quantile check error: {e}")
        checklist["ATR Quantile"] = False

    # Order Block confirmation (if available)
    ob_ok = False
    try:
        ob = detect_order_block(price_data, direction=direction)
        ob_ok = ob is not None and ob.get('confirmed', False)
        checklist["Order Block"] = ob_ok
        if ob_ok: score += weights.get("Order Block", 1)
    except Exception as e:
        logging.debug(f"[CHECKLIST] Order block check error: {e}")
        checklist["Order Block"] = False

    # FVG confirmed with structure (if available)
    fvg_confirmed = False
    try:
        if fvg:
            # Check that FVG aligns with direction
            fvg_list = fvg if isinstance(fvg, (list, tuple)) else [fvg]
            fvg_confirmed = len(fvg_list) > 0
            checklist["FVG Confirmed"] = fvg_confirmed
            if fvg_confirmed: score += weights.get("FVG Confirmed", 1)
    except Exception as e:
        logging.debug(f"[CHECKLIST] FVG confirmed check error: {e}")
        checklist["FVG Confirmed"] = False

    # ATR and spread (soft)
    try:
        atr = (price_data['high'] - price_data['low']).rolling(window=14).mean().iloc[-2]
        atr_ok = atr >= config.get('min_atr', 0.0002)
    except Exception as e:
        logging.error(f"Error checking ATR: {e}")
        atr_ok = False
    checklist["ATR OK"] = atr_ok
    if atr_ok: score += weights["ATR OK"]

    spread = get_spread(symbol)
    spread_ok = spread <= config.get('spread_threshold', 0.0008)
    checklist["Spread OK"] = spread_ok
    if spread_ok: score += weights["Spread OK"]

    # Session & news (soft)
    session_name = session or get_session_name(datetime.utcnow())
    session_ok = session_name in {"London", "New York", "NY Reversal"} or config.get('allow_asian_session', False)
    checklist["Session OK"] = session_ok
    if session_ok: score += weights["Session OK"]

    checklist["News OK"] = news_ok
    if news_ok: score += weights["News OK"]

    # RR filter (soft)
    rr_ok = rr is not None and rr >= config.get('rr_threshold', 1.2)
    checklist["RR OK"] = rr_ok
    if rr_ok: score += weights["RR OK"]

    # Recent loss cooldown (anti-overtrading)
    recent_loss_cooldown = False
    try:
        recent_trades = get_recent_trades(symbol, n=3)
        if recent_trades and all(t['pnl'] < 0 for t in recent_trades):
            recent_loss_cooldown = True
    except Exception:
        recent_loss_cooldown = False
    checklist["Recent Loss Cooldown"] = not recent_loss_cooldown
    if recent_loss_cooldown:
        return False, score, checklist

def get_recent_trades(symbol, n=3):
    """
    Returns a list of the last n closed trades for the given symbol.
    Each trade is a dict with at least a 'pnl' (profit/loss) key.
    """
    try:
        if 'mt5' in globals():
            from datetime import datetime, timedelta
            now = datetime.now()
            # Get history for the last 7 days
            history = mt5.history_deals_get(now - timedelta(days=7), now)
            trades = []
            if history is not None:
                for deal in reversed(history):
                    if getattr(deal, 'symbol', '') == symbol:
                        pnl = getattr(deal, 'profit', 0.0)
                        trades.append({'pnl': pnl})
                        if len(trades) >= n:
                            break
            return trades
    except Exception as e:
        logging.error(f"Error in get_recent_trades: {e}")
    return []

    # Allow if score >= MIN_SCORE
    allow = score >= MIN_SCORE

    # Attach score for debugging
    checklist["__score"] = score
    checklist["__min_score"] = MIN_SCORE

    return allow, score, checklist

def place_sniper_entry(symbol, direction, entry_price, sl, tp, lot=SNIPER_MAX_LOT, num_trades=1, comment="SNIPER", pattern_name=None,
                       price_data=None, htf_bias=None, poi=None, fvg=None, low_tf_data=None, rr=None, session=None, force_sniper=False):
    """
    Places a sniper entry and scales out at multiple targets:
    - TP1: opposing FVG
    - TP2: liquidity
    - TP3: runner for imbalance fill
    Only executes if sniper_entry_checklist AND SMC/ICT entry trigger returns True.
    """
    # --- SMC/ICT entry trigger ---
    def smc_ict_entry_trigger(price_data, poi, direction):
        """
        Returns True if SMC/ICT signals are strong enough to open a trade.
        Uses POI (or FVG) as entry zone, liquidity sweep/BOS/CHOCH for confirmation.
        """
        # Entry zone: POI or FVG (if provided)
        entry_zone = None
        if poi and isinstance(poi, dict):
            try:
                low = float(poi.get("low", 0))
                high = float(poi.get("high", 0))
                entry_zone = (low, high)
            except Exception:
                entry_zone = None
        elif fvg and isinstance(fvg, (tuple, list)) and len(fvg) == 2:
            try:
                entry_zone = (min(fvg), max(fvg))
            except Exception:
                entry_zone = None
        in_zone = False
        last_price = entry_price
        if entry_zone is not None:
            try:
                in_zone = entry_zone[0] <= last_price <= entry_zone[1]
            except Exception:
                in_zone = False

        # Confirmation: liquidity sweep, BOS, or CHOCH
        liquidity_sweep = False
        bos = False
        choch = False
        try:
            liquidity_sweep = bool(detect_liquidity_sweep(price_data))
        except Exception:
            liquidity_sweep = False
        try:
            ms = check_market_structure(price_data, direction)
            bos = ms.get("bos", False)
            choch = ms.get("choch", False)
        except Exception:
            bos = False
            choch = False

        # Direction alignment
        direction_ok = (direction == "buy" and (bos or choch)) or (direction == "sell" and (bos or choch))

        # Diagnostic payload
        diag = {
            'in_zone': in_zone,
            'entry_zone': entry_zone,
            'last_price': last_price,
            'liquidity_sweep': liquidity_sweep,
            'bos': bos,
            'choch': choch,
            'direction_ok': direction_ok
        }
        logging.debug(f"[SMC_TRIG DIAG] {symbol} -> {diag}")

        # Primary requirement: confirmation + direction alignment. Entry zone is recommended but NOT strictly required.
        return (liquidity_sweep or bos or choch) and direction_ok

    # --- SMC/ICT entry check ---
    if not force_sniper and not smc_ict_entry_trigger(price_data, poi, direction):
        print(f"[{symbol}] SMC/ICT entry trigger failed. Skipping sniper entry. (use force_sniper=True to override)")
        try:
            logging.debug(f"[SMC_BLOCK] symbol={symbol} direction={direction} poi={poi} fvg={fvg}")
        except Exception:
            pass
        return []
    elif force_sniper:
        logging.debug(f"[SNIPER OVERRIDE] force_sniper=True for {symbol}. Bypassing SMC/ICT trigger.")

    # Gather enriched sniper context (POI/FVG/M1 data)
    sniper_ctx = gather_sniper_context(symbol, price_data, direction)
    
    # Check sniper entry checklist with scoring using enriched data
    allow, score, checklist = sniper_entry_checklist(
        symbol, direction, price_data, htf_bias, sniper_ctx["poi"], sniper_ctx["fvg"], sniper_ctx["low_tf"], rr=rr, session=session
    )
    print(f"[SNIPER CHECK] allow={allow} score={score} checklist={checklist}")
    if not allow:
        print(f"[SNIPER ENTRY BLOCKED] Checklist score {score} < {checklist.get('__min_score')}. No trade.")
        return []

    # --- Multi-timeframe confirmation (M15/M5 + M1) ---
    try:
        # Process 15m chart to get entry_zone and confirmation
        ob_zone, m15_conf = (None, False)
        if 'process_15m_chart' in globals():
            try:
                ob_zone, m15_conf = process_15m_chart(symbol)
            except Exception as e:
                logging.debug(f"[MTF] process_15m_chart error: {e}")
        # Require M15 confirmation if available
        if ob_zone is not None and not m15_conf:
            print(f"[{symbol}] M15 confirmation failed. Blocking sniper entry.")
            try:
                send_telegram_alert(f"[SNIPER BLOCKED] {symbol} M15 confirmation failed. Checklist score={score}")
            except Exception:
                pass
            return []

        # Process 1m chart for refined entry if ob_zone exists
        try:
            if ob_zone is not None and 'process_1min_chart' in globals():
                m1_ok = process_1min_chart(symbol, ob_zone)
                if not m1_ok:
                    print(f"[{symbol}] M1 refined entry conditions not met. Blocking sniper entry.")
                    try:
                        send_telegram_alert(f"[SNIPER BLOCKED] {symbol} M1 refined entry failed. Checklist score={score}")
                    except Exception:
                        pass
                    return []
        except Exception as e:
            logging.debug(f"[MTF] process_1min_chart error: {e}")

    except Exception as e:
        logging.debug(f"[SNIPER] Multi-timeframe check error: {e}")

    # Check per-session trade limit for this symbol
    session_name = session or get_session_name(datetime.utcnow())
    if not can_trade_symbol_session(symbol, session_name):
        print(f"[{symbol}] Per-session trade limit reached. Skipping entry.")
        return []

    # Additional hard gates: spread and HTF alignment
    try:
        spread = get_spread(symbol) if 'get_spread' in globals() else 0
        max_spread = get_spread_threshold(symbol) if 'get_spread_threshold' in globals() else SPREAD_THRESHOLD
        if spread > max_spread:
            print(f"[{symbol}] Spread too high ({spread} > {max_spread}). Blocking entry.")
            # Send BOS notification even if blocked
            try:
                send_telegram_alert(f"[BOS BLOCKED] {symbol} | Spread too high ({spread:.4f} > {max_spread:.4f})")
            except Exception as e:
                logging.error(f"[TELEGRAM] Failed to send BOS block notification: {e}")
            return []
    except Exception as e:
        print(f"[{symbol}] Spread check error: {e}")
    try:
        htf = get_htf_trend(symbol, time_frame="H1") if 'get_htf_trend' in globals() else None
        if htf is not None and not htf_trend_allows_trade(direction, htf):
            print(f"[{symbol}] HTF ({htf}) blocks trade for direction {direction}. Blocking entry.")
            # Send BOS notification even if blocked by HTF
            try:
                send_telegram_alert(f"[BOS BLOCKED] {symbol} | HTF {htf} blocks {direction}")
            except Exception as e:
                logging.error(f"[TELEGRAM] Failed to send HTF block notification: {e}")
            return []
    except Exception as e:
        print(f"[{symbol}] HTF check error: {e}")

    # Per-symbol cooldown: avoid overtrading same symbol
    if is_symbol_on_cooldown(symbol, SYMBOL_COOLDOWN_MINUTES):
        print(f"[{symbol}] On cooldown. Skipping entry.")
        return []

    allowed_symbols = {
        "XAUUSD", "EURUSD", "GBPUSD", "NZDUSD", "USDCAD", "USDCHF", "USDJPY", "BTCUSD",
        "XAUUSD.m", "EURUSD.m", "GBPUSD.m", "NZDUSD.m", "USDCAD.m", "USDCHF.m", "USDJPY.m", "BTCUSD.m",
        "XAUUSD.ecn", "EURUSD.ecn", "GBPUSD.ecn", "NZDUSD.ecn", "USDCAD.ecn", "USDCHF.ecn", "USDJPY.ecn", "BTCUSD.ecn",
        "XAUUSD.x", "EURUSD.x", "GBPUSD.x", "NZDUSD.x", "USDCAD.x", "USDCHF.x", "USDJPY.x", "BTCUSD.x"
    }
    symbol_base = symbol.upper().split(".")[0]
    if symbol_base not in {"XAUUSD", "EURUSD", "GBPUSD", "NZDUSD", "USDCAD", "USDCHF", "USDJPY", "BTCUSD"}:
        print(f"[TRADE BLOCKED] Trade for {symbol} not allowed. Only major forex pairs and gold are permitted.")
        return None

    # --- DISABLED SYMBOLS CHECK ---
    try:
        if symbol_base in DISABLED_SYMBOLS:
            print(f"[TRADE BLOCKED] {symbol}: Trades for {symbol_base} are disabled by configuration.")
            return None
    except Exception:
        pass

    # Enforce max 7 open entries
    open_positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
    if open_positions is not None and len(open_positions) >= 5:
        print("[ENTRY BLOCKED] Max 10 open entries reached. No new trades will be opened.")
        return []

    # --- PREVENT OPPOSITE TRADES ON SAME SYMBOL ---
    if open_positions is not None:
        for pos in open_positions:
            pos_symbol = getattr(pos, 'symbol', '')
            pos_type = getattr(pos, 'type', None)
            # Check if position is on the same symbol
            if pos_symbol == symbol or pos_symbol.split('.')[0] == symbol.split('.')[0]:
                # Check if it's opposite direction
                is_buy_position = pos_type == mt5.ORDER_TYPE_BUY
                is_sell_position = pos_type == mt5.ORDER_TYPE_SELL
                
                if (direction == "buy" and is_sell_position) or (direction == "sell" and is_buy_position):
                    print(f"[ENTRY BLOCKED] {symbol}: Opposite position already open (BUY/SELL conflict). Skipping trade.")
                    return []

    # --- PARTIAL TP LOGIC ---
    # Calculate candidates for partial TPs
    targets = get_partial_tp_targets(price_data, direction)
    # Re-order / select targets according to strategy-specific TP priority rules
    try:
        targets = select_priority_tps(pattern_name if 'pattern_name' in locals() else None, targets, entry_price, sl, price_data=price_data, config_obj=(config if 'config' in globals() else None))
    except Exception:
        # Fallback to original candidates if selector fails
        pass
    # If this is explicitly a sniper placement, expand SL/TP to give room for big moves
    try:
        sniper_tp_multiplier = config.get('sniper_tp_multiplier', 3.0) if config else 3.0
        sniper_sl_multiplier = config.get('sniper_sl_multiplier', 2.0) if config else 2.0
    except Exception:
        sniper_tp_multiplier = 3.0
        sniper_sl_multiplier = 2.0

    is_sniper_call = False
    try:
        if comment and "SNIPER" in str(comment).upper():
            is_sniper_call = True
        if pattern_name and "SNIPER" in str(pattern_name).upper():
            is_sniper_call = True
    except Exception:
        is_sniper_call = False

    if is_sniper_call and targets:
        # Expand each TP away from entry by multiplier
        new_targets = []
        for t in targets:
            if t is None:
                new_targets.append(None)
                continue
            if direction == 'buy':
                new_t = entry_price + (t - entry_price) * sniper_tp_multiplier
            else:
                new_t = entry_price - (entry_price - t) * sniper_tp_multiplier
            new_targets.append(new_t)
        targets = new_targets
        # Widen SL proportionally if provided
        try:
            if sl is not None:
                if direction == 'buy':
                    sl = entry_price - abs(entry_price - sl) * sniper_sl_multiplier
                else:
                    sl = entry_price + abs(entry_price - sl) * sniper_sl_multiplier
        except Exception:
            pass
    if not targets or len(targets) < 2:
        print("[PARTIAL TP] Not enough targets found for partial TP. Using single TP.")
        targets = [tp, tp, tp]  # fallback: all at same TP

    # Split lot size for 3 partials (TP1, TP2, runner)
    lot1 = round_lot_to_step(lot * 0.4, symbol)
    lot2 = round_lot_to_step(lot * 0.4, symbol)
    lot3 = round_lot_to_step(max(lot - lot1 - lot2, 0.0), symbol)
    lots = [lot1, lot2, lot3]
    tps = [targets[0], targets[1], targets[2]]

    results = []
    deviation = 10
    with ThreadPoolExecutor(max_workers=2) as executor:
        futures = []
        for i in range(3):
            # Check again in case multiple trades requested
            open_positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
            current_open_count = len(open_positions) if open_positions is not None else 0
            # Block if we already have 10+ open, OR if submitting this entry would push us to 10+
            # This is strict: we allow only up to 9 to have room for final safety margin
            if current_open_count >= 10:
                print(f"[ENTRY BLOCKED] Max 10 open entries already reached ({current_open_count} open). Stopping batch entries.")
                break
            
            # --- CHECK FOR OPPOSITE POSITIONS DURING BATCH ---
            if open_positions is not None:
                has_opposite = False
                for pos in open_positions:
                    pos_symbol = getattr(pos, 'symbol', '')
                    pos_type = getattr(pos, 'type', None)
                    if pos_symbol == symbol or pos_symbol.split('.')[0] == symbol.split('.')[0]:
                        is_buy_position = pos_type == mt5.ORDER_TYPE_BUY
                        is_sell_position = pos_type == mt5.ORDER_TYPE_SELL
                        if (direction == "buy" and is_sell_position) or (direction == "sell" and is_buy_position):
                            has_opposite = True
                            break
                if has_opposite:
                    print(f"[ENTRY BLOCKED] {symbol}: Opposite position exists during batch. Stopping batch.")
                    break
            
            this_lot = lots[i]
            this_tp = tps[i]
            if this_lot <= 0:
                continue
            if direction == "buy":
                req_type = mt5.ORDER_TYPE_BUY
                tick_info = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
                price = tick_info.ask if tick_info else entry_price
            else:
                req_type = mt5.ORDER_TYPE_SELL
                tick_info = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
                price = tick_info.bid if tick_info else entry_price

            # Always use MARKET orders to avoid MT5 "Invalid price" validation errors
            # LIMIT orders fail when price is near/at market price across all symbols
            # Get supported filling modes for this symbol
            supported_filling_modes = get_broker_supported_filling_modes(symbol)
            filling_mode = supported_filling_modes[0] if supported_filling_modes else mt5.ORDER_FILLING_RETURN
            
            order_request = {
                "action": mt5.TRADE_ACTION_DEAL,
                "symbol": symbol,
                "volume": this_lot,
                "type": req_type,
                "price": price,
                "sl": sl,
                "tp": this_tp,
                "deviation": deviation,
                "magic": 0,
                "comment": f"{comment} MARKET",
                "type_filling": filling_mode
            }
            futures.append(executor.submit(async_order_send, order_request))

        for fut in as_completed(futures):
            res = fut.result()
            results.append(res)
            # Log every trade attempt (entry)
            log_entry = {
                "timestamp": datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S UTC'),
                "symbol": symbol,
                "direction": direction,
                "entry_price": entry_price,
                "sl": sl,
                "tp": tp,
                "lot": lot,
                "result": getattr(res, "retcode", None),
                "ticket": getattr(res, "order", None) if res else None,
                "comment": comment,
                "type": "entry"
            }
            if pattern_name:
                log_entry["pattern"] = pattern_name
            log_trade_journal(log_entry)
            # Send email notification on successful order send
            if res is not None and getattr(res, "retcode", None) == mt5.TRADE_RETCODE_DONE:
                # Record this symbol trade for cooldown tracking
                record_symbol_trade(symbol)
                try:
                    session_name = session or get_session_name(datetime.utcnow())
                    record_symbol_session_trade(symbol, session_name)
                except Exception:
                    pass
                subject = f"Trade Entry Opened: {symbol} {direction.upper()}"
                body = (
                    f"Entry opened:\n"
                    f"Symbol: {symbol}\n"
                    f"Direction: {direction}\n"
                    f"Entry Price: {entry_price}\n"
                    f"SL: {sl}\n"
                    f"TP: {tp}\n"
                    f"Lot: {lot}\n"
                    f"Pattern: {pattern_name if pattern_name else 'N/A'}\n"
                    f"Time: {datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S UTC')}\n"
                )
                send_email(
                    subject,
                    body,
                    to_email=(getattr(config, 'NOTIFY_EMAIL', None) if config is not None else None),
                    from_email=(getattr(config, 'SMTP_USER', None) if config is not None else None),
                    smtp_server=(getattr(config, 'SMTP_SERVER', 'smtp.example.com') if config is not None else 'smtp.example.com'),
                    smtp_port=(getattr(config, 'SMTP_PORT', 465) if config is not None else 465),
                    smtp_user=(getattr(config, 'SMTP_USER', None) if config is not None else None),
                    smtp_password=(getattr(config, 'SMTP_PASSWORD', None) if config is not None else None)
                )
                # Send Telegram notification about opened trade (best-effort)
                try:
                    send_telegram_signal(
                        f"*Trade Opened*\nSymbol: {symbol}\nDirection: {direction}\nEntry: {entry_price}\nSL: {sl}\nTP: {tp}\nLot: {lot}\nPattern: {pattern_name if pattern_name else 'N/A'}\nTime: {datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S UTC')}",
                        symbol=symbol
                    )
                except Exception:
                    pass
    return results

def get_partial_tp_targets(price_data, direction):
    """
    Returns a list of 3 targets for partial TP:
    [TP1: opposing FVG, TP2: liquidity, TP3: runner/imbalance]
    """
    # 1. TP1: Opposing FVG
    opposing_fvgs = fvg_as_targets(price_data)
    tp1 = None
    if opposing_fvgs:
        tp1 = opposing_fvgs[0]["fvg"][0] if direction == "sell" else opposing_fvgs[0]["fvg"][1]
    # 2. TP2: Liquidity
    liq_targets = find_liquidity_targets(price_data, direction == "buy")
    tp2 = liq_targets[0] if liq_targets else None
    # 3. TP3: Runner for imbalance fill (set a distant TP or None)
    if direction == "buy":
        tp3 = price_data['high'].max() * 1.01  # 1% above max high as a runner
    else:
        tp3 = price_data['low'].min() * 0.99   # 1% below min low as a runner
    # Fallbacks if any are missing
    targets = [tp for tp in [tp1, tp2, tp3] if tp is not None]
    while len(targets) < 3:
        targets.append(targets[-1] if targets else None)
    return targets[:3]

def select_priority_tps(strategy_name, candidates, entry_price, sl, price_data=None, config_obj=None):
    """
    Selects and orders TP targets according to a lightweight strategy-to-priority mapping.
    - strategy_name: human-readable pattern/strategy (may be None)
    - candidates: list of candidate TPs [tp1, tp2, tp3] from get_partial_tp_targets
    - entry_price, sl: used to compute RR-based TP when required
    - price_data: optional DataFrame for ATR-based fallbacks
    Returns: list of 3 TP values (no None values if possible)
    """
    # Normalize inputs
    strat = (strategy_name or "").upper()
    cand = list(candidates) if candidates else [None, None, None]

    # Helper: compute ATR-based TP fallback
    def compute_atr_tp(multiplier=3.0, direction="buy"):
        try:
            if price_data is not None and 'high' in price_data.columns:
                atr = (price_data['high'] - price_data['low']).rolling(window=14).mean().iloc[-2]
                if direction == 'buy':
                    return float(entry_price + atr * multiplier)
                else:
                    return float(entry_price - atr * multiplier)
        except Exception:
            pass
        # Last-resort: use SL-based RR if SL exists
        try:
            if sl is not None:
                rr = abs(entry_price - sl)
                if rr > 0:
                    if direction == 'buy':
                        return float(entry_price + rr * multiplier)
                    else:
                        return float(entry_price - rr * multiplier)
        except Exception:
            pass
        # If all fails, repeat entry_price to avoid None
        return float(entry_price)

    # Determine trade direction from TP candidates or sign of SL
    direction = 'buy'
    if sl is not None and entry_price is not None:
        direction = 'buy' if entry_price > sl else 'sell'

    # Strategy-specific priority rules
    prioritized = []
    if any(k in strat for k in ("ICT", "BOS", "SNIPER", "ORDER", "OB", "PULLBACK")):
        # Prefer an RR-based target (entry + 3*risk) then candidate TP1/TP2
        rr_based = compute_atr_tp(multiplier=3.0, direction=direction)
        prioritized = [rr_based] + [c for c in cand if c is not None and c != rr_based]
    elif any(k in strat for k in ("SCALP", "SCALPING")):
        # Scalp: prefer ATR expansion fallback
        atr_mult = (config_obj.get('TP_ATR_MULTIPLIER', 3.0) if config_obj else globals().get('TP_ATR_MULTIPLIER', 3.0))
        atr_tp = compute_atr_tp(multiplier=atr_mult, direction=direction)
        prioritized = [atr_tp] + [c for c in cand if c is not None and c != atr_tp]
    else:
        # Default: keep candidate order (tp1,tp2,tp3), then ATR fallback
        prioritized = [c for c in cand if c is not None]
        atr_mult = (config_obj.get('TP_ATR_MULTIPLIER', 3.0) if config_obj else globals().get('TP_ATR_MULTIPLIER', 3.0))
        atr_tp = compute_atr_tp(multiplier=atr_mult, direction=direction)
        if atr_tp not in prioritized:
            prioritized.append(atr_tp)

    # Ensure we have 3 items
    final = []
    for p in prioritized:
        if p is None:
            continue
        final.append(float(p))
        if len(final) >= 3:
            break
    # Pad if needed
    while len(final) < 3:
        final.append(final[-1] if final else float(entry_price))
    return final[:3]
