def detect_displacement(price_data):
    """
    Detects strong displacement candle (body > ATR, volume spike, or large move).
    Returns True if displacement detected.
    """
    if price_data is None or len(price_data) < 15:
        return False
    last = price_data.iloc[-1]
    # Calculate ATR (average true range)
    atr = (price_data['high'] - price_data['low']).rolling(window=14).mean().iloc[-2]
    body = abs(last.close - last.open)
    # Displacement: body > 1.2 * ATR
    return body > 1.2 * atr

def detect_fvg(price_data, htf_bias=None, zone_low=None, zone_high=None):
    """
    ADVANCED Fair Value Gap Detection with Multi-Level Validation:
    
    1. DISPLACEMENT VALIDATION:
       - Large body candle (body > 60% of range)
       - Strong institutional move (body > 1.2 * ATR)
       - Volume confirmation (volume spike OR body > wick rejection)
    
    2. IMBALANCE VALIDATION:
       - Clear gap between candles (no overlap in bodies)
       - Minimum gap size relative to ATR
       - Must be CLEAN (no wick interruption from middle candle)
    
    3. STRUCTURE CONFIRMATION:
       - Break of structure in FVG direction
       - Aligned with HTF bias (if provided)
       - Momentum in direction (close > open for bullish, vice versa)
    
    4. FALSE SIGNAL FILTERS:
       - Reject if small body/wick ratio (lack of conviction)
       - Reject if FVG filled immediately (lack of intent)
       - Reject if opposite momentum candle follows
    
    Returns dict with FVG info, strength rating, and confidence score
    """
    if price_data is None or len(price_data) < 3:
        return None
    
    prev = price_data.iloc[-2]
    last = price_data.iloc[-1]
    mid = price_data.iloc[-3] if len(price_data) >= 3 else None
    
    # === STEP 1: DISPLACEMENT VALIDATION ===
    body = abs(last['close'] - last['open'])
    wick = (last['high'] - last['low']) - body
    range_size = last['high'] - last['low']
    
    if range_size <= 0:
        return None
    
    # Confirm large body (institutional strength)
    body_ratio = body / range_size
    if body_ratio < 0.6:
        return None  # Weak body = weak displacement
    
    # Confirm institutional move with ATR
    atr = (price_data['high'] - price_data['low']).rolling(window=14).mean()
    if len(atr) >= 2:
        atr_val = atr.iloc[-2]
        institutional_move = body > atr_val * 1.2
    else:
        institutional_move = body_ratio > 0.65
    
    if not institutional_move:
        return None  # Not institutional enough
    
    # Volume confirmation (if available)
    has_volume = 'tick_volume' in price_data.columns or 'volume' in price_data.columns
    vol_col = 'tick_volume' if 'tick_volume' in price_data.columns else 'volume'
    
    volume_spike = False
    if has_volume and len(price_data) > 14:
        last_vol = price_data[vol_col].iloc[-1]
        avg_vol = price_data[vol_col].iloc[-15:-1].mean()
        volume_spike = last_vol > avg_vol * 1.3  # 30% above average
    
    # Wick rejection (small wick relative to body = conviction)
    wick_rejection = wick < body * 0.4
    
    # Accept displacement if: (volume spike) OR (body > wick AND body ratio > 70%)
    strong_displacement = volume_spike or (wick_rejection and body_ratio > 0.7)
    
    if not strong_displacement:
        return None
    
    # === STEP 2: IMBALANCE VALIDATION ===
    # Check for clean gap (imbalance)
    direction = None
    fvg_low = None
    fvg_high = None
    
    # Bullish FVG: gap up (last bar's low > prev bar's high)
    if last['low'] > prev['high']:
        fvg_low = prev['high']
        fvg_high = last['low']
        direction = "bullish"
    # Bearish FVG: gap down
    elif last['high'] < prev['low']:
        fvg_low = last['high']
        fvg_high = prev['low']
        direction = "bearish"
    else:
        return None  # No clear gap
    
    # Minimum gap size validation (must be meaningful)
    gap_size = abs(fvg_high - fvg_low)
    min_gap = 0.0001 if gap_size < 1 else (0.01 if gap_size < 100 else 0.1)
    if gap_size < min_gap:
        return None
    
    # === STEP 3: CLEAN FVG CHECK ===
    # Middle candle's wicks must NOT interrupt the FVG
    if mid is not None and len(price_data) >= 3:
        if direction == "bullish":
            # For bullish FVG, middle candle's LOW must be above prev high
            if mid['low'] < prev['high']:
                return None  # Wick interrupts FVG
        else:  # Bearish
            # For bearish FVG, middle candle's HIGH must be below prev low
            if mid['high'] > prev['low']:
                return None  # Wick interrupts FVG
    
    # === STEP 4: STRUCTURE & MOMENTUM CONFIRMATION ===
    # Break of structure: new impulse in FVG direction
    closes = price_data['close'].values
    opens = price_data['open'].values
    
    if direction == "bullish":
        # Bullish FVG must have bullish momentum (close > open)
        if last['close'] <= last['open']:
            return None
        # Check previous bar wasn't already higher (real break)
        if len(closes) >= 3 and closes[-2] > closes[-1]:
            return None  # Previous bar higher = not real continuation
    else:  # Bearish
        # Bearish FVG must have bearish momentum
        if last['close'] >= last['open']:
            return None
        if len(closes) >= 3 and closes[-2] < closes[-1]:
            return None
    
    # === STEP 5: HTF BIAS ALIGNMENT ===
    if htf_bias and zone_low is not None and zone_high is not None:
        fvg_mid = (fvg_low + fvg_high) / 2
        zone_mid = (zone_low + zone_high) / 2
        
        if direction == "bullish" and htf_bias == "buy":
            # Bullish FVG should be in discount zone (lower 50%)
            if not (zone_low <= fvg_mid <= zone_mid):
                return None
        elif direction == "bearish" and htf_bias == "sell":
            # Bearish FVG should be in premium zone (upper 50%)
            if not (zone_mid <= fvg_mid <= zone_high):
                return None
        elif direction != htf_bias:
            # Direction doesn't match bias
            return None
    
    # === STEP 6: CONFIDENCE RATING ===
    confidence = 0.5
    strength = "weak"
    
    # Boost confidence for each positive factor
    if institutional_move:
        confidence += 0.1
    if volume_spike:
        confidence += 0.15
    if wick_rejection:
        confidence += 0.05
    if body_ratio > 0.75:
        confidence += 0.1
    
    if confidence >= 0.85:
        strength = "strong"
    elif confidence >= 0.70:
        strength = "moderate"
    
    return {
        "fvg": (fvg_low, fvg_high),
        "direction": direction,
        "displacement_strength": strength,
        "institutional_move": institutional_move,
        "volume_spike": volume_spike,
        "body_ratio": body_ratio,
        "confidence": min(confidence, 1.0),
        "gap_size": gap_size,
        "atr_multiple": body / atr_val if 'atr_val' in locals() else 0
    }

def fvg_refill_market_structure_continuation(price_data, htf_bias):
    """
    Implements FVG Refill + Market Structure Continuation logic:
    1. Identify displacement → creates the FVG
    2. Wait for price to retrace into the FVG
    3. Look for continuation in the displacement direction
    Returns dict with FVG info and signal if setup is valid.
    """
    # 1. Identify displacement and FVG
    if not detect_displacement(price_data):
        return {"signal": False, "reason": "No displacement"}
    fvg = detect_fvg(price_data)
    if not fvg:
        return {"signal": False, "reason": "No FVG created"}
    # 2. Wait for price to retrace into the FVG (last 3 bars)
    if not detect_fvg_fill(price_data, fvg):
        return {"signal": False, "reason": "No retrace into FVG"}
    # 3. Look for continuation in the displacement direction, aligned with HTF bias
    last = price_data.iloc[-1]
    direction = "buy" if last.close > last.open else "sell"
    if not htf_bias_aligned(htf_bias, direction):
        return {"signal": False, "reason": "HTF bias not aligned"}
    return {
        "signal": True,
        "direction": direction,
        "fvg": fvg,
        "displacement_bar": last.name,
        "reason": "FVG Refill + Market Structure Continuation"
    }

def detect_return_to_poi(price_data, poi, fvg=None, slow_return_bars=5, impulsive_threshold=2.0, allow_fast_return=False):
    """
    Checks if price returns to a POI or FVG after displacement.
    Returns True if price returned (slow or fast depending on allow_fast_return) and not aggressively impulsive.
    """
    if price_data is None or poi is None and fvg is None or len(price_data) < 6:
        return False

    # Find index of displacement/fvg creation — try to detect the bar where FVG formed (search last 20 bars)
    creation_idx = None
    for i in range(len(price_data)-3, 0, -1):
        prev = price_data.iloc[i-1]
        curr = price_data.iloc[i]
        # bullish FVG
        if curr.low > prev.high:
            creation_idx = i
            break
        # bearish FVG
        if curr.high < prev.low:
            creation_idx = i
            break

    if creation_idx is None:
        # fallback: assume displacement was 3 bars ago
        creation_idx = max(0, len(price_data) - 4)

    # Search forward from creation_idx for first bar that re-enters POI/FVG
    returned = False
    return_bars = None
    for j in range(creation_idx + 1, len(price_data)):
        bar = price_data.iloc[j]
        if fvg:
            fvg_low, fvg_high = min(fvg), max(fvg)
            if bar.low <= fvg_high and bar.high >= fvg_low:
                returned = True
                return_bars = j - creation_idx
                break
        else:
            low = float(poi.get("low", -1e9)) if isinstance(poi, dict) else None
            high = float(poi.get("high", 1e9)) if isinstance(poi, dict) else None
            if low is not None and high is not None:
                if low <= bar.close <= high or low <= bar.open <= high:
                    returned = True
                    return_bars = j - creation_idx
                    break

    if not returned:
        return False

    # If fast returns are allowed, accept them (useful for many markets)
    if allow_fast_return:
        fast_ok = True
    else:
        fast_ok = (return_bars is not None and return_bars >= slow_return_bars)

    if not fast_ok:
        return False

    # Reject if any bar in the return path was an aggressive opposite impulse
    atr_series = (price_data['high'] - price_data['low']).rolling(window=14).mean()
    atr_at_creation = atr_series.iloc[creation_idx] if creation_idx < len(atr_series) else atr_series.iloc[-1]
    for k in range(creation_idx+1, creation_idx + 1 + (return_bars or 0)):
        if k >= len(price_data):
            break
        bar = price_data.iloc[k]
        body = abs(bar.close - bar.open)
        if atr_at_creation and body > impulsive_threshold * atr_at_creation:
            return False

    return True

def detect_fvg_fill(price_data, fvg):
    """
    Returns True if any of the last 3 bars trades into the FVG zone.
    """
    if price_data is None or fvg is None or len(price_data) < 3:
        return False
    fvg_low, fvg_high = fvg
    recent_lows = price_data['low'].iloc[-3:]
    recent_highs = price_data['high'].iloc[-3:]
    # FVG fill: any bar trades into FVG zone
    filled = any((low <= fvg_high and high >= fvg_low) for low, high in zip(recent_lows, recent_highs))
    return filled

def detect_order_block(price_data, fvg, direction):
    """
    Detects an Order Block (OB), breaker, or mitigation block inside the FVG zone.
    Returns (ob_low, ob_high) if found, else None.
    """
    if price_data is None or fvg is None or len(price_data) < 5:
        return None
    fvg_low, fvg_high = min(fvg), max(fvg)
    # Search last 5 bars inside FVG for OB
    for i in range(-5, 0):
        bar = price_data.iloc[i]
        if direction == "bullish":
            # Bullish OB: down candle inside FVG
            if bar.close < bar.open and bar.low >= fvg_low and bar.high <= fvg_high:
                return (bar.low, bar.high)
        else:
            # Bearish OB: up candle inside FVG
            if bar.close > bar.open and bar.low >= fvg_low and bar.high <= fvg_high:
                return (bar.low, bar.high)
    return None

def detect_low_risk_fvg_entry(price_data, fvg_info, refine_to="midpoint"):
    """
    Detects a refined FVG entry:
    - Entry at 100% of FVG, midpoint (50%), or refined to OB/breaker inside FVG
    - Stop loss below/above FVG (or refined OB)
    - Targets: opposing FVG, then liquidity highs/lows
    Returns dict with entry, stop, and targets if setup is valid.
    Prints each filter step for debugging.
    """
    print("[FVG ENTRY] --- Checking filters for FVG entry ---")
    if price_data is None or fvg_info is None or "fvg" not in fvg_info or len(price_data) < 3:
        print("[FVG ENTRY] FAIL: No FVG or insufficient data")
        return {"signal": False, "reason": "No FVG or insufficient data"}
    print("[FVG ENTRY] PASS: FVG and data present")
    fvg_low, fvg_high = min(fvg_info["fvg"]), max(fvg_info["fvg"])
    direction = fvg_info.get("direction", "bullish")
    last = price_data.iloc[-1]
    is_bullish = direction == "bullish"

    # OB refinement: look for OB inside FVG
    ob_zone = detect_order_block(price_data, fvg_info["fvg"], direction)
    if ob_zone:
        print(f"[FVG ENTRY] OB refinement found in FVG: {ob_zone}")
    else:
        print("[FVG ENTRY] No OB refinement found in FVG")

    # Entry refinement
    if refine_to == "ob" and ob_zone:
        entry = ob_zone[0] if is_bullish else ob_zone[1]
        stop = ob_zone[1] if is_bullish else ob_zone[0]
        print(f"[FVG ENTRY] Entry refined to OB: entry={entry}, stop={stop}")
    elif refine_to == "100%":
        entry = fvg_low if is_bullish else fvg_high
        stop = (fvg_low - (fvg_high - fvg_low) * 0.1) if is_bullish else (fvg_high + (fvg_high - fvg_low) * 0.1)
        print(f"[FVG ENTRY] Entry at 100% FVG: entry={entry}, stop={stop}")
    else:  # midpoint
        entry = (fvg_low + fvg_high) / 2
        stop = (fvg_low - (fvg_high - fvg_low) * 0.1) if is_bullish else (fvg_high + (fvg_high - fvg_low) * 0.1)
        print(f"[FVG ENTRY] Entry at midpoint: entry={entry}, stop={stop}")

    # Confirm price has entered FVG
    entered = (last.low <= fvg_high and last.high >= fvg_low)
    if not entered:
        print("[FVG ENTRY] FAIL: Price has not entered FVG")
        return {"signal": False, "reason": "Price has not entered FVG"}
    print("[FVG ENTRY] PASS: Price has entered FVG")

    # Confirm with BOS, SIBI/BISI, or small displacement
    bos = detect_bos(price_data, is_bullish)
    sibi_bisi = detect_sibi_bisi(price_data, is_bullish)
    small_disp = detect_small_displacement(price_data, is_bullish)
    print(f"[FVG ENTRY] BOS: {bos}, SIBI/BISI: {sibi_bisi}, Small Displacement: {small_disp}")

    # --- FIX: Require confirmation on the bar that actually enters the FVG, not just the last bar ---
    # If price entered FVG in a previous bar, check confirmation on that bar
    if not (bos or sibi_bisi or small_disp):
        print("[FVG ENTRY] No confirmation on last bar, checking previous 3 bars...")
        # Try to check confirmation on the first bar that entered the FVG in the last 3 bars
        for i in range(-3, 0):
            bar = price_data.iloc[i]
            entered_bar = (bar.low <= fvg_high and bar.high >= fvg_low)
            if entered_bar:
                is_bullish_bar = bar.close > bar.open if is_bullish else bar.close < bar.open
                bos_bar = detect_bos(price_data.iloc[:i+1], is_bullish)
                sibi_bisi_bar = detect_sibi_bisi(price_data.iloc[:i+1], is_bullish)
                small_disp_bar = detect_small_displacement(price_data.iloc[:i+1], is_bullish)
                print(f"[FVG ENTRY] Bar {i}: BOS={bos_bar}, SIBI/BISI={sibi_bisi_bar}, Small Displacement={small_disp_bar}")
                if bos_bar or sibi_bisi_bar or small_disp_bar:
                    print(f"[FVG ENTRY] PASS: Confirmation found on bar {i}")
                    break
        else:
            print("[FVG ENTRY] FAIL: No entry confirmation (BOS/SIBI/BISI/small displacement)")
            return {"signal": False, "reason": "No entry confirmation (BOS/SIBI/BISI/small displacement)"}
    else:
        print("[FVG ENTRY] PASS: Entry confirmation found on last bar")

    # Targets: first = opposing FVG, next = liquidity highs/lows, runner = large imbalance
    opposing_fvgs = fvg_as_targets(price_data)
    liq_targets = find_liquidity_targets(price_data, is_bullish)
    targets = []
    if opposing_fvgs:
        targets.append(opposing_fvgs[0]["fvg"])
        print(f"[FVG ENTRY] Target: Opposing FVG {opposing_fvgs[0]['fvg']}")
    else:
        print("[FVG ENTRY] No opposing FVG target found")
    if liq_targets:
        targets.append(liq_targets[0])
        print(f"[FVG ENTRY] Target: Liquidity {liq_targets[0]}")
    else:
        print("[FVG ENTRY] No liquidity target found")
    # Optionally leave runner for large imbalance fills

    print("[FVG ENTRY] --- All filters passed, entry signal generated ---")
    return {
        "signal": True,
        "entry": entry,
        "stop": stop,
        "targets": targets,
        "fvg": (fvg_low, fvg_high),
        "ob_zone": ob_zone,
        "displacement_strength": fvg_info.get("displacement_strength", None),
        "reason": "Refined FVG Entry with OB refinement" if ob_zone else "Refined FVG Entry"
    }

import numpy as np
import pandas as pd

# OLD detect_bos REMOVED - See line 54739 for authoritative version

def detect_sibi_bisi(price_data, is_bullish, window=3):
    """
    ADVANCED CHOCH Detection: Change of Character
    Detects shift in market behavior:
    - CHOCH Bullish: Shift from bearish to bullish (lower lows → higher highs)
    - CHOCH Bearish: Shift from bullish to bearish (higher highs → lower lows)
    Validates with volume and momentum
    Returns "bullish" or "bearish" if detected, else 0
    """
    if price_data is None or len(price_data) < window * 3 + 2:
        return 0
    
    lookback = window * 3  # Need more bars to confirm character change
    closes = price_data['close'].values[-lookback:]
    opens = price_data['open'].values[-lookback:]
    highs = price_data['high'].values[-lookback:]
    lows = price_data['low'].values[-lookback:]
    
    if len(closes) < lookback:
        return 0
    
    has_volume = 'tick_volume' in price_data.columns or 'volume' in price_data.columns
    if has_volume:
        vol_col = 'tick_volume' if 'tick_volume' in price_data.columns else 'volume'
        volumes = price_data[vol_col].values[-lookback:]
    
    # Calculate momentum: are closes moving higher or lower?
    price_momentum = closes[-1] - closes[-(window+1)]
    
    if is_bullish:
        # CHOCH Bullish: Previous 3 bars lower lows, now breaking with HIGHER LOWS
        # AND volume confirmation
        prev_lows = lows[:-window]
        recent_lows = lows[-window:]
        
        # Previous phase: lower lows (downtrend)
        lower_lows = all(prev_lows[i] > prev_lows[i-1] for i in range(1, len(prev_lows))) or np.std(prev_lows) < np.std(recent_lows)
        
        # Recent phase: HIGHER lows (reversal) - not just one bar
        higher_lows = all(recent_lows[i] > recent_lows[i-1] for i in range(1, len(recent_lows)-1))
        
        # Momentum confirmation: must be closing higher
        momentum_ok = price_momentum > 0
        
        # Volume confirmation: increase in bullish candles
        if has_volume:
            bullish_candles = sum(1 for i in range(-window, 0) if closes[i] > opens[i])
            vol_avg = np.mean(volumes)
            recent_vol = volumes[-1]
            vol_ok = recent_vol > vol_avg * 0.95
        else:
            bullish_candles = sum(1 for i in range(-window, 0) if closes[i] > opens[i])
            vol_ok = True
        
        if higher_lows and momentum_ok and bullish_candles >= window and vol_ok:
            return "bullish"
        else:
            return 0
    
    else:  # Bearish CHOCH
        # CHOCH Bearish: Previous higher highs, now breaking with LOWER HIGHS
        prev_highs = highs[:-window]
        recent_highs = highs[-window:]
        
        # Previous phase: higher highs (uptrend)
        higher_highs = all(prev_highs[i] < prev_highs[i-1] for i in range(1, len(prev_highs))) or np.std(prev_highs) < np.std(recent_highs)
        
        # Recent phase: LOWER highs (reversal)
        lower_highs = all(recent_highs[i] < recent_highs[i-1] for i in range(1, len(recent_highs)-1))
        
        # Momentum confirmation
        momentum_ok = price_momentum < 0
        
        # Volume confirmation
        if has_volume:
            bearish_candles = sum(1 for i in range(-window, 0) if closes[i] < opens[i])
            vol_avg = np.mean(volumes)
            recent_vol = volumes[-1]
            vol_ok = recent_vol > vol_avg * 0.95
        else:
            bearish_candles = sum(1 for i in range(-window, 0) if closes[i] < opens[i])
            vol_ok = True
        
        if lower_highs and momentum_ok and bearish_candles >= window and vol_ok:
            return "bearish"
        else:
            return 0

def detect_small_displacement(price_data, is_bullish, window=3, min_body_ratio=0.5):
    """
    Robustly detects a small displacement entry trigger in the direction of bias.
    Returns "bullish" or "bearish" if detected, else 0.
    """
    if price_data is None or len(price_data) < window + 1:
        return 0
    for i in range(1, window+1):
        last = price_data.iloc[-i]
        prev = price_data.iloc[-i-1]
        body = abs(last.close - last.open)
        prev_body = abs(prev.close - prev.open)
        if prev_body == 0:
            continue
        if (body > min_body_ratio * prev_body):
            if is_bullish and last.close > last.open:
                return "bullish"
            elif not is_bullish and last.close < last.open:
                return "bearish"
    return 0

def find_liquidity_targets(price_data, is_bullish, lookback=20):
    """
    Finds next liquidity highs/lows as targets, robust to missing data.
    Returns a sorted list of unique levels.
    """
    if price_data is None or len(price_data) < lookback + 1:
        return []
    highs = price_data['high'].iloc[-lookback:-1].dropna()
    lows = price_data['low'].iloc[-lookback:-1].dropna()
    if is_bullish:
        return sorted(list(set([highs.max()])))
    else:
        return sorted(list(set([lows.min()])))

def fvg_as_targets(price_data, min_gap=1e-8):
    """
    Finds FVGs that can be used as magnet targets (not entry).
    Returns a list of FVGs above/below current price, robust to missing data.
    """
    if price_data is None or len(price_data) < 10:
        return []
    current_price = price_data['close'].iloc[-1]
    fvg_list = []
    for i in range(-10, -2):
        prev = price_data.iloc[i]
        last = price_data.iloc[i+1]
        # Bullish FVG: last.low > prev.high by at least min_gap
        if last.low > prev.high + min_gap:
            fvg = (prev.high, last.low)
            if fvg[0] > current_price:
                fvg_list.append({"type": "bullish", "fvg": fvg})
        # Bearish FVG: last.high < prev.low by at least min_gap
        if last.high < prev.low - min_gap:
            fvg = (last.high, prev.low)
            if fvg[1] < current_price:
                fvg_list.append({"type": "bearish", "fvg": fvg})
    return fvg_list

def detect_refined_entry(low_tf_data, window=2):
    """
    Looks for robust refined entry confirmation on low timeframes (engulfing, pin bar, etc).
    Returns True if confirmation found in last `window` bars.
    """
    if low_tf_data is None or len(low_tf_data) < window:
        return False
    for i in range(1, window+1):
        last = low_tf_data.iloc[-i]
        prev = low_tf_data.iloc[-i-1]
        # Bullish engulfing
        bullish_engulf = last.close > last.open and last.open < prev.close and last.close > prev.open
        # Bearish engulfing
        bearish_engulf = last.close < last.open and last.open > prev.close and last.close < prev.open
        # Pin bar (long wick)
        pin_bar = (abs(last.close - last.open) < (last.high - last.low) * 0.3)
        if bullish_engulf or bearish_engulf or pin_bar:
            return True
    return False

# ====== TECHNICAL ANALYSIS FUNCTIONS ======
def detect_trend(df):
    """Detect trend direction: bullish, bearish, or sideways"""
    if df is None or len(df) < 5:
        return "sideways"
    highs = df['high'].values
    lows = df['low'].values
    if highs[-1] > highs[-2] and lows[-1] > lows[-2]:
        return "bullish"
    elif lows[-1] < lows[-2] and highs[-1] < highs[-2]:
        return "bearish"
    return "sideways"

def detect_trendline_break(df):
    """Detect if trendline is broken"""
    if df is None or len(df) < 5:
        return False
    closes = df['close'].values
    if len(closes) < 3:
        return False
    trend = (closes[-1] - closes[-3]) / closes[-3] if closes[-3] != 0 else 0
    return abs(trend) > 0.01

def detect_double_top(df):
    """Detect double top pattern"""
    if df is None or len(df) < 10:
        return False
    highs = df['high'].values
    recent_high = highs[-1]
    prev_high = highs[-5] if len(highs) >= 5 else 0
    return abs(recent_high - prev_high) < 0.0005 and recent_high > 0

def detect_double_bottom(df):
    """Detect double bottom pattern"""
    if df is None or len(df) < 10:
        return False
    lows = df['low'].values
    recent_low = lows[-1]
    prev_low = lows[-5] if len(lows) >= 5 else float('inf')
    return abs(recent_low - prev_low) < 0.0005 and recent_low > 0

def ma_crossover(df):
    """Detect moving average crossover"""
    if df is None or len(df) < 20:
        return None
    closes = df['close'].values
    ma_10 = np.mean(closes[-10:])
    ma_20 = np.mean(closes[-20:])
    return "bullish" if ma_10 > ma_20 else "bearish"

def detect_rsi_divergence(df):
    """Detect RSI divergence"""
    if df is None or len(df) < 14:
        return False
    closes = df['close'].values
    deltas = np.diff(closes)
    seed = deltas[:14]
    up = seed[seed >= 0].sum() / 14
    down = -seed[seed < 0].sum() / 14
    rs = up / down if down != 0 else 0
    rsi = 100 - (100 / (1 + rs)) if rs >= 0 else 0
    return rsi > 70 or rsi < 30

def fibonacci_levels(df):
    """Calculate Fibonacci levels"""
    if df is None or len(df) < 5:
        return {"level_0": 0, "level_0.382": 0, "level_0.5": 0, "level_0.618": 0, "level_1": 0}
    highs = df['high'].values
    lows = df['low'].values
    recent_high = np.max(highs[-5:])
    recent_low = np.min(lows[-5:])
    diff = recent_high - recent_low
    return {
        "level_0": recent_low,
        "level_0.382": recent_low + 0.382 * diff,
        "level_0.5": recent_low + 0.5 * diff,
        "level_0.618": recent_low + 0.618 * diff,
        "level_1": recent_high
    }

# ====================================================================
# 🎯 SNIPER ENTRY CONDITION VALIDATORS
# ====================================================================
def price_in_fvg_midpoint(price, fvg_zone, tolerance_pct=0.5):
    """
    Check if price is at the FVG midpoint (50% level).
    
    Args:
        price: Current price
        fvg_zone: {'low': float, 'high': float} or tuple (low, high)
        tolerance_pct: Tolerance as % of FVG width (default 0.5% = tight)
    
    Returns:
        bool: True if price within tolerance of FVG midpoint
    """
    try:
        if not fvg_zone:
            return False
        
        if isinstance(fvg_zone, dict):
            fvg_low = float(fvg_zone.get('low', -1e9))
            fvg_high = float(fvg_zone.get('high', 1e9))
        else:
            fvg_low = float(fvg_zone[0]) if len(fvg_zone) > 0 else -1e9
            fvg_high = float(fvg_zone[1]) if len(fvg_zone) > 1 else 1e9
        
        if fvg_low >= fvg_high:
            return False
        
        midpoint = (fvg_low + fvg_high) / 2.0
        width = fvg_high - fvg_low
        tolerance = width * (tolerance_pct / 100.0)
        
        return abs(price - midpoint) <= tolerance
    except Exception:
        return False


def liquidity_sweep_detected(df, direction, lookback=5):
    """
    Detect liquidity sweep: price breaks structure then closes back inside.
    
    For BUY: High goes above previous candle high, then closes inside
    For SELL: Low goes below previous candle low, then closes inside
    
    Args:
        df: Price dataframe with OHLC
        direction: 'buy' or 'sell'
        lookback: Lookback bars to check
    
    Returns:
        bool: True if sweep detected
    """
    try:
        if df is None or len(df) < lookback + 1:
            return False
        
        recent = df.tail(lookback)
        current = recent.iloc[-1]
        prev = recent.iloc[-2]
        
        if direction.lower() == "buy":
            # BUY sweep: current high > prev high, current close < prev high
            return current['high'] > prev['high'] and current['close'] < prev['high']
        else:  # sell
            # SELL sweep: current low < prev low, current close > prev low
            return current['low'] < prev['low'] and current['close'] > prev['low']
    except Exception:
        return False


def ltf_structure_confirmation(df_ltf, direction, lookback=10):
    """
    Confirm structure shift (BOS/CHOCH) on lower timeframe.
    Reuses higher-level BOS detection logic for consistency.
    
    Args:
        df_ltf: Lower-timeframe dataframe (e.g., M5 or M15)
        direction: 'buy' or 'sell'
        lookback: Bars to analyze
    
    Returns:
        dict: {'confirmed': bool, 'reason': str, 'strength': float (0-1)}
    """
    result = {'confirmed': False, 'reason': 'No LTF structure', 'strength': 0.0}
    
    try:
        if df_ltf is None or len(df_ltf) < lookback:
            return result
        
        recent = df_ltf.tail(lookback)
        highs = recent['high'].values
        lows = recent['low'].values
        closes = recent['close'].values
        
        # For BUY: Need bullish structure (HH/HL + close near highs)
        if direction.lower() == "buy":
            recent_high = highs[-1]
            prev_high = np.max(highs[:-1])
            recent_low = lows[-1]
            prev_low = np.min(lows[:-1])
            
            # Bullish: recent high > prev high (higher high)
            higher_high = recent_high > prev_high
            # Higher low (optional but good)
            higher_low = recent_low > prev_low
            # Close near top (bullish pressure)
            close_near_high = (recent_high - closes[-1]) < (highs[-1] - lows[-1]) * 0.3
            
            confirmed = higher_high and close_near_high
            strength = (1.0 if higher_high else 0) + (0.5 if higher_low else 0) + (0.5 if close_near_high else 0)
            strength = min(strength / 2.0, 1.0)  # Normalize to 0-1
            
            if confirmed:
                result['confirmed'] = True
                result['reason'] = f"LTF bullish structure: HH({recent_high:.5f}>{prev_high:.5f})"
                result['strength'] = strength
        
        else:  # sell
            recent_high = highs[-1]
            prev_high = np.max(highs[:-1])
            recent_low = lows[-1]
            prev_low = np.min(lows[:-1])
            
            # Bearish: recent low < prev low (lower low)
            lower_low = recent_low < prev_low
            # Lower high (optional but good)
            lower_high = recent_high < prev_high
            # Close near bottom (bearish pressure)
            close_near_low = (closes[-1] - recent_low) < (highs[-1] - lows[-1]) * 0.3
            
            confirmed = lower_low and close_near_low
            strength = (1.0 if lower_low else 0) + (0.5 if lower_high else 0) + (0.5 if close_near_low else 0)
            strength = min(strength / 2.0, 1.0)
            
            if confirmed:
                result['confirmed'] = True
                result['reason'] = f"LTF bearish structure: LL({recent_low:.5f}<{prev_low:.5f})"
                result['strength'] = strength
        
        return result
    
    except Exception as e:
        result['reason'] = f"LTF check error: {e}"
        return result


def normal_entry_allowed(signal_data):
    """
    Validate NORMAL entry conditions (existing bot behavior).
    
    Requires:
    - HTF BOS/CHOCH ✅
    - FVG present ✅  
    - Displacement confirmed ✅
    
    Args:
        signal_data: dict with keys: bos_confirmed, fvg_valid, displacement
    
    Returns:
        bool: True if entry allowed
    """
    try:
        return (
            signal_data.get('bos_confirmed', False)
            and signal_data.get('fvg_valid', False)
            and signal_data.get('displacement', False)
        )
    except Exception:
        return False


# ====================================================================
# 🛡️ CRITICAL SAFETY GOVERNORS (Prevent catastrophic losses)
# ====================================================================

def check_impulse_range_blocker(symbol, df_h4, df_h1, direction):
    """IMPULSE RANGE BLOCKER: Disable counter-trend trades if HTF impulse > 2% of daily range."""
    try:
        if df_h4 is None or len(df_h4) < 50:
            return True, "✅ H4 data loading (check bypassed)"
        h4_data = df_h4.tail(20)
        impulse_high = float(h4_data['high'].max())
        impulse_low = float(h4_data['low'].min())
        impulse_range = impulse_high - impulse_low
        daily_range = float(df_h4['high'].tail(100).max() - df_h4['low'].tail(100).min())
        if daily_range <= 0:
            return True, "Daily range zero"
        impulse_pct = (impulse_range / daily_range) * 100.0
        if impulse_pct > 2.0:
            recent_close = float(df_h4['close'].iloc[-1])
            impulse_bias = "bullish" if recent_close > (impulse_low + impulse_high) / 2 else "bearish"
            if (impulse_bias == "bullish" and direction == "sell") or (impulse_bias == "bearish" and direction == "buy"):
                return False, f"🔥 IMPULSE BLOCKER: HTF impulse {impulse_pct:.1f}% ({impulse_bias}) — {direction.upper()} counter-trend BLOCKED"
            else:
                return True, f"✅ Impulse {impulse_pct:.1f}% ({impulse_bias}) aligns with {direction.upper()}"
        else:
            return True, f"Impulse normal ({impulse_pct:.1f}% of daily)"
    except Exception as e:
        return True, f"Impulse check error: {e}"

def check_position_conflict_blocker(symbol, direction, entry_score=None):
    """FIX #1: AUTO-CLOSE opposite positions if entry_score >= 6.5 instead of blocking."""
    try:
        positions = safe_positions_get()
        if not positions:
            return True, "No open positions", 0
        buy_positions = []
        sell_positions = []
        for pos in positions:
            if hasattr(pos, 'symbol') and pos.symbol == symbol:
                if hasattr(pos, 'type'):
                    if pos.type == 0:
                        buy_positions.append(pos)
                    elif pos.type == 1:
                        sell_positions.append(pos)
        
        opposite_positions = sell_positions if direction == "buy" else buy_positions
        opposite_type = "SELL" if direction == "buy" else "BUY"
        
        if len(opposite_positions) > 0:
            if entry_score is not None and entry_score >= 6.5:
                print(f"[🔥 AUTO-CLOSE] {symbol}: Score={entry_score:.1f}. Closing {len(opposite_positions)} {opposite_type} position(s)...")
                for pos in opposite_positions:
                    try:
                        mt5.Close(pos.ticket)
                        print(f"  ✅ Closed {pos.ticket}")
                    except Exception as e:
                        print(f"  ⚠️ Close failed {pos.ticket}: {e}")
                return True, f"Auto-closed (score={entry_score:.1f})", 0
            else:
                return False, f"⚠️ CONFLICT: {len(opposite_positions)} {opposite_type} open (score too weak)", len(opposite_positions)
        else:
            return True, f"No conflict ({direction.upper()} allowed)", 0
    except Exception as e:
        return True, f"Position check error: {e}", 0

def check_volatility_safety_governor(symbol, df_m15, direction):
    """VOLATILITY SAFETY GOVERNOR: Disable/reduce entries during extreme volatility."""
    try:
        if df_m15 is None or len(df_m15) < 50:
            return True, "✅ M15 data loading (check bypassed)", "unknown"
        vol_regime = assess_volatility_regime(df_m15, lookback=50, low_pct=20.0, high_pct=85.0)
        regime = vol_regime.get('regime', 'normal')
        percentile = vol_regime.get('percentile', 50.0)
        atr = vol_regime.get('atr', 0.0)
        high_thresh = vol_regime.get('high_thresh', 0.0)
        if regime == 'wild':
            reason = f"⚠️  VOLATILITY GOVERNOR: Wild regime (ATR {atr:.4f} > {high_thresh:.4f}, {percentile:.0f}th percentile) — Requires confidence 0.80+ (up from 0.75)"
            return True, reason, regime
        elif regime == 'quiet':
            return True, f"✅ Volatility quiet ({percentile:.0f}th percentile) — Ideal for sniper entries", regime
        else:
            return True, f"✅ Volatility normal ({percentile:.0f}th percentile) — Proceed", regime
    except Exception as e:
        return True, f"Volatility check error: {e}", "unknown"


