# 🎯 HTF ALIGNMENT FILTER (Critical: Prevents Counter-Trend Trades)
# ====================================================================
def detect_htf_trend_strength(df_h4, df_h1=None):
    """
    Detect HTF (H4/H1) trend strength and direction.
    
    Returns:
        dict: {
            'trend': 'bullish' | 'bearish' | 'none',
            'strength': 0-100,  # 0=none, 50=moderate, 100=extreme
            'htf_choch': bool,  # True if HTF CHoCH detected
            'impulse_range': float,  # Size of impulse move
            'reason': str
        }
    """
    result = {
        'trend': 'none',
        'strength': 0,
        'htf_choch': False,
        'impulse_range': 0.0,
        'reason': 'Insufficient data'
    }
    
    try:
        df = df_h4 if df_h4 is not None and len(df_h4) >= 20 else (df_h1 if df_h1 is not None and len(df_h1) >= 20 else None)
        if df is None:
            return result
        
        recent = df.tail(20)
        highs = recent['high'].values
        lows = recent['low'].values
        closes = recent['close'].values
        
        # Detect trend direction (Higher Highs & Higher Lows = bullish, vice versa)
        hh_count = 0  # Higher highs
        hl_count = 0  # Higher lows
        lh_count = 0  # Lower highs
        ll_count = 0  # Lower lows
        
        for i in range(1, len(recent)):
            if highs[i] > highs[i-1]:
                hh_count += 1
            else:
                lh_count += 1
            
            if lows[i] > lows[i-1]:
                hl_count += 1
            else:
                ll_count += 1
        
        # Determine trend
        bullish_score = hh_count + hl_count
        bearish_score = lh_count + ll_count
        
        if bullish_score > bearish_score * 1.5:  # Clear bullish
            result['trend'] = 'bullish'
            result['strength'] = min(100, int((bullish_score / 20) * 100))
        elif bearish_score > bullish_score * 1.5:  # Clear bearish
            result['trend'] = 'bearish'
            result['strength'] = min(100, int((bearish_score / 20) * 100))
        else:
            result['trend'] = 'none'
            result['strength'] = 50
        
        # Measure impulse range
        recent_high = max(highs[-10:])
        recent_low = min(lows[-10:])
        result['impulse_range'] = recent_high - recent_low
        
        # 🔥 CRITICAL FIX: Detect HTF CHoCH (Change of Character)
        # CHoCH = trend reversal signal (NOT continuation)
        # 
        # BULLISH CHoCH: During bearish trend, price breaks ABOVE previous high (reversal to bullish)
        # BEARISH CHoCH: During bullish trend, price breaks BELOW previous low (reversal to bearish)
        #
        # We check if trend recently CHANGED (not if it's continuing)
        prev_10_highs = highs[-20:-10]  # Previous 10 candles
        prev_10_lows = lows[-20:-10]
        recent_5_highs = highs[-5:]  # Most recent 5 candles
        recent_5_lows = lows[-5:]
        
        if len(prev_10_highs) >= 5 and len(recent_5_highs) >= 5:
            prev_high = max(prev_10_highs)
            prev_low = min(prev_10_lows)
            recent_high = max(recent_5_highs)
            recent_low = min(recent_5_lows)
            
            # CHoCH = structure break AGAINST current trend
            if result['trend'] == 'bullish':
                # If bullish trend but recent candles broke BELOW previous lows = potential bearish CHoCH
                result['htf_choch'] = recent_low < prev_low
            elif result['trend'] == 'bearish':
                # If bearish trend but recent candles broke ABOVE previous highs = potential bullish CHoCH
                result['htf_choch'] = recent_high > prev_high
            else:
                result['htf_choch'] = False
        else:
            result['htf_choch'] = False
        
        result['reason'] = f"{result['trend'].upper()} (strength: {result['strength']}/100, CHoCH: {'YES (reversal likely)' if result['htf_choch'] else 'NO'})"
        
        return result
    
    except Exception as e:
        result['reason'] = f"Error: {e}"
        return result


def is_price_in_htf_premium(price, df_h4, df_h1=None):
    """
    Check if price is in HTF premium zone (upper 50% of recent range).
    Used for filtering counter-trend (sell) entries.
    
    Returns:
        dict: {'in_premium': bool, 'location_pct': 0-100, 'reason': str}
    """
    result = {'in_premium': False, 'location_pct': 50, 'reason': 'Unknown'}
    
    try:
        df = df_h4 if df_h4 is not None and len(df_h4) >= 20 else (df_h1 if df_h1 is not None and len(df_h1) >= 20 else None)
        if df is None:
            return result
        
        recent = df.tail(50)  # Last 50 candles
        htf_high = recent['high'].max()
        htf_low = recent['low'].min()
        htf_range = htf_high - htf_low
        
        if htf_range == 0:
            return result
        
        # Location as % from low (0% = low, 100% = high)
        location_pct = ((price - htf_low) / htf_range) * 100
        
        # Premium = top 50% (above 50%)
        in_premium = location_pct > 50
        
        result['in_premium'] = in_premium
        result['location_pct'] = round(location_pct, 1)
        result['reason'] = f"Price at {location_pct:.0f}% of HTF range {'(PREMIUM)' if in_premium else '(DISCOUNT)'}"
        
        return result
    
    except Exception as e:
        result['reason'] = f"Error: {e}"
        return result


def is_price_in_htf_discount(price, df_h4, df_h1=None):
    """
    Check if price is in HTF discount zone (lower 50% of recent range).
    Used for filtering counter-trend (buy) entries.
    
    Returns:
        dict: {'in_discount': bool, 'location_pct': 0-100, 'reason': str}
    """
    result = {'in_discount': False, 'location_pct': 50, 'reason': 'Unknown'}
    
    try:
        df = df_h4 if df_h4 is not None and len(df_h4) >= 20 else (df_h1 if df_h1 is not None and len(df_h1) >= 20 else None)
        if df is None:
            return result
        
        recent = df.tail(50)
        htf_high = recent['high'].max()
        htf_low = recent['low'].min()
        htf_range = htf_high - htf_low
        
        if htf_range == 0:
            return result
        
        # Location as % from low
        location_pct = ((price - htf_low) / htf_range) * 100
        
        # Discount = bottom 50% (below 50%)
        in_discount = location_pct < 50
        
        result['in_discount'] = in_discount
        result['location_pct'] = round(location_pct, 1)
        result['reason'] = f"Price at {location_pct:.0f}% of HTF range {'(DISCOUNT)' if in_discount else '(PREMIUM)'}"
        
        return result
    
    except Exception as e:
        result['reason'] = f"Error: {e}"
        return result


def validate_htf_alignment(direction, htf_trend, htf_choch, price, df_h4, df_h1, symbol):
    """
    � HTF = TRAFFIC LIGHT (Direction Permission Layer)
    
    HTF gives PERMISSION. LTF gives PRECISION.
    
    HARD RULES (NO EXCEPTIONS):
    ═══════════════════════════════════════════════════════════════
    🟢 HTF BULLISH  → ✅ BUYS ALLOWED  | 🚫 SELLS BLOCKED
    🔴 HTF BEARISH  → 🚫 BUYS BLOCKED  | ✅ SELLS ALLOWED
    🟡 HTF NEUTRAL  → ✅ BOTH ALLOWED (with location filter)
    ═══════════════════════════════════════════════════════════════
    
    This is the #1 rule. If HTF blocks → LTF doesn't even run.
    
    Args:
        direction: 'buy' or 'sell'
        htf_trend: 'bullish', 'bearish', 'none'
        htf_choch: bool (has HTF changed character? - MUST be strong reversal)
        price: current price
        df_h4, df_h1: HTF dataframes
        symbol: symbol for logging
    
    Returns:
        dict: {'allowed': bool, 'reason': str, 'severity': 'ok'|'warn'|'block'}
    """
    result = {'allowed': False, 'reason': 'Unknown', 'severity': 'warn'}
    
    try:
        direction = direction.lower()
        htf_trend = htf_trend.lower()
        
        # ═══════════════════════════════════════════════════════════════
        # 🟢 HTF BULLISH = GREEN LIGHT FOR BUYS, RED LIGHT FOR SELLS
        # ═══════════════════════════════════════════════════════════════
        if htf_trend == 'bullish':
            if direction == 'buy':
                # ✅ PERFECT ALIGNMENT: HTF bullish + BUY
                result['allowed'] = True
                result['reason'] = f"🟢 HTF BULLISH → BUY ALLOWED (trend-following)"
                result['severity'] = 'ok'
            
            else:  # sell
                # 🚫 COUNTER-TREND: HTF bullish + SELL = BLOCKED
                # ONLY exception: Strong HTF CHoCH (reversal confirmed)
                if htf_choch:
                    # HTF CHoCH detected = trend may be reversing
                    # BUT: Still risky, so require price in premium zone
                    premium_check = is_price_in_htf_premium(price, df_h4, df_h1)
                    if premium_check['in_premium']:
                        result['allowed'] = True
                        result['reason'] = f"⚠️  HTF BULLISH + SELL: CHoCH detected + price in premium ({premium_check['location_pct']:.0f}%) → SELL allowed with caution"
                        result['severity'] = 'warn'
                    else:
                        # CHoCH but price not in premium = still too risky
                        result['allowed'] = False
                        result['reason'] = f"🚫 BLOCKED: HTF bullish + SELL, CHoCH detected but price NOT in premium ({premium_check['location_pct']:.0f}%) → SELL too risky"
                        result['severity'] = 'block'
                else:
                    # NO CHoCH = hard block (selling into bullish trend = suicide)
                    result['allowed'] = False
                    result['reason'] = f"🚫 BLOCKED: HTF BULLISH → NO SELLS (counter-trend without CHoCH)"
                    result['severity'] = 'block'
        
        # ═══════════════════════════════════════════════════════════════
        # 🔴 HTF BEARISH = RED LIGHT FOR BUYS, GREEN LIGHT FOR SELLS
        # ═══════════════════════════════════════════════════════════════
        elif htf_trend == 'bearish':
            if direction == 'sell':
                # ✅ PERFECT ALIGNMENT: HTF bearish + SELL
                result['allowed'] = True
                result['reason'] = f"🔴 HTF BEARISH → SELL ALLOWED (trend-following)"
                result['severity'] = 'ok'
            
            else:  # buy
                # 🚫 COUNTER-TREND: HTF bearish + BUY = BLOCKED
                # ONLY exception: Strong HTF CHoCH (reversal confirmed)
                if htf_choch:
                    # HTF CHoCH detected = trend may be reversing
                    # BUT: Still risky, so require price in discount zone
                    discount_check = is_price_in_htf_discount(price, df_h4, df_h1)
                    if discount_check['in_discount']:
                        result['allowed'] = True
                        result['reason'] = f"⚠️  HTF BEARISH + BUY: CHoCH detected + price in discount ({discount_check['location_pct']:.0f}%) → BUY allowed with caution"
                        result['severity'] = 'warn'
                    else:
                        # CHoCH but price not in discount = still too risky
                        result['allowed'] = False
                        result['reason'] = f"🚫 BLOCKED: HTF bearish + BUY, CHoCH detected but price NOT in discount ({discount_check['location_pct']:.0f}%) → BUY too risky"
                        result['severity'] = 'block'
                else:
                    # NO CHoCH = hard block (buying into bearish trend = suicide)
                    result['allowed'] = False
                    result['reason'] = f"🚫 BLOCKED: HTF BEARISH → NO BUYS (counter-trend without CHoCH)"
                    result['severity'] = 'block'
        
        # ═══════════════════════════════════════════════════════════════
        # 🟡 HTF NEUTRAL = YELLOW LIGHT (both allowed but filter by location)
        # ═══════════════════════════════════════════════════════════════
        else:  # htf_trend == 'none'
            # No clear HTF trend - allow both directions but apply STRICT location filter
            if direction == 'buy':
                # BUYs need to be in DISCOUNT zone (bottom 25%)
                discount_check = is_price_in_htf_discount(price, df_h4, df_h1)
                if discount_check['in_discount']:
                    result['allowed'] = True
                    result['reason'] = f"🟡 HTF NEUTRAL + BUY in discount ({discount_check['location_pct']:.0f}%) → ALLOWED"
                    result['severity'] = 'ok'
                else:
                    result['allowed'] = False
                    result['reason'] = f"🚫 BLOCKED: HTF neutral but BUY NOT in discount ({discount_check['location_pct']:.0f}%) → too risky"
                    result['severity'] = 'block'
            
            else:  # sell
                # SELLs need to be in PREMIUM zone (top 25%)
                premium_check = is_price_in_htf_premium(price, df_h4, df_h1)
                if premium_check['in_premium']:
                    result['allowed'] = True
                    result['reason'] = f"🟡 HTF NEUTRAL + SELL in premium ({premium_check['location_pct']:.0f}%) → ALLOWED"
                    result['severity'] = 'ok'
                else:
                    result['allowed'] = False
                    result['reason'] = f"🚫 BLOCKED: HTF neutral but SELL NOT in premium ({premium_check['location_pct']:.0f}%) → too risky"
                    result['severity'] = 'block'
        
        return result
    
    except Exception as e:
        # On error, BLOCK the trade (fail-safe)
        result['allowed'] = False
        result['reason'] = f"🚫 HTF validation error: {e} → BLOCKED for safety"
        result['severity'] = 'block'
        return result


