def advanced_fibonacci_confluence(price, direction, df_m15=None, df_h1=None, df_h4=None, symbol=None):
    """
    🎯 ADVANCED SNIPER FIBONACCI SYSTEM
    
    Multi-timeframe Fibonacci with smart swing detection, confluence zones,
    and precise entry scoring for catching exact reversals.
    
    Scoring (0-5 points):
    - Golden Pocket (0.618-0.786): +3.0 points (PRIME reversal zone)
    - Optimal Entry Zone (OTE 0.705-0.79): +4.0 points (BEST OF BEST)
    - Equilibrium (0.5): +1.5 points
    - Silver Zone (0.382-0.5): +1.0 point
    - Multi-TF alignment: +1.0 bonus per additional timeframe
    - Extension targets (1.272, 1.618): TP guidance
    
    Args:
        price: Current entry price
        direction: 'buy' or 'sell'
        df_m15, df_h1, df_h4: Price dataframes
        symbol: Symbol name for logging
    
    Returns:
        dict: {'score': float, 'levels': dict, 'reason': str, 'tp_targets': list}
    """
    result = {
        'score': 0.0,
        'levels': {},
        'reason': 'No Fib confluence',
        'golden_pocket': False,
        'ote_zone': False,
        'equilibrium': False,
        'mtf_count': 0,
        'tp_targets': [],
        'entry_precision': 0.0  # How close to ideal level (0-100%)
    }
    
    if price is None or direction is None:
        return result
    
    direction = direction.lower()
    
    # ========================================================================
    # SMART SWING DETECTION: Find most recent impulsive move
    # ========================================================================
    def find_smart_swing_points(df, lookback=50):
        """Find swing using structure breaks + ATR volatility"""
        try:
            if df is None or len(df) < 20:
                return None, None, None
            
            lookback = min(lookback, len(df))
            recent = df.tail(lookback)
            
            # Calculate ATR for volatility context
            highs = recent['high'].values
            lows = recent['low'].values
            closes = recent['close'].values
            
            tr = np.maximum(highs[1:], closes[:-1]) - np.minimum(lows[1:], closes[:-1])
            atr = tr[-14:].mean() if len(tr) >= 14 else tr.mean()
            
            # Find swing high (most recent strong high with rejection)
            swing_high_idx = None
            for i in range(len(recent) - 3, max(len(recent) - 25, 0), -1):
                if (highs[i] > highs[i-1] and highs[i] > highs[i+1] and 
                    highs[i] >= np.max(highs[i-2:i+3])):
                    swing_high_idx = i
                    break
            
            # Find swing low (most recent strong low with bounce)
            swing_low_idx = None
            for i in range(len(recent) - 3, max(len(recent) - 25, 0), -1):
                if (lows[i] < lows[i-1] and lows[i] < lows[i+1] and 
                    lows[i] <= np.min(lows[i-2:i+3])):
                    swing_low_idx = i
                    break
            
            # Use indices to get actual swing points
            swing_high = highs[swing_high_idx] if swing_high_idx else highs.max()
            swing_low = lows[swing_low_idx] if swing_low_idx else lows.min()
            
            # Validate: swing range should be at least 2x ATR (real impulse move)
            if (swing_high - swing_low) < (2 * atr):
                # Expand range to capture real move
                swing_high = highs.max()
                swing_low = lows.min()
            
            return swing_high, swing_low, atr
            
        except Exception as e:
            # Fallback to simple max/min
            try:
                lookback = min(lookback, len(df))
                return df['high'].tail(lookback).max(), df['low'].tail(lookback).min(), None
            except:
                return None, None, None
    
    # ========================================================================
    # CALCULATE PREMIUM FIB LEVELS
    # ========================================================================
    def calc_advanced_fib_levels(swing_high, swing_low, direction, atr=None):
        """Calculate Fib with extensions + premium zones"""
        if swing_high is None or swing_low is None or swing_high <= swing_low:
            return {}
        
        diff = swing_high - swing_low
        
        # For BUY: price retraces DOWN to Fib support, then bounces UP
        # For SELL: price retraces UP to Fib resistance, then rejects DOWN
        if direction == 'buy':
            levels = {
                # Retracement levels (from swing high down)
                '0.236': swing_high - 0.236 * diff,
                '0.382': swing_high - 0.382 * diff,
                '0.500': swing_high - 0.500 * diff,  # Equilibrium
                '0.618': swing_high - 0.618 * diff,  # Golden zone start
                '0.705': swing_high - 0.705 * diff,  # OTE (Optimal Trade Entry)
                '0.786': swing_high - 0.786 * diff,  # Golden zone end
                '0.886': swing_high - 0.886 * diff,  # Deep retracement
                '1.000': swing_low,  # Full retracement
                
                # Extension targets (for TP)
                'ext_1.272': swing_high + 0.272 * diff,  # First TP
                'ext_1.618': swing_high + 0.618 * diff,  # Primary TP (Golden extension)
                'ext_2.000': swing_high + 1.000 * diff,  # Extended TP
                'ext_2.618': swing_high + 1.618 * diff,  # Moon shot TP
            }
        else:  # sell
            levels = {
                # Retracement levels (from swing low up)
                '0.236': swing_low + 0.236 * diff,
                '0.382': swing_low + 0.382 * diff,
                '0.500': swing_low + 0.500 * diff,  # Equilibrium
                '0.618': swing_low + 0.618 * diff,  # Golden zone start
                '0.705': swing_low + 0.705 * diff,  # OTE
                '0.786': swing_low + 0.786 * diff,  # Golden zone end
                '0.886': swing_low + 0.886 * diff,  # Deep retracement
                '1.000': swing_high,  # Full retracement
                
                # Extension targets (for TP)
                'ext_1.272': swing_low - 0.272 * diff,  # First TP
                'ext_1.618': swing_low - 0.618 * diff,  # Primary TP
                'ext_2.000': swing_low - 1.000 * diff,  # Extended TP
                'ext_2.618': swing_low - 1.618 * diff,  # Moon shot TP
            }
        
        return levels
    
    # ========================================================================
    # PRECISION ZONE CHECKER
    # ========================================================================
    def check_price_in_zone(price, level_low, level_high, tolerance_pips=None):
        """Check if price within a Fib zone with smart tolerance"""
        if level_low is None or level_high is None:
            return False, 0.0
        
        # Ensure low < high
        if level_low > level_high:
            level_low, level_high = level_high, level_low
        
        # Auto-tolerance: 0.1% of zone width
        zone_width = level_high - level_low
        tolerance = tolerance_pips if tolerance_pips else (zone_width * 0.1)
        
        # Check if price in zone (with small buffer)
        in_zone = (level_low - tolerance) <= price <= (level_high + tolerance)
        
        # Calculate precision: how centered price is in zone (0-100%)
        if in_zone:
            zone_center = (level_low + level_high) / 2
            distance_from_center = abs(price - zone_center)
            precision = max(0, 100 - (distance_from_center / (zone_width / 2) * 100))
        else:
            precision = 0.0
        
        return in_zone, precision
    
    # ========================================================================
    # COLLECT MULTI-TIMEFRAME FIB LEVELS
    # ========================================================================
    timeframes_data = []
    
    # M15: Recent swings (last 50 bars = ~12.5 hours)
    if df_m15 is not None and len(df_m15) >= 20:
        swing_h, swing_l, atr_m15 = find_smart_swing_points(df_m15, lookback=50)
        levels_m15 = calc_advanced_fib_levels(swing_h, swing_l, direction, atr_m15)
        if levels_m15:
            timeframes_data.append(('M15', levels_m15, atr_m15))
    
    # H1: Medium swings (last 100 bars = ~4 days)
    if df_h1 is not None and len(df_h1) >= 20:
        swing_h, swing_l, atr_h1 = find_smart_swing_points(df_h1, lookback=100)
        levels_h1 = calc_advanced_fib_levels(swing_h, swing_l, direction, atr_h1)
        if levels_h1:
            timeframes_data.append(('H1', levels_h1, atr_h1))
    
    # H4: Major swings (last 200 bars = ~33 days)
    if df_h4 is not None and len(df_h4) >= 20:
        swing_h, swing_l, atr_h4 = find_smart_swing_points(df_h4, lookback=200)
        levels_h4 = calc_advanced_fib_levels(swing_h, swing_l, direction, atr_h4)
        if levels_h4:
            timeframes_data.append(('H4', levels_h4, atr_h4))
    
    if not timeframes_data:
        return result
    
    # ========================================================================
    # SCORE FIB CONFLUENCE WITH PRECISION
    # ========================================================================
    ote_hits = 0  # Optimal Trade Entry (0.705-0.79)
    golden_hits = 0  # Golden Pocket (0.618-0.786)
    equilibrium_hits = 0  # 0.5 level
    silver_hits = 0  # Silver zone (0.382-0.5)
    fib_reasons = []
    best_precision = 0.0
    tp_targets = []
    
    for tf_name, levels, atr in timeframes_data:
        # 🎯 OTE ZONE: 0.705-0.79 (BEST ENTRY)
        if '0.705' in levels and '0.786' in levels:
            in_ote, precision = check_price_in_zone(price, levels['0.705'], levels['0.786'])
            if in_ote:
                ote_hits += 1
                best_precision = max(best_precision, precision)
                fib_reasons.append(f"{tf_name} OTE (0.705-0.79)")
        
        # 🥇 GOLDEN POCKET: 0.618-0.786
        if '0.618' in levels and '0.786' in levels:
            in_gp, precision = check_price_in_zone(price, levels['0.618'], levels['0.786'])
            if in_gp and ote_hits == 0:  # Don't double count with OTE
                golden_hits += 1
                best_precision = max(best_precision, precision)
                fib_reasons.append(f"{tf_name} Golden Pocket (0.618-0.786)")
        
        # ⚖️ EQUILIBRIUM: 0.5 level (±0.3%)
        if '0.500' in levels:
            tolerance = abs(levels['0.500'] * 0.003)  # 0.3% tolerance
            if abs(price - levels['0.500']) <= tolerance:
                equilibrium_hits += 1
                fib_reasons.append(f"{tf_name} Equilibrium (0.5)")
        
        # 🥈 SILVER ZONE: 0.382-0.5
        if '0.382' in levels and '0.500' in levels:
            in_silver, _ = check_price_in_zone(price, levels['0.382'], levels['0.500'])
            if in_silver and golden_hits == 0 and ote_hits == 0:
                silver_hits += 1
                fib_reasons.append(f"{tf_name} Silver (0.382-0.5)")
        
        # Collect TP targets (extensions)
        if 'ext_1.272' in levels:
            tp_targets.append({'level': 'TP1', 'price': levels['ext_1.272'], 'tf': tf_name})
        if 'ext_1.618' in levels:
            tp_targets.append({'level': 'TP2 (Primary)', 'price': levels['ext_1.618'], 'tf': tf_name})
    
    # ========================================================================
    # CALCULATE FINAL SCORE
    # ========================================================================
    # OTE Zone: 4.0 base + 1.0 per additional TF
    if ote_hits > 0:
        result['ote_zone'] = True
        result['score'] += 4.0 + (ote_hits - 1) * 1.0
    
    # Golden Pocket: 3.0 base + 1.0 per additional TF
    elif golden_hits > 0:
        result['golden_pocket'] = True
        result['score'] += 3.0 + (golden_hits - 1) * 1.0
    
    # Equilibrium: 1.5 base + 0.5 per additional TF
    if equilibrium_hits > 0:
        result['equilibrium'] = True
        result['score'] += 1.5 + (equilibrium_hits - 1) * 0.5
    
    # Silver Zone: 1.0 point
    if silver_hits > 0:
        result['score'] += 1.0
    
    # Precision bonus: up to +1.0 for perfect center hits
    if best_precision > 0:
        precision_bonus = (best_precision / 100) * 1.0  # Max +1.0
        result['score'] += precision_bonus
        result['entry_precision'] = best_precision
    
    # Cap max score at 5.0
    result['score'] = min(result['score'], 5.0)
    result['mtf_count'] = len(timeframes_data)
    result['levels'] = timeframes_data
    result['tp_targets'] = tp_targets[:2]  # Top 2 TP targets
    
    if fib_reasons:
        result['reason'] = ' + '.join(fib_reasons)
        if best_precision > 80:
            result['reason'] += f" (🎯 {best_precision:.0f}% precision)"
    
    return result

def detect_sr_levels(df):
    """Detect support and resistance levels"""
    if df is None or len(df) < 10:
        return {"support": 0, "resistance": 0}
    highs = df['high'].values
    lows = df['low'].values
    return {
        "support": np.min(lows[-10:]),
        "resistance": np.max(highs[-10:])
    }

def calculate_stochastic(df):
    """Calculate Stochastic oscillator K and D"""
    if df is None or len(df) < 14:
        return pd.Series([0]*len(df)), pd.Series([0]*len(df))
    closes = df['close'].values
    highs = df['high'].values
    lows = df['low'].values
    k_values = []
    for i in range(14, len(closes)):
        high_14 = np.max(highs[i-14:i])
        low_14 = np.min(lows[i-14:i])
        k = 100 * (closes[i] - low_14) / (high_14 - low_14) if (high_14 - low_14) != 0 else 0
        k_values.append(k)
    k = pd.Series(k_values, index=df.index[14:])
    d = k.rolling(window=3).mean()
    return k, d

def calculate_macd(df):
    """Calculate MACD indicator"""
    if df is None or len(df) < 26:
        return pd.Series([0]*len(df)), pd.Series([0]*len(df))
    closes = df['close'].values
    ema_12 = pd.Series(closes).ewm(span=12, adjust=False).mean()
    ema_26 = pd.Series(closes).ewm(span=26, adjust=False).mean()
    macd = ema_12 - ema_26
    return macd, macd.ewm(span=9, adjust=False).mean()

def detect_market_regime(df):
    """Detect market regime: trending, ranging, or volatile"""
    if df is None or len(df) < 20:
        return "unknown"
    closes = df['close'].values
    returns = np.diff(closes) / closes[:-1]
    volatility = np.std(returns)
    trend_strength = abs(np.mean(returns)) / volatility if volatility > 0 else 0
    if trend_strength > 0.5:
        return "trending"
    elif volatility > 0.02:
        return "volatile"
    return "ranging"

def detect_volume_profile(df):
    """Detect volume profile point of control (POC)"""
    if df is None or len(df) < 10 or 'volume' not in df.columns:
        return np.median(df['close'].values) if df is not None else 0
    volumes = df['volume'].values
    closes = df['close'].values
    if len(volumes) == 0:
        return 0
    poc_idx = np.argmax(volumes[-20:]) if len(volumes) >= 20 else np.argmax(volumes)
    return closes[poc_idx] if poc_idx < len(closes) else 0

def htf_bias_aligned(htf_bias, direction):
    """
    Checks if higher timeframe bias matches trade direction.
    htf_bias: 'bullish' or 'bearish'
    direction: 'buy' or 'sell'
    Returns True if aligned and HTF structure is clear, else False.
    """
    if htf_bias is None or direction is None:
        return False
    if not isinstance(htf_bias, str) or not isinstance(direction, str):
        return False
    # Only allow if HTF bias is clear (bullish or bearish)
    if htf_bias.lower() not in ('bullish', 'bearish'):
        print("[HTF BIAS] Higher timeframe structure unclear. NO TRADE.")
        return False
    if htf_bias.lower() == 'bullish' and direction.lower() == 'buy':
        return True
    if htf_bias.lower() == 'bearish' and direction.lower() == 'sell':
        return True
    return False

def check_and_notify_symbol_profit(threshold_points=175):
    """
    Sends ONE notification per symbol when the total open profit for that symbol
    reaches or exceeds threshold_points.
    """
    positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
    if positions is None:
        return

    # Group positions by symbol
    symbol_positions = {}
    for pos in positions:
        symbol_positions.setdefault(pos.symbol, []).append(pos)

    for symbol, pos_list in symbol_positions.items():
        # Calculate total profit points for the symbol
        info = safe_symbol_info(symbol) if 'safe_symbol_info' in globals() else (mt5.symbol_info(symbol) if mt5 else None)
        if not info:
            continue

        point_value = info.point
        total_points = 0.0
        total_profit_usd = 0.0

        for pos in pos_list:
            # Points = absolute difference between current and open price divided by point size
            diff_points = abs((pos.price_current - pos.price_open) / point_value)
            total_points += diff_points
            total_profit_usd += pos.profit

        # If total points exceeds threshold and hasn't been notified yet
        if total_points >= threshold_points and symbol not in NOTIFIED_SYMBOLS:
            subject = f"🚀 {symbol} now +{int(total_points)} points total profit"
            body = (
                f"Symbol: {symbol}\n"
                f"Number of positions: {len(pos_list)}\n"
                f"Total profit (points): {int(total_points)}\n"
                f"Total profit (USD): {total_profit_usd:.2f}\n"
                f"Time: {datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S UTC')}\n"
            )
            try:
                send_email(
                    subject,
                    body,
                    to_email=(getattr(config, 'NOTIFY_EMAIL', None) if config is not None else None),
                    from_email=(getattr(config, 'SMTP_USER', None) if config is not None else None),
                    smtp_server=(getattr(config, 'SMTP_SERVER', 'smtp.example.com') if config is not None else 'smtp.example.com'),
                    smtp_port=(getattr(config, 'SMTP_PORT', 465) if config is not None else 465),
                    smtp_user=(getattr(config, 'SMTP_USER', None) if config is not None else None),
                    smtp_password=(getattr(config, 'SMTP_PASSWORD', None) if config is not None else None)
                )
                print(f"[EMAIL] Profit notification sent for {symbol}")
                NOTIFIED_SYMBOLS.add(symbol)
            except Exception as e:
                print(f"[EMAIL ERROR] Failed to send symbol profit notification: {e}")

    # Reset notification flag if symbol has no open positions anymore
    current_symbols = set(symbol_positions.keys())
    for s in list(NOTIFIED_SYMBOLS):
        if s not in current_symbols:
            NOTIFIED_SYMBOLS.remove(s)

def monitor_trade_for_quick_profit(ticket, symbol, direction, monitor_bars=SNIPER_MONITOR_BARS, min_profit_usd=SNIPER_MIN_PROFIT_USD):
    """
    After placing a trade, call this. Waits for `monitor_bars` full bars, then:
    - if PnL >= min_profit_usd: keep trade
    - if 0 < PnL < min_profit_usd: move SL to breakeven
    - if PnL <= 0: close trade (or move to tiny SL) to avoid getting stuck in a negative micro-drawdown
    NOTE: compares profit in account currency using mt5.positions_get() profit field.
    """
    # Wait for 'monitor_bars' new bar(s)
    # We'll poll price ticks and check number of closed candles to be safe
    check_interval = 5  # seconds
    start = time.time()
    bars_seen = 0
    last_bar_time = None
    # get initial bar time
    df = get_price_data(symbol, bars=monitor_bars+2)
    if df is None or df.empty:
        time.sleep(monitor_bars * 60)
    else:
        last_bar_time = df['time'].iloc[-1]

    # Wait until we see `monitor_bars` new closed bars
    while bars_seen < monitor_bars:
        df = get_price_data(symbol, bars=monitor_bars+2)
        if df is None or df.empty:
            time.sleep(check_interval)
            continue
        t = df['time'].iloc[-1]
        if last_bar_time is None or t > last_bar_time:
            bars_seen += 1
            last_bar_time = t
            # small sleep to allow a full bar to close
            time.sleep(1)
        else:
            time.sleep(check_interval)

    # After waiting, check current profit
    positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
    pos = None
    if positions:
        for p in positions:
            if getattr(p, "ticket", None) == ticket or (hasattr(p, "symbol") and p.symbol == symbol and (direction=="buy" and p.type==mt5.ORDER_TYPE_BUY or direction=="sell" and p.type==mt5.ORDER_TYPE_SELL)):
                pos = p
                break
    if not pos:
        # Position closed already (good or bad)
        return

    profit = getattr(pos, "profit", 0.0)
    # Decide action
    if profit >= min_profit_usd:
        print(f"[SNIPER MONITOR] Trade {ticket} PROFIT {profit:.2f} >= {min_profit_usd}. Keep running.")
        return
    elif 0 < profit < min_profit_usd:
        # Move SL to small profit / breakeven
        try:
            digits = mt5.symbol_info(symbol).digits
            new_sl = pos.price_open + (0.0 if direction=="buy" else 0.0)  # breakeven
            request = {
                "action": mt5.TRADE_ACTION_SLTP,
                "position": pos.ticket,
                "symbol": symbol,
                "sl": round(pos.price_open, digits),
                "tp": pos.tp
            }
            result = safe_order_modify(pos.ticket, pos.price_open, pos.price_open, pos.tp) if 'safe_order_modify' in globals() else mt5.order_send(request)
            print(f"[SNIPER MONITOR] Trade {ticket} small profit {profit:.2f}. SL moved to breakeven.")
        except Exception as e:
            print(f"[SNIPER MONITOR] move SL error: {e}")
        return
    else:
        # Loss or zero: close to limit damage
        try:
            tick_info = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
            if not tick_info:
                print(f"[SNIPER MONITOR] Could not get tick info for {symbol}. Trade {ticket} not closed.")
                return
            if direction == "buy":
                close_price = tick_info.bid
                close_type = mt5.ORDER_TYPE_SELL
            else:
                close_price = tick_info.ask
                close_type = mt5.ORDER_TYPE_BUY
            supported_modes = get_broker_supported_filling_modes(symbol)
            fill_mode = supported_modes[0] if supported_modes else mt5.ORDER_FILLING_RETURN
            close_req = {
                "action": mt5.TRADE_ACTION_DEAL,
                "position": pos.ticket,
                "symbol": symbol,
                "volume": pos.volume,
                "type": close_type,
                "price": close_price,
                "deviation": 20,
                "type_filling": fill_mode
            }
            res = safe_order_send(close_req) if 'safe_order_send' in globals() else mt5.order_send(close_req)
            print(f"[SNIPER MONITOR] Trade {ticket} closed due to no quick profit. result: {getattr(res, 'retcode', str(res))}")
        except Exception as e:
            print(f"[SNIPER MONITOR] Error closing trade {ticket}: {e}")
        return

# ====== PAUSE ON $50 LOSS ======
def check_and_pause_on_loss(threshold=PAUSE_ON_LOSS_THRESHOLD, pause_minutes=60):
    """
    Call this periodically (e.g., at main loop top). If realized losses for the day
    (or cumulative recent PnL from your logs) exceed threshold, set TRADING_PAUSED_UNTIL.
    """
    global TRADING_PAUSED_UNTIL
    # Use existing daily PnL function(s) if available
    try:
        daily_loss = get_total_daily_profit_loss()  # your function used elsewhere
    except Exception as e:
        logging.error(f"Error getting daily loss: {e}")
        daily_loss = get_daily_pnl()  # fallback name
    # daily_loss is positive for profit; we want cumulative losses
    if daily_loss <= -threshold:
        now = datetime.now(timezone.utc)
        if not TRADING_PAUSED_UNTIL or now > TRADING_PAUSED_UNTIL:
            TRADING_PAUSED_UNTIL = now + timedelta(minutes=pause_minutes)
            print(f"[PAUSE_ON_LOSS] Realized loss {daily_loss:.2f} <= -{threshold}. Pausing trading until {TRADING_PAUSED_UNTIL}.")
        return True
    return False

def get_max_daily_drawdown():
    """Returns the max daily drawdown in account currency."""
    starting_balance = get_starting_balance()
    return starting_balance * 0.10  # 10% drawdown

def get_current_drawdown():
    """
    Returns the current drawdown in account currency using a persistent
    high-water-mark (HWM). The function returns a tuple: `(drawdown_amount, drawdown_pct)`.
    - drawdown_amount: non-negative dollar amount below the HWM
    - drawdown_pct: percentage drawdown relative to the HWM (0.0 if HWM == 0)
    This is more intuitive than comparing to the day's starting balance.
    """
    try:
        current_equity = float(get_current_equity())
    except Exception:
        current_equity = 0.0

    # Load persisted HWM (if available); otherwise initialize from current equity
    hwm = None
    try:
        if os.path.exists(HWM_FILE):
            with open(HWM_FILE, 'r') as f:
                data = json.load(f)
                hwm = float(data.get('hwm', current_equity))
    except Exception:
        hwm = None

    if hwm is None:
        hwm = current_equity

    # Update HWM if we've reached a new peak
    if current_equity > hwm:
        hwm = current_equity
        try:
            with open(HWM_FILE, 'w') as f:
                json.dump({'hwm': hwm, 'updated': datetime.now(timezone.utc).isoformat()}, f)
        except Exception:
            pass

    drawdown = max(0.0, hwm - current_equity)
    drawdown_pct = (drawdown / hwm) * 100.0 if hwm > 0 else 0.0
    return drawdown


