def get_symbol_point_value(symbol):
    """
    Returns a tuple (point, digits, contract_size, usd_per_point)
    usd_per_point is estimated as contract_size * point * conversion_rate_to_account_currency
    We attempt to use `mt5.symbol_info` for accurate values, and fall back to sensible defaults.
    """
    try:
        info = None
        if 'safe_symbol_info' in globals():
            info = safe_symbol_info(symbol)
        elif mt5:
            info = mt5.symbol_info(symbol)
        if info:
            point = getattr(info, 'point', None) or (10 ** (-getattr(info, 'digits', 5)))
            digits = getattr(info, 'digits', 5)
            contract = getattr(info, 'trade_contract_size', getattr(info, 'contract_size', 100))
            # Estimate usd_per_point: contract * point. For forex cross pairs this is approximate.
            usd_per_point = float(contract) * float(point)
            return point, digits, contract, usd_per_point
    except Exception:
        pass
    # Fallback heuristics
    sym = str(symbol).upper()
    if 'XAU' in sym or 'GOLD' in sym:
        # XAU: point ~ 0.01, contract 100, usd_per_point ~ 1.0
        return 0.01, 2, 100, 1.0
    if 'JPY' in sym:
        # JPY pairs: point is 0.01, contract 100000, usd_per_point ~ 1.0
        return 0.01, 3, 100000, 1.0
    # Default forex point 0.0001
    return 0.0001, 5, 100000, 10.0


