def resolve_symbol_live(symbol):
    """
    Resolve a base symbol (e.g., 'XAUUSD') to the correct MT5 symbol name for the current broker,
    handling any prefix or suffix (e.g., '.m', '.ecn', 'fx.', etc.).
    For brokers with no prefix/suffix, this will match the exact symbol name.
    """
    try:
        all_mt5_symbols = [s.name for s in mt5.symbols_get()]
        # Try exact match first (for brokers with no prefix/suffix)
        if symbol in all_mt5_symbols:
            mt5.symbol_select(symbol, True)
            return symbol
        # Try case-insensitive match
        for s in all_mt5_symbols:
            if s.lower() == symbol.lower():
                mt5.symbol_select(s, True)
                return s
        # If the broker uses an alias for this canonical symbol (e.g., GOLD for XAUUSD),
        # try to resolve using the configured alias mapping.
        try:
            alias = BROKER_SYMBOL_ALIASES.get(symbol.upper()) if 'BROKER_SYMBOL_ALIASES' in globals() else None
            if alias:
                for s in all_mt5_symbols:
                    if _normalize_alias_name(s) == _normalize_alias_name(alias):
                        mt5.symbol_select(s, True)
                        return s
        except Exception:
            pass
        # Try to find a symbol that matches the base symbol exactly (ignoring suffixes/prefixes)
        for s in all_mt5_symbols:
            # Remove common suffixes/prefixes for comparison
            base = s.replace('.m','').replace('.pro','').replace('.ecn','').replace('.mini','').replace('.std','').replace('.fx','').replace('.i','').replace('.r','').replace('.s','')
            base = base.replace('fx.','').replace('cfd.','').replace('pro.','').replace('ecn.','').replace('mini.','').replace('std.','')
            if base == symbol:
                mt5.symbol_select(s, True)
                return s
        # Try with common suffixes
        suffixes = [".m", ".pro", ".ecn", ".mini", ".std", ".fx", ".i", ".r", ".s"]
        for suf in suffixes:
            candidate = symbol + suf
            if candidate in all_mt5_symbols:
                mt5.symbol_select(candidate, True)
                return candidate
        # Try with common prefixes
        prefixes = ["fx.", "cfd.", "pro.", "ecn.", "mini.", "std."]
        for pre in prefixes:
            candidate = pre + symbol
            if candidate in all_mt5_symbols:
                mt5.symbol_select(candidate, True)
                return candidate
        # Try partial match (e.g., USDJPY.mini, USDJPYmicro, etc.)
        partial_matches = [s for s in all_mt5_symbols if symbol.replace('.', '') in s.replace('.', '')]
        if partial_matches:
            mt5.symbol_select(partial_matches[0], True)
            return partial_matches[0]
        # If not found, print hint and return None
        print(f"[ERROR] Could not resolve symbol: {symbol}")
        print("[HINT] Ensure the symbol is visible in Market Watch and history is loaded.")
        return None
    except Exception as e:
        print(f"[RESOLVE] Exception resolving symbol {symbol}: {e}")
        print("[HINT] Ensure the symbol is visible in Market Watch and history is loaded.")
        return None

def get_all_live_symbols():
    if mt5 is None or not mt5.initialize():
        print("[MT5] Not initialized for symbol discovery.")
        return BASE_SYMBOLS
    live = []
    for base in BASE_SYMBOLS:
        resolved = resolve_symbol_live(base)
        if resolved:
            live.append(resolved)
    print(f"[INIT] Active broker symbols resolved: {live}")
    return live

