def apply_min_distance(symbol, sl, tp):
    """
    Ensures SL and TP are at least the minimum distance from entry, and not equal to entry.
    """
    # Set minimums for gold
    if "XAUUSD" in symbol:
        min_sl = config.get('min_sl_distance_xau', 2.0)
        min_tp = config.get('min_tp_distance_xau', 2.0)
    else:
        min_sl = MIN_SL_DISTANCE
        min_tp = MIN_TP_DISTANCE

    # If sl or tp is 0 or too close, force minimum
    sl = abs(sl)
    tp = abs(tp)
    if sl < min_sl or sl == 0:
        sl = min_sl
    if tp < min_tp or tp == 0:
        tp = min_tp
    return sl, tp
