def market_structure_higher_highs_and_lows(df):
    """
    Returns True if the last 3 swings show higher highs and higher lows (bullish structure).
    """
    if df is None or len(df) < 6:
        return False
    highs = df['high'].rolling(window=3).max()
    lows = df['low'].rolling(window=3).min()
    # Compare last 3 swings
    return highs.iloc[-1] > highs.iloc[-2] and lows.iloc[-1] > lows.iloc[-2]

def market_structure_lower_highs_and_lows(df):
    """
    Returns True if the last 3 swings show lower highs and lower lows (bearish structure).
    """
    if df is None or len(df) < 6:
        return False
    highs = df['high'].rolling(window=3).max()
    lows = df['low'].rolling(window=3).min()
    return highs.iloc[-1] < highs.iloc[-2] and lows.iloc[-1] < lows.iloc[-2]

def detect_support_resistance(df, num_levels=3):
    """
    Detects key support/resistance levels using swing highs/lows.
    Returns a list of price levels.
    """
    if df is None or len(df) < 10:
        return []
    swing_highs = df['high'].rolling(window=3).max()
    swing_lows = df['low'].rolling(window=3).min()
    levels = []
    levels += list(swing_highs.tail(num_levels).values)
    levels += list(swing_lows.tail(num_levels).values)
    return sorted(set([round(l, 2) for l in levels]))

def detect_order_blocks(df, num_blocks=2):
    """
    Detects order blocks as large candles with above-average volume.
    Returns a list of (open, close) tuples.
    """
    if df is None or len(df) < 20:
        return []
    # Use 'volume' if available, else fallback to 'tick_volume'
    vol_col = None
    if 'volume' in df.columns:
        vol_col = 'volume'
    elif 'tick_volume' in df.columns:
        vol_col = 'tick_volume'
    if vol_col:
        avg_vol = df[vol_col].rolling(window=20).mean().iloc[-1]
    else:
        avg_vol = None  # Or set to 0 if you prefer
    blocks = []
    for i in range(-10, 0):
        if vol_col and avg_vol is not None and df[vol_col].iloc[i] > avg_vol * 1.2:
            blocks.append((df['open'].iloc[i], df['close'].iloc[i]))
    return blocks[-num_blocks:]

def detect_breaker_block_fvg_confluence(price_data):
    """
    Detects confluence of a breaker block and FVG (Fair Value Gap).
    Returns dict with confluence info and signal if setup is valid.
    """
    # 1. Detect FVG
    fvg = detect_fvg(price_data)
    if not fvg:
        return {"signal": False, "reason": "No FVG"}
    # 2. Detect order blocks (breaker blocks)
    order_blocks = detect_order_blocks(price_data, num_blocks=3)
    if not order_blocks:
        return {"signal": False, "reason": "No breaker block"}
    # 3. Check for overlap/confluence
    fvg_low, fvg_high = fvg
    for ob_open, ob_close in order_blocks:
        ob_low, ob_high = min(ob_open, ob_close), max(ob_open, ob_close)
        # Overlap if FVG and order block price ranges intersect
        if fvg_high >= ob_low and fvg_low <= ob_high:
            return {
                "signal": True,
                "fvg": fvg,
                "breaker_block": (ob_open, ob_close),
                "reason": "Breaker Block + FVG Confluence"
            }
    return {"signal": False, "reason": "No confluence"}

