def detect_break_of_structure(df, swing_window=5, min_bars=10):
    """
    EXTREMELY ADVANCED: Detects break of structure (BOS) on 1H chart.
    - Uses swing high/low detection, volume, and candle confirmation
    Returns 'bullish', 'bearish', or None.
    """
    if df is None or len(df) < min_bars:
        return None
    # Find last swing high/low
    swing_high = df['high'].rolling(window=swing_window).max().iloc[-2]
    swing_low = df['low'].rolling(window=swing_window).min().iloc[-2]
    last_close = df['close'].iloc[-1]
    last_open = df['open'].iloc[-1]
    last_vol = df['tick_volume'].iloc[-1] if 'tick_volume' in df.columns else 0
    avg_vol = df['tick_volume'].rolling(window=10).mean().iloc[-2] if 'tick_volume' in df.columns else 0
    # Bullish BOS: last close > previous swing high with volume spike
    if last_close > swing_high and last_vol > avg_vol * 1.2:
        return "bullish"
    # Bearish BOS: last close < previous swing low with volume spike
    if last_close < swing_low and last_vol > avg_vol * 1.2:
        return "bearish"
    return None

def check_liquidity_grab(df, swing_window=5, min_bars=10):
    """
    EXTREMELY ADVANCED: Checks for robust liquidity sweep (grab) on 1H chart.
    - Requires price to take out previous swing high/low with volume spike
    Returns True if sweep detected.
    """
    if df is None or len(df) < min_bars:
        return False
    last = df.iloc[-1]
    swing_high = df['high'].rolling(window=swing_window).max().iloc[-2]
    swing_low = df['low'].rolling(window=swing_window).min().iloc[-2]
    last_vol = df['tick_volume'].iloc[-1] if 'tick_volume' in df.columns else 0
    avg_vol = df['tick_volume'].rolling(window=10).mean().iloc[-2] if 'tick_volume' in df.columns else 0
    sweep_up = last.high > swing_high and last_vol > avg_vol * 1.2
    sweep_down = last.low < swing_low and last_vol > avg_vol * 1.2
    return sweep_up or sweep_down

def detect_imbalance(df, min_gap=0.0002, min_bars=10):
    """
    EXTREMELY ADVANCED: Detects imbalance (Fair Value Gap) on 1H chart.
    - Finds largest FVG in last N bars, confirms with volume and price action
    Returns tuple (low, high) if FVG found, else None.
    """
    if df is None or len(df) < min_bars:
        return None
    max_gap = 0
    fvg = None
    for i in range(-min_bars+2, 0):
        prev_high = df['high'].iloc[i-2]
        prev_low = df['low'].iloc[i-2]
        curr_low = df['low'].iloc[i]
        curr_high = df['high'].iloc[i]
        # Bullish FVG: gap up
        if curr_low - prev_high > min_gap and (curr_low - prev_high) > max_gap:
            max_gap = curr_low - prev_high
            fvg = (prev_high, curr_low)
        # Bearish FVG: gap down
        if prev_low - curr_high > min_gap and (prev_low - curr_high) > max_gap:
            max_gap = prev_low - curr_high
            fvg = (curr_high, prev_low)
    # Confirm with volume in FVG region
    if fvg:
        region = df[(df['low'] >= fvg[0]) & (df['high'] <= fvg[1])]
        if not region.empty:
            avg_vol = df['tick_volume'].rolling(5).mean().iloc[-1] if 'tick_volume' in df.columns else 0
            if region['tick_volume'].mean() > avg_vol:
                return fvg
    return fvg

def detect_order_block_15m(df, min_bars=20, wick_threshold=0.5, min_body_ratio=0.5):
    """
    EXTREMELY ADVANCED: Detects robust order block on 15m chart.
    - Finds institutional candles (large body, large wick, high volume)
    - Confirms with structure break and liquidity sweep
    Returns (open, close) tuple or None.
    """
    if df is None or len(df) < min_bars:
        return None
    candles = df.tail(min_bars)
    bodies = (candles['close'] - candles['open']).abs()
    ranges = (candles['high'] - candles['low']).abs()
    wick_sizes = ranges - bodies
    body_ratios = bodies / (ranges + 1e-9)
    vol_col = 'volume' if 'volume' in candles.columns else 'tick_volume'
    high_vol = candles[vol_col] > candles[vol_col].rolling(10).mean()
    large_wick = wick_sizes > wick_threshold * ranges
    strong_body = body_ratios > min_body_ratio
    institutional = candles[high_vol & large_wick & strong_body]
    if not institutional.empty:
        ob_candle = institutional.iloc[-1]
        return (ob_candle['open'], ob_candle['close'])
    # Fallback: use lowest low and highest high of last 10 bars
    ob_low = candles['low'].iloc[-10:].min()
    ob_high = candles['high'].iloc[-10:].max()
    return (ob_low, ob_high)

def detect_imbalance_15m(df, min_gap=0.0001, min_bars=10):
    """
    EXTREMELY ADVANCED: Detects robust imbalance (FVG) on 15m chart.
    - Finds largest FVG in last N bars, confirms with volume and price action
    Returns (low, high) tuple or None.
    """
    if df is None or len(df) < min_bars:
        return None
    max_gap = 0
    fvg = None
    candles = df.tail(min_bars)
    for i in range(2, len(candles)):
        prev_high = candles['high'].iloc[i-2]
        prev_low = candles['low'].iloc[i-2]
        curr_low = candles['low'].iloc[i]
        curr_high = candles['high'].iloc[i]
        # Bullish FVG: gap up
        if curr_low - prev_high > min_gap and (curr_low - prev_high) > max_gap:
            max_gap = curr_low - prev_high
            fvg = (prev_high, curr_low)
        # Bearish FVG: gap down
        if prev_low - curr_high > min_gap and (prev_low - curr_high) > max_gap:
            max_gap = prev_low - curr_high
            fvg = (curr_high, prev_low)
    # Confirm with volume in FVG region
    if fvg:
        region = candles[(candles['low'] >= fvg[0]) & (candles['high'] <= fvg[1])]
        vol_col = 'volume' if 'volume' in candles.columns else 'tick_volume'
        if not region.empty:
            avg_vol = candles[vol_col].rolling(5).mean().iloc[-1]
            if region[vol_col].mean() > avg_vol:
                return fvg
    return fvg

# --- Helper functions for advanced logic ---

def advanced_liquidity_sweep(df, swing_window=5, min_bars=10):
    """
    Robust liquidity sweep: price takes out swing high/low with volume spike and wick.
    """
    if df is None or len(df) < min_bars:
        return False
    last = df.iloc[-1]
    swing_high = df['high'].rolling(window=swing_window).max().iloc[-2]
    swing_low = df['low'].rolling(window=swing_window).min().iloc[-2]
    last_vol = df['tick_volume'].iloc[-1] if 'tick_volume' in df.columns else 0
    avg_vol = df['tick_volume'].rolling(window=10).mean().iloc[-2] if 'tick_volume' in df.columns else 0
    wick = (last.high - last.low) - abs(last.close - last.open)
    sweep_up = last.high > swing_high and last_vol > avg_vol * 1.2 and wick > (last.high - last.low) * 0.4
    sweep_down = last.low < swing_low and last_vol > avg_vol * 1.2 and wick > (last.high - last.low) * 0.4
    return sweep_up or sweep_down

def advanced_detect_fvg(df, min_gap=0.0002, min_bars=10):
    """
    Finds the largest FVG in last N bars.
    """
    if df is None or len(df) < min_bars:
        return None
    max_gap = 0
    fvg = None
    for i in range(-min_bars+2, 0):
        prev_high = df['high'].iloc[i-2]
        prev_low = df['low'].iloc[i-2]
        curr_low = df['low'].iloc[i]
        curr_high = df['high'].iloc[i]
        if curr_low - prev_high > min_gap and (curr_low - prev_high) > max_gap:
            max_gap = curr_low - prev_high
            fvg = (prev_high, curr_low)
        if prev_low - curr_high > min_gap and (prev_low - curr_high) > max_gap:
            max_gap = prev_low - curr_high
            fvg = (curr_high, prev_low)
    return fvg

def advanced_fvg_fill(df, fvg, lookback=5):
    """
    Returns True if price filled the FVG in the last `lookback` bars.
    """
    if df is None or fvg is None:
        return False
    low, high = min(fvg), max(fvg)
    recent = df.tail(lookback)
    return any((low <= row.low <= high or low <= row.high <= high) for _, row in recent.iterrows())

def advanced_refined_entry(df, window=3):
    """
    Looks for strong reversal: engulfing, pin bar, or volume spike in last `window` bars.
    """
    if df is None or len(df) < window + 1:
        return False
    for i in range(1, window+1):
        last = df.iloc[-i]
        prev = df.iloc[-i-1]
        # Bullish engulfing
        bullish_engulf = last.close > last.open and last.open < prev.close and last.close > prev.open
        # Bearish engulfing
        bearish_engulf = last.close < last.open and last.open > prev.close and last.close < prev.open
        # Pin bar (long wick)
        pin_bar = (abs(last.close - last.open) < (last.high - last.low) * 0.3) and ((last.high - last.close) > (last.close - last.open) * 2 or (last.open - last.low) > (last.open - last.close) * 2)
        # Volume spike
        vol_col = 'volume' if 'volume' in df.columns else 'tick_volume'
        avg_vol = df[vol_col].rolling(window=5).mean().iloc[-i-1]
        vol_spike = last[vol_col] > avg_vol * 1.5
        if bullish_engulf or bearish_engulf or pin_bar or vol_spike:
            return True
    return False

def volume_spike_15m(df, spike_mult=1.7, window=15):
    """
    EXTREMELY ADVANCED: Returns True if last bar volume is a spike (>spike_mult x avg of last `window` bars),
    confirmed by price expansion and volatility.
    """
    if df is None or len(df) < window + 1:
        return False
    vol_col = 'volume' if 'volume' in df.columns else ('tick_volume' if 'tick_volume' in df.columns else None)
    if not vol_col:
        return False
    avg_vol = df[vol_col].rolling(window=window).mean().iloc[-2]
    last_vol = df[vol_col].iloc[-1]
    # Confirm with price expansion (range > 1.2x avg range)
    avg_range = (df['high'] - df['low']).rolling(window=window).mean().iloc[-2]
    last_range = df['high'].iloc[-1] - df['low'].iloc[-1]
    # Confirm with volatility spike (std dev of close)
    avg_std = df['close'].rolling(window=window).std().iloc[-2]
    last_std = df['close'].iloc[-window:].std()
    return (
        last_vol > avg_vol * spike_mult
        and last_range > avg_range * 1.2
        and last_std > avg_std * 1.1
    )

def micro_bos_15m(df, swing_window=4):
    """
    EXTREMELY ADVANCED: Returns True if last close breaks previous swing high/low (micro BOS),
    confirmed by volume and candle body size.
    """
    if df is None or len(df) < swing_window + 1:
        return False
    swing_high = df['high'].rolling(window=swing_window).max().iloc[-2]
    swing_low = df['low'].rolling(window=swing_window).min().iloc[-2]
    last_close = df['close'].iloc[-1]
    last_body = abs(df['close'].iloc[-1] - df['open'].iloc[-1])
    avg_body = (df['close'] - df['open']).abs().rolling(window=swing_window).mean().iloc[-2]
    vol_col = 'volume' if 'volume' in df.columns else ('tick_volume' if 'tick_volume' in df.columns else None)
    last_vol = df[vol_col].iloc[-1] if vol_col else 0
    avg_vol = df[vol_col].rolling(window=swing_window).mean().iloc[-2] if vol_col else 1
    bos = (last_close > swing_high or last_close < swing_low)
    return bos and last_body > avg_body * 1.1 and last_vol > avg_vol * 1.1

def price_enters_zone(price, zone):
    """
    EXTREMELY ADVANCED: Returns True if price enters the given zone (tuple of (low, high) or (open, close)).
    Handles string/float conversion, dict input, and tolerates floating point error.
    """
    if zone is None:
        return False
    try:
        price = float(price)
        # Handle dict input (e.g., {"low": ..., "high": ...})
        if isinstance(zone, dict):
            low = float(zone.get("low", float("-inf")))
            high = float(zone.get("high", float("inf")))
        else:
            # Assume tuple/list
            low, high = float(min(zone)), float(max(zone))
        # Allow for floating point tolerance
        return low - 1e-7 <= price <= high + 1e-7
    except (TypeError, ValueError):
        return False

def process_15m_chart(symbol):
    """
    EXTREMELY ADVANCED: Processes the 15m chart for entry confirmation.
    Returns entry_zone, confirmation.
    """
    df_15m = get_price_data(symbol, timeframe=mt5.TIMEFRAME_M15, bars=40)
    if df_15m is None or df_15m.empty:
        return None, False
    entry_zone = detect_order_block_15m(df_15m) or detect_imbalance_15m(df_15m)
    # Require both volume spike and micro BOS for confirmation
    confirmation = volume_spike_15m(df_15m) and micro_bos_15m(df_15m)
    return entry_zone, confirmation

def trend_shift_1min(df, window=6, rsi_window=14):
    """
    EXTREMELY ADVANCED: Returns True if 1min chart shows a trend shift (bullish to bearish or vice versa),
    confirmed by moving average cross and momentum.
    """
    if df is None or len(df) < window + 2:
        return False
    last3 = df['close'].iloc[-3:]
    prev3 = df['close'].iloc[-window:-3]
    # Confirm with fast/slow EMA cross
    fast_ema = df['close'].ewm(span=3, adjust=False).mean().iloc[-1]
    slow_ema = df['close'].ewm(span=6, adjust=False).mean().iloc[-1]
    ema_cross = (fast_ema > slow_ema and last3.mean() > prev3.mean()) or (fast_ema < slow_ema and last3.mean() < prev3.mean())
    # Confirm with momentum (RSI)
    delta = df['close'].diff()
    up = delta.clip(lower=0)
    down = -1 * delta.clip(upper=0)
    ma_up = up.rolling(window=rsi_window).mean().iloc[-1]
    ma_down = down.rolling(window=rsi_window).mean().iloc[-1]
    rs = ma_up / (ma_down + 1e-9)
    rsi = 100 - (100 / (1 + rs))
    return ema_cross and (rsi > 55 or rsi < 45)

def wick_rejection_1min(df):
    """
    EXTREMELY ADVANCED: Returns True if last 1min candle is a wick rejection (long wick, small body),
    confirmed by volume spike and price rejection.
    """
    if df is None or len(df) < 2:
        return False
    last = df.iloc[-1]
    prev = df.iloc[-2]
    body = abs(last.close - last.open)
    wick = (last.high - last.low) - body
    # Confirm with volume spike
    vol_col = 'volume' if 'volume' in df.columns else ('tick_volume' if 'tick_volume' in df.columns else None)
    last_vol = last[vol_col] if vol_col else 0
    avg_vol = df[vol_col].rolling(window=5).mean().iloc[-2] if vol_col else 1
    # Confirm price rejection: close near open, far from high/low
    rejection = min(abs(last.close - last.low), abs(last.close - last.high)) > body * 1.5
    return wick > body * 1.5 and last_vol > avg_vol * 1.2 and rejection

def price_respects_ob_1min(price, ob_zone):
    """
    EXTREMELY ADVANCED: Safely checks if price is within the order block zone.
    Handles cases where price or ob_zone values are not numeric, and allows for small tolerance.
    """
    try:
        if ob_zone is None or price is None:
            return False
        # If ob_zone is a dict, extract low/high
        if isinstance(ob_zone, dict):
            low = float(ob_zone.get("low", float("-inf")))
            high = float(ob_zone.get("high", float("inf")))
        elif isinstance(ob_zone, (tuple, list)) and len(ob_zone) == 2:
            low = float(ob_zone[0])
            high = float(ob_zone[1])
        else:
            return False
        price = float(price)
        return low - 1e-7 <= price <= high + 1e-7
    except Exception as e:
        print(f"[ERROR] price_respects_ob_1min: {e} (price={price}, ob_zone={ob_zone})")
        return False

def process_1min_chart(symbol, ob_zone):
    """
    EXTREMELY ADVANCED: Processes the 1min chart for sniper execution.
    Returns True if all sniper conditions met.
    """
    df_1m = get_price_data(symbol, timeframe=mt5.TIMEFRAME_M1, bars=15)
    if df_1m is None or df_1m.empty:
        return False
    price = df_1m['close'].iloc[-1]
    return (
        trend_shift_1min(df_1m)
        and wick_rejection_1min(df_1m)
        and price_respects_ob_1min(price, ob_zone)
    )

def process_1h_chart(symbol):
    """
    EXTREMELY ADVANCED: Processes the 1H chart for BOS, liquidity sweep, and imbalance.
    Returns bos, liquidity_swept, imbalance.
    """
    df_1h = get_price_data(symbol, timeframe=mt5.TIMEFRAME_H1, bars=60)
    if df_1h is None or df_1h.empty:
        return None, False, None
    bos = detect_break_of_structure(df_1h)
    liquidity_swept = check_liquidity_grab(df_1h)
    imbalance = detect_imbalance(df_1h)
    return bos, liquidity_swept, imbalance

def process_4h_chart(symbol):
    """
    EXTREMELY ADVANCED: Processes the 4H chart for bias and key levels.
    Returns bias, key_levels, order_blocks_4h.
    """
    df_4h = get_price_data(symbol, timeframe=mt5.TIMEFRAME_H4, bars=120)
    if df_4h is None or df_4h.empty:
        return "neutral", [], []
    
    # Use EMA bias as HTF filter
    if len(df_4h) >= 200:
        ema_50 = df_4h['close'].ewm(span=50, adjust=False).mean()
        ema_200 = df_4h['close'].ewm(span=200, adjust=False).mean()
        current_price = df_4h['close'].iloc[-1]
        current_ema_50 = ema_50.iloc[-1]
        current_ema_200 = ema_200.iloc[-1]
        
        if current_price > current_ema_50 > current_ema_200:
            bias = "bullish"
        elif current_price < current_ema_50 < current_ema_200:
            bias = "bearish"
        else:
            bias = "neutral"
    else:
        bias = "neutral"
    
    key_levels = detect_support_resistance(df_4h, num_levels=5)
    order_blocks_4h = detect_order_blocks(df_4h, num_blocks=3)
    return bias, key_levels, order_blocks_4h
import MetaTrader5 as mt5
import os
import json
from datetime import datetime

STARTING_BALANCE_FILE = "starting_balance.json"

ACCOUNT_INFO_FILE = "last_account_info.json"

def check_and_greet_account():
    """
    Checks the current MT5 account number/name.
    If changed since last run, resets session/account state and greets the account holder.
    """
    account_info = mt5.account_info()
    if account_info is None:
        print("[ERROR] Could not get account info for greeting.")
        return

    account_number = getattr(account_info, "login", None)
    account_name = getattr(account_info, "name", None)
    account_id = f"{account_number}_{account_name}"

    # Load last account info
    last_account_id = None
    if os.path.exists(ACCOUNT_INFO_FILE):
        with open(ACCOUNT_INFO_FILE, "r") as f:
            last_account_id = f.read().strip()

    # If account changed, reset state
    if last_account_id != account_id:
        print(f"\n👋 Welcome, {account_name} (Account #{account_number})! Starting fresh for this account.\n")
        # Reset starting balance, notifications, journals, etc.
        if os.path.exists(STARTING_BALANCE_FILE):
            os.remove(STARTING_BALANCE_FILE)
        # Optionally clear other files or flags here
        # Save new account info
        with open(ACCOUNT_INFO_FILE, "w") as f:
            f.write(account_id)
    else:
        print(f"\n👋 Welcome back, {account_name} (Account #{account_number})!\n")

def is_account_new():
    """
    Detect if the account is new by checking:
    1. If there are no closed trades/deals in MT5 history
    2. If the balance is close to the initial deposit (within 5% variance)
    
    Returns True if account is new, False otherwise.
    """
    try:
        if mt5 is None:
            return False
        
        account_info = mt5.account_info()
        if account_info is None:
            print("[NEWACCT] Could not get account info to check if new.")
            return False
        
        current_balance = account_info.balance
        initial_deposit = getattr(account_info, 'credit', current_balance)  # fallback to balance
        
        # Check 1: Are there any closed deals/trades?
        try:
            # Get all deals for the account (entire history)
            deals = mt5.history_deals_get(datetime(1970, 1, 1), datetime.now(timezone.utc))
            if deals and len(deals) > 0:
                # Account has trading history
                print(f"[NEWACCT] Account has {len(deals)} closed trades. Not a new account.")
                return False
        except Exception as e:
            print(f"[NEWACCT] Could not check deal history: {e}")
        
        # Check 2: Is balance close to initial deposit (within 5%)?
        if initial_deposit > 0:
            balance_variance = abs(current_balance - initial_deposit) / initial_deposit
            if balance_variance < 0.05:
                # Balance is within 5% of initial deposit → likely new account
                print(f"[NEWACCT] Account is new (balance ${current_balance:.2f} ~= initial ${initial_deposit:.2f}, variance {balance_variance*100:.1f}%)")
                return True
            else:
                print(f"[NEWACCT] Account is established (balance ${current_balance:.2f}, initial ${initial_deposit:.2f}, variance {balance_variance*100:.1f}%)")
                return False
        
        print("[NEWACCT] Could not determine if account is new.")
        return False
        
    except Exception as e:
        print(f"[NEWACCT] Error checking if account is new: {e}")
        return False

def reset_account_state_for_new_account():
    """
    Reset all drawdown trackers, stats, and risk controls for a newly detected account.
    This should be called once at startup before any trades are placed.
    
    Resets:
    - Equity High-Water-Mark (HWM) tracker
    - Starting balance cache
    - Session trades counter
    - Symbol cooldowns
    - Trading pause flags
    - Daily stats
    """
    global TRADING_PAUSED_UNTIL, _daily_start_balance, _doubling_notified, _last_balance_date, TRADING_STOPPED_FOR_DAY, TRADING_HALTED
    
    print("[NEWACCT] ⚠️  New account detected! Resetting all trackers and state...")
    
    try:
        # 1. Reset HWM (equity high-water-mark)
        if os.path.exists(HWM_FILE):
            os.remove(HWM_FILE)
            print(f"[NEWACCT] ✓ Deleted {HWM_FILE}")
        
        # Create fresh HWM with current equity
        account_info = mt5.account_info()
        if account_info:
            current_equity = account_info.equity
            with open(HWM_FILE, 'w') as f:
                json.dump({'hwm': current_equity, 'updated': datetime.now(timezone.utc).isoformat()}, f)
            print(f"[NEWACCT] ✓ Initialized HWM to current equity: ${current_equity:.2f}")
        
        # 2. Reset starting balance
        if os.path.exists(STARTING_BALANCE_FILE):
            os.remove(STARTING_BALANCE_FILE)
            print(f"[NEWACCT] ✓ Cleared {STARTING_BALANCE_FILE}")
        
        # 3. Reset session trades counter
        if os.path.exists(SESSION_TRADES_FILE):
            os.remove(SESSION_TRADES_FILE)
            print(f"[NEWACCT] ✓ Cleared {SESSION_TRADES_FILE}")
        
        # 4. Reset symbol cooldowns
        if os.path.exists(SESSION_COOLDOWNS_FILE):
            os.remove(SESSION_COOLDOWNS_FILE)
            print(f"[NEWACCT] ✓ Cleared {SESSION_COOLDOWNS_FILE}")
        
        # 5. Reset global flags
        TRADING_PAUSED_UNTIL = None
        _daily_start_balance = None
        _doubling_notified = False
        _last_balance_date = None
        TRADING_STOPPED_FOR_DAY = False
        TRADING_HALTED = False
        print("[NEWACCT] ✓ Reset global trading flags")
        
        # 6. Clear any trade journal for this account (optional)
        if os.path.exists(TRADE_JOURNAL_FILE):
            try:
                os.remove(TRADE_JOURNAL_FILE)
                print(f"[NEWACCT] ✓ Cleared {TRADE_JOURNAL_FILE}")
            except Exception:
                print(f"[NEWACCT] Could not clear {TRADE_JOURNAL_FILE}, continuing anyway")
        
        # 7. Initialize starting balance for the day
        get_starting_balance()  # This will create a fresh entry in STARTING_BALANCE_FILE
        
        print("[NEWACCT] ✅ Account state reset complete. Bot is ready to trade safely!")
        
    except Exception as e:
        print(f"[NEWACCT] ⚠️  Error resetting account state: {e}")

def get_starting_balance():
    """
    Returns the account balance at the start of the current trading day.
    Stores the value in a file and reuses it for the rest of the day.
    Includes account ID to ensure file is invalidated when account switches.
    """
    today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    current_account_id = get_account_id()
    
    # Try to load from file
    if os.path.exists(STARTING_BALANCE_FILE):
        try:
            with open(STARTING_BALANCE_FILE, "r") as f:
                data = json.load(f)
            # Only use cached balance if it's today AND same account ID
            if (data.get("date") == today and 
                data.get("account_id") == current_account_id and 
                "balance" in data and 
                data["balance"] > 0):
                return data["balance"]
        except Exception as e:
            print(f"[DEBUG] Could not load cached starting balance: {e}")
    
    # If not found, outdated, or account switched - get fresh from MT5
    account_info = mt5.account_info()
    if account_info is None:
        print("[ERROR] Could not get account info for starting balance.")
        return 100.0  # fallback minimum
    
    balance = account_info.balance
    # For new accounts, use the actual balance (even if low) to avoid false "doubled" alerts
    if balance <= 0:
        print(f"[WARN] Account balance invalid ({balance}), using $100 as starting balance.")
        balance = 100.0
    
    # Save with today's date AND account ID to detect switches
    try:
        with open(STARTING_BALANCE_FILE, "w") as f:
            json.dump({"date": today, "account_id": current_account_id, "balance": balance}, f)
    except Exception as e:
        print(f"[DEBUG] Could not save starting balance: {e}")
    
    return balance

def get_current_equity():
    """
    Returns the current account equity.
    """
    account_info = mt5.account_info()
    if account_info is None:
        print("[ERROR] Could not get account info for equity.")
        return 0.0
    return account_info.equity

def get_current_drawdown():
    """
    Returns the current drawdown in account currency using a persistent HWM.
    Non-negative float (0.0 when at or above HWM).
    """
    try:
        current_equity = float(get_current_equity())
    except Exception:
        current_equity = 0.0

    hwm = None
    try:
        if os.path.exists(HWM_FILE):
            with open(HWM_FILE, 'r') as f:
                data = json.load(f)
                hwm = float(data.get('hwm', current_equity))
    except Exception:
        hwm = None

    if hwm is None:
        hwm = current_equity

    if current_equity > hwm:
        hwm = current_equity
        try:
            with open(HWM_FILE, 'w') as f:
                json.dump({'hwm': hwm, 'updated': datetime.now(timezone.utc).isoformat()}, f)
        except Exception:
            pass

    drawdown = max(0.0, hwm - current_equity)
    return drawdown

def get_open_trades():
    """
    Returns a list of open trades as dicts with at least 'symbol', 'volume', 'price_open', and 'type'.
    """
    orders = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
    if orders is None:
        print("[ERROR] Could not get open trades from MT5.")
        return []
    trades = []
    for o in orders:
        trades.append({
            "symbol": o.symbol,
            "volume": o.volume,
            "price_open": o.price_open,
            "type": o.type,  # 0=buy, 1=sell
            "ticket": o.ticket,
            "profit": o.profit,
            "sl": getattr(o, "sl", None),
            "tp": getattr(o, "tp", None),
            "recovery": getattr(o, "comment", "").lower().find("recovery") != -1
        })
    return trades

