def monitor_recovery_and_hedge():
    """
    Monitors all open trades for recovery and hedge triggers.
    - If a trade is in recovery, grid orders are placed at scheduled levels.
    - If price moves adversely by a multiple of ATR, a hedge trade is placed.
    """
