def train_ensemble(X_train, y_train):
    """
    Train a stacking/voting ensemble of RF, XGBoost, LightGBM, and NN.
    Returns the fitted ensemble model.
    """
    rf = RandomForestClassifier(n_estimators=100, random_state=42)
    xgb = XGBClassifier(use_label_encoder=False, eval_metric='logloss', random_state=42, verbosity=0)
    lgb = LGBMClassifier(random_state=42, verbose=-1)
    nn = MLPClassifier(hidden_layer_sizes=(32, 16), max_iter=200, random_state=42)

    estimators = [
        ('rf', rf),
        ('xgb', xgb),
        ('lgb', lgb),
        ('nn', nn)
    ]
    # Voting ensemble (soft voting)
    ensemble = VotingClassifier(estimators=estimators, voting='soft')
    ensemble.fit(X_train, y_train)
    return ensemble, estimators

def save_model(model, version):
    path = os.path.join(MODEL_DIR, f"model_{version}.pkl")
    joblib.dump(model, path)
    print(f"[MODEL] Saved model version {version} to {path}")

def load_model(version):
    path = os.path.join(MODEL_DIR, f"model_{version}.pkl")
    return joblib.load(path)

def log_model_metrics(version, metrics):
    # Append or update metrics for this version
    if os.path.exists(MODEL_METRICS_FILE):
        with open(MODEL_METRICS_FILE, "r") as f:
            all_metrics = json.load(f)
    else:
        all_metrics = {}
    all_metrics[version] = metrics
    with open(MODEL_METRICS_FILE, "w") as f:
        json.dump(all_metrics, f, indent=2)

def save_feature_importance(importances, version):
    # Save feature importances for drift detection
    if os.path.exists(FEATURE_IMPORTANCE_FILE):
        with open(FEATURE_IMPORTANCE_FILE, "r") as f:
            all_importances = json.load(f)
    else:
        all_importances = {}
    all_importances[version] = importances
    with open(FEATURE_IMPORTANCE_FILE, "w") as f:
        json.dump(all_importances, f, indent=2)

def detect_feature_importance_drift(current_importance, prev_importance, threshold=0.2):
    """
    Returns True if drift is detected (any feature's importance changes by > threshold).
    """
    drift = False
    for feat in current_importance:
        prev = prev_importance.get(feat, 0)
        curr = current_importance[feat]
        if abs(curr - prev) > threshold:
            print(f"[DRIFT] Feature '{feat}' importance changed from {prev:.3f} to {curr:.3f}")
            drift = True
    return drift

def retrain_and_monitor(X_train, y_train, X_val, y_val, feature_names):
    # Versioning
    version = datetime.now().strftime("%Y%m%d_%H%M%S")
    # Train ensemble
    ensemble, estimators = train_ensemble(X_train, y_train)
    save_model(ensemble, version)
    # Evaluate
    val_score = ensemble.score(X_val, y_val)
    metrics = {"val_score": val_score}
    log_model_metrics(version, metrics)
    # Feature importance (average across tree models)
    importances = {}
    for name, est in estimators:
        if hasattr(est, "feature_importances_"):
            for i, feat in enumerate(feature_names):
                importances[feat] = importances.get(feat, 0) + est.feature_importances_[i]
    if importances:
        for feat in importances:
            importances[feat] /= 3  # average over RF, XGB, LGB
        save_feature_importance(importances, version)
        # Drift detection
        if os.path.exists(FEATURE_IMPORTANCE_FILE):
            with open(FEATURE_IMPORTANCE_FILE, "r") as f:
                all_importances = json.load(f)
            prev_versions = sorted(all_importances.keys())
            if len(prev_versions) > 1:
                prev_importance = all_importances[prev_versions[-2]]
                if detect_feature_importance_drift(importances, prev_importance):
                    print("[DRIFT] Feature importance drift detected! Pausing auto-trading.")
                    # Set a global flag or call your trading pause logic here
    return ensemble

def calculate_atr(df, period=14):
    if len(df) < period + 1:
        return 0
    high = df['high']
    low = df['low']
    close = df['close']
    tr = np.maximum(high[1:].values - low[1:].values,
                    np.abs(high[1:].values - close[:-1].values),
                    np.abs(low[1:].values - close[:-1].values))
    atr = pd.Series(tr).rolling(period).mean().iloc[-1]
    return 0 if np.isnan(atr) else float(atr)

def calculate_rsi(df, period=14):
    if len(df) < period + 1:
        return 50
    delta = df['close'].diff()
    up = delta.clip(lower=0)
    down = -1 * delta.clip(upper=0)
    ma_up = up.rolling(window=period).mean()
    ma_down = down.rolling(window=period).mean()
    rs = ma_up / (ma_down + 1e-9)
    rsi = 100 - (100 / (1 + rs))
    return 50 if np.isnan(rsi.iloc[-1]) else float(rsi.iloc[-1])

def calculate_ema(df, period=20):
    """
    Calculate the Exponential Moving Average (EMA) for a DataFrame with a 'close' column.
    Returns the most recent EMA value as a float, or np.nan if not enough data.
    Pure function: no side effects, no fallback to last close.
    """
    import numpy as np
    if len(df) < period or 'close' not in df:
        return np.nan
    ema = df['close'].ewm(span=period, adjust=False).mean()
    return np.nan if np.isnan(ema.iloc[-1]) else float(ema.iloc[-1])

def calculate_std(df, period=20):
    if len(df) < period:
        return 0
    std = df['close'].rolling(window=period).std()
    return 0 if np.isnan(std.iloc[-1]) else float(std.iloc[-1])



def can_open_trade(lot, sl_pips, symbol, entry_signal=None):
    """
    Enforces a hard risk cap per trade and for all open trades combined.
    Uses smart lot sizing to cap exposure during bad streaks.
    Returns True if the trade is allowed, False if it would exceed risk limits.
    entry_signal parameter is optional for compatibility with different callers.
    """
    import MetaTrader5 as mt5
    account_info = mt5.account_info()
    balance = account_info.balance if account_info else 1000
    # pip_value: 10 for most FX, 1 for JPY pairs, 0.1 for XAU
    pip_value = 10 if "JPY" not in symbol and "XAU" not in symbol else (1 if "JPY" in symbol else 0.1)

    # --- Dynamic lot sizing: reduce lot if recent losses ---
    all_positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
    recent_losses = sum([pos.profit for pos in all_positions or [] if pos.profit < 0])
    if recent_losses < -0.05 * balance:  # If recent losses >5% of balance, halve lot size
        lot = max(lot * 0.5, 0.01)

    trade_risk = (sl_pips * pip_value * lot) / balance
    if trade_risk > MAX_OPEN_RISK:
        print(f"[RISK] Trade risk {trade_risk:.2%} exceeds max per trade {MAX_OPEN_RISK:.2%}")
        return False

    total_risk = 0
    positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
    for pos in positions or []:
        pos_sl = abs(pos.price_open - pos.sl) if pos.sl > 0 else 0
        pos_pip_value = 10 if "JPY" not in pos.symbol and "XAU" not in pos.symbol else (1 if "JPY" in pos.symbol else 0.1)
        pos_risk = (pos_sl * pos_pip_value * pos.volume) / balance
        total_risk += pos_risk

    if total_risk + trade_risk > MAX_TOTAL_RISK:
        print(f"[RISK] Total open risk {total_risk + trade_risk:.2%} exceeds max allowed {MAX_TOTAL_RISK:.2%}")
        return False

    return True
