class WrappedModel:
    def __init__(self, model, threshold=None):
        self.model = model
        self.threshold = threshold if threshold is not None else CONFIDENCE_THRESHOLD
    def predict(self, features):
        X = np.array([[features.get(k, 0) for k in KERAS_FEATURE_ORDER_20]])
        # Assert input shape matches model
        if hasattr(self.model, "n_features_in_") and X.shape[1] != self.model.n_features_in_:
            print(f"[MODEL] Warning: feature length {X.shape[1]} != model.n_features_in_ {self.model.n_features_in_}")
        preds = self.model.predict(X)[0]
        label_idx, pattern_idx = preds[0], preds[1]
        # For confidence, use the main output's proba (safe version with error handling)
        proba = safe_predict_proba(self.model.estimators_[0], X, model_type="sklearn") if 'safe_predict_proba' in globals() else (self.model.estimators_[0].predict_proba(X)[0] if hasattr(self.model.estimators_[0], 'predict_proba') else [0.0] * 3)
        label_map = {0: "hold", 1: "buy", 2: "sell"}
        pattern_map = {0: "none", 1: "bullish", 2: "bearish"}
        label = label_map.get(label_idx, "hold")
        pattern_pred = pattern_map.get(pattern_idx, "none")
        confidence = float(proba[label_idx]) if label_idx < len(proba) else 0.0
        # --- 5. Dynamic threshold ---
        if confidence < self.threshold:
            return ("hold", confidence, pattern_pred)
        # --- 6. Allow trade if ML signal OR any filter is strong ---
        pattern_strength = features.get("pattern_score", 0)
        momentum = features.get("body_vs_avg", 0)
        structure = features.get("trend_alignment_score", 0)
        # Allow trade if ML signal is strong OR any filter is strong
        filter_pass = (
            pattern_strength >= MIN_TOTAL_SCORE or
            abs(momentum) >= 1.0 or
            abs(structure) >= 1
        )
        if label in ("buy", "sell") and not filter_pass:
            return ("hold", confidence, pattern_pred)
        return (label, confidence, pattern_pred)



