def detect_price_action_pattern(df, lookback=3):
    """
    Detects bullish/bearish price action patterns in the last few candles.
    Returns: "bullish", "bearish", or "none"
    """
    if len(df) < lookback + 1:
        return "none"
    recent = df.iloc[-lookback:]
    # Bullish engulfing
    if (
        recent['close'].iloc[-1] > recent['open'].iloc[-1] and
        recent['open'].iloc[-1] < recent['close'].iloc[-2] and
        recent['close'].iloc[-1] > recent['open'].iloc[-2]
    ):
        return "bullish"
    # Bearish engulfing
    if (
        recent['close'].iloc[-1] < recent['open'].iloc[-1] and
        recent['open'].iloc[-1] > recent['close'].iloc[-2] and
        recent['close'].iloc[-1] < recent['open'].iloc[-2]
    ):
        return "bearish"
    # Hammer (bullish reversal)
    if (
        recent['close'].iloc[-1] > recent['open'].iloc[-1] and
        (recent['low'].iloc[-1] < min(recent['open'].iloc[-1], recent['close'].iloc[-1]) - 2 * abs(recent['close'].iloc[-1] - recent['open'].iloc[-1]))
    ):
        return "bullish"
    # Shooting star (bearish reversal)
    if (
        recent['close'].iloc[-1] < recent['open'].iloc[-1] and
        (recent['high'].iloc[-1] > max(recent['open'].iloc[-1], recent['close'].iloc[-1]) + 2 * abs(recent['close'].iloc[-1] - recent['open'].iloc[-1]))
    ):
        return "bearish"
    # Strong up move
    if (recent['close'].iloc[-1] - recent['open'].iloc[-1]) > 2 * abs(recent['open'].iloc[-1] - recent['close'].iloc[-2]):
        return "bullish"
    # Strong down move
    if (recent['open'].iloc[-1] - recent['close'].iloc[-1]) > 2 * abs(recent['close'].iloc[-2] - recent['open'].iloc[-1]):
        return "bearish"
    return "none"
