def get_backtest_data(symbol=SYMBOLS, timeframe="M15", bars=None, from_year=2024, to_year=None, data_dir="./History"):
    import os
    import pandas as pd
    if isinstance(symbol, (list, tuple)):
        # if caller accidentally passed SYMBOLS list, pick first allowed symbol
        symbol = symbol[0] if symbol else "XAUUSD.ecn"

    # Try several filename patterns to be robust against broker suffixes
    base = str(symbol).split('.')[0]
    candidates = [
        f"{symbol}_M15.csv",
        f"{base}_M15.csv",
        f"{symbol.replace('.', '')}_M15.csv",
        f"{base}.m_M15.csv",
        f"{base}.ecn_M15.csv",
        f"{base}.m_M15.csv",
        f"{base}.M15.csv",
        f"{base}_M15.CSV"
    ]

    csv_path = None
    for c in candidates:
        p = os.path.join(data_dir, c)
        if os.path.exists(p):
            csv_path = p
            break

    # If not found, try a glob-style search for files that contain the base symbol
    if csv_path is None:
        try:
            for fname in os.listdir(data_dir):
                low = fname.lower()
                if base.lower() in low and ("m15" in low or "_m15" in low or "m_15" in low or low.endswith('.csv')):
                    candidate = os.path.join(data_dir, fname)
                    csv_path = candidate
                    break
        except Exception:
            pass

    if csv_path is None or not os.path.exists(csv_path):
        print(f"[BACKTEST] No CSV found for symbol '{symbol}' in {data_dir}. Tried: {candidates}")
        return None

    # Simple cache to avoid reloading large CSVs repeatedly
    global _BACKTEST_DATA_CACHE
    try:
        _BACKTEST_DATA_CACHE
    except NameError:
        _BACKTEST_DATA_CACHE = {}

    cache_key = (csv_path, timeframe, bars, from_year, to_year)
    if cache_key in _BACKTEST_DATA_CACHE:
        cached_df = _BACKTEST_DATA_CACHE[cache_key]
        return cached_df.copy()

    # Read with automatic separator detection (engine='python')
    df = pd.read_csv(csv_path, sep=None, engine='python')
    # Rename columns to standard names
    df.rename(columns={
        '<DATE>': 'date',
        '<TIME>': 'time',
        '<OPEN>': 'open',
        '<HIGH>': 'high',
        '<LOW>': 'low',
        '<CLOSE>': 'close',
        '<TICKVOL>': 'tick_volume',
        '<VOL>': 'real_volume',
        '<SPREAD>': 'spread'
    }, inplace=True)
    # Combine date and time into a single datetime column
    if 'date' in df.columns and 'time' in df.columns:
        df['time'] = pd.to_datetime(df['date'] + ' ' + df['time'], format='%Y.%m.%d %H:%M:%S', errors='coerce')
        df.drop(columns=['date'], inplace=True)
    elif 'time' in df.columns and isinstance(df['time'].iloc[0], str):
        # If time column is just a string, try to parse it
        df['time'] = pd.to_datetime(df['time'], format='%Y.%m.%d %H:%M:%S', errors='coerce')
    
    if 'time' not in df.columns:
        print(f"[ERROR] 'time' column missing in {csv_path}. Columns found: {df.columns.tolist()}")
        return None
    
    # Ensure time column is datetime
    if not pd.api.types.is_datetime64_any_dtype(df['time']):
        df['time'] = pd.to_datetime(df['time'], errors='coerce')
        if df['time'].isna().all():
            df['time'] = pd.to_datetime(df['time'], format='%Y.%m.%d %H:%M:%S', errors='coerce')
    
    if 'time' not in df.columns:
        print(f"[ERROR] 'time' column missing in {csv_path}. Columns found: {df.columns.tolist()}")
        return None
    
    # Ensure time column is datetime
    if not pd.api.types.is_datetime64_any_dtype(df['time']):
        df['time'] = pd.to_datetime(df['time'], errors='coerce')
    # Filter by a reasonable default start (2023) but respect from_year/to_year args
    try:
        if from_year:
            df = df[df['time'].dt.year >= int(from_year)]
        else:
            df = df[df['time'] >= pd.Timestamp('2023-01-01')]
        if to_year:
            df = df[df['time'].dt.year <= int(to_year)]
    except Exception:
        # If time parsing didn't work above, keep full df (later checks will catch it)
        pass

    if bars is not None and len(df) > bars:
        df = df.tail(bars).reset_index(drop=True)

    df = df.reset_index(drop=True)

    if len(df) < 50:
        print(f"[BACKTEST] Not enough data in {csv_path} (rows={len(df)}). Skipping.")
        return None

    print(f"[BACKTEST] Loaded {len(df)} rows for {symbol} from {csv_path}")

    # Keep last ~6 months for relevance (only trim if very long)
    approx_6months = 24 * 4 * 30 * 6
    if len(df) > approx_6months:
        df = df.tail(approx_6months).reset_index(drop=True)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")

    # Attach a symbol column for downstream code
    df['symbol'] = symbol
    try:
        _BACKTEST_DATA_CACHE[cache_key] = df.copy()
    except Exception:
        pass
    return df

def split_walkforward(df):
    """
    Splits DataFrame into train (2024), validate (early 2025), test (current live).
    Returns: train_df, val_df, test_df
    """
    train_start = pd.Timestamp("2023-01-01")
    train_end   = pd.Timestamp("2023-12-31 23:59:59")
    val_start   = pd.Timestamp("2024-01-01")
    val_end     = pd.Timestamp("2024-12-31 23:59:59")
    test_start  = pd.Timestamp("2025-01-01")

    train_df = df[(df['time'] >= train_start) & (df['time'] <= train_end)].copy()
    val_df = df[(df['time'] >= val_start) & (df['time'] <= val_end)].copy()
    test_df = df[df['time'] >= test_start].copy()
    return train_df, val_df, test_df

def detect_regime(df, lookback=100):
    """Return 'trend' or 'range' based on recent price action."""
    if len(df) < lookback:
        return "unknown"
    closes = df['close'].tail(lookback)
    # Simple regime: if std of returns > threshold, call it trend
    returns = closes.pct_change().dropna()
    if returns.std() > 0.002:  # tune this threshold
        return "trend"
    else:
        return "range"

def get_label(df, lookahead=5, profit_pips=10):
    """
    Returns 1 if price moves up by profit_pips within lookahead bars,
    2 if price moves down by profit_pips within lookahead bars,
    0 otherwise.
    """
    if len(df) < lookahead + 1:
        return None
    last_close = df['close'].iloc[-(lookahead+1)]
    pip = 0.01 if "JPY" in df.get('symbol', [''])[0] else 0.0001
    tp = last_close + profit_pips * pip
    sl = last_close - profit_pips * pip
    future = df['close'].iloc[-lookahead:]
    if (future >= tp).any():
        return 1  # buy
    elif (future <= sl).any():
        return 2  # sell
    else:
        return 0  # hold

def detect_structure(df, window=5, tolerance=1e-6):
    """
    Adds market structure points (HH, HL, LH, LL) as binary features to the DataFrame.
    Uses rolling window (default 5 bars) for comparison, making detection more sensitive.
    """
    df = df.copy()
    df.columns = [col.lower() for col in df.columns]
    # Rolling max/min for last N bars (excluding current)
    high_max = df['high'].rolling(window, min_periods=1).max().shift(1)
    low_max = df['low'].rolling(window, min_periods=1).max().shift(1)
    high_min = df['high'].rolling(window, min_periods=1).min().shift(1)
    low_min = df['low'].rolling(window, min_periods=1).min().shift(1)
    # HH: current high/low >= max of previous N highs/lows
    df['HH'] = ((df['high'] >= high_max - tolerance) & (df['low'] >= low_max - tolerance)).astype(int)
    # HL: current low >= min of previous N lows, high <= max of previous N highs
    df['HL'] = ((df['low'] >= low_min - tolerance) & (df['high'] <= high_max + tolerance)).astype(int)
    # LH: current high <= min of previous N highs, low <= max of previous N lows
    df['LH'] = ((df['high'] <= high_min + tolerance) & (df['low'] <= low_max + tolerance)).astype(int)
    # LL: current low <= min of previous N lows, high <= min of previous N highs
    df['LL'] = ((df['low'] <= low_min + tolerance) & (df['high'] <= high_min + tolerance)).astype(int)
    return df

def get_structure_last(df):
    """
    Returns the last market structure values (HH, HL, LH, LL) for a DataFrame.
    """
    df = detect_structure(df)
    return {k: int(df[k].iloc[-1]) if k in df.columns else 0 for k in ["HH", "HL", "LH", "LL"]}

