def detect_order_block(df, lookback=20, min_body_ratio=0.7, min_volume_spike=1.5):
    """
    Advanced order block detection:
    - Finds bullish/bearish order blocks (large candle, volume spike, structure break)
    - Returns dict: {'bull': 1/0, 'bear': 1/0, 'mitigation': 1/0, 'breaker': 1/0, 'displacement': 1/0, 'liquidity_sweep': 1/0}
    """
    result = {'bull': 0, 'bear': 0, 'mitigation': 0, 'breaker': 0, 'displacement': 0, 'liquidity_sweep': 0}
    if len(df) < lookback + 2:
        return result
    recent = df.tail(lookback)
    # Bullish order block: large bullish candle, volume spike, followed by structure break
    body = abs(recent['close'].iloc[-2] - recent['open'].iloc[-2])
    range_ = recent['high'].iloc[-2] - recent['low'].iloc[-2]
    body_ratio = body / (range_ + 1e-9)
    vol = recent['tick_volume'].iloc[-2]
    avg_vol = recent['tick_volume'].rolling(lookback).mean().iloc[-2]
    volume_spike = vol > min_volume_spike * avg_vol
    bullish = recent['close'].iloc[-2] > recent['open'].iloc[-2]
    bearish = recent['close'].iloc[-2] < recent['open'].iloc[-2]
    # Structure break: next candle closes above high (bull) or below low (bear)
    next_close = recent['close'].iloc[-1]
    prev_high = recent['high'].iloc[-2]
    prev_low = recent['low'].iloc[-2]
    # Bullish order block
    if bullish and body_ratio > min_body_ratio and volume_spike and next_close > prev_high:
        result['bull'] = 1
        # Displacement: next candle closes far above high
        if next_close > prev_high + 0.5 * (prev_high - recent['low'].iloc[-2]):
            result['displacement'] = 1
        # Liquidity sweep: next candle's low sweeps below previous low then closes above high
        if recent['low'].iloc[-1] < prev_low and next_close > prev_high:
            result['liquidity_sweep'] = 1
    # Bearish order block
    if bearish and body_ratio > min_body_ratio and volume_spike and next_close < prev_low:
        result['bear'] = 1
        if next_close < prev_low - 0.5 * (recent['high'].iloc[-2] - prev_low):
            result['displacement'] = 1
        if recent['high'].iloc[-1] > prev_high and next_close < prev_low:
            result['liquidity_sweep'] = 1
    # Mitigation: price returns to order block zone and reacts
    if result['bull'] and recent['low'].iloc[-1] < prev_low and next_close > prev_high:
        result['mitigation'] = 1
    if result['bear'] and recent['high'].iloc[-1] > prev_high and next_close < prev_low:
        result['mitigation'] = 1
    # Breaker: order block forms after failed sweep and then price breaks through
    if result['bull'] and recent['low'].iloc[-1] < prev_low and next_close > prev_high + 0.5 * (prev_high - recent['low'].iloc[-2]):
        result['breaker'] = 1
    if result['bear'] and recent['high'].iloc[-1] > prev_high and next_close < prev_low - 0.5 * (recent['high'].iloc[-2] - prev_low):
        result['breaker'] = 1
    return result


