def calculate_volume_profile_vpoc_feature(df, lookback=50):
    """Calculate distance from Volume Profile VPOC (Volume Point of Control)."""
    if len(df) < lookback:
        return 0.0
    
    window = df.iloc[-lookback:]
    current = df.iloc[-1]
    
    price_range = window['high'].max() - window['low'].min()
    num_bins = 20
    bin_size = price_range / num_bins if price_range > 0 else 0
    
    if bin_size == 0:
        return 0.0
    
    volume_by_price = {}
    for i in range(len(window)):
        candle = window.iloc[i]
        mid_price = (candle['high'] + candle['low']) / 2
        bin_idx = int((mid_price - window['low'].min()) / bin_size)
        bin_idx = min(bin_idx, num_bins - 1)
        
        if bin_idx not in volume_by_price:
            volume_by_price[bin_idx] = 0
        volume_by_price[bin_idx] += candle.get('tick_volume', candle.get('volume', 0))
    
    if not volume_by_price:
        return 0.0
    
    vpoc_bin = max(volume_by_price, key=volume_by_price.get)
    vpoc_price = window['low'].min() + (vpoc_bin * bin_size) + (bin_size / 2)
    
    distance_pct = (current['close'] - vpoc_price) / vpoc_price if vpoc_price > 0 else 0
    return distance_pct


def calculate_cumulative_volume_delta_feature(df, lookback=20):
    """Calculate Cumulative Volume Delta (CVD) for smart money tracking."""
    if len(df) < lookback:
        return 0.0
    
    window = df.iloc[-lookback:]
    
    cvd = 0.0
    for i in range(len(window)):
        candle = window.iloc[i]
        
        close_position = (candle['close'] - candle['low']) / (candle['high'] - candle['low']) if (candle['high'] - candle['low']) > 0 else 0.5
        
        volume = candle.get('tick_volume', candle.get('volume', 0))
        buy_volume = volume * close_position
        sell_volume = volume * (1 - close_position)
        
        delta = buy_volume - sell_volume
        cvd += delta
    
    total_volume = window['tick_volume'].sum() if 'tick_volume' in window else window.get('volume', pd.Series([0])).sum()
    if total_volume > 0:
        return cvd / total_volume
    
    return 0.0


def detect_inside_outside_bars_feature(df):
    """Detect Inside/Outside bar patterns. Returns 1=inside, 2=outside, 0=none."""
    if len(df) < 2:
        return 0
    
    current = df.iloc[-1]
    prev = df.iloc[-2]
    
    if current['high'] < prev['high'] and current['low'] > prev['low']:
        return 1  # Inside bar
    
    if current['high'] > prev['high'] and current['low'] < prev['low']:
        return 2  # Outside bar
    
    return 0


def calculate_htf_sr_proximity_feature(df, lookback=100):
    """Calculate distance to nearest HTF Support/Resistance."""
    if len(df) < lookback:
        return 0.0
    
    window = df.iloc[-lookback:]
    current = df.iloc[-1]
    
    swing_highs = []
    swing_lows = []
    
    for i in range(5, len(window)-5):
        if window.iloc[i]['high'] == window.iloc[i-5:i+6]['high'].max():
            swing_highs.append(window.iloc[i]['high'])
        
        if window.iloc[i]['low'] == window.iloc[i-5:i+6]['low'].min():
            swing_lows.append(window.iloc[i]['low'])
    
    if not swing_highs and not swing_lows:
        return 0.0
    
    nearest_resistance = min(swing_highs, key=lambda x: abs(x - current['close'])) if swing_highs else current['close'] * 1.1
    nearest_support = min(swing_lows, key=lambda x: abs(x - current['close'])) if swing_lows else current['close'] * 0.9
    
    dist_to_resistance = (nearest_resistance - current['close']) / current['close'] if current['close'] > 0 else 0
    dist_to_support = (current['close'] - nearest_support) / current['close'] if current['close'] > 0 else 0
    
    if dist_to_resistance < dist_to_support:
        return dist_to_resistance
    else:
        return -dist_to_support


def calculate_session_range_position_feature(df):
    """Calculate position within current session range (0-100%)."""
    if len(df) < 2:
        return 50.0
    
    session_start = max(0, len(df) - 96)  # Last 24h for M15
    session = df.iloc[session_start:]
    
    session_high = session['high'].max()
    session_low = session['low'].min()
    current = df.iloc[-1]
    
    if session_high - session_low == 0:
        return 50.0
    
    position = ((current['close'] - session_low) / (session_high - session_low)) * 100
    return position


def detect_volatility_regime_feature(df, lookback=50):
    """Detect volatility regime: 0=low, 1=normal, 2=high."""
    if len(df) < lookback:
        return 1
    
    window = df.iloc[-lookback:]
    
    returns = window['close'].pct_change().dropna()
    if len(returns) == 0:
        return 1
    
    current_vol = returns.std()
    
    rolling_vol = returns.rolling(20).std().dropna()
    if len(rolling_vol) == 0:
        return 1
    
    percentile_25 = rolling_vol.quantile(0.25)
    percentile_75 = rolling_vol.quantile(0.75)
    
    if current_vol > percentile_75:
        return 2
    elif current_vol < percentile_25:
        return 0
    else:
        return 1


def detect_momentum_divergence_feature(df, lookback=20):
    """Detect RSI/Price momentum divergence. Returns 1=bullish_div, -1=bearish_div, 0=none."""
    if len(df) < lookback + 14:
        return 0
    
    window = df.iloc[-lookback:]
    
    delta = window['close'].diff()
    gain = (delta.where(delta > 0, 0)).rolling(window=14).mean()
    loss = (-delta.where(delta < 0, 0)).rolling(window=14).mean()
    rs = gain / loss
    rsi = 100 - (100 / (1 + rs))
    
    if len(rsi) < 2:
        return 0
    
    recent_price_lows = []
    recent_rsi_lows = []
    
    for i in range(5, len(window)-5):
        if window.iloc[i]['low'] == window.iloc[i-5:i+6]['low'].min():
            recent_price_lows.append((i, window.iloc[i]['low']))
            recent_rsi_lows.append((i, rsi.iloc[i]))
    
    if len(recent_price_lows) >= 2:
        if recent_price_lows[-1][1] < recent_price_lows[-2][1]:
            if recent_rsi_lows[-1][1] > recent_rsi_lows[-2][1]:
                return 1  # Bullish divergence
    
    recent_price_highs = []
    recent_rsi_highs = []
    
    for i in range(5, len(window)-5):
        if window.iloc[i]['high'] == window.iloc[i-5:i+6]['high'].max():
            recent_price_highs.append((i, window.iloc[i]['high']))
            recent_rsi_highs.append((i, rsi.iloc[i]))
    
    if len(recent_price_highs) >= 2:
        if recent_price_highs[-1][1] > recent_price_highs[-2][1]:
            if recent_rsi_highs[-1][1] < recent_rsi_highs[-2][1]:
                return -1  # Bearish divergence
    
    return 0


def detect_pin_bar_feature(df):
    """Detect Pin Bar pattern. Returns 1=bullish_pin, -1=bearish_pin, 0=none."""
    if len(df) < 1:
        return 0
    
    current = df.iloc[-1]
    
    total_range = current['high'] - current['low']
    if total_range == 0:
        return 0
    
    body = abs(current['close'] - current['open'])
    upper_wick = current['high'] - max(current['close'], current['open'])
    lower_wick = min(current['close'], current['open']) - current['low']
    
    if body / total_range < 0.3:
        if lower_wick / total_range > 0.6:
            return 1  # Bullish pin
        
        if upper_wick / total_range > 0.6:
            return -1  # Bearish pin
    
    return 0


def calculate_htf_candle_position_feature(df):
    """Calculate where current M15 price is within HTF (H1) candle (0-100%)."""
    if len(df) < 4:
        return 50.0
    
    h1_candles = df.iloc[-4:]
    
    h1_high = h1_candles['high'].max()
    h1_low = h1_candles['low'].min()
    
    current = df.iloc[-1]
    
    if h1_high - h1_low == 0:
        return 50.0
    
    position = ((current['close'] - h1_low) / (h1_high - h1_low)) * 100
    return position


def calculate_close_position_pct_feature(df):
    """Calculate where close is within the candle range (0-100%)."""
    if len(df) < 1:
        return 50.0
    
    current = df.iloc[-1]
    
    total_range = current['high'] - current['low']
    if total_range == 0:
        return 50.0
    
    position = ((current['close'] - current['low']) / total_range) * 100
    return position


def get_features_fixed(df):
    # Defensive: handle short windows
    if len(df) < 20:
        return {k: 0 for k in [
            "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
            "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
            "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength",
            "distance_from_tp", "minutes_left_session", "atr_squeeze", "atr_burst",
            "macd", "macd_signal", "macd_hist", "obv", "divergence",
            "macd_cross", "htf_confluence", "volume_delta",
            "volume_spike", "volatility_spike",
            "adx", "order_block", "order_block_bull", "order_block_bear", "order_block_mitigation", "order_block_breaker", "order_block_displacement", "order_block_liquidity_sweep", "bos",
            "bsl", "ssl", "inducement"
        ]}

    features = {}

    def safe_feature(key, func, default=0):
        try:
            features[key] = func()
        except Exception:
            features[key] = default

    # --- Standard features ---
    safe_feature("atr", lambda: calculate_atr(df), 0)
    if "atr" not in features:
        features["atr"] = 0
    safe_feature("rsi", lambda: calculate_rsi(df), 50)
    safe_feature("ema200", lambda: calculate_ema(df, 200), 0)
    safe_feature("ema50", lambda: calculate_ema(df, 50), 0)
    safe_feature("ema20", lambda: calculate_ema(df, 20), 0)
    safe_feature("ema200_dist", lambda: df['close'].iloc[-1] - features["ema200"], 0)
    safe_feature("adx", lambda: calculate_adx(df), 0)  # <-- add new feature here

    # --- Advanced Order Block Features ---
    # Use the global detect_order_block function (defined at module level, not the nested version requiring direction)
    try:
        # Try calling the bullish order block detection
        ob_result_bull = detect_order_block(df, direction="bullish")
        # Try calling the bearish order block detection
        ob_result_bear = detect_order_block(df, direction="bearish")
    except (TypeError, KeyError, Exception):
        # Fallback if nested version is shadowing the global or any other error
        ob_result_bull = {'detected': False, 'block_high': 0, 'block_low': 0, 'strength': 0, 'impulse_bars': 0}
        ob_result_bear = {'detected': False, 'block_high': 0, 'block_low': 0, 'strength': 0, 'impulse_bars': 0}
    
    # Map new structure to feature names
    features["order_block"] = int(ob_result_bull.get("detected", False) or ob_result_bear.get("detected", False))
    features["order_block_bull"] = int(ob_result_bull.get("detected", False))
    features["order_block_bear"] = int(ob_result_bear.get("detected", False))
    features["order_block_mitigation"] = int(ob_result_bull.get("strength", 0) > 0) if ob_result_bull.get("detected") else int(ob_result_bear.get("strength", 0) > 0)
    features["order_block_breaker"] = ob_result_bull.get("strength", 0) if ob_result_bull.get("detected") else ob_result_bear.get("strength", 0)
    features["order_block_displacement"] = ob_result_bull.get("impulse_bars", 0) if ob_result_bull.get("detected") else ob_result_bear.get("impulse_bars", 0)
    features["order_block_liquidity_sweep"] = 0  # Not provided by detect_order_block, set to 0


    def prev_body():
        prev_open = df['open'].iloc[-2]
        prev_close = df['close'].iloc[-2]
        return abs(prev_close - prev_open)
    safe_feature("prev_body", prev_body, 0)

    def prev_wick():
        prev_high = df['high'].iloc[-2]
        prev_low = df['low'].iloc[-2]
        return (prev_high - prev_low) - features["prev_body"]
    safe_feature("prev_wick", prev_wick, 0)

    def prev_bull():
        prev_open = df['open'].iloc[-2]
        prev_close = df['close'].iloc[-2]
        return 1 if prev_close > prev_open else 0
    safe_feature("prev_bull", prev_bull, 0)

    safe_feature("std20", lambda: calculate_std(df, 20), 0)

    def get_now():
        # Keep last 6 months for training relevance
        if len(df) > (24*4*30*6):  # M15 candles in ~6 months
            df_trimmed = df.tail(24*4*30*6)
            # print(f"[DATA] Trimmed dataset to last 6 months ({len(df_trimmed)} bars).")
            return df_trimmed['time'].iloc[-1] if 'time' in df.columns else datetime.now(timezone.utc)
        return df['time'].iloc[-1] if 'time' in df.columns else datetime.now(timezone.utc)

    safe_feature("hour", lambda: get_now().hour, 12)
    safe_feature("day_of_week", lambda: get_now().weekday(), 2)
    safe_feature("volume", lambda: df['tick_volume'].iloc[-1], 0)

    # Volume delta
    try:
        v1 = df['tick_volume'].iloc[-1]
        v2 = df['tick_volume'].iloc[-2]
        if pd.isna(v1) or pd.isna(v2):
            features["volume_delta"] = 0
        else:
            features["volume_delta"] = int(v1) - int(v2)
    except Exception:
        features["volume_delta"] = 0

    # --- Volume/Volatility spike features for ML reversal detection ---
    try:
        # Volume spike: current volume > 1.5x rolling 20-bar mean
        features["volume_spike"] = int(features["volume"] > 1.5 * pd.Series(df['tick_volume']).rolling(20).mean().iloc[-1])
    except Exception:
        features["volume_spike"] = 0
    try:
        # Volatility spike: current ATR > 1.5x rolling 20-bar std
        features["volatility_spike"] = int(features["atr"] > 1.5 * pd.Series(df['close']).rolling(20).std().iloc[-1])
    except Exception:
        features["volatility_spike"] = 0

    # News filter
    def get_news_impact():
        try:
            import requests
            resp = requests.get(f"https://your-news-api.com/events?symbol={df.get('symbol', ['XAUUSD.ecn'])[-1]}&window=30")
            if resp.status_code == 200 and resp.json().get("high_impact"):
                return 1
            else:
                return 0
        except Exception:
            return 0
    safe_feature("news_impact", get_news_impact, 0)

    # No-trade zone
    def is_no_trade_zone():
        hour = features.get("hour", 12)
        return 21 <= hour < 23
    safe_feature("is_no_trade_zone", is_no_trade_zone, 0)

    # Smart lot sizing
    def smart_lot():
        try:
            account_info = mt5.account_info()
            balance = account_info.balance if account_info else 1000
            if balance < 10000:
                return 0.01
            risk_pct = 0.015
            atr = features.get("atr", 0.001)
            # Use symbol_info.point for pip/point math
            symbol = df["symbol"].iloc[-1] if "symbol" in df.columns and len(df) > 0 else None
            info = mt5.symbol_info(symbol) if symbol else None
            point = info.point if info else 0.01
            contract_size = info.trade_contract_size if info else 100
            # Calculate SL in points (e.g., 2x ATR)
            sl_points = max(atr * 2 / point, 10)
            pip_value = contract_size * point
            risk_amount = balance * risk_pct
            lot = risk_amount / (sl_points * pip_value)
            return round_lot_to_step(max(lot, 0.01), symbol)
        except Exception:
            return 0.01
    safe_feature("smart_lot", smart_lot, 0.01)

    # Hedge signal
    safe_feature("hedge_signal", lambda: 0, 0)

    # Trend filter MTF
    def trend_mtf():
        try:
            symbol = df["symbol"].iloc[-1] if "symbol" in df.columns and len(df) > 0 else None
            h1_df = get_price_data(symbol, timeframe=mt5.TIMEFRAME_H1, bars=200) if symbol else None
            if h1_df is not None and len(h1_df) > 50:
                ema200_h1 = calculate_ema(h1_df, 200)
                last_close = h1_df['close'].iloc[-1]
                return 1 if last_close > ema200_h1 else -1
        except Exception:
            pass
        return 0
    safe_feature("trend_mtf", trend_mtf, 0)

    # TA-Lib patterns + fallback to custom logic if TA-Lib not present or always 0
    def custom_bullish_engulfing():
        if len(df) < 2:
            return 0
        prev = df.iloc[-2]
        curr = df.iloc[-1]
        return int(
            prev["close"] < prev["open"] and
            curr["close"] > curr["open"] and
            curr["open"] < prev["close"] and
            curr["close"] > prev["open"]
        )

    def custom_bearish_engulfing():
        if len(df) < 2:
            return 0
        prev = df.iloc[-2]
        curr = df.iloc[-1]
        return int(
            prev["close"] > prev["open"] and
            curr["close"] < curr["open"] and
            curr["open"] > prev["close"] and
            curr["close"] < prev["open"]
        )

    def custom_hammer():
        if len(df) < 1:
            return 0
        c = df.iloc[-1]
        body = abs(c["close"] - c["open"])
        lower_wick = min(c["close"], c["open"]) - c["low"]
        upper_wick = c["high"] - max(c["close"], c["open"])
        total_range = c["high"] - c["low"]
        return int(
            body < total_range * 0.3 and
            lower_wick > body * 2 and
            upper_wick < body
        )

    def custom_morning_star():
        if len(df) < 3:
            return 0
        a, b, c = df.iloc[-3], df.iloc[-2], df.iloc[-1]
        return int(
            a["close"] < a["open"] and
            abs(b["close"] - b["open"]) < (a["open"] - a["close"]) * 0.5 and
            c["close"] > c["open"] and
            c["close"] > ((a["open"] + a["close"]) / 2)
        )

    def custom_three_white_soldiers():
        if len(df) < 3:
            return 0
        a, b, c = df.iloc[-3], df.iloc[-2], df.iloc[-1]
        return int(
            a["close"] > a["open"] and
            b["close"] > b["open"] and
            c["close"] > c["open"] and
            b["open"] > a["open"] and
            c["open"] > b["open"]
        )

    def custom_three_black_crows():
        if len(df) < 3:
            return 0
        a, b, c = df.iloc[-3], df.iloc[-2], df.iloc[-1]
        return int(
            a["close"] < a["open"] and
            b["close"] < b["open"] and
            c["close"] < c["open"] and
            b["open"] < a["open"] and
            c["open"] < b["open"]
        )

    def custom_shooting_star():
        if len(df) < 1:
            return 0
        c = df.iloc[-1]
        body = abs(c["close"] - c["open"])
        upper_wick = c["high"] - max(c["close"], c["open"])
        lower_wick = min(c["close"], c["open"]) - c["low"]
        total_range = c["high"] - c["low"]
        return int(
            body < total_range * 0.3 and
            upper_wick > body * 2 and
            lower_wick < body
        )

    def custom_evening_star():
        if len(df) < 3:
            return 0
        a, b, c = df.iloc[-3], df.iloc[-2], df.iloc[-1]
        return int(
            a["close"] > a["open"] and
            abs(b["close"] - b["open"]) < (a["close"] - a["open"]) * 0.5 and
            c["close"] < c["open"] and
            c["close"] < ((a["open"] + a["close"]) / 2)
        )

    def custom_pin_bar():
        if len(df) < 1:
            return 0
        c = df.iloc[-1]
        body = abs(c["close"] - c["open"])
        lower_wick = min(c["close"], c["open"]) - c["low"]
        upper_wick = c["high"] - max(c["close"], c["open"])
        total_range = c["high"] - c["low"]
        # Pin bar: long wick on one side, small body
        return int(
            body < total_range * 0.4 and
            (lower_wick > total_range * 0.6 or upper_wick > total_range * 0.6)
        )

    def custom_tweezer_bottom():
        if len(df) < 2:
            return 0
        prev = df.iloc[-2]
        curr = df.iloc[-1]
        return int(
            abs(prev["low"] - curr["low"]) < 0.001 * curr["low"] and
            curr["close"] > curr["open"]
        )

    def custom_tweezer_top():
        if len(df) < 2:
            return 0
        prev = df.iloc[-2]
        curr = df.iloc[-1]
        return int(
            abs(prev["high"] - curr["high"]) < 0.001 * curr["high"] and
            curr["close"] < curr["open"]
        )

    # Try TA-Lib, fallback to custom if always 0 or TA-Lib not present
    try:
        import talib
        if len(df) > 20:
            open_ = df['open'].values
            high_ = df['high'].values
            low_ = df['low'].values
            close_ = df['close'].values
            features["cdl_bullish_engulfing"] = int(talib.CDLENGULFING(open_, high_, low_, close_)[-1] > 0)
            features["cdl_bearish_engulfing"] = int(talib.CDLENGULFING(open_, high_, low_, close_)[-1] < 0)
            features["cdl_hammer"] = int(talib.CDLHAMMER(open_, high_, low_, close_)[-1] > 0)
            features["cdl_morning_star"] = int(talib.CDLMORNINGSTAR(open_, high_, low_, close_)[-1] > 0)
            features["cdl_three_white_soldiers"] = int(talib.CDL3WHITESOLDIERS(open_, high_, low_, close_)[-1] > 0)
            features["cdl_three_black_crows"] = int(talib.CDL3BLACKCROWS(open_, high_, low_, close_)[-1] > 0)
            features["cdl_shooting_star"] = int(talib.CDLSHOOTINGSTAR(open_, high_, low_, close_)[-1] > 0)
            features["cdl_evening_star"] = int(talib.CDLEVENINGSTAR(open_, high_, low_, close_)[-1] > 0)
            # If all are 0, fallback to custom
            if sum(features[k] for k in [
                "cdl_bullish_engulfing", "cdl_bearish_engulfing", "cdl_hammer", "cdl_morning_star",
                "cdl_three_white_soldiers", "cdl_three_black_crows", "cdl_shooting_star", "cdl_evening_star"
            ]) == 0:
                raise Exception("TA-Lib patterns all zero, fallback to custom")
    except Exception:
        features["cdl_bullish_engulfing"] = custom_bullish_engulfing()
        features["cdl_bearish_engulfing"] = custom_bearish_engulfing()
        features["cdl_hammer"] = custom_hammer()
        features["cdl_morning_star"] = custom_morning_star()
        features["cdl_three_white_soldiers"] = custom_three_white_soldiers()
        features["cdl_three_black_crows"] = custom_three_black_crows()
        features["cdl_shooting_star"] = custom_shooting_star()
        features["cdl_evening_star"] = custom_evening_star()

    # Always set custom patterns
    features["is_pin_bar"] = custom_pin_bar()
    features["is_tweezer_bottom"] = custom_tweezer_bottom()
    features["is_tweezer_top"] = custom_tweezer_top()
    features["is_bullish_engulfing"] = custom_bullish_engulfing()
    features["is_bearish_engulfing"] = custom_bearish_engulfing()
    features["is_hammer"] = custom_hammer()

    # --- ADVANCED PATTERN DETECTION (Never Misses Patterns) ---
    # Calculate comprehensive pattern strength by aggregating all detected patterns
    bullish_patterns_found = []
    bearish_patterns_found = []
    
    # Collect all bullish patterns
    bullish_pattern_weights = {
        "cdl_bullish_engulfing": (features.get("cdl_bullish_engulfing", 0), 2.0),
        "is_bullish_engulfing": (features.get("is_bullish_engulfing", 0), 2.0),
        "cdl_hammer": (features.get("cdl_hammer", 0), 1.8),
        "is_hammer": (features.get("is_hammer", 0), 1.8),
        "cdl_morning_star": (features.get("cdl_morning_star", 0), 1.5),
        "cdl_three_white_soldiers": (features.get("cdl_three_white_soldiers", 0), 1.7),
        "is_tweezer_bottom": (features.get("is_tweezer_bottom", 0), 1.5),
    }
    
    # Collect all bearish patterns
    bearish_pattern_weights = {
        "cdl_bearish_engulfing": (features.get("cdl_bearish_engulfing", 0), 2.0),
        "is_bearish_engulfing": (features.get("is_bearish_engulfing", 0), 2.0),
        "cdl_shooting_star": (features.get("cdl_shooting_star", 0), 1.8),
        "cdl_evening_star": (features.get("cdl_evening_star", 0), 1.5),
        "cdl_three_black_crows": (features.get("cdl_three_black_crows", 0), 1.7),
        "is_tweezer_top": (features.get("is_tweezer_top", 0), 1.5),
        "is_pin_bar": (features.get("is_pin_bar", 0), 1.6),  # Pin bars can be bearish
    }
    
    # Calculate weighted bullish strength
    bullish_strength_score = 0.0
    for pattern_name, (detected, weight) in bullish_pattern_weights.items():
        if detected > 0:
            bullish_patterns_found.append(pattern_name)
            bullish_strength_score += weight * detected
    
    # Calculate weighted bearish strength
    bearish_strength_score = 0.0
    for pattern_name, (detected, weight) in bearish_pattern_weights.items():
        if detected > 0:
            bearish_patterns_found.append(pattern_name)
            bearish_strength_score += weight * detected
    
    # Normalize scores to 0-10 scale
    bullish_score_normalized = min(bullish_strength_score, 10.0)
    bearish_score_normalized = min(bearish_strength_score, 10.0)
    
    # Advanced pattern enhancement: Check for strong candle body + volume
    try:
        curr = df.iloc[-1]
        prev = df.iloc[-2] if len(df) > 1 else None
        body = abs(curr["close"] - curr["open"])
        total_range = curr["high"] - curr["low"]
        body_ratio = body / total_range if total_range > 0 else 0
        avg_volume = df['tick_volume'].rolling(20).mean().iloc[-2] if len(df) > 20 else 1
        curr_volume = curr.get('tick_volume', 1)
        volume_ratio = curr_volume / avg_volume if avg_volume > 0 else 1
        
        # Strong bullish momentum: body > 0.7, above average volume
        if curr["close"] > curr["open"] and body_ratio > 0.7 and volume_ratio > 1.2:
            bullish_strength_score += 2.0
            bullish_patterns_found.append("strong_bullish_body_volume")
        
        # Strong bearish momentum: body > 0.7, above average volume
        if curr["close"] < curr["open"] and body_ratio > 0.7 and volume_ratio > 1.2:
            bearish_strength_score += 2.0
            bearish_patterns_found.append("strong_bearish_body_volume")
        
        # Bullish rejection (long lower wick + close near high)
        if len(df) > 1:
            lower_wick = min(curr["close"], curr["open"]) - curr["low"]
            upper_wick = curr["high"] - max(curr["close"], curr["open"])
            if lower_wick > total_range * 0.5 and curr["close"] > (curr["low"] + 0.7 * total_range):
                bullish_strength_score += 1.5
                bullish_patterns_found.append("bullish_rejection_wick")
            
            # Bearish rejection (long upper wick + close near low)
            if upper_wick > total_range * 0.5 and curr["close"] < (curr["high"] - 0.7 * total_range):
                bearish_strength_score += 1.5
                bearish_patterns_found.append("bearish_rejection_wick")
        
        # Consecutive bars in same direction (momentum continuation)
        if len(df) >= 3:
            bars_bullish = sum(1 for i in range(-3, 0) if df.iloc[i]["close"] >= df.iloc[i]["open"])
            bars_bearish = sum(1 for i in range(-3, 0) if df.iloc[i]["close"] < df.iloc[i]["open"])
            
            if bars_bullish == 3:  # Three consecutive bullish candles
                bullish_strength_score += 1.0
                bullish_patterns_found.append("three_consecutive_bullish")
            elif bars_bearish == 3:  # Three consecutive bearish candles
                bearish_strength_score += 1.0
                bearish_patterns_found.append("three_consecutive_bearish")
    except Exception:
        pass
    
    # Final normalization: Cap at 10.0
    features["bullish_pattern_strength"] = min(bullish_strength_score, 10.0)
    features["bearish_pattern_strength"] = min(bearish_strength_score, 10.0)
    
    # Aggregate pattern signal
    if bullish_strength_score > bearish_strength_score:
        features["pattern_score"] = bullish_strength_score / 10.0
    elif bearish_strength_score > bullish_strength_score:
        features["pattern_score"] = bearish_strength_score / 10.0
    else:
        features["pattern_score"] = 0.0
    
    # Debug logging (optional)
    if bullish_patterns_found or bearish_patterns_found:
        debug_patterns = f"Bullish: {bullish_patterns_found} ({bullish_strength_score:.1f}), Bearish: {bearish_patterns_found} ({bearish_strength_score:.1f})"
        # print(f"[PATTERN DEBUG] {debug_patterns}")

    # --- CONTEXT FEATURES FOR ML CONTEXT AWARENESS ---

    # 1. Distance to EMA200 (trend context, already present as ema200_dist)
    # 2. Distance to last swing high/low (structure context)
    def swing_high():
        lookback = 20
        if len(df) < lookback + 2:
            return 0
        return df['high'].rolling(lookback).max().iloc[-2]
    def swing_low():
        lookback = 20
        if len(df) < lookback + 2:
            return 0
        return df['low'].rolling(lookback).min().iloc[-2]
    safe_feature("dist_to_swing_high", lambda: df['close'].iloc[-1] - swing_high(), 0)
    safe_feature("dist_to_swing_low", lambda: df['close'].iloc[-1] - swing_low(), 0)

    # --- BSL/SSL (Buy-side/Sell-side liquidity) ---
    lookback = 20
    if len(df) >= lookback + 2:
        features["bsl"] = df['high'].rolling(lookback).max().iloc[-2]
        features["ssl"] = df['low'].rolling(lookback).min().iloc[-2]
    else:
        features["bsl"] = None
        features["ssl"] = None

    # --- Inducement detection ---
    # Inducement: price sweeps a recent swing low (SSL) or high (BSL) and then reverses
    features["inducement"] = 0
    if len(df) >= lookback + 3 and features["bsl"] is not None and features["ssl"] is not None:
        # Bullish inducement: price sweeps below SSL and closes above previous close
        prev_close = df['close'].iloc[-2]
        curr_low = df['low'].iloc[-1]
        curr_close = df['close'].iloc[-1]
        ssl = features["ssl"]
        bsl = features["bsl"]
        # Bullish inducement: sweep below SSL, close above previous close
        if curr_low < ssl and curr_close > prev_close:
            features["inducement"] = 1
        # Bearish inducement: sweep above BSL, close below previous close
        elif df['high'].iloc[-1] > bsl and curr_close < prev_close:
            features["inducement"] = 1

    # 3. Candle body ratio vs average (momentum context)
    def body_vs_avg():
        body = abs(df["close"].iloc[-1] - df["open"].iloc[-1])
        avg_body = abs(df["close"] - df["open"]).rolling(20).mean().iloc[-2]
        return body / avg_body if avg_body != 0 else 0
    safe_feature("body_vs_avg", body_vs_avg, 0)

    # 4. Recent ATR (volatility state, already present as "atr")

    # Defensive ensures
    if "atr" not in features:
        features["atr"] = 0
    for k in ["macd_cross", "htf_confluence", "volume_delta", "volume_spike", "volatility_spike"]:
        if k not in features:
            features[k] = 0
    # Add new context features to KERAS_FEATURE_ORDER_20 if not present
    for k in KERAS_FEATURE_ORDER_20 + [
        "dist_to_swing_high", "dist_to_swing_low", "body_vs_avg"
    ]:
        if k not in features:
            features[k] = 0
    assert len(KERAS_FEATURE_ORDER_20) == len(set(KERAS_FEATURE_ORDER_20)), "Feature order duplicate!"

    # print(f"[DEBUG] Features generated: {features}")
    # Add market structure features (use last row)
    # Add market structure features (use last row)
    for col in ["HH", "HL", "LH", "LL"]:
        if col in df.columns:
            features[col] = int(df[col].iloc[-1])
        else:
            features[col] = 0

    # --- Market structure and price action detection using new logic ---
    # Determine bias for direction (you may have a function for this)
    is_bullish = features.get("trend_alignment_score", 0) >= 0

    # Use new detection functions and assign their descriptive return values
    features["bos"] = detect_bos(df, is_bullish)
    features["sibi_bisi"] = detect_sibi_bisi(df, is_bullish)
    features["small_displacement"] = detect_small_displacement(df, is_bullish)
    # If you have a liquidity sweep detection function, use it here:
    features["liquidity_sweep"] = detect_liquidity_sweep(df) if "detect_liquidity_sweep" in globals() else 0

    # FVG detection (example, adapt to your actual function)
    fvg_info = detect_fvg(df) if "detect_fvg" in globals() else None
    if fvg_info:
        features["fvg"] = fvg_info.get("direction", None)
        features["fvg_zone"] = fvg_info.get("fvg", None)
        features["displacement_strength"] = fvg_info.get("displacement_strength", None)
    else:
        features["fvg"] = None
        features["fvg_zone"] = None
        features["displacement_strength"] = None

    # --- ONE-HOT ENCODE FVG (matches training encoding) ---
    fvg_val = features.get("fvg", "none")
    features["fvg_bull"] = 1 if fvg_val == "bull" else 0
    features["fvg_bear"] = 1 if fvg_val == "bear" else 0
    features["fvg_none"] = 1 if fvg_val == "none" or fvg_val is None else 0

    # --- BINARY ENCODE DISPLACEMENT STRENGTH ---
    disp_strength = features.get("displacement_strength", "weak")
    features["displacement_strong"] = 1 if disp_strength == "strong" else 0

    # --- CALCULATE INSTITUTIONAL MOVE (confluence of displacement + BOS + volume) ---
    has_displacement = features.get("displacement_strong", 0) == 1
    has_bos = features.get("bos", 0) != 0 and features.get("bos") is not None
    has_volume_spike = features.get("volume_spike", 0) == 1
    features["institutional_move"] = 1 if (has_displacement and has_bos and has_volume_spike) else 0

    # Add close price for entry zone checks
    features["close"] = df['close'].iloc[-1] if len(df) > 0 else None

    # --- Multi-timeframe market structure context ---
    symbol = df["symbol"].iloc[-1] if "symbol" in df.columns and len(df) > 0 else None
    # H1 structure
    h1_df = get_price_data(symbol, timeframe=mt5.TIMEFRAME_H1, bars=100) if symbol else None
    if h1_df is not None and len(h1_df) > 20:
        h1_struct = get_structure_last(h1_df)
        for k in h1_struct:
            features[f"H1_{k}"] = h1_struct[k]
    else:
        for k in ["HH", "HL", "LH", "LL"]:
            features[f"H1_{k}"] = 0
    # H4 structure
    h4_df = get_price_data(symbol, timeframe=mt5.TIMEFRAME_H4, bars=100) if symbol else None
    if h4_df is not None and len(h4_df) > 20:
        h4_struct = get_structure_last(h4_df)
        for k in h4_struct:
            features[f"H4_{k}"] = h4_struct[k]
    else:
        for k in ["HH", "HL", "LH", "LL"]:
            features[f"H4_{k}"] = 0

    # --- Example: Aggregate for "trend alignment score" ---
    # +1 for each timeframe showing HH/HL (uptrend), -1 for LH/LL (downtrend)
    trend_score = 0
    for tf in ["", "H1_", "H4_"]:
        if features.get(f"{tf}HH", 0) and features.get(f"{tf}HL", 0):
            trend_score += 1
        if features.get(f"{tf}LH", 0) and features.get(f"{tf}LL", 0):
            trend_score -= 1
    features["trend_alignment_score"] = trend_score

    # --- Countertrend detection ---
    # HTF = H4, LTF = current
    htf_bear = bool(features.get("H4_LH", 0)) or bool(features.get("H4_LL", 0))
    htf_bull = bool(features.get("H4_HH", 0)) or bool(features.get("H4_HL", 0))
    ltf_bull = bool(features.get("HH", 0)) or bool(features.get("HL", 0))
    ltf_bear = bool(features.get("LH", 0)) or bool(features.get("LL", 0))
    # Countertrend: HTF bearish, LTF bullish (or vice versa)
    features["countertrend_signal"] = int((htf_bear and ltf_bull) or (htf_bull and ltf_bear))

    # ============================================================================
    # TOP 10 HIGH-VALUE FEATURES (Aligned with train_modelv8.py)
    # ============================================================================
    try:
        features["volume_profile_vpoc_distance"] = calculate_volume_profile_vpoc_feature(df)
    except Exception:
        features["volume_profile_vpoc_distance"] = 0.0
    
    try:
        features["cumulative_volume_delta"] = calculate_cumulative_volume_delta_feature(df)
    except Exception:
        features["cumulative_volume_delta"] = 0.0
    
    try:
        features["inside_outside_bar"] = detect_inside_outside_bars_feature(df)
    except Exception:
        features["inside_outside_bar"] = 0
    
    try:
        features["htf_sr_proximity"] = calculate_htf_sr_proximity_feature(df)
    except Exception:
        features["htf_sr_proximity"] = 0.0
    
    try:
        features["session_range_position"] = calculate_session_range_position_feature(df)
    except Exception:
        features["session_range_position"] = 50.0
    
    try:
        features["volatility_regime"] = detect_volatility_regime_feature(df)
    except Exception:
        features["volatility_regime"] = 1
    
    try:
        features["momentum_divergence"] = detect_momentum_divergence_feature(df)
    except Exception:
        features["momentum_divergence"] = 0
    
    try:
        features["pin_bar_type"] = detect_pin_bar_feature(df)
    except Exception:
        features["pin_bar_type"] = 0
    
    try:
        features["htf_candle_position"] = calculate_htf_candle_position_feature(df)
    except Exception:
        features["htf_candle_position"] = 50.0
    
    try:
        features["close_position_pct"] = calculate_close_position_pct_feature(df)
    except Exception:
        features["close_position_pct"] = 50.0

    # Murphy-style entry classification (blend with ML)
    features["murphy_entry_type"] = classify_murphy_entry(df, features)
    return features

def classify_murphy_entry(df, features):
    """
    Returns 'sniper' if price is at/near key support/resistance and confirmed by strong pattern/volume,
    else 'normal' if ML signal/trend/structure align, else ''.
    """
    close = df['close'].iloc[-1]
    # --- BSL/SSL logic ---
    # BSL: Buy-side liquidity (recent swing high)
    # SSL: Sell-side liquidity (recent swing low)
    lookback = 20
    if len(df) >= lookback + 2:
        bsl = df['high'].rolling(lookback).max().iloc[-2]
        ssl = df['low'].rolling(lookback).min().iloc[-2]
    else:
        bsl = None
        ssl = None
    features["bsl"] = bsl
    features["ssl"] = ssl

    sr_support = features.get("sr_support", None)
    sr_resistance = features.get("sr_resistance", None)
    cdl_bullish = features.get("cdl_bullish_engulfing", 0) or features.get("cdl_hammer", 0)
    cdl_bearish = features.get("cdl_bearish_engulfing", 0) or features.get("cdl_shooting_star", 0)
    volume_spike = features.get("volume_spike", 0)
    body_vs_avg = features.get("body_vs_avg", 0)
    near_support = sr_support is not None and abs(close - sr_support) < 0.001 * close
    near_resistance = sr_resistance is not None and abs(close - sr_resistance) < 0.001 * close
    if (near_support and cdl_bullish and volume_spike) or (near_resistance and cdl_bearish and volume_spike):
        return "sniper"
    trend_score = features.get("trend_alignment_score", 0)
    ml_signal = features.get("ml_signal", "")
    if ml_signal in ("buy", "sell") and abs(trend_score) >= 1 and abs(body_vs_avg) >= 0.8:
        return "normal"
    return ""

def get_latest_signal():
    """
    Runs the ML model on the latest data and returns a signal string like 'BUY XAUUSD.m', 'SELL GBPUSD.m', or ''.
    Blends Murphy entry type with ML signal for context.
    """
    import pandas as pd
    import numpy as np
    from datetime import datetime, timezone

    # Choose the symbol to trade (e.g., XAUUSD.m)
    symbol = "XAUUSD.m"

    # Load the latest data (adjust path and logic as needed)
    df = get_backtest_data(symbol=symbol, timeframe="M15", bars=200)
    if df is None or len(df) < 50:
        print("[SIGNAL] Not enough data to generate signal.")
        return ""

    # Check for stale data
    if not stale_data_check(df, max_age_minutes=2):
        print("[SIGNAL] Data is stale, not trading.")
        return ""

    # Extract features
    features = get_features_fixed(df)

    # --- Prepare feature vector for the loaded model ---
    try:
        # Prepare feature vector
        feature_vector = [features.get(k, 0.0) for k in rf_feature_orders[symbol]]
        symbol_onehot = [int(symbol.startswith(s)) for s in rf_symbol_onehot_orders[symbol]]
        feature_vector += symbol_onehot
        X = np.array([feature_vector])

        # RandomForest prediction
        rf_pred = rf_models[symbol].predict(X)
        rf_proba = safe_predict_proba(rf_models[symbol], X, model_type="sklearn") if 'safe_predict_proba' in globals() else (rf_models[symbol].predict_proba(X) if hasattr(rf_models[symbol], 'predict_proba') else np.array([0.33, 0.33, 0.33]))
        rf_confidence = float(np.max(rf_proba[0]) if rf_proba.ndim > 1 else np.max(rf_proba))
        label_map = {0: "hold", 1: "buy", 2: "sell"}
        rf_signal = label_map.get(rf_pred[0], "hold")

        # XGBoost prediction
        xgb_X = xgb.DMatrix(X)
        xgb_pred = xgb_models[symbol].predict(xgb_X)
        xgb_signal = label_map.get(int(np.round(xgb_pred[0])), "hold")
        xgb_proba = xgb_models[symbol].predict(xgb_X, output_margin=False)
        if xgb_proba.ndim == 2:
            xgb_confidence = float(np.max(xgb_proba[0]))
        else:
            xgb_confidence = float(np.max(xgb_proba))

        # LightGBM prediction
        lgb_pred = lgb_models[symbol].predict(X)
        lgb_signal = label_map.get(int(np.round(lgb_pred[0])), "hold")
        lgb_proba = lgb_models[symbol].predict(X, raw_score=False)
        if isinstance(lgb_proba, np.ndarray) and lgb_proba.ndim == 2:
            lgb_confidence = float(np.max(lgb_proba[0]))
        else:
            lgb_confidence = float(np.max(lgb_proba))

        # Example: Use majority vote or pick the most confident model
        signals = [rf_signal, xgb_signal, lgb_signal]
        confidences = [rf_confidence, xgb_confidence, lgb_confidence]
        # Majority vote
        from collections import Counter
        vote = Counter(signals).most_common(1)[0][0]
        # Or pick the signal with highest confidence
        best_idx = int(np.argmax(confidences))
        ml_signal = signals[best_idx]
        confidence = confidences[best_idx]
        features["ml_signal"] = ml_signal  # For Murphy entry logic

    except Exception as e:
        print(f"[SIGNAL] Model prediction error: {e}")

    # Murphy-style entry type
    murphy_entry_type = features.get("murphy_entry_type", "")

    # --- ADVANCED FILTER: Require liquidity sweep, order block, or BOS ---
    liquidity_sweep = features.get("liquidity_sweep", 0)
    order_block = features.get("order_block", 0)
    # BOS (Break of Structure) is not being set in get_features_fixed!
    # Let's define BOS as a break above HH (bullish) or below LL (bearish) compared to previous bar.
    prev_hh = df['high'].iloc[-2] if len(df) > 1 else 0
    prev_ll = df['low'].iloc[-2] if len(df) > 1 else 0
    curr_hh = df['high'].iloc[-1]
    curr_ll = df['low'].iloc[-1]
    bos = int((curr_hh > prev_hh) or (curr_ll < prev_ll))
    countertrend_signal = features.get("countertrend_signal", 0)
    # Log the feature values
    print(f"[ENTRY FILTER] liquidity_sweep={liquidity_sweep}, order_block={order_block}, bos={bos}, countertrend_signal={countertrend_signal}, ml_signal={ml_signal}, confidence={confidence:.2f}")

    # Only trade if confidence is high enough, not "hold", AND one of the advanced features is present
    # OR if countertrend signal is present
    # --- Confirmation logic ---
    confirmation = False
    if ml_signal == "buy" and confidence >= CONFIDENCE_THRESHOLD and (liquidity_sweep or order_block or bos or countertrend_signal):
        confirmation = True
        print(f"[TRADE] BUY {symbol} | EntryType: {murphy_entry_type} | Reason: Advanced feature or countertrend present")
        return f"BUY {symbol} | EntryType: {murphy_entry_type}"
    elif ml_signal == "sell" and confidence >= CONFIDENCE_THRESHOLD and (liquidity_sweep or order_block or bos or countertrend_signal):
        confirmation = True
        print(f"[TRADE] SELL {symbol} | EntryType: {murphy_entry_type} | Reason: Advanced feature or countertrend present")
        return f"SELL {symbol} | EntryType: {murphy_entry_type}"
    else:
        print(f"[NO TRADE] Blocked by advanced filter: liquidity_sweep={liquidity_sweep}, order_block={order_block}, bos={bos}, countertrend_signal={countertrend_signal}, confirmation={confirmation}, price={df['close'].iloc[-1]}")
        return ""

