def detect_feature_importance_drift(current_importance, prev_importance, threshold=0.2):
    drift = False
    for feat in current_importance:
        prev = prev_importance.get(feat, 0)
        curr = current_importance[feat]
        if abs(curr - prev) > threshold:
            print(f"[DRIFT] Feature '{feat}' importance changed from {prev:.3f} to {curr:.3f}")
            drift = True
    return drift



def evaluate_model(models, split="val"):
    """
    Evaluate the given models dict on the specified data split ("val" or "test").
    Returns a dict with at least a 'net_profit' key for A/B selection.
    Evaluates all backtest symbols and returns their net profits.
    """
    # Use .ecn symbols for backtest and reporting
    # ONLY PROFITABLE SYMBOLS
    backtest_symbols = ["XAUUSD.m", "AUDUSD.m", "NZDUSD.m"]
    results = {}
    for symbol in backtest_symbols:
        # Try to load data for .ecn, fallback to .m if not found
        df = get_backtest_data(symbol, timeframe="M15", from_year=2023)
        if (df is None or len(df) < 100) and symbol.endswith(".ecn"):
            alt_symbol = symbol.replace(".ecn", ".m")
            df = get_backtest_data(alt_symbol, timeframe="M15", from_year=2023)
        if df is None or len(df) < 100:
            results[symbol] = 0
            continue
        train_df, val_df, test_df = split_walkforward(df)
        if split == "val":
            eval_df = val_df
        else:
            eval_df = test_df
        if eval_df is None or len(eval_df) < 50:
            results[symbol] = 0
            continue
        # Simple walk-forward: simulate trades using model predictions
        equity = 0
        for i in range(50, len(eval_df) - 5):
            window = eval_df.iloc[:i+1]
            features = get_features_fixed(window)
            pred = models[symbol].predict(features)
            ml_signal, confidence, *_ = extract_ml_signal_and_confidence(pred, models[symbol], features)

            if ml_signal not in ("buy", "sell"):
                continue
            # --- ENFORCE MINIMUM CONFIDENCE FOR LIVE AND BACKTEST TRADES ---
            CONFIDENCE_THRESHOLD = 0.85  # Set your desired minimum confidence here
            if confidence < CONFIDENCE_THRESHOLD:
                continue
            entry = window['close'].iloc[-1]
            # Dynamically set SL/TP based on ATR and a risk/reward ratio
            atr = features.get("atr", 0.2)
            # --- SWING/INTRADAY: Use wider stops and targets for ALL symbols ---
            if "XAU" in symbol:
                min_sl_tp = 5.0   # 5 dollars for gold swing
            elif "JPY" in symbol:
                min_sl_tp = 0.15  # 15 pips for JPY pairs
            else:
                min_sl_tp = 0.0015  # 15 pips for all other FX pairs (EURUSD, AUDUSD, etc)
            sl_dist = max(atr * 4, min_sl_tp)  # Use 4x ATR for swing/intraday
            rr_ratio = 2.5  # More ambitious RR for swing/intraday
            if ml_signal == "buy":
                sl = entry - sl_dist
                tp = entry + sl_dist * rr_ratio
            else:
                sl = entry + sl_dist
                tp = entry - sl_dist * rr_ratio
            # Simulate outcome: if next 5 bars hit TP or SL
            future = eval_df['close'].iloc[i+1:i+6]
            if ml_signal == "buy":
                if (future >= tp).any():
                    equity += tp - entry
                elif (future <= sl).any():
                    equity += sl - entry
            else:
                if (future <= tp).any():
                    equity += entry - tp
                elif (future >= sl).any():
                    equity += entry - sl
        results[symbol] = equity
    output = {"net_profit": sum(results.values())}
    for symbol in backtest_symbols:
        output[symbol] = results.get(symbol, 0)
    return output

def ab_test_and_promote():
    # Train two models with different params
    models_a = {sym: EnsembleMLModel(sym) for sym in SYMBOLS}
    models_b = {sym: EnsembleMLModel(sym) for sym in SYMBOLS}
    # Evaluate on validation set
    val_metrics_a = evaluate_model(models_a, "val")
    val_metrics_b = evaluate_model(models_b, "val")
    # Promote the better model
    if val_metrics_a["net_profit"] > val_metrics_b["net_profit"]:
        # Save logic for ensemble models if needed
        print("[A/B TEST] Promoted model A")
    else:
        print("[A/B TEST] Promoted model B")

def initialize_model(model_type="random_forest", **kwargs):
    """
    Initialize and return the selected ML model.
    Supported types: random_forest, voting_ensemble, stacking_ensemble, regime_switch, deep_learning
    """
    if model_type == "random_forest":
        from sklearn.ensemble import RandomForestClassifier
        model = RandomForestClassifier(n_estimators=100)
        # Load or train your model here
        return model
    elif model_type == "voting_ensemble":
        # Example: Voting ensemble of several models



        class EnsembleMLModel:
            """Load trained models from train_modelv8.py output."""
            def __init__(self, symbol):
                import joblib
                import os
                self.symbol = symbol
                self.models = []
                self.smc_detectors = {}
                self.feature_order = None
                
                # Model paths - matches train_modelv8.py output
                model_paths = [
                    (f"models/model_rf_{symbol}.pkl", "sklearn"),
                    (f"models/model_xgb_{symbol}.json", "xgboost"),
                    (f"models/model_lgb_{symbol}.txt", "lightgbm"),
                    (f"models/model_svm_{symbol}.pkl", "sklearn"),
                ]
                
                # Load main prediction models
                for path, mtype in model_paths:
                    if not os.path.exists(path):
                        continue
                    try:
                        if mtype == "sklearn":
                            model_data = joblib.load(path)
                            # Handle wrapped models from train_modelv8.py
                            if isinstance(model_data, dict) and "model" in model_data:
                                self.models.append(model_data["model"])
                                if not self.feature_order and "feature_order" in model_data:
                                    self.feature_order = model_data["feature_order"]
                            else:
                                self.models.append(model_data)
                        elif mtype == "xgboost":
                            import xgboost as xgb
                            booster = xgb.Booster(model_file=path)
                            self.models.append(booster)
                        elif mtype == "lightgbm":
                            import lightgbm as lgb
                            booster = lgb.Booster(model_file=path)
                            self.models.append(booster)
                    except Exception as e:
                        pass  # Skip unavailable models
                
                # Load SMC pattern detectors
                smc_types = ["bos", "choch", "fvg", "displacement", "liquidity", "orderblock"]
                for smc_type in smc_types:
                    smc_path = f"models/model_smc_{smc_type}_{symbol}.pkl"
                    if os.path.exists(smc_path):
                        try:
                            smc_data = joblib.load(smc_path)
                            if isinstance(smc_data, dict) and "model" in smc_data:
                                self.smc_detectors[smc_type] = smc_data["model"]
                            else:
                                self.smc_detectors[smc_type] = smc_data
                        except Exception as e:
                            pass
                
                # Fallback: create dummy model if no models loaded
                if not self.models:
                    print(f"[FALLBACK] No models found for {symbol}. Using dummy classifier.")
                    from sklearn.ensemble import RandomForestClassifier
                    import numpy as np
                    # Determine number of features
                    n_features = len(self.feature_order) if self.feature_order else 120
                    X_dummy = np.random.rand(20, n_features)
                    y_dummy = np.random.randint(0, 3, 20)
                    dummy_model = RandomForestClassifier(n_estimators=10, random_state=42)
                    dummy_model.fit(X_dummy, y_dummy)
                    self.models.append(dummy_model)

            def predict(self, X):
                """Ensemble prediction with confidence."""
                preds = []
                for model in self.models:
                    try:
                        if hasattr(model, "predict"):
                            pred = model.predict(X)
                            if hasattr(pred, "__len__") and len(pred) > 0:
                                preds.append(pred[0] if len(pred) == 1 else pred[-1])
                    except Exception:
                        pass
                
                if not preds:
                    return 0, 0.0
                
                from collections import Counter
                vote = Counter(preds).most_common(1)[0][0]
                confidence = preds.count(vote) / len(preds) if len(preds) > 0 else 0.0
                return vote, confidence
            
            def predict_smc_patterns(self, X):
                """Get SMC pattern detections (BOS, CHOCH, FVG, etc)."""
                smc_scores = {}
                for smc_type, detector in self.smc_detectors.items():
                    try:
                        pred = detector.predict(X)
                        smc_scores[smc_type] = 1.0 if pred[0] == 1 else 0.0
                    except Exception:
                        smc_scores[smc_type] = 0.0
                return smc_scores

        # Initialize per symbol
        models = {
            sym: EnsembleMLModel(sym)
            for sym in SYMBOLS
        }

        # To predict for a symbol:
        # pred, conf = models[symbol].predict(X)
        # smc_patterns = models[symbol].predict_smc_patterns(X)
        return models
    elif model_type == "stacking_ensemble":
        # Example: Stacking ensemble (replace with your stacking logic)
        class AdvancedEnsembleModel:
            """
            Combines multiple ML models (sklearn, xgboost, keras, RL agent) for robust signal generation.
            """
            def __init__(self, model_configs: list[dict[str, str]]):
                self.models = []
                for cfg in model_configs:
                    try:
                        if cfg["type"] == "rf" or cfg["type"] == "sklearn":
                            import joblib
                            self.models.append(joblib.load(cfg["path"]))
                        elif cfg["type"] == "xgb" or cfg["type"] == "xgboost":
                            import joblib
                            self.models.append(joblib.load(cfg["path"]))
                        elif cfg["type"] == "lgb" or cfg["type"] == "lightgbm":
                            import joblib
                            self.models.append(joblib.load(cfg["path"]))
                        else:
                            raise ValueError(f"Unknown model type: {cfg['type']}")
                    except Exception as e:
                        print(f"[WARNING] Could not load model {cfg['path']}: {e}. Skipping this model.")

            def predict(self, X):
                preds = []
                for model in self.models:
                    if hasattr(model, "predict"):
                        pred = model.predict(X)
                        if hasattr(pred, "__getitem__"):
                            preds.append(pred[0])
                        else:
                            preds.append(pred)
                    else:
                        preds.append(0)
                # For demonstration, just return the mean
                import numpy as np
                avg_pred = np.mean(preds)
                # Confidence: how close avg_pred is to 1 or 2 (buy/sell)
                confidence = max(abs(avg_pred - 1), abs(avg_pred - 2))
                return int(round(avg_pred)), confidence

        model_configs = [
            {"path": f"model_rf_{symbol}.pkl", "type": "rf"},
            {"path": f"model_xgb_{symbol}.pkl", "type": "xgb"},
            {"path": f"model_lgb_{symbol}.pkl", "type": "lgb"},
        ]
        return AdvancedEnsembleModel(model_configs)
    elif model_type == "regime_switch":
        # Example: Regime-based switching (replace with your logic)
        def regime_model(features):
            regime = features.get("regime", "trend")
            if regime == "trend":
                return None  # return RealMLModel("model_trend.pkl", "sklearn")  # ERROR: RealMLModel not defined
            elif regime == "range":
                return None  # return RealMLModel("model_range.pkl", "sklearn")  # ERROR: RealMLModel not defined
            else:
                return None  # return RealMLModel("model_default.pkl", "sklearn")  # ERROR: RealMLModel not defined
        return regime_model
    elif model_type == "deep_learning":
        # Example: Deep learning model (replace with your Keras/TensorFlow/PyTorch logic)
        # from keras.models import load_model  # ERROR: module not found
        model = load_model("model_dl.h5")
        return model
    else:
        raise ValueError(f"Unknown model_type: {model_type}")

