import joblib
import xgboost as xgb
import lightgbm as lgb
import numpy as np

def load_rf_model(symbol):
    """Load RandomForest model from models/ directory (output from train_modelv8.py)."""
    import os
    import joblib
    
    model_path = os.path.join("models", f"model_rf_{symbol}.pkl")
    if not os.path.exists(model_path):
        raise FileNotFoundError(f"Model not found: {model_path}")
    
    model_data = joblib.load(model_path)
    
    # Handle wrapped model format from train_modelv8.py
    if isinstance(model_data, dict) and "model" in model_data:
        model = model_data["model"]
        feature_order = model_data.get("feature_order", list(range(120)))
        symbol_onehot_order = model_data.get("symbol_onehot_order", [])
    else:
        # Fallback: model is raw
        model = model_data
        feature_order = list(range(120))
        symbol_onehot_order = []
    
    return model, feature_order, symbol_onehot_order

def load_xgb_model(symbol):
    """Load XGBoost model from models/ directory (output from train_modelv8.py)."""
    import os
    import joblib
    
    model_path = os.path.join("models", f"model_xgb_{symbol}.json")
    if not os.path.exists(model_path):
        raise FileNotFoundError(f"XGBoost model not found: {model_path}")
    
    model = xgb.Booster()
    model.load_model(model_path)
    
    # Get feature order from RF model metadata
