def stale_data_check(df, max_age_minutes=2):
    """Return True if data is fresh, False if stale."""
    if df is None or len(df) == 0:
        return False
    last_time = df['time'].iloc[-1]
    import pandas as pd
    # Robustly ensure last_time is timezone-aware UTC
    if isinstance(last_time, pd.Timestamp):
        if last_time.tzinfo is None or last_time.tzinfo.utcoffset(last_time) is None:
            # Use pd.Timestamp with utc=True to avoid errors
            last_time = pd.Timestamp(last_time, tz='UTC')
        else:
            last_time = last_time.tz_convert('UTC')
    else:
        # If it's a datetime.datetime, use replace or astimezone
        from datetime import timezone
        if getattr(last_time, 'tzinfo', None) is None:
            # Use datetime with UTC
            import pandas as pd
            last_time = pd.Timestamp(last_time, tz='UTC')
        else:
            last_time = last_time.astimezone(timezone.utc)

    from datetime import datetime, timezone
    now = datetime.now(timezone.utc)
    age = (now - last_time).total_seconds() / 60.0
    if age > max_age_minutes:
        print(f"[STALE DATA] Last candle is {age:.1f} minutes old. Skipping trading this cycle.")
        return False
    return True

def mt5_reconnect():
    """Try to re-initialize MT5 if connection/data is stale."""
    try:
        if mt5 is not None:
            mt5.shutdown()
            pytime.sleep(2)
            if not mt5.initialize():
                print("[MT5] Re-initialization failed.")
                return False
            print("[MT5] Reconnected successfully.")
            return True
    except Exception as e:
        print(f"[MT5] Reconnect error: {e}")
    return False

  
    
