# --- Dynamic Max Risk Management ---
DEFAULT_MAX_RISK = 0.02  # 2% per trade
MIN_MAX_RISK = 0.005     # 0.5% per trade
RISK_REDUCTION_FACTOR = 0.5  # Reduce by 50% after a losing day

def get_yesterday_pnl():
    # Implement this to read from your trade journal/log
    # Return positive or negative float
    try:
        with open("trade_journal.csv") as f:
            import csv
            from datetime import datetime, timedelta
            reader = csv.DictReader(f)
            yesterday = (datetime.now().date() - timedelta(days=1))
            pnl = 0.0
            for row in reader:
                if "timestamp" in row and "pnl" in row:
                    trade_date = datetime.strptime(row["timestamp"][:10], "%Y-%m-%d").date()
                    if trade_date == yesterday:
                        pnl += float(row["pnl"])
            return pnl
    except Exception:
        return 0.0

def get_dynamic_max_risk():
    pnl = get_yesterday_pnl()
    if pnl < 0:
        return max(DEFAULT_MAX_RISK * RISK_REDUCTION_FACTOR, MIN_MAX_RISK)
    return DEFAULT_MAX_RISK


def extract_ml_signal_and_confidence(prediction, model=None, features=None):
    """
    Robustly extracts ML signal and confidence from model prediction output.
    Supports tuple, dict, str, list, and other formats.
    Returns: ml_signal, confidence, pattern (pattern may be None)
    """
    print(f"[DEBUG] Raw model prediction: {prediction}")
    ml_signal = "hold"
    confidence = 0.0
    pattern = None
    conf = 0.0

    try:
        if isinstance(prediction, tuple):
            if len(prediction) == 2:
                ml_signal, conf = prediction
            elif len(prediction) == 3:
                ml_signal, conf, pattern = prediction
            else:
                ml_signal = prediction[0]
                conf = prediction[1] if len(prediction) > 1 else 0.0
        elif isinstance(prediction, dict):
            ml_signal = prediction.get("label", "hold")
            conf = prediction.get("confidence", 0.0)
            pattern = prediction.get("pattern", None)
        elif isinstance(prediction, str):
            ml_signal = prediction
            conf = 1.0
        elif isinstance(prediction, list):
            for item in prediction:
                if isinstance(item, dict) and "label" in item:
                    ml_signal = item["label"]
                    conf = item.get("confidence", 0.0)
                    pattern = item.get("pattern", None)
                    break
        else:
            ml_signal = str(prediction)
            conf = 0.0

        # Ensure confidence is a float
        if isinstance(conf, (int, float)):
            confidence = float(conf)
        elif isinstance(conf, dict):
            confidence = float(next((v for v in conf.values() if isinstance(v, (int, float))), 0.0))
        else:
            confidence = 0.0

    except Exception as e:
        print(f"[CONFIDENCE ERROR] Could not parse prediction: {prediction} | Error: {e}")
        ml_signal = "hold"
        confidence = 0.0

    print(f"[DEBUG] ML signal: {ml_signal}, confidence: {confidence}, pattern: {pattern}")
    return ml_signal, confidence, pattern




def can_place_trade(symbol, max_trades_per_symbol=None, max_trades_per_hour=None):
    """
    Returns True if the symbol can place another trade (not exceeding max for this period and per hour).
    Now allows any of your 5 base symbols, resolved dynamically.
    """
    max_trades = max_trades_per_symbol if max_trades_per_symbol is not None else get_max_trades_for_symbol(symbol)
    count = symbol_trade_counts.get(symbol, 0)
    now = datetime.now()
    hour = now.replace(minute=0, second=0, microsecond=0)
    hourly_count = symbol_hourly_trade_counts[symbol][hour] if hour in symbol_hourly_trade_counts[symbol] else 0
    max_hourly = max_trades_per_hour if max_trades_per_hour is not None else MAX_TRADES_PER_SYMBOL_PER_HOUR
    if hourly_count >= max_hourly:
        return False
    return count < max_trades


def resolve_dict_key(symbol, dct, suffixes=(".ecn", ".m", ".pro", "")):
    """
    Returns the correct key for a symbol in a dictionary, trying common suffixes.
    Example: resolve_dict_key("EURUSD", buffer_dict)
    """
    if symbol in dct:
        return symbol
    for suffix in suffixes:
        key = symbol + suffix
        if key in dct:
            return key
    # Try removing known suffixes if symbol already has one
    for suffix in suffixes:
        if symbol.endswith(suffix) and symbol[:-len(suffix)] in dct:
            return symbol[:-len(suffix)]
    raise KeyError(f"Symbol key not found for {symbol} in dict (tried suffixes: {suffixes})")


# === SYMBOL RESOLVER ===
def resolve_symbol(base_symbol, verbose=True):
    """
    Dynamically resolve the correct symbol name for trading, matching any suffix/prefix in MT5.
    Tries multiple common suffixes (.m, .ecn, .pro, .std, etc.) until one is found.
    Returns the resolved symbol name or None if not found.
    """
    if not mt5.initialize():
        if verbose:
            print("[MT5] Initialization failed inside resolve_symbol.")
        return None
    
    symbols_result = mt5.symbols_get()
    if symbols_result is None:
        if verbose:
            print("[MT5] symbols_get() returned None - MT5 connection failed.")
        return None
    
    all_mt5_symbols = [s.name for s in symbols_result]
    clean_base = base_symbol.replace('.m', '').replace('.ecn', '').replace('.pro', '').replace('.std', '').replace('.mini', '').replace('.fx', '')
    
    # STRATEGY: Try variations in priority order
    # 1. Exact match (as-is)
    # 2. Common broker suffixes (.m, .ecn, .pro, .std)
    # 3. Case-insensitive match
    # 4. Partial match (ignore all suffixes)
    
    candidate_symbols = [base_symbol]  # Start with exact
    
    # Add common suffix variants
    for suffix in ['.m', '.ecn', '.pro', '.std', '.mini', '.x']:
        candidate_symbols.append(clean_base + suffix)
    
    # Try each candidate
    for candidate in candidate_symbols:
        if candidate in all_mt5_symbols:
            info = mt5.symbol_info(candidate)
            if info and not info.visible:
                mt5.symbol_select(candidate, True)
            if verbose:
                print(f"[SYMBOL RESOLVED] {base_symbol} -> {candidate}")
            return candidate
    
    # Try case-insensitive match
    for s in all_mt5_symbols:
        if s.lower() == base_symbol.lower():
            info = mt5.symbol_info(s)
            if info and not info.visible:
                mt5.symbol_select(s, True)
            if verbose:
                print(f"[SYMBOL RESOLVED] {base_symbol} -> {s} (case-insensitive)")
            return s
    
    # Try partial match (strip all suffixes and compare base)
    for s in all_mt5_symbols:
        s_clean = s.replace('.m', '').replace('.ecn', '').replace('.pro', '').replace('.std', '').replace('.mini', '').replace('.fx', '')
        if s_clean.upper() == clean_base.upper():
            info = mt5.symbol_info(s)
            if info and not info.visible:
                mt5.symbol_select(s, True)
            if verbose:
                print(f"[SYMBOL RESOLVED] {base_symbol} -> {s} (suffix match)")
            return s
    
    if verbose:
        print(f"[ERROR] Could not resolve symbol: {base_symbol}")
        print(f"[HINT] Available patterns: {[s for s in all_mt5_symbols if clean_base.upper() in s.upper()][:5]}")
        print("[HINT] Ensure the symbol is visible in Market Watch and history is loaded.")
    return None

def get_full_history(symbol, years=2):
    """
    Load historical price data for your 5 symbols from MetaTrader5 or CSV files.
    Return a pandas DataFrame with OHLCV data indexed by datetime.
    """
    filename = f'data/{symbol}_{years}years.csv'
    df = pd.read_csv(filename, parse_dates=['time'], index_col='time')
    # Ensure time is timezone-aware UTC
    df['time'] = pd.to_datetime(df['time'], utc=True)
    df.index = pd.to_datetime(df.index, utc=True)

    # Keep last 6 months for training relevance
    if len(df) > (24*4*30*6):  # M15 candles in ~6 months
        df = df.tail(24*4*30*6)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
    return df

