def record_trade(symbol, duplicates=1):
    """
    Call this after placing a trade to increment the trade count for the symbol and for the current hour.
    If placing duplicate trades, increments by the number of duplicates.
    """
    symbol_trade_counts[symbol] = symbol_trade_counts.get(symbol, 0) + duplicates
    now = datetime.now()
    hour = now.replace(minute=0, second=0, microsecond=0)
    symbol_hourly_trade_counts[symbol][hour] += duplicates
