# 2. Profit-based metrics
def profit_metrics(trades):
    """
    Accepts a list of trade dicts (with 'result' key) and returns performance metrics.
    """
    import numpy as np
    if not trades:
        return {}
    if hasattr(trades, "to_dict"):
        trades = trades.to_dict("records")
    results = np.array([t['result'] for t in trades])
    equity_curve = np.cumsum(results)
    drawdown = np.maximum.accumulate(equity_curve) - equity_curve
    max_drawdown = drawdown.max() if len(drawdown) else 0
    sharpe = results.mean() / (results.std() + 1e-8) * np.sqrt(252) if results.std() > 0 else 0
    wins = results[results > 0]
    losses = results[results <= 0]
    profit_factor = abs(wins.sum()) / abs(losses.sum()) if losses.sum() != 0 else float('inf')
    return {
        "winrate": 100 * len(wins) / len(results) if len(results) else 0,
        "avg_win": wins.mean() if len(wins) else 0,
        "avg_loss": losses.mean() if len(losses) else 0,
        "profit_factor": profit_factor,
        "net_profit": results.sum(),
        "trades": len(results),
        "max_drawdown": max_drawdown,
        "sharpe": sharpe,
    }
# 3. Deep learning models (Keras MLP, LSTM, CNN)
def train_keras_deep_model(X, y, save_path="keras_model.h5"):
    """
    Trains a Keras MLP model for ML trading signals.
    """
    from tensorflow import keras
    try:
        from tensorflow.keras import layers
    except Exception:
        class _DummyLayers:
            def Dense(self, *a, **k):
                return None
        layers = _DummyLayers()
    num_classes = 3
    y_cat = keras.utils.to_categorical(y, num_classes)
    model = keras.Sequential([
        layers.Input(shape=(X.shape[1],)),
        layers.Dense(128, activation='relu'),
        layers.BatchNormalization(),
        layers.Dense(128, activation='relu'),
        layers.BatchNormalization(),
        layers.Dense(64, activation='relu'),
        layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    # Suppress all output from model.fit
    import os
    import sys
    class NullWriter:
        def write(self, s): pass
        def flush(self): pass
    old_stdout = sys.stdout
    old_stderr = sys.stderr
    sys.stdout = NullWriter()
    sys.stderr = NullWriter()
    try:
        model.fit(X, y_cat, epochs=30, batch_size=32, verbose=0)
    finally:
        sys.stdout = old_stdout
        sys.stderr = old_stderr
    model.save(save_path)
    print(f"[DEEP LEARNING] Keras MLP model trained and saved to {save_path}")
    return model

def train_keras_lstm_model(X, y, save_path="keras_lstm_model.h5", lookback=20):
    """
    Trains a robust LSTM model for ML trading signals.
    X: 2D array (samples, features) or 3D (samples, timesteps, features)
    y: 1D array (labels)
    """
    from tensorflow import keras
    try:
        from tensorflow.keras import layers
    except Exception:
        class _DummyLayers:
            def Dense(self, *a, **k):
                return None
        layers = _DummyLayers()
    import numpy as np
    num_classes = 3
    y_cat = keras.utils.to_categorical(y, num_classes)
    # Reshape X to (samples, timesteps, features)
    if X.ndim == 2:
        n_samples = X.shape[0]
        n_features = X.shape[1]
        if n_samples < lookback:
            raise ValueError("Not enough samples for LSTM lookback window.")
        X_seq = np.array([X[i-lookback:i] for i in range(lookback, n_samples)])
        y_seq = y[lookback:]
    else:
        X_seq = X
        y_seq = y
    model = keras.Sequential([
        layers.Input(shape=(X_seq.shape[1], X_seq.shape[2])),
        layers.LSTM(64, return_sequences=True),
        layers.LSTM(32),
        layers.BatchNormalization(),
        layers.Dense(32, activation='relu'),
        layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    # Suppress all output from model.fit
    import sys
    class NullWriter:
        def write(self, s): pass
        def flush(self): pass
    old_stdout = sys.stdout
    old_stderr = sys.stderr
    sys.stdout = NullWriter()
    sys.stderr = NullWriter()
    try:
        model.fit(X_seq, keras.utils.to_categorical(y_seq, num_classes), epochs=30, batch_size=32, verbose=0)
    finally:
        sys.stdout = old_stdout
        sys.stderr = old_stderr
    model.save(save_path)
    print(f"[DEEP LEARNING] Keras LSTM model trained and saved to {save_path}")
    return model

def train_keras_cnn_model(X, y, save_path="keras_cnn_model.h5", lookback=20):
    """
    Trains a robust 1D CNN model for ML trading signals.
    X: 2D array (samples, features) or 3D (samples, timesteps, features)
    y: 1D array (labels)
    """
    from tensorflow import keras
    try:
        from tensorflow.keras import layers
    except Exception:
        class _DummyLayers:
            def Dense(self, *a, **k):
                return None
        layers = _DummyLayers()
    import numpy as np
    num_classes = 3
    y_cat = keras.utils.to_categorical(y, num_classes)
    # Reshape X to (samples, timesteps, features)
    if X.ndim == 2:
        n_samples = X.shape[0]
        n_features = X.shape[1]
        if n_samples < lookback:
            raise ValueError("Not enough samples for CNN lookback window.")
        X_seq = np.array([X[i-lookback:i] for i in range(lookback, n_samples)])
        y_seq = y[lookback:]
    else:
        X_seq = X
        y_seq = y
    model = keras.Sequential([
        layers.Input(shape=(X_seq.shape[1], X_seq.shape[2])),
        layers.Conv1D(64, kernel_size=3, activation='relu'),
        layers.Conv1D(32, kernel_size=3, activation='relu'),
        layers.BatchNormalization(),
        layers.GlobalMaxPooling1D(),
        layers.Dense(32, activation='relu'),
        layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    # Suppress all output from model.fit
    import sys
    class NullWriter:
        def write(self, s): pass
        def flush(self): pass
    old_stdout = sys.stdout
    old_stderr = sys.stderr
    sys.stdout = NullWriter()
    sys.stderr = NullWriter()
    try:
        model.fit(X_seq, keras.utils.to_categorical(y_seq, num_classes), epochs=30, batch_size=32, verbose=0)
    finally:
        sys.stdout = old_stdout
        sys.stderr = old_stderr
    model.save(save_path)
    print(f"[DEEP LEARNING] Keras CNN model trained and saved to {save_path}")
    return model

class KerasLSTMModel:
    def __init__(self, keras_model_path, label_map=None, lookback=20):
        from tensorflow import keras
        self.model = keras.models.load_model(keras_model_path)
        self.label_map = label_map or {0: "hold", 1: "buy", 2: "sell"}
        self.lookback = lookback

    def predict(self, features_seq):
        # features_seq: list of dicts (length = lookback)
        import numpy as np
        X = np.array([[f.get(k, 0) for k in KERAS_FEATURE_ORDER_20] for f in features_seq])
        X = X.reshape((1, X.shape[0], X.shape[1]))
        preds = self.model.predict(X, verbose=0)
        pred = np.argmax(preds, axis=1)[0]
        confidence = preds[0][pred]
        return self.label_map.get(pred, "hold"), float(confidence)

class KerasCNNModel:
    def __init__(self, keras_model_path, label_map=None, lookback=20):
        from tensorflow import keras
        self.model = keras.models.load_model(keras_model_path)
        self.label_map = label_map or {0: "hold", 1: "buy", 2: "sell"}
        self.lookback = lookback

    def predict(self, features_seq):
        # features_seq: list of dicts (length = lookback)
        import numpy as np
        X = np.array([[f.get(k, 0) for k in KERAS_FEATURE_ORDER_20] for f in features_seq])
        X = X.reshape((1, X.shape[0], X.shape[1]))
        preds = self.model.predict(X, verbose=0)
        pred = np.argmax(preds, axis=1)[0]
        confidence = preds[0][pred]
        return self.label_map.get(pred, "hold"), float(confidence)

def is_session_open(features=None):
    """
    Returns True if either London or NY session is open.
    If features dict is provided, uses its session flags.
    """
    if features is not None:
        return features.get("is_london", 0) or features.get("is_ny", 0)
    # Fallback: check current hour (UTC)
    now = datetime.now(timezone.utc).hour
    # London: 7-16 UTC, NY: 12-21 UTC
    return (7 <= now <= 16) or (12 <= now <= 21)

class VotingMLModel:
    """
    Simple majority voting ensemble for ML signals.
    """
    def __init__(self, models):
        self.models = models  # List of model objects with .predict()

    def predict(self, features):
        votes = []
        confidences = []
        for model in self.models:
            signal, conf = model.predict(features)
            votes.append(signal)
            confidences.append(conf)
        # Majority vote
        from collections import Counter
        vote_counts = Counter(votes)
        top_signal = vote_counts.most_common(1)[0][0]
        avg_conf = sum(confidences) / len(confidences)
        return top_signal, avg_conf

class KerasMLModel:
    def __init__(self, keras_model_path, label_map=None):
        from tensorflow import keras
        self.model = keras.models.load_model(keras_model_path)
        self.label_map = label_map or {0: "hold", 1: "buy", 2: "sell"}

    def predict(self, features):
        # Ensure features strictly match model input order
        X = np.array([[features.get(k, 0) for k in KERAS_FEATURE_ORDER_20]])
        expected_shape = self.model.input_shape[-1]
        if X.shape[1] != expected_shape:
            raise ValueError(f"Feature vector length {X.shape[1]} != model input {expected_shape}")
        preds = self.model.predict(X, verbose=0)
        pred = np.argmax(preds, axis=1)[0]
        confidence = preds[0][pred]
        return self.label_map.get(pred, "hold"), float(confidence)

# 4. Stacking meta-model
def train_stacking_meta_model(X_base_preds, y, save_path="meta_model.pkl"):
    from sklearn.linear_model import LogisticRegression
    import joblib
    meta_model = LogisticRegression()
    meta_model.fit(X_base_preds, y)
    joblib.dump(meta_model, save_path)
    print(f"[STACKING] Meta-model trained and saved to {save_path}")
    return meta_model
# === ModelAdapter ===
class ModelAdapter:
    def __init__(self, model, feature_names=None):
        self.model = model
        # Use model.feature_names_in_ if available, else use provided, else default
        if feature_names is not None:
            self.feature_names = feature_names
        elif hasattr(model, "feature_names_in_"):
            self.feature_names = list(model.feature_names_in_)
        else:
            self.feature_names = [
                "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
                "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
                "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength",
                "distance_from_tp", "minutes_left_session", "atr_squeeze", "atr_burst",
                "macd", "macd_signal", "macd_hist", "obv", "divergence"
            ][:getattr(model, "n_features_in_", 20)]

    def predict(self, features_dict):
        import numpy as np
        # Flatten nested dicts if present
        features = {}
        for k, v in features_dict.items():
            if isinstance(v, dict):
                for subk, subv in v.items():
                    features[f"{k}_{subk}"] = subv
            else:
                features[k] = v
        # Build 2D array in fixed order
        X = np.array([[features.get(k, 0) for k in self.feature_names]])
        # Custom models (tuple output)
        if hasattr(self.model, "is_custom") and self.model.is_custom:
            signal, confidence = self.model.predict(features)
        else:
            pred = self.model.predict(X)
            if hasattr(self.model, "predict_proba"):
                proba = safe_predict_proba(self.model, X, model_type="sklearn") if 'safe_predict_proba' in globals() else self.model.predict_proba(X)[0]
                pred_idx = pred[0] if hasattr(pred, "__getitem__") else pred
                if isinstance(pred_idx, str):
                    label_map = getattr(self.model, "label_map", {"hold": 0, "buy": 1, "sell": 2})
                    pred_idx = label_map.get(pred_idx, 0)
                confidence = proba[int(pred_idx)] if int(pred_idx) < len(proba) else max(proba) if proba else 0.0
                signal = getattr(self.model, "label_map", {0: "hold", 1: "buy", 2: "sell"}).get(pred[0], pred[0])
            else:
                signal, confidence = pred[0], 1.0
        # Normalize output
        signal = str(signal).lower()
        if signal not in ["buy", "sell", "hold"]:
            signal = "hold"
        try:
            confidence = float(confidence)
        except Exception:
            confidence = 0.0
        if not (0 <= confidence <= 1):
            confidence = 0.0
        return signal, confidence
class StackingMLModel:
    """
    Stacking ensemble: uses predictions from base models as features for a meta-model.
    """
    def __init__(self, base_models, meta_model):
        self.base_models = base_models  # List of model objects with .predict()
        self.meta_model = meta_model    # Trained sklearn model

    def predict(self, features):
        base_preds = []
        for model in self.base_models:
            signal, conf = model.predict(features)
            # Encode signal as int for meta-model: hold=0, buy=1, sell=2
            base_preds.append({"hold": 0, "buy": 1, "sell": 2}[signal])
        X_meta = np.array([base_preds])
        pred = self.meta_model.predict(X_meta)[0]
        proba = safe_predict_proba(self.meta_model, X_meta, model_type="sklearn") if 'safe_predict_proba' in globals() else (self.meta_model.predict_proba(X_meta)[0] if hasattr(self.meta_model, 'predict_proba') else np.array([0.33, 0.33, 0.33]))
        label_map = {0: "hold", 1: "buy", 2: "sell"}
        confidence = float(proba[int(pred)]) if int(pred) < len(proba) else float(np.max(proba)) if len(proba) > 0 else 0.0
        return label_map[int(pred)], confidence

# 5. Hyperparameter tuning (grid search example)
def grid_search_model(X, y):
    from sklearn.ensemble import RandomForestClassifier
    from sklearn.model_selection import GridSearchCV
    param_grid = {
        "n_estimators": [100, 200, 300],
        "max_depth": [6, 8, 10],
        "min_samples_split": [2, 5, 10]
    }
    grid = GridSearchCV(RandomForestClassifier(), param_grid, cv=3, scoring="accuracy", n_jobs=-1)
    grid.fit(X, y)
    print(f"[GRID SEARCH] Best params: {grid.best_params_} | Best score: {grid.best_score_:.4f}")
    return grid.best_estimator_

# 6. Example: Full pipeline usage
# --- Trade Management & ML/Risk Enhancements ---

def dynamic_position_size(account_equity, risk_per_trade, sl_pips, pip_value, setup_quality=1.0, volatility=1.0):
    """
    Calculate position size based on account equity, risk %, stop loss, setup quality, and volatility.
    """
    # Risk per trade in currency
    risk_amount = account_equity * risk_per_trade * setup_quality / volatility
    lot_size = risk_amount / (sl_pips * pip_value)
    return max(round(lot_size, 2), 0.01)

def adaptive_stop_loss(entry, sl, structure_confirmed, direction):
    """
    Move SL to breakeven only if structure is confirmed (e.g., after MSS/CHOCH or key level retest).
    """
    if structure_confirmed:
        return entry  # Move SL to BE
    return sl

def partial_take_profit(trade_id, key_levels, current_price, direction):
    """
    Scale out at key levels to lock in profit.
    """
    # Example: If price hits a key level, close part of the position
    for level in key_levels:
        if (direction == "buy" and current_price >= level) or (direction == "sell" and current_price <= level):
            # close_partial(trade_id, percent=0.5)  # ERROR: function not defined
            print(f"[TP] Partial take profit at key level {level}")
            break

def reentry_logic(last_trade, current_conditions_valid, was_liquidity_wick):
    """
    If stopped out by a liquidity wick but conditions remain valid, allow re-entry.
    """
    if last_trade['exit_reason'] == "stop_loss" and was_liquidity_wick and current_conditions_valid:
        print("[RE-ENTRY] Re-entering after liquidity wick stopout.")
        return True
    return False

