# ADVANCED FEATURE #1: CORRELATION-BASED RISK MANAGEMENT
# ═══════════════════════════════════════════════════════════════════════════════

def calculate_symbol_correlation_matrix(symbols, lookback=200):
    """
    Calculate correlation matrix between symbols to detect correlated pairs.
    Returns dict: {('SYM1', 'SYM2'): correlation_coefficient}
    """
    correlations = {}
    try:
        price_data = {}
        for symbol in symbols:
            df = get_price_data(symbol, bars=lookback)
            if df is not None and len(df) > 0:
                price_data[symbol] = df['close'].pct_change().dropna()
        
        if len(price_data) >= 2:
            for i, sym1 in enumerate(symbols):
                for sym2 in symbols[i+1:]:
                    if sym1 in price_data and sym2 in price_data:
                        corr = price_data[sym1].corr(price_data[sym2])
                        if not np.isnan(corr):
                            correlations[(sym1, sym2)] = corr
    except Exception as e:
        print(f"[CORRELATION] Error calculating correlations: {e}")
    
    return correlations

def check_correlation_risk(symbol, direction, open_positions, correlation_matrix, threshold=0.7):
    """
    Check if opening a trade in 'direction' would create dangerous correlation exposure.
    Returns (is_safe, reason)
    """
    try:
        if not open_positions:
            return True, "No open positions to correlate against"
        
        symbol_clean = symbol.replace('.m', '')
        
        for pos in open_positions:
            pos_symbol = pos.symbol.replace('.m', '')
            
            # Check correlation
            corr_key = tuple(sorted([symbol_clean, pos_symbol]))
            corr = correlation_matrix.get(corr_key, 0)
            
            # If correlated and same direction, flag as risky
            if abs(corr) > threshold:
                pos_is_buy = pos.type == mt5.ORDER_TYPE_BUY
                trade_is_buy = direction == "buy"
                
                if pos_is_buy == trade_is_buy:
                    return False, f"High correlation ({corr:.2f}) with {pos_symbol} in same direction"
        
        return True, "Correlation check passed"
    except Exception as e:
        print(f"[CORRELATION] Error in correlation check: {e}")
        return True, f"Correlation check failed safely: {e}"

