# ADVANCED FEATURE #2: DRAWDOWN MONITORING & CIRCUIT BREAKER
# ═══════════════════════════════════════════════════════════════════════════════

class DrawdownTracker:
    def __init__(self, daily_max_drawdown=0.05, weekly_max_drawdown=0.10):
        self.daily_max_drawdown = daily_max_drawdown  # 5% daily
        self.weekly_max_drawdown = weekly_max_drawdown  # 10% weekly
        self.session_start_balance = None
        self.session_start_time = None
        self.weekly_start_balance = None
        self.weekly_start_time = None
        self.peak_daily_equity = None
        self.peak_weekly_equity = None
        self.daily_halt = False
        self.weekly_halt = False
    
    def update(self):
        """Check and update drawdown status"""
        try:
            acct = mt5.account_info()
            if not acct:
                return
            
            current_equity = acct.equity
            current_balance = acct.balance
            
            # Initialize session if needed
            now = datetime.now()
            if self.session_start_time is None:
                self.session_start_balance = current_balance
                self.session_start_time = now
                self.peak_daily_equity = current_equity
            
            if self.weekly_start_time is None:
                self.weekly_start_balance = current_balance
                self.weekly_start_time = now
                self.peak_weekly_equity = current_equity
            
            # Reset daily at midnight
            if (now - self.session_start_time).days >= 1:
                self.session_start_balance = current_balance
                self.session_start_time = now
                self.peak_daily_equity = current_equity
                self.daily_halt = False
            
            # Reset weekly on Sunday
            if (now - self.weekly_start_time).days >= 7:
                self.weekly_start_balance = current_balance
                self.weekly_start_time = now
                self.peak_weekly_equity = current_equity
                self.weekly_halt = False
            
            # Update peaks
            if current_equity > self.peak_daily_equity:
                self.peak_daily_equity = current_equity
            if current_equity > self.peak_weekly_equity:
                self.peak_weekly_equity = current_equity
            
            # Calculate drawdowns
            daily_dd = (self.peak_daily_equity - current_equity) / self.peak_daily_equity if self.peak_daily_equity > 0 else 0
            weekly_dd = (self.peak_weekly_equity - current_equity) / self.peak_weekly_equity if self.peak_weekly_equity > 0 else 0
            
            # Check thresholds and trigger halts
            if daily_dd > self.daily_max_drawdown:
                self.daily_halt = True
                print(f"[CIRCUIT BREAKER] Daily drawdown {daily_dd:.2%} exceeds limit {self.daily_max_drawdown:.2%}. Trading HALTED for today.")
            
            if weekly_dd > self.weekly_max_drawdown:
                self.weekly_halt = True
                print(f"[CIRCUIT BREAKER] Weekly drawdown {weekly_dd:.2%} exceeds limit {self.weekly_max_drawdown:.2%}. Trading HALTED for week.")
        
        except Exception as e:
            print(f"[DRAWDOWN TRACKER] Error: {e}")
    
    def is_trading_allowed(self):
        """Check if trading is allowed based on drawdown limits"""
        return not (self.daily_halt or self.weekly_halt)
    
    def get_position_size_adjustment(self):
        """Return multiplier for position sizing during drawdown (e.g., 0.5x if 50% through daily limit)"""
        try:
            acct = mt5.account_info()
            if not acct or not self.peak_daily_equity:
                return 1.0
            
            current_equity = acct.equity
            daily_dd = (self.peak_daily_equity - current_equity) / self.peak_daily_equity
            
            # Reduce position size proportionally as we approach drawdown limit
            remaining_dd_capacity = max(0, self.daily_max_drawdown - daily_dd)
            adjustment = remaining_dd_capacity / self.daily_max_drawdown if self.daily_max_drawdown > 0 else 1.0
            
            return max(0.1, min(1.0, adjustment))
        except Exception:
            return 1.0

drawdown_tracker = DrawdownTracker()

