# ADVANCED FEATURE #3: WIN RATE & R:R BASED POSITION SIZING
# ═══════════════════════════════════════════════════════════════════════════════

class TradeStatistics:
    def __init__(self, lookback_trades=50):
        self.lookback_trades = lookback_trades
        self.trade_history = []  # List of {'direction': 'buy'/'sell', 'profit': float, 'rr_ratio': float}
    
    def add_closed_trade(self, direction, profit_loss, rr_ratio):
        """Record a closed trade"""
        self.trade_history.append({
            'direction': direction,
            'profit': profit_loss,
            'rr_ratio': rr_ratio,
            'timestamp': datetime.now()
        })
        # Keep only recent trades
        if len(self.trade_history) > self.lookback_trades:
            self.trade_history = self.trade_history[-self.lookback_trades:]
    
    def get_win_rate(self, direction=None):
        """Calculate win rate (default: all trades, or specific direction)"""
        if not self.trade_history:
            return 0.5
        
        trades = self.trade_history
        if direction:
            trades = [t for t in trades if t['direction'] == direction]
        
        if not trades:
            return 0.5
        
        wins = len([t for t in trades if t['profit'] > 0])
        return wins / len(trades)
    
    def get_avg_rr_ratio(self):
        """Calculate average risk-reward ratio from closed trades"""
        if not self.trade_history:
            return 1.5
        
        rrs = [t['rr_ratio'] for t in self.trade_history if t['rr_ratio'] > 0]
        return sum(rrs) / len(rrs) if rrs else 1.5
    
    def get_position_size_multiplier(self, base_confidence=0.5):
        """
        Calculate lot size multiplier based on:
        - Win rate (high win rate = bigger lots)
        - Recent RR ratio (good RR = bigger lots)
        - Base confidence from ML
        """
        try:
            win_rate = self.get_win_rate()
            avg_rr = self.get_avg_rr_ratio()
            
            # Multiplier formula: (win_rate * avg_rr * base_confidence)
            # This naturally scales down during losing streaks
            multiplier = win_rate * min(avg_rr, 3.0) * (base_confidence / 0.5)  # Normalize base
            
            # Bounds: never go below 0.5x or above 2.5x
            return max(0.5, min(2.5, multiplier))
        except Exception:
            return 1.0

trade_stats = TradeStatistics()

