def update_trade_statistics_from_history():
    """
    Scan MT5 closed trades and update statistics.
    Call this periodically in main loop to keep trade_stats updated.
    """
    try:
        # Use history_deals_get with date range (last 30 days) instead of deals_get
        from datetime import datetime, timezone, timedelta
        end_time = datetime.now(timezone.utc)
        start_time = end_time - timedelta(days=30)
        deals = mt5.history_deals_get(start_time, end_time) if mt5 else None
        if not deals:
            return
        
        # Process recent deals (last 100)
        for deal in deals[-100:]:
            # Only process closed deals
            if deal.profit != 0:
                direction = "buy" if deal.type == mt5.DEAL_TYPE_BUY else "sell"
                
                # Estimate RR ratio (would need entry/exit prices)
                rr_ratio = 1.5  # Default fallback
                
                # Record in trade statistics
                if not any(t['timestamp'] == deal.time for t in trade_stats.trade_history):
                    trade_stats.add_closed_trade(direction, deal.profit, rr_ratio)
    except Exception as e:
        print(f"[TRADE STATS] Error updating from history: {e}")

