# ADVANCED FEATURE #4: VOLATILITY EXPANSION DETECTION
# ═══════════════════════════════════════════════════════════════════════════════

def detect_volatility_expansion(df, window=20, std_threshold=2.0):
    """
    Detect when current volatility expands beyond historical levels.
    Returns (is_expansion, volatility_z_score, description)
    """
    try:
        if df is None or len(df) < window + 5:
            return False, 0, "Insufficient data"
        
        # Calculate rolling volatility (20-period)
        returns = df['close'].pct_change().dropna()
        rolling_std = returns.rolling(window).std()
        
        current_volatility = rolling_std.iloc[-1]
        historical_mean = rolling_std.iloc[:-1].mean()
        historical_std = rolling_std.iloc[:-1].std()
        
        # Z-score of current volatility
        if historical_std > 0:
            z_score = (current_volatility - historical_mean) / historical_std
        else:
            z_score = 0
        
        is_expansion = z_score > std_threshold
        
        description = f"Vol Z-Score: {z_score:.2f} ({'EXPANSION' if is_expansion else 'Normal'})"
        
        return is_expansion, z_score, description
    except Exception as e:
        print(f"[VOLATILITY EXPANSION] Error: {e}")
        return False, 0, f"Error: {e}"

