# ADVANCED FEATURE #5: ORDER FLOW IMBALANCE (VOLUME PROFILE)
# ═══════════════════════════════════════════════════════════════════════════════

def detect_order_flow_imbalance(df, lookback=20):
    """
    Detect order flow imbalance using volume-weighted price levels.
    Returns (buy_pressure, sell_pressure, imbalance_ratio)
    """
    try:
        if df is None or len(df) < lookback:
            return 0.5, 0.5, 1.0
        
        recent = df.iloc[-lookback:]
        
        # Calculate volume-weighted pressure
        buy_volume = recent[recent['close'] > recent['open']]['tick_volume'].sum()
        sell_volume = recent[recent['close'] < recent['open']]['tick_volume'].sum()
        neutral_volume = recent[recent['close'] == recent['open']]['tick_volume'].sum()
        
        total_volume = buy_volume + sell_volume + neutral_volume
        
        if total_volume == 0:
            return 0.5, 0.5, 1.0
        
        buy_pressure = buy_volume / total_volume
        sell_pressure = sell_volume / total_volume
        imbalance_ratio = buy_volume / (sell_volume + 1)  # +1 to avoid division by zero
        
        return buy_pressure, sell_pressure, imbalance_ratio
    except Exception as e:
        print(f"[ORDER FLOW] Error: {e}")
        return 0.5, 0.5, 1.0

