class RegimeMLModel:
    """
    Predicts market regime (trending/ranging) and switches strategy.
    """
    def __init__(self, regime_model, trend_strategy, range_strategy):
        self.regime_model = regime_model  # e.g., trained classifier
        self.trend_strategy = trend_strategy  # ML model for trending
        self.range_strategy = range_strategy  # ML model for ranging

    def predict(self, features):
        regime = self.regime_model.predict([features])[0]  # 0=ranging, 1=trending
        if regime == 1:
            return self.trend_strategy.predict(features)
        else:
            return self.range_strategy.predict(features)
class EnsembleMLModel:
    """
    Advanced ensemble model: majority vote and confidence averaging of multiple models.
    Supports sklearn, xgboost, keras, etc.
    """
    def __init__(self, model_configs):
        # model_configs: list of dicts with keys: path, type
        self.models = []
        try:
            self.models = [RealMLModel(cfg["path"], cfg["type"]) for cfg in model_configs]
        except NameError:
            pass  # Fallback if RealMLModel not defined

    def predict(self, features):
        votes = []
        confidences = []
        for model in self.models:
            # Flatten nested dicts if present
            if isinstance(features, dict) and any(isinstance(v, dict) for v in features.values()):
                flat_features = {}
                for k, v in features.items():
                    if isinstance(v, dict):
                        for subk, subv in v.items():
                            flat_features[f"{k}_{subk}"] = subv
                    else:
                        flat_features[k] = v
                features = flat_features
            # Defensive: Convert features dict to a 2D array for sklearn
            if hasattr(model, "predict") and callable(model.predict):
                import numpy as np
                if hasattr(model, "feature_names_in_"):
                    feature_names = list(model.feature_names_in_)
                else:
                    feature_names = [
                        "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
                        "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
                        "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength",
                        "distance_from_tp", "minutes_left_session", "atr_squeeze", "atr_burst",
                        "macd", "macd_signal", "macd_hist", "obv", "divergence"
                    ][:model.n_features_in_ if hasattr(model, "n_features_in_") else 20]
                X = np.array([[features.get(k, 0) for k in feature_names]])
                # If model is a custom model (like MockMLModel), pass features dict, not X
                if hasattr(model, "is_custom") and model.is_custom:
                    signal, confidence = model.predict(features)
                else:
                    pred = model.predict(X)
                    if hasattr(model, "predict_proba"):
                        proba = model.predict_proba(X)[0]
                        pred_idx = pred[0] if hasattr(pred, "__getitem__") else pred
                        if isinstance(pred_idx, str):
                            label_map = getattr(model, "label_map", {"hold": 0, "buy": 1, "sell": 2})
                            pred_idx = label_map.get(pred_idx, 0)
                        confidence = proba[int(pred_idx)] if int(pred_idx) < len(proba) else max(proba)
                        signal = getattr(model, "label_map", {0: "hold", 1: "buy", 2: "sell"}).get(pred[0], pred[0])
                    else:
                        signal, confidence = pred[0], 1.0
            else:
                signal, confidence = model.predict(features)
            votes.append(signal)
            confidences.append(confidence)
        # Majority vote
        if not votes:
            return "hold", 0.0
        signal = max(set(votes), key=votes.count)
        avg_conf = sum(confidences) / len(confidences)
        return signal, avg_conf

# === Indicators ===
def calculate_keltner_channel(df, period=20, atr_mult=2):
    """
    Returns (kc_upper, kc_lower, kc_width) for the last bar.
    """
    import numpy as np
    ema = df['close'].ewm(span=period, adjust=False).mean()
    atr = df['high'].rolling(period).max() - df['low'].rolling(period).min()
    kc_upper = ema + atr_mult * atr
    kc_lower = ema - atr_mult * atr
    kc_width = (kc_upper - kc_lower).iloc[-1] / ema.iloc[-1]
    return kc_upper.iloc[-1], kc_lower.iloc[-1], kc_width

def detect_price_action_pattern(df):
    """
    Returns 'bullish', 'bearish', or 'none' for last bar using gold-tuned price action logic.
    """
    # Gold moves in points (0.01 USD), so thresholds should be in USD
    if len(df) < 3:
        return "none"
    last = df.iloc[-1]
    prev = df.iloc[-2]
    prev2 = df.iloc[-3]

    # Parameters tuned for XAUUSD
    min_body = 0.10   # Minimum body size in USD (1.0 = $1, 0.1 = $0.10)
    min_wick = 0.15   # Minimum wick size in USD
    engulf_body_ratio = 0.9  # How much bigger the engulfing candle should be

    # Candle values
    body = abs(last['close'] - last['open'])
    range_ = last['high'] - last['low']
    upper_wick = last['high'] - max(last['close'], last['open'])
    lower_wick = min(last['close'], last['open']) - last['low']

    # Bullish Engulfing
    if (
        prev['close'] < prev['open'] and  # Previous candle bearish
        last['close'] > last['open'] and  # Current candle bullish
        last['close'] > prev['open'] and
        last['open'] < prev['close'] and
        body > min_body and
        body > abs(prev['close'] - prev['open']) * engulf_body_ratio
    ):
        return "bullish"

    # Bearish Engulfing
    if (
        prev['close'] > prev['open'] and  # Previous candle bullish
        last['close'] < last['open'] and  # Current candle bearish
        last['close'] < prev['open'] and
        last['open'] > prev['close'] and
        body > min_body and
        body > abs(prev['close'] - prev['open']) * engulf_body_ratio
    ):
        return "bearish"

    # Hammer (bullish reversal)
    if (
        body > min_body and
        lower_wick > body * 1.5 and
        upper_wick < body * 0.5 and
        range_ > min_body + min_wick
    ):
        return "bullish"

    # Shooting Star (bearish reversal)
    if (
        body > min_body and
        upper_wick > body * 1.5 and
        lower_wick < body * 0.5 and
        range_ > min_body + min_wick
    ):
        return "bearish"

    # Morning Star (bullish 3-bar pattern)
    if (
        prev2['close'] < prev2['open'] and
        abs(prev2['close'] - prev2['open']) > min_body and
        abs(prev['close'] - prev['open']) < min_body and
        last['close'] > last['open'] and
        last['close'] > prev2['open']
    ):
        return "bullish"

    # Evening Star (bearish 3-bar pattern)
    if (
        prev2['close'] > prev2['open'] and
        abs(prev2['close'] - prev2['open']) > min_body and
        abs(prev['close'] - prev['open']) < min_body and
        last['close'] < last['open'] and
        last['close'] < prev2['open']
    ):
        return "bearish"

    return "none"

def detect_regime(
    df,
    lookback=100,
    vol_threshold=0.002,
    slope_threshold=0.0002,
    adx_threshold=25,
    bb_width_threshold=0.01,
    kc_width_threshold=0.015
):
    """
    Detects market regime: 'trend' or 'range' using volatility, MA slope, ADX, Bollinger Band width, Keltner Channel width, and price action pattern.
    Returns: "trend", "range", or "unknown"
    """
    if len(df) < lookback:
        return "unknown"
    closes = df['close'].tail(lookback)
    returns = closes.pct_change().dropna()
    is_trend_vol = returns.std() > vol_threshold
    ma = closes.rolling(lookback//2).mean()
    slope = (ma.iloc[-1] - ma.iloc[0]) / lookback
    is_trend_slope = abs(slope) > slope_threshold

    # ADX regime (trend if ADX > threshold)
    try:
        import talib
        adx = talib.ADX(df['high'].values, df['low'].values, df['close'].values, timeperiod=14)
        adx_val = adx[-1]
    except Exception:
        adx_val = 20
    is_trend_adx = adx_val > adx_threshold

    # Bollinger Band width regime (trend if bands are wide)
    try:
        upper = closes.rolling(20).mean() + closes.rolling(20).std() * 2
        lower = closes.rolling(20).mean() - closes.rolling(20).std() * 2
        bb_width = (upper - lower) / closes.rolling(20).mean()
        bb_width_val = bb_width.iloc[-1]
    except Exception:
        bb_width_val = 0.01
    is_trend_bb = bb_width_val > bb_width_threshold

    # Keltner Channel width regime (trend if wide)
    try:
        _, _, kc_width_val = calculate_keltner_channel(df)
    except Exception:
        kc_width_val = 0.01
    is_trend_kc = kc_width_val > kc_width_threshold

    # Price action pattern regime (trend if strong pattern)
    pattern = detect_price_action_pattern(df)
    is_trend_pattern = pattern in ("bullish", "bearish")

    # Combine all signals (majority vote)
    trend_votes = sum([is_trend_vol, is_trend_slope, is_trend_adx, is_trend_bb, is_trend_kc, is_trend_pattern])
    if trend_votes >= 3:
        return "trend"
    else:
        return "range"

def is_symbol_in_active_session(symbol, dt=None):
    """
    Returns True if the symbol is in its active session (NY time).
    GBPUSD: 7-12 NY time (12-17 UTC)
    AUDUSD: 20-23,0-2 NY time (1-5,5-7 UTC)
    """
    from datetime import datetime, timezone, timedelta
    import pytz

    # Get current NY hour
    if dt is None:
        dt = datetime.now(timezone.utc)
    ny_tz = pytz.timezone("America/New_York")
    ny_time = dt.astimezone(ny_tz)
    hour = ny_time.hour

    if "GBPUSD" in symbol:
        return 7 <= hour <= 12
    if "AUDUSD" in symbol:
        return (20 <= hour <= 23) or (0 <= hour <= 2)
    return True  # Other symbols: always tradable

def generate_trade_signal(df, features, model):
    """
    Generate a trade signal using advanced regime detection and custom filters.
    Includes RSI and news sentiment confluence logic.
    """
    symbol = features.get("symbol") or df.get("symbol", [None])[-1]
    # --- SESSION FILTER ---
    from datetime import datetime, timezone
    if not is_symbol_in_active_session(symbol):
        print(f"[SESSION FILTER] {symbol}: Not in active session, holding.")
        return "hold", 0.0, None

    regime = detect_regime(df)
    print(f"[REGIME] Detected regime: {regime}")

    ema_fast = features.get("ema20", 0)
    ema_slow = features.get("ema200", 0)
    rsi = features.get("rsi", 50)
    news_sentiment = features.get("news_sentiment", 0)
    _, _, kc_width = calculate_keltner_channel(df)
    pattern = detect_price_action_pattern(df)

    # --- RSI and News Sentiment Confluence ---
    # Only allow buy if RSI < 70 and news sentiment is not negative, sell if RSI > 30 and news not positive
    # This allows more trades in range regimes, but blocks extreme overbought/oversold
    def rsi_news_filter(signal, rsi, news_sentiment):
        if signal == "buy" and (rsi > 70 or news_sentiment < 0):
            print(f"[CONFLUENCE] Buy blocked by RSI/news (RSI={rsi}, news={news_sentiment})")
            return False
        if signal == "sell" and (rsi < 30 or news_sentiment > 0):
            print(f"[CONFLUENCE] Sell blocked by RSI/news (RSI={rsi}, news={news_sentiment})")
            return False
        return True

    if regime == "trend":
        # Trend-following logic: only trade in direction of moving average, breakout, etc.
        if ema_fast > ema_slow and rsi > 55 and kc_width > 0.015 and pattern == "bullish":
            signal, confidence, pattern_ml = model.predict(features)
            if rsi_news_filter(signal, rsi, news_sentiment):
                if confidence < MIN_ML_CONFIDENCE:
                    print(f"[TREND] ML confidence {confidence:.2f} below min {MIN_ML_CONFIDENCE:.2f}. Holding.")
                    return "hold", 0.0, None
                print("[TREND] Trend-following BUY filter passed.")
                return signal, confidence, pattern_ml
            else:
                return "hold", 0.0, None
        elif ema_fast < ema_slow and rsi < 45 and kc_width > 0.015 and pattern == "bearish":
            signal, confidence, pattern_ml = model.predict(features)
            if rsi_news_filter(signal, rsi, news_sentiment):
                if confidence < MIN_ML_CONFIDENCE:
                    print(f"[TREND] ML confidence {confidence:.2f} below min {MIN_ML_CONFIDENCE:.2f}. Holding.")
                    return "hold", 0.0, None
                print("[TREND] Trend-following SELL filter passed.")
                return signal, confidence, pattern_ml
            else:
                return "hold", 0.0, None
        else:
            print("[TREND] No valid trend-following setup.")
            return "hold", 0.0, None
    elif regime == "range":
        # Mean-reversion logic: trade reversals at overbought/oversold, support/resistance
        if rsi < 35 and pattern == "bullish":
            signal, confidence, pattern_ml = model.predict(features)
            if rsi_news_filter(signal, rsi, news_sentiment):
                if confidence < MIN_ML_CONFIDENCE:
                    print(f"[RANGE] ML confidence {confidence:.2f} below min {MIN_ML_CONFIDENCE:.2f}. Holding.")
                    return "hold", 0.0, None
                print("[RANGE] Mean-reversion BUY filter passed.")
                return signal, confidence, pattern_ml
            else:
                return "hold", 0.0, None
        elif rsi > 65 and pattern == "bearish":
            signal, confidence, pattern_ml = model.predict(features)
            if rsi_news_filter(signal, rsi, news_sentiment):
                if confidence < MIN_ML_CONFIDENCE:
                    print(f"[RANGE] ML confidence {confidence:.2f} below min {MIN_ML_CONFIDENCE:.2f}. Holding.")
                    return "hold", 0.0, None
                print("[RANGE] Mean-reversion SELL filter passed.")
                return signal, confidence, pattern_ml
            else:
                return "hold", 0.0, None
        else:
            print("[RANGE] No valid mean-reversion setup.")
            return "hold", 0.0, None
    else:
        print("[REGIME] Unknown regime, defaulting to hold.")
        return "hold", 0.0, None


def load_main_model(symbol):
    """
    Loads the per-symbol ML model if available, otherwise falls back to rule-based strategy.
    Tries RandomForest, XGBoost, and LightGBM in order.
    """
    import joblib
    import os
    # Try RandomForest
    model_path_rf = f"models/model_rf_{symbol}.pkl"
    if os.path.exists(model_path_rf):
        print(f"[INFO] Loading RandomForest model for {symbol} from {model_path_rf}")
        return joblib.load(model_path_rf)
    # Try XGBoost
    # XGBoost
    model_path_xgb = f"models/model_xgb_{symbol}.json"
    if os.path.exists(model_path_xgb):
        try:
            import xgboost as xgb
            print(f"[INFO] Loading XGBoost model for {symbol} from {model_path_xgb}")
            return xgb.Booster(model_file=model_path_xgb)
        except Exception as e:
            print(f"[WARNING] Could not load XGBoost model for {symbol}: {e}")
    # LightGBM
    model_path_lgb = f"models/model_lgb_{symbol}.txt"
    if os.path.exists(model_path_lgb):
        try:
            import lightgbm as lgb
            print(f"[INFO] Loading LightGBM model for {symbol} from {model_path_lgb}")
            return lgb.Booster(model_file=model_path_lgb)
        except Exception as e:
            print(f"[WARNING] Could not load LightGBM model for {symbol}: {e}")
    print(f"[ERROR] No ML model found for {symbol}, using RuleBasedFallbackStrategy.")
    return RuleBasedFallbackStrategy()

class RuleBasedFallbackStrategy:
    """
    Fallback strategy: always returns a rule-based signal (e.g., from Breakout or TrendMomentum).
    """
    def __init__(self):
        # You can use your best rule-based strategy here
        self.fallback = BreakoutStrategy()

    def predict(self, features):
        # features should include a DataFrame as 'df' or you can pass it directly
        df = features.get("df")
        if df is not None:
            signal = self.fallback.check(df, features)
            # Return a tuple to match ML model interface: (signal, confidence)
            return signal if signal else "hold", 1.0
        # If no DataFrame, just hold
        return "hold", 1.0

def calculate_atr(df, period=14, symbol=None):
    """
    Robust and advanced ATR calculation.
    - Handles missing data, gaps, and symbol-specific point values.
    - Uses Wilder's smoothing (EMA) for more responsive ATR.
    - Returns both the latest ATR value and the full ATR series if needed.
    - Optionally adjusts for JPY pairs and metals.
    """
    import numpy as np
    import pandas as pd

    # Defensive: Ensure required columns exist
    for col in ['high', 'low', 'close']:
        if col not in df.columns:
            raise ValueError(f"DataFrame missing required column: {col}")

    high = df['high'].astype(float)
    low = df['low'].astype(float)
    close = df['close'].astype(float)

    prev_close = close.shift(1)
    tr1 = high - low
    tr2 = abs(high - prev_close)
    tr3 = abs(low - prev_close)
    tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)

    # Use Wilder's smoothing (EMA with alpha=1/period)
    atr = tr.ewm(alpha=1/period, min_periods=period, adjust=False).mean()

    # Defensive: Remove outliers (spikes > 5x median)
    median_tr = tr.rolling(window=period, min_periods=1).median()
    tr = np.where(tr > 5 * median_tr, median_tr, tr)
    atr = pd.Series(tr).ewm(alpha=1/period, min_periods=period, adjust=False).mean()

    # Symbol-specific adjustment for JPY pairs and metals
    point_value = 0.0001
    if symbol is not None:
        if "JPY" in symbol:
            point_value = 0.01
        elif "XAU" in symbol or "GOLD" in symbol:
            point_value = 0.1

    # Normalize ATR to points (if needed)
    atr_val = atr.iloc[-1]
    if point_value != 1.0:
        atr_val = round(atr_val / point_value, 2) * point_value

    # Defensive: If ATR is NaN or zero, fallback to a small value
    if np.isnan(atr_val) or atr_val == 0:
        atr_val = max(abs(high.iloc[-1] - low.iloc[-1]), 0.0005)

    return atr_val


