def calculate_rsi(df, period=14):
    """
    Calculates the Relative Strength Index (RSI) indicator for a given DataFrame.

    RSI is a momentum oscillator that measures the speed and change of price movements.

    Args:
        df (pd.DataFrame): DataFrame containing a 'close' column.
        period (int): The period over which to calculate RSI.

    Returns:
        float: The latest RSI value.
    """
    delta = df['close'].diff()
    gain = (delta.where(delta > 0, 0)).rolling(window=period).mean()
    loss = (-delta.where(delta < 0, 0)).rolling(window=period).mean()
    rs = gain / loss
    rsi = 100 - (100 / (1 + rs))
    return rsi.iloc[-1]

# === Utility ===
def is_friday_near_market_close():
    """
    Returns True if it's Friday and within 15 minutes of market close (4:45 PM NY time = ~21:45 UTC).
    This prevents opening new trades at end of week to avoid gap/slippage risk over the weekend.
    """
    now = get_utc_now()
    is_friday = now.weekday() == 4  # 0=Monday, 4=Friday
    # Market closes 5 PM NY time Friday. 5 PM ET = 21:00 UTC (winter) or 22:00 UTC (summer)
    # To be safe, use 21:45 UTC as the threshold (15 mins before nominal close)
    hour_and_minute = now.hour * 60 + now.minute  # Convert to minutes since midnight UTC
    close_threshold_utc = 23 * 60 + 00  # 21:45 UTC in minutes
    is_near_close = hour_and_minute >= close_threshold_utc
    return is_friday and is_near_close

def get_current_session():
    """
    Returns a string indicating which session is currently open: 'Sydney', 'Tokyo', 'London', 'New York', 'Overlap', or 'Closed'.
    Always uses UTC time, automatically converting from local time.
    """
    now = get_utc_now()
    hour = now.hour
    sydney = 22 <= hour or hour < 7  # 22:00 - 07:00 UTC
    tokyo = 0 <= hour < 9
    london = 7 <= hour < 16
    newyork = 12 <= hour < 21

    if sydney and london:
        return "Sydney & London"
    elif sydney and tokyo:
        return "Sydney & Tokyo"
    elif london and newyork:
        return "London & New York"
    elif sydney:
        return "Sydney"
    elif tokyo:
        return "Tokyo"
    elif london:
        return "London"
    elif newyork:
        return "New York"
    else:
        return "Closed"

def is_session_open(symbol=None):
    """
    Returns True if the current time is within the main trading sessions (Sydney, Tokyo, London, or New York).
    If symbol is provided, allows trading in Tokyo for JPY pairs and XAUUSD.
    """
    now = get_utc_now()
    hour = now.hour
    # Sydney: 22-07 UTC, Tokyo: 0-9 UTC, London: 7-16 UTC, New York: 12-21 UTC
    if symbol is not None:
        if "JPY" in symbol or symbol == "XAUUSD":
            return (0 <= hour < 9) or (7 <= hour < 16) or (12 <= hour < 21)  # Tokyo, London, NY
    return (22 <= hour or hour < 7) or (0 <= hour < 9) or (7 <= hour < 16) or (12 <= hour < 21)



