# --- Risk Limits: Always from ConfigManager ---
config = ConfigManager()
MAX_DAILY_LOSS = config.get('max_daily_loss', -50)
MAX_DAILY_PROFIT = config.get('max_daily_profit', 250)
DAILY_LOSS_CAP_PCT = config.get('daily_loss_cap_pct', 0.08)  # 8% default

_daily_start_balance = None
_daily_pnl = 0
_daily_trading_blocked = False

def reset_daily_pnl():
    global _daily_start_balance, _daily_pnl, _daily_trading_blocked
    account_info = mt5.account_info()
    _daily_start_balance = account_info.balance if account_info else 1000
    _daily_pnl = 0
    _daily_trading_blocked = False

def update_daily_pnl(trade_pnl):
    global _daily_pnl, _daily_trading_blocked, _daily_start_balance, TRADING_HALTED
    _daily_pnl += trade_pnl
    if _daily_start_balance is None:
        account_info = mt5.account_info()
        _daily_start_balance = account_info.balance if account_info else 1000
    if _daily_pnl <= -_daily_start_balance * DAILY_LOSS_CAP_PCT:
        _daily_trading_blocked = True
        TRADING_HALTED = True
        print(f"[RISK] Daily loss cap hit! PnL={_daily_pnl:.2f}, cap={-_daily_start_balance * DAILY_LOSS_CAP_PCT:.2f}. Trading halted for today.")
        send_telegram_alert(f"TRADING HALTED: Daily loss cap hit! PnL={_daily_pnl:.2f}")

def can_trade_today():
    return not _daily_trading_blocked

