import threading

def send_telegram_alert(message, chat_id=None, token=None):
    """
    Send a Telegram alert using python-telegram-bot.
    Set your bot token and chat_id in config or as arguments.
    """
    try:
        import telegram
        token = token or TELEGRAM_BOT_TOKEN
        chat_id = chat_id or TELEGRAM_CHAT_ID
        bot = telegram.Bot(token=token)
        # Use threading to avoid blocking main loop
        threading.Thread(target=bot.send_message, args=(chat_id, message)).start()
    except Exception as e:
        print(f"[TELEGRAM] Failed to send alert: {e}")

