def get_price_data(symbol, timeframe=TIMEFRAME, bars=5000):
    """
    Robustly fetches price data for a symbol, ensuring enough bars are returned.
    Tries multiple methods and symbol suffixes if needed.
    """
    import os
    from datetime import datetime
    import pandas as pd
    import MetaTrader5 as mt5
    import time as _pytime

    # --- Map string timeframes to MT5 constants ---
    TIMEFRAME_MAP = {
        "M1": mt5.TIMEFRAME_M1,
        "M2": mt5.TIMEFRAME_M2,
        "M3": mt5.TIMEFRAME_M3,
        "M4": mt5.TIMEFRAME_M4,
        "M5": mt5.TIMEFRAME_M5,
        "M6": mt5.TIMEFRAME_M6,
        "M10": mt5.TIMEFRAME_M10,
        "M12": mt5.TIMEFRAME_M12,
        "M15": mt5.TIMEFRAME_M15,
        "M20": mt5.TIMEFRAME_M20,
        "M30": mt5.TIMEFRAME_M30,
        "H1": mt5.TIMEFRAME_H1,
        "H2": mt5.TIMEFRAME_H2,
        "H3": mt5.TIMEFRAME_H3,
        "H4": mt5.TIMEFRAME_H4,
        "H6": mt5.TIMEFRAME_H6,
        "H8": mt5.TIMEFRAME_H8,
        "H12": mt5.TIMEFRAME_H12,
        "D1": mt5.TIMEFRAME_D1,
        "W1": mt5.TIMEFRAME_W1,
        "MN1": mt5.TIMEFRAME_MN1,
    }

    # Convert string timeframe to MT5 constant if needed
    tf = timeframe
    if isinstance(timeframe, str):
        tf = TIMEFRAME_MAP.get(timeframe.upper(), mt5.TIMEFRAME_M15)

    # Simple in-memory cache to avoid repeated expensive MT5/csv reads during one run
    global _PRICE_DATA_CACHE
    try:
        _PRICE_DATA_CACHE
    except NameError:
        _PRICE_DATA_CACHE = {}

    cache_key = (resolved_symbol, tf, int(bars)) if 'resolved_symbol' in locals() else (symbol, tf, int(bars))
    cache_entry = _PRICE_DATA_CACHE.get(cache_key)
    if cache_entry is not None:
        cached_ts, cached_df = cache_entry
        # Use cached data (no TTL for now, could add refresh)
        return cached_df.copy()

    df = None

    # --- Resolve symbol ---
    resolved_symbol = resolve_symbol(symbol, verbose=False)
    if not resolved_symbol:
        print(f"[ERROR] Could not resolve symbol: {symbol}")
        return None

    # --- Step 1: Try direct fetch ---
    rates = mt5.copy_rates_from_pos(resolved_symbol, tf, 0, bars)
    if rates is not None and len(rates) >= bars:
        df = pd.DataFrame(rates)
        df['time'] = pd.to_datetime(df['time'], unit='s')
        df['symbol'] = resolved_symbol

    # --- Step 2: Try Market Watch selection ---
    if df is None:
        info = mt5.symbol_info(resolved_symbol)
        if info is not None and not info.visible:
            mt5.symbol_select(resolved_symbol, True)
        rates = mt5.copy_rates_from_pos(resolved_symbol, tf, 0, bars)
        if rates is not None and len(rates) >= bars:
            df = pd.DataFrame(rates)
            df['time'] = pd.to_datetime(df['time'], unit='s')
            df['symbol'] = resolved_symbol

    # --- Step 3: Try CSV file ---
    if df is None:
        # Look for CSVs in local history_data first, then in user's data directory
        csv_candidates = []
        hist_path = os.path.join("history_data", f"{resolved_symbol}_history.csv")
        csv_candidates.append(hist_path)

        # Determine timeframe label for filename (prefer the original timeframe arg if it was a string)
        try:
            tf_label = timeframe if isinstance(timeframe, str) else None
        except Exception:
            tf_label = None
        if not tf_label:
            # reverse map common mt5 timeframe constants
            TF_REV = {v: k for k, v in TIMEFRAME_MAP.items()}
            tf_label = TF_REV.get(tf, 'M15')

        # Configurable data dir (look in config or environment)
        data_dir = None
        try:
            data_dir = getattr(config, 'DATA_DIR', None) if 'config' in globals() and config else None
        except Exception:
            data_dir = None
        if not data_dir:
            data_dir = os.environ.get('DATA_DIR', r'C:\Users\JEFFKID\data')

        base = resolved_symbol.split('.')[0]
        # Build candidate filenames to try
        if data_dir:
            candidates = [
                os.path.join(data_dir, f"{resolved_symbol}_{tf_label}.csv"),
                os.path.join(data_dir, f"{resolved_symbol}_M15.csv"),
                os.path.join(data_dir, f"{base}_{tf_label}.csv"),
                os.path.join(data_dir, f"{base}_M15.csv"),
                os.path.join(data_dir, f"{base}.m_{tf_label}.csv"),
                os.path.join(data_dir, f"{base}.m_{tf_label}.CSV"),
                os.path.join(data_dir, f"{base}_M15.CSV"),
            ]
            csv_candidates.extend(candidates)

        # Try reading candidate files robustly
        for csv_path in csv_candidates:
            if not csv_path or not os.path.exists(csv_path):
                continue
            try:
                # read with automatic sep; if read yields single column, try tab/semicolon
                tmp = pd.read_csv(csv_path, sep=None, engine='python')
                if len(tmp.columns) == 1:
                    # detect delimiter by inspecting first line
                    with open(csv_path, 'r', encoding='utf-8', errors='ignore') as fh:
                        first = fh.readline()
                    sep = '\t' if '\t' in first else (';' if ';' in first else ',')
                    tmp = pd.read_csv(csv_path, sep=sep, engine='python')

                # Normalize headers (common MT5 CSV headers and variants)
                rename_map = {}
                for c in list(tmp.columns):
                    lc = c.lower().strip()
                    if lc in ('<date>', 'date'):
                        rename_map[c] = 'date'
                    if lc in ('<time>', 'time'):
                        rename_map[c] = 'time'
                    if lc in ('<open>', 'open', 'o'):
                        rename_map[c] = 'open'
                    if lc in ('<high>', 'high', 'h'):
                        rename_map[c] = 'high'
                    if lc in ('<low>', 'low', 'l'):
                        rename_map[c] = 'low'
                    if lc in ('<close>', 'close', 'c'):
                        rename_map[c] = 'close'
                    if lc in ('<tickvol>', 'tickvol', 'tick_volume', 'volume'):
                        rename_map[c] = 'tick_volume'
                tmp.rename(columns=rename_map, inplace=True)

                # Combine date/time if present
                if 'date' in tmp.columns and 'time' in tmp.columns:
                    try:
                        tmp['time'] = pd.to_datetime(tmp['date'].astype(str) + ' ' + tmp['time'].astype(str), errors='coerce')
                        tmp.drop(columns=['date'], inplace=True)
                    except Exception:
                        pass

                # If 'time' missing but first column looks like datetime, try parsing
                if 'time' not in tmp.columns and tmp.shape[1] > 0:
                    firstcol = tmp.columns[0]
                    try:
                        tmp['time'] = pd.to_datetime(tmp[firstcol], errors='coerce')
                    except Exception:
                        pass

                # Ensure OHLC present or infer from 'price' or bid/ask
                if not all(k in tmp.columns for k in ['open', 'high', 'low', 'close']):
                    orig_cols = [c for c in tmp.columns]
                    if 'price' in [c.lower() for c in orig_cols]:
                        price_col = [c for c in orig_cols if c.lower()=='price'][0]
                        tmp['close'] = tmp[price_col]
                        tmp['open'] = tmp[price_col]
                        tmp['high'] = tmp[price_col]
                        tmp['low'] = tmp[price_col]
                    elif 'bid' in [c.lower() for c in orig_cols] and 'ask' in [c.lower() for c in orig_cols]:
                        bid_col = [c for c in orig_cols if c.lower()=='bid'][0]
                        ask_col = [c for c in orig_cols if c.lower()=='ask'][0]
                        tmp['close'] = (tmp[bid_col] + tmp[ask_col]) / 2.0
                        tmp['open'] = tmp['close']
                        tmp['high'] = tmp['close']
                        tmp['low'] = tmp['close']
                    else:
                        # Not usable
                        print(f"[HISTORY LOAD] File {csv_path} missing OHLC columns. Detected: {list(tmp.columns)}")
                        continue

                # Filter by reasonable date and tail to bars
                if 'time' in tmp.columns:
                    tmp['time'] = pd.to_datetime(tmp['time'], errors='coerce')
                    tmp = tmp[tmp['time'].notna()]
                tmp = tmp.reset_index(drop=True)
                if len(tmp) > bars:
                    tmp = tmp.tail(bars).reset_index(drop=True)
                tmp['symbol'] = resolved_symbol
                df = tmp
                break
            except Exception as e:
                print(f"[HISTORY LOAD] Failed to read {csv_path}: {e}")
                continue

    # --- Step 4: Try to download from MT5 ---
    if df is None:
        try:
            print(f"[INFO] Attempting to download history for {resolved_symbol} from MT5...")
            info = mt5.symbol_info(resolved_symbol)
            if info is not None:
                if not info.visible:
                    mt5.symbol_select(resolved_symbol, True)
                now = datetime.now()
                from_date = datetime(now.year - 3, now.month, now.day)
                try:
                    mt5.chart_open(resolved_symbol, tf)
                except Exception:
                    pass
                _pytime.sleep(3)
                rates = mt5.copy_rates_range(resolved_symbol, tf, from_date, now)
                if rates is not None and len(rates) > 0:
                    df = pd.DataFrame(rates)
                    df['time'] = pd.to_datetime(df['time'], unit='s')
                    df['symbol'] = resolved_symbol
                    os.makedirs("history_data", exist_ok=True)
                    df.to_csv(os.path.join("history_data", f"{resolved_symbol}_history.csv"), index=False)
                    print(f"[INFO] Downloaded and saved {len(df)} bars for {resolved_symbol}")
                    if len(df) < bars:
                        print(f"[USER ACTION REQUIRED] Please open a chart for '{resolved_symbol}' in MT5, scroll back as far as possible, and rerun the bot.")
        except Exception as e:
            print(f"[ERROR] Could not download history for {resolved_symbol}: {e}")

    # --- Final check ---
    if df is None or len(df) < bars:
        print(f"[ERROR] Error fetching price data for {resolved_symbol}: Not enough bars found (needed {bars})")
        print(f"[HINT] Ensure the symbol is visible in Market Watch and history is loaded.")
        return None

    # --- Keep only last 6 months of M15 candles for training relevance ---
    max_bars_6m = 24 * 4 * 30 * 6
    if len(df) > max_bars_6m:
        df = df.tail(max_bars_6m)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")

    # Cache and return
    try:
        _PRICE_DATA_CACHE[cache_key] = (time.time(), df.copy())
    except Exception:
        pass
    return df
def get_symbol_lookahead(symbol):
    """
    Returns the lookahead window for the given symbol.
    GBPUSD/AUDUSD: 3 (or 4) bars, EURUSD/XAUUSD: 5 bars.
    """
    if "GBPUSD" in symbol or "AUDUSD" in symbol:
        return 3
    elif "EURUSD" in symbol or "XAUUSD" in symbol or "GOLD" in symbol:
        return 5
    else:
        return 5  # Default

def is_symbol_in_active_session(symbol, dt=None):
    from datetime import datetime, timezone, timedelta
    import pytz
    if dt is None:
        dt = datetime.now(timezone.utc)
    ny_tz = pytz.timezone("America/New_York")
    ny_time = dt.astimezone(ny_tz)
    hour = ny_time.hour
    if "GBPUSD" in symbol:
        return 7 <= hour <= 12
    if "AUDUSD" in symbol:
        return (20 <= hour <= 23) or (0 <= hour <= 2)
    return True

def backtest_with_model(symbol, model, df, lookahead=None, profit_pips=10):
    if lookahead is None:
        lookahead = get_symbol_lookahead(symbol)
    trades = []
    pip_size = 0.01 if "JPY" in symbol else 0.0001
    SL_ATR_MULTIPLIER, TP_ATR_MULTIPLIER, MIN_SL_POINTS, point_value = get_symbol_atr_params(symbol)
    for i in range(50, len(df) - lookahead):
        window = df.iloc[:i+1]
        features = get_features_fixed(window)
        if isinstance(features, dict) and any(isinstance(v, dict) for v in features.values()):
            flat_features = {}
            for k, v in features.items():
                if isinstance(v, dict):
                    for subk, subv in v.items():
                        flat_features[f"{k}_{subk}"] = subv
                else:
                    flat_features[k] = v
            features = flat_features
        
        entry = df['close'].iloc[i]
        signal, confidence = model.predict(features)
        if signal not in ("buy", "sell"):
            continue
        atr = features.get("atr", 0.001)
        sl_points = max(int(atr * SL_ATR_MULTIPLIER / point_value), MIN_SL_POINTS)
        tp_points = int(sl_points * (TP_ATR_MULTIPLIER / SL_ATR_MULTIPLIER))
        if signal == "buy":
            sl = entry - sl_points * point_value
            tp = entry + tp_points * point_value
        else:
            sl = entry + sl_points * point_value
            tp = entry - tp_points * point_value

        future = df['close'].iloc[i+1:i+1+lookahead]
        max_up = (future - entry).max()
        max_down = (future - entry).min()

        if signal == "buy":
            result = tp - entry if max_up >= (tp - entry) else (sl - entry if max_down <= (sl - entry) else 0)
        else:
            result = entry - tp if -max_down >= (entry - tp) else (entry - sl if -max_up <= (entry - sl) else 0)

        trades.append({
            "entry_time": df['time'].iloc[i],
            "signal": signal,
            "confidence": confidence,
            "result": result
        })
    return trades

def extended_metrics(trades):
    metrics = profit_metrics(trades)
    returns = [t['result'] for t in trades]
    if returns:
        metrics["sharpe"] = np.mean(returns) / (np.std(returns) + 1e-6)  # Sharpe
        drawdown = 0
        peak = 0
        balance = 0
        for r in returns:
            balance += r
            peak = max(peak, balance)
            drawdown = max(drawdown, peak - balance)
        metrics["max_drawdown"] = drawdown
    return metrics

    
def get_full_history(symbol, timeframe=mt5.TIMEFRAME_M15, years=2):
    now = datetime.now()
    from_date = datetime(now.year - years, now.month, now.day)
    rates = mt5.copy_rates_range(symbol, timeframe, from_date, now)
    if rates is None or len(rates) == 0:
        print(f"[{symbol}] No data found for backtest.")
        return None
    df = pd.DataFrame(rates)
    df['time'] = pd.to_datetime(df['time'], unit='s')

    # Keep last 6 months for training relevance
    if len(df) > (24*4*30*6):  # M15 candles in ~6 months
        df = df.tail(24*4*30*6)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
    return df

def get_backtest_data(symbol=SYMBOLS, timeframe="M15", bars=None, from_year=2024, to_year=None, data_dir="./data"):
    import os
    import pandas as pd
    if isinstance(symbol, (list, tuple)):
        # if caller accidentally passed SYMBOLS list, pick first allowed symbol
        symbol = symbol[0] if symbol else "XAUUSD.ecn"
    # Use .m for CSV files (no replacement)
    csv_path = os.path.join(data_dir, f"{symbol}_M15.csv")
    if not os.path.exists(csv_path):
        print(f"[BACKTEST] {csv_path} not found.")
        return None
    # Read with tab or whitespace separator and rename columns
    df = pd.read_csv(csv_path, sep=None, engine='python')
    # Rename columns to standard names
    df.rename(columns={
        '<DATE>': 'date',
        '<TIME>': 'time',
        '<OPEN>': 'open',
        '<HIGH>': 'high',
        '<LOW>': 'low',
        '<CLOSE>': 'close',
        '<TICKVOL>': 'tick_volume',
        '<VOL>': 'real_volume',
        '<SPREAD>': 'spread'
    }, inplace=True)
    # --- Ensure we have a proper datetime `time` column ---
    # If the CSV has separate date/time columns (common in some exports), combine them.
    if 'date' in df.columns and 'time' in df.columns:
        try:
            df['time'] = pd.to_datetime(df['date'].astype(str) + ' ' + df['time'].astype(str), format='%Y.%m.%d %H:%M:%S', errors='coerce')
        except Exception:
            df['time'] = pd.to_datetime(df['date'].astype(str) + ' ' + df['time'].astype(str), errors='coerce')
        try:
            df.drop(columns=['date'], inplace=True)
        except Exception:
            pass

    # If 'time' exists but is not a datetime dtype, try to coerce it robustly.
    if 'time' not in df.columns:
        print(f"[ERROR] 'time' column missing in {csv_path}. Columns found: {df.columns.tolist()}")
        return None

    # Attempt a few common parse strategies (epoch seconds, generic parse)
    try:
        if pd.api.types.is_numeric_dtype(df['time']):
            # assume epoch seconds if numeric
            df['time'] = pd.to_datetime(df['time'], unit='s', errors='coerce')
        else:
            # try generic parse first (handles many formats)
            df['time'] = pd.to_datetime(df['time'].astype(str), errors='coerce')
            # If parsing failed for many rows, try alternative formats
            if df['time'].isna().sum() > 0 and df['time'].notna().sum() < len(df):
                try:
                    df['time'] = pd.to_datetime(df['time'].astype(str), format='%Y.%m.%d %H:%M:%S', errors='coerce')
                except Exception:
                    pass
    except Exception:
        try:
            df['time'] = pd.to_datetime(df['time'].astype(str), errors='coerce')
        except Exception:
            pass

    # Drop rows with unparseable time values
    if df['time'].isna().all():
        print(f"[ERROR] Could not parse any datetime values in {csv_path} 'time' column.")
        return None

    # Convert any remaining object/string values to datetimes (defensive)
    try:
        df['time'] = pd.to_datetime(df['time'])
    except Exception:
        df['time'] = pd.to_datetime(df['time'], errors='coerce')

    # Filter to recent data (safe now that time is datetime)
    df = df[df['time'] >= pd.Timestamp('2023-01-01')]

    if bars is not None and len(df) > bars:
        df = df.tail(bars).reset_index(drop=True)
    if from_year or to_year:
        if from_year:
            df = df[df['time'].dt.year >= from_year]
        if to_year:
            df = df[df['time'].dt.year <= to_year]
        df = df.reset_index(drop=True)
    if len(df) < 50:
        print(f"[BACKTEST] Not enough data in {csv_path} (rows={len(df)}). Skipping.")
        return None
    print(f"[BACKTEST] Loaded {len(df)} rows for {symbol} from {csv_path}")

    # Keep last 6 months for training relevance
    if len(df) > (24*4*30*6):  # M15 candles in ~6 months
        df = df.tail(24*4*30*6)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
    return df
    
def calculate_ema(df, period=200):
    """
    Calculates the Exponential Moving Average (EMA) for a given DataFrame.

    Returns the most recent EMA value for the specified period.
    If not enough data, returns np.nan.

    Args:
        df (pd.DataFrame): DataFrame containing a 'close' column.
        period (int): The period over which to calculate EMA.

    Returns:
        float: The latest EMA value or np.nan if insufficient data.
    """
    import numpy as np
    if len(df) < period or 'close' not in df:
        return np.nan
    ema = df['close'].ewm(span=period, adjust=False).mean()
    return float(ema.iloc[-1]) if not np.isnan(ema.iloc[-1]) else np.nan

def calculate_std(df, period=20):
    """
    Calculates the rolling standard deviation of the close price.

    Returns the most recent standard deviation value for the specified period.

    Args:
        df (pd.DataFrame): DataFrame containing a 'close' column.
        period (int): The period over which to calculate the standard deviation.

    Returns:
        float: The latest rolling standard deviation value.
    """

    # Keep last 6 months for training relevance
    if len(df) > (24*4*30*6):  # M15 candles in ~6 months
        df = df.tail(24*4*30*6)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
    return df['close'].rolling(window=period).std().iloc[-1]


def profit_metrics(trades):
    """
    Accepts a list of trade dicts (with 'result' key) and returns performance metrics.
    """
    if not trades:
        return {
            'total_profit': 0,
            'winrate': 0,
            'sharpe': 0,
            'max_drawdown': 0
        }
    # If trades is a DataFrame, convert to list of dicts
    if hasattr(trades, "to_dict"):
        trades = trades.to_dict("records")
    # Defensive: If trades is a list of dicts, use keys, not column names
    results = [t['result'] for t in trades if 'result' in t]
    total_profit = sum(results)
    winrate = sum(1 for r in results if r > 0) / len(results) if results else 0
    returns = np.array(results)

    # Sharpe ratio example: mean return / std return * sqrt(annualization factor)
    sharpe = returns.mean() / (returns.std() + 1e-8) * np.sqrt(252) if returns.std() != 0 else 0

    # Max drawdown calculation
    cum_returns = returns.cumsum()
    peak = np.maximum.accumulate(cum_returns)
    drawdown = (cum_returns - peak).min() if len(cum_returns) > 0 else 0

    return {
        'total_profit': total_profit,
        'winrate': winrate,
        'sharpe': sharpe,
        'max_drawdown': drawdown
    }
    # --- Standard features ---
    


def has_open_trade(symbol):
    """
    Checks if there is an open trade for the given symbol.

    Returns True if there is at least one open position for the symbol.

    Args:
        symbol (str): The trading symbol to check.

    Returns:
        bool: True if an open trade exists, False otherwise.
    """
    resolved_symbol = resolve_symbol(symbol, verbose=False)
    if not resolved_symbol:
        print(f"[ERROR] Could not resolve symbol: {symbol}")
        return False
    positions = mt5.positions_get(symbol=resolved_symbol)
    return len(positions) > 0 if positions else False

def get_open_position(symbol):
    """
    Gets the first open position for a symbol, or None if no position exists.
    Returns dict with 'direction', 'ticket', 'volume', 'price_open', 'sl', 'tp', 'profit'.
    
    Args:
        symbol (str): The trading symbol to check.
    
    Returns:
        dict or None: Position details if found, None otherwise.
    """
    try:
        resolved_symbol = resolve_symbol(symbol, verbose=False)
        if not resolved_symbol:
            return None
        
        positions = mt5.positions_get(symbol=resolved_symbol)
        if not positions or len(positions) == 0:
            return None
        
        # Return the first open position
        pos = positions[0]
        return {
            'direction': 'buy' if pos.type == 0 else 'sell',
            'ticket': pos.ticket,
            'volume': pos.volume,
            'price_open': pos.price_open,
            'sl': getattr(pos, 'sl', None),
            'tp': getattr(pos, 'tp', None),
            'profit': pos.profit,
            'symbol': pos.symbol
        }
    except Exception as e:
        print(f"[ERROR] Exception in get_open_position({symbol}): {e}")
        return None

def has_sufficient_balance(lot, symbol):
    account_info = mt5.account_info()
    if account_info is None:
        print("[MARGIN DEBUG] Could not get account info.")
        return False
    free_margin = account_info.margin_free
    # Estimate margin required for this trade
    symbol_info = mt5.symbol_info(symbol)
    if symbol_info is None:
        print(f"[MARGIN DEBUG] Could not get symbol info for {symbol}.")
        return False
    price = mt5.symbol_info_tick(symbol).ask
    margin_required = lot * symbol_info.trade_contract_size * price / account_info.leverage
    print(f"[MARGIN DEBUG] {symbol}: Free margin={free_margin:.2f}, Required={margin_required:.2f}, Lot={lot}")
    return free_margin > margin_required * 1.1  # Add 10% buffer
def get_broker_min_stop_distance(symbol):
    """
    Return broker-enforced minimum stop distance (in price units) for symbol,
    based on MT5 symbol_info.stops_level / trade_stops_level.
    Falls back to 0 if info unavailable.
    """
    try:
        info = mt5.symbol_info(symbol)
        if info is None:
            return 0.0
        # stops_level is in points; convert to price
        point = info.point
        # use the stricter of stops_level & trade_stops_level if present
        stops_level = getattr(info, "stops_level", 0) or 0
        trade_stops_level = getattr(info, "trade_stops_level", 0) or 0
        min_points = max(stops_level, trade_stops_level)
        return float(min_points) * float(point)
    except Exception:
        return 0.0
def get_current_spread(symbol):
    """
    Returns the current spread (ask - bid) for the given symbol.
    """
    resolved_symbol = resolve_symbol(symbol, verbose=False)
    if not resolved_symbol:
        print(f"[ERROR] Could not resolve symbol: {symbol}")
        return None
    tick = mt5.symbol_info_tick(resolved_symbol)
    if tick:
        return tick.ask - tick.bid
    return None

def get_current_price(symbol):
    """
    Retrieves the current ask and bid prices for the given symbol.

    Args:
        symbol (str): The trading symbol.

    Returns:
        tuple: (ask price, bid price)
    """
    resolved_symbol = resolve_symbol(symbol, verbose=False)
    if not resolved_symbol:
        print(f"[ERROR] Could not resolve symbol: {symbol}")
        return None, None
    tick = safe_symbol_info_tick(resolved_symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(resolved_symbol) if mt5 else None)
    return (tick.ask, tick.bid) if tick else (None, None)

# === Advanced: Smart Trade Duplication Logic ===

# === KEY LESSON: Candle Must Prove Direction (Break + Close, Pullback, Continuation) ===

def validate_level_break_with_direction_proof(df, level_price, direction, lookback=5):
    """
    KEY RULE: "Touching a level is NOT enough - the candle must prove direction"
    
    Validates three valid entry patterns:
    1. BREAK + CLOSE: Price breaks level and closes beyond it (strongest)
    2. PULLBACK: Price pulls back to level and bounces in intended direction
    3. CONTINUATION: Price continues in direction after testing level
    
    This eliminates ~70% of bad entries by filtering weak breakouts.
    
    Args:
        df: DataFrame with OHLC data
        level_price: Support/Resistance level to validate
        direction: "buy" or "sell"
        lookback: How many candles to analyze (default 5)
    
    Returns:
        dict with entry_valid, pattern_type, and confirmation details
    """
    if df is None or len(df) < lookback + 1:
        return {'entry_valid': False, 'reason': 'Insufficient data', 'pattern': None}
    
    current_candle = df.iloc[-1]
    prev_candle = df.iloc[-2]
    
    current_close = current_candle['close']
    current_open = current_candle['open']
    current_high = current_candle['high']
    current_low = current_candle['low']
    
    prev_close = prev_candle['close']
    
    # === PATTERN 1: BREAK + CLOSE ===
    # Candle breaks level AND closes beyond it (strongest confirmation)
    if direction.lower() == "buy":
        # For buy: low must touch/break level, close must be above level
        is_break_candle = current_low <= level_price
        is_close_beyond = current_close > level_price
        body_closes_beyond = current_close > current_open  # bullish body
        
        break_and_close = is_break_candle and is_close_beyond and body_closes_beyond
        
        if break_and_close:
            return {
                'entry_valid': True,
                'pattern': 'BREAK + CLOSE',
                'strength': 'STRONGEST',
                'details': {
                    'level': level_price,
                    'low': current_low,
                    'close': current_close,
                    'break_touched': is_break_candle,
                    'closed_beyond': is_close_beyond,
                    'bullish_body': body_closes_beyond
                }
            }
    
    else:  # sell
        # For sell: high must touch/break level, close must be below level
        is_break_candle = current_high >= level_price
        is_close_beyond = current_close < level_price
        body_closes_beyond = current_close < current_open  # bearish body
        
        break_and_close = is_break_candle and is_close_beyond and body_closes_beyond
        
        if break_and_close:
            return {
                'entry_valid': True,
                'pattern': 'BREAK + CLOSE',
                'strength': 'STRONGEST',
                'details': {
                    'level': level_price,
                    'high': current_high,
                    'close': current_close,
                    'break_touched': is_break_candle,
                    'closed_beyond': is_close_beyond,
                    'bearish_body': body_closes_beyond
                }
            }
    
    # === PATTERN 2: PULLBACK ===
    # Price pulls back to level and bounces (tests level with intent to move)
    if direction.lower() == "buy":
        # For buy: price must test level from above, then bounce up
        touched_level = current_low <= level_price <= current_high
        bounced_up = current_close > current_open and current_close > prev_close
        
        pullback = touched_level and bounced_up
        
        if pullback:
            return {
                'entry_valid': True,
                'pattern': 'PULLBACK',
                'strength': 'STRONG',
                'details': {
                    'level': level_price,
                    'low': current_low,
                    'high': current_high,
                    'touched_level': touched_level,
                    'bounced_up': bounced_up,
                    'close': current_close
                }
            }
    
    else:  # sell
        # For sell: price must test level from below, then drop down
        touched_level = current_low <= level_price <= current_high
        bounced_down = current_close < current_open and current_close < prev_close
        
        pullback = touched_level and bounced_down
        
        if pullback:
            return {
                'entry_valid': True,
                'pattern': 'PULLBACK',
                'strength': 'STRONG',
                'details': {
                    'level': level_price,
                    'low': current_low,
                    'high': current_high,
                    'touched_level': touched_level,
                    'bounced_down': bounced_down,
                    'close': current_close
                }
            }
    
    # === PATTERN 3: CONTINUATION ===
    # Price continues in direction after testing nearby level
    if direction.lower() == "buy":
        # For buy: current candle bullish, continues above level
        is_bullish = current_close > current_open
        is_above_level = current_close > level_price
        has_momentum = current_close > prev_close
        
        continuation = is_bullish and is_above_level and has_momentum
        
        if continuation:
            return {
                'entry_valid': True,
                'pattern': 'CONTINUATION',
                'strength': 'MODERATE',
                'details': {
                    'level': level_price,
                    'close': current_close,
                    'is_bullish': is_bullish,
                    'above_level': is_above_level,
                    'momentum': has_momentum
                }
            }
    
    else:  # sell
        # For sell: current candle bearish, continues below level
        is_bearish = current_close < current_open
        is_below_level = current_close < level_price
        has_momentum = current_close < prev_close
        
        continuation = is_bearish and is_below_level and has_momentum
        
        if continuation:
            return {
                'entry_valid': True,
                'pattern': 'CONTINUATION',
                'strength': 'MODERATE',
                'details': {
                    'level': level_price,
                    'close': current_close,
                    'is_bearish': is_bearish,
                    'below_level': is_below_level,
                    'momentum': has_momentum
                }
            }
    
    # No valid pattern found
    return {
        'entry_valid': False,
        'pattern': None,
        'reason': 'Candle did not prove direction at level',
        'details': {
            'level': level_price,
            'current_close': current_close,
            'message': 'Touching level alone is NOT sufficient - candle must prove intent'
        }
    }

# === Advanced Buy/Sell Signal Functions and 5x Duplication ===

def advanced_buy_signal(features):
    """
    Returns True if all advanced buy conditions are met.
    """
    return (
        features.get("is_bullish_engulfing", 0)
        and features.get("trend_strength", 0) > 0.002
        and (features.get("is_london", 0) or features.get("is_ny", 0))
        and features.get("is_high_vol", 0)
        and features.get("rsi", 50) < 45
        and features.get("ema200_dist", 0) > 0
    )

def validate_sell_confirmation(df_m15, df_m5=None, entry_price=None, ema200_value=None):
    """
    Proper sell confirmation with all four criteria:
    ✔ Rejection wick (lower wick with rejection from support/resistance)
    ✔ Bearish close below the green line (EMA200)
    ✔ Lower high on M5/M15 (lower high than previous swing high)
    ✔ Momentum shift (not chop) - RSI divergence or strong directional move
    
    Returns: dict with confirmation status and details
    """
    if df_m15 is None or len(df_m15) < 5:
        return {'sell_confirmed': False, 'reason': 'Insufficient data'}
    
    last_candle = df_m15.iloc[-1]
    prev_candle = df_m15.iloc[-2]
    current_close = last_candle['close']
    current_high = last_candle['high']
    current_low = last_candle['low']
    current_open = last_candle['open']
    
    details = {}
    confirmations = []
    
    # === CRITERION 1: REJECTION WICK ===
    # Lower wick should exist and be significant (at least 0.5x the body)
    body_size = abs(current_close - current_open)
    lower_wick = current_open - current_low if current_open > current_low else current_close - current_low
    
    has_rejection_wick = False
    if body_size > 0 and lower_wick > 0:
        wick_ratio = lower_wick / body_size
        # Rejection wick: lower wick is at least 50% of body size
        has_rejection_wick = wick_ratio >= 0.5
        details['rejection_wick'] = {
            'has_wick': has_rejection_wick,
            'wick_size': lower_wick,
            'body_size': body_size,
            'ratio': wick_ratio
        }
    
    if has_rejection_wick:
        confirmations.append('✔ Rejection wick detected')
    
    # === CRITERION 2: BEARISH CLOSE BELOW GREEN LINE (EMA200) ===
    bearish_close_below_ema = False
    if ema200_value is not None:
        # Bearish close: current close is below EMA200
        bearish_close_below_ema = current_close < ema200_value
        details['ema200_check'] = {
            'current_close': current_close,
            'ema200': ema200_value,
            'below_ema': bearish_close_below_ema
        }
    else:
        # Calculate EMA200 if not provided
        if 'close' in df_m15.columns and len(df_m15) >= 200:
            ema200 = df_m15['close'].ewm(span=200, adjust=False).mean().iloc[-1]
            bearish_close_below_ema = current_close < ema200
            details['ema200_check'] = {
                'current_close': current_close,
                'ema200': ema200,
                'below_ema': bearish_close_below_ema
            }
    
    if bearish_close_below_ema:
        confirmations.append('✔ Bearish close below EMA200 (green line)')
    
    # === CRITERION 3: LOWER HIGH ON M5/M15 ===
    # Check for lower high pattern across last 3 candles
    lower_high_m15 = False
    if len(df_m15) >= 3:
        prev_high = df_m15.iloc[-2]['high']
        prev_prev_high = df_m15.iloc[-3]['high']
        
        # Lower high: current high < previous high, or previous high < prev-prev high
        lower_high_m15 = (current_high < prev_high) or (prev_high < prev_prev_high)
        details['lower_high_m15'] = {
            'current_high': current_high,
            'prev_high': prev_high,
            'prev_prev_high': prev_prev_high,
            'lower_high_detected': lower_high_m15
        }
    
    # Check M5 if provided
    lower_high_m5 = False
    if df_m5 is not None and len(df_m5) >= 3:
        m5_current_high = df_m5.iloc[-1]['high']
        m5_prev_high = df_m5.iloc[-2]['high']
        m5_prev_prev_high = df_m5.iloc[-3]['high']
        
        lower_high_m5 = (m5_current_high < m5_prev_high) or (m5_prev_high < m5_prev_prev_high)
        details['lower_high_m5'] = {
            'current_high': m5_current_high,
            'prev_high': m5_prev_high,
            'prev_prev_high': m5_prev_prev_high,
            'lower_high_detected': lower_high_m5
        }
    
    if lower_high_m15 or lower_high_m5:
        confirmations.append('✔ Lower high detected on M5/M15')
    
    # === CRITERION 4: MOMENTUM SHIFT (NOT CHOP) ===
    # Check for momentum shift using RSI divergence and directional strength
    momentum_shift = False
    
    if 'close' in df_m15.columns and len(df_m15) >= 15:
        # Calculate RSI
        def calculate_rsi(prices, period=14):
            deltas = prices.diff()
            seed = deltas[:period+1]
            up = seed[seed >= 0].sum() / period
            down = -seed[seed < 0].sum() / period
            rs = up / down if down != 0 else 0
            rsi = 100.0 - 100.0 / (1.0 + rs)
            return rsi
        
        closes = df_m15['close'].tail(15)
        if len(closes) >= 15:
            current_rsi = calculate_rsi(closes)
            prev_rsi = calculate_rsi(df_m15['close'].tail(16).head(15))
            
            # Momentum shift: RSI moving downward (above 50) or strong directional move
            strong_down_move = current_close < prev_candle['close']
            rsi_divergence = current_rsi < prev_rsi and current_rsi < 50
            
            momentum_shift = strong_down_move or rsi_divergence
            details['momentum_shift'] = {
                'current_rsi': current_rsi,
                'prev_rsi': prev_rsi,
                'rsi_divergence': rsi_divergence,
                'strong_down_move': strong_down_move,
                'momentum_shift': momentum_shift
            }
    
    if momentum_shift:
        confirmations.append('✔ Momentum shift detected (strong directional move)')
    
    # === FINAL VERDICT ===
    # All 4 criteria must be met for strong sell confirmation
    all_criteria_met = has_rejection_wick and bearish_close_below_ema and (lower_high_m15 or lower_high_m5) and momentum_shift
    
    return {
        'sell_confirmed': all_criteria_met,
        'rejection_wick': has_rejection_wick,
        'bearish_close_below_ema': bearish_close_below_ema,
        'lower_high': lower_high_m15 or lower_high_m5,
        'momentum_shift': momentum_shift,
        'confirmations': confirmations,
        'details': details,
        'criteria_met': len(confirmations)
    }

def advanced_sell_signal(features):
    """
    Returns True if all advanced sell conditions are met.
    """
    return (
        features.get("is_bearish_engulfing", 0)
        and features.get("trend_strength", 0) > 0.002
        and (features.get("is_london", 0) or features.get("is_ny", 0))
        and features.get("is_high_vol", 0)
        and features.get("rsi", 50) > 55
        and features.get("ema200_dist", 0) < 0
    )

