def gold_scalper_pro_signal(df, features):
    """
    Implements a simplified Gold Scalper Pro logic for XAUUSD.
    - Focuses on scalping small moves in the direction of short-term momentum and volatility.
    - Only runs on XAUUSD.
    """
    if "XAUUSD" not in df.get("symbol", ["XAUUSD"])[-1]:
        return None

    # Example logic (you can tune this to match Gold Scalper Pro more closely):
    # - Trade only during London/NY session
    # - Look for short-term momentum (e.g., last 3 closes up or down)
    # - Only trade if ATR is above a threshold (active market)
    # - Use tight SL/TP

    is_london = features.get("is_london", 0)
    is_ny = features.get("is_ny", 0)
    atr = features.get("atr", 0)
    close = df['close'].iloc[-1]
    closes = df['close'].iloc[-4:]
    momentum_up = all(closes.diff().iloc[1:] > 0)
    momentum_down = all(closes.diff().iloc[1:] < 0)

    if (is_london or is_ny) and atr > 1.0:
        if momentum_up:
            return "buy"
        if momentum_down:
            return "sell"
    return None

def gold_scalper_pro_trade(symbol, model, buffer_dict, bars=500):
    """
    Specialized trade function for Gold Scalper Pro logic on XAUUSD.
    """
    try:
        print(f"\n=== {symbol} (Gold Scalper Pro) ===")
        # Always ensure buffer is loaded and has enough bars
        if symbol not in buffer_dict or buffer_dict[symbol] is None or len(buffer_dict[symbol]) < bars:
            buffer_dict[symbol] = load_historical_buffer(symbol, bars=bars)
            if buffer_dict[symbol] is None or len(buffer_dict[symbol]) < bars:
                print(f"    [{symbol}] Buffer not ready or empty. Skipping trade.")
                print("=" * 40)
                return

        latest = get_price_data(symbol, bars=1)
        if latest is not None and not latest.empty:
            if buffer_dict[symbol]['time'].iloc[-1] != latest['time'].iloc[-1]:
                buffer_dict[symbol] = pd.concat([buffer_dict[symbol], latest]).iloc[-bars:].reset_index(drop=True)

        df = buffer_dict[symbol]
        if df is None or len(df) < bars:
            print(f"    [{symbol}] Buffer not ready or empty. Skipping trade.")
            print("=" * 40)
            return

        latest = get_price_data(symbol, bars=1)
        if latest is not None and not latest.empty:
            if buffer_dict[symbol]['time'].iloc[-1] != latest['time'].iloc[-1]:
                buffer_dict[symbol] = pd.concat([buffer_dict[symbol], latest]).iloc[-bars:].reset_index(drop=True)

        df = buffer_dict[symbol]
        if df is None or len(df) < bars:
            print(f"    [{symbol}] Buffer not ready.")
            print("=" * 40)
            return

        features = get_features_fixed(df)
        signal = gold_scalper_pro_signal(df, features)
        if signal not in ("buy", "sell"):
            print(f"    [{symbol}] Gold Scalper Pro gave no actionable direction. No trade.")
            print("=" * 40)
            return

        direction = signal  # FIX: Assign signal to direction
        entry = mt5.symbol_info_tick(symbol).ask if direction == "buy" else mt5.symbol_info_tick(symbol).bid

        # --- FIX: Ensure SL and TP are valid and not equal to or too close to entry ---
        # MetaTrader5 requires SL and TP to be at least a minimum distance from entry (stops_level)
        symbol_info = mt5.symbol_info(symbol)
        stops_level = symbol_info.stops_level * symbol_info.point if symbol_info else 0.0
        min_stop_distance = max(stops_level, 0.05)  # 0.05 is a safe fallback for gold

        atr = features.get("atr", 2.0)  # fallback to 2.0 if ATR not available
        sl_mult = 1.5  # SL = 2x ATR
        tp_mult = 3.0  # TP = 3x ATR (can tune this)
        sl_dist = max(atr * sl_mult, min_stop_distance)
        tp_dist = max(atr * tp_mult, min_stop_distance)
        if direction == "buy":
            sl = entry - sl_dist
            tp = entry + tp_dist
        else:
            sl = entry + sl_dist
            tp = entry - tp_dist

        # Ensure SL and TP are not equal to entry and are valid
        if abs(entry - sl) < min_stop_distance:
            sl = entry - min_stop_distance if direction == "buy" else entry + min_stop_distance
        if abs(tp - entry) < min_stop_distance:
            tp = entry + min_stop_distance if direction == "buy" else entry - min_stop_distance

        print(f"    [{symbol}] Entry: {entry:.2f} | SL: {sl:.2f} | TP: {tp:.2f} | MinStop: {min_stop_distance:.2f}")

        risk_ok, risk_reason = risk_management(symbol, direction, LOT_SIZE, sl, tp, entry)
        if not risk_ok:
            print(f"    [{symbol}] Risk management blocked trade: {risk_reason}")
            print("=" * 40)
            return

        # --- Lower lot size until it fits free margin ---
        symbol_info = mt5.symbol_info(symbol)
        if symbol_info is not None:
            min_lot = symbol_info.volume_min
            lot_step = symbol_info.volume_step
            # Defensive: round to 2 decimals for most brokers
            while not has_sufficient_balance(LOT_SIZE, symbol) and LOT_SIZE > min_lot:
                LOT_SIZE -= lot_step
                LOT_SIZE = round(LOT_SIZE, 2)
            if LOT_SIZE < min_lot or not has_sufficient_balance(LOT_SIZE, symbol):
                print(f"[{symbol}] Trade not placed: Not enough free margin even at minimum lot size.")
                return
        else:
            print(f"[{symbol}] Trade not placed: Could not get symbol info for lot size validation.")
            return

        result = place_trade_with_model_selection(symbol, direction, LOT_SIZE, sl, tp, strategy_votes="GoldScalperPro+ML", context={'symbol': symbol, 'signal': direction, 'price': sl+(tp-sl)/2})
        if hasattr(result, "retcode") and result.retcode == mt5.TRADE_RETCODE_DONE:
            print(f"    [{symbol}] Gold Scalper Pro/ML trade placed successfully")
            # --- Trailing stop management: update trailing stops after placing a trade ---
            update_trailing_stops_by_profit(symbol)
            update_trailing_stops(symbol, trailing_atr_mult=1.0)
            # --- Log trade result for performance tracking ---
            if 'performance_tracker' in globals():
                try:
                    trade_result = getattr(result, "profit", 0) if hasattr(result, "profit") else 0
                    performance_tracker.log_trade(symbol, "GoldScalperPro+ML", trade_result)
                except Exception as e:
                    print(f"[PERF TRACKER] Failed to log trade: {e}")
        else:
            print(f"    [{symbol}] Failed to place Gold Scalper Pro/ML trade")

        print("=" * 40)
        return
        
    except Exception as e:
        print(f"[ERROR] Exception in gold_scalper_pro_trade for {symbol}: {e}")
        import traceback
        traceback.print_exc()

def place_advanced_signal_trades(symbol, direction, lot, sl, tp, features):
    """
    Place 5 duplicate trades if all advanced signal conditions are met.
    Optimized for small lot sizes to allow multiple trade duplications.
    """
    # Check if advanced signal conditions are met
    if (direction == "buy" and advanced_buy_signal(features)) or (direction == "sell" and advanced_sell_signal(features)):
        # Always attempt to place 5 trades
        duplicates_placed = 0
        for i in range(5):
            # Check margin and balance before each trade
            if has_sufficient_balance(lot, symbol):
                place_trade_with_model_selection(symbol, direction, lot, sl, tp, context={'symbol': symbol, 'signal': direction, 'price': sl+(tp-sl)/2})
                duplicates_placed += 1
                print(f"    [{symbol}] {direction.upper()} DUPLICATE #{duplicates_placed} placed (all advanced conditions met)")
            else:
                print(f"    [{symbol}] Not enough margin to duplicate {direction.upper()} trade.")
                break

        if duplicates_placed == 0:
            print(f"    [{symbol}] No trades placed due to insufficient margin.")
    else:
        print(f"    [{symbol}] Advanced {direction.upper()} signal conditions not met. No trades placed.")




def update_trailing_stops_by_profit(symbol):
    """
    ✅ ELITE TRAILING STOP - BY PROFIT IN R UNITS
    
    Very important logic that fixes a LOT:
    - If profit >= 1R: move SL to breakeven
    - If profit >= 2R: trail SL to last swing low (for buys) or last swing high (for sells)
    
    This is a SIMPLER, more EFFECTIVE trailing stop than ATR-based approaches.
    Focuses on protecting PROFITS, not just distance.
    
    Args:
        symbol (str): The trading symbol to manage
    
    Returns:
        None
    """
    try:
        positions = safe_positions_get(symbol=symbol) if 'safe_positions_get' in globals() else (mt5.positions_get(symbol=symbol) if mt5 else None)
        if not positions or len(positions) == 0:
            return
        
        # Get current price data
        df = get_price_data(symbol, timeframe='M15', bars=100)
        if df is None or df.empty or len(df) < 30:
            return
        
        # Get current tick
        tick = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
        if not tick:
            return
        
        # Process each position
        for pos in positions:
            try:
                # --- CALCULATE PROFIT IN R UNITS ---
                entry_price = pos.price_open
                current_price = tick.bid if pos.type == mt5.ORDER_TYPE_BUY else tick.ask
                
                # ═══════════════════════════════════════════════════════════════════════════════
                # 🌪️ ENHANCEMENT C: VOLATILITY-ADAPTIVE EXIT ADJUSTMENTS
                # ═══════════════════════════════════════════════════════════════════════════════
                try:
                    direction = "buy" if pos.type == mt5.ORDER_TYPE_BUY else "sell"
                    initial_sl = pos.sl
                    initial_tp = pos.tp
                    profit_in_r = (abs(current_price - entry_price) / abs(entry_price - initial_sl)) if abs(entry_price - initial_sl) > 0 else 0
                    
                    # Call volatility-adaptive exit calculation
                    exit_adj = calculate_volatility_adaptive_exit(
                        df=df,
                        direction=direction,
                        entry_price=entry_price,
                        initial_sl=initial_sl,
                        initial_tp=initial_tp,
                        current_profit_r=profit_in_r
                    )
                    
                    if exit_adj:
                        vol_regime = exit_adj.get('volatility_regime', 'NORMAL')
                        rec_sl = exit_adj.get('recommended_sl')
                        rec_tp = exit_adj.get('recommended_tp')
                        reason = exit_adj.get('adjustment_reason', 'Standard')
                        
                        # Log volatility regime and adjustments
                        if rec_sl != initial_sl or rec_tp != initial_tp:
                            print(f"🌪️ [{symbol}] VOLATILITY-ADAPTIVE EXIT ({vol_regime}): {reason}")
                            print(f"   Current: SL={initial_sl:.5f}, TP={initial_tp:.5f}")
                            print(f"   Adjusted: SL={rec_sl:.5f}, TP={rec_tp:.5f}")
                except Exception as e:
                    print(f"[VOLATILITY EXIT ERROR] {symbol}: {e}")
                    pass
                sl_price = pos.sl if pos.sl else entry_price
                
                # Risk = distance from entry to SL
                risk = abs(entry_price - sl_price)
                
                if risk <= 0:
                    # No valid risk setup, skip
                    continue
                
                # Profit = unrealized profit in pips
                if pos.type == mt5.ORDER_TYPE_BUY:
                    profit = current_price - entry_price
                    direction = "BUY"
                else:
                    profit = entry_price - current_price
                    direction = "SELL"
                
                # Profit in R units = total profit / risk distance
                profit_r = profit / risk if risk > 0 else 0
                
                # --- STAGE 1: PROFIT >= 1R → MOVE SL TO BREAKEVEN ---
                if profit_r >= 1.0:
                    # Calculate breakeven SL (at entry price)
                    breakeven_sl = entry_price
                    
                    # For BUY: new SL should be >= breakeven
                    # For SELL: new SL should be <= breakeven
                    should_move_sl = False
                    
                    if pos.type == mt5.ORDER_TYPE_BUY:
                        # For BUY, only move SL UP (to breakeven)
                        if sl_price < breakeven_sl:
                            should_move_sl = True
                            new_sl = breakeven_sl
                    else:
                        # For SELL, only move SL DOWN (to breakeven)
                        if sl_price > breakeven_sl:
                            should_move_sl = True
                            new_sl = breakeven_sl
                    
                    if should_move_sl:
                        # Attempt to move SL to breakeven
                        modify_result = safe_order_modify(pos.ticket, entry_price, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, entry_price, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                        if modify_result:
                            print(f"    ✅ [{symbol}] PROFIT GATE 1R: {direction} #{pos.ticket} SL → BREAKEVEN ({new_sl:.5f}), Profit={profit_r:.2f}R")
                        else:
                            print(f"    ❌ [{symbol}] PROFIT GATE 1R: Failed to move {direction} #{pos.ticket} SL to breakeven")
                
                # --- STAGE 2: PROFIT >= 2R → TRAIL SL TO SWING LEVEL ---
                if profit_r >= 2.0:
                    # Find last swing low (for BUY) or swing high (for SELL)
                    lookback = 30
                    
                    if pos.type == mt5.ORDER_TYPE_BUY:
                        # For BUY: Trail to last swing low
                        swing_level = df['low'].iloc[-lookback:].min()
                        trail_buffer = 0.0010 if 'JPY' not in symbol else 0.01  # Small buffer below swing low
                        trail_sl = swing_level - trail_buffer
                        
                        # Only move SL UP, never down
                        if trail_sl > sl_price:
                            should_move = True
                        else:
                            should_move = False
                    else:
                        # For SELL: Trail to last swing high
                        swing_level = df['high'].iloc[-lookback:].max()
                        trail_buffer = 0.0010 if 'JPY' not in symbol else 0.01  # Small buffer above swing high
                        trail_sl = swing_level + trail_buffer
                        
                        # Only move SL DOWN, never up
                        if trail_sl < sl_price:
                            should_move = True
                        else:
                            should_move = False
                    
                    if should_move:
                        modify_result = safe_order_modify(pos.ticket, entry_price, trail_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, entry_price, trail_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                        if modify_result:
                            print(f"    ✅ [{symbol}] PROFIT GATE 2R: {direction} #{pos.ticket} SL → SWING ({trail_sl:.5f}), Profit={profit_r:.2f}R")
                        else:
                            print(f"    ❌ [{symbol}] PROFIT GATE 2R: Failed to trail {direction} #{pos.ticket} SL to swing level")
                
            except Exception as pos_error:
                print(f"    [ERROR] [{symbol}] Position {pos.ticket} trailing stop error: {pos_error}")
                continue
    
    except Exception as e:
        print(f"    [ERROR] [{symbol}] Trailing stop by profit error: {e}")


def close_partial_at_profit(symbol):
    """
    ✅ PARTIAL CLOSE SYSTEM - CLOSE 50% AT 1R, LET 50% RUN
    
    Elite money management:
    - Close 50% when profit = 1R (lock in gains)
    - Let remaining 50% run to 2R+ for bigger wins
    - Best of both worlds: secure profit + catch big trends
    
    Args:
        symbol (str): The trading symbol
    
    Returns:
        None (but modifies positions by closing 50% at 1R)
    """
    try:
        positions = safe_positions_get(symbol=symbol) if 'safe_positions_get' in globals() else (mt5.positions_get(symbol=symbol) if mt5 else None)
        if not positions or len(positions) == 0:
            return
        
        tick = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
        if not tick:
            return
        
        for pos in positions:
            try:
                entry_price = pos.price_open
                current_price = tick.bid if pos.type == mt5.ORDER_TYPE_BUY else tick.ask
                sl_price = pos.sl if pos.sl else entry_price
                
                risk = abs(entry_price - sl_price)
                if risk <= 0:
                    continue
                
                # Calculate profit in R
                if pos.type == mt5.ORDER_TYPE_BUY:
                    profit = current_price - entry_price
                    direction = "BUY"
                else:
                    profit = entry_price - current_price
                    direction = "SELL"
                
                profit_r = profit / risk if risk > 0 else 0
                
                # --- PARTIAL CLOSE: At 1.5R profit, close 30% (OPTIMIZED) ---
                # CHANGED from: Close 50% at 1R (too aggressive, missed trends)
                # NEW: Close 30% at 1.5R (lets winners run, still locks gains)
                if profit_r >= 1.5 and not getattr(pos, '_partial_closed_flag', False):
                    # Calculate 30% of position size (down from 50%)
                    close_volume = pos.volume * 0.30
                    
                    # Close 50% to lock in profit
                    if pos.type == mt5.ORDER_TYPE_BUY:
                        close_price = tick.bid
                        price_label = "BID"
                    else:
                        close_price = tick.ask
                        price_label = "ASK"
                    
                    # Create close order request
                    request = {
                        'action': mt5.TRADE_ACTION_DEAL,
                        'symbol': symbol,
                        'volume': close_volume,
                        'type': mt5.ORDER_TYPE_SELL if pos.type == mt5.ORDER_TYPE_BUY else mt5.ORDER_TYPE_BUY,
                        'position': pos.ticket,
                        'price': close_price,
                        'type_filling': mt5.ORDER_FILLING_RETURN,
                        'comment': f'Partial close 50% at {profit_r:.2f}R profit',
                    }
                    
                    # Send close request
                    result = mt5.order_send(request)
                    
                    if result and result.retcode == mt5.TRADE_RETCODE_DONE:
                        realized_profit = close_volume * (abs(close_price - entry_price) * 
                                                         (10000 if 'JPY' not in symbol else 100))
                        print(f"    ✅ [{symbol}] PARTIAL CLOSE 30% at {profit_r:.2f}R: {direction} closed {close_volume:.2f} lots @ {close_price:.5f} ({price_label}), PnL ~${realized_profit:.2f}")
                        
                        # Mark this position as having had partial close
                        pos._partial_closed_flag = True
                    else:
                        retcode = result.retcode if result else "No result"
                        print(f"    ❌ [{symbol}] PARTIAL CLOSE FAILED: {direction} #{pos.ticket} - Error: {retcode}")
                
            except Exception as pos_error:
                print(f"    [ERROR] [{symbol}] Partial close error for #{pos.ticket}: {pos_error}")
                continue
    
    except Exception as e:
        print(f"    [ERROR] [{symbol}] Partial close system error: {e}")


def detect_market_structure_exit(symbol, df=None):
    """
    ✅ MARKET STRUCTURE EXIT - SMART EXIT WHEN STRUCTURE FLIPS
    
    Exit logic:
    - For BUY trades: Exit on BEARISH BOS or CHoCH
    - For SELL trades: Exit on BULLISH BOS or CHoCH
    
    This prevents giving back profits when market structure changes.
    
    Args:
        symbol (str): The trading symbol
        df (pd.DataFrame): Optional price data (M15 by default)
    
    Returns:
        dict: {'should_exit': bool, 'reason': str, 'structure_type': str}
    """
    try:
        if df is None:
            df = get_price_data(symbol, timeframe='M15', bars=100)
        
        if df is None or df.empty or len(df) < 50:
            return {'should_exit': False, 'reason': 'Insufficient data', 'structure_type': None}
        
        # Get positions for this symbol
        positions = safe_positions_get(symbol=symbol) if 'safe_positions_get' in globals() else (mt5.positions_get(symbol=symbol) if mt5 else None)
        if not positions or len(positions) == 0:
            return {'should_exit': False, 'reason': 'No open positions', 'structure_type': None}
        
        pos = positions[0]  # Get first position
        direction = 'buy' if pos.type == mt5.ORDER_TYPE_BUY else 'sell'
        
        # --- DETECT STRUCTURE CHANGE ---
        lookback = 30
        
        if direction == 'buy':
            # BUY trade: Exit on BEARISH structure (lower high + lower low)
            recent_hh = df['high'].iloc[-lookback:].max()
            recent_ll = df['low'].iloc[-lookback:].min()
            
            prev_hh = df['high'].iloc[-lookback-5:-5].max() if len(df) > lookback + 5 else recent_hh
            prev_ll = df['low'].iloc[-lookback-5:-5].min() if len(df) > lookback + 5 else recent_ll
            
            # Check for Lower High (HH → LH = bearish BOS)
            current_high = df['high'].iloc[-1]
            if current_high < prev_hh:
                # Check if there's also a lower low (CHoCH = change of character)
                current_low = df['low'].iloc[-1]
                if current_low < prev_ll:
                    return {'should_exit': True, 'reason': 'BEARISH CHoCH (LH + LL)', 'structure_type': 'choch'}
                
                # Just LH (bearish BOS)
                return {'should_exit': True, 'reason': 'BEARISH BOS (Lower High)', 'structure_type': 'bos'}
        
        else:  # SELL trade
            # SELL trade: Exit on BULLISH structure (higher low + higher high)
            recent_hh = df['high'].iloc[-lookback:].max()
            recent_ll = df['low'].iloc[-lookback:].min()
            
            prev_hh = df['high'].iloc[-lookback-5:-5].max() if len(df) > lookback + 5 else recent_hh
            prev_ll = df['low'].iloc[-lookback-5:-5].min() if len(df) > lookback + 5 else recent_ll
            
            # Check for Higher Low (LL → HL = bullish BOS)
            current_low = df['low'].iloc[-1]
            if current_low > prev_ll:
                # Check if there's also a higher high (CHoCH = change of character)
                current_high = df['high'].iloc[-1]
                if current_high > prev_hh:
                    return {'should_exit': True, 'reason': 'BULLISH CHoCH (HL + HH)', 'structure_type': 'choch'}
                
                # Just HL (bullish BOS)
                return {'should_exit': True, 'reason': 'BULLISH BOS (Higher Low)', 'structure_type': 'bos'}
        
        return {'should_exit': False, 'reason': 'No structure flip detected', 'structure_type': None}
    
    except Exception as e:
        print(f"    [ERROR] [{symbol}] Structure exit detection error: {e}")
        return {'should_exit': False, 'reason': f'Error: {e}', 'structure_type': None}


def calculate_dynamic_tp(entry_price, direction, atr, min_rr=2.5, max_rr=5.0):
    """
    ✅ ATR-BASED DYNAMIC TP - ADAPT TO VOLATILITY
    
    Instead of fixed TP, use ATR:
    tp = entry + (ATR * 2.5) for normal markets
    
    Scales to:
    - Slow markets: uses ATR * 2.5 (tighter)
    - Fast markets: uses ATR * 3.5 (wider)
    
    Args:
        entry_price (float): Entry price
        direction (str): 'buy' or 'sell'
        atr (float): Current ATR value
        min_rr (float): Minimum RR ratio
        max_rr (float): Maximum RR ratio
    
    Returns:
        float: Adjusted TP price
    """
    try:
        # Default: ATR * 2.5 for balanced approach
        atr_multiplier = 2.5
        
        # The actual TP distance in pips
        tp_distance = atr * atr_multiplier
        
        if direction == 'buy':
            tp = entry_price + tp_distance
        else:  # sell
            tp = entry_price - tp_distance
        
        return tp
    
    except Exception as e:
        print(f"[ERROR] Dynamic TP calculation error: {e}")
        return None


def get_trend_strength(symbol, df=None):
    """
    ✅ TREND STRENGTH FILTER - HOLD OR EXIT
    
    Uses multiple indicators to determine trend strength:
    - EMA slope: Rate of change of EMA
    - ADX: Directional strength (>25 = strong, <20 = weak)
    - Momentum score: ML-based or price momentum
    - Structure: HH/HL pattern
    
    Returns strength score 0-100:
    - 80-100: VERY STRONG (HOLD runner)
    - 60-79: STRONG (HOLD position)
    - 40-59: MODERATE (TIGHT SL, consider exit)
    - 0-39: WEAK (EXIT or tight SL)
    
    Args:
        symbol (str): The trading symbol
        df (pd.DataFrame): Optional price data (uses M15 if None)
    
    Returns:
        dict: {
            'score': int (0-100),
            'strength': str ('VERY_STRONG'/'STRONG'/'MODERATE'/'WEAK'),
            'components': dict of individual scores,
            'recommendation': str
        }
    """
    try:
        if df is None:
            df = get_price_data(symbol, timeframe='M15', bars=100)
        
        if df is None or df.empty or len(df) < 50:
            return {
                'score': 50,
                'strength': 'UNKNOWN',
                'components': {'ema_slope': 0, 'adx': 50, 'momentum': 50, 'structure': 50},
                'recommendation': 'Insufficient data'
            }
        
        components = {}
        
        # --- EMA SLOPE SCORE (0-25 pts) ---
        try:
            ema_20 = df['close'].ewm(span=20).mean()
            ema_50 = df['close'].ewm(span=50).mean()
            
            # Slope = rate of change of EMA
            ema_20_slope = (ema_20.iloc[-1] - ema_20.iloc[-5]) / ema_20.iloc[-5]
            
            if abs(ema_20_slope) > 0.005:  # >0.5% change = strong
                ema_slope_score = 25
            elif abs(ema_20_slope) > 0.002:  # >0.2% = moderate
                ema_slope_score = 15
            elif abs(ema_20_slope) > 0.0:
                ema_slope_score = 8
            else:
                ema_slope_score = 0
            
            components['ema_slope'] = ema_slope_score
        except:
            components['ema_slope'] = 12
        
        # --- ADX SCORE (0-25 pts) ---
        try:
            # Simple ADX calculation: use +DI and -DI
            # Real ADX needs 14 periods, so we'll use simple momentum proxy
            high = df['high'].values
            low = df['low'].values
            close = df['close'].values
            
            # Approximate ADX using trend strength
            up_moves = sum(1 for i in range(1, len(high)) if close[i] > close[i-1])
            down_moves = sum(1 for i in range(1, len(low)) if close[i] < close[i-1])
            total_moves = up_moves + down_moves
            
            trend_ratio = max(up_moves, down_moves) / total_moves if total_moves > 0 else 0.5
            
            if trend_ratio > 0.70:  # Strong trend
                adx_score = 25
            elif trend_ratio > 0.60:  # Moderate
                adx_score = 15
            elif trend_ratio > 0.50:
                adx_score = 8
            else:
                adx_score = 0
            
            components['adx'] = adx_score
        except:
            components['adx'] = 12
        
        # --- MOMENTUM SCORE (0-25 pts) ---
        try:
            # Momentum = rate of price change
            price_momentum = (close[-1] - close[-5]) / close[-5]
            
            if abs(price_momentum) > 0.01:  # >1% change = strong
                momentum_score = 25
            elif abs(price_momentum) > 0.005:  # >0.5% = moderate
                momentum_score = 15
            elif abs(price_momentum) > 0.0:
                momentum_score = 8
            else:
                momentum_score = 0
            
            components['momentum'] = momentum_score
        except:
            components['momentum'] = 12
        
        # --- STRUCTURE SCORE (0-25 pts) ---
        try:
            # Check pattern quality: HH/HL for trend continuation
            lookback = 20
            recent_hh = df['high'].iloc[-lookback:].max()
            recent_ll = df['low'].iloc[-lookback:].min()
            
            prev_hh = df['high'].iloc[-lookback-5:-5].max() if len(df) > lookback + 5 else recent_hh
            prev_ll = df['low'].iloc[-lookback-5:-5].min() if len(df) > lookback + 5 else recent_ll
            
            if recent_hh > prev_hh and recent_ll > prev_ll:
                # Strong uptrend structure (HH & HL)
                structure_score = 25
            elif recent_hh < prev_hh and recent_ll < prev_ll:
                # Strong downtrend structure (LH & LL)
                structure_score = 25
            elif recent_hh > prev_hh or recent_ll > prev_ll:
                # Partial structure
                structure_score = 12
            else:
                structure_score = 0
            
            components['structure'] = structure_score
        except:
            components['structure'] = 12
        
        # --- CALCULATE OVERALL SCORE ---
        total_score = sum(components.values())
        
        if total_score >= 80:
            strength = 'VERY_STRONG'
            recommendation = '🟢 HOLD runner - Strong trend, let it run'
        elif total_score >= 60:
            strength = 'STRONG'
            recommendation = '🟢 HOLD position - Trend is established'
        elif total_score >= 40:
            strength = 'MODERATE'
            recommendation = '🟡 CAUTION - Tighten SL, consider partial exit'
        else:
            strength = 'WEAK'
            recommendation = '🔴 EXIT or TIGHT SL - Trend weakening'
        
        return {
            'score': total_score,
            'strength': strength,
            'components': components,
            'recommendation': recommendation
        }
    
    except Exception as e:
        print(f"    [ERROR] [{symbol}] Trend strength error: {e}")
        return {
            'score': 50,
            'strength': 'ERROR',
            'components': {'error': str(e)},
            'recommendation': 'Check trend strength calculation'
        }


def is_above_trendline_filter(symbol, direction, df=None, lookback=50):
    """
    ✅ FILTER #1: HTF TRENDLINE + BIAS CHECK (NON-NEGOTIABLE)
    
    🚨 ABSOLUTE HTF BIAS ENFORCEMENT:
    - For BUY: HTF MUST be BULLISH (no exceptions)
    - For SELL: HTF MUST be BEARISH (no exceptions)
    - Counter-trend entries are PERMANENTLY BLOCKED
    
    Args:
        symbol (str): The trading symbol
        direction (str): 'buy' or 'sell'
        df (pd.DataFrame): Optional HTF data (H4 or H1)
        lookback (int): Bars to use for trendline calculation
    
    Returns:
        dict: {
            'passed': bool,
            'reason': str,
            'price_position': str,
            'htf_bias': str
        }
    """
    try:
        if df is None:
            # Use H4 as HTF for trendline analysis
            df = get_price_data(symbol, timeframe='H4', bars=lookback)
        
        if df is None or df.empty or len(df) < 20:
            return {'passed': False, 'reason': 'Insufficient HTF data', 'price_position': None, 'htf_bias': None}
        
        current_price = df['close'].iloc[-1]
        
        # --- CALCULATE TRENDLINE (linear regression) ---
        import numpy as np
        x = np.arange(len(df))
        y = df['close'].values
        z = np.polyfit(x, y, 1)
        trendline = z[0] * (len(df) - 1) + z[1]  # Most recent trendline value
        
        # --- DETERMINE HTF BIAS ---
        ema_50 = df['close'].ewm(span=50).mean().iloc[-1]
        high_50 = df['high'].iloc[-50:].max()
        low_50 = df['low'].iloc[-50:].min()
        
        if ema_50 > low_50:
            htf_bias = 'BULLISH'
        else:
            htf_bias = 'BEARISH'
        
        # --- 🚨 ABSOLUTE HTF BIAS VETO (NON-NEGOTIABLE) ---
        if direction == 'buy' and htf_bias == 'BEARISH':
            # ❌ NEVER buy in bearish market - NO EXCEPTIONS
            return {
                'passed': False,
                'reason': f'❌ ABSOLUTE VETO: Cannot BUY when HTF is BEARISH - NO EXCEPTIONS',
                'price_position': f'${current_price:.5f}',
                'htf_bias': htf_bias
            }
        
        if direction == 'sell' and htf_bias == 'BULLISH':
            # ❌ NEVER sell in bullish market - NO EXCEPTIONS
            return {
                'passed': False,
                'reason': f'❌ ABSOLUTE VETO: Cannot SELL when HTF is BULLISH - NO EXCEPTIONS',
                'price_position': f'${current_price:.5f}',
                'htf_bias': htf_bias
            }
        
        # --- CHECK FILTER CONDITIONS ---
        if direction == 'buy':
            # For BUY: Need BULLISH bias + price above trendline
            if current_price > trendline:
                return {
                    'passed': True,
                    'reason': f'✅ BUY allowed: Price ABOVE trendline + HTF {htf_bias}',
                    'price_position': f'Above (${current_price:.5f} > ${trendline:.5f})',
                    'htf_bias': htf_bias
                }
            else:
                return {
                    'passed': False,
                    'reason': f'❌ BUY blocked: Price below trendline',
                    'price_position': f'Below (${current_price:.5f} < ${trendline:.5f})',
                    'htf_bias': htf_bias
                }
        
        else:  # SELL
            # For SELL: Need BEARISH bias + price below trendline
            if current_price < trendline:
                return {
                    'passed': True,
                    'reason': f'✅ SELL allowed: Price BELOW trendline + HTF {htf_bias}',
                    'price_position': f'Below (${current_price:.5f} < ${trendline:.5f})',
                    'htf_bias': htf_bias
                }
            else:
                return {
                    'passed': False,
                    'reason': f'❌ SELL blocked: Price above trendline',
                    'price_position': f'Above (${current_price:.5f} > ${trendline:.5f})',
                    'htf_bias': htf_bias
                }
    
    except Exception as e:
        return {'passed': False, 'reason': f'Trendline filter error: {e}', 'price_position': None, 'htf_bias': None}


def is_impulsive_move_confirmed(symbol, direction, df=None, lookback=20):
    """
    ✅ FILTER #2: IMPULSIVE MOVE DETECTION
    
    Requires a STRONG directional move BEFORE entry pullback.
    
    Example: For BUY pullback entries, require first a strong UP impulsive move.
    This prevents buying random pullbacks without prior momentum.
    
    Logic:
    - Calculate 5-bar average candle size (impulsive moves are BIG candles)
    - For BUY: Require >1.5x average candle size UP move recently
    - For SELL: Require >1.5x average candle size DOWN move recently
    
    Args:
        symbol (str): The trading symbol
        direction (str): 'buy' or 'sell'
        df (pd.DataFrame): Optional M5/M15 data
        lookback (int): Bars to check for impulsive move
    
    Returns:
        dict: {
            'passed': bool,
            'reason': str,
            'impulsive_strength': float,
            'avg_candle_size': float
        }
    """
    try:
        if df is None:
            df = get_price_data(symbol, timeframe='M5', bars=50)
        
        if df is None or df.empty or len(df) < 25:
            return {'passed': False, 'reason': 'Insufficient data', 'impulsive_strength': 0, 'avg_candle_size': 0}
        
        # --- CALCULATE CANDLE SIZES ---
        # Candle size = abs(close - open)
        candle_sizes = abs(df['close'] - df['open'])
        avg_candle_size = candle_sizes.iloc[-20:].mean()
        
        pip_size = 0.01 if 'JPY' in symbol else 0.0001
        
        if direction == 'buy':
            # For BUY: Look for strong UP move in recent bars
            # Impulsive move = bars closing higher than open (bullish) with >1.5x average size
            recent_range = df['close'].iloc[-lookback:].max() - df['low'].iloc[-lookback:].min()
            avg_up_move = (df['close'] - df['open']).iloc[-lookback:].mean()
            
            impulsive_strength = avg_up_move / avg_candle_size if avg_candle_size > 0 else 0
            
            if impulsive_strength >= 1.5:
                return {
                    'passed': True,
                    'reason': f'✅ IMPULSIVE BUY move detected: {impulsive_strength:.2f}x average candle size',
                    'impulsive_strength': impulsive_strength,
                    'avg_candle_size': avg_candle_size
                }
            else:
                return {
                    'passed': False,
                    'reason': f'❌ No impulsive BUY move: Only {impulsive_strength:.2f}x (need 1.5x+)',
                    'impulsive_strength': impulsive_strength,
                    'avg_candle_size': avg_candle_size
                }
        
        else:  # SELL
            # For SELL: Look for strong DOWN move
            recent_range = df['high'].iloc[-lookback:].max() - df['close'].iloc[-lookback:].min()
            avg_down_move = (df['open'] - df['close']).iloc[-lookback:].mean()
            
            impulsive_strength = abs(avg_down_move) / avg_candle_size if avg_candle_size > 0 else 0
            
            if impulsive_strength >= 1.5:
                return {
                    'passed': True,
                    'reason': f'✅ IMPULSIVE SELL move detected: {impulsive_strength:.2f}x average candle size',
                    'impulsive_strength': impulsive_strength,
                    'avg_candle_size': avg_candle_size
                }
            else:
                return {
                    'passed': False,
                    'reason': f'❌ No impulsive SELL move: Only {impulsive_strength:.2f}x (need 1.5x+)',
                    'impulsive_strength': impulsive_strength,
                    'avg_candle_size': avg_candle_size
                }
    
    except Exception as e:
        return {'passed': False, 'reason': f'Impulsive move error: {e}', 'impulsive_strength': 0, 'avg_candle_size': 0}


def universal_liquidity_sweep(df, direction, lookback=30):
    """
    🚨 UNIVERSAL LIQUIDITY SWEEP DETECTOR - UPGRADED SYSTEM
    
    Next-gen sweep detection that validates BOTH:
    1. TRIGGERED: Sweep actually occurred (wick touched extreme)
    2. RECLAIMED: Price recovered from sweep (showing strong hands rebought/resold)
    
    Weak wicks that don't get reclaimed = fake sweeps, don't trade.
    
    Returns:
        dict: {
            'triggered': bool,      # Did sweep occur?
            'reclaimed': bool,       # Did price reclaim from sweep?
            'sweep_level': float,    # Where sweep happened
            'reclaim_level': float,  # Where price returned to
            'strength': float        # 0-100 score (how strong reclaim)
        }
    """
    try:
        if df is None or df.empty or len(df) < lookback + 5:
            return {
                'triggered': False,
                'reclaimed': False,
                'sweep_level': None,
                'reclaim_level': None,
                'strength': 0
            }
        
        # Get recent range
        recent_high = df['high'].iloc[-lookback:].max()
        recent_low = df['low'].iloc[-lookback:].min()
        mid_point = (recent_low + recent_high) / 2
        
        # Check if sweep occurred
        if direction == 'buy':
            # For BUY: Need wick BELOW half of range
            sweep_level = min(df['low'].iloc[-lookback:])  # Lowest point touched
            triggered = sweep_level < mid_point - 0.0005  # Swept significantly below mid
            
            if triggered:
                # Check if price RECLAIMED above the sweep
                # Look at last 3-5 candles to see if price recovered
                recent_close = df['close'].iloc[-1]
                recent_closes = df['close'].iloc[-5:].mean()
                
                # Reclaim = closed ABOVE sweep level (strong recovery)
                reclaimed = recent_close > sweep_level + 0.0010  # At least 10 pips above sweep
                
                # Strength score: how far recovered
                if reclaimed:
                    recovery_range = recent_close - sweep_level
                    total_range = recent_high - recent_low
                    strength = min(100, (recovery_range / total_range * 100)) if total_range > 0 else 0
                else:
                    strength = 0
                
                return {
                    'triggered': triggered,
                    'reclaimed': reclaimed,
                    'sweep_level': sweep_level,
                    'reclaim_level': recent_close,
                    'strength': strength
                }
            else:
                return {
                    'triggered': False,
                    'reclaimed': False,
                    'sweep_level': sweep_level,
                    'reclaim_level': None,
                    'strength': 0
                }
        
        else:  # SELL
            # For SELL: Need wick ABOVE half of range
            sweep_level = max(df['high'].iloc[-lookback:])  # Highest point touched
            triggered = sweep_level > mid_point + 0.0005  # Swept significantly above mid
            
            if triggered:
                # Check if price RECLAIMED below the sweep
                recent_close = df['close'].iloc[-1]
                recent_closes = df['close'].iloc[-5:].mean()
                
                # Reclaim = closed BELOW sweep level (strong reversal)
                reclaimed = recent_close < sweep_level - 0.0010  # At least 10 pips below sweep
                
                # Strength score: how far recovered
                if reclaimed:
                    recovery_range = sweep_level - recent_close
                    total_range = recent_high - recent_low
                    strength = min(100, (recovery_range / total_range * 100)) if total_range > 0 else 0
                else:
                    strength = 0
                
                return {
                    'triggered': triggered,
                    'reclaimed': reclaimed,
                    'sweep_level': sweep_level,
                    'reclaim_level': recent_close,
                    'strength': strength
                }
            else:
                return {
                    'triggered': False,
                    'reclaimed': False,
                    'sweep_level': sweep_level,
                    'reclaim_level': None,
                    'strength': 0
                }
    
    except Exception as e:
        return {'triggered': False, 'reclaimed': False, 'sweep_level': None, 'reclaim_level': None, 'strength': 0}


def is_liquidity_sweep_present(symbol, direction, df=None, lookback=30):
    """
    ✅ FILTER #3: LIQUIDITY SWEEP / STOP HUNT DETECTION (UPGRADED)
    
    🚨 NOW USES UNIVERSAL_LIQUIDITY_SWEEP - REQUIRES BOTH:
    1. Sweep triggered (wick touched extreme)
    2. Price reclaimed (showing strong conviction)
    
    Elite traders know: Random wicks without reclaim = FAKES
    Only trade sweeps where strong hands rebought/resold.
    
    Args:
        symbol (str): The trading symbol
        direction (str): 'buy' or 'sell'
        df (pd.DataFrame): Optional price data
        lookback (int): Bars to check for sweep
    
    Returns:
        dict: {
            'passed': bool,
            'reason': str,
            'sweep_detected': bool,
            'sweep_level': float,
            'sweep_reclaimed': bool,  ← NEW: For Filter 9 quality score
            'sweep_strength': float   ← NEW: For Filter 9 quality score
        }
    """
    try:
        if df is None:
            df = get_price_data(symbol, timeframe='M15', bars=lookback)
        
        if df is None or df.empty or len(df) < 15:
            return {
                'passed': False,
                'reason': 'Insufficient data',
                'sweep_detected': False,
                'sweep_level': None,
                'sweep_reclaimed': False,
                'sweep_strength': 0
            }
        
        # Use upgraded sweep detection
        sweep_result = universal_liquidity_sweep(df, direction, lookback)
        
        if not sweep_result['triggered']:
            reason = f'❌ No sweep triggered (no extreme wick)'
            return {
                'passed': False,
                'reason': reason,
                'sweep_detected': False,
                'sweep_level': None,
                'sweep_reclaimed': False,
                'sweep_strength': 0
            }
        
        if not sweep_result['reclaimed']:
            reason = f'❌ Sweep triggered but NOT reclaimed (weak, likely fake) - Level: ${sweep_result["sweep_level"]:.5f}'
            return {
                'passed': False,
                'reason': reason,
                'sweep_detected': False,
                'sweep_level': sweep_result['sweep_level'],
                'sweep_reclaimed': False,
                'sweep_strength': 0
            }
        
        # ✅ Both conditions met: sweep triggered AND reclaimed
        direction_text = 'BUY' if direction == 'buy' else 'SELL'
        reason = f'✅ {direction_text} sweep CONFIRMED: Triggered at ${sweep_result["sweep_level"]:.5f} + Reclaimed to ${sweep_result["reclaim_level"]:.5f} (Strength: {sweep_result["strength"]:.0f}%)'
        return {
            'passed': True,
            'reason': reason,
            'sweep_detected': True,
            'sweep_level': sweep_result['sweep_level'],
            'sweep_reclaimed': True,
            'sweep_strength': sweep_result['strength']
        }
    
    except Exception as e:
        return {'passed': False, 'reason': f'Sweep detection error: {e}', 'sweep_detected': False, 'sweep_level': None}


def is_multi_tf_aligned(symbol, direction, df_m15=None, df_m5=None):
    """
    ✅ FILTER #4: M15 + M5 MULTI-TIMEFRAME ALIGNMENT
    
    Requires BOTH M15 and M5 to agree on direction.
    
    This is the most important filter:
    - Prevents trading weakM5 signals (random noise)
    - Waits for M15 confirmation
    - Only trades when BOTH timeframes agree
    
    Logic:
    - M15: Medium-term trend (more reliable)
    - M5: Entry confirmation (precise timing)
    - BOTH must point same direction
    
    Args:
        symbol (str): The trading symbol
        direction (str): 'buy' or 'sell'
        df_m15 (pd.DataFrame): Optional M15 data
        df_m5 (pd.DataFrame): Optional M5 data
    
    Returns:
        dict: {
            'passed': bool,
            'reason': str,
            'm15_signal': str,
            'm5_signal': str,
            'agreement': bool
        }
    """
    try:
        if df_m15 is None:
            df_m15 = get_price_data(symbol, timeframe='M15', bars=50)
        if df_m5 is None:
            df_m5 = get_price_data(symbol, timeframe='M5', bars=50)
        
        if (df_m15 is None or df_m15.empty or len(df_m15) < 20 or 
            df_m5 is None or df_m5.empty or len(df_m5) < 20):
            return {'passed': False, 'reason': 'Insufficient multi-TF data', 'm15_signal': None, 'm5_signal': None, 'agreement': False}
        
        # --- DETERMINE M15 SIGNAL ---
        m15_ema_20 = df_m15['close'].ewm(span=20).mean().iloc[-1]
        m15_ema_50 = df_m15['close'].ewm(span=50).mean().iloc[-1]
        m15_close = df_m15['close'].iloc[-1]
        m15_high = df_m15['high'].iloc[-20:].max()
        m15_low = df_m15['low'].iloc[-20:].min()
        
        if m15_close > m15_ema_20 and m15_ema_20 > m15_ema_50:
            m15_signal = 'buy'
        elif m15_close < m15_ema_20 and m15_ema_20 < m15_ema_50:
            m15_signal = 'sell'
        else:
            m15_signal = 'neutral'
        
        # --- DETERMINE M5 SIGNAL ---
        m5_ema_20 = df_m5['close'].ewm(span=20).mean().iloc[-1]
        m5_ema_9 = df_m5['close'].ewm(span=9).mean().iloc[-1]
        m5_close = df_m5['close'].iloc[-1]
        m5_high = df_m5['high'].iloc[-20:].max()
        m5_low = df_m5['low'].iloc[-20:].min()
        
        if m5_close > m5_ema_9:
            m5_signal = 'buy'
        elif m5_close < m5_ema_9:
            m5_signal = 'sell'
        else:
            m5_signal = 'neutral'
        
        # --- CHECK AGREEMENT ---
        agreement = (m15_signal == m5_signal) and (m15_signal == direction)
        
        if agreement:
            return {
                'passed': True,
                'reason': f'✅ M15+M5 ALIGNED: Both {direction.upper()} - Confluence entry',
                'm15_signal': m15_signal,
                'm5_signal': m5_signal,
                'agreement': True
            }
        else:
            disagreement_msg = ""
            if m15_signal != direction:
                disagreement_msg += f"M15={m15_signal} | "
            if m5_signal != direction:
                disagreement_msg += f"M5={m5_signal}"
            
            return {
                'passed': False,
                'reason': f'❌ M15+M5 MISMATCH: {disagreement_msg}',
                'm15_signal': m15_signal,
                'm5_signal': m5_signal,
                'agreement': False
            }
    
    except Exception as e:
        return {'passed': False, 'reason': f'Multi-TF alignment error: {e}', 'm15_signal': None, 'm5_signal': None, 'agreement': False}


def check_displacement(df, direction):
    """
    ✅ FILTER #6: DISPLACEMENT REQUIREMENT (STRONG CANDLE BODIES)
    
    🚨 This alone eliminates A LOT of bad trades!
    
    Requirement: Candle body must be >= 60% of total candle range
    
    If candle is mostly wick (doji/hammer): it's weak, don't trade
    If candle is strong body: it shows conviction, trade it
    
    Args:
        df (pd.DataFrame): Price data
        direction (str): 'buy' or 'sell'
    
    Returns:
        dict: {'passed': bool, 'reason': str, 'displacement': float}
    """
    try:
        if df is None or df.empty or len(df) < 5:
            return {'passed': False, 'reason': 'Insufficient data', 'displacement': 0}
        
        # Last 5 candles - check they have strong bodies
        recent = df.iloc[-5:]
        
        for idx, row in recent.iterrows():
            candle_range = row['high'] - row['low']
            body = abs(row['close'] - row['open'])
            
            if candle_range == 0:
                continue
            
            body_ratio = body / candle_range
            
            # Body must be at least 60% of range (not mostly wicks)
            if body_ratio < 0.60:
                return {
                    'passed': False,
                    'reason': f'❌ WEAK CANDLE: Body only {body_ratio*100:.0f}% of range (need 60%+) - Doji/Hammer detected',
                    'displacement': body_ratio
                }
        
        # All recent candles have strong bodies
        avg_displacement = recent[['high', 'low', 'close', 'open']].apply(
            lambda row: abs(row['close'] - row['open']) / (row['high'] - row['low']) if row['high'] != row['low'] else 0,
            axis=1
        ).mean()
        
        return {
            'passed': True,
            'reason': f'✅ STRONG DISPLACEMENT: {avg_displacement*100:.0f}% average body ratio',
            'displacement': avg_displacement
        }
    
    except Exception as e:
        return {'passed': False, 'reason': f'Displacement check error: {e}', 'displacement': 0}


def check_consolidation(df, symbol):
    """
    ✅ FILTER #7: BLOCK CONSOLIDATION TRADES (AVOIDS RANGE-BOUND ENTRIES)
    
    🚨 THIS FIXES SCREENSHOT ISSUES - Trades in tight range get whipped
    
    If recent 20-bar range < 2x ATR: Market is CONSOLIDATING, DON'T TRADE
    
    Args:
        df (pd.DataFrame): Price data
        symbol (str): Trading symbol
    
    Returns:
        dict: {'passed': bool, 'reason': str, 'range_size': float}
    """
    try:
        if df is None or df.empty or len(df) < 25:
            return {'passed': False, 'reason': 'Insufficient data', 'range_size': 0}
        
        # Calculate recent range
        recent_high = df['high'].tail(20).max()
        recent_low = df['low'].tail(20).min()
        range_size = recent_high - recent_low
        
        # Calculate ATR
        atr_values = []
        for i in range(len(df) - 14, len(df)):
            tr = max(
                df['high'].iloc[i] - df['low'].iloc[i],
                abs(df['high'].iloc[i] - df['close'].iloc[i-1]),
                abs(df['low'].iloc[i] - df['close'].iloc[i-1])
            )
            atr_values.append(tr)
        
        atr = sum(atr_values) / len(atr_values) if atr_values else 0.0001
        
        # Check if consolidating
        if range_size < atr * 2:
            return {
                'passed': False,
                'reason': f'❌ CONSOLIDATION DETECTED: Range {range_size:.5f} < 2x ATR ({atr*2:.5f}) - Market is TIGHT, NO TRADE',
                'range_size': range_size
            }
        
        return {
            'passed': True,
            'reason': f'✅ NO CONSOLIDATION: Range {range_size:.5f} > 2x ATR ({atr*2:.5f}) - Market has momentum',
            'range_size': range_size
        }
    
    except Exception as e:
        return {'passed': False, 'reason': f'Consolidation check error: {e}', 'range_size': 0}


def check_liquidity_sequence(sweep_detected, bos_detected):
    """
    ✅ FILTER #8: ENFORCE LIQUIDITY SEQUENCE (SWEEP BEFORE BOS)
    
    🚨 PRO-LEVEL: Order matters!
    
    Real setup: 
    1. Market sweeps stops (liquidity hunt)
    2. Strong hands accumulate
    3. THEN market breaks structure (BOS)
    
    Fake setup:
    1. BOS happens randomly
    2. Then someone gets liquidated (sweep)
    3. Dead cat bounce = STOP OUT
    
    Args:
        sweep_detected (bool): Was liquidity sweep detected?
        bos_detected (bool): Was BOS detected?
    
    Returns:
        dict: {'passed': bool, 'reason': str}
    """
    try:
        # If sweep NOT detected but BOS is: WRONG ORDER
        if bos_detected and not sweep_detected:
            return {
                'passed': False,
                'reason': '❌ WRONG SEQUENCE: BOS without liquidity sweep - Likely fake breakout',
            }
        
        # If BOTH detected: Good - sweep happened, then structure broke
        if sweep_detected and bos_detected:
            return {
                'passed': True,
                'reason': '✅ CORRECT SEQUENCE: Liquidity swept first, then BOS - Institutional move',
            }
        
        # If neither: Skip
        if not sweep_detected and not bos_detected:
            return {
                'passed': False,
                'reason': '❌ Neither sweep nor BOS detected',
            }
        
        # If sweep only (no BOS): Need BOS
        return {
            'passed': False,
            'reason': '❌ Sweep detected but NO BOS - Not enough confluence',
        }
    
    except Exception as e:
        return {'passed': False, 'reason': f'Sequence check error: {e}'}


def calculate_entry_quality_score(bos_strength, sweep_reclaimed, displacement, htf_bias, 
                                   m15_aligned, m5_aligned, rr_ratio, bos_detected):
    """
    ✅ FILTER #9: ELITE ENTRY QUALITY SCORE (0-10 SCALE)
    
    🚨 THIS IS PROFESSIONAL-GRADE - Instead of yes/no, score every setup!
    
    Score Components:
    - BOS Strength: 0-2 pts (0=none, 1=weak, 2=strong 70+)
    - Sweep Reclaimed: 0-2 pts (0=no, 2=yes reclaimed)
    - Displacement: 0-2 pts (0=weak <60%, 2=strong)
    - HTF Aligned: 0-2 pts (0=no, 2=yes + bullish/bearish)
    - RR Ratio: 0-2 pts (0=<1.5, 1=1.5-2.0, 2=2.0+)
    
    MINIMUM SCORE: 7/10 to enter (A-grade only)
    
    Args:
        bos_strength (float): 0-100 BOS strength
        sweep_reclaimed (bool): Did sweep get reclaimed?
        displacement (float): 0-1 body ratio
        htf_bias (bool): Is HTF aligned with direction?
        m15_aligned (bool): Is M15 aligned?
        m5_aligned (bool): Is M5 aligned?
        rr_ratio (float): Risk/reward ratio
        bos_detected (bool): Was BOS detected?
    
    Returns:
        dict: {'score': float, 'breakdown': dict, 'grade': str}
    """
    try:
        score = 0
        breakdown = {}
        
        # Component 1: BOS Strength (0-2)
        if bos_detected and bos_strength >= 70:
            bos_score = 2 if bos_strength >= 80 else 1.5
            breakdown['bos'] = {'score': bos_score, 'reason': f'Strong BOS ({bos_strength:.0f})'}
            score += bos_score
        else:
            breakdown['bos'] = {'score': 0, 'reason': f'BOS missing or weak (<70)'}
        
        # Component 2: Sweep Reclaim (0-2)
        if sweep_reclaimed:
            breakdown['sweep'] = {'score': 2, 'reason': 'Sweep reclaimed + confirmed'}
            score += 2
        else:
            breakdown['sweep'] = {'score': 0, 'reason': 'No sweep or not reclaimed'}
        
        # Component 3: Displacement (0-2)
        if displacement >= 0.70:
            displacement_score = 2
        elif displacement >= 0.60:
            displacement_score = 1.5
        else:
            displacement_score = 0
        breakdown['displacement'] = {'score': displacement_score, 'reason': f'Body ratio {displacement*100:.0f}%'}
        score += displacement_score
        
        # Component 4: HTF Bias (0-2)
        if htf_bias:
            breakdown['htf'] = {'score': 2, 'reason': 'HTF aligned + confirmed'}
            score += 2
        else:
            breakdown['htf'] = {'score': 0, 'reason': 'HTF not aligned'}
        
        # Component 5: RR Ratio (0-2)
        if rr_ratio >= 2.5:
            rr_score = 2
        elif rr_ratio >= 2.0:
            rr_score = 1.5
        elif rr_ratio >= 1.5:
            rr_score = 1
        else:
            rr_score = 0
        breakdown['rr'] = {'score': rr_score, 'reason': f'RR ratio {rr_ratio:.2f}:1'}
        score += rr_score
        
        # Determine grade
        if score >= 9:
            grade = '🟢 ELITE (9+) - Perfect setup'
        elif score >= 8:
            grade = '🟢 A-GRADE (8+) - Excellent entry'
        elif score >= 7:
            grade = '🟡 B-GRADE (7+) - Good entry'
        else:
            grade = '🔴 FAIL (<7) - Insufficient quality'
        
        return {
            'score': score,
            'grade': grade,
            'breakdown': breakdown,
            'passed': score >= 7
        }
    
    except Exception as e:
        return {'score': 0, 'grade': f'ERROR: {e}', 'breakdown': {}, 'passed': False}


def update_trailing_stops(symbol, trailing_atr_mult=1.0):
    """
    Updates the stop loss for all open trades on the given symbol using a trailing stop strategy.

    If the price moves in favor of the trade by more than trailing_atr_mult * ATR, the stop loss is moved to maintain the trailing distance.
    This function should be called after each new trade and periodically in the main loop to manage open trades.

    Args:
        symbol (str): The trading symbol to update trailing stops for.
        trailing_atr_mult (float): The ATR multiple to use for the trailing stop distance.

    Returns:
        None
    """
    positions = safe_positions_get(symbol=symbol) if 'safe_positions_get' in globals() else (mt5.positions_get(symbol=symbol) if mt5 else None)
    if not positions:
        return
    df = get_price_data(symbol)
    if df is None or df.empty:
        return
    atr = calculate_atr(df)
    tick = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
    if not tick:
        return
    for pos in positions:
        if pos.type == mt5.ORDER_TYPE_BUY:
            new_sl = tick.bid - atr * trailing_atr_mult
            if (pos.sl is None or new_sl > pos.sl) and new_sl < tick.bid:
                modify_result = safe_order_modify(pos.ticket, pos.price_open, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, pos.price_open, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                if modify_result:
                    print(f"    [{symbol}] Trailing stop updated for BUY position {pos.ticket}: SL moved to {new_sl:.5f}")
        elif pos.type == mt5.ORDER_TYPE_SELL:
            new_sl = tick.ask + atr * trailing_atr_mult
            if (pos.sl is None or new_sl < pos.sl) and new_sl > tick.ask:
                modify_result = safe_order_modify(pos.ticket, pos.price_open, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, pos.price_open, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                if modify_result:
                    print(f"    [{symbol}] Trailing stop updated for SELL position {pos.ticket}: SL moved to {new_sl:.5f}")


def update_trailing_stops_three_stage(symbol):
    """
    Updates trailing stops using the THREE-STAGE TRAILING SYSTEM with RETRY + VERIFICATION.
    
    This implements:
    - Stage 1: Break-Even+ activation at +1.2R from entry
    - Stage 2: Structure-based trailing to swing highs/lows
    - Stage 3: Aggressive liquidity-protective trailing at 70% distance to TP
    
    Automatically detects volatility regime (QUIET/NORMAL/WILD) per symbol.
    
    ENHANCEMENTS:
    - Retry logic: Up to 3 attempts if SL modification fails
    - Verification: Confirms SL was actually moved on broker
    - Safe fallback: Only moves SL if conditions are valid
    
    Args:
        symbol (str): The trading symbol to manage
    
    Returns:
        None
    """
    try:
        import MetaTrader5 as mt5
        
        positions = safe_positions_get(symbol=symbol) if 'safe_positions_get' in globals() else (mt5.positions_get(symbol=symbol) if mt5 else None)
        if not positions:
            return
        
        df_m15 = get_price_data(symbol, timeframe='M15', bars=100)
        df_m5 = get_price_data(symbol, timeframe='M5', bars=100)
        if df_m15 is None or df_m15.empty or df_m5 is None or df_m5.empty:
            return
        
        tick = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
        if not tick:
            return
        
        atr = calculate_atr(df_m15)
        spread = tick.ask - tick.bid
        
        # Detect volatility regime for this symbol
        atr_percentiles = get_atr_percentiles(symbol) if 'get_atr_percentiles' in globals() else {'p25': atr * 0.7, 'p75': atr * 1.3}
        if atr < atr_percentiles.get('p25', atr * 0.7):
            regime = 'QUIET'
        elif atr < atr_percentiles.get('p75', atr * 1.3):
            regime = 'NORMAL'
        else:
            regime = 'WILD'
        
        # Update each position with ELITE three-phase trailing
        for pos in positions:
            direction = 'buy' if pos.type == mt5.ORDER_TYPE_BUY else 'sell'
            current_price = tick.bid if direction == 'buy' else tick.ask
            
            # Calculate unrealized R
            risk = abs(pos.price_open - pos.sl)
            if direction == 'buy':
                profit = current_price - pos.price_open
            else:
                profit = pos.price_open - current_price
            unrealized_r = profit / risk if risk > 0 else 0
            
            # Initialize phase tracking if first time
            if pos.ticket not in POSITION_PHASE_TRACKING:
                POSITION_PHASE_TRACKING[pos.ticket] = {
                    'phase': 'PROTECTION',
                    'entry_r': 0,
                    'partial_closed': False,
                    'direction': direction,
                    'entry': pos.price_open
                }
                POSITION_TRAILING_STATS[pos.ticket] = {
                    'entry': pos.price_open,
                    'direction': direction,
                    'reason_list': []
                }
            
            # Create or retrieve elite trailing system for this position
            if pos.ticket not in POSITION_TRAILING_SYSTEMS:
                system = ThreeStageTrailingSystem(
                    entry=pos.price_open,
                    tp=pos.tp,
                    atr=atr,
                    spread=spread,
                    symbol=symbol,
                    regime=regime,
                    sl=pos.sl
                )
                POSITION_TRAILING_SYSTEMS[pos.ticket] = system
            else:
                system = POSITION_TRAILING_SYSTEMS[pos.ticket]
            
            # Get new SL from ELITE engine (includes partial close signal)
            try:
                new_sl, phase, reason, should_partial = system.update(
                    current_price=current_price,
                    current_sl=pos.sl,
                    df_m15=df_m15,
                    df_m5=df_m5,
                    direction=direction,
                    unrealized_r=unrealized_r,
                    displacement_confirmed=False,  # Could integrate from market state
                    second_bos=False,  # Could integrate from order block logic
                    ml_confidence=0.65  # Could pull from actual ML scores
                )
                
                # Update phase tracking
                POSITION_PHASE_TRACKING[pos.ticket]['phase'] = phase
                POSITION_PHASE_TRACKING[pos.ticket]['entry_r'] = unrealized_r
                POSITION_TRAILING_STATS[pos.ticket]['reason_list'].append(f"{phase}: {reason}")
                
                # 🔥 ELITE FEATURE: Handle partial close at 1R (40% close)
                if should_partial and not POSITION_PHASE_TRACKING[pos.ticket]['partial_closed']:
                    partial_volume = pos.volume * 0.4
                    try:
                        close_result = safe_order_close(pos.ticket, partial_volume) if 'safe_order_close' in globals() else mt5.Close(pos.ticket)
                        if close_result:
                            POSITION_PHASE_TRACKING[pos.ticket]['partial_closed'] = True
                            print(f"[🔥 PARTIAL CLOSE] {symbol} {direction.upper()} {pos.ticket} | 40% close at {unrealized_r:.2f}R | Volume: {partial_volume:.2f}")
                        else:
                            print(f"[⚠️ PARTIAL CLOSE FAILED] {symbol} {pos.ticket} | Could not close 40%")
                    except Exception as pc_e:
                        print(f"[⚠️ PARTIAL CLOSE ERROR] {symbol} {pos.ticket}: {pc_e}")
                
                # Apply new SL if it changed
                if new_sl is not None and new_sl != pos.sl:
                    # Minimum move threshold: only modify if SL improves by at least 5 pips
                    point = get_symbol_point_value(symbol)[0]
                    min_move = 5 * point
                    sl_improvement = abs(new_sl - pos.sl)
                    if sl_improvement < min_move:
                        print(f"[TRAILING SKIP] {symbol} {pos.ticket} | Move too small ({sl_improvement:.5f} < {min_move:.5f})")
                        continue
                    
                    # Ensure SL moves in correct direction
                    should_modify = False
                    if direction == 'buy' and new_sl > pos.sl:
                        should_modify = True
                    elif direction == 'sell' and new_sl < pos.sl:
                        should_modify = True
                    
                    if should_modify:
                        # RETRY LOGIC: Up to 3 attempts
                        max_retries = 3
                        modify_result = None
                        for attempt in range(max_retries):
                            try:
                                modify_result = safe_order_modify(pos.ticket, pos.price_open, new_sl, pos.tp) if 'safe_order_modify' in globals() else mt5.order_modify(pos.ticket, pos.price_open, new_sl, pos.tp, 0, mt5.ORDER_TIME_GTC)
                                
                                if modify_result and (hasattr(modify_result, 'retcode') and modify_result.retcode == mt5.TRADE_RETCODE_DONE or modify_result is True):
                                    # SUCCESS: SL was modified, verify on broker
                                    pytime.sleep(0.1)  # Brief delay to ensure broker update
                                    updated_pos = mt5.positions_get(ticket=pos.ticket)[0] if mt5.positions_get(ticket=pos.ticket) else pos
                                    if abs(updated_pos.sl - new_sl) < 0.00001:  # Verify within 1 pip
                                        print(f"[THREE-STAGE ✓] {symbol} {direction.upper()} {pos.ticket} | {reason} | SL {pos.sl:.5f} → {new_sl:.5f} [VERIFIED]")
                                        break
                                    else:
                                        print(f"[THREE-STAGE VERIFY] {symbol} {pos.ticket} | Expected SL {new_sl:.5f}, broker shows {updated_pos.sl:.5f}")
                                        break
                                else:
                                    print(f"[THREE-STAGE RETRY] {symbol} {pos.ticket} | Attempt {attempt+1}/{max_retries} failed, retrying...")
                                    pytime.sleep(0.2)  # Small delay before retry
                            except Exception as retry_e:
                                print(f"[THREE-STAGE RETRY ERROR] {symbol} {pos.ticket} | Attempt {attempt+1}/{max_retries}: {retry_e}")
                                if attempt < max_retries - 1:
                                    pytime.sleep(0.2)
                                continue
            except Exception as e:
                print(f"[THREE-STAGE ERROR] {symbol} {pos.ticket}: {e}")
                continue
    
    except Exception as e:
        print(f"[THREE-STAGE MAIN ERROR] {symbol}: {e}")


def cleanup_closed_trailing_systems():
    """
    Removes tracking entries for closed positions from POSITION_TRAILING_SYSTEMS and TRADE_STATE_MANAGER.
    Call this periodically to prevent memory buildup.
    """
    try:
        import MetaTrader5 as mt5
        
        all_positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
        if not all_positions:
            all_positions = []
        
        open_tickets = {pos.ticket for pos in all_positions}
        closed_tickets = set(POSITION_TRAILING_SYSTEMS.keys()) - open_tickets
        
        for ticket in closed_tickets:
            POSITION_TRAILING_SYSTEMS.pop(ticket, None)
            POSITION_PHASE_TRACKING.pop(ticket, None)
            POSITION_TRAILING_STATS.pop(ticket, None)
            TRADE_STATE_MANAGER.remove_position(ticket)
            print(f"[CLEANUP] Removed tracking for closed position {ticket}")
    
    except Exception as e:
        print(f"[CLEANUP ERROR]: {e}")


def risk_reward_ok(entry, sl, tp, symbol=None, features=None, min_rr_base=1.0, ml_confidence=None, strategy_votes=None):
    """
    Checks if the risk-reward ratio for a trade meets a minimum threshold.
    Allows RR as low as 1.0 only if ML confidence >= 0.90 or strategy_votes >= 2.
    Otherwise, uses min_rr_base (default 1.0).
    """
    risk = abs(entry - sl)
    reward = abs(tp - entry)
    if risk == 0:
        print(f"[RISK/REWARD] {symbol}: Risk is zero (entry={entry}, sl={sl}).")
        return False
    rr = reward / risk

    # Default min_rr is 1.0, but only allow if high confidence or votes
    min_rr = min_rr_base

    # Check for high confidence or enough votes
    allow_low_rr = False
    # Try to get ml_confidence and strategy_votes from features if not passed
    if ml_confidence is None and features is not None:
        ml_confidence = features.get("ml_confidence", None)
    if strategy_votes is None and features is not None:
        strategy_votes = features.get("strategy_votes", None)
    if ml_confidence is not None and ml_confidence >= 0.95:
        allow_low_rr = True
    if strategy_votes is not None and isinstance(strategy_votes, (list, tuple, set)) and len(strategy_votes) >= 2:
        allow_low_rr = True

    # If RR < 1.0, only allow if high confidence or votes
    if rr < 1.0 and not allow_low_rr:
        print(f"[RISK/REWARD] {symbol}: RR {rr:.2f} < 1.0 and no high confidence or votes. Blocked.")
        return False

    # If RR < min_rr_base, block
    if rr < min_rr:
        print(f"[RISK/REWARD] {symbol}: RR check failed. Entry={entry}, SL={sl}, TP={tp}, Risk={risk:.5f}, Reward={reward:.5f}, RR={rr:.2f}, MinRR={min_rr:.2f}")
        return False
    return True


# --- Trade Entry Filter with All Requested Logic ---
import time

# Store last trade times for overtrading protection
_last_trade_times = {}

# RULE 3: ONE ENTRY PER STRUCTURE LEG - Track last BOS times
_last_bos_times = {}  # {symbol: {direction: timestamp}}

def can_add_entry_after_bos(symbol, direction, current_time=None):
    """
    RULE 3: ONE ENTRY PER STRUCTURE LEG

    No new trade allowed until a NEW BOS occurs.
    After a trade is opened, no new entries until structure improves (new BOS).

    Returns (can_enter: bool, reason: str)
    """
    if current_time is None:
        current_time = time.time()

    symbol_bos = _last_bos_times.get(symbol, {})
    last_bos_time = symbol_bos.get(direction, 0)
    last_trade_time = _last_trade_times.get(symbol, 0)

    # If no BOS has occurred yet, allow entry (first trade)
    if last_bos_time == 0:
        return True, "FIRST_TRADE_ALLOWED"

    # If BOS occurred after last trade, structure has improved - allow entry
    if last_bos_time > last_trade_time:
        return True, f"NEW_BOS_DETECTED ({last_bos_time} > {last_trade_time})"

    # Structure hasn't improved since last trade - block entry
    return False, f"WAITING_FOR_NEW_BOS (last_trade: {last_trade_time}, last_bos: {last_bos_time})"


def update_bos_time(symbol, direction, timestamp=None):
    """
    Update the last BOS time for a symbol/direction pair.
    Called when BOS is detected.
    """
    if timestamp is None:
        timestamp = time.time()

    if symbol not in _last_bos_times:
        _last_bos_times[symbol] = {}

    _last_bos_times[symbol][direction] = timestamp
    print(f"[BOS TRACKED] {symbol} {direction.upper()} BOS at {timestamp}")


# ⚡ FIX #4: DISPLACEMENT FILTER (Huge) ⚡
def check_displacement(symbol, df=None, threshold_multiplier=1.5):
    """
    FIX #4: DISPLACEMENT FILTER - Block trades in choppy/fake pullback zones.
    
    Rule: Only allow entries when current candle shows REAL MOMENTUM
    - current_candle_range > avg_range * 1.5 = displacement_ok (momentum exists)
    - current_candle_range <= avg_range * 1.5 = NO DISPLACEMENT (chop, fake move)
    
    Purpose: Avoid entering in low-volatility chop (fake pullbacks, no real moves)
    
    Returns: (displacement_ok, reason, current_range, avg_range)
    """
    try:
        if df is None:
            df = get_price_data(symbol, bars=100)
        if df is None or len(df) < 20:
            # Not enough data, assume no displacement (safer)
            return False, "INSUFFICIENT_DATA", 0.0, 0.0
        
        # Current candle range (high - low)
        current_range = df['high'].iloc[-1] - df['low'].iloc[-1]
        
        # Average range over last 20 candles
        ranges = df['high'].iloc[-20:-1] - df['low'].iloc[-20:-1]
        avg_range = ranges.mean()
        
        if avg_range <= 0:
            return False, "INVALID_AVG_RANGE", current_range, 0.0
        
        displacement_threshold = avg_range * threshold_multiplier
        displacement_ok = current_range > displacement_threshold
        
        reason = f"DISPLACEMENT_OK" if displacement_ok else f"NO_DISPLACEMENT"
        reason += f" (current: {current_range:.6f}, avg: {avg_range:.6f}, threshold: {displacement_threshold:.6f})"
        
        return displacement_ok, reason, current_range, avg_range
    
    except Exception as e:
        return False, f"DISPLACEMENT_ERROR: {str(e)}", 0.0, 0.0

# ⚡ FIX #5: ENTRY COOLDOWN (Mandatory) ⚡
def check_entry_cooldown(symbol, min_cooldown_seconds=60, max_cooldown_seconds=120):
    """
    FIX #5: ENTRY COOLDOWN - Prevent stacked/revenge entries on same symbol.
    
    Rule: Block entries for 60-120 seconds after last trade on M1 timeframe
    - Prevents rapid stacking of entries on same symbol
    - Avoids revenge trading after exit
    - Forces trader to reassess setup after exit
    
    Purpose: Stop multiple entries in quick succession (stacked entries)
    
    Returns: (cooldown_ok, reason, seconds_since_last_trade, remaining_cooldown)
    """
    try:
        now = time.time()
        last_trade_time = _last_trade_times.get(symbol, 0)
        
        # If no previous trade, cooldown is ok
        if last_trade_time == 0:
            return True, "FIRST_TRADE", 0, 0
        
        elapsed_seconds = now - last_trade_time
        remaining_seconds = max(0, max_cooldown_seconds - elapsed_seconds)
        
        # For M1 timeframe: use stricter cooldown (60-120 seconds)
        # This prevents entry stacking
        if elapsed_seconds >= max_cooldown_seconds:
            # Cooldown expired, allow entry
            return True, f"COOLDOWN_EXPIRED (elapsed: {elapsed_seconds:.0f}s)", elapsed_seconds, 0
        elif elapsed_seconds >= min_cooldown_seconds:
            # In the grace period (60-120s) - only allow on confluence/very strong signals
            # For now, we'll log but still allow it (user can tighten this)
            return True, f"GRACE_PERIOD (elapsed: {elapsed_seconds:.0f}s, warn)", elapsed_seconds, 0
        else:
            # Still in hard cooldown (< 60s) - BLOCK entry
            return False, f"COOLDOWN_ACTIVE (elapsed: {elapsed_seconds:.0f}s, need {min_cooldown_seconds}s)", elapsed_seconds, remaining_seconds
    
    except Exception as e:
        return True, f"COOLDOWN_ERROR: {str(e)}", 0, 0

def trade_entry_filter(
    symbol, signal, confidence, features, entry=None, sl=None, tp=None,
    min_confidence=None, min_rr_base=1.0, min_atr=0.0002, min_time_between_trades=5,
    require_pattern=False, require_session=False, require_confluence=False,
    pattern_conf_threshold=1
):
    """
    Loosened entry filter for normal entries (non-sniper).
    - Lower confidence and ATR thresholds
    - Session and confluence checks are optional
    - Pattern requirement is optional
    - RR filter is more permissive
    """
    threshold = min_confidence if min_confidence is not None else CONFIDENCE_THRESHOLD
    # 1. ML direction check
    if signal not in ("buy", "sell"):
        return False, None

    # 2. ML confidence OR pattern
    if confidence < threshold and features.get("pattern_strength", 0) < pattern_conf_threshold:
        return False, None

    # 3. Confluence (optional)
    if require_confluence:
        bullish_score = features.get("bullish_pattern_strength", 0)
        bearish_score = features.get("bearish_pattern_strength", 0)
        if signal == "buy" and bullish_score <= 0 and bearish_score <= 0:
            return False, None
        if signal == "sell" and bearish_score <= 0 and bullish_score <= 0:
            return False, None

    # 4. Pattern detection (optional)
    pattern_name = None
    pattern_strength = 0
    if require_pattern:
        bullish_patterns = [
            "cdl_bullish_engulfing", "cdl_three_white_soldiers", "cdl_hammer", "cdl_morning_star",
            "is_bullish_engulfing", "is_hammer", "is_pin_bar", "is_tweezer_bottom"
        ]
        bearish_patterns = [
            "cdl_bearish_engulfing", "cdl_three_black_crows", "cdl_hanging_man", "cdl_evening_star",
            "is_bearish_engulfing", "is_tweezer_top", "is_pin_bar"
        ]
        if signal == "buy":
            for p in bullish_patterns:
                if features.get(p, 0) > pattern_strength:
                    pattern_strength = features.get(p, 0)
                    pattern_name = p if pattern_strength >= pattern_conf_threshold else None
        else:
            for p in bearish_patterns:
                if features.get(p, 0) > pattern_strength:
                    pattern_strength = features.get(p, 0)
                    pattern_name = p if pattern_strength >= pattern_conf_threshold else None
        if pattern_name is None:
            return False, None

    # 5. Session filter (optional)
    if require_session:
        in_session = features.get("is_london", 0) or features.get("is_ny", 0)
        if not in_session:
            return False, None

    # 6. Spread filter (relaxed)
    spread = get_current_spread(symbol)
    spread_threshold = SPREAD_THRESHOLD * 3
    if spread is not None and spread > spread_threshold:
        return False, None

    # 7. News filter (optional)
    news_impact = features.get("news_impact", 0)
    if news_impact == 1 and confidence < 0.9:
        return False, None

    # 8. Volatility (ATR) filter (relaxed)
    atr = features.get("atr", 0)
    if atr < min_atr:
        return False, None

    # ⚡ FIX #3: Block entries that chase a strong expansion candle
    # Rule: NO BUY if previous candle is bullish and body > 1.5 * ATR
    #       NO SELL if previous candle is bearish and body > 1.5 * ATR
    try:
        atr_val = float(atr) if atr is not None else None
        if atr_val and symbol:
            recent = None
            try:
                recent = get_price_data(symbol, bars=3)
            except Exception:
                recent = None
            if recent is not None and len(recent) >= 2:
                prev = recent.iloc[-2]
                prev_body = abs(prev['close'] - prev['open'])
                if signal == 'buy' and prev['close'] > prev['open'] and prev_body > 1.5 * atr_val:
                    return False, None
                if signal == 'sell' and prev['close'] < prev['open'] and prev_body > 1.5 * atr_val:
                    return False, None
    except Exception:
        pass

    # 9. Overtrading protection (relaxed)
    now = time.time()
    last_time = _last_trade_times.get(symbol, 0)
    if now - last_time < min_time_between_trades:
        return False, None

    # 10. RR filter (relaxed)
    if entry and sl and tp:
        min_rr = min_rr_base
        if confidence >= 0.90:
            min_rr = 0.7
        if confidence >= 0.95:
            min_rr = 0.5
        if not risk_reward_ok(entry, sl, tp, symbol, features, min_rr_base=min_rr):
            return False, None

    _last_trade_times[symbol] = now
    return True, pattern_name


