from email.mime.multipart import MIMEMultipart

class ConfigManager:
    """
    Centralized configuration management with environment-based overrides.
    """
    _instance = None
    _config = None

    def __new__(cls):
        if not cls._instance:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __init__(self, config_path='config.yaml'):
        if not self._config:
            self.load_config(config_path)

    def load_config(self, config_path):
        """Load configuration from YAML with environment variable overrides."""
        try:
            with open(config_path, 'r') as f:
                self._config = yaml.safe_load(f)
            
            # Override with environment variables
            for key, value in os.environ.items():
                if key.startswith('BOT_'):
                    config_key = key[4:].lower()
                    try:
                        # Convert string to appropriate type
                        if value.lower() in ['true', 'false']:
                            value = value.lower() == 'true'
                        elif value.isdigit():
                            value = int(value)
                        elif self._is_float(value):
                            value = float(value)
                        self._config[config_key] = value
                    except Exception as e:
                        print(f"Error parsing env var {key}: {e}")
        except FileNotFoundError:
            print(f"Config file {config_path} not found. Using defaults.")
            self._config = self._default_config()

    def _is_float(self, value):
        try:
            float(value)
            return True
        except ValueError:
            return False

    def _default_config(self):
        """Provide default configuration if no file is found."""
        return {
            'symbols': ['GBPUSD', 'EURUSD'],
            'lot_size': 0.01,
            'max_daily_loss': -100,
            'max_daily_profit': 200,
            'confidence_threshold': 0.6,
            'risk_per_trade': 0.1,
            'logging_level': 'INFO'
        }

    def get(self, key, default=None):
        """Retrieve a configuration value with optional default."""
        return self._config.get(key, default)

    def update(self, key, value):
        """Update a configuration value."""
        self._config[key] = value

    def save(self, config_path='config.yaml'):
        """Save current configuration to file."""
        with open(config_path, 'w') as f:
            yaml.dump(self._config, f)

class ErrorRecoveryManager:
    """
    Advanced error recovery and monitoring system with email watchdog.
    """
    def __init__(self, max_retries=3, retry_delay=60, email_config=None):
        self.max_retries = max_retries
        self.retry_delay = retry_delay
        self.error_log = []
        self.email_config = email_config or {
            "smtp_server": getattr(config, 'SMTP_SERVER', 'smtp.gmail.com') if config is not None else 'smtp.gmail.com',
            "smtp_port": getattr(config, 'SMTP_PORT', 587) if config is not None else 587,
            "smtp_user": getattr(config, 'SMTP_USER', None) if config is not None else None,
            "smtp_password": getattr(config, 'SMTP_PASSWORD', None) if config is not None else None,
            "to_email": getattr(config, 'NOTIFY_EMAIL', None) if config is not None else None
        }

    def handle_error(self, context, error):
        """
        Log and potentially recover from errors.

        Args:
            context (str): Context of the error
            error (Exception): The error that occurred
        """
        error_details = {
            'timestamp': datetime.now().isoformat(),
            'context': context,
            'error_type': type(error).__name__,
            'error_message': str(error),
            'traceback': traceback.format_exc()
        }

        self.error_log.append(error_details)

        # Log to file
        with open('error_recovery.log', 'a') as f:
            json.dump(error_details, f)
            f.write('\n')

        # Send notification via email
        self._send_error_notification(error_details)

    def _send_error_notification(self, error_details):
        """
        Send error notification via email.
        """
        try:
            msg = MIMEMultipart()
            msg['From'] = self.email_config["smtp_user"]
            msg['To'] = self.email_config["to_email"]
            msg['Subject'] = f"[BOT WATCHDOG] Error: {error_details['context']} - {error_details['error_type']}"
            body = f"""
            Time: {error_details['timestamp']}
            Context: {error_details['context']}
            Error Type: {error_details['error_type']}
            Error Message: {error_details['error_message']}
            Traceback:
            {error_details['traceback']}
            """
            msg.attach(MIMEText(body, 'plain'))

            server = smtplib.SMTP(self.email_config["smtp_server"], self.email_config["smtp_port"])
            server.starttls()
            server.login(self.email_config["smtp_user"], self.email_config["smtp_password"])
            server.sendmail(self.email_config["smtp_user"], self.email_config["to_email"], msg.as_string())
            server.quit()
            print(f"[WATCHDOG] Error email sent to {self.email_config['to_email']}")
        except Exception as e:
            print(f"[WATCHDOG] Failed to send error email: {e}")

    def should_retry(self, context):
        """
        Determine if a retry should be attempted.

        Args:
            context (str): Context of the operation

        Returns:
            bool: Whether to retry the operation
        """
        recent_errors = [
            e for e in self.error_log 
            if e['context'] == context and datetime.fromisoformat(e['timestamp']) > datetime.now() - timedelta(minutes=30)
        ]
        return len(recent_errors) < self.max_retries

class PerformanceTracker:
    """
    Granular performance tracking per strategy and symbol.
    """
    def __init__(self):
        self.performance_data = {}


    def log_trade(self, symbol, strategy, trade_result):
        """
        Log individual trade performance.
        
        Args:
            symbol (str): Trading symbol
            strategy (str): Strategy name
            trade_result (float): Trade profit/loss
        """
        if symbol not in self.performance_data:
            self.performance_data[symbol] = {}
        
        if strategy not in self.performance_data[symbol]:
            self.performance_data[symbol][strategy] = {
                'trades': 0,
                'wins': 0,
                'losses': 0,
                'total_pnl': 0,
                'max_win': float('-inf'),
                'max_loss': float('inf')
            }
        
        data = self.performance_data[symbol][strategy]
        data['trades'] += 1
        data['total_pnl'] += trade_result
        
        if trade_result > 0:
            data['wins'] += 1
            data['max_win'] = max(data['max_win'], trade_result)
        else:
            data['losses'] += 1
            data['max_loss'] = min(data['max_loss'], trade_result)

    def get_strategy_performance(self, symbol=None, strategy=None):
        """
        Retrieve performance metrics.
        
        Args:
            symbol (str, optional): Specific symbol
            strategy (str, optional): Specific strategy
        
        Returns:
            dict: Performance metrics
        """
        if symbol and strategy:
            return self.performance_data.get(symbol, {}).get(strategy, {})
        elif symbol:
            return self.performance_data.get(symbol, {})
        else:
            return self.performance_data

def setup_logging(log_level='INFO', log_file='bot.log'):
    """
    Set up advanced logging with rotation.
    
    Args:
        log_level (str): Logging level
        log_file (str): Log file path
    """
    # Create logs directory if it doesn't exist
    os.makedirs('logs', exist_ok=True)
    
    # Configure logging
    logging.basicConfig(
        level=getattr(logging, log_level.upper()),
        format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
        handlers=[
            logging.StreamHandler(),  # Console output
            RotatingFileHandler(
                os.path.join('logs', log_file), 
                maxBytes=10*1024*1024,  # 10 MB
                backupCount=5  # Keep 5 backup files
            )
        ]
    )
