# 1. Multi-timeframe Confirmation
def multi_timeframe_confirm(symbol, signal, timeframe="M15", bars=3):
    rates = mt5.copy_rates_from_pos(symbol, getattr(mt5, f"TIMEFRAME_{timeframe}"), 1, bars)
    if rates is None or len(rates) < bars:
        return False
    if signal == "buy":
        return all(r['close'] > r['open'] for r in rates)
    elif signal == "sell":
        return all(r['close'] < r['open'] for r in rates)
    return False

# 2. Dynamic Position Sizing (Kelly/volatility scaling)
def dynamic_lot_size(account_balance, risk_per_trade, sl_pips, pip_value):
    """Calculate lot size based on account balance and risk, with micro-lot support for small accounts."""
    # Enforce hard cap on `risk_per_trade` if configured
    try:
        rpt = float(risk_per_trade)
    except Exception:
        rpt = float(MAX_RISK_PER_TRADE_PCT) if 'MAX_RISK_PER_TRADE_PCT' in globals() else 0.01
    if 'HARD_RISK_MAX_PCT' in globals():
        rpt = min(rpt, HARD_RISK_MAX_PCT)
    risk_amount = account_balance * rpt
    # Prevent division by zero
    if sl_pips <= 0 or pip_value <= 0:
        return 0.001  # Minimum micro-lot
    lot = risk_amount / (sl_pips * pip_value)
    # For accounts under $2000, use micro-lots (0.001 minimum)
    if account_balance < 2000:
        return max(0.001, round(lot, 3))
    # For larger accounts, use mini-lots (0.01 minimum)
    return max(0.01, round(lot, 2))

def calculate_lot_size_with_threshold(account_balance, risk_per_trade, sl_pips, pip_value):
    """
    Calculate lot size with account balance threshold.
    - If balance < $200: always use 0.01 lot (fixed)
    - If balance >= $200: dynamically calculate using risk management
    """
    try:
        balance = float(account_balance)
    except Exception:
        balance = 10000.0  # fallback
    
    # Hard threshold: small accounts always use 0.01
    if balance < 200:
        return 0.01
    
    # For larger accounts, use dynamic sizing
    return dynamic_lot_size(account_balance, risk_per_trade, sl_pips, pip_value)

# 3. News Filter (block trades during high-impact news)
