# 4. Adaptive Trailing Stop (move SL to BE after RR>1, then trail)
def adaptive_trailing_stop(
    trade, df, atr_mult=1.0,
    trail_pct=0.01, chandelier_mult=3, step_size=None, ma_value=None, profit_trigger=None
):
    """
    Adaptive trailing stop that combines multiple trailing stop methods.
    """
    entry = trade['price_open']
    sl = trade['sl']
    signal = "buy" if trade['type'] == mt5.ORDER_TYPE_BUY else "sell"
    current_price = get_current_price(trade['symbol'])[0] if signal == "buy" else get_current_price(trade['symbol'])[1]
    features = get_features_fixed(df)
    atr = features.get("atr", 0.0005)

    # Calculate highest high / lowest low for chandelier exit
    highest_high = None
    lowest_low = None
    if len(df) > 0:
        highest_high = df['high'].max()
        lowest_low = df['low'].min()

    # Calculate moving average if not provided
    if ma_value is None and 'ema20' in features:
        ma_value = features['ema20']

    rr = abs(current_price - entry) / abs(entry - sl) if abs(entry - sl) > 0 else 0
    if rr > 1 and ((signal == "buy" and current_price > entry) or (signal == "sell" and current_price < entry)):
        new_sl = entry
    else:
        new_sl = get_trailing_sl(
            entry, current_price, sl, signal, atr * atr_mult,
            highest_high=highest_high, lowest_low=lowest_low,
            trail_pct=trail_pct, atr_mult=chandelier_mult,
            step_size=step_size, ma_value=ma_value, profit_trigger=profit_trigger
        )
    return new_sl

