def get_pip_value(symbol, price=None, lot=1.0):
    """
    Return approximate pip value in account currency per lot for given symbol.
    This is a heuristic mapping used for lot-sizing calculations.

    Args:
        symbol: instrument symbol, e.g. 'XAUUSD'.
        price:  optional, kept for backwards compatibility (ignored).
        lot:    lot size to scale pip value by (default 1.0).
    """
    s = str(symbol).upper()
    # XAU/XAG approximate pip (point) value per lot in USD-equivalent
    if s.startswith('XAU') or s.startswith('XAG'):
        return 1.0 * float(lot)
    # JPY pairs: pip = 0.01; value per lot slightly different
    if 'JPY' in s:
        return 9.1 * float(lot)
    # Default for most forex majors (pip 0.0001)
    return 10.0 * float(lot)

def daily_loss_exceeded(current_equity, start_of_day_equity):
    daily_dd = (start_of_day_equity - current_equity) / start_of_day_equity
    return daily_dd >= MAX_DAILY_LOSS

def total_open_risk(open_trades):
    return sum(trade["risk_pct"] for trade in open_trades)

def calculate_lot_size(symbol, stop_loss_points, equity):
    if symbol == "XAUUSD":
        risk_pct = RISK_PER_TRADE_XAU
    else:
        risk_pct = RISK_PER_TRADE_FX

    risk_amount = equity * risk_pct

    tick_value = get_pip_value(symbol)   # already in your code
    lot_size = risk_amount / (stop_loss_points * tick_value)

    # Dynamic lot sizing: 0.01 minimum, 1.0 maximum (respects config SYMBOL_MAX_LOT)
    max_lot = SYMBOL_MAX_LOT.get(symbol.upper().split('.')[0], MAX_LOT_SIZE)
    lot_size = max(0.01, min(lot_size, max_lot))

    return round(lot_size, 2)

def _legacy_execute_trade(symbol, direction, sl, tp, lot):
    # Original execution logic preserved here (renamed to allow scorer wrapper)
    print(f"Executing trade: {symbol} {direction} SL={sl} TP={tp} Lot={lot}")
    # Store trade with risk_pct for risk management
    risk_pct = RISK_PER_TRADE_XAU if symbol == "XAUUSD" else RISK_PER_TRADE_FX
    trade = {
        "symbol": symbol,
        "direction": direction,
        "sl": sl,
        "tp": tp,
        "lot": lot,
        "risk_pct": risk_pct
    }
    # Assume open_trades is a global list
