def execute_trade(symbol, direction, sl, tp, lot, use_scorer=True, min_score=60):
    """Wrapper around legacy execution that optionally consults the scorer.

    If `use_scorer` is True and `integrate_scorer_decision` is available in this module,
    the scorer will be called and its internal executor will invoke `_legacy_execute_trade`
    if the scorer accepts the trade. Otherwise, falls back to legacy execution.
    """
    try:
        if use_scorer and 'integrate_scorer_decision' in globals():
            # Minimal context: provide direction and a basic near_key_level hint.
            context = {
                "bos_direction": direction,
                "near_key_level": True,
            }

            def _executor(sym, dir, conf, metadata):
                # Forward to the original executor; keep signature minimal.
                _legacy_execute_trade(sym, dir, sl, tp, lot)

            decision = integrate_scorer_decision(context, _executor, symbol=symbol, min_score=min_score)
            if decision:
                return
        # Fallback to legacy immediate execution
        return _legacy_execute_trade(symbol, direction, sl, tp, lot)
    except Exception:
        # On any error in scorer flow, ensure legacy executes to avoid blocking
        return _legacy_execute_trade(symbol, direction, sl, tp, lot)


def compute_sl_tp_from_logic(symbol, direction, entry_price, features, m5_structure_level,
                             rr=2.0, atr_mult=1.2, min_sl_points_gold=20.0, min_sl_points_fx=10.0):
    """
    Compute SL/TP using:
      1) Liquidity-based levels (swing highs/lows, order blocks, FVG)
      2) M5 structure / OB,
      3) ATR-based buffer,
      4) Minimum floor in points.

    sl_distance = max(liquidity_sl, structure_sl, atr * atr_mult, min_floor)
    tp = entry ± sl_distance * RR
    """
    # Get liquidity-based SL level
    liquidity_sl_price = calculate_liquidity_based_sl(symbol, direction, entry_price)

    atr = float(features.get("atr", 0.0) or 0.0)

    # Determine minimum SL floor based on symbol
    s = str(symbol).upper()
    if s.startswith("XAU"):
        min_floor = min_sl_points_gold
    else:
        min_floor = min_sl_points_fx

    # 1. Liquidity-based SL distance
    liquidity_sl_distance = 0.0
    if liquidity_sl_price is not None:
        # Validate that liquidity SL is on the correct side of entry
        if direction == "buy" and liquidity_sl_price < entry_price:
            liquidity_sl_distance = abs(entry_price - liquidity_sl_price)
            print(f"[SL CALC] {symbol} BUY: Using liquidity SL at {liquidity_sl_price:.5f}, distance {liquidity_sl_distance:.5f}")
        elif direction == "sell" and liquidity_sl_price > entry_price:
            liquidity_sl_distance = abs(liquidity_sl_price - entry_price)
            print(f"[SL CALC] {symbol} SELL: Using liquidity SL at {liquidity_sl_price:.5f}, distance {liquidity_sl_distance:.5f}")
        else:
            print(f"[SL CALC] {symbol} {direction.upper()}: Invalid liquidity SL level {liquidity_sl_price:.5f}, ignoring")
            liquidity_sl_price = None

    # 2. Structure-based SL distance
    structure_sl_distance = 0.0
    if m5_structure_level is not None:
        if direction == "buy":
            structure_sl_distance = abs(entry_price - m5_structure_level)
        else:  # sell
            structure_sl_distance = abs(m5_structure_level - entry_price)

    # 3. ATR-based distance
    atr_distance = atr * atr_mult if atr > 0 else 0.0

    # 4. Minimum floor (in price points)
    min_floor_distance = float(min_floor)

    # Final SL distance - prioritize liquidity levels
    sl_distance = max(liquidity_sl_distance, structure_sl_distance, atr_distance, min_floor_distance)

    if sl_distance <= 0:
        return None, None, None  # invalid

    # Set SL price
    if direction == "buy":
        sl_price = entry_price - sl_distance
        tp_price = entry_price + sl_distance * rr
        # Safeguard: Ensure TP is above entry for buys
        if tp_price <= entry_price:
            print(f"[RR SAFEGUARD] {symbol} BUY: TP {tp_price:.5f} <= entry {entry_price:.5f}, adjusting")
            tp_price = entry_price + sl_distance * max(rr, 1.1)  # Minimum 1.1 RR
    else:  # sell
        sl_price = entry_price + sl_distance
        tp_price = entry_price - sl_distance * rr
        # Safeguard: Ensure TP is below entry for sells
        if tp_price >= entry_price:
            print(f"[RR SAFEGUARD] {symbol} SELL: TP {tp_price:.5f} >= entry {entry_price:.5f}, adjusting")
            tp_price = entry_price - sl_distance * max(rr, 1.1)  # Minimum 1.1 RR

    return sl_price, tp_price, sl_distance


def calculate_liquidity_based_sl(symbol, direction, entry_price, lookback_bars=50):
    """
    Calculate stop loss based on key liquidity levels:
    - Recent swing highs/lows
    - Order blocks
    - Fair value gaps (FVG)
    - Previous resistance/support levels

    Returns the most relevant liquidity level for SL placement.
    """
    try:
        # Get M5 data for liquidity analysis
        df_m5 = get_price_data(symbol, timeframe="M5", bars=lookback_bars + 20)
        if df_m5 is None or len(df_m5) < lookback_bars:
            return None

        liquidity_levels = []

        # 1. Find recent swing highs/lows
        swing_levels = find_swing_levels(df_m5, lookback=lookback_bars//2)
        if swing_levels:
            if direction == "buy":
                # For buy trades, use recent swing lows as potential SL levels
                swing_lows = [level for level in swing_levels if level < entry_price]
                if swing_lows:
                    liquidity_levels.append(max(swing_lows))  # Closest swing low below entry
            else:  # sell
                # For sell trades, use recent swing highs as potential SL levels
                swing_highs = [level for level in swing_levels if level > entry_price]
                if swing_highs:
                    liquidity_levels.append(min(swing_highs))  # Closest swing high above entry

        # 2. Find order blocks
        ob_levels = find_order_blocks(df_m5, lookback=lookback_bars//3)
        if ob_levels:
            if direction == "buy":
                # Use bearish order blocks below entry as SL levels
                bear_ob = [level for level in ob_levels.get('bear', []) if level < entry_price]
                if bear_ob:
                    liquidity_levels.append(max(bear_ob))  # Closest bear OB below entry
            else:  # sell
                # Use bullish order blocks above entry as SL levels
                bull_ob = [level for level in ob_levels.get('bull', []) if level > entry_price]
                if bull_ob:
                    liquidity_levels.append(min(bull_ob))  # Closest bull OB above entry

        # 3. Find fair value gaps
        fvg_levels = find_fair_value_gaps(df_m5, lookback=lookback_bars//2)
        if fvg_levels:
            if direction == "buy":
                # Use bearish FVGs below entry as SL levels
                bear_fvg = [level for level in fvg_levels.get('bearish', []) if level < entry_price]
                if bear_fvg:
                    liquidity_levels.append(max(bear_fvg))  # Closest bear FVG below entry
            else:  # sell
                # Use bullish FVGs above entry as SL levels
                bull_fvg = [level for level in fvg_levels.get('bullish', []) if level > entry_price]
                if bull_fvg:
                    liquidity_levels.append(min(bull_fvg))  # Closest bull FVG above entry

        # 4. Find previous resistance/support levels
        structure_levels = find_structure_levels(df_m5, lookback=lookback_bars)
        if structure_levels:
            if direction == "buy":
                support_levels = [level for level in structure_levels.get('support', []) if level < entry_price]
                if support_levels:
                    liquidity_levels.append(max(support_levels))  # Strongest support below entry
            else:  # sell
                resistance_levels = [level for level in structure_levels.get('resistance', []) if level > entry_price]
                if resistance_levels:
                    liquidity_levels.append(min(resistance_levels))  # Strongest resistance above entry

        # Select the best liquidity level for SL
        if liquidity_levels:
            if direction == "buy":
                # For buys, choose the highest level below entry (closest/strongest support)
                valid_levels = [level for level in liquidity_levels if level < entry_price]
                if valid_levels:
                    selected_level = max(valid_levels)
                    print(f"[LIQUIDITY SL] {symbol} BUY: Selected support level {selected_level:.5f} below entry {entry_price:.5f}")
                    return selected_level
            else:  # sell
                # For sells, choose the lowest level above entry (closest/strongest resistance)
                valid_levels = [level for level in liquidity_levels if level > entry_price]
                if valid_levels:
                    selected_level = min(valid_levels)
                    print(f"[LIQUIDITY SL] {symbol} SELL: Selected resistance level {selected_level:.5f} above entry {entry_price:.5f}")
                    return selected_level

        print(f"[LIQUIDITY SL] {symbol} {direction.upper()}: No valid liquidity levels found, using fallback")
        return None

    except Exception as e:
        print(f"[LIQUIDITY SL ERROR] {symbol}: {e}")
        return None


def find_swing_levels(df, lookback=25):
    """
    Find recent swing highs and lows in the price data.
    Returns list of swing levels.
    """
    try:
        if len(df) < lookback * 2:
            return []

        levels = []
        window = max(3, lookback // 5)  # Adaptive window size

        # Find swing highs and lows using zigzag-like logic
        for i in range(window, len(df) - window):
            # Check if this is a swing high
            is_swing_high = True
            high_val = df['high'].iloc[i]
            for j in range(i - window, i + window + 1):
                if j != i and df['high'].iloc[j] > high_val:
                    is_swing_high = False
                    break
            if is_swing_high:
                levels.append(high_val)

            # Check if this is a swing low
            is_swing_low = True
            low_val = df['low'].iloc[i]
            for j in range(i - window, i + window + 1):
                if j != i and df['low'].iloc[j] < low_val:
                    is_swing_low = False
                    break
            if is_swing_low:
                levels.append(low_val)

        # Remove duplicates and filter out levels too close to each other
        unique_levels = []
        levels.sort()
        for level in levels:
            if not unique_levels or abs(level - unique_levels[-1]) > 0.0001:  # Minimum separation
                unique_levels.append(level)

        return unique_levels

    except Exception as e:
        print(f"[SWING LEVELS ERROR] {e}")
        return []


def find_order_blocks(df, lookback=20):
    """
    Find order blocks in the price data.
    Returns dict with 'bull' and 'bear' lists of order block levels.
    """
    try:
        if len(df) < lookback + 5:
            return {'bull': [], 'bear': []}

        bull_ob = []
        bear_ob = []

        # Look for order blocks in recent candles
        for i in range(max(5, len(df) - lookback), len(df)):
            try:
                # Get recent candles for analysis
                recent_df = df.iloc[max(0, i-20):i+1]
                if len(recent_df) < 5:
                    continue

                # Simple order block detection based on volume and price action
                curr_candle = recent_df.iloc[-1]
                prev_candle = recent_df.iloc[-2]

                body_size = abs(curr_candle['close'] - curr_candle['open'])
                range_size = curr_candle['high'] - curr_candle['low']

                # Volume spike detection
                avg_volume = recent_df['tick_volume'].rolling(10).mean().iloc[-1]
                volume_spike = curr_candle['tick_volume'] > avg_volume * 1.5

                # Bullish order block: strong bullish candle with volume
                if (curr_candle['close'] > curr_candle['open'] and
                    body_size > range_size * 0.6 and
                    volume_spike):
                    bull_ob.append(curr_candle['low'])  # OB level at low

                # Bearish order block: strong bearish candle with volume
                elif (curr_candle['close'] < curr_candle['open'] and
                      body_size > range_size * 0.6 and
                      volume_spike):
                    bear_ob.append(curr_candle['high'])  # OB level at high

            except Exception as e:
                continue

        return {'bull': bull_ob[-5:], 'bear': bear_ob[-5:]}  # Keep only recent 5

    except Exception as e:
        print(f"[ORDER BLOCKS ERROR] {e}")
        return {'bull': [], 'bear': []}


def find_fair_value_gaps(df, lookback=25):
    """
    Find fair value gaps (FVG) in the price data.
    Returns dict with 'bullish' and 'bearish' lists of FVG levels.
    """
    try:
        bullish_fvg = []
        bearish_fvg = []

        for i in range(2, min(lookback + 2, len(df))):
            prev_candle = df.iloc[i-2]
            curr_candle = df.iloc[i-1]
            next_candle = df.iloc[i]

            # Bullish FVG: gap between prev high and curr low, next candle doesn't fill
            if prev_candle['high'] < curr_candle['low']:
                gap_level = (prev_candle['high'] + curr_candle['low']) / 2
                if next_candle['high'] < curr_candle['low']:
                    bullish_fvg.append(gap_level)

            # Bearish FVG: gap between curr high and next low, prev candle doesn't fill
            if curr_candle['high'] < next_candle['low']:
                gap_level = (curr_candle['high'] + next_candle['low']) / 2
                if prev_candle['low'] > curr_candle['high']:
                    bearish_fvg.append(gap_level)

        return {'bullish': bullish_fvg, 'bearish': bearish_fvg}
    except Exception:
        return {'bullish': [], 'bearish': []}


def find_structure_levels(df, lookback=50):
    """
    Find key structure levels (resistance/support) from recent price action.
    Returns dict with 'resistance' and 'support' lists.
    """
    try:
        resistance_levels = []
        support_levels = []

        # Use structure detection to find key levels
        structure_df = detect_structure(df, window=5)

        # Find areas where HH/HL patterns occur (potential resistance/support)
        for i in range(len(structure_df)):
            if structure_df['HH'].iloc[i]:
                resistance_levels.append(df['high'].iloc[i])
            if structure_df['LL'].iloc[i]:
                support_levels.append(df['low'].iloc[i])

        # Remove duplicates and sort
        resistance_levels = sorted(list(set(resistance_levels)), reverse=True)
        support_levels = sorted(list(set(support_levels)), reverse=True)

        return {'resistance': resistance_levels, 'support': support_levels}
    except Exception:
        return {'resistance': [], 'support': []}

