def hh_hl_structure(df, lookback=20):
    """
    Detect HH/HL (Higher High/Higher Low) structure for trend confirmation.
    Returns 'uptrend', 'downtrend', or None.
    """
    highs = df['high'].iloc[-lookback:].to_numpy()
    lows = df['low'].iloc[-lookback:].to_numpy()
    if all(highs[i] < highs[i+1] for i in range(len(highs)-1)) and all(lows[i] < lows[i+1] for i in range(len(lows)-1)):
        return 'uptrend'
    if all(highs[i] > highs[i+1] for i in range(len(highs)-1)) and all(lows[i] > lows[i+1] for i in range(len(lows)-1)):
        return 'downtrend'
    return None

