    # --- 4H Trend Filter (EMA + structure) ---
    # Use a robust helper to evaluate 4H EMA ribbon and market structure
    def evaluate_4h_ema_structure(df_h4, symbol=None, min_bars=50):
        """
        Evaluates 4H EMAs (20/50/200), structure (HH/HL or LH/LL), and returns a detailed
        diagnostic dict with a decision: 'long', 'short', or 'neutral'. Also provides
        a numeric score and readable diagnostics to aid debugging.
        """
        out = {
            'decision': 'neutral',
            'score': 0.0,
            'ema20': None,
            'ema50': None,
            'ema200': None,
            'ema20_slope': None,
            'ema50_slope': None,
            'ema200_slope': None,
            'structure': None,
            'reasons': []
        }
        try:
            if df_h4 is None or df_h4.empty or len(df_h4) < min_bars:
                out['reasons'].append('insufficient_bars')
                return out

            close = df_h4['close']
            ema20 = close.ewm(span=20, adjust=False).mean().iloc[-1]
            ema50 = close.ewm(span=50, adjust=False).mean().iloc[-1]
            ema200 = close.ewm(span=200, adjust=False).mean().iloc[-1]
            out['ema20'] = float(ema20)
            out['ema50'] = float(ema50)
            out['ema200'] = float(ema200)

            # EMA slopes (relative change over last 3 bars)
            def slope(series, n=3):
                if len(series) < n+1:
                    return 0.0
                return float((series.iloc[-1] - series.iloc[-1-n]) / (series.iloc[-1-n] + 1e-12))

            out['ema20_slope'] = slope(close.ewm(span=20, adjust=False).mean())
            out['ema50_slope'] = slope(close.ewm(span=50, adjust=False).mean())
            out['ema200_slope'] = slope(close.ewm(span=200, adjust=False).mean())

            # Structure detection using helpers if available
            struct_up = False
            struct_down = False
            try:
                struct_up = market_structure_higher_highs_and_lows(df_h4)
                struct_down = market_structure_lower_highs_and_lows(df_h4)
                out['structure'] = 'uptrend' if struct_up else ('downtrend' if struct_down else 'sideways')
            except Exception:
                out['structure'] = 'unknown'

            # Scoring rules
            score = 0.0
            # Strong EMA ribbon alignment adds to score
            if out['ema20'] > out['ema50'] > out['ema200']:
                score += 3.0
                out['reasons'].append('ema_ribbon_bull')
            if out['ema20'] < out['ema50'] < out['ema200']:
                score += 3.0
                out['reasons'].append('ema_ribbon_bear')

            # Structure alignment bonus
            if struct_up:
                score += 2.0
                out['reasons'].append('hh_hl')
            if struct_down:
                score += 2.0
                out['reasons'].append('ll_lh')

            # EMA slope confirmation
            if out['ema20_slope'] and out['ema20_slope'] > 0.0002:
                score += 1.0
            if out['ema20_slope'] and out['ema20_slope'] < -0.0002:
                score += 1.0

            # Distance between EMA50 and EMA200 (trend strength proxy)
            try:
                dist = abs(out['ema50'] - out['ema200']) / (out['ema200'] + 1e-12)
                if dist > 0.005:
                    score += 1.0
                    out['reasons'].append('ema_distance')
            except Exception:
                pass

            out['score'] = round(score, 2)

            # Decision thresholding
            if score >= 4.0 and out['ema20'] > out['ema50'] > out['ema200'] and struct_up:
                out['decision'] = 'long'
            elif score >= 4.0 and out['ema20'] < out['ema50'] < out['ema200'] and struct_down:
                out['decision'] = 'short'
            else:
                out['decision'] = 'neutral'

            return out
        except Exception as e:
            out['reasons'].append(f'error:{e}')
            return out

