    # --- 30M Automated Demand/Supply Zone Detection ---
    def detect_supply_demand_zone(df, direction):
        for i in range(-10, -2):
            if direction == "buy" and df['close'].iloc[i] < df['open'].iloc[i]:
                return (df['low'].iloc[i], df['high'].iloc[i])
            if direction == "sell" and df['close'].iloc[i] > df['open'].iloc[i]:
                return (df['low'].iloc[i], df['high'].iloc[i])
        return None

    def is_in_sr_zone(direction, last_close, zone):
        if not zone:
            return False
        low, high = zone
        return low <= last_close <= high

    def detect_market_structure_shift(df, direction):
        closes = df['close']
        lows = df['low']
        highs = df['high']
        if direction == "buy":
            bos = closes.iloc[-1] > closes.max()
            hl = lows.iloc[-1] > lows.iloc[-3]
            momentum = closes.iloc[-1] > closes.iloc[-2] > closes.iloc[-3]
            wick = (highs.iloc[-1] - closes.iloc[-1]) > (closes.iloc[-1] - lows.iloc[-1]) * 1.5
            engulf = closes.iloc[-1] > closes.iloc[-2] and closes.iloc[-2] < closes.iloc[-3]
            return bos and hl and (momentum or wick or engulf)
        if direction == "sell":
            bos = closes.iloc[-1] < closes.min()
            lh = highs.iloc[-1] < highs.iloc[-3]
            momentum = closes.iloc[-1] < closes.iloc[-2] < closes.iloc[-3]
            wick = (closes.iloc[-1] - lows.iloc[-1]) > (highs.iloc[-1] - closes.iloc[-1]) * 1.5
            engulf = closes.iloc[-1] < closes.iloc[-2] and closes.iloc[-2] > closes.iloc[-3]
            return bos and lh and (momentum or wick or engulf)
        return False

    def calculate_confluence_score(signal, ml_conf, htf_conf, sr_conf, bos_conf):
        """
        Multi-source confluence scoring for additional validation.
        Higher score = more sources agree with the signal.
        """
        confluence_sources = 0
        total_confidence = 0
        
        # Count how many sources support this signal
        if signal == "buy":
            if ml_conf >= 0.5: confluence_sources += 1; total_confidence += ml_conf
            if htf_conf >= 0.5: confluence_sources += 1; total_confidence += htf_conf
            if sr_conf >= 0.5: confluence_sources += 1; total_confidence += sr_conf
            if bos_conf >= 0.5: confluence_sources += 1; total_confidence += bos_conf
        else:  # sell
            if ml_conf >= 0.5: confluence_sources += 1; total_confidence += ml_conf
            if htf_conf >= 0.5: confluence_sources += 1; total_confidence += htf_conf
            if sr_conf >= 0.5: confluence_sources += 1; total_confidence += sr_conf
            if bos_conf >= 0.5: confluence_sources += 1; total_confidence += bos_conf
        
        avg_confidence = total_confidence / max(confluence_sources, 1)
        return confluence_sources, avg_confidence

