    def get_upcoming_news(symbol, within_minutes=15):
        # Trading Economics API: https://tradingeconomics.com/ws
        # Register for a free API key and set as env var TRADING_ECONOMICS_API_KEY
        # symbol: e.g. 'USD', 'EUR', 'GBP', etc.
        try:
            now = datetime.utcnow()
            future = now + timedelta(minutes=within_minutes)
            url = f'https://api.tradingeconomics.com/calendar/country/all?c={TRADING_ECONOMICS_API_KEY}'
            resp = requests.get(url, timeout=5)
            if resp.status_code == 200:
                events = resp.json()
                relevant = []
                for event in events:
                    # Filter by currency and time window
                    if symbol.upper() in str(event.get('currency', '')):
                        event_time = event.get('date')
                        if event_time:
                            event_dt = datetime.strptime(event_time[:19], '%Y-%m-%dT%H:%M:%S')
                            if now <= event_dt <= future:
                                if event.get('importance', '').lower() in ['high', 'medium']:
                                    relevant.append(event)
                return relevant
        except Exception as e:
            print(f"[NEWS] Error fetching economic calendar: {e}")
        return []

    def get_latest_headlines(symbol, max_results=5):
        # NewsAPI: https://newsapi.org/
        # Register for a free API key and set as env var NEWSAPI_KEY
        try:
            url = f'https://newsapi.org/v2/everything?q={symbol}&apiKey={NEWSAPI_KEY}&language=en&sortBy=publishedAt&pageSize={max_results}'
            resp = requests.get(url, timeout=5)
            if resp.status_code == 200:
                data = resp.json()
                return [a['title'] for a in data.get('articles', [])]
        except Exception as e:
            print(f"[NEWS] Error fetching news headlines: {e}")
        return []

