    def avoid_late_entry_filter(df, direction, max_cont_candles=None, impulse_atr_mult=2.0, max_zone_distance_pips=None):
        """
        Block entries that are 'late' into a move:
        - If there are >= `max_cont_candles` consecutive continuation candles on the entry TF
          and the combined body size (impulse) exceeds `impulse_atr_mult * ATR`, block.
        - If features contain an `entry_zone`, ensure price is inside or within `max_zone_distance_pips`.
        """
        try:
            if df is None or len(df) < 6:
                return True
            if max_cont_candles is None:
                max_cont_candles = globals().get('MAX_CONTINUATION_CANDLES', 3)
            if max_zone_distance_pips is None:
                # default: 30 pips for XAU (i.e., $30), small for FX
                max_zone_distance_pips = globals().get('MAX_ZONE_DISTANCE_PIPS_XAU', 30) if 'XAU' in symbol.upper() else globals().get('MAX_ZONE_DISTANCE_PIPS', 8)

            # Look at last closed candles (exclude current)
            bodies = (df['close'] - df['open']).iloc[-6:-1].tolist()
            # Count consecutive continuation candles from the most recent backward
            count = 0
            for b in reversed(bodies):
                if direction == 'buy' and b > 0:
                    count += 1
                elif direction == 'sell' and b < 0:
                    count += 1
                else:
                    break

            # Compute impulse magnitude of those continuation candles
            impulse = sum(abs(x) for x in bodies[-count:]) if count > 0 else 0.0
            atr_val = df['close'].rolling(14).std().iloc[-2] if 'close' in df and len(df) >= 16 else 0.0

            if count >= max_cont_candles and impulse > (impulse_atr_mult * (atr_val or 1e-6)):
                print(f"[{symbol}] Late-entry filter: {count} continuation candles with impulse {impulse:.6f} > {impulse_atr_mult}*ATR -> blocking.")
                return False

            # Distance to entry zone (if available)
            try:
                ez = None
                if 'features' in locals() and isinstance(features, dict) and 'entry_zone' in features:
                    ez = features.get('entry_zone')
                else:
                    # attempt to pull features from outer scope if present
                    ez = globals().get('CURRENT_FEATURES_FOR_ENTRY', None)
                if isinstance(ez, dict) and ez.get('low') is not None and ez.get('high') is not None:
                    price_now = df['close'].iloc[-2]
                    if not (ez['low'] <= price_now <= ez['high']):
                        pip = 0.01 if 'JPY' in symbol.upper() else (1.0 if 'XAU' in symbol.upper() else 0.0001)
                        dist = min(abs(price_now - ez['low']), abs(price_now - ez['high'])) / pip
                        if dist > max_zone_distance_pips:
                            print(f"[{symbol}] Late-entry filter: price {price_now} is {dist:.1f} pips from entry zone -> blocking.")
                            return False
            except Exception:
                pass

            return True
        except Exception as e:
            print(f"[{symbol}] Late-entry filter error: {e}")
            return True

