    # --- SMC/ICT: Detect BSL/SSL, Inducement, OB, POI, LQ Sweep (Advanced) ---
    def detect_liquidity_sweep(df, lookback=20, volume_mult=1.2):
        """
        Detects liquidity sweep with volume and candle pattern confirmation.
        Returns (sweep_high, sweep_low, sweep_details)
        """
        recent_high = df['high'].iloc[-lookback-2:-2].max()
        recent_low = df['low'].iloc[-lookback-2:-2].min()
        last_high = df['high'].iloc[-2]
        last_low = df['low'].iloc[-2]
        last_close = df['close'].iloc[-2]
        last_open = df['open'].iloc[-2]
        last_volume = df['tick_volume'].iloc[-2]
        avg_volume = df['tick_volume'].iloc[-lookback-2:-2].mean()
        # Candle pattern: engulfing or pin bar
        bullish_engulf = last_close > last_open and last_close > df['close'].iloc[-3]
        bearish_engulf = last_close < last_open and last_close < df['close'].iloc[-3]
        sweep_high = last_high > recent_high and last_volume > avg_volume * volume_mult and bearish_engulf
        sweep_low = last_low < recent_low and last_volume > avg_volume * volume_mult and bullish_engulf
        sweep_details = {
            "recent_high": recent_high,
            "recent_low": recent_low,
            "last_high": last_high,
            "last_low": last_low,
            "last_volume": last_volume,
            "avg_volume": avg_volume,
            "bullish_engulf": bullish_engulf,
            "bearish_engulf": bearish_engulf
        }
        return sweep_high, sweep_low, sweep_details

    def detect_order_block(df, direction, lookback=20, min_body_ratio=0.6, min_volume_mult=1.2):
        """
        Detects order block with body ratio, volume, and context.
        Returns (is_ob, ob_details)
        """
        last_close = df['close'].iloc[-2]
        last_open = df['open'].iloc[-2]
        body = abs(last_close - last_open)
        range_ = df['high'].iloc[-2] - df['low'].iloc[-2]
        last_volume = df['tick_volume'].iloc[-2]
        avg_volume = df['tick_volume'].iloc[-lookback-2:-2].mean()
        is_large_candle = body > min_body_ratio * range_
        is_volume_spike = last_volume > avg_volume * min_volume_mult
        # Confirm with wick rejection
        upper_wick = df['high'].iloc[-2] - max(last_close, last_open)
        lower_wick = min(last_close, last_open) - df['low'].iloc[-2]
        wick_reject = (direction == "buy" and lower_wick > body * 0.5) or (direction == "sell" and upper_wick > body * 0.5)
        is_ob = False
        if direction == "buy" and last_close > last_open and is_large_candle and is_volume_spike and wick_reject:
            is_ob = True
        if direction == "sell" and last_close < last_open and is_large_candle and is_volume_spike and wick_reject:
            is_ob = True
        ob_details = {
            "body": body,
            "range": range_,
            "last_volume": last_volume,
            "avg_volume": avg_volume,
            "is_large_candle": is_large_candle,
            "is_volume_spike": is_volume_spike,
            "wick_reject": wick_reject
        }
        return is_ob, ob_details

    def detect_inducement(df, direction, lookback=10, min_reversal=0.5):
        """
        Detects inducement: sweep then reversal with momentum.
        Returns (is_inducement, inducement_details)
        """
        closes = df['close'].iloc[-lookback:]
        momentum = abs(closes.iloc[-1] - closes.iloc[-2]) > min_reversal * closes.std()
        if direction == "buy":
            is_inducement = closes.min() == closes.iloc[-1] and momentum
        elif direction == "sell":
            is_inducement = closes.max() == closes.iloc[-1] and momentum
        else:
            is_inducement = False
        inducement_details = {
            "momentum": momentum,
            "closes": closes.tolist()
        }
        return is_inducement, inducement_details

    def detect_poi(df, direction, lookback=20, ema_filter=True):
        """
        Detects POI with EMA filter and candle context.
        Returns (poi_price, poi_details)
        """
        if direction == "buy":
            poi_price = df['low'].iloc[-2]
        elif direction == "sell":
            poi_price = df['high'].iloc[-2]
        else:
            poi_price = None
        ema50 = df['close'].ewm(span=50, adjust=False).mean().iloc[-2]
        ema200 = df['close'].ewm(span=200, adjust=False).mean().iloc[-2]
        ema_ok = (direction == "buy" and ema50 > ema200) or (direction == "sell" and ema50 < ema200) if ema_filter else True
        candle_ok = (df['close'].iloc[-2] > df['open'].iloc[-2]) if direction == "buy" else (df['close'].iloc[-2] < df['open'].iloc[-2])
        poi_details = {
            "ema50": ema50,
            "ema200": ema200,
            "ema_ok": ema_ok,
            "candle_ok": candle_ok
        }
        if poi_price is not None and ema_ok and candle_ok:
            return poi_price, poi_details
        return None, poi_details

    # Lower-timeframe POI refinement (M5)
    df_m5_poi = get_price_data(symbol, timeframe="M5", bars=50)
    lower_poi, lower_poi_details = detect_poi(df_m5_poi, signal_type) if signal_type else (None, {})

    sweep_high, sweep_low, sweep_details = detect_liquidity_sweep(df_main)
    ob_detected, ob_details = detect_order_block(df_main, signal_type)
    inducement, inducement_details = detect_inducement(df_main, signal_type)
    poi, poi_details = detect_poi(df_main, signal_type)

    # Entry only if all SMC/ICT conditions are met
    smc_conditions = [
        (signal_type == "buy" and sweep_low),
        (signal_type == "sell" and sweep_high),
        ob_detected,
        inducement,
        poi is not None,
        lower_poi is not None
    ]

    if all(smc_conditions):
        # Build scorer context from available local signals
        context = {
            "liquidity_sweep": bool(sweep_low) if signal_type == "buy" else bool(sweep_high),
            "bos": False,
            "bos_direction": signal_type,
            "choch": bool(inducement),
            "htf_bias": None,
            "ema_alignment": poi_details.get("ema_ok") if isinstance(poi_details, dict) else False,
            "pullback_zone": False,
            "volume_expansion": has_volume_expansion(df_main) if 'has_volume_expansion' in globals() else False,
            "rsi": None,
            "near_key_level": bool(poi),
            "volatility_compression": False,
        }

        # Try scorer first; it will call your executor if it accepts the trade.
        decision = integrate_scorer_decision(context, execute_trade, symbol=symbol, min_score=60)
        if decision:
            print(f"[{symbol}] SMC/ICT Entry ACCEPTED BY SCORER: {decision.strategy} -> {decision.direction.upper()} | Score={decision.score:.1f} | Conf={decision.confidence:.2f}")
            continue
        # Fall back to legacy direct execution if scorer declined
        # Calculate risk-based lot size
        stop_loss_points = abs(price - sl)  # Assuming price is entry price
        equity = get_account_balance()
        lot_size = calculate_lot_size(symbol, stop_loss_points, equity)
        execute_trade(symbol, signal_type, sl=sl, tp=tps[0] if tps else None, lot=lot_size)
        print(f"[{symbol}] SMC/ICT Entry (legacy): {signal_type.upper()} | Price={price} | SL={sl} | TP={tps} | POI={poi} | Lower-TF POI={lower_poi}")
        print(f"  Sweep details: {sweep_details}")
        print(f"  Order Block details: {ob_details}")
        print(f"  Inducement details: {inducement_details}")
        print(f"  POI details: {poi_details}")
        print(f"  Lower-TF POI details: {lower_poi_details}")
    else:
        print(f"[{symbol}] SMC/ICT filter blocked entry. Details:")
        print(f"  sweep_high={sweep_high}, sweep_low={sweep_low}, sweep_details={sweep_details}")
        print(f"  ob_detected={ob_detected}, ob_details={ob_details}")
        print(f"  inducement={inducement}, inducement_details={inducement_details}")
        print(f"  poi={poi}, poi_details={poi_details}")
        print(f"  lower_poi={lower_poi}, lower_poi_details={lower_poi_details}")

