def strategy_consensus(df, features, ml_signal=None, ml_confidence=None):
    """
    Consensus: ML is the brain (main vote), candlestick patterns are sensory input (support).
    ML has more power; candlestick patterns only boost confidence if they agree.

    Returns:
    - direction ('buy', 'sell', or None)
    - confidence score (0-1)
    - detailed strategy votes
    """
    strategy_votes = {}
    strategy_confidences = {}

    # --- ML voting (the brain) ---
    if ml_signal is not None and ml_confidence is not None:
        strategy_votes["ML"] = ml_signal
        strategy_confidences["ML"] = ml_confidence

    # --- Candlestick pattern support (the sensory input) ---
    bullish_patterns = [
        "cdl_bullish_engulfing", "cdl_three_white_soldiers", "cdl_hammer", "cdl_morning_star",
        "is_bullish_engulfing", "is_hammer", "is_pin_bar", "is_tweezer_bottom"
    ]
    bearish_patterns = [
        "cdl_bearish_engulfing", "cdl_three_black_crows", "cdl_hanging_man", "cdl_evening_star",
        "is_bearish_engulfing", "is_tweezer_top", "is_pin_bar"
    ]
    bullish_score = sum(features.get(p, 0) for p in bullish_patterns)
    bearish_score = sum(features.get(p, 0) for p in bearish_patterns)

    # Candlestick patterns only support ML if they agree with its direction
    if ml_signal == "buy" and bullish_score >= 1:
        strategy_votes["CandlestickPatterns"] = "buy"
        # Boost confidence if strong pattern
        strategy_confidences["CandlestickPatterns"] = 0.2 if bullish_score == 1 else 0.3
    elif ml_signal == "sell" and bearish_score >= 1:
        strategy_votes["CandlestickPatterns"] = "sell"
        strategy_confidences["CandlestickPatterns"] = 0.2 if bearish_score == 1 else 0.3

    # Calculate consensus
    if ml_signal in ("buy", "sell"):
        # ML is the main vote, candlestick patterns only boost confidence if they agree
        base_conf = ml_confidence if ml_confidence is not None else 0.5
        pattern_boost = strategy_confidences.get("CandlestickPatterns", 0)
        final_conf = min(base_conf + pattern_boost, 1.0)
        return ml_signal, final_conf, strategy_votes

    return None, 0, strategy_votes




def breakout_logic(df, box_period=BREAKOUT_BOX_PERIOD, atr_mult=BREAKOUT_ATR_MULT, volume_mult=BREAKOUT_VOLUME_MULT):
    """
    Advanced Volatility Box Breakout logic:
    - Looks for breakouts above/below a recent high/low (box)
    - Confirms with ATR and volume
    Returns 'buy', 'sell', or None.
    """
    if len(df) < box_period + 2:
        print("    [DEBUG] Not enough bars for breakout logic.")
        return None

    # Define the box (range) using the last N bars (excluding the most recent closed candle)
    box_high = df['high'].iloc[-box_period-2:-2].max()
    box_low = df['low'].iloc[-box_period-2:-2].min()
    last_close = df['close'].iloc[-2]
    last_high = df['high'].iloc[-2]
    last_low = df['low'].iloc[-2]
    last_volume = df['tick_volume'].iloc[-2]
    atr = calculate_atr(df)
    avg_volume = df['tick_volume'].iloc[-box_period-2:-2].mean()

    #print(f"    [DEBUG] Breakout box: High={box_high:.5f}, Low={box_low:.5f}, LastClose={last_close:.5f}, ATR={atr:.5f}, LastVol={last_volume:.2f}, AvgVol={avg_volume:.2f}")

    # Bullish breakout: last candle closes above box high, with strong body and volume
    if last_close > box_high and (last_close - df['open'].iloc[-2]) > atr * 0.5 and last_volume > avg_volume * volume_mult:
        #print("    [DEBUG] Bullish breakout detected.")
        return 'buy'
    # Bearish breakout: last candle closes below box low, with strong body and volume
    if last_close < box_low and (df['open'].iloc[-2] - last_close) > atr * 0.5 and last_volume > avg_volume * volume_mult:
        #print("    [DEBUG] Bearish breakout detected.")
        return 'sell'
    return None

