def load_historical_buffer(symbol, bars=5000):
    """
    Loads a sufficient historical buffer for the symbol.
    Increase the default 'bars' parameter to ensure enough data for all indicators.
    """
    df = get_price_data(symbol, bars=bars)
    if df is None or df.empty or len(df) < bars:
        print(f"    [{symbol}] Not enough historical data.")
        return None

    # Keep last 6 months for training relevance
    if len(df) > (24*4*30*6):  # M15 candles in ~6 months
        df = df.tail(24*4*30*6)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
    return df
