# === S&R Zone Detection and Retest Confirmation ===

def detect_major_sr_zones(df_h4, df_h1, lookback=50, tolerance=0.0005):
    """
    Detect major S&R zones from H4/H1 timeframes.
    Returns a list of price levels (zones).
    """
    sr_zones = set()
    # Use swing highs/lows as S&R candidates
    for df in [df_h4, df_h1]:
        highs = df['high'].rolling(3).max()
        lows = df['low'].rolling(3).min()
        for i in range(-lookback, 0):
            # Swing high
            if df['high'].iloc[i] == highs.iloc[i]:
                sr_zones.add(round(df['high'].iloc[i], 4))
            # Swing low
            if df['low'].iloc[i] == lows.iloc[i]:
                sr_zones.add(round(df['low'].iloc[i], 4))
    return sorted(sr_zones)

def confirm_retest(df_m15, sr_zones, direction, tolerance=0.0005):
    """
    Confirm retest of S&R zone on M15 for tighter stop and entry.
    Returns True if retest confirmed.
    """
    last_close = df_m15['close'].iloc[-2]
    last_open = df_m15['open'].iloc[-2]
    for zone in sr_zones:
        if direction == "buy" and abs(last_close - zone) < tolerance and last_close > last_open:
            return True
        if direction == "sell" and abs(last_close - zone) < tolerance and last_close < last_open:
            return True
    return False

def hh_hl_structure(df, lookback=20):
    """
    Detect HH/HL (Higher High/Higher Low) structure for trend confirmation.
    Returns 'uptrend', 'downtrend', or None.
    """
    highs = df['high'].iloc[-lookback:].to_numpy()
    lows = df['low'].iloc[-lookback:].to_numpy()
    if all(highs[i] < highs[i+1] for i in range(len(highs)-1)) and all(lows[i] < lows[i+1] for i in range(len(lows)-1)):
        return 'uptrend'
    if all(highs[i] > highs[i+1] for i in range(len(highs)-1)) and all(lows[i] > lows[i+1] for i in range(len(lows)-1)):
        return 'downtrend'
    return None

# Example integration in your entry logic:
def sr_entry_filter(symbol, df_h4, df_h1, df_m15, df_m5, df_main, direction):
    """
    Combines S&R zone detection, retest confirmation, and HH/HL structure.
    Returns True if all conditions met for high-probability entry.
    """
    sr_zones = detect_major_sr_zones(df_h4, df_h1)
    # Confirm retest on M15 or M5
    retest_confirmed = confirm_retest(df_m15, sr_zones, direction) or confirm_retest(df_m5, sr_zones, direction)
    # Confirm structure
    structure = hh_hl_structure(df_main)
    if direction == "buy" and retest_confirmed and structure == "uptrend":
        return True
    if direction == "sell" and retest_confirmed and structure == "downtrend":
        return True
    return False

