class StrategyBase:
    def __init__(self, name):
        self.name = name

    def check(self, df, features):
        """Return 'buy', 'sell', or None."""
        raise NotImplementedError

# === Squeeze Momentum Indicator Strategy ===
# === Squeeze Momentum Indicator Strategy ===
class SqueezeMomentumStrategy(StrategyBase):
    def __init__(self, bb_period=20, kc_period=20, mult=2.0):
        super().__init__("SqueezeMomentumStrategy")
        self.bb_period = bb_period
        self.kc_period = kc_period
        self.mult = mult
    def check(self, df, features):
        if len(df) < max(self.bb_period, self.kc_period) + 10:
            return None
        close = df['close']
        high = df['high']
        low = df['low']
        bb_mid = close.rolling(self.bb_period).mean()
        bb_std = close.rolling(self.bb_period).std()
        bb_upper = bb_mid + self.mult * bb_std
        bb_lower = bb_mid - self.mult * bb_std
        tr = (high - low).rolling(self.kc_period).mean()
        kc_mid = close.rolling(self.kc_period).mean()
        kc_upper = kc_mid + self.mult * tr
        kc_lower = kc_mid - self.mult * tr
        squeeze_on = (bb_upper.iloc[-2] < kc_upper.iloc[-2]) and (bb_lower.iloc[-2] > kc_lower.iloc[-2])
        squeeze_off = (bb_upper.iloc[-2] > kc_upper.iloc[-2]) and (bb_lower.iloc[-2] < kc_lower.iloc[-2])
        momentum_bars = close.iloc[-6:-1]
        trend_up = all(momentum_bars.iloc[i] < momentum_bars.iloc[i+1] for i in range(len(momentum_bars)-1))
        trend_down = all(momentum_bars.iloc[i] > momentum_bars.iloc[i+1] for i in range(len(momentum_bars)-1))
        volume_spike = df['tick_volume'].iloc[-2] > df['tick_volume'].rolling(20).mean().iloc[-2] * 1.5

        if squeeze_on and squeeze_off and trend_up and volume_spike:
            return "buy"
        if squeeze_on and squeeze_off and trend_down and volume_spike:
            return "sell"
        return None

# === MACD Custom Indicator Strategy ===
class MACDStrategy(StrategyBase):
    def __init__(self, fast=12, slow=26, signal=9):
        super().__init__("MACDStrategy")
        self.fast = fast
        self.slow = slow
        self.signal = signal
    def check(self, df, features):
        if len(df) < self.slow + self.signal + 10:
            return None
        close = df['close']
        ema_fast = close.ewm(span=self.fast, adjust=False).mean()
        ema_slow = close.ewm(span=self.slow, adjust=False).mean()
        macd = ema_fast - ema_slow
        macd_signal = macd.ewm(span=self.signal, adjust=False).mean()
        macd_hist = macd - macd_signal
        prev_macd = macd.iloc[-2]
        prev_signal = macd_signal.iloc[-2]
        curr_macd = macd.iloc[-1]
        curr_signal = macd_signal.iloc[-1]
        hist_trend_up = all(macd_hist.iloc[i] < macd_hist.iloc[i+1] for i in range(-6, -1))
        hist_trend_down = all(macd_hist.iloc[i] > macd_hist.iloc[i+1] for i in range(-6, -1))
        volume_spike = df['tick_volume'].iloc[-2] > df['tick_volume'].rolling(20).mean().iloc[-2] * 1.5

        if prev_macd < prev_signal and curr_macd > curr_signal and hist_trend_up and volume_spike:
            return "buy"
        if prev_macd > prev_signal and curr_macd < curr_signal and hist_trend_down and volume_spike:
            return "sell"
        return None

# === Smart Money Concepts (SMC) Strategy ===
class SmartMoneyConceptsStrategy(StrategyBase):
    def __init__(self, lookback=20):
        super().__init__("SmartMoneyConceptsStrategy")
        self.lookback = lookback

    def check(self, df, features):
        if len(df) < self.lookback + 5:
            return None

        # 1. Detect liquidity grab (sweep of recent high/low)
        recent_high = df['high'].iloc[-self.lookback-2:-2].max()
        recent_low = df['low'].iloc[-self.lookback-2:-2].min()
        last_high = df['high'].iloc[-2]
        last_low = df['low'].iloc[-2]
        last_close = df['close'].iloc[-2]
        last_open = df['open'].iloc[-2]

        # 2. Detect order block (large candle after sweep)
        body = abs(last_close - last_open)
        range_ = df['high'].iloc[-2] - df['low'].iloc[-2]
        is_large_candle = body > 0.6 * range_

        # 3. Trend context (EMA50/EMA200)
        ema50 = df['close'].ewm(span=50, adjust=False).mean().iloc[-2]
        ema200 = df['close'].ewm(span=200, adjust=False).mean().iloc[-2]
        trend_up = ema50 > ema200
        trend_down = ema50 < ema200

        # --- Bullish SMC: sweep of low, large bullish candle, in uptrend ---
        if last_low < recent_low and last_close > last_open and is_large_candle and trend_up:
            # Confirm break of structure (BOS): close above recent swing high
            swing_high = df['high'].iloc[-self.lookback:-2].max()
            if last_close > swing_high:
                return "buy"

        # --- Bearish SMC: sweep of high, large bearish candle, in downtrend ---
        if last_high > recent_high and last_close < last_open and is_large_candle and trend_down:
            # Confirm break of structure (BOS): close below recent swing low
            swing_low = df['low'].iloc[-self.lookback:-2].min()
            if last_close < swing_low:
                return "sell"

        return None

