# 1. Trend-Following EMA Crossover Strategy
class EMACrossoverStrategy(StrategyBase):
    def __init__(self, fast=9, slow=21):
        super().__init__("EMACrossoverStrategy")
        self.fast = fast
        self.slow = slow
    def check(self, df, features):
        if len(df) < self.slow + 2:
            return None
        close = df['close']
        ema_fast = close.ewm(span=self.fast, adjust=False).mean()
        ema_slow = close.ewm(span=self.slow, adjust=False).mean()
        if ema_fast.iloc[-2] < ema_slow.iloc[-2] and ema_fast.iloc[-1] > ema_slow.iloc[-1]:
            return "buy"
        if ema_fast.iloc[-2] > ema_slow.iloc[-2] and ema_fast.iloc[-1] < ema_slow.iloc[-1]:
            return "sell"
        return None

# 2. RSI Overbought/Oversold Reversal Strategy
class RSIStrategy(StrategyBase):
    def __init__(self, period=14, overbought=70, oversold=30):
        super().__init__("RSIStrategy")
        self.period = period
        self.overbought = overbought
        self.oversold = oversold
    def check(self, df, features):
        if len(df) < self.period + 2:
            return None
        close = df['close']
        delta = close.diff()
        gain = (delta.where(delta > 0, 0)).rolling(self.period).mean()
        loss = (-delta.where(delta < 0, 0)).rolling(self.period).mean()
        rs = gain / (loss + 1e-8)
        rsi = 100 - (100 / (1 + rs))
        if rsi.iloc[-2] < self.oversold and rsi.iloc[-1] > self.oversold:
            return "buy"
        if rsi.iloc[-2] > self.overbought and rsi.iloc[-1] < self.overbought:
            return "sell"
        return None

# 3. Breakout Box Strategy (already present as breakout_logic, but now as a class)
class BreakoutBoxStrategy(StrategyBase):
    def __init__(self, box_period=20, atr_mult=1.0, volume_mult=1.5, lookback=20):
        super().__init__("BreakoutBoxStrategy")
        self.box_period = box_period
        self.atr_mult = atr_mult
        self.volume_mult = volume_mult
        self.lookback = lookback

    def check(self, df, features):
        # Box breakout logic
        if len(df) >= self.box_period + 2:
            box_high = df['high'].iloc[-self.box_period-2:-2].max()
            box_low = df['low'].iloc[-self.box_period-2:-2].min()
            last_close = df['close'].iloc[-2]
            last_open = df['open'].iloc[-2]
            last_volume = df['tick_volume'].iloc[-2]
            atr = features.get("atr", 0)
            avg_volume = df['tick_volume'].iloc[-self.box_period-2:-2].mean()
            if last_close > box_high and (last_close - last_open) > atr * 0.5 and last_volume > avg_volume * self.volume_mult:
                return "buy"
            if last_close < box_low and (last_open - last_close) > atr * 0.5 and last_volume > avg_volume * self.volume_mult:
                return "sell"

        # Advanced Break of Structure (BOS) logic
        if len(df) >= self.lookback + 10:
            highs = df['high'].iloc[-self.lookback:]
            lows = df['low'].iloc[-self.lookback:]
            close = df['close'].iloc[-1]
            volume_avg = df['tick_volume'].rolling(20).mean().iloc[-1]
            volume_current = df['tick_volume'].iloc[-1]

            # Bullish BOS with advanced confirmation
            if close > highs.max():
                for i in range(-2, -self.lookback, -1):
                    if (df['close'].iloc[i] < df['open'].iloc[i] and 
                        volume_current > volume_avg * 1.5):
                        ob = df['low'].iloc[i]
                        if (close > ob and 
                            close > df['close'].rolling(10).mean().iloc[-1] and 
                            df['close'].iloc[-2] > df['open'].iloc[-2]):
                            return "buy"

            # Bearish BOS with advanced confirmation
            if close < lows.min():
                for i in range(-2, -self.lookback, -1):
                    if (df['close'].iloc[i] > df['open'].iloc[i] and 
                        volume_current > volume_avg * 1.5):
                        ob = df['high'].iloc[i]
                        if (close < ob and 
                            close < df['close'].rolling(10).mean().iloc[-1] and 
                            df['close'].iloc[-2] < df['open'].iloc[-2]):
                            return "sell"
        return None

# === SuperTrend Strategy ===
class SuperTrendStrategy(StrategyBase):
    def __init__(self, period=10, multiplier=3.0):
        super().__init__("SuperTrendStrategy")
        self.period = period
        self.multiplier = multiplier
    def check(self, df, features):
        if len(df) < self.period + 10:
            return None
        high = df['high']
        low = df['low']
        close = df['close']
    
    # Use True Range for more accurate ATR
        tr = pd.DataFrame({
            'h-l': high - low,
            'h-pc': abs(high - close.shift()),
            'l-pc': abs(low - close.shift())
        }).max(axis=1)
        atr = tr.rolling(self.period).mean()
        
        hl2 = (high + low) / 2
        basic_ub = hl2 + self.multiplier * atr
        basic_lb = hl2 - self.multiplier * atr
        
        final_ub = basic_ub.copy()
        final_lb = basic_lb.copy()
        
        for i in range(1, len(df)):
            final_ub.iloc[i] = min(basic_ub.iloc[i], final_ub.iloc[i-1]) if close.iloc[i-1] > final_ub.iloc[i-1] else basic_ub.iloc[i]
            final_lb.iloc[i] = max(basic_lb.iloc[i], final_lb.iloc[i-1]) if close.iloc[i-1] < final_lb.iloc[i-1] else basic_lb.iloc[i]
        
        supertrend = pd.Series(index=close.index, dtype=float)
        supertrend.iloc[0] = final_ub.iloc[0]
        
        for i in range(1, len(df)):
            if close.iloc[i-1] <= supertrend.iloc[i-1]:
                supertrend.iloc[i] = final_ub.iloc[i]
            else:
                supertrend.iloc[i] = final_lb.iloc[i]
        
        # Volume and trend confirmation
        volume_avg = df['tick_volume'].rolling(20).mean().iloc[-1]
        volume_current = df['tick_volume'].iloc[-1]
        
        # Multi-bar trend confirmation
        trend_bars = close.iloc[-5:]
        trend_up = all(trend_bars.iloc[i] > trend_bars.iloc[i+1] for i in range(len(trend_bars)-1))
        trend_down = all(trend_bars.iloc[i] < trend_bars.iloc[i+1] for i in range(len(trend_bars)-1))
        
        # Buy: price crosses above supertrend with volume and trend confirmation
        if (close.iloc[-2] < supertrend.iloc[-2] and 
            close.iloc[-1] > supertrend.iloc[-1] and 
            volume_current > volume_avg * 1.5 and 
            trend_up):
            return "buy"
        
        # Sell: price crosses below supertrend with volume and trend confirmation
        if (close.iloc[-2] > supertrend.iloc[-2] and 
            close.iloc[-1] < supertrend.iloc[-1] and 
            volume_current > volume_avg * 1.5 and 
            trend_down):
            return "sell"
    
        return None

# === Multi-Level ZigZag Harmonic Pattern Strategy ===

class ZigZagHarmonicStrategy(StrategyBase):
    """
    Detects multi-level zigzag harmonic patterns for reversal or breakout signals.
    """
    def __init__(self, depth=12, deviation=5, backstep=3):
        super().__init__("ZigZagHarmonic")
        self.depth = depth
        self.deviation = deviation
        self.backstep = backstep

    def find_zigzag_points(self, df):
        # Simple zigzag implementation (high/low pivots)
        pivots = []
        for i in range(self.depth, len(df) - self.depth):
            high = df['high'].iloc[i]
            low = df['low'].iloc[i]
            if high == max(df['high'].iloc[i-self.depth:i+self.depth+1]):
                pivots.append((i, 'high', high))
            if low == min(df['low'].iloc[i-self.depth:i+self.depth+1]):
                pivots.append((i, 'low', low))
        return pivots

    def detect_harmonic(self, pivots):
        # Look for ABCD or Gartley-like patterns in last 5 pivots
        if len(pivots) < 5:
            return None
        last5 = pivots[-5:]
        # Example: bullish ABCD (low, high, low, high, low)
        types = [p[1] for p in last5]
        if types == ['low', 'high', 'low', 'high', 'low']:
            return 'bullish'
        if types == ['high', 'low', 'high', 'low', 'high']:
            return 'bearish'
        return None

    def check(self, df, features):
        pivots = self.find_zigzag_points(df)
        pattern = self.detect_harmonic(pivots)
        if pattern == 'bullish':
            return 'buy'
        elif pattern == 'bearish':
            return 'sell'
        return None

# === NR4 & NR7 Breakout Strategy (LuxAlgo style) ===

class NRBreakoutStrategy(StrategyBase):
    """
    Detects NR4 and NR7 (Narrow Range 4/7) breakouts for volatility expansion trades.
    """
    def __init__(self, nr_period=4, atr_mult=1.0):
        super().__init__("NR4_NR7_Breakout")
        self.nr_period = nr_period
        self.atr_mult = atr_mult

    def is_nr(self, df, bars):
        if len(df) < bars + 2:
            return False
        last_range = df['high'].iloc[-2] - df['low'].iloc[-2]
        prior_ranges = [df['high'].iloc[-i-2] - df['low'].iloc[-i-2] for i in range(1, bars)]
        return last_range < min(prior_ranges)

    def check(self, df, features):
        atr = calculate_atr(df)
        # NR4
        if self.is_nr(df, 4):
            # Bullish breakout
            if df['close'].iloc[-2] > df['high'].iloc[-3] and (df['close'].iloc[-2] - df['open'].iloc[-2]) > atr * self.atr_mult:
                return 'buy'
            # Bearish breakout
            if df['close'].iloc[-2] < df['low'].iloc[-3] and (df['open'].iloc[-2] - df['close'].iloc[-2]) > atr * self.atr_mult:
                return 'sell'
        # NR7
        if self.is_nr(df, 7):
            if df['close'].iloc[-2] > df['high'].iloc[-3] and (df['close'].iloc[-2] - df['open'].iloc[-2]) > atr * self.atr_mult:
                return 'buy'
            if df['close'].iloc[-2] < df['low'].iloc[-3] and (df['open'].iloc[-2] - df['close'].iloc[-2]) > atr * self.atr_mult:
                return 'sell'
        return None
class ScalpingOrderFlowLiquidityStrategy(StrategyBase):
    def __init__(self):
        super().__init__("ScalpingOrderFlowLiquidity")

    def check(self, df, features):
        if len(df) < 52:
            return None
        close = df['close'].iloc[-1]
        ema20 = features['ema20']
        ema50 = features['ema50']
        ema200 = features['ema200']
        rsi = features['rsi']
        atr = features['atr']

        if close > ema20 > ema50 > ema200 and rsi > 60:
            return 'buy'
        if close < ema20 < ema50 < ema200 and rsi < 40:
            return 'sell'
        return None

class BreakoutStrategy(StrategyBase):
    def __init__(self):
        super().__init__("Breakout")

    def check(self, df, features):
        # Existing advanced breakout logic
        breakout = breakout_logic(df)
        if breakout is not None:
            return breakout
        
        # --- NEW ENTRY PATTERNS FOR BREAKOUT ---
        # 1. Inside bar breakout (last 2 bars)
        if len(df) >= 3:
            prev_high = df['high'].iloc[-3]
            prev_low = df['low'].iloc[-3]
            last_high = df['high'].iloc[-2]
            last_low = df['low'].iloc[-2]
            # Inside bar: last high < prev high and last low > prev low
            if last_high < prev_high and last_low > prev_low:
                # Breakout up
                if df['close'].iloc[-1] > prev_high:
                    #print("    [DEBUG] Inside bar breakout up.")
                    return 'buy'
                # Breakout down
                if df['close'].iloc[-1] < prev_low:
                    #print("    [DEBUG] Inside bar breakout down.")
                    return 'sell'
        
        # 2. Volatility expansion (ATR spike)
        if len(df) >= 20:
            atr_now = calculate_atr(df)
            atr_prev = calculate_atr(df.iloc[:-1])
            if atr_now > atr_prev * 1.5:
                # New: Any close above previous high or below previous low (ultra-permissive breakout)
                if df['close'].iloc[-1] > df['high'].iloc[-2]:
                    #print("    [DEBUG] Close above previous high (breakout, ultra-permissive).")
                    return 'buy'
                if df['close'].iloc[-1] < df['low'].iloc[-2]:
                    #print("    [DEBUG] Close below previous low (breakout, ultra-permissive).")
                    return 'sell'
        return None

class TrendMomentumStrategy(StrategyBase):
    def __init__(self):
        super().__init__("TrendMomentum")

    def check(self, df, features):
        if len(df) < 52:
            print("    [DEBUG] Not enough bars for pattern logic.")
            return None

        # Volatility regime filter (adaptive and ultra-permissive)
        returns = df['close'].pct_change().dropna()
        volatility_cluster = returns.rolling(10).std().iloc[-1]
        regime = "trend"
        if volatility_cluster < 0.0005:
            regime = "range"
            # print("    [DEBUG] Volatility low: switching to range regime (relaxing filters).")
        # Relax filter: allow entries in range regime
        if regime == "trend" and volatility_cluster < 0.0005:
            # print("    [DEBUG] Volatility too low for momentum trading.")
            return None
        elif regime == "range":
            # In range regime, allow ultra-permissive entries
            close = df['close'].iloc[-1]
            ema20 = features["ema20"]
            rsi = features["rsi"]
            atr = features["atr"]
            # EMA bounce or RSI reversal
            if abs(close - ema20) < atr and 35 < rsi < 65:
                # print("    [DEBUG] Range regime: EMA bounce or RSI reversal (ultra-permissive).")
                return 'buy' if close > ema20 else 'sell'
            # Simple candle color (green/red) as entry
            last_close = df['close'].iloc[-2]
            last_open = df['open'].iloc[-2]
            if last_close > last_open:
                # print("    [DEBUG] Range regime: Green candle, ultra-permissive buy.")
                return 'buy'
            if last_close < last_open:
                # print("    [DEBUG] Range regime: Red candle, ultra-permissive sell.")
                return 'sell'
            # RSI reversal (ultra-permissive)
            if rsi < 35:
                # print("    [DEBUG] Range regime: RSI reversal buy.")
                return 'buy'
            if rsi > 65:
                # print("    [DEBUG] Range regime: RSI reversal sell.")
                return 'sell'
            # Lower ML confidence threshold in range regime
            if features.get("ml_confidence", 0) > 0.25:
                # print("    [DEBUG] Range regime: ML confidence override, ultra-permissive entry.")
                return 'buy' if features.get("ml_signal") == "buy" else 'sell'


        close = df['close'].iloc[-1]
        ema200 = features["ema200"]
        trend_up = close > ema200
        trend_down = close < ema200

        # Momentum breakout (20-bar high/low with strong candle)
        high20 = df['high'].iloc[-21:-1].max()
        low20 = df['low'].iloc[-21:-1].min()
        last_close = df['close'].iloc[-2]
        last_open = df['open'].iloc[-2]
        last_body = abs(last_close - last_open)
        atr = features["atr"]
        momentum = last_body > atr * 0.7

        if trend_up and last_close > high20 and momentum:
            #print("    [DEBUG] Bullish momentum breakout detected.")
            return 'buy'
        if trend_down and last_close < low20 and momentum:
            #print("    [DEBUG] Bearish momentum breakout detected.")
            return 'sell'

        # Trend pullback entry (RSI pullback in trend direction)
        rsi = features["rsi"]
        if trend_up and rsi < 45 and last_close > last_open:
            #print("    [DEBUG] Trend pullback buy detected.")
            return 'buy'
        if trend_down and rsi > 55 and last_close < last_open:
            #print("    [DEBUG] Trend pullback sell detected.")
            return 'sell'

        # --- NEW ENTRY PATTERNS FOR TREND/MOMENTUM ---
        # 1. EMA20/EMA50 bounce in trend direction
        if trend_up and abs(close - features["ema20"]) < atr * 0.5 and close > features["ema50"]:
            #print("    [DEBUG] EMA20 bounce in uptrend.")
            return 'buy'
        if trend_down and abs(close - features["ema20"]) < atr * 0.5 and close < features["ema50"]:
            #print("    [DEBUG] EMA20 bounce in downtrend.")
            return 'sell'
        
        # 2. Any close above EMA20 (trend up) or below EMA20 (trend down)
        if close > features["ema20"]:
            #print("    [DEBUG] Close above EMA20 (trend/momentum, ultra-permissive).")
            return 'buy'
        if close < features["ema20"]:
            #print("    [DEBUG] Close below EMA20 (trend/momentum, ultra-permissive).")
            return 'sell'
        
        return None
# === Add to ALL_STRATEGIES for switching/ensemble ===
class GPSForexRobot3Strategy(StrategyBase):
    """
    Mimics the core logic of GPS Forex Robot 3:
    - Trend-following entry
    - Tight SL/TP
    - Reverse trade on loss (recovery mode)
    """
    def __init__(self):
        super().__init__("GPSForexRobot3")
        self.last_trade_result = None
        self.recovery_mode = False
        self.recovery_direction = None

    def check(self, df, features):
        # Only trade EURUSD for GPS logic
        if 'symbol' in df.columns and df['symbol'].iloc[-1] != "EURUSD":
            return None

        close = df['close'].iloc[-1]
        ema50 = features['ema50']
        ema200 = features['ema200']
        trend_up = close > ema50 > ema200
        trend_down = close < ema50 < ema200

        # If in recovery mode, reverse the last direction
        if self.recovery_mode:
            return self.recovery_direction

        # Normal GPS logic: trend-following
        if trend_up:
            return "buy"
        elif trend_down:
            return "sell"
        else:
            return None

    def on_trade_close(self, result, direction):
        # If loss, activate recovery mode with reverse direction
        if result < 0:
            self.recovery_mode = True
            self.recovery_direction = "sell" if direction == "buy" else "buy"
        else:
            self.recovery_mode = False
            self.recovery_direction = None

