# === Walk-Forward Optimization ===

def check_for_overfit(model, df, n_train=100, n_test=100):
    """
    Check for overfitting by comparing train and test accuracy.
    """
    if df is None or len(df) < n_train + n_test + 20:
        print("[OVERFIT] Not enough data to check for overfit.")
        return
    # Split data
    train_df = df.iloc[:n_train]
    test_df = df.iloc[-n_test:]
    # Train accuracy
    correct_train = 0
    for i in range(20, len(train_df)):
        feats = get_features_fixed(train_df.iloc[:i])
        pred, _ = model.predict(feats)
        actual = 'buy' if train_df['close'].iloc[i] > train_df['close'].iloc[i-1] else 'sell' if train_df['close'].iloc[i] < train_df['close'].iloc[i-1] else 'hold'
        if pred == actual:
            correct_train += 1
    acc_train = correct_train / (len(train_df) - 20)
    # Test accuracy
    correct_test = 0
    for i in range(20, len(test_df)):
        feats = get_features_fixed(test_df.iloc[:i])
        pred, _ = model.predict(feats)
        actual = 'buy' if test_df['close'].iloc[i] > test_df['close'].iloc[i-1] else 'sell' if test_df['close'].iloc[i] < test_df['close'].iloc[i-1] else 'hold'
        if pred == actual:
            correct_test += 1
    acc_test = correct_test / (len(test_df) - 20)
    print(f"[OVERFIT] Train accuracy: {acc_train:.2%} | Test accuracy: {acc_test:.2%}")
    if acc_train - acc_test > 0.10:
        print("[OVERFIT] Warning: Model may be overfitting (train acc much higher than test acc).")
    else:
        print("[OVERFIT] No significant overfit detected.")

def walk_forward_retrain(model_path, data, labels, model_type="sklearn"):
    """
    Retrain the ML model on the most recent data and save it to disk.
    """
    if data is None or len(data) == 0 or labels is None or len(labels) == 0:
        print("[ERROR] No training data, skipping retrain.")
        return
    if model_type == "sklearn":
        from sklearn.ensemble import RandomForestClassifier
        model = RandomForestClassifier(n_estimators=100)
        model.fit(data, labels)
        pickle.dump(model, open(model_path, "wb"))
    elif model_type == "xgboost":
        import xgboost as xgb
        model = xgb.XGBClassifier(n_estimators=100)
        model.fit(data, labels)
        model.save_model(model_path)
    # Add more model types as needed
    print(f"[WALK-FORWARD] Model retrained and saved to {model_path}")

def periodic_walk_forward_retrain(model_path, get_training_data_func, retrain_interval_hours=24, model_type="sklearn"):
    """
    Periodically retrain the ML model every N hours.
    """
    import threading
    import time
    def retrain_loop():
        while True:
            result = get_training_data_func()
            if not result or not isinstance(result, (tuple, list)) or len(result) != 2:
                print("[RETRAIN] No training data returned, skipping retrain cycle.")
                time.sleep(retrain_interval_hours * 3600)
                continue
            data, labels = result
            walk_forward_retrain(model_path, data, labels, model_type)
            print(f"[WALK-FORWARD] Model retrained and saved to {model_path} at { datetime.now(timezone.utc)}")
            # Sleep for the specified interval (e.g., 24*7=168 for weekly, 24*30=720 for monthly)
            time.sleep(retrain_interval_hours * 3600)
    threading.Thread(target=retrain_loop, daemon=True).start()


# Start auto-retraining thread (call this ONCE at startup)


def schedule_weekly_model_retraining(model_path, get_training_data_func, model_type="sklearn"):
    """
    Schedule model retraining to run automatically every week (168 hours).
    """
    periodic_walk_forward_retrain(
        model_path=model_path,
        get_training_data_func=get_training_data_func,
        retrain_interval_hours=168,  # 7 days * 24 hours
        model_type=model_type
    )

def schedule_monthly_model_retraining(model_path, get_training_data_func, model_type="sklearn"):
    """
    Schedule model retraining to run automatically every month (approx 30 days).
    """
    periodic_walk_forward_retrain(
        model_path=model_path,
        get_training_data_func=get_training_data_func,
        retrain_interval_hours=720,  # 30 days * 24 hours
        model_type=model_type
    )

