# === Ensemble/Stacked ML Model Support ===

class EnsembleMLModel:
    """
    Example ensemble model: majority vote of multiple models.
    """
    def __init__(self, model_paths, model_types):
        self.models = []
        for path, typ in zip(model_paths, model_types):
            try:
                if typ == "sklearn":
                    import joblib
                    self.models.append(joblib.load(path))
                elif typ == "xgboost":
                    import xgboost as xgb
                    self.models.append(xgb.Booster(model_file=path))
                elif typ == "lightgbm":
                    import lightgbm as lgb
                    self.models.append(lgb.Booster(model_file=path))
                else:
                    raise ValueError(f"Unknown model type: {typ}")
            except Exception as e:
                print(f"[WARNING] Could not load {path}: {e}")

    def predict(self, features):
        votes = []
        confidences = []
        for model in self.models:
            if isinstance(features, dict) and any(isinstance(v, dict) for v in features.values()):
                # Flatten nested dicts if present
                flat_features = {}
                for k, v in features.items():
                    if isinstance(v, dict):
                        for subk, subv in v.items():
                            flat_features[f"{k}_{subk}"] = subv
                    else:
                        flat_features[k] = v
                features = flat_features
            # Defensive: Convert features dict to a 2D array for sklearn
            
            votes.append(signal)
            try:
                confidences.append(confidence)
            except NameError:
                confidences.append(0.5)  # Fallback confidence
        # Majority vote
        if not votes:
            return "hold", 0.0
        signal = max(set(votes), key=votes.count)
        avg_conf = sum(confidences) / len(confidences)
        return signal, avg_conf

# === ADVANCED ML & FILTERING TIPS FOR HIGHER WINRATE ===

def advanced_feature_engineering(df, news_sentiment=None, symbol=None):
    """
    Add advanced features for ML model to improve winrate, including:
    - Candle patterns, session/time, volatility, trend, orderflow, liquidity, multi-timeframe
    - News and sentiment analysis
    - Reinforcement learning state features (optional)
    - Structure features: FVG, BOS, displacement, liquidity sweep, order blocks, etc.
    """
    features = get_features_fixed(df)

    # --- Advanced Structure Detection ---
    # 1. Displacement
    displacement = detect_displacement(df)
    features["displacement_strength"] = "strong" if displacement else "weak"

    # 2. FVG detection (returns dict or None)
    fvg_info = detect_fvg(df)
    if fvg_info:
        features["fvg"] = fvg_info["direction"] if "direction" in fvg_info else "none"
        features["displacement_strength"] = fvg_info.get("displacement_strength", "weak")
        features["bos"] = "yes" if fvg_info.get("bos", False) else "none"
        features["institutional_move"] = fvg_info.get("institutional_move", False)
        features["volume_spike"] = fvg_info.get("volume_spike", False)
        features["fvg_zone"] = fvg_info.get("fvg", None)
    else:
        features["fvg"] = "none"
        features["displacement_strength"] = "weak"
        features["bos"] = "none"
        features["institutional_move"] = False
        features["volume_spike"] = False
        features["fvg_zone"] = None

    # 3. Liquidity Sweep
    sweep = detect_liquidity_sweep(df)
    features["liquidity_sweep"] = "yes" if sweep else "none"

    # 4. Order Block detection (inside FVG zone)
    if fvg_info and fvg_info.get("fvg"):
        ob_zone = detect_order_block(df, fvg_info["fvg"], fvg_info["direction"])
        features["order_block"] = ob_zone if ob_zone else "none"
    else:
        features["order_block"] = "none"

    # --- Market Structure: BOS (Break of Structure) ---
    if len(df) > 5:
        swing_high = max(df['high'].iloc[-5:-1])
        swing_low = min(df['low'].iloc[-5:-1])
        last_close = df['close'].iloc[-1]
        if last_close > swing_high:
            features["bos"] = "bull"
        elif last_close < swing_low:
            features["bos"] = "bear"
        else:
            features["bos"] = "none"
    else:
        features["bos"] = "none"

    # --- Displacement Strength (large candle body relative to ATR) ---
    if len(df) > 2:
        body = abs(df['close'].iloc[-1] - df['open'].iloc[-1])
        atr = features.get("atr", 0.0001)
        features["displacement_strength"] = "strong" if body > 1.5 * atr else "weak"
    else:
        features["displacement_strength"] = "weak"

    # --- Order Blocks (simple: large volume + engulfing candle) ---
    if len(df) > 3:
        import talib
        engulfing = talib.CDLENGULFING(df['open'].values, df['high'].values, df['low'].values, df['close'].values)[-1]
        large_vol = df['volume'].iloc[-1] > 1.5 * df['volume'].iloc[-2]
        features["order_block"] = "buy" if engulfing > 0 and large_vol else "sell" if engulfing < 0 and large_vol else "none"
    else:
        features["order_block"] = "none"

    # --- Time and Session features already present ---
    # --- Volatility and risk management already present ---

    # --- Candlestick Pattern Detection ---
    import talib

    # List of all TA-Lib candlestick pattern function names
    talib_cdl_patterns = [
        "CDL2CROWS", "CDL3BLACKCROWS", "CDL3INSIDE", "CDL3LINESTRIKE", "CDL3OUTSIDE", "CDL3STARSINSOUTH",
        "CDL3WHITESOLDIERS", "CDLABANDONEDBABY", "CDLADVANCEBLOCK", "CDLBELTHOLD", "CDLBREAKAWAY",
        "CDLCLOSINGMARUBOZU", "CDLCONCEALBABYSWALL", "CDLCOUNTERATTACK", "CDLDARKCLOUDCOVER",
        "CDLDOJI", "CDLDOJISTAR", "CDLDRAGONFLYDOJI", "CDLENGULFING", "CDLEVENINGDOJISTAR",
        "CDLEVENINGSTAR", "CDLGAPSIDESIDEWHITE", "CDLGRAVESTONEDOJI", "CDLHAMMER", "CDLHANGINGMAN",
        "CDLHARAMI", "CDLHARAMICROSS", "CDLHIGHWAVE", "CDLHIKKAKE", "CDLHIKKAKEMOD", "CDLHOMINGPIGEON",
        "CDLIDENTICAL3CROWS", "CDLINNECK", "CDLINVERTEDHAMMER", "CDLKICKING", "CDLKICKINGBYLENGTH",
        "CDLLADDERBOTTOM", "CDLLONGLEGGEDDOJI", "CDLLONGLINE", "CDLMARUBOZU", "CDLMATCHINGLOW",
        "CDLMATHOLD", "CDLMORNINGDOJISTAR", "CDLMORNINGSTAR", "CDLONNECK", "CDLPIERCING",
        "CDLRICKSHAWMAN", "CDLRISEFALL3METHODS", "CDLSEPARATINGLINES", "CDLSHOOTINGSTAR",
        "CDLSHORTLINE", "CDLSPINNINGTOP", "CDLSTALLEDPATTERN", "CDLSTICKSANDWICH", "CDLTAKURI",
        "CDLTASUKIGAP", "CDLTHRUSTING", "CDLTRISTAR", "CDLUNIQUE3RIVER", "CDLUPSIDEGAP2CROWS",
        "CDLXSIDEGAP3METHODS"
    ]

    # Ensure we have enough bars for pattern detection
    if len(df) > 20:
        open_ = df['open'].values
        high_ = df['high'].values
        low_ = df['low'].values
        close_ = df['close'].values

        for pattern in talib_cdl_patterns:
            func = getattr(talib, pattern, None)
            if func is not None:
                try:
                    val = func(open_, high_, low_, close_)
                    # Some patterns are bullish/bearish (positive/negative), some just != 0
                    if pattern in ["CDLENGULFING", "CDL3LINESTRIKE", "CDLCOUNTERATTACK", "CDLMATHOLD"]:
                        features[pattern.lower() + "_bull"] = int(val[-2] > 0)
                        features[pattern.lower() + "_bear"] = int(val[-2] < 0)
                    else:
                        features[pattern.lower()] = int(val[-2] != 0)
                except Exception:
                    features[pattern.lower()] = 0
    # 2. Session/time features
    features["is_london"] = 7 <=  datetime.now(timezone.utc).hour < 16
    features["is_ny"] = 12 <=  datetime.now(timezone.utc).hour < 21
    features["is_asian"] = (22 <=  datetime.now(timezone.utc).hour or  datetime.now(timezone.utc).hour < 9)
    # 3. Volatility regime (high/low)
    features["is_high_vol"] = features["atr"] > np.median([features["atr"]] + [0.0001 for _ in range(19)])
    # 4. Trend strength (distance from EMA200)
    features["trend_strength"] = abs(features["ema200_dist"]) / features["ema200"]
    # 5. News and sentiment features
    if news_sentiment is not None:
        features["news_sentiment"] = news_sentiment.get(symbol, 0)
        features["is_high_impact_news"] = int(abs(news_sentiment.get(symbol, 0)) > 0.7)
    else:
        features["news_sentiment"] = 0
        features["is_high_impact_news"] = 0
    # 6. RL state features (optional, for RL agent)
    # features["open_trades"] = ... (number of open trades)
    # features["drawdown"] = ... (current drawdown)
    return features

# === Adaptive Risk Management Example ===
def adaptive_risk_management(symbol, features, account_info, base_risk_pct=0.01):
    """
    Adjust risk per trade based on volatility, news, and sentiment.
    """
    risk_pct = base_risk_pct
    # Reduce risk during high-impact news or negative sentiment
    if features.get("is_high_impact_news", 0):
        risk_pct *= 0.5
    if features.get("news_sentiment", 0) < -0.5:
        risk_pct *= 0.7
    # Increase risk in strong trends and positive sentiment
    if features.get("trend_strength", 0) > 0.003 and features.get("news_sentiment", 0) > 0.5:
        risk_pct *= 1.5
    # Cap risk
    risk_pct = min(max(risk_pct, 0.002), 0.03)
    try:
        lot = adaptive_lot_size(account_info.balance, risk_pct, features["atr"], symbol, abs(features["ema200_dist"]) / (0.0001 if "JPY" not in symbol else 0.01))
    except (NameError, TypeError, KeyError):
        lot = 0.01  # Fallback lot size
    return lot, risk_pct

# === Ensemble Model Example ===
class AdvancedEnsembleModel:
    """
    Combines multiple ML models (sklearn, xgboost, keras, RL agent) for robust signal generation.
    """
    def __init__(self, model_configs, rl_agent=None):
        self.models = []
        try:
            self.models = [RealMLModel(cfg["path"], cfg["type"]) for cfg in model_configs]
        except NameError:
            pass  # Fallback if RealMLModel not defined
        self.rl_agent = rl_agent  # Optional: pass a trained RL agent

    def predict(self, features):
        votes = []
        confidences = []
        for model in self.models:
            if isinstance(features, dict) and any(isinstance(v, dict) for v in features.values()):
                # Flatten nested dicts if present
                flat_features = {}
                for k, v in features.items():
                    if isinstance(v, dict):
                        for subk, subv in v.items():
                            flat_features[f"{k}_{subk}"] = subv
                    else:
                        flat_features[k] = v
                features = flat_features
            # Defensive: Convert features dict to a 2D array for sklearn
            if hasattr(model, "predict") and callable(model.predict):
                import numpy as np
                if hasattr(model, "feature_names_in_"):
                    feature_names = list(model.feature_names_in_)
                else:
                    feature_names = [
                        "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
                        "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
                        "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength",
                        "distance_from_tp", "minutes_left_session", "atr_squeeze", "atr_burst",
                        "macd", "macd_signal", "macd_hist", "obv", "divergence"
                    ][:model.n_features_in_ if hasattr(model, "n_features_in_") else 20]
                X = np.array([[features.get(k, 0) for k in feature_names]])
                # If model is a custom model (like MockMLModel), pass features dict, not X
                if hasattr(model, "is_custom") and model.is_custom:
                    signal, confidence = model.predict(features)
                else:
                    pred = model.predict(X)
                    if hasattr(model, "predict_proba"):
                        proba = model.predict_proba(X)[0]
                        pred_idx = pred[0] if hasattr(pred, "__getitem__") else pred
                        if isinstance(pred_idx, str):
                            label_map = getattr(model, "label_map", {"hold": 0, "buy": 1, "sell": 2})
                            pred_idx = label_map.get(pred_idx, 0)
                        confidence = proba[int(pred_idx)] if int(pred_idx) < len(proba) else max(proba)
                        signal = getattr(model, "label_map", {0: "hold", 1: "buy", 2: "sell"}).get(pred[0], pred[0])
                    else:
                        signal, confidence = pred[0], 1.0
            else:
                signal, confidence = model.predict(features)   # Replace with your own prediction logic
            votes.append(signal)
            confidences.append(confidence)
        # RL agent vote (if available)
        if self.rl_agent is not None:
            rl_signal, rl_conf = self.rl_agent.predict(features)
            votes.append(rl_signal)
            confidences.append(rl_conf)
        # Majority vote
        signal = max(set(votes), key=votes.count)
        avg_conf = sum(confidences) / len(confidences)
        return signal, avg_conf

