def test_strategy_on_symbol(strategy_func, symbol, bars=2000):
    """
    Backtest a given strategy function on a symbol and print winrate, avg win/loss, and drawdown.
    """
    df = get_backtest_data(symbol, bars=bars)
    if df is None or len(df) < 200:
        print(f"[TEST] Not enough data for {symbol}")
        return
    wins, losses, total, pnl, max_dd = 0, 0, 0, 0, 0
    equity = 0
    peak = 0
    for i in range(100, len(df)):
        window = df.iloc[:i+1]
        features = get_features_fixed(window)
        signal = strategy_func(window, features)
        if signal not in ("buy", "sell"):
            continue
        entry = window['close'].iloc[-1]
        atr = features["atr"]
        sl = entry - SL_ATR_MULTIPLIER * atr if signal == "buy" else entry + SL_ATR_MULTIPLIER * atr
        tp = entry + TP_ATR_MULTIPLIER * atr if signal == "buy" else entry - TP_ATR_MULTIPLIER * atr
        # Simulate trade exit
        high = window['high'].iloc[-1]
        low = window['low'].iloc[-1]
        if signal == "buy":
            if low <= sl:
                result = sl - entry
            elif high >= tp:
                result = tp - entry
            else:
                continue
        else:
            if high >= sl:
                result = entry - sl
            elif low <= tp:
                result = entry - tp
            else:
                continue
        pnl += result
        equity += result
        peak = max(peak, equity)
        dd = peak - equity
        max_dd = max(max_dd, dd)
        if result > 0:
            wins += 1
        else:
            losses += 1
        total += 1
    winrate = wins / total * 100 if total else 0
    avg_win = pnl / wins if wins else 0
    avg_loss = pnl / losses if losses else 0
    print(f"[TEST] {strategy_func.__name__} on {symbol}: Trades={total}, Winrate={winrate:.2f}%, AvgWin={avg_win:.2f}, AvgLoss={avg_loss:.2f}, MaxDD={max_dd:.2f}, NetPnL={pnl:.2f}")

