        print(f"[ENTRY DEBUG] {symbol} | ML: {ml_signal} | Confidence: {confidence:.2f} "
              f"| Pattern: {pattern_signal} (src={pattern_src}) | Bullish: {bullish_score} | Bearish: {bearish_score} "
              f"| SessionOK: {session_ok} | FVG: {fvg_status} | BOS: {bos_status} | Displacement: {displacement_status} | LiquiditySweep: {liquidity_sweep_status} | OrderBlock: {order_block_status} | VolatilityOK: {volatility_ok}")

