            print(f"    Filter 5 (BOS Strength): ⚠️ BOS strength {bos_strength}/100 ({bos_quality}) - Below minimum 70")
            print(f"    ❌ BLOCKED by Filter 5 - Trade cancelled (BOS too weak)")
            print(f"    💡 Thresholds: 60=Okay, 70+=Strong, 80+=A+ Trades")
