        print(f"    Filter 5 (BOS Strength): ✅ BOS {bos_quality} - Level: ${bos_level:.5f}")
        
        # 🚨 NEW: APPLY 4 ELITE INSTITUTION-GRADE FILTERS (Filters 6-9) ---
        print(f"\n[🚨 ELITE FILTERS 6-9] Checking 4 pro-level filters for {symbol}...")
        
        # Filter 6: Displacement Requirement
        filter6_result = check_displacement(df, ml_signal)
