        # TEMPORARILY DISABLED - Filter 8 too strict (requires BOTH sweep AND BOS)
        filter8_result = {'passed': True, 'reason': '⏭️ SKIPPED: Filter 8 temporarily disabled'}
        
        # --- HYBRID APPROACH: ATR SL + FIBONACCI TP ---
        direction = ml_signal  # <--- FIX: define direction for use below
        entry = mt5.symbol_info_tick(symbol).ask if direction == "buy" else mt5.symbol_info_tick(symbol).bid
        
        # ✅ STOP LOSS: Use ATR (tight, mechanical protection)
        sl = entry - SL_ATR_MULTIPLIER * atr if direction == "buy" else entry + SL_ATR_MULTIPLIER * atr
        
        # ✅ TAKE PROFIT: Use Fibonacci Extension (targets natural structure levels)
        # Find recent swing high and low for Fibonacci calculation
        recent_high = df['high'].tail(20).max()
        recent_low = df['low'].tail(20).min()
        fib_range = recent_high - recent_low
        
        if direction == "buy":
            # For BUY: TP at Fibonacci 1.618 extension above swing low
            tp = recent_low + 1.618 * fib_range
        else:
            # For SELL: TP at Fibonacci 1.618 extension below swing high
            tp = recent_high - 1.618 * fib_range

        # RR check
        risk = abs(entry - sl)
        reward = abs(tp - entry)
        rr = reward / risk if risk > 0 else 0
        
        # Filter 9: ELITE ENTRY QUALITY SCORE (0-10)
        sweep_reclaimed = filter3_result.get('sweep_reclaimed', False)  # ✅ NOW AVAILABLE from Filter 3
        htf_aligned = filter1_result.get('passed', False)
        
