def count_open_positions_for_symbol(symbol):
    """
    Counts the number of open positions for a given symbol.
    Returns the count of open positions (0 if no positions or error).
    """
    try:
        positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
        if not positions:
            return 0
        symbol_positions = [p for p in positions if p.symbol == symbol]
        return len(symbol_positions)
    except Exception as e:
        print(f"[ERROR] Failed to count open positions for {symbol}: {e}")
        return 0

def validate_filters_for_multi_entry(symbol, signal, features, df=None):
    """
    Validates that ALL critical filters are STILL in agreement before allowing a 2nd+ entry on same symbol.
    
    For 2nd entries, we enforce STRICTER requirements to ensure confluence hasn't changed.
    Only proceeds if all core filters validate:
    - FVG presence and direction alignment
    - HTF bias alignment
    - Consolidation/chopiness check
    - Structure confirmation
    - Trend confirmation
    
    Returns: (all_filters_agree: bool, reason: str, filter_details: dict)
    """
    filter_details = {}
    
    try:
        # ✅ FILTER 1: FVG VALIDATION
        fvg_status = features.get("fvg", None)
        if fvg_status is None or fvg_status == "none":
            return False, "[MULTI-ENTRY] FVG no longer present—cannot add 2nd entry", filter_details
        
        direction_map = {"bull": "buy", "bear": "sell"}
        fvg_direction = direction_map.get(fvg_status, None)
        if fvg_direction and signal in ("buy", "sell") and fvg_direction != signal:
            return False, f"[MULTI-ENTRY] FVG direction ({fvg_direction}) no longer agrees with signal ({signal})—cannot add 2nd entry", filter_details
        
        filter_details['fvg'] = 'agreement'
        
        # ✅ FILTER 2: PRICE IN FVG ZONE
        fvg_zone = features.get("fvg_zone", None)
        price = features.get("close", None)
        if fvg_zone and price is not None:
            zone_low = fvg_zone.get("low", None)
            zone_high = fvg_zone.get("high", None)
            if zone_low is not None and zone_high is not None:
                if not (zone_low <= price <= zone_high):
                    return False, f"[MULTI-ENTRY] Price {price:.5f} no longer in FVG zone {zone_low:.5f}-{zone_high:.5f}—cannot add 2nd entry", filter_details
        
        filter_details['fvg_zone'] = 'in_zone'
        
        # ✅ FILTER 3: HTF BIAS VALIDATION
        if symbol:
            htf_valid, htf_reason = check_htf_bias_filter(symbol, signal)
            if not htf_valid:
                return False, f"[MULTI-ENTRY] HTF bias no longer aligned: {htf_reason}—cannot add 2nd entry", filter_details
            filter_details['htf_bias'] = 'aligned'
        
        # ✅ FILTER 4: CONSOLIDATION CHECK
        if df is not None and not df.empty:
            chop_valid, chop_reason = check_consolidation_filter(df, lookback=20, chop_threshold=45)
            if not chop_valid:
                return False, f"[MULTI-ENTRY] Consolidation filter broken: {chop_reason}—cannot add 2nd entry", filter_details
            filter_details['consolidation'] = 'passed'
        
        # ✅ FILTER 5: STRUCTURE CONFIRMATION
        if df is not None and not df.empty:
            struct_valid, struct_reason = check_structure_break_confirmation(df, signal, lookback=20)
            if not struct_valid:
                return False, f"[MULTI-ENTRY] Structure no longer confirmed: {struct_reason}—cannot add 2nd entry", filter_details
            filter_details['structure'] = 'confirmed'
        
        # ✅ FILTER 6: TREND CONFIRMATION (EMA)
        ema50 = features.get("ema50")
        ema200 = features.get("ema200")
        last_close = features.get("close", None)
        
        if last_close and ema50 is not None and ema200 is not None:
            trend_up = last_close > ema50 > ema200
            trend_down = last_close < ema50 < ema200
            
            if (signal == "buy" and not trend_up) or (signal == "sell" and not trend_down):
                trend_status = "UP" if trend_up else "DOWN" if trend_down else "NEUTRAL"
                return False, f"[MULTI-ENTRY] Trend {trend_status} no longer aligns with {signal}—cannot add 2nd entry", filter_details
            filter_details['trend'] = 'aligned'
        
        # ✅ FILTER 7: SELL-SPECIFIC VALIDATION (Pullback + Premium + Structure)
        if signal == "sell" and df is not None and not df.empty:
            pullback_valid, _ = validate_sell_pullback(df, lookback=20)
            if not pullback_valid:
                return False, "[MULTI-ENTRY] SELL pullback validation failed—cannot add 2nd entry", filter_details
            
            at_premium, zone_info = is_at_premium_zone(df, symbol, lookback=50)
            if not at_premium:
                return False, f"[MULTI-ENTRY] SELL premium zone broken (at {zone_info.get('price_position_pct', 0):.1f}%)—cannot add 2nd entry", filter_details
            
            structure_confirmed, _ = confirm_bearish_structure(df, lookback=10)
            if not structure_confirmed:
                return False, "[MULTI-ENTRY] SELL bearish structure no longer confirmed—cannot add 2nd entry", filter_details
            
            filter_details['sell_structure'] = 'confirmed'
        
        # ✅ FILTER 8: BUY-SPECIFIC VALIDATION (Pullback + Discount + Structure)
        if signal == "buy" and df is not None and not df.empty:
            pullback_valid, _ = validate_buy_pullback(df, lookback=20)
            if not pullback_valid:
                return False, "[MULTI-ENTRY] BUY pullback validation failed—cannot add 2nd entry", filter_details
            
            at_discount, zone_info = is_at_discount_zone(df, symbol, lookback=50)
            if not at_discount:
                return False, f"[MULTI-ENTRY] BUY discount zone broken (at {zone_info.get('price_position_pct', 0):.1f}%)—cannot add 2nd entry", filter_details
            
            structure_confirmed, _ = confirm_bullish_structure(df, lookback=10)
            if not structure_confirmed:
                return False, "[MULTI-ENTRY] BUY bullish structure no longer confirmed—cannot add 2nd entry", filter_details
            
            filter_details['buy_structure'] = 'confirmed'
        
        # ✅ ALL FILTERS PASSED
        return True, "[MULTI-ENTRY] ✅ All filters still in agreement - 2nd entry approved", filter_details
        
    except Exception as e:
        print(f"[ERROR] validate_filters_for_multi_entry({symbol}): {e}")
        return False, f"[MULTI-ENTRY] Validation error: {str(e)}", filter_details

def can_enter_symbol(symbol, max_entries_per_symbol=5, signal=None, features=None, df=None):
    """
    Checks if we can enter a new position for the given symbol.
    
    For 2nd+ entries, ALSO validates that all filters are still in agreement.
    Returns (can_enter: bool, reason: str)
    
    Parameters:
    - symbol: The trading symbol (e.g., 'EURUSD')
    - max_entries_per_symbol: Maximum number of concurrent entries allowed per symbol (default: 5)
    - signal: The trade signal ('buy' or 'sell') - required for 2nd entry filter validation
    - features: Feature dict from ML model - required for 2nd entry filter validation
    - df: DataFrame with price data - required for 2nd entry filter validation
    """
    open_count = count_open_positions_for_symbol(symbol)
    if open_count >= max_entries_per_symbol:
        return False, f"Max {max_entries_per_symbol} entries per symbol reached. Currently have {open_count} open position(s) for {symbol}"
    
    # ✅ FOR 2ND+ ENTRIES: VALIDATE THAT ALL FILTERS STILL AGREE
    if open_count >= 1:  # We already have 1+ positions, so this is a 2nd+ entry
        if signal and features:
            filters_agree, filter_reason, _ = validate_filters_for_multi_entry(symbol, signal, features, df)
            if not filters_agree:
                print(f"❌ [2ND ENTRY CHECK] {filter_reason}")
                return False, filter_reason
            print(f"✅ [2ND ENTRY CHECK] {filter_reason}")
        else:
            # If no signal/features provided, allow with warning
            print(f"⚠️ [2ND ENTRY CHECK] No filter data provided for {symbol}, allowing based on position count only")
    
    return True, f"Can enter ({open_count}/{max_entries_per_symbol} entries used)"

def validate_sell_pullback(df, lookback=20):
    """
    Validates SELL entry by checking:
    1. Price is NOT making higher lows (no uptrend)
    2. Momentum is NOT bullish into entry
    3. Recent structure supports bearish move
    
    Returns (is_valid: bool, reason: str)
    """
    if df is None or len(df) < lookback:
        return False, "Insufficient bars for pullback validation"
    
    recent = df.iloc[-lookback:].copy()
    lows = recent['low'].values
    highs = recent['high'].values
    closes = recent['close'].values
    
    # Check: Are recent lows HIGHER (making higher lows = bullish, DON'T SELL)
    if len(lows) >= 3:
        recent_lows = lows[-3:]
        is_making_higher_lows = all(recent_lows[i] < recent_lows[i+1] for i in range(len(recent_lows)-1))
        if is_making_higher_lows:
            return False, "SELL BLOCKED: Price making higher lows (uptrend protection)"
    
    # Check: Momentum into entry (RSI, MACD slope)
    if len(closes) >= 5:
        recent_closes = closes[-5:]
        momentum_up = all(recent_closes[i] <= recent_closes[i+1] for i in range(len(recent_closes)-1))
        if momentum_up:
            return False, "SELL BLOCKED: Bullish momentum into entry zone"
    
    # Check: Recent swing low exists (pullback target)
    recent_lows_indexed = list(zip(range(len(lows)), lows))
    swing_lows = sorted(recent_lows_indexed, key=lambda x: x[1])[:2]  # 2 lowest lows
    
    if len(swing_lows) > 1:
        swing_low_price = swing_lows[-1][1]
        current_price = closes[-1]
        pullback_range = current_price - swing_low_price
        
        if pullback_range < 0:
            return False, "SELL BLOCKED: No valid pullback zone found"
        
        print(f"[SELL VALIDATION] Pullback zone confirmed: Low={swing_low_price:.5f}, Current={current_price:.5f}, Range={pullback_range:.5f}")
    
    return True, "SELL APPROVED: Pullback structure valid"

def is_at_premium_zone(df, symbol, lookback=50):
    """
    Validates SELL by checking if price is at PREMIUM zone (recent highs/supply).
    Don't sell in the middle of a move - only at extremes.
    
    Returns (at_premium: bool, zone_info: dict)
    """
    if df is None or len(df) < lookback:
        return False, {}
    
    recent = df.iloc[-lookback:].copy()
    highs = recent['high'].values
    closes = recent['close'].values
    
    current_price = closes[-1]
    recent_high = highs.max()
    recent_low = highs.min()
    
    # Calculate where price is in recent range
    range_size = recent_high - recent_low
    price_position = (current_price - recent_low) / range_size if range_size > 0 else 0.5
    
    # SELL at top 25% (premium zone)
    at_premium = price_position > 0.75
    
    zone_info = {
        "current_price": current_price,
        "recent_high": recent_high,
        "recent_low": recent_low,
        "price_position_pct": price_position * 100,
        "at_premium": at_premium
    }
    
    if at_premium:
        distance_from_high = recent_high - current_price
        print(f"[PREMIUM ZONE] {symbol} at {price_position*100:.1f}% of range. Distance from high: {distance_from_high:.5f}")
    else:
        print(f"[DISCOUNT ZONE WARNING] {symbol} at {price_position*100:.1f}% of range. Too close to lows - risky SELL")
        return False, zone_info
    
    return True, zone_info

def confirm_bearish_structure(df, lookback=10):
    """
    Confirms SELL entry structure:
    1. Lower High formed (HH to LH - reversal signal)
    2. Bearish confirmation candle (close below open, momentum down)
    
    Returns (confirmed: bool, structure: dict)
    """
    if df is None or len(df) < lookback:
        return False, {}
    
    recent = df.iloc[-lookback:].copy()
    highs = recent['high'].values
    opens = recent['open'].values
    closes = recent['close'].values
    
    structure = {
        "lower_high_found": False,
        "bearish_candle_found": False,
        "structure_confirmed": False,
        "reasons": []
    }
    
    # Check for Lower High (HH to LH pattern)
    if len(highs) >= 3:
        prev_hh = highs[-3]
        current_high = highs[-1]
        
        if current_high < prev_hh:
            structure["lower_high_found"] = True
            structure["reasons"].append(f"Lower High: {prev_hh:.5f} → {current_high:.5f}")
            print(f"[STRUCTURE] Lower High confirmed: {prev_hh:.5f} → {current_high:.5f}")
        else:
            structure["reasons"].append(f"No Lower High: Current {current_high:.5f} >= Previous {prev_hh:.5f}")
    
    # Check for Bearish Confirmation Candle
    if len(opens) > 0 and len(closes) > 0:
        current_open = opens[-1]
        current_close = closes[-1]
        prev_close = closes[-2] if len(closes) > 1 else current_open
        
        is_bearish_candle = current_close < current_open
        has_momentum = (prev_close - current_close) > abs(current_open - current_close) * 0.5
        
        if is_bearish_candle:
            structure["bearish_candle_found"] = True
            structure["reasons"].append("Bearish candle (close < open)")
            print(f"[CANDLE] Bearish confirmation: Close {current_close:.5f} < Open {current_open:.5f}")
        
        if has_momentum:
            structure["reasons"].append("Strong bearish momentum")
    
    # Overall confirmation: need BOTH conditions
    structure["structure_confirmed"] = structure["lower_high_found"] and structure["bearish_candle_found"]
    
    if structure["structure_confirmed"]:
        print(f"[STRUCTURE CONFIRMED] ✅ Lower High + Bearish Candle = Valid SELL setup")
    else:
        print(f"[STRUCTURE WAITING] ⏳ Missing: Lower High={structure['lower_high_found']}, Bearish Candle={structure['bearish_candle_found']}")
    
    return structure["structure_confirmed"], structure

def validate_buy_pullback(df, lookback=20):
    """
    Validates BUY entry by checking:
    1. Price is NOT making lower highs (no downtrend)
    2. Momentum is NOT bearish into entry
    3. Recent structure supports bullish move
    
    Returns (is_valid: bool, reason: str)
    """
    if df is None or len(df) < lookback:
        return False, "Insufficient bars for pullback validation"
    
    recent = df.iloc[-lookback:].copy()
    lows = recent['low'].values
    highs = recent['high'].values
    closes = recent['close'].values
    
    # Check: Are recent highs LOWER (making lower highs = bearish, DON'T BUY)
    if len(highs) >= 3:
        recent_highs = highs[-3:]
        is_making_lower_highs = all(recent_highs[i] > recent_highs[i+1] for i in range(len(recent_highs)-1))
        if is_making_lower_highs:
            return False, "BUY BLOCKED: Price making lower highs (downtrend protection)"
    
    # Check: Momentum into entry (RSI, MACD slope)
    if len(closes) >= 5:
        recent_closes = closes[-5:]
        momentum_down = all(recent_closes[i] >= recent_closes[i+1] for i in range(len(recent_closes)-1))
        if momentum_down:
            return False, "BUY BLOCKED: Bearish momentum into entry zone"
    
    # Check: Recent swing high exists (pullback target)
    recent_highs_indexed = list(zip(range(len(highs)), highs))
    swing_highs = sorted(recent_highs_indexed, key=lambda x: x[1])[-2:]  # 2 highest highs
    
    if len(swing_highs) > 1:
        swing_high_price = swing_highs[-1][1]
        current_price = closes[-1]
        pullback_range = swing_high_price - current_price
        
        if pullback_range < 0:
            return False, "BUY BLOCKED: No valid pullback zone found"
        
        print(f"[BUY VALIDATION] Pullback zone confirmed: High={swing_high_price:.5f}, Current={current_price:.5f}, Range={pullback_range:.5f}")
    
    return True, "BUY APPROVED: Pullback structure valid"

def is_at_discount_zone(df, symbol, lookback=50):
    """
    Validates BUY by checking if price is at DISCOUNT zone (recent lows/demand).
    Don't buy in the middle of a move - only at extremes (support zones).
    
    Returns (at_discount: bool, zone_info: dict)
    """
    if df is None or len(df) < lookback:
        return False, {}
    
    recent = df.iloc[-lookback:].copy()
    highs = recent['high'].values
    lows = recent['low'].values
    closes = recent['close'].values
    
    current_price = closes[-1]
    recent_high = highs.max()
    recent_low = lows.min()
    
    # Calculate where price is in recent range
    range_size = recent_high - recent_low
    price_position = (current_price - recent_low) / range_size if range_size > 0 else 0.5
    
    # BUY at bottom 25% (discount zone)
    at_discount = price_position < 0.25
    
    zone_info = {
        "current_price": current_price,
        "recent_high": recent_high,
        "recent_low": recent_low,
        "price_position_pct": price_position * 100,
        "at_discount": at_discount
    }
    
    if at_discount:
        distance_from_low = current_price - recent_low
        print(f"[DISCOUNT ZONE] {symbol} at {price_position*100:.1f}% of range. Distance from low: {distance_from_low:.5f}")
    else:
        print(f"[PREMIUM ZONE WARNING] {symbol} at {price_position*100:.1f}% of range. Too close to highs - risky BUY")
        return False, zone_info
    
    return True, zone_info

def confirm_bullish_structure(df, lookback=10):
    """
    Confirms BUY entry structure:
    1. Higher Low formed (LL to HL - reversal signal)
    2. Bullish confirmation candle (close above open, momentum up)
    
    Returns (confirmed: bool, structure: dict)
    """
    if df is None or len(df) < lookback:
        return False, {}
    
    recent = df.iloc[-lookback:].copy()
    lows = recent['low'].values
    opens = recent['open'].values
    closes = recent['close'].values
    
    structure = {
        "higher_low_found": False,
        "bullish_candle_found": False,
        "structure_confirmed": False,
        "reasons": []
    }
    
    # Check for Higher Low (LL to HL pattern)
    if len(lows) >= 3:
        prev_ll = lows[-3]
        current_low = lows[-1]
        
        if current_low > prev_ll:
            structure["higher_low_found"] = True
            structure["reasons"].append(f"Higher Low: {prev_ll:.5f} → {current_low:.5f}")
            print(f"[STRUCTURE] Higher Low confirmed: {prev_ll:.5f} → {current_low:.5f}")
        else:
            structure["reasons"].append(f"No Higher Low: Current {current_low:.5f} <= Previous {prev_ll:.5f}")
    
    # Check for Bullish Confirmation Candle
    if len(opens) > 0 and len(closes) > 0:
        current_open = opens[-1]
        current_close = closes[-1]
        prev_close = closes[-2] if len(closes) > 1 else current_open
        
        is_bullish_candle = current_close > current_open
        has_momentum = (current_close - prev_close) > abs(current_close - current_open) * 0.5
        
        if is_bullish_candle:
            structure["bullish_candle_found"] = True
            structure["reasons"].append("Bullish candle (close > open)")
            print(f"[CANDLE] Bullish confirmation: Close {current_close:.5f} > Open {current_open:.5f}")
        
        if has_momentum:
            structure["reasons"].append("Strong bullish momentum")
    
    # Overall confirmation: need BOTH conditions
    structure["structure_confirmed"] = structure["higher_low_found"] and structure["bullish_candle_found"]
    
    if structure["structure_confirmed"]:
        print(f"[STRUCTURE CONFIRMED] ✅ Higher Low + Bullish Candle = Valid BUY setup")
    else:
        print(f"[STRUCTURE WAITING] ⏳ Missing: Higher Low={structure['higher_low_found']}, Bullish Candle={structure['bullish_candle_found']}")
    
    return structure["structure_confirmed"], structure

