# 🎯 PROBABILITY GATE SYSTEM (Retail Bot → Funded-Ready Bot Transformation)
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════

def calculate_entry_probability(df, symbol, direction, entry_price, features=None):
    """
    PROBABILITY SCORING SYSTEM
    Scores entry quality: 0-100 scale
    - 80+ = HIGH probability (execute immediately)
    - 60-79 = MEDIUM probability (wait for confirmation)
    - <60 = LOW probability (skip or wait for retest)
    
    Args:
        df: OHLC dataframe
        symbol: Trading symbol
        direction: 'buy' or 'sell'
        entry_price: Proposed entry price
        features: Additional feature dict
    
    Returns:
        (probability_score: 0-100, breakdown: dict)
    """
    try:
        if df is None or len(df) < 50:
            return 50, {"reason": "Insufficient data"}
        
        score = 0
        breakdown = {}
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        # FACTOR 1: Price at Support/Resistance (20 points max)
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        recent_50 = df.iloc[-50:].copy()
        support = recent_50['low'].min()
        resistance = recent_50['high'].max()
        
        if direction == "buy":
            distance_to_support = entry_price - support
            zone_size = (resistance - support) * 0.1
            
            # Score: closer to support = higher score
            if distance_to_support <= zone_size * 1.5:
                sr_score = 20
                breakdown["at_support"] = f"✅ AT SUPPORT (within {zone_size*1.5:.5f} of {support:.5f})"
            elif distance_to_support <= zone_size * 2.5:
                sr_score = 12
                breakdown["at_support"] = f"⚠️ NEAR SUPPORT (within {zone_size*2.5:.5f})"
            else:
                sr_score = 5
                breakdown["at_support"] = f"❌ FAR FROM SUPPORT ({distance_to_support:.5f} away)"
            score += sr_score
        
        else:  # sell
            distance_to_resistance = resistance - entry_price
            zone_size = (resistance - support) * 0.1
            
            if distance_to_resistance <= zone_size * 1.5:
                sr_score = 20
                breakdown["at_resistance"] = f"✅ AT RESISTANCE (within {zone_size*1.5:.5f} of {resistance:.5f})"
            elif distance_to_resistance <= zone_size * 2.5:
                sr_score = 12
                breakdown["at_resistance"] = f"⚠️ NEAR RESISTANCE (within {zone_size*2.5:.5f})"
            else:
                sr_score = 5
                breakdown["at_resistance"] = f"❌ FAR FROM RESISTANCE ({distance_to_resistance:.5f} away)"
            score += sr_score
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        # FACTOR 2: Trend Alignment (15 points max)
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        recent_close = df['close'].iloc[-1]
        lookback_20 = df['close'].iloc[-20]
        lookback_50 = df['close'].iloc[-50]
        
        if direction == "buy":
            trend_20 = "bullish" if recent_close > lookback_20 else "bearish"
            trend_50 = "bullish" if recent_close > lookback_50 else "bearish"
            
            if trend_20 == "bullish" and trend_50 == "bullish":
                trend_score = 15
                breakdown["trend"] = "✅ STRONG BULLISH (20b + 50b)"
            elif trend_20 == "bullish":
                trend_score = 10
                breakdown["trend"] = "⚠️ SHORT-TERM BULLISH (20b only)"
            else:
                trend_score = 0
                breakdown["trend"] = "❌ BEARISH TREND"
            score += trend_score
        
        else:  # sell
            trend_20 = "bearish" if recent_close < lookback_20 else "bullish"
            trend_50 = "bearish" if recent_close < lookback_50 else "bullish"
            
            if trend_20 == "bearish" and trend_50 == "bearish":
                trend_score = 15
                breakdown["trend"] = "✅ STRONG BEARISH (20b + 50b)"
            elif trend_20 == "bearish":
                trend_score = 10
                breakdown["trend"] = "⚠️ SHORT-TERM BEARISH (20b only)"
            else:
                trend_score = 0
                breakdown["trend"] = "❌ BULLISH TREND"
            score += trend_score
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        # FACTOR 3: Recent Volatility (15 points max)
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        atr = calculate_atr(df)
        close_price = df['close'].iloc[-1]
        atr_percent = (atr / close_price) * 100 if close_price > 0 else 0
        
        # Higher volatility = more confident entries (not too wild, not too dead)
        if 0.02 <= atr_percent <= 0.15:
            vol_score = 15
            breakdown["volatility"] = f"✅ OPTIMAL VOLATILITY ({atr_percent:.3f}%)"
        elif 0.01 <= atr_percent <= 0.25:
            vol_score = 10
            breakdown["volatility"] = f"⚠️ ACCEPTABLE VOLATILITY ({atr_percent:.3f}%)"
        else:
            vol_score = 3
            breakdown["volatility"] = f"❌ POOR VOLATILITY ({atr_percent:.3f}%)"
        score += vol_score
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        # FACTOR 4: Structure Confirmation (25 points max)
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        if direction == "buy":
            # Check for higher low pattern (bull structure)
            recent_30 = df.iloc[-30:].copy()
            lows = recent_30['low'].values
            
            higher_lows = sum([lows[i] > lows[i-1] for i in range(1, len(lows))])
            higher_low_ratio = higher_lows / len(lows)
            
            if higher_low_ratio >= 0.6:
                struct_score = 25
                breakdown["structure"] = f"✅ STRONG BULL STRUCTURE ({higher_low_ratio:.1%} higher lows)"
            elif higher_low_ratio >= 0.4:
                struct_score = 15
                breakdown["structure"] = f"⚠️ WEAK BULL STRUCTURE ({higher_low_ratio:.1%} higher lows)"
            else:
                struct_score = 5
                breakdown["structure"] = f"❌ NO BULL STRUCTURE ({higher_low_ratio:.1%} higher lows)"
            score += struct_score
        
        else:  # sell
            # Check for lower high pattern (bear structure)
            recent_30 = df.iloc[-30:].copy()
            highs = recent_30['high'].values
            
            lower_highs = sum([highs[i] < highs[i-1] for i in range(1, len(highs))])
            lower_high_ratio = lower_highs / len(highs)
            
            if lower_high_ratio >= 0.6:
                struct_score = 25
                breakdown["structure"] = f"✅ STRONG BEAR STRUCTURE ({lower_high_ratio:.1%} lower highs)"
            elif lower_high_ratio >= 0.4:
                struct_score = 15
                breakdown["structure"] = f"⚠️ WEAK BEAR STRUCTURE ({lower_high_ratio:.1%} lower highs)"
            else:
                struct_score = 5
                breakdown["structure"] = f"❌ NO BEAR STRUCTURE ({lower_high_ratio:.1%} lower highs)"
            score += struct_score
        
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        # FACTOR 5: Retest Confirmation (25 points max)
        # ═══════════════════════════════════════════════════════════════════════════════════════════════
        # Did price test the zone before entry? (Most important for funded traders)
        recent_5 = df.iloc[-5:].copy()
        
        if direction == "buy":
            # For buy: did price test support then bounce?
            support_touched = any(recent_5['low'] <= support * 1.001)
            if support_touched and recent_close > recent_5['low'].iloc[-2]:
                retest_score = 25
                breakdown["retest"] = "✅ CONFIRMED RETEST: Support touched + bounced"
            elif support_touched:
                retest_score = 15
                breakdown["retest"] = "⚠️ PARTIAL RETEST: Support touched but no bounce yet"
            else:
                retest_score = 5
                breakdown["retest"] = "❌ NO RETEST: Haven't tested support yet"
            score += retest_score
        
        else:  # sell
            # For sell: did price test resistance then reject?
            resistance_touched = any(recent_5['high'] >= resistance * 0.999)
            if resistance_touched and recent_close < recent_5['high'].iloc[-2]:
                retest_score = 25
                breakdown["retest"] = "✅ CONFIRMED RETEST: Resistance touched + rejected"
            elif resistance_touched:
                retest_score = 15
                breakdown["retest"] = "⚠️ PARTIAL RETEST: Resistance touched but no reject yet"
            else:
                retest_score = 5
                breakdown["retest"] = "❌ NO RETEST: Haven't tested resistance yet"
            score += retest_score
        
        breakdown["final_score"] = score
        breakdown["quality"] = "🟢 HIGH PROB" if score >= 80 else ("🟡 MEDIUM PROB" if score >= 60 else "🔴 LOW PROB")
        
        return min(100, score), breakdown
    
    except Exception as e:
        print(f"[PROB CALC ERROR] {symbol}: {e}")
        return 50, {"error": str(e)}

def wait_for_confirmation(symbol, direction, entry_price, max_wait_bars=10, check_interval=1):
    """
    CONFIRMATION WAITING MODE
    For medium-probability setups, wait for price to retest before executing
    
    This transforms the bot from:
    - ❌ "Signal → Execute immediately" (reactive = retail)
    - ✅ "Signal → Wait for retest → Execute" (confirmation = professional)
    
    Args:
        symbol: Trading symbol
        direction: 'buy' or 'sell'
        entry_price: Target entry zone
        max_wait_bars: How many bars to wait for retest
        check_interval: How often to check (in seconds)
    
    Returns:
        (confirmed: bool, retest_price: float or None)
    """
    bars_waited = 0
    print(f"[WAIT FOR CONFIRMATION] {symbol} {direction.upper()}: Waiting for retest at {entry_price:.5f}")
    
    while bars_waited < max_wait_bars and not stop_event.is_set():
        try:
            tick = safe_symbol_info_tick(symbol) if 'safe_symbol_info_tick' in globals() else (mt5.symbol_info_tick(symbol) if mt5 else None)
            if not tick:
                interruptible_sleep(check_interval)
                bars_waited += 1
                continue
            
            current_bid = tick.bid
            current_ask = tick.ask
            current_price = (current_bid + current_ask) / 2
            
            if direction == "buy":
                # For buy: waiting for retest DOWN to entry zone
                if current_bid <= entry_price * 1.002:  # Within 0.2% of entry
                    print(f"[CONFIRMATION ✅] {symbol} BUY: Retested at {current_bid:.5f} (target was {entry_price:.5f}) - READY TO EXECUTE")
                    return True, current_bid
            
            else:  # sell
                # For sell: waiting for retest UP to entry zone
                if current_ask >= entry_price * 0.998:  # Within 0.2% of entry
                    print(f"[CONFIRMATION ✅] {symbol} SELL: Retested at {current_ask:.5f} (target was {entry_price:.5f}) - READY TO EXECUTE")
                    return True, current_ask
            
            interruptible_sleep(check_interval)
            bars_waited += 1
        
        except Exception as e:
            print(f"[WAIT CONFIRMATION ERROR] {symbol}: {e}")
            interruptible_sleep(check_interval)
            bars_waited += 1
    
    print(f"[TIMEOUT] {symbol}: Waited {bars_waited} bars without retest confirmation")
    return False, None

# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
# 🧠 PROBABILITY GATE: The New Entry Decision Logic
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════

def should_execute_with_probability_gate(symbol, direction, entry_price, df, features=None, min_high_prob=80, min_medium_prob=60):
    """
    NEW DECISION LOGIC: Don't execute based on signals alone
    Execute based on PROBABILITY + CONFIRMATION
    
    Gate 1: Score ≥80 (HIGH) → Execute immediately
    Gate 2: Score 60-79 (MEDIUM) → Wait for retest, then execute
    Gate 3: Score <60 (LOW) → Skip this trade, wait for better setup
    
    Args:
        symbol, direction, entry_price: Trade details
        df: Price data
        features: Additional features
        min_high_prob: Threshold for immediate execution (default 80)
        min_medium_prob: Threshold for wait-and-confirm (default 60)
    
    Returns:
        (should_execute: bool, reason: str, prob_score: int)
    """
    prob_score, breakdown = calculate_entry_probability(df, symbol, direction, entry_price, features)
    
    print(f"\n🎯 PROBABILITY GATE DECISION")
    print(f"━" * 80)
    for key, val in breakdown.items():
        print(f"  {key}: {val}")
    print(f"━" * 80)
    print(f"FINAL SCORE: {prob_score}/100 | {breakdown['quality']}")
    print(f"━" * 80)
    
    if prob_score >= min_high_prob:
        print(f"✅ HIGH PROBABILITY ({prob_score}≥{min_high_prob}): Execute immediately (no wait needed)")
        return True, f"HIGH_PROB_EXECUTE", prob_score
    
    elif prob_score >= min_medium_prob:
        print(f"⏳ MEDIUM PROBABILITY ({min_medium_prob}≤{prob_score}<{min_high_prob}): Waiting for confirmation retest...")
        confirmed, retest_price = wait_for_confirmation(symbol, direction, entry_price, max_wait_bars=10)
        if confirmed:
            print(f"✅ RETEST CONFIRMED: Execute now at {retest_price:.5f}")
            return True, f"MEDIUM_PROB_CONFIRMED", prob_score
        else:
            print(f"❌ RETEST TIMEOUT: Setup expired, looking for better opportunity")
            return False, f"MEDIUM_PROB_TIMEOUT", prob_score
    
    else:
        print(f"❌ LOW PROBABILITY ({prob_score}<{min_medium_prob}): SKIPPING - Waiting for high-probability setup")
        return False, f"LOW_PROB_SKIP", prob_score

# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
# � RANGE FILTER - CRITICAL HARD BLOCKER (BLOCKS ALL TRADES IN RANGES)
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════

def detect_range_market(df, lookback=50):
    """
    ⭐ CRITICAL FILTER: Detects range-bound/consolidation markets
    
    Range-bound = NO directional progression, whipsaws guaranteed
    This is a HARD BLOCKER - no trades allowed in ranges
    
    Detection Criteria:
    1. NO HH/HL progression (buys blocked)
    2. NO LL/LH progression (sells blocked)
    3. Price stuck between equal highs/lows
    4. Low displacement (no strong moves)
    5. Chop Index high (choppy = no clarity)
    
    Returns:
    {
        'is_range': bool,
        'range_low': float,
        'range_high': float,
        'range_width': float,
        'structure_score': float (0-100, 0=clean range, 100=strong trend),
        'chop_index': float,
        'displacement_avg': float,
        'reason': str
    }
    """
    if df is None or len(df) < lookback + 5:
        return {
            'is_range': False,
            'range_low': None,
            'range_high': None,
            'range_width': None,
            'structure_score': 50,  # Unknown
            'chop_index': 50,
            'displacement_avg': 0,
            'reason': 'Insufficient data'
        }
    
    try:
        recent = df.iloc[-lookback:].copy()
        
        # METRIC 1: Structure Progression Analysis
        # Check for clean HH/HL (buy structure) or LL/LH (sell structure)
        highs = recent['high'].values
        lows = recent['low'].values
        
        # Count higher highs and lower lows
        higher_highs = sum([highs[i] > highs[i-1] for i in range(1, len(highs))])
        lower_lows = sum([lows[i] < lows[i-1] for i in range(1, len(lows))])
        lower_highs = sum([highs[i] < highs[i-1] for i in range(1, len(highs))])
        higher_lows = sum([lows[i] > lows[i-1] for i in range(1, len(lows))])
        
        hh_ratio = higher_highs / len(highs) if len(highs) > 0 else 0
        ll_ratio = lower_lows / len(lows) if len(lows) > 0 else 0
        lh_ratio = lower_highs / len(highs) if len(highs) > 0 else 0
        hl_ratio = higher_lows / len(lows) if len(lows) > 0 else 0
        
        # Strong structure = either HH+HL (bullish) OR LL+LH (bearish)
        bull_structure_score = (hh_ratio + hl_ratio) / 2 if (hh_ratio > 0.5 and hl_ratio > 0.5) else 0
        bear_structure_score = (ll_ratio + lh_ratio) / 2 if (ll_ratio > 0.5 and lh_ratio > 0.5) else 0
        structure_score = max(bull_structure_score, bear_structure_score) * 100  # 0-100
        
        # METRIC 2: Range Analysis
        range_high = recent['high'].max()
        range_low = recent['low'].min()
        range_width = range_high - range_low
        atr = (recent['high'] - recent['low']).mean()
        range_to_atr_ratio = range_width / atr if atr > 0 else 0
        
        # METRIC 3: Displacement (avg candle body)
        bodies = abs(recent['close'] - recent['open']).values
        displacement_avg = bodies.mean()
        avg_range = (recent['high'] - recent['low']).mean()
        displacement_pct = (displacement_avg / avg_range * 100) if avg_range > 0 else 0
        
        # METRIC 4: Chop Index (measures trendiness vs chop)
        # High Chop = choppy (equal highs/lows), Low Chop = trendy
        log_sum = np.sum(np.log10(abs(recent['high'] - recent['low']) + 1e-10))
        log_max = np.log10(recent['high'].max() - recent['low'].min() + 1e-10)
        chop_index = 100 * log_sum / (lookback * log_max) if log_max > 0 else 50
        
        # METRIC 5: Equal highs/lows detection (range signature)
        # Count how many unique highs/lows (low count = equal levels = range)
        unique_highs = len(np.unique(np.round(highs, 4)))  # Round to 4 decimals
        unique_lows = len(np.unique(np.round(lows, 4)))
        unique_ratio = (unique_highs + unique_lows) / (lookback * 2)  # Should be close to 1 if all unique
        
        # ═══ RANGE DETECTION LOGIC ═══
        # Market is in RANGE if:
        is_range = (
            (structure_score < 40)  # Weak structure progression
            and (chop_index > 60)   # Choppy market (high Chop)
            and (displacement_pct < 40)  # Low displacement
            and (unique_ratio < 0.7)  # Many equal highs/lows
        )
        
        # Calculate severity score
        range_severity = 0
        if structure_score < 40:
            range_severity += 25
        if chop_index > 60:
            range_severity += 25
        if displacement_pct < 40:
            range_severity += 25
        if unique_ratio < 0.7:
            range_severity += 25
        
        # Generate reason
        reasons = []
        if structure_score < 40:
            reasons.append(f"Weak structure ({structure_score:.0f}/100)")
        if chop_index > 60:
            reasons.append(f"High chop ({chop_index:.0f})")
        if displacement_pct < 40:
            reasons.append(f"Low displacement ({displacement_pct:.0f}%)")
        if unique_ratio < 0.7:
            reasons.append(f"Equal highs/lows ({unique_ratio:.1%})")
        
        reason_str = " + ".join(reasons) if reasons else "Market neutral"
        
        if is_range:
            print(f"\n🛑 [RANGE BLOCKER] DETECTED - NO TRADES ALLOWED")
            print(f"   Reason: {reason_str}")
            print(f"   Structure: {structure_score:.0f}/100 | Chop: {chop_index:.0f} | Displacement: {displacement_pct:.0f}%")
        
        return {
            'is_range': is_range,
            'range_low': range_low,
            'range_high': range_high,
            'range_width': range_width,
            'structure_score': structure_score,
            'chop_index': chop_index,
            'displacement_avg': displacement_avg,
            'range_severity': range_severity,
            'reason': reason_str
        }
    
    except Exception as e:
        print(f"[ERROR] detect_range_market: {e}")
        return {
            'is_range': False,
            'range_low': None,
            'range_high': None,
            'range_width': None,
            'structure_score': 50,
            'chop_index': 50,
            'displacement_avg': 0,
            'reason': f'Error: {str(e)}'
        }


# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
# �💧 SWEEP DETECTION + RETEST ENTRY SYSTEM (NEW - CHANGES EVERYTHING)
# ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════

def detect_liquidity_sweep_advanced(df, direction, lookback=20):
    """
    ENHANCED SWEEP DETECTION: Find liquidity hunts (extreme wicks with rejection)
    
    For BUY: Look for wick sweeping BELOW recent support with rejection (close > low)
    For SELL: Look for wick sweeping ABOVE recent resistance with rejection (close < high)
    
    Returns:
    {
        'sweep_detected': bool,
        'sweep_price': float - The extreme price of the sweep,
        'sweep_strength': float 0-100 - How strong was the rejection,
        'rejection_high': float - High of the rejection candle (for BUY),
        'rejection_low': float - Low of the rejection candle (for SELL),
        'bars_since_sweep': int - How many bars ago did sweep happen
    }
    """
    if df is None or len(df) < lookback + 5:
        return {'sweep_detected': False, 'sweep_price': None, 'sweep_strength': 0, 'bars_since_sweep': 999}
    
    try:
        recent_data = df.iloc[-lookback:].copy()
        last = df.iloc[-1]
        
        # Find recent support/resistance
        if direction == "buy":
            # For BUY: Find recent swing low (support)
            support_level = recent_data['low'].min()
            support_idx = recent_data['low'].idxmin()
            
            # Check if latest candle has a wick below support with rejection above
            current_low = last['low']
            current_close = last['close']
            current_high = last['high']
            
            # Sweep check: low swept below support
            if current_low < support_level * 0.998:  # Swept below (allows for floating point)
                # Rejection check: close is above the wick (strong rejection)
                wick_size = support_level - current_low
                body_above_wick = current_close - current_low
                rejection_strength = (body_above_wick / wick_size * 100) if wick_size > 0 else 0
                
                if rejection_strength > 40:  # At least 40% of wick size recovered = good rejection
                    bars_since = len(df) - 1 - support_idx
                    print(f"[💧 SWEEP BUY] Swept below support {support_level:.5f} → {current_low:.5f}, "
                          f"Rejected to {current_close:.5f} (strength: {rejection_strength:.0f}%)")
                    
                    return {
                        'sweep_detected': True,
                        'sweep_price': current_low,
                        'sweep_strength': min(rejection_strength, 100),
                        'rejection_high': current_close,
                        'rejection_low': current_low,
                        'bars_since_sweep': bars_since,
                        'support_level': support_level
                    }
        
        else:  # direction == "sell"
            # For SELL: Find recent swing high (resistance)
            resistance_level = recent_data['high'].max()
            resistance_idx = recent_data['high'].idxmax()
            
            # Check if latest candle has a wick above resistance with rejection below
            current_high = last['high']
            current_close = last['close']
            current_low = last['low']
            
            # Sweep check: high swept above resistance
            if current_high > resistance_level * 1.002:  # Swept above
                # Rejection check: close is below the wick (strong rejection)
                wick_size = current_high - resistance_level
                body_below_wick = current_high - current_close
                rejection_strength = (body_below_wick / wick_size * 100) if wick_size > 0 else 0
                
                if rejection_strength > 40:  # At least 40% of wick size recovered = good rejection
                    bars_since = len(df) - 1 - resistance_idx
                    print(f"[💧 SWEEP SELL] Swept above resistance {resistance_level:.5f} → {current_high:.5f}, "
                          f"Rejected to {current_close:.5f} (strength: {rejection_strength:.0f}%)")
                    
                    return {
                        'sweep_detected': True,
                        'sweep_price': current_high,
                        'sweep_strength': min(rejection_strength, 100),
                        'rejection_high': current_high,
                        'rejection_low': current_close,
                        'bars_since_sweep': bars_since,
                        'resistance_level': resistance_level
                    }
        
        return {'sweep_detected': False, 'sweep_price': None, 'sweep_strength': 0, 'bars_since_sweep': 999}
    
    except Exception as e:
        print(f"[ERROR] detect_liquidity_sweep_advanced: {e}")
        return {'sweep_detected': False, 'sweep_price': None, 'sweep_strength': 0, 'bars_since_sweep': 999}


def is_price_retesting_sweep(df, direction, sweep_price, lookback=15):
    """
    CHECK: Is price retesting (coming back) to the sweep zone?
    
    For BUY: Is price pulling back UP from the sweep low? (approaching it from above)
    For SELL: Is price pulling back DOWN from the sweep high? (approaching it from below)
    
    Returns:
    {
        'is_retesting': bool,
        'current_distance_pct': float - How close to sweep zone (0-100%),
        'retest_type': str - 'APPROACHING', 'AT_ZONE', 'PASSED', 'FAR_AWAY'
    }
    """
    if df is None or len(df) < 5 or sweep_price is None:
        return {'is_retesting': False, 'current_distance_pct': 0, 'retest_type': 'INSUFFICIENT_DATA'}
    
    try:
        last = df.iloc[-1]
        current_price = last['close']
        recent_high = df['high'].iloc[-lookback:].max()
        recent_low = df['low'].iloc[-lookback:].min()
        
        if direction == "buy":
            # For BUY: Price should be pulling back DOWN toward the sweep low
            # sweep_price is the low, we're looking for pullback INTO it
            
            # Measure distance from current price to sweep zone
            if current_price < sweep_price:
                # Already past the sweep (rare, means we didn't catch the retest)
                distance_pct = 0
                retest_type = "PASSED"
            else:
                # Calculate % distance from sweep to highest point in the move
                total_range = recent_high - sweep_price
                current_dist = current_price - sweep_price
                distance_pct = (1.0 - (current_dist / total_range)) * 100 if total_range > 0 else 0
                distance_pct = max(0, min(100, distance_pct))
                
                if distance_pct < 5:
                    retest_type = "FAR_AWAY"
                elif distance_pct < 20:
                    retest_type = "APPROACHING"
                elif distance_pct < 60:
                    retest_type = "AT_ZONE"
                else:
                    retest_type = "APPROACHING"
            
            is_retesting = retest_type in ["AT_ZONE", "APPROACHING"]
            print(f"[🔄 RETEST CHECK BUY] Price {current_price:.5f} vs sweep {sweep_price:.5f}: "
                  f"Distance {distance_pct:.1f}% ({retest_type})")
            
        else:  # direction == "sell"
            # For SELL: Price should be pulling back UP toward the sweep high
            # sweep_price is the high, we're looking for pullback INTO it
            
            if current_price > sweep_price:
                # Already past the sweep
                distance_pct = 0
                retest_type = "PASSED"
            else:
                # Calculate % distance from sweep down to lowest point
                total_range = sweep_price - recent_low
                current_dist = sweep_price - current_price
                distance_pct = (1.0 - (current_dist / total_range)) * 100 if total_range > 0 else 0
                distance_pct = max(0, min(100, distance_pct))
                
                if distance_pct < 5:
                    retest_type = "FAR_AWAY"
                elif distance_pct < 20:
                    retest_type = "APPROACHING"
                elif distance_pct < 60:
                    retest_type = "AT_ZONE"
                else:
                    retest_type = "APPROACHING"
            
            is_retesting = retest_type in ["AT_ZONE", "APPROACHING"]
            print(f"[🔄 RETEST CHECK SELL] Price {current_price:.5f} vs sweep {sweep_price:.5f}: "
                  f"Distance {distance_pct:.1f}% ({retest_type})")
        
        return {
            'is_retesting': is_retesting,
            'current_distance_pct': distance_pct,
            'retest_type': retest_type
        }
    
    except Exception as e:
        print(f"[ERROR] is_price_retesting_sweep: {e}")
        return {'is_retesting': False, 'current_distance_pct': 0, 'retest_type': 'ERROR'}


def calculate_sweep_based_sl(symbol, direction, entry_price, sweep_info, buffer_pips=2):
    """
    ⭐ CRITICAL FIX #2: SL = BEYOND SWEEP, NOT ATR-BASED
    
    For BUY: SL = sweep_low - buffer_pips
    For SELL: SL = sweep_high + buffer_pips
    
    This replaces the old ATR-based wide SL with a structural stop at the actual market extreme
    
    Args:
        symbol: Trading symbol
        direction: 'buy' or 'sell'
        entry_price: Current entry price
        sweep_info: Dict from detect_liquidity_sweep_advanced() with 'sweep_price' key
        buffer_pips: How many pips beyond sweep to place SL (default 2)
    
    Returns:
        sl_price: The stop loss price
    """
    try:
        sweep_price = sweep_info.get('sweep_price')
        if sweep_price is None:
            return None
        
        # Convert buffer from pips to price points
        # Most forex pairs: 1 pip = 0.0001
        # JPY pairs: 1 pip = 0.01
        # Gold: 1 pip = 0.01
        if 'JPY' in symbol.upper():
            pip_value = 0.01
        elif 'XAU' in symbol.upper() or 'GOLD' in symbol.upper():
            pip_value = 0.01
        else:
            pip_value = 0.0001
        
        buffer_price = buffer_pips * pip_value
        
        if direction == "buy":
            # BUY: SL below the sweep low
            sl_price = sweep_price - buffer_price
            print(f"[💰 SL CALC] {symbol} BUY: Sweep low {sweep_price:.5f} → SL {sl_price:.5f} (buffer {buffer_pips} pips)")
        else:  # sell
            # SELL: SL above the sweep high
            sl_price = sweep_price + buffer_price
            print(f"[💰 SL CALC] {symbol} SELL: Sweep high {sweep_price:.5f} → SL {sl_price:.5f} (buffer {buffer_pips} pips)")
        
        return sl_price
    
    except Exception as e:
        print(f"[ERROR] calculate_sweep_based_sl: {e}")
        return None


def should_enter_on_sweep_retest(symbol, direction, df, lookback=20):
    """
    ⭐⭐ CRITICAL FIX #1: ENTER ON RETEST/PULLBACK AFTER SWEEP (NOT BOS CANDLE)
    
    This is the NEW entry decision logic:
    1. Detect if liquidity sweep happened
    2. Check if price is retesting/pulling back to sweep zone
    3. IF BOTH TRUE → ENTER, don't wait for BOS confirmation
    
    Returns:
    {
        'should_enter': bool,
        'entry_price': float or None,
        'sweep_info': dict with sweep details,
        'retest_info': dict with retest details,
        'sl_price': float or None,
        'reason': str
    }
    """
    if df is None or len(df) < lookback + 5:
        return {
            'should_enter': False,
            'entry_price': None,
            'sweep_info': None,
            'retest_info': None,
            'sl_price': None,
            'reason': 'Insufficient data'
        }
    
    try:
        # STEP 1: Detect the liquidity sweep
        sweep_info = detect_liquidity_sweep_advanced(df, direction, lookback)
        
        if not sweep_info.get('sweep_detected'):
            return {
                'should_enter': False,
                'sweep_info': sweep_info,
                'reason': 'No liquidity sweep detected'
            }
        
        # STEP 2: Check if price is retesting the sweep
        retest_info = is_price_retesting_sweep(df, direction, sweep_info['sweep_price'], lookback)
        
        if not retest_info.get('is_retesting'):
            return {
                'should_enter': False,
                'sweep_info': sweep_info,
                'retest_info': retest_info,
                'reason': f"Sweep detected but price not retesting: {retest_info.get('retest_type')}"
            }
        
        # STEP 3: Calculate entry price (at the zone mid)
        last = df.iloc[-1]
        current_price = last['close']
        entry_price = current_price  # Enter at current retest price
        
        # STEP 4: Calculate SL beyond sweep (not ATR!)
        sl_price = calculate_sweep_based_sl(symbol, direction, entry_price, sweep_info, buffer_pips=2)
        
        if sl_price is None:
            return {
                'should_enter': False,
                'sweep_info': sweep_info,
                'retest_info': retest_info,
                'reason': 'Could not calculate SL'
            }
        
        # STEP 5: Success!
        print(f"\n✅ [SWEEP+RETEST ENTRY] {symbol} {direction.upper()}")
        print(f"   Sweep detected: {sweep_info.get('sweep_price'):.5f}")
        print(f"   Retesting: {retest_info.get('retest_type')}")
        print(f"   Entry: {entry_price:.5f}")
        print(f"   SL: {sl_price:.5f}")
        
        return {
            'should_enter': True,
            'entry_price': entry_price,
            'sweep_info': sweep_info,
            'retest_info': retest_info,
            'sl_price': sl_price,
            'reason': f"✅ Sweep + Retest confirmed (strength: {sweep_info.get('sweep_strength'):.0f}%, "
                     f"retest: {retest_info.get('retest_type')})"
        }
    
    except Exception as e:
        print(f"[ERROR] should_enter_on_sweep_retest: {e}")
        return {
            'should_enter': False,
            'entry_price': None,
            'sweep_info': None,
            'retest_info': None,
            'sl_price': None,
            'reason': f'Error: {str(e)}'
        }


