def check_htf_bias_filter(symbol, direction, lookback=50):
    """
    FILTER 1: Higher Timeframe Bias Filter
    Only allow buys if H4 trend is bullish, only allow sells if H4 trend is bearish
    
    Args:
        symbol: Trading symbol
        direction: 'buy' or 'sell'
        lookback: Number of bars for trend calculation
    
    Returns:
        (is_valid: bool, reason: str)
    """
    try:
        # Get H4 data
        df_h4 = get_price_data(symbol, timeframe='H4', bars=max(100, lookback + 20))
        if df_h4 is None or len(df_h4) < 20:
            return True, "HTF Bias: H4 data unavailable, allowing trade"
        
        # Calculate simple trend on H4
        recent_close = df_h4['close'].iloc[-1]
        lookback_close = df_h4['close'].iloc[-min(lookback, len(df_h4))]
        
        # H4 trend direction
        h4_trend = "bullish" if recent_close > lookback_close else "bearish"
        recent_high = df_h4['high'].iloc[-lookback:].max()
        recent_low = df_h4['low'].iloc[-lookback:].min()
        
        print(f"[HTF BIAS] {symbol}: H4 trend={h4_trend} (current={recent_close:.5f}, lookback={lookback_close:.5f})")
        
        # Check direction alignment
        if direction == "buy":
            if h4_trend == "bullish":
                return True, f"✅ HTF Bias OK: H4 bullish (trend: {lookback_close:.5f} → {recent_close:.5f})"
            else:
                return False, f"❌ HTF Bias REJECTED: H4 bearish, no buy signal (trend: {lookback_close:.5f} → {recent_close:.5f})"
        else:  # sell
            if h4_trend == "bearish":
                return True, f"✅ HTF Bias OK: H4 bearish (trend: {lookback_close:.5f} → {recent_close:.5f})"
            else:
                return False, f"❌ HTF Bias REJECTED: H4 bullish, no sell signal (trend: {lookback_close:.5f} → {recent_close:.5f})"
    
    except Exception as e:
        print(f"[HTF BIAS ERROR] {symbol}: {e}")
        return True, f"HTF Bias: Error checking, allowing trade"

def check_structure_break_confirmation(df, direction, lookback=20):
    """
    FILTER 2: Structure Break Confirmation
    For buys: Must break previous higher high, then retest
    For sells: Must break previous lower low, then retest
    
    Args:
        df: OHLC dataframe
        direction: 'buy' or 'sell'
        lookback: Number of bars to analyze
    
    Returns:
        (is_valid: bool, reason: str)
    """
    try:
        if df is None or len(df) < lookback + 5:
            return True, "Structure Break: Insufficient data, allowing trade"
        
        recent = df.iloc[-lookback:].copy()
        current_price = df['close'].iloc[-1]
        
        if direction == "buy":
            # For BUY: Need to break higher high then retest
            # Previous higher high is the highest point before current swing
            prev_high = recent['high'].iloc[:-1].max() if len(recent) > 1 else df['high'].iloc[-2]
            current_high = recent['high'].iloc[-1]
            
            # Check if we broke above previous high
            broke_high = current_high > prev_high
            
            # Check if we've retested (came back down but staying above break point)
            if broke_high and len(df) > 2:
                recent_low_after_break = df['low'].iloc[-2:].min()
                retest_valid = recent_low_after_break >= prev_high * 0.99  # Allow 1% wiggle
                
                print(f"[STRUCTURE] BUY: prev_high={prev_high:.5f}, current_high={current_high:.5f}, broke={broke_high}, retest_valid={retest_valid}")
                
                if broke_high and retest_valid:
                    return True, f"✅ Structure Break OK: BUY broke {prev_high:.5f} and retested"
                elif broke_high:
                    return False, f"❌ Structure Break REJECTED: BUY broke {prev_high:.5f} but retest failed"
                else:
                    return False, f"❌ Structure Break REJECTED: BUY didn't break {prev_high:.5f}"
            else:
                return False, f"❌ Structure Break REJECTED: BUY no break above {prev_high:.5f}"
        
        else:  # sell
            # For SELL: Need to break lower low then retest
            prev_low = recent['low'].iloc[:-1].min() if len(recent) > 1 else df['low'].iloc[-2]
            current_low = recent['low'].iloc[-1]
            
            # Check if we broke below previous low
            broke_low = current_low < prev_low
            
            # Check if we've retested (came back up but staying below break point)
            if broke_low and len(df) > 2:
                recent_high_after_break = df['high'].iloc[-2:].max()
                retest_valid = recent_high_after_break <= prev_low * 1.01  # Allow 1% wiggle
                
                print(f"[STRUCTURE] SELL: prev_low={prev_low:.5f}, current_low={current_low:.5f}, broke={broke_low}, retest_valid={retest_valid}")
                
                if broke_low and retest_valid:
                    return True, f"✅ Structure Break OK: SELL broke {prev_low:.5f} and retested"
                elif broke_low:
                    return False, f"❌ Structure Break REJECTED: SELL broke {prev_low:.5f} but retest failed"
                else:
                    return False, f"❌ Structure Break REJECTED: SELL didn't break {prev_low:.5f}"
            else:
                return False, f"❌ Structure Break REJECTED: SELL no break below {prev_low:.5f}"
    
    except Exception as e:
        print(f"[STRUCTURE ERROR] {e}")
        return True, "Structure Break: Error checking, allowing trade"

def check_entry_zone_filter(df, symbol, direction):
    """
    FILTER 3: Entry Zone Filter
    Only enter if at support/demand zone OR after breakout + retest
    
    Args:
        df: OHLC dataframe
        symbol: Trading symbol
        direction: 'buy' or 'sell'
    
    Returns:
        (is_valid: bool, reason: str)
    """
    try:
        if df is None or len(df) < 50:
            return True, "Entry Zone: Insufficient data, allowing trade"
        
        current_price = df['close'].iloc[-1]
        recent_100 = df.iloc[-100:].copy()
        
        # Calculate support/demand zones
        period = 50
        recent = df.iloc[-period:].copy()
        
        # Support (low zone) and Resistance (high zone)
        support = recent['low'].min()
        resistance = recent['high'].max()
        range_size = resistance - support
        zone_width = range_size * 0.1  # 10% zone width
        
        if direction == "buy":
            # Check if price is in demand zone (support ±10%)
            in_demand_zone = (current_price >= support) and (current_price <= support + zone_width)
            
            # OR check if we just broke and retested resistance
            broke_resistance = df['high'].iloc[-2] >= resistance
            retesting_resistance = current_price >= resistance * 0.98
            breakout_confirmation = broke_resistance and retesting_resistance
            
            print(f"[ENTRY ZONE] BUY: support={support:.5f}, resistance={resistance:.5f}, price={current_price:.5f}")
            print(f"[ENTRY ZONE] BUY: in_demand={in_demand_zone}, breakout_conf={breakout_confirmation}")
            
            if in_demand_zone:
                return True, f"✅ Entry Zone OK: BUY at demand zone ({support:.5f}-{support+zone_width:.5f})"
            elif breakout_confirmation:
                return True, f"✅ Entry Zone OK: BUY breakout + retest above {resistance:.5f}"
            else:
                return False, f"❌ Entry Zone REJECTED: BUY not at demand zone, no breakout"
        
        else:  # sell
            # Check if price is in supply zone (resistance ±10%)
            in_supply_zone = (current_price <= resistance) and (current_price >= resistance - zone_width)
            
            # OR check if we just broke and retested support
            broke_support = df['low'].iloc[-2] <= support
            retesting_support = current_price <= support * 1.02
            breakout_confirmation = broke_support and retesting_support
            
            print(f"[ENTRY ZONE] SELL: support={support:.5f}, resistance={resistance:.5f}, price={current_price:.5f}")
            print(f"[ENTRY ZONE] SELL: in_supply={in_supply_zone}, breakout_conf={breakout_confirmation}")
            
            if in_supply_zone:
                return True, f"✅ Entry Zone OK: SELL at supply zone ({resistance-zone_width:.5f}-{resistance:.5f})"
            elif breakout_confirmation:
                return True, f"✅ Entry Zone OK: SELL breakout + retest below {support:.5f}"
            else:
                return False, f"❌ Entry Zone REJECTED: SELL not at supply zone, no breakout"
    
    except Exception as e:
        print(f"[ENTRY ZONE ERROR] {e}")
        return True, "Entry Zone: Error checking, allowing trade"

def check_consolidation_filter(df, lookback=20, chop_threshold=45):
    """
    FILTER 4: Kill Trades in Chop / Consolidation
    Detects if market is consolidating/ranging and skips trades
    Uses ATR ratio and range size to detect chop
    
    Args:
        df: OHLC dataframe
        lookback: Number of bars for analysis
        chop_threshold: ATR ratio threshold (lower = more choppy)
    
    Returns:
        (is_not_chop: bool, reason: str) - True if safe to trade (not choppy)
    """
    try:
        if df is None or len(df) < lookback + 10:
            return True, "Consolidation: Insufficient data, allowing trade"
        
        recent = df.iloc[-lookback:].copy()
        
        # Calculate range size vs volatility
        range_high = recent['high'].max()
        range_low = recent['low'].min()
        range_size = range_high - range_low
        
        # Calculate ATR
        atr = calculate_atr(recent)
        
        # Chop Index-like metric: if range is small relative to ATR, it's choppy
        # ATR ratio = range_size / (ATR * lookback)
        # Low ratio = choppy (range not expanding relative to volatility)
        atr_ratio = range_size / (atr * lookback) if atr > 0 else 1.0
        
        is_choppy = atr_ratio < (chop_threshold / 100.0)
        
        # Alternative: Check if price is oscillating around a level
        midpoint = (range_high + range_low) / 2
        price_oscillations = 0
        for i in range(1, len(recent)):
            prev_price = recent['close'].iloc[i-1]
            curr_price = recent['close'].iloc[i]
            if (prev_price < midpoint and curr_price > midpoint) or (prev_price > midpoint and curr_price < midpoint):
                price_oscillations += 1
        
        is_oscillating = price_oscillations > lookback * 0.6  # More than 60% of bars cross midpoint
        
        print(f"[CONSOLIDATION] ATR Ratio={atr_ratio:.3f}, Oscillations={price_oscillations}/{lookback}, Choppy={is_choppy}")
        
        if is_choppy or is_oscillating:
            return False, f"❌ CONSOLIDATION DETECTED: ATR ratio={atr_ratio:.3f} < threshold={chop_threshold/100.0:.3f}. SKIPPING TRADE."
        else:
            return True, f"✅ Consolidation Clear: ATR ratio={atr_ratio:.3f} (trending, not choppy)"
    
    except Exception as e:
        print(f"[CONSOLIDATION ERROR] {e}")
        return True, "Consolidation: Error checking, allowing trade"

