def detect_order_block(df, lookback=50, direction="bullish"):
    """
    SMART MONEY DETECTION: Find where institutional traders accumulated
    Order blocks = support/resistance from accumulation zones (70%+ win rate)
    """
    try:
        if df is None or len(df) < lookback + 5:
            return {'detected': False, 'block_high': 0, 'block_low': 0, 'strength': 0}
        
        highs = df['high'].values
        lows = df['low'].values
        closes = df['close'].values
        volumes = df['tick_volume'].values if 'tick_volume' in df.columns else df['volume'].values if 'volume' in df.columns else np.ones(len(df))
        
        if direction == "bullish":
            # Find 3+ consecutive bulls with volume expansion
            bull_count = 0
            for i in range(len(closes) - 1, max(0, len(closes) - 30), -1):
                is_bull = closes[i] > closes[i-1] if i > 0 else False
                has_volume = volumes[i] > np.mean(volumes[max(0, i-20):i]) * 1.2 if i >= 20 else True
                
                if is_bull and has_volume:
                    bull_count += 1
                else:
                    break
            
            if bull_count >= 3:
                impulse_end = len(closes) - bull_count - 1
                impulse_range = max(highs[max(0, impulse_end-bull_count):impulse_end]) - min(lows[max(0, impulse_end-bull_count):impulse_end]) if impulse_end > 0 else 0
                
                if impulse_range > 0:
                    consol_range = max(highs[max(0, impulse_end-10):impulse_end]) - min(lows[max(0, impulse_end-10):impulse_end])
                    
                    if consol_range < impulse_range * 0.6:  # Range contracted 40%+
                        block_high = max(highs[max(0, impulse_end-10):impulse_end]) + (impulse_range * 0.02)
                        block_low = min(lows[max(0, impulse_end-10):impulse_end]) - (impulse_range * 0.02)
                        return {
                            'detected': True,
                            'block_high': float(block_high),
                            'block_low': float(block_low),
                            'impulse_bars': bull_count,
                            'strength': min(10, bull_count / 3.0)
                        }
        
        return {'detected': False, 'block_high': 0, 'block_low': 0, 'strength': 0}
    except Exception:
        return {'detected': False, 'block_high': 0, 'block_low': 0, 'strength': 0}

def get_volatility_regime(df, symbol=""):
    """
    VOLATILITY ADAPTATION: Classifies market regime and adjusts entry strictness
    """
    try:
        if df is None or len(df) < 50:
            return {'regime': 'UNKNOWN', 'multiplier': 1.0, 'atr_percentile': 50, 'recommendation': 'NORMAL'}
        
        highs = df['high'].values
        lows = df['low'].values
        closes = df['close'].values
        
        tr_list = []
        for i in range(1, min(50, len(highs))):
            tr = max(highs[i] - lows[i], abs(highs[i] - closes[i-1]), abs(lows[i] - closes[i-1]))
            tr_list.append(tr)
        
        if not tr_list:
            return {'regime': 'NORMAL', 'multiplier': 1.0, 'atr_percentile': 50, 'recommendation': 'NORMAL'}
        
        atr_current = np.mean(tr_list[-14:])
        atr_hist = sorted(tr_list)
        atr_20th = atr_hist[max(0, int(len(atr_hist) * 0.2))]
        atr_80th = atr_hist[max(0, int(len(atr_hist) * 0.8))]
        
        if atr_current <= atr_20th:
            regime = 'CALM'
            multiplier = 0.7
            percentile = 20
            rec = 'STRICTER'
        elif atr_current <= (atr_20th + atr_80th) / 2:
            regime = 'NORMAL'
            multiplier = 1.0
            percentile = 50
            rec = 'NORMAL'
        elif atr_current <= atr_80th:
            regime = 'ELEVATED'
            multiplier = 1.3
            percentile = 80
            rec = 'FASTER'
        else:
            regime = 'EXTREME'
            multiplier = 0.5
            percentile = 95
            rec = 'STRICTER'
        
        return {
            'regime': regime,
            'multiplier': multiplier,
            'atr_current': float(atr_current),
            'atr_percentile': percentile,
            'recommendation': rec
        }
    except Exception:
        return {'regime': 'NORMAL', 'multiplier': 1.0, 'atr_percentile': 50, 'recommendation': 'NORMAL'}

def calculate_volatility_adaptive_exit(df, direction, entry_price, initial_sl, initial_tp, current_profit_r=0.5):
    """
    VOLATILITY-ADAPTIVE EXIT: Adjust SL/TP spacing based on market volatility
    
    Strategy:
    - CALM: Tighter stops (less noise), wider TP (let winners run)
    - EXTREME: Wider stops (protect from whipsaws), closer TP (take profits early)
    - Profit-based adjustments: Move SL more aggressively at higher profits
    """
    try:
        if df is None or len(df) < 14:
            return {'recommended_sl': initial_sl, 'recommended_tp': initial_tp}
        
        vol_regime = get_volatility_regime(df)
        
        highs = df['high'].values
        lows = df['low'].values
        closes = df['close'].values
        
        # Calculate ATR for scaling
        atr_list = []
        for i in range(1, min(14, len(highs))):
            tr = max(highs[i] - lows[i], abs(highs[i] - closes[i-1]), abs(lows[i] - closes[i-1]))
            atr_list.append(tr)
        atr = np.mean(atr_list) if atr_list else 0.001
        
        if direction == "buy":
            # CALM regime: Tighter SL, wider TP
            if vol_regime['regime'] == 'CALM':
                new_sl = entry_price - (atr * 0.8)  # Tighter 0.8x ATR
                new_tp = entry_price + (atr * 4.0)   # EXPANDED TP: 4.0x ATR to let winners runs
            # EXTREME regime: Wider SL, EXPANDED TP (despite volatility, let winners run)
            elif vol_regime['regime'] == 'EXTREME':
                new_sl = entry_price - (atr * 0.8)  # Tight 0.8x ATR SL
                new_tp = entry_price + (atr * 3.0)  # EXPANDED TP: 3.0x ATR (was 1.8x) - let winners capture more in volatility
            # NORMAL/ELEVATED
            else:
                new_sl = entry_price - (atr * 1.0)
                new_tp = entry_price + (atr * 3.5)  # EXPANDED TP: 3.5x ATR (was 2.5x)
            
            # Profit-based SL adjustment: move SL closer to entry at high profits
            if current_profit_r >= 2.0:
                # At 2R profit, move SL to 1.2R profit (lock in most gains)
                new_sl = max(new_sl, entry_price + (atr * 0.5))
            elif current_profit_r >= 1.0:
                # At 1R profit, move SL to breakeven
                new_sl = max(new_sl, entry_price - (atr * 0.1))
        
        else:  # sell
            if vol_regime['regime'] == 'CALM':
                new_sl = entry_price + (atr * 0.8)
                new_tp = entry_price - (atr * 4.0)  # EXPANDED TP: 4.0x ATR to let winners run
            elif vol_regime['regime'] == 'EXTREME':
                new_sl = entry_price + (atr * 0.8)  # Tight 0.8x ATR SL
                new_tp = entry_price - (atr * 3.0)  # EXPANDED TP: 3.0x ATR (was 1.8x)
            else:
                new_sl = entry_price + (atr * 1.0)
                new_tp = entry_price - (atr * 3.5)  # EXPANDED TP: 3.5x ATR (was 2.5x)
            
            if current_profit_r >= 2.0:
                new_sl = min(new_sl, entry_price - (atr * 0.5))
            elif current_profit_r >= 1.0:
                new_sl = min(new_sl, entry_price + (atr * 0.1))
        
        return {
            'recommended_sl': float(new_sl),
            'recommended_tp': float(new_tp),
            'volatility_regime': vol_regime['regime'],
            'atr': float(atr),
            'adjustment_reason': f"{vol_regime['regime']} volatility - {'tighter' if vol_regime['regime'] == 'CALM' else 'wider' if vol_regime['regime'] == 'EXTREME' else 'normal'} stops"
        }
    except Exception:
        return {'recommended_sl': initial_sl, 'recommended_tp': initial_tp}

def detect_a_plus_entry_setup(df, direction, entry_price, features_dict=None, symbol=""):
    """
    ⭐ ADVANCED A+ ENTRY DETECTION SYSTEM (BULLETPROOF VERSION)
    
    Identifies premium A+ quality entries by analyzing 7 factors with advanced validation.
    Handles edge cases, null values, and malformed data gracefully.
    
    Returns: {
        'tier': 'A+' / 'A' / 'B+' / 'B' / 'C' / 'D',
        'score': 0-100,
        'is_premium': bool,
        'factors': {...},
        'reasoning': str,
        'recommendation': str,
        'debug': {...diagnostics...}
    }
    """
    debug_info = {}
    
    try:
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # PHASE 1: DATA VALIDATION & SAFETY CHECKS
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        # Validate dataframe
        if df is None:
            return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': 'No data provided', 'recommendation': 'SKIP', 'debug': {'error': 'df is None'}}
        
        if len(df) < 50:
            return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': f'Insufficient data: {len(df)} bars < 50 required', 'recommendation': 'SKIP', 'debug': {'error': 'data too small'}}
        
        # Validate direction
        direction = str(direction).lower().strip()
        if direction not in ['buy', 'sell']:
            return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': f'Invalid direction: {direction}', 'recommendation': 'SKIP', 'debug': {'error': f'bad direction: {direction}'}}
        
        # Extract data with validation
        try:
            highs = df['high'].values
            lows = df['low'].values
            closes = df['close'].values
        except Exception as e:
            return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': f'Missing OHLC columns: {e}', 'recommendation': 'SKIP', 'debug': {'error': f'column error: {e}'}}
        
        # Validate OHLC data
        if len(highs) != len(lows) or len(highs) != len(closes):
            return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': 'Mismatched OHLC column lengths', 'recommendation': 'SKIP', 'debug': {'error': 'column length mismatch'}}
        
        # Remove any NaN/inf values
        try:
            valid_idx = ~(np.isnan(highs) | np.isnan(lows) | np.isnan(closes) | np.isinf(highs) | np.isinf(lows) | np.isinf(closes))
            if not np.any(valid_idx[-50:]):  # Check last 50 bars
                return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': 'All recent data is NaN/inf', 'recommendation': 'SKIP', 'debug': {'error': 'all NaN/inf'}}
            
            highs = highs[valid_idx][-50:]
            lows = lows[valid_idx][-50:]
            closes = closes[valid_idx][-50:]
            debug_info['valid_bars'] = len(highs)
        except Exception as e:
            debug_info['validation_warning'] = str(e)
        
        # Validate volume data
        try:
            if 'tick_volume' in df.columns:
                volumes = df['tick_volume'].values
            elif 'volume' in df.columns:
                volumes = df['volume'].values
            else:
                volumes = np.ones(len(highs))
            
            # Remove NaN/inf from volumes
            volumes = volumes[~(np.isnan(volumes) | np.isinf(volumes))][-50:]
            if len(volumes) == 0:
                volumes = np.ones(len(highs))
        except Exception as e:
            debug_info['volume_error'] = str(e)
            volumes = np.ones(len(highs))
        
        # Validate entry price
        try:
            entry_price = float(entry_price)
            if entry_price <= 0 or np.isnan(entry_price) or np.isinf(entry_price):
                return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': f'Invalid entry price: {entry_price}', 'recommendation': 'SKIP', 'debug': {'error': f'bad entry_price: {entry_price}'}}
        except Exception as e:
            return {'tier': 'D', 'score': 0, 'is_premium': False, 'reasoning': f'Cannot parse entry price: {e}', 'recommendation': 'SKIP', 'debug': {'error': f'entry_price parse: {e}'}}
        
        features = features_dict if features_dict and isinstance(features_dict, dict) else {}
        score = 0
        breakdown = {}
        
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # PHASE 2: CALCULATE 7 ENTRY QUALITY FACTORS
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        # FACTOR 1: ORDER BLOCK QUALITY (0-20 points) - SAFE
        try:
            ob_score = 0
            ob_detected = bool(features.get('order_block_detected', False))
            ob_strength = float(features.get('ob_strength', 0))
            ob_strength = max(0, min(10, ob_strength))  # Constrain 0-10
            
            if ob_detected:
                ob_score = min(20, ob_strength * 2)
            
            breakdown['order_block'] = float(ob_score)
            score += ob_score
            debug_info['ob'] = {'detected': ob_detected, 'strength': ob_strength, 'score': ob_score}
        except Exception as e:
            debug_info['ob_error'] = str(e)
            breakdown['order_block'] = 0.0
        
        # FACTOR 2: SWEEP + RETRACEMENT (0-20 points) - SAFE
        try:
            sweep_score = 0
            sweep_detected = bool(features.get('sweep_detected', False))
            sweep_reclaimed = bool(features.get('sweep_reclaimed', False))
            
            if sweep_detected:
                sweep_score += 10
                if sweep_reclaimed:
                    sweep_score += 10
            
            sweep_score = float(min(20, sweep_score))
            breakdown['sweep_quality'] = sweep_score
            score += sweep_score
            debug_info['sweep'] = {'detected': sweep_detected, 'reclaimed': sweep_reclaimed, 'score': sweep_score}
        except Exception as e:
            debug_info['sweep_error'] = str(e)
            breakdown['sweep_quality'] = 0.0
        
        # FACTOR 3: STRUCTURE STRENGTH (0-15 points) - SAFE WITH BOUNDS
        try:
            structure_score = 0
            
            if direction == "buy":
                higher_lows = 0
                for i in range(len(lows) - 1, max(0, len(lows) - 25), -1):
                    try:
                        if i > 0 and float(lows[i]) > float(lows[i-1]):
                            higher_lows += 1
                        else:
                            break
                    except:
                        break
                structure_score = min(15.0, float(higher_lows) * 2.0)
            else:  # sell
                lower_highs = 0
                for i in range(len(highs) - 1, max(0, len(highs) - 25), -1):
                    try:
                        if i > 0 and float(highs[i]) < float(highs[i-1]):
                            lower_highs += 1
                        else:
                            break
                    except:
                        break
                structure_score = min(15.0, float(lower_highs) * 2.0)
            
            breakdown['structure_strength'] = float(structure_score)
            score += structure_score
            debug_info['structure'] = {'direction': direction, 'count': higher_lows if direction == "buy" else lower_highs, 'score': structure_score}
        except Exception as e:
            debug_info['structure_error'] = str(e)
            breakdown['structure_strength'] = 0.0
        
        # FACTOR 4: VOLUME IMBALANCE (0-15 points) - SAFE DIVISION
        try:
            if len(volumes) < 21:
                avg_vol_20 = np.mean(volumes) if len(volumes) > 0 else 1.0
            else:
                avg_vol_20 = np.mean(volumes[-21:-1])
            
            avg_vol_20 = float(avg_vol_20)
            if avg_vol_20 <= 0:
                avg_vol_20 = 1.0
            
            current_vol = float(volumes[-1]) if len(volumes) > 0 else 1.0
            vol_ratio = current_vol / avg_vol_20
            vol_ratio = max(0.0, min(10.0, vol_ratio))  # Constrain 0-10 ratio
            
            vol_score = 0.0
            if vol_ratio >= 2.0:
                vol_score = 15.0
            elif vol_ratio >= 1.5:
                vol_score = 12.0
            elif vol_ratio >= 1.2:
                vol_score = 8.0
            elif vol_ratio >= 0.8:
                vol_score = 4.0
            else:
                vol_score = 1.0
            
            breakdown['volume_expansion'] = float(vol_score)
            score += vol_score
            debug_info['volume'] = {'ratio': vol_ratio, 'avg_vol_20': avg_vol_20, 'current_vol': current_vol, 'score': vol_score}
        except Exception as e:
            debug_info['volume_error'] = str(e)
            breakdown['volume_expansion'] = 0.0
        
        # FACTOR 5: CANDLE PATTERN QUALITY (0-12 points) - ROBUST CALCULATION
        try:
            candle_score = 0.0
            current_high = float(highs[-1])
            current_low = float(lows[-1])
            current_close = float(closes[-1])
            prev_close = float(closes[-2]) if len(closes) > 1 else current_close
            
            candle_range = current_high - current_low
            if candle_range <= 0:
                candle_range = 0.0001  # Prevent division by zero
            
            if direction == "buy":
                body_height = max(current_close, prev_close) - current_low
                body_ratio = body_height / candle_range if candle_range > 0 else 0
                body_ratio = max(0.0, min(1.0, body_ratio))
                
                if current_close > prev_close:  # Bull candle
                    lower_wick_size = current_low - current_low
                    if body_ratio > 0.7:
                        candle_score = 12.0
                    elif body_ratio > 0.6:
                        candle_score = 8.0
                    elif body_ratio > 0.5:
                        candle_score = 4.0
            else:  # sell
                body_height = current_high - min(current_close, prev_close)
                body_ratio = body_height / candle_range if candle_range > 0 else 0
                body_ratio = max(0.0, min(1.0, body_ratio))
                
                if current_close < prev_close:  # Bear candle
                    if body_ratio > 0.7:
                        candle_score = 12.0
                    elif body_ratio > 0.6:
                        candle_score = 8.0
                    elif body_ratio > 0.5:
                        candle_score = 4.0
            
            breakdown['candle_pattern'] = float(candle_score)
            score += candle_score
            debug_info['candle'] = {'range': candle_range, 'body_ratio': body_ratio, 'score': candle_score}
        except Exception as e:
            debug_info['candle_error'] = str(e)
            breakdown['candle_pattern'] = 0.0
        
        # FACTOR 6: MOMENTUM CONFIRMATION (0-10 points) - SAFE DICT ACCESS
        try:
            momentum_score = 0.0
            momentum_data = features.get('momentum_confirmation', {})
            
            if momentum_data and isinstance(momentum_data, dict):
                confirmation = str(momentum_data.get('confirmation', '')).upper()
                if 'STRONG' in confirmation:
                    momentum_score = 10.0
                elif 'MILD' in confirmation:
                    momentum_score = 5.0
                else:
                    momentum_score = 0.0
            
            breakdown['momentum'] = float(momentum_score)
            score += momentum_score
            debug_info['momentum'] = {'confirmation': momentum_data.get('confirmation', 'NONE'), 'score': momentum_score}
        except Exception as e:
            debug_info['momentum_error'] = str(e)
            breakdown['momentum'] = 0.0
        
        # FACTOR 7: RISK/REWARD EXCELLENCE (0-8 points) - SAFE RATIO
        try:
            rr_ratio = float(features.get('rr_ratio', 1.5))
            rr_ratio = max(0.5, min(5.0, rr_ratio))  # Constrain 0.5-5.0
            
            rr_score = 0.0
            if rr_ratio >= 3.0:
                rr_score = 8.0
            elif rr_ratio >= 2.5:
                rr_score = 6.0
            elif rr_ratio >= 2.0:
                rr_score = 4.0
            elif rr_ratio >= 1.5:
                rr_score = 2.0
            else:
                rr_score = 0.0
            
            breakdown['rr_ratio'] = float(rr_score)
            score += rr_score
            debug_info['rr'] = {'ratio': rr_ratio, 'score': rr_score}
        except Exception as e:
            debug_info['rr_error'] = str(e)
            breakdown['rr_ratio'] = 0.0
        
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # PHASE 3: TIER CLASSIFICATION WITH BOUNDS
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        score = float(score)
        score = max(0.0, min(100.0, score))  # Enforce 0-100 bounds
        
        if score >= 95:
            tier = "🌟 A+"
            is_premium = True
            reasoning = "Perfect confluence: elite order block + sweep reclaim + strong structure"
        elif score >= 85:
            tier = "⭐ A"
            is_premium = True
            reasoning = "Premium entry: strong OB + sweep + structure aligned"
        elif score >= 75:
            tier = "✅ B+"
            is_premium = False
            reasoning = "Good entry: multiple factors aligned"
        elif score >= 65:
            tier = "✔️ B"
            is_premium = False
            reasoning = "Acceptable entry: some confluence present"
        elif score >= 50:
            tier = "⚠️ C"
            is_premium = False
            reasoning = "Weak entry: limited confluence"
        else:
            tier = "❌ D"
            is_premium = False
            reasoning = "Poor entry quality: skip or wait for confirmation"
        
        recommendation = "EXECUTE" if score >= 75 else "WAIT" if score >= 65 else "SKIP"
        
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # PHASE 4: OUTPUT VALIDATION & RETURN
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        # Verify all factors sum correctly
        factor_sum = sum(breakdown.values())
        if abs(factor_sum - score) > 1.0:  # Allow 1 point rounding error
            debug_info['factor_sum_mismatch'] = f'{factor_sum} != {score}'
        
        return {
            'tier': tier,
            'score': int(round(score)),
            'is_premium': is_premium,
            'factors': {k: float(v) for k, v in breakdown.items()},
            'reasoning': reasoning,
            'recommendation': recommendation,
            'signal_strength': {
                'order_block': bool(features.get('order_block_detected', False)),
                'sweep_reclaimed': bool(features.get('sweep_reclaimed', False)),
                'strong_structure': float(breakdown.get('structure_strength', 0)) >= 10.0,
                'high_volume': float(breakdown.get('volume_expansion', 0)) >= 12.0,
                'quality_candle': float(breakdown.get('candle_pattern', 0)) >= 8.0,
                'momentum_aligned': float(breakdown.get('momentum', 0)) >= 5.0
            },
            'debug': debug_info
        }
    
    except Exception as e:
        import traceback
        return {
            'tier': 'D',
            'score': 0,
            'is_premium': False,
            'factors': {},
            'reasoning': f'Critical error in A+ detection: {str(e)}',
            'recommendation': 'SKIP',
            'signal_strength': {'order_block': False, 'sweep_reclaimed': False, 'strong_structure': False, 'high_volume': False, 'quality_candle': False, 'momentum_aligned': False},
            'debug': {'critical_error': str(e), 'traceback': traceback.format_exc()}
        }

def identify_premium_entry_patterns(df, direction, entry_price, features_dict=None):
    """
    🎯 PREMIUM ENTRY PATTERN RECOGNITION (BULLETPROOF VERSION)
    
    Identifies which premium pattern the current setup matches with advanced validation:
    - PATTERN 1: Order Block + Sweep Reclaim (Perfect SMC entry)
    - PATTERN 2: Multiple Higher Lows/Lower Highs + Momentum Breakout
    - PATTERN 3: Supply/Demand Imbalance with Volume Explosive
    - PATTERN 4: Retest of Key Structure with Reversal Divergence
    
    All calculations validated for NaN, inf, and edge cases.
    """
    debug_info = {}
    
    try:
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # VALIDATION PHASE
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        if df is None:
            return {'patterns': [], 'primary_pattern': 'NONE', 'confidence': 0, 'debug': {'error': 'df is None'}}
        
        if len(df) < 50:
            return {'patterns': [], 'primary_pattern': 'NONE', 'confidence': 0, 'debug': {'error': f'insufficient data: {len(df)}'}}
        
        # Validate direction
        direction = str(direction).lower().strip()
        if direction not in ['buy', 'sell']:
            return {'patterns': [], 'primary_pattern': 'NONE', 'confidence': 0, 'debug': {'error': f'bad direction: {direction}'}}
        
        # Extract and validate data
        try:
            highs = np.array(df['high'].values, dtype=float)
            lows = np.array(df['low'].values, dtype=float)
            closes = np.array(df['close'].values, dtype=float)
        except Exception as e:
            return {'patterns': [], 'primary_pattern': 'NONE', 'confidence': 0, 'debug': {'error': f'OHLC extraction: {e}'}}
        
        # Clean NaN/inf
        try:
            valid_mask = ~(np.isnan(highs) | np.isnan(lows) | np.isnan(closes) | np.isinf(highs) | np.isinf(lows) | np.isinf(closes))
            if not np.any(valid_mask[-50:]):
                return {'patterns': [], 'primary_pattern': 'NONE', 'confidence': 0, 'debug': {'error': 'all recent data NaN/inf'}}
            
            highs = highs[valid_mask][-50:]
            lows = lows[valid_mask][-50:]
            closes = closes[valid_mask][-50:]
        except Exception as e:
            debug_info['data_clean_error'] = str(e)
        
        # Volume extraction and validation
        try:
            if 'tick_volume' in df.columns:
                volumes = np.array(df['tick_volume'].values, dtype=float)
            elif 'volume' in df.columns:
                volumes = np.array(df['volume'].values, dtype=float)
            else:
                volumes = np.ones(len(highs), dtype=float)
            
            vol_mask = ~(np.isnan(volumes) | np.isinf(volumes) | (volumes <= 0))
            if np.any(vol_mask):
                volumes = volumes[vol_mask][-50:]
            else:
                volumes = np.ones(len(highs), dtype=float)
        except Exception as e:
            debug_info['volume_error'] = str(e)
            volumes = np.ones(len(highs), dtype=float)
        
        features = features_dict if isinstance(features_dict, dict) else {}
        patterns_detected = []
        
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # PATTERN DETECTION WITH GUARDS
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        # PATTERN 1: Order Block + Sweep Reclaim (ELITE SMC)
        try:
            ob_detected = bool(features.get('order_block_detected', False))
            sweep_reclaimed = bool(features.get('sweep_reclaimed', False))
            
            if ob_detected and sweep_reclaimed:
                patterns_detected.append({
                    'pattern': 'ORDER_BLOCK_SWEEP_RECLAIM',
                    'name': 'Perfect SMC Setup',
                    'confidence': 95,
                    'description': 'OB held + Sweep reclaimed = institutional entry'
                })
                debug_info['pattern_1'] = 'detected'
        except Exception as e:
            debug_info['pattern_1_error'] = str(e)
        
        # PATTERN 2: Structure Trend + Breakout (WITH GUARDS)
        try:
            if direction == "buy":
                higher_lows = 0
                for i in range(len(lows) - 1, max(0, len(lows) - 15), -1):
                    try:
                        if i > 0 and float(lows[i]) > float(lows[i-1]):
                            higher_lows += 1
                        else:
                            break
                    except:
                        break
                
                if higher_lows >= 4:
                    patterns_detected.append({
                        'pattern': 'MULTI_HIGHER_LOWS_BREAKOUT',
                        'name': 'Strong Uptrend Continuation',
                        'confidence': 85,
                        'description': f'{higher_lows} consecutive higher lows + momentum breakout'
                    })
                    debug_info['pattern_2'] = f'detected ({higher_lows} HL)'
            else:  # sell
                lower_highs = 0
                for i in range(len(highs) - 1, max(0, len(highs) - 15), -1):
                    try:
                        if i > 0 and float(highs[i]) < float(highs[i-1]):
                            lower_highs += 1
                        else:
                            break
                    except:
                        break
                
                if lower_highs >= 4:
                    patterns_detected.append({
                        'pattern': 'MULTI_LOWER_HIGHS_BREAKOUT',
                        'name': 'Strong Downtrend Continuation',
                        'confidence': 85,
                        'description': f'{lower_highs} consecutive lower highs + momentum breakout'
                    })
                    debug_info['pattern_2'] = f'detected ({lower_highs} LH)'
        except Exception as e:
            debug_info['pattern_2_error'] = str(e)
        
        # PATTERN 3: Volume Explosion (SAFE DIVISION)
        try:
            if len(volumes) < 21:
                avg_vol_20 = np.mean(volumes) if len(volumes) > 0 else 1.0
            else:
                avg_vol_20 = np.mean(volumes[-21:-1])
            
            avg_vol_20 = float(avg_vol_20)
            if avg_vol_20 <= 0 or np.isnan(avg_vol_20) or np.isinf(avg_vol_20):
                avg_vol_20 = 1.0
            
            current_vol = float(volumes[-1]) if len(volumes) > 0 else 1.0
            current_vol = abs(current_vol)  # Handle negative volumes
            
            vol_ratio = current_vol / avg_vol_20
            vol_ratio = max(0.0, min(20.0, vol_ratio))  # Constrain 0-20x
            
            if vol_ratio >= 2.5:
                patterns_detected.append({
                    'pattern': 'VOLUME_EXPLOSION',
                    'name': 'Institutional Volume',
                    'confidence': 90,
                    'description': f'Volume spike {vol_ratio:.1f}x - institutional move confirmed'
                })
                debug_info['pattern_3'] = f'EXPLOSION ({vol_ratio:.1f}x)'
            elif vol_ratio >= 1.8:
                patterns_detected.append({
                    'pattern': 'VOLUME_SURGE',
                    'name': 'Strong Volume Confirmation',
                    'confidence': 80,
                    'description': f'Volume surge {vol_ratio:.1f}x confirms move'
                })
                debug_info['pattern_3'] = f'SURGE ({vol_ratio:.1f}x)'
        except Exception as e:
            debug_info['pattern_3_error'] = str(e)
        
        # PATTERN 4: Rejection/Reversal from Structure
        try:
            momentum_confirmation = features.get('momentum_confirmation', {})
            momentum_strong = isinstance(momentum_confirmation, dict) and 'STRONG' in str(momentum_confirmation.get('confirmation', '')).upper()
            sweep_detected = bool(features.get('sweep_detected', False))
            
            if momentum_strong and sweep_detected:
                patterns_detected.append({
                    'pattern': 'STRUCTURE_REJECTION',
                    'name': 'Smart Money Rejection',
                    'confidence': 88,
                    'description': 'Price rejected structure + momentum confirmation = MM entry'
                })
                debug_info['pattern_4'] = 'detected'
        except Exception as e:
            debug_info['pattern_4_error'] = str(e)
        
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # DETERMINE PRIMARY PATTERN WITH SAFE INDEXING
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        primary_pattern = 'NONE'
        max_confidence = 0
        
        try:
            if len(patterns_detected) > 0:
                # Sort by confidence and get highest
                sorted_patterns = sorted(patterns_detected, key=lambda x: float(x.get('confidence', 0)), reverse=True)
                if len(sorted_patterns) > 0:
                    primary_pattern = sorted_patterns[0].get('pattern', 'NONE')
                    max_confidence = int(sorted_patterns[0].get('confidence', 0))
                    max_confidence = max(0, min(100, max_confidence))  # Bounds check
        except Exception as e:
            debug_info['primary_pattern_error'] = str(e)
        
        # ═══════════════════════════════════════════════════════════════════════════════════════
        # RETURN WITH VALIDATION
        # ═══════════════════════════════════════════════════════════════════════════════════════
        
        return {
            'patterns': patterns_detected if isinstance(patterns_detected, list) else [],
            'primary_pattern': str(primary_pattern),
            'confidence': int(max_confidence),
            'total_patterns_found': len(patterns_detected) if isinstance(patterns_detected, list) else 0,
            'debug': debug_info
        }
    
    except Exception as e:
        import traceback
        return {
            'patterns': [],
            'primary_pattern': 'NONE',
            'confidence': 0,
            'total_patterns_found': 0,
            'debug': {'critical_error': str(e), 'traceback': traceback.format_exc()}
        }

def find_optimal_entry_in_zone(df, zone_low, zone_high, direction="buy", lookback=20):
    """
    OPTIMAL ENTRY ZONE: Find best entry point within zone (lower SL)
    """
    try:
        if df is None or zone_low >= zone_high:
            return {'price': (zone_low + zone_high) / 2, 'probability': 50}
        
        closes = df['close'].values[-lookback:]
        highs = df['high'].values[-lookback:]
        lows = df['low'].values[-lookback:]
        
        zone_size = zone_high - zone_low
        zone_mid = (zone_low + zone_high) / 2
        
        if direction == "buy":
            zone_lows_in_range = [l for l in lows if zone_low <= l <= zone_high]
            if zone_lows_in_range:
                support = min(zone_lows_in_range)
            else:
                support = zone_low
            
            optimal_price = support
            distance_from_bottom = (optimal_price - zone_low) / zone_size if zone_size > 0 else 0
            probability = max(50, 85 - (distance_from_bottom * 50))
        else:
            zone_highs_in_range = [h for h in highs if zone_low <= h <= zone_high]
            if zone_highs_in_range:
                resistance = max(zone_highs_in_range)
            else:
                resistance = zone_high
            
            optimal_price = resistance
            distance_from_top = (zone_high - optimal_price) / zone_size if zone_size > 0 else 0
            probability = max(50, 85 - (distance_from_top * 50))
        
        return {
            'optimal_price': float(optimal_price),
            'zone_low': float(zone_low),
            'zone_high': float(zone_high),
            'zone_mid': float(zone_mid),
            'probability': int(probability),
            'recommendation': 'ENTER_NOW' if probability >= 75 else 'WAIT_FOR_BETTER_PRICE'
        }
    except Exception:
        return {'price': (zone_low + zone_high) / 2, 'probability': 50}

def detect_trend_chasing(df, direction="buy"):
    """
    🚫 TREND CHASING DETECTOR: Prevents entering late in mature trends
    
    Logic:
    - Find last swing (high for sells, low for buys)
    - Count bars since that swing (trend age)
    - If trend_age > 8 bars + momentum declining → REJECT (late entry)
    - If fresh trend (< 8 bars) → ALLOW (early stage)
    - If pullback detected + strong momentum → ALLOW (reconfirmation)
    
    Returns: {'is_chasing': bool, 'trend_age': int, 'momentum_declining': bool, 'reason': str}
    """
    try:
        if df is None or len(df) < 20:
            return {'is_chasing': False, 'trend_age': 0, 'momentum_declining': False, 'reason': 'Not enough data'}
        
        closes = df['close'].values
        highs = df['high'].values
        lows = df['low'].values
        
        # Calculate RSI to measure momentum
        deltas = np.diff(closes)
        gains = np.where(deltas > 0, deltas, 0)
        losses = np.where(deltas < 0, -deltas, 0)
        avg_gain = np.mean(gains[-14:]) if len(gains) >= 14 else np.mean(gains)
        avg_loss = np.mean(losses[-14:]) if len(losses) >= 14 else np.mean(losses)
        rs = avg_gain / avg_loss if avg_loss > 0 else 100
        rsi = 100 - (100 / (1 + rs))
        
        if direction == "buy":
            # Find last swing low (start of uptrend)
            swing_low_val = None
            swing_low_idx = None
            for i in range(len(lows) - 1, max(0, len(lows) - 30), -1):
                is_swing = True
                for j in range(1, 3):
                    if i - j >= 0 and lows[i] >= lows[i - j]:
                        is_swing = False
                        break
                    if i + j < len(lows) and lows[i] >= lows[i + j]:
                        is_swing = False
                        break
                if is_swing:
                    swing_low_val = lows[i]
                    swing_low_idx = i
                    break
            
            if swing_low_idx is not None:
                trend_age = len(lows) - 1 - swing_low_idx  # Bars since swing low
                momentum_declining = rsi > 60  # RSI above 60 = overbought, momentum fading
                
                # REJECTION RULE: If trend age > 8 bars AND momentum declining → CHASING
                if trend_age > 8 and momentum_declining:
                    return {
                        'is_chasing': True,
                        'trend_age': trend_age,
                        'momentum_declining': True,
                        'reason': f'Late entry: {trend_age} bars since swing low, RSI={rsi:.0f} (overbought)',
                        'rsi': rsi
                    }
                elif trend_age > 12:
                    # Even with good momentum, don't enter >12 bars into trend
                    return {
                        'is_chasing': True,
                        'trend_age': trend_age,
                        'momentum_declining': momentum_declining,
                        'reason': f'Trend too old: {trend_age} bars since swing low - wait for pullback',
                        'rsi': rsi
                    }
                
                return {
                    'is_chasing': False,
                    'trend_age': trend_age,
                    'momentum_declining': momentum_declining,
                    'reason': f'Early trend: {trend_age} bars in, RSI={rsi:.0f}',
                    'rsi': rsi
                }
        
        else:  # SELL
            # Find last swing high (start of downtrend)
            swing_high_val = None
            swing_high_idx = None
            for i in range(len(highs) - 1, max(0, len(highs) - 30), -1):
                is_swing = True
                for j in range(1, 3):
                    if i - j >= 0 and highs[i] <= highs[i - j]:
                        is_swing = False
                        break
                    if i + j < len(highs) and highs[i] <= highs[i + j]:
                        is_swing = False
                        break
                if is_swing:
                    swing_high_val = highs[i]
                    swing_high_idx = i
                    break
            
            if swing_high_idx is not None:
                trend_age = len(highs) - 1 - swing_high_idx  # Bars since swing high
                momentum_declining = rsi < 40  # RSI below 40 = oversold, momentum fading
                
                # REJECTION RULE: If trend age > 8 bars AND momentum declining → CHASING
                if trend_age > 8 and momentum_declining:
                    return {
                        'is_chasing': True,
                        'trend_age': trend_age,
                        'momentum_declining': True,
                        'reason': f'Late entry: {trend_age} bars since swing high, RSI={rsi:.0f} (oversold)',
                        'rsi': rsi
                    }
                elif trend_age > 12:
                    # Even with good momentum, don't enter >12 bars into trend
                    return {
                        'is_chasing': True,
                        'trend_age': trend_age,
                        'momentum_declining': momentum_declining,
                        'reason': f'Trend too old: {trend_age} bars since swing high - wait for pullback',
                        'rsi': rsi
                    }
                
                return {
                    'is_chasing': False,
                    'trend_age': trend_age,
                    'momentum_declining': momentum_declining,
                    'reason': f'Early trend: {trend_age} bars in, RSI={rsi:.0f}',
                    'rsi': rsi
                }
        
        return {'is_chasing': False, 'trend_age': 0, 'momentum_declining': False, 'reason': 'No swing found'}
    
    except Exception as e:
        return {'is_chasing': False, 'trend_age': 0, 'momentum_declining': False, 'reason': f'Error: {e}'}

def get_momentum_confirmation(df, direction="buy", threshold_buy=30, threshold_sell=70):
    """
    MOMENTUM CONFIRMATION: RSI/Stochastic at support/resistance
    """
    try:
        if df is None or len(df) < 50:
            return {'rsi': 50, 'stoch': 50, 'momentum_score': 50, 'confirmation': 'NEUTRAL'}
        
        closes = df['close'].values
        
        # CALCULATE RSI (14-period)
        deltas = np.diff(closes)
        gains = np.where(deltas > 0, deltas, 0)
        losses = np.where(deltas < 0, -deltas, 0)
        
        avg_gain = np.mean(gains[-14:]) if len(gains) >= 14 else np.mean(gains)
        avg_loss = np.mean(losses[-14:]) if len(losses) >= 14 else np.mean(losses)
        
        rs = avg_gain / avg_loss if avg_loss > 0 else 100
        rsi = 100 - (100 / (1 + rs))
        
        # CALCULATE STOCHASTIC (14, 3)
        lows_14 = np.min(df['low'].values[-14:])
        highs_14 = np.max(df['high'].values[-14:])
        current_close = closes[-1]
        
        stoch_raw = ((current_close - lows_14) / (highs_14 - lows_14)) * 100 if (highs_14 - lows_14) > 0 else 50
        stoch = stoch_raw
        
        momentum_score = 50
        confirmation = 'NEUTRAL'
        
        if direction == "buy":
            if rsi < threshold_buy:
                momentum_score = int(35 - rsi)
                confirmation = "🟢 STRONG_BUY"
            elif rsi < 50:
                momentum_score = int(35)
                confirmation = "🟡 MILD_BUY"
            else:
                momentum_score = int(20)
                confirmation = "🔴 WAIT"
        else:
            if rsi > threshold_sell:
                momentum_score = int(rsi - 50)
                confirmation = "🟢 STRONG_SELL"
            elif rsi > 50:
                momentum_score = int(35)
                confirmation = "🟡 MILD_SELL"
            else:
                momentum_score = int(20)
                confirmation = "🔴 WAIT"
        
        return {
            'rsi': round(rsi, 1),
            'stochastic': round(stoch, 1),
            'momentum_score': momentum_score,
            'confirmation': confirmation
        }
    except Exception:
        return {'rsi': 50, 'stoch': 50, 'momentum_score': 50, 'confirmation': 'ERROR'}

def calculate_weighted_confluence_score(signals_dict):
    """
    WEIGHTED CONFLUENCE: Intelligent weighting (not equal weight)
    BOS=25%, Sweep=20%, Structure=20%, Momentum=15%, Volume=10%, RR=10%
    """
    try:
        bos_score = signals_dict.get('bos_score', 0)
        sweep_score = signals_dict.get('sweep_score', 0)
        structure_score = signals_dict.get('structure_score', 0)
        momentum_score = signals_dict.get('momentum_score', 0)
        volume_score = signals_dict.get('volume_score', 0)
        rr_score = signals_dict.get('rr_score', 0)
        
        WEIGHTS = {
            'bos': 0.25,
            'sweep': 0.20,
            'structure': 0.20,
            'momentum': 0.15,
            'volume': 0.10,
            'rr': 0.10
        }
        
        weighted_total = (
            bos_score * WEIGHTS['bos'] +
            sweep_score * WEIGHTS['sweep'] +
            structure_score * WEIGHTS['structure'] +
            momentum_score * WEIGHTS['momentum'] +
            volume_score * WEIGHTS['volume'] +
            rr_score * WEIGHTS['rr']
        )
        
        if weighted_total >= 85:
            grade = "🟢🟢 ELITE CONFLUENCE"
        elif weighted_total >= 75:
            grade = "🟢 HIGH CONFLUENCE"
        elif weighted_total >= 70:
            grade = "🟡 GOOD CONFLUENCE"
        elif weighted_total >= 60:
            grade = "🟠 ACCEPTABLE"
        else:
            grade = "🔴 SKIP"
        
        return {
            'weighted_score': int(weighted_total),
            'grade': grade,
            'signal_strength': {
                'bos': bos_score,
                'sweep': sweep_score,
                'structure': structure_score,
                'momentum': momentum_score,
                'volume': volume_score,
                'rr': rr_score
            },
            'recommendation': 'EXECUTE' if weighted_total >= 70 else 'SKIP'
        }
    except Exception:
        return {'weighted_score': 0, 'grade': '🔴 ERROR', 'recommendation': 'SKIP'}

def calculate_dynamic_lot_size(base_lot, confluence_score, rr_ratio, account_balance=5000):
    """
    POSITION SIZING BY CONFLUENCE: Scale lot size based on setup quality
    
    Start: base_lot = SYMBOL_MAX_LOT (your configured static lot)
    Scale by confluence & RR, but NEVER EXCEED base_lot (ceiling at your static values)
    
    Logic:
    - ELITE (85+): 100% base lot (FULL)
    - HIGH (75-84): 85% base lot
    - GOOD (70-74): 70% base lot
    - ACCEPTABLE (60-69): 50% base lot
    - WEAK (<60): 30% base lot (minimum, allows some downside)
    
    Additional adjustments:
    - RR bonus: If RR > 2.5, add 10% (capped at base_lot)
    - RR penalty: If RR < 1.5, reduce 20%
    
    Result is CAPPED AT base_lot (never exceeds your static configuration)
    """
    try:
        if confluence_score >= 85:
            multiplier = 1.0
            quality = "ELITE"
        elif confluence_score >= 75:
            multiplier = 0.85
            quality = "HIGH"
        elif confluence_score >= 70:
            multiplier = 0.70
            quality = "GOOD"
        elif confluence_score >= 60:
            multiplier = 0.50
            quality = "ACCEPTABLE"
        else:
            multiplier = 0.30  # Updated from 0.10 to 0.30 (less aggressive downside)
            quality = "WEAK"
        
        # RR adjustments
        if rr_ratio >= 2.5:
            multiplier = min(1.0, multiplier * 1.10)  # +10% for excellent RR (but capped at 1.0)
        elif rr_ratio < 1.5:
            multiplier = multiplier * 0.80  # -20% for poor RR
        
        final_lot = base_lot * multiplier
        
        # ✅ CEILING: Never exceed base_lot (your static configuration)
        # FLOOR: Don't go too low (30% of base_lot minimum)
        final_lot = max(base_lot * 0.30, min(base_lot, final_lot))
        
        return {
            'lot_size': round(final_lot, 4),
            'multiplier': round(multiplier, 2),
            'quality_grade': quality,
            'confluence_score': confluence_score,
            'rr_ratio': round(rr_ratio, 2),
            'details': f"{quality}: {confluence_score}/100 | RR: {rr_ratio:.1f}:1 | Size: {multiplier:.0%} of base (max {base_lot:.4f})"
        }
    except Exception as e:
        # Fallback: use 50% of base lot on error
        return {'lot_size': round(base_lot * 0.5, 4), 'multiplier': 0.5, 'quality_grade': 'ERROR'}

def should_trade_advanced(signal, confidence, features, spread, symbol=None, min_confidence=0.4, df=None):
    """
    Weighted confluence entry logic: combines ML, candlestick, structure/chart patterns,
    pattern strength, volume, volatility, cluster, session, news, and risk management.
    Returns (should_enter: bool, reason: str)
    """
    # ✅ FIRST GATE: Check if symbol is disabled
    if symbol:
        symbol_base = symbol.upper().split('.')[0]
        if symbol_base in DISABLED_SYMBOLS:
            return False, f"{symbol_base} is disabled - no entries allowed"
    
    # ✅ DEBUG START: Comprehensive gate logging
    if symbol:
        print(f"\n{'='*100}")
        print(f"🔍 [ENTRY GATE AUDIT] {symbol.upper()} | Signal: {signal.upper()} | ML Confidence: {confidence:.2f}")
        print(f"   Mode: STRICT (confluence ≥4, SL tight, RR ≥2.0)")
        print(f"{'='*100}")
    
    # --- Require FVG for entry ---
    fvg_status = features.get("fvg", None)
    if fvg_status is None or fvg_status == "none":
        if symbol:
            print(f"❌ [GATE 1 - FVG] BLOCKED: FVG required but not present")
        return False, "FVG required for entry but not present"

    # --- FVG direction must agree with ML signal ---
    direction_map = {"bull": "buy", "bear": "sell"}
    fvg_direction = direction_map.get(fvg_status, None)
    if fvg_direction and signal in ("buy", "sell") and fvg_direction != signal:
        if symbol:
            print(f"❌ [GATE 2 - FVG DIRECTION] BLOCKED: FVG {fvg_direction} != signal {signal}")
        return False, f"FVG direction ({fvg_direction}) does not agree with ML signal ({signal})"
    else:
        if symbol:
            print(f"✅ [GATE 2 - FVG DIRECTION] PASSED: {fvg_direction} aligns with {signal}")

    # --- Entry price must be within FVG entry zone ---
    fvg_zone = features.get("fvg_zone", None)
    price = features.get("close", None)
    if fvg_zone and price is not None:
        zone_low = fvg_zone.get("low", None)
        zone_high = fvg_zone.get("high", None)
        if zone_low is not None and zone_high is not None:
            if not (zone_low <= price <= zone_high):
                if symbol:
                    print(f"❌ [GATE 3 - FVG ZONE] BLOCKED: Price {price:.5f} outside zone {zone_low:.5f}-{zone_high:.5f}")
                return False, f"Entry price {price} not within FVG entry zone ({zone_low} - {zone_high})"
            else:
                if symbol:
                    print(f"✅ [GATE 3 - FVG ZONE] PASSED: Price {price:.5f} within zone {zone_low:.5f}-{zone_high:.5f}")

    # --- Check max entries per symbol (max 5 concurrent entries per config) ---
    if symbol:
        can_enter, entry_check_reason = can_enter_symbol(symbol, max_entries_per_symbol=MAX_ENTRIES_PER_SYMBOL, signal=signal, features=features, df=df)
        if not can_enter:
            print(f"❌ [GATE 4 - MAX ENTRIES] BLOCKED: {entry_check_reason}")
            return False, entry_check_reason
        print(f"✅ [GATE 4 - MAX ENTRIES] PASSED: {entry_check_reason}")

    # ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
    # ✅ NEW FILTER GATES: Check all 4 new filters before proceeding
    # ════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════
    
    # FILTER 1: Higher Timeframe Bias Filter
    if symbol:
        htf_valid, htf_reason = check_htf_bias_filter(symbol, signal)
        if htf_valid:
            print(f"✅ [FILTER 1 - HTF BIAS] PASSED: {htf_reason}")
        else:
            print(f"❌ [FILTER 1 - HTF BIAS] BLOCKED: {htf_reason}")
            return False, htf_reason
    
    # FILTER 4: Consolidation/Chop Filter (MUST check before structure to avoid choppy moves)
    if df is not None and not df.empty:
        chop_valid, chop_reason = check_consolidation_filter(df, lookback=20, chop_threshold=45)
        if chop_valid:
            print(f"✅ [FILTER 4 - CONSOLIDATION] PASSED: {chop_reason}")
        else:
            print(f"❌ [FILTER 4 - CONSOLIDATION] BLOCKED: {chop_reason}")
            return False, chop_reason
    
    # FILTER 2: Structure Break Confirmation
    if df is not None and not df.empty:
        struct_valid, struct_reason = check_structure_break_confirmation(df, signal, lookback=20)
        if struct_valid:
            print(f"✅ [FILTER 2 - STRUCTURE] PASSED: {struct_reason}")
        else:
            print(f"❌ [FILTER 2 - STRUCTURE] BLOCKED: {struct_reason}")
            return False, struct_reason
    
    # FILTER 3: Entry Zone Filter
    if symbol and df is not None and not df.empty:
        zone_valid, zone_reason = check_entry_zone_filter(df, symbol, signal)
        if zone_valid:
            print(f"✅ [FILTER 3 - ENTRY ZONE] PASSED: {zone_reason}")
        else:
            print(f"❌ [FILTER 3 - ENTRY ZONE] BLOCKED: {zone_reason}")
            return False, zone_reason

    # --- Robustly ensure confidence is a float ---
    try:
        confidence = float(confidence)
    except (TypeError, ValueError):
        confidence = 0.0
    spread_threshold = get_spread_threshold(symbol)

    # --- Recovery logic state ---
    global recovery_state
    if 'recovery_state' not in globals():
        recovery_state = {}
    if symbol not in recovery_state:
        recovery_state[symbol] = {"active": False, "direction": None}

    # If in recovery mode, only allow the recovery direction
    if recovery_state[symbol]["active"]:
        if signal != recovery_state[symbol]["direction"]:
            return False, f"GPS Recovery: Only taking recovery {recovery_state[symbol]['direction']} trade after loss"

    # --- Volatility thresholds by symbol ---
    symbol_vol_thresholds = {
        "EURUSD": 0.0003,
        "GBPUSD": 0.0004,

        "XAUUSD": 0.5,
    }
    default_vol_threshold = 0.0005

    volatility_val = features.get("volatility_cluster", 0)
    atr_val = features.get("atr", 0)
    vol_threshold = symbol_vol_thresholds.get(symbol, default_vol_threshold)

    # If London/NY session, allow lower volatility threshold
    if features.get("is_london", 0) or features.get("is_ny", 0):
        vol_threshold *= 0.7

    volatility_ok = volatility_val > vol_threshold or atr_val > vol_threshold
    if not volatility_ok:
        print(f"[DEBUG] Volatility check: volatility_cluster={volatility_val:.5f}, atr={atr_val:.5f}, threshold={vol_threshold:.5f}")
        print(f"[WARNING] Volatility below normal threshold, but allowing trade for more signals.")

    # --- Candlestick and chart pattern scoring ---
    candlestick_patterns = [
        "cdl_hammer", "cdl_inverted_hammer", "cdl_morning_star", "cdl_evening_star",
        "cdl_bullish_engulfing", "cdl_bearish_engulfing", "cdl_doji", "cdl_hanging_man",
        "cdl_shooting_star", "cdl_piercing", "cdl_dark_cloud_cover", "cdl_three_white_soldiers",
        "cdl_three_black_crows", "cdl_tweezer_top", "cdl_tweezer_bottom", "cdl_inside",
        "is_bullish_engulfing", "is_bearish_engulfing", "is_pin_bar", "is_hammer", "is_tweezer_top", "is_tweezer_bottom"
    ]
    candlestick_score = sum(features.get(p, 0) for p in candlestick_patterns)
    candlestick_score = min(candlestick_score / 3, 1)  # Normalize (0-1, 3+ patterns = max)

    chart_patterns = [
        "is_double_top", "is_double_bottom", "is_head_and_shoulders", "is_inverse_head_and_shoulders",
        "is_flag", "is_triangle", "is_edge"
    ]
    chart_score = sum(features.get(p, 0) for p in chart_patterns)
    chart_score = min(chart_score / 2, 1)  # Normalize (0-1, 2+ patterns = max)

    # --- ML confidence fallback to pattern confluence ---
    # Defensive: ensure min_confidence is a float and not None
    if min_confidence is None:
        min_confidence = 0.0
    try:
        min_confidence = float(min_confidence)
    except Exception:
        min_confidence = 0.0

    if confidence < min_confidence:
        strong_candle = features.get("bullish_pattern_strength", 0) >= 1 if signal == "buy" else features.get("bearish_pattern_strength", 0) >= 1
        strong_chart = (
            (features.get("is_double_bottom", 0) or features.get("is_inverse_head_and_shoulders", 0))
            if signal == "buy"
            else (features.get("is_double_top", 0) or features.get("is_head_and_shoulders", 0))
        )
        pattern_agrees = strong_candle or strong_chart

        if pattern_agrees:
            print(f"[INFO] ML confidence low ({confidence:.2f} < {min_confidence:.2f}), but strong candlestick/chart pattern agrees with ML direction. Allowing trade based on patterns.")
            return True, f"Pattern confluence overrides ML confidence for {signal.upper()}"
        else:
            print(f"[DEBUG] Candlestick features: bullish={features.get('bullish_pattern_strength', 0)}, bearish={features.get('bearish_pattern_strength', 0)}")
            print(f"[DEBUG] Chart features: double_bottom={features.get('is_double_bottom', 0)}, inverse_hns={features.get('is_inverse_head_and_shoulders', 0)}, double_top={features.get('is_double_top', 0)}, hns={features.get('is_head_and_shoulders', 0)}")
            return False, f"GPS+ML filter: ML confidence too low ({confidence:.2f} < {min_confidence:.2f}) and no strong candlestick/chart confluence"

    # --- Trend/volatility/session filters (as before) ---
    ema50 = features.get("ema50")
    ema200 = features.get("ema200")
    last_close = features.get("close", None)
    # Defensive: ensure last_close is a float and not None
    if last_close is None or not isinstance(last_close, (int, float)):
        if df is not None and len(df) > 0:
            last_valid_close = df['close'][df['close'] != 0].iloc[-1] if (df['close'] != 0).any() else df['close'].iloc[-1]
            last_close = float(last_valid_close)
            features['close'] = last_close
        else:
            last_close = 0.0
    elif last_close == 0:
        last_close = 0.0

    trend_up = last_close > ema50 > ema200 if (ema50 is not None and ema200 is not None) else False
    trend_down = last_close < ema50 < ema200 if (ema50 is not None and ema200 is not None) else False

    if (signal == "buy" and not trend_up) or (signal == "sell" and not trend_down):
        if symbol:
            trend_status = "UP" if trend_up else "DOWN" if trend_down else "NONE"
            print(f"❌ [GATE 5 - TREND CONFIRMATION] BLOCKED: Signal={signal.upper()} but trend={trend_status} | Close={last_close:.5f}, EMA50={ema50}, EMA200={ema200}")
        return False, "GPS+ML filter: ML/indicator confluence not met"
    else:
        if symbol:
            trend_status = "UP" if trend_up else "DOWN"
            print(f"✅ [GATE 5 - TREND CONFIRMATION] PASSED: {trend_status} trend matches {signal.upper()} signal")

    # ============================================================================
    # NEW: ENHANCED SELL VALIDATION (Pullback + Premium Zone + Structure)
    # ============================================================================
    if signal == "sell":
        # 1. Validate pullback zones and check for bullish momentum protection
        pullback_valid, pullback_reason = validate_sell_pullback(df, lookback=20)
        if not pullback_valid:
            if symbol:
                print(f"❌ [GATE S1 - SELL PULLBACK] BLOCKED: {pullback_reason}")
            return False, pullback_reason
        else:
            if symbol:
                print(f"✅ [GATE S1 - SELL PULLBACK] PASSED: {pullback_reason}")
        
        # 2. Confirm price is at PREMIUM zone (near supply/recent highs, not in middle of move)
        at_premium, zone_info = is_at_premium_zone(df, symbol, lookback=50)
        if not at_premium:
            if symbol:
                print(f"❌ [GATE S2 - SELL PREMIUM ZONE] BLOCKED: Price at {zone_info.get('price_position_pct', 0):.1f}% of range (need >75%)")
            return False, f"SELL ENTRY FILTER: Price not in premium zone. Currently at {zone_info.get('price_position_pct', 0):.1f}% of range (need >75%)"
        else:
            if symbol:
                print(f"✅ [GATE S2 - SELL PREMIUM ZONE] PASSED: Price at {zone_info.get('price_position_pct', 0):.1f}% (in premium zone)")
        
        # 3. Confirm bearish structure (lower high + bearish candle)
        structure_confirmed, structure = confirm_bearish_structure(df, lookback=10)
        if not structure_confirmed:
            if symbol:
                reasons_str = '. '.join(structure.get('reasons', ['Unknown reason']))
                print(f"❌ [GATE S3 - SELL STRUCTURE] BLOCKED: {reasons_str}")
            return False, f"SELL STRUCTURE WAITING: {'. '.join(structure.get('reasons', []))}"
        else:
            if symbol:
                print(f"✅ [GATE S3 - SELL STRUCTURE] PASSED: Bearish structure confirmed (Lower High + Bearish candle)")
        
        if symbol:
            print(f"🟢 [SELL VALIDATION] ✅ All SELL checks passed: Pullback + Premium Zone + Structure confirmed")

    # ============================================================================
    # NEW: ENHANCED BUY VALIDATION (Pullback + Discount Zone + Structure)
    # ============================================================================
    if signal == "buy":
        # 1. Validate pullback zones and check for bearish momentum protection
        pullback_valid, pullback_reason = validate_buy_pullback(df, lookback=20)
        if not pullback_valid:
            if symbol:
                print(f"❌ [GATE B1 - BUY PULLBACK] BLOCKED: {pullback_reason}")
            return False, pullback_reason
        else:
            if symbol:
                print(f"✅ [GATE B1 - BUY PULLBACK] PASSED: {pullback_reason}")
        
        # 2. Confirm price is at DISCOUNT zone (near demand/recent lows, not in middle of move)
        at_discount, zone_info = is_at_discount_zone(df, symbol, lookback=50)
        if not at_discount:
            if symbol:
                print(f"❌ [GATE B2 - BUY DISCOUNT ZONE] BLOCKED: Price at {zone_info.get('price_position_pct', 0):.1f}% of range (need <25%)")
