    def pattern_cluster(df, bullish=True, n=5):
        try:
            import talib
        except ImportError:
            return False
        if len(df) < n + 2:
            return False
        open_ = df['open'].values
        high_ = df['high'].values
        low_ = df['low'].values
        close_ = df['close'].values
        if bullish:
            return (
                sum(talib.CDLENGULFING(open_, high_, low_, close_)[-n:] > 0) +
                sum(talib.CDLHAMMER(open_, high_, low_, close_)[-n:] != 0)
            ) >= 2
        else:
            return (
                sum(talib.CDLENGULFING(open_, high_, low_, close_)[-n:] < 0) +
                sum(talib.CDLHANGINGMAN(open_, high_, low_, close_)[-n:] != 0)
            ) >= 2

