# --- Recovery logic update function ---
def update_recovery_state(symbol, result, last_direction):
    """
    Call this after each trade closes.
    If the trade was a loss, activate recovery mode and set the reverse direction.
    If the trade was a win, deactivate recovery mode.
    """
    global recovery_state
    if 'recovery_state' not in globals():
        recovery_state = {}
    if symbol not in recovery_state:
        recovery_state[symbol] = {"active": False, "direction": None}
    if result < 0:
        # Activate recovery mode with reverse direction
        recovery_state[symbol]["active"] = True
        recovery_state[symbol]["direction"] = "sell" if last_direction == "buy" else "buy"
    else:
        # Deactivate recovery mode
        recovery_state[symbol]["active"] = False
        recovery_state[symbol]["direction"] = None

