# --- Vectorized and Deep Learning-Ready Backtest ---
def vectorized_backtest_xauusd_m15(model, bars=5000, timeframe="M15"):
    """
    Fast, vectorized backtest for XAUUSD M15 using numpy/pandas.
    Supports both sklearn and deep learning models (keras, pytorch).
    Only uses London/NY session bars and the same feature/decision logic as live trading.
    """
    symbol = "XAUUSD"
    df = get_backtest_data(symbol, timeframe=timeframe, bars=bars)
    if df is None or len(df) < 200:
        print("[BACKTEST] Not enough XAUUSD M15 data.")
        return []

    # --- Add market structure features ---
    df = detect_structure(df)

    # --- Vectorized feature engineering ---
    # Precompute all features in a DataFrame for speed
    feature_rows = []
    for i in range(50, len(df)):
        window = df.iloc[:i+1]
        try:
            features = get_features_fixed(window)
            # Only use session bars
            if not (features.get("is_london", 0) or features.get("is_ny", 0)):
                continue
            feature_rows.append((i, features))
        except Exception:
            continue

    if not feature_rows:
        print("[BACKTEST] No valid session bars for XAUUSD backtest.")
        return []

    # Build feature matrix for ML model
    feature_order = [
        "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
        "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
        "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength"
    ]
    X = np.array([[f.get(k, 0) for k in feature_order] for _, f in feature_rows])

    # --- Deep learning support: keras/pytorch models ---
    if hasattr(model, "predict_proba"):
        preds = model.predict_proba(X)
        pred_labels = model.model.predict(X)
    elif hasattr(model, "predict"):  # keras or torch
        preds = model.predict(X)
        pred_labels = np.argmax(preds, axis=1)
    else:
        preds = np.zeros((len(X), 3))
        pred_labels = np.zeros(len(X))

    # --- Vectorized trade simulation ---
    trades = []
    for idx, (i, features) in enumerate(feature_rows):
        ml_signal = model.label_map.get(pred_labels[idx], "hold") if hasattr(model, "label_map") else pred_labels[idx]
        confidence = preds[idx][int(pred_labels[idx])] if preds.shape[1] > int(pred_labels[idx]) else np.max(preds[idx])
        atr = features.get("atr", 0)
        ema50 = features.get("ema50", 0)
        ema200 = features.get("ema200", 0)
        last_close = df['close'].iloc[i]
        trend_up = last_close > ema50 > ema200
        trend_down = last_close < ema50 < ema200
        volatility_ok = features.get("volatility_cluster", 0) > 0.0002 or atr > 0.0002
        bullish_score = features.get("bullish_pattern_strength", 0)
        bearish_score = features.get("bearish_pattern_strength", 0)
        is_london = features.get("is_london", 0)
        is_ny = features.get("is_ny", 0)

        # Weighted decision logic (same as live)
        ml_w = 0.4
        gps_w = 0.2
        vol_w = 0.15
        candle_w = 0.15
        session_w = 0.1

        ml_score = confidence
        gps_score = 1.0 if ((ml_signal == "buy" and trend_up) or (ml_signal == "sell" and trend_down)) else 0.0
        vol_score = 1.0 if volatility_ok else 0.0
        candle_score = bullish_score if ml_signal == "buy" else bearish_score if ml_signal == "sell" else 0.0
        session_score = 1.0 if (is_london or is_ny) else 0.0

        total_score = (
            ml_w * ml_score +
            gps_w * gps_score +
            vol_w * vol_score +
            candle_w * min(candle_score / 2, 1.0) +
            session_w * session_score
        )

        ENTRY_THRESHOLD = 0.65
        if total_score < ENTRY_THRESHOLD:
            continue

        # --- Safety filters: RR, time, GPS-style stops ---
        entry = df['close'].iloc[i]
        sl = entry - 0.0015 if ml_signal == "buy" else entry + 0.0015
        tp = entry + 0.0020 if ml_signal == "buy" else entry - 0.0020
        min_stop = atr * 0.5
        if ml_signal == "buy" and abs(entry - sl) < min_stop:
            sl = entry - min_stop
        if ml_signal == "sell" and abs(entry - sl) < min_stop:
            sl = entry + min_stop

        # RR check
        if not risk_reward_ok(entry, sl, tp):
            continue

        # Time filter: avoid trading late Friday (after 15:00 UTC)
        now = df['time'].iloc[i]
        if now.weekday() == 4 and now.hour > 15:
            continue

        # Simulate trade exit (vectorized: use next bar's high/low)
        if i+1 >= len(df):
            continue
        high = df['high'].iloc[i+1]
        low = df['low'].iloc[i+1]
        trade = {
            "entry": entry,
            "sl": sl,
            "tp": tp,
            "direction": ml_signal,
            "open_time": df['time'].iloc[i]
        }
        if ml_signal == "buy":
            if low <= sl:
                trade['exit'] = sl
                trade['result'] = sl - entry
            elif high >= tp:
                trade['exit'] = tp
                trade['result'] = tp - entry
            else:
                continue
        elif ml_signal == "sell":
            if high >= sl:
                trade['exit'] = sl
                trade['result'] = entry - sl
            elif low <= tp:
                trade['exit'] = tp
                trade['result'] = entry - tp
            else:
                continue
        else:
            continue
        trades.append(trade)
    print(f"[VEC BACKTEST] XAUUSD M15: {len(trades)} trades generated.")
    return trades

# --- Example: Deep Learning Model Wrapper (Keras) ---

def detect_structure(df, window=5, tolerance=1e-6):
    """
    Adds market structure points (HH, HL, LH, LL) as binary features to the DataFrame.
    Uses rolling window (default 5 bars) for comparison, making detection more sensitive.
    """
    df = df.copy()
    df.columns = [col.lower() for col in df.columns]
    # Rolling max/min for last N bars (excluding current)
    high_max = df['high'].rolling(window, min_periods=1).max().shift(1)
    low_max = df['low'].rolling(window, min_periods=1).max().shift(1)
    high_min = df['high'].rolling(window, min_periods=1).min().shift(1)
    low_min = df['low'].rolling(window, min_periods=1).min().shift(1)
    # HH: current high/low >= max of previous N highs/lows
    df['HH'] = ((df['high'] >= high_max - tolerance) & (df['low'] >= low_max - tolerance)).astype(int)
    # HL: current low >= min of previous N lows, high <= max of previous N highs
    df['HL'] = ((df['low'] >= low_min - tolerance) & (df['high'] <= high_max + tolerance)).astype(int)
    # LH: current high <= min of previous N highs, low <= max of previous N lows
    df['LH'] = ((df['high'] <= high_min + tolerance) & (df['low'] <= low_max + tolerance)).astype(int)
    # LL: current low <= min of previous N lows, high <= min of previous N highs
    df['LL'] = ((df['low'] <= low_min + tolerance) & (df['high'] <= high_min + tolerance)).astype(int)
    return df

# --- Example: Deep Learning Model Training (Keras) ---
def train_keras_deep_model(X, y, save_path="keras_model.h5"):
    from tensorflow import keras
    try:
        from tensorflow.keras import layers
    except Exception:
        class _DummyLayers:
            def Dense(self, *a, **k):
                return None
        layers = _DummyLayers()
    num_classes = 3
    y_cat = keras.utils.to_categorical(y, num_classes)
    model = keras.Sequential([
        layers.Input(shape=(X.shape[1],)),
        layers.Dense(128, activation='relu'),
        layers.BatchNormalization(),
        layers.Dense(128, activation='relu'),
        layers.BatchNormalization(),
        layers.Dense(64, activation='relu'),
        layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    model.fit(X, y_cat, epochs=30, batch_size=32, verbose=1)
    model.save(save_path)
    print(f"[DEEP LEARNING] Keras model trained and saved to {save_path}")
    return model

