# === ADVANCED ML: Stacking/Meta-Model Example ===

class StackingMLModel:
    """
    Stacking ensemble: uses predictions from base models as features for a meta-model.
    """
    def __init__(self, base_model_configs, meta_model_path, meta_model_type="sklearn"):
        self.base_models = []
        self.meta_model = None
        try:
            self.base_models = [RealMLModel(cfg["path"], cfg["type"]) for cfg in base_model_configs]
            self.meta_model = RealMLModel(meta_model_path, meta_model_type)
        except NameError:
            pass  # Fallback if RealMLModel not defined

    def predict(self, features):
        base_preds = []
        base_confs = []
        for model in self.base_models:
            signal, conf = model.predict(features)
            # Encode signal as int for meta-model: hold=0, buy=1, sell=2
            base_preds.append({"hold": 0, "buy": 1, "sell": 2}[signal])
            base_confs.append(conf)
        meta_features = np.array([base_preds + base_confs]).reshape(1, -1)
        # Meta-model expects base predictions and confidences as input
        proba = self.meta_model.model.predict_proba(meta_features)[0]
        pred = np.argmax(proba)
        label_map = {0: "hold", 1: "buy", 2: "sell"}
        return label_map[pred], proba[pred]

