# === Live Performance Monitoring ===

def log_live_trade(symbol, direction, entry, sl, tp, result, pnl, strategy_name):
    """
    Log live trade results for performance monitoring and parameter optimization.
    Ensures the log file exists and writes a header if not.
    """
    import os
    log_path = "live_trade_performance_log.csv"
    file_exists = os.path.isfile(log_path)
    # If the file does not exist or is empty, write the header
    write_header = not file_exists or os.path.getsize(log_path) == 0
    with open(log_path, "a") as f:
        if write_header:
            f.write("time,symbol,direction,entry,sl,tp,result,pnl,strategy\n")
        f.write(f"{ datetime.now(timezone.utc)},{symbol},{direction},{entry},{sl},{tp},{result},{pnl},{strategy_name}\n")

import matplotlib.pyplot as plt

def analyze_live_performance(log_path="live_trade_performance_log.csv", plot=True):
    """
    Analyze live trade results for winrate, avg win/loss, drawdown, profit factor, and visualize equity curve.
    """
    import pandas as pd
    import numpy as np
    if not os.path.exists(log_path):
        print("[PERF] No live trade log found.")
        return
    df = pd.read_csv(log_path, header=None, names=["time","symbol","direction","entry","sl","tp","result","pnl","strategy"])
    if df.empty:
        print("[PERF] No trades in log.")
        return
    total = df["pnl"].sum()
    wins = (df["pnl"] > 0).sum()
    losses = (df["pnl"] <= 0).sum()
    winrate = wins / (wins + losses) * 100 if (wins + losses) else 0
    avg_win = df[df["pnl"] > 0]["pnl"].mean() if wins else 0
    avg_loss = df[df["pnl"] <= 0]["pnl"].mean() if losses else 0
    # Calculate equity curve and drawdown
    equity = 0
    equity_curve = []
    for pnl in df["pnl"]:
        equity += pnl
        equity_curve.append(equity)
    peak = 0
    max_dd = 0
    dd_curve = []
    for eq in equity_curve:
        peak = max(peak, eq)
        dd = peak - eq
        dd_curve.append(dd)
        max_dd = max(max_dd, dd)
    profit_factor = abs(df[df["pnl"] > 0]["pnl"].sum()) / abs(df[df["pnl"] <= 0]["pnl"].sum()) if losses else float('inf')
    print(f"[PERF] Trades: {len(df)} | Wins: {wins} | Losses: {losses} | Winrate: {winrate:.2f}% | Net: {total:.2f}")
    print(f"[PERF] Avg Win: {avg_win:.2f} | Avg Loss: {avg_loss:.2f} | Max Drawdown: {max_dd:.2f} | Profit Factor: {profit_factor:.2f}")
    # Per-symbol stats
    for symbol in df["symbol"].unique():
        d = df[df["symbol"] == symbol]
        t = d["pnl"].sum()
        w = (d["pnl"] > 0).sum()
        l = (d["pnl"] <= 0).sum()
        wr = w / (w + l) * 100 if (w + l) else 0
        print(f"    [{symbol}] Trades: {len(d)} | Wins: {w} | Losses: {l} | Winrate: {wr:.2f}% | Net: {t:.2f}")
    print("[PERF] --- End of live performance report ---")
    # Visualization
    if plot:
        plt.figure(figsize=(10,5))
        plt.plot(equity_curve, label="Equity Curve")
        plt.plot(dd_curve, label="Drawdown", color="red", linestyle="--")
        plt.title("Live Equity Curve and Drawdown")
        plt.xlabel("Trade #")
        plt.ylabel("PnL")
        plt.legend()
        plt.grid(True)
        plt.tight_layout()
        plt.show()

def check_for_overfit(model, df, n_train=100, n_test=100):
    """
    Check for overfitting by comparing train and test accuracy.
    """
    if df is None or len(df) < n_train + n_test + 20:
        print("[OVERFIT] Not enough data to check for overfit.")
        return
    # Split data
    train_df = df.iloc[:n_train]
    test_df = df.iloc[-n_test:]
    # Train accuracy
    correct_train = 0
    for i in range(20, len(train_df)):
        feats = get_features_fixed(train_df.iloc[:i])
        pred, _ = model.predict(feats)
        actual = 'buy' if train_df['close'].iloc[i] > train_df['close'].iloc[i-1] else 'sell' if train_df['close'].iloc[i] < train_df['close'].iloc[i-1] else 'hold'
        if pred == actual:
            correct_train += 1
    acc_train = correct_train / (len(train_df) - 20)
    # Test accuracy
    correct_test = 0
    for i in range(20, len(test_df)):
        feats = get_features_fixed(test_df.iloc[:i])
        pred, _ = model.predict(feats)
        actual = 'buy' if test_df['close'].iloc[i] > test_df['close'].iloc[i-1] else 'sell' if test_df['close'].iloc[i] < test_df['close'].iloc[i-1] else 'hold'
        if pred == actual:
            correct_test += 1
    acc_test = correct_test / (len(test_df) - 20)
    print(f"[OVERFIT] Train accuracy: {acc_train:.2%} | Test accuracy: {acc_test:.2%}")
    if acc_train - acc_test > 0.10:
        print("[OVERFIT] Warning: Model may be overfitting (train acc much higher than test acc).")
    else:
        print("[OVERFIT] No significant overfit detected.")

# === ADVANCED ML FILTERING: Example of ultra-high-confidence ensemble ===

def ultra_advanced_ml_filter(signal, confidence, features, model, min_conf=0.85):
    """
    Only allow trades if:
    - ML confidence is very high (default >= 0.85)
    - Trend, volatility, and session are all favorable
    - Multi-timeframe regime agrees
    - Optionally, add more custom logic
    """
    if confidence < min_conf:
        return False, "ML confidence too low"
    if not (features.get("is_london", 0) or features.get("is_ny", 0)):
        return False, "Not in active session"
    if not features.get("is_high_vol", 0):
        return False, "Volatility too low"
    if features.get("regime") != features.get("regime_h1"):
        return False, "No multi-timeframe confluence"
    # Optionally, require ensemble agreement
    if hasattr(model, "models"):
        votes = []
        for m in model.models:
            s, c = m.predict(features)
            votes.append(s)
        if votes.count(signal) < len(model.models):
            return False, "No ensemble agreement"
    return True, ""
