def analyze_strategy_performance(symbols, model):
    """
    Run backtests and print summary for each symbol.
    Look for: Win rate > 50%, Profit factor > 1.3, Drawdown < 15%
    """
    try:
        performance_summary = {
            'total_trades': 0,
            'total_profit': 0,
            'win_rate': 0,
            'avg_win': 0,
            'avg_loss': 0,
            'max_drawdown': 0,
            'profit_factor': 0
        }

        symbol_performances = {}

        # ONLY PROFITABLE SYMBOLS
        if 'config' in globals() and hasattr(config, 'get'):
            BASE_SYMBOLS = config.get('SYMBOLS', config.get('symbols', ["XAUUSD", "EURUSD", "GBPUSD", "NZDUSD", "USDJPY", "BTCUSD"]))
        else:
            BASE_SYMBOLS = ["XAUUSD", "EURUSD", "GBPUSD", "NZDUSD", "USDJPY", "BTCUSD"]
        for symbol in SYMBOLS:
            backtest_symbol(symbol, model)
            if not trades:
                print(f"[BACKTEST] {symbol}: No trades found.")
                continue

            # Calculate metrics
            results = [t['result'] for t in trades]
            wins = [r for r in results if r > 0]
            losses = [r for r in results if r <= 0]
            win_rate = len(wins) / len(results) * 100 if results else 0
            avg_win = np.mean(wins) if wins else 0
            avg_loss = np.mean(losses) if losses else 0
            profit_factor = abs(sum(wins)) / abs(sum(losses)) if losses else float('inf')
            net_profit = sum(results)
            # Drawdown calculation
            equity = 0
            equity_curve = []
            for r in results:
                equity += r
                equity_curve.append(equity)
            peak = 0
            max_dd = 0
            for eq in equity_curve:
                peak = max(peak, eq)
                dd = peak - eq
                max_dd = max(max_dd, dd)
            max_drawdown_pct = (max_dd / peak * 100) if peak > 0 else 0

            symbol_performance = {
                'trades': len(trades),
                'profit': net_profit,
                'win_rate': win_rate,
                'avg_win': avg_win,
                'avg_loss': avg_loss,
                'profit_factor': profit_factor,
                'max_drawdown_pct': max_drawdown_pct
            }
            symbol_performances[symbol] = symbol_performance

            # Print summary for this symbol
            print(f"\n[BACKTEST] {symbol}:")
            print(f"  Trades: {len(trades)}")
            print(f"  Win rate: {win_rate:.2f}% {'✅' if win_rate > 50 else '❌'}")
            print(f"  Profit factor: {profit_factor:.2f} {'✅' if profit_factor > 1.3 else '❌'}")
            print(f"  Max drawdown: {max_drawdown_pct:.2f}% {'✅' if max_drawdown_pct < 15 else '❌'}")
            print(f"  Net profit: {net_profit:.2f}")
            print(f"  Avg win: {avg_win:.2f} | Avg loss: {avg_loss:.2f}")

            # Aggregate total performance
            performance_summary['total_trades'] += symbol_performance['trades']
            performance_summary['total_profit'] += symbol_performance['profit']

        return performance_summary, symbol_performances
    except Exception as e:
        print(f"[ERROR] Strategy performance analysis failed: {e}")
        import traceback
        traceback.print_exc()
        return {}, {}


def optimize_entry_conditions(symbols, model):
    """
    Dynamically optimize entry conditions based on symbol performance.
    """
    # Base conditions to optimize
    condition_ranges = {
        'rsi_buy_threshold': (30, 50),
        'rsi_sell_threshold': (50, 70),
        'trend_strength_threshold': (0.001, 0.005),
        'volatility_threshold': (0.0005, 0.002)
    }

    best_conditions = {}

    for symbol in symbols:
        best_profit = float('-inf')
        best_symbol_conditions = {}

        # Grid search for optimal conditions
        for rsi_buy in np.linspace(*condition_ranges['rsi_buy_threshold'], 10):
            for rsi_sell in np.linspace(*condition_ranges['rsi_sell_threshold'], 10):
                for trend_strength in np.linspace(*condition_ranges['trend_strength_threshold'], 10):
                    for volatility in np.linspace(*condition_ranges['volatility_threshold'], 10):
                        # Modify entry conditions dynamically
                        def custom_should_trade(signal, confidence, features, spread):
                            return (
                                (features.get('rsi', 50) < rsi_buy if signal == 'buy' else features.get('rsi', 50) > rsi_sell if signal == 'sell' else False)
                                and features.get('trend_strength', 0) > trend_strength
                                and features.get('volatility_cluster', 0) > volatility
                            )

                        # Backtest with these conditions
                        trades = backtest_symbol(symbol, model, custom_should_trade)
                        total_profit = sum(trade['result'] for trade in trades)

                        if total_profit > best_profit:
                            best_profit = total_profit
                            best_symbol_conditions = {
                                'rsi_buy': rsi_buy,
                                'rsi_sell': rsi_sell,
                                'trend_strength': trend_strength,
                                'volatility': volatility
                            }

        best_conditions[symbol] = best_symbol_conditions
        print(f"{symbol} Best Conditions: {best_symbol_conditions}")

    return best_conditions

def generate_strategy_dashboard(performance_data, symbol_performances):
    """
    Generate a comprehensive dashboard of strategy performance.
    """
    import matplotlib.pyplot as plt
    import seaborn as sns

    # Visualization setup
    plt.figure(figsize=(15, 10))
    plt.suptitle("Trading Strategy Performance Dashboard", fontsize=16)

    # Subplot 1: Overall Performance
    plt.subplot(2, 2, 1)
    plt.title("Overall Performance Metrics")
    metrics = ['total_trades', 'total_profit', 'win_rate']
    values = [performance_data[metric] for metric in metrics]
    plt.bar(metrics, values)
    plt.xticks(rotation=45)

    # Subplot 2: Symbol Performance Comparison
    plt.subplot(2, 2, 2)
    plt.title("Profit by Symbol")
    symbols = list(symbol_performances.keys())
    profits = [perf['profit'] for perf in symbol_performances.values()]
    plt.bar(symbols, profits)
    plt.xticks(rotation=45)

    # Subplot 3: Win Rates
    plt.subplot(2, 2, 3)
    plt.title("Win Rates by Symbol")
    win_rates = [perf['win_rate'] for perf in symbol_performances.values()]
    plt.bar(symbols, win_rates)
    plt.xticks(rotation=45)
    plt.axhline(y=50, color='r', linestyle='--')  # 50% reference line

    # Subplot 4: Trade Distribution
    plt.subplot(2, 2, 4)
    plt.title("Number of Trades by Symbol")
    trades = [perf['trades'] for perf in symbol_performances.values()]
    plt.bar(symbols, trades)
    plt.xticks(rotation=45)

    plt.tight_layout()
    plt.savefig('strategy_performance_dashboard.png')
    plt.close()

import numpy as np
import pandas as pd
from concurrent.futures import ProcessPoolExecutor, as_completed

def optimized_backtest_symbol(symbol, model, custom_should_trade=None, max_bars=2000, step_size=10):
    """
    Optimized backtest function with reduced computational complexity.
    
    Args:
        symbol (str): Trading symbol
        model: ML model for predictions
        custom_should_trade (callable, optional): Custom trade decision function
        max_bars (int): Maximum number of bars to process
        step_size (int): Number of bars to skip between iterations
    
    Returns:
        list: Trades taken during backtest
    """
    try:
        # Load data
        script_dir = os.path.dirname(os.path.abspath(__file__))
        df = get_backtest_data(symbol, bars=max_bars, data_dir=script_dir)

        if df is None or len(df) < 200:
            return []

        trades = []
        open_trade = None
        
        # Vectorized calculations
        close = df['close'].values
        high = df['high'].values
        low = df['low'].values
        
        # Process only subset of bars to speed up
        for i in range(200, len(df)-1, step_size):
            try:
                # Get window of data
                window = df.iloc[:i+1]
                features = get_features_fixed(window)
                
                # Predict signal
                # Defensive: Ensure features is a flat vector, not a dict of dicts
                if isinstance(features, dict) and any(isinstance(v, dict) for v in features.values()):
                    # Flatten nested dicts if present
                    flat_features = {}
                    for k, v in features.items():
                        if isinstance(v, dict):
                            for subk, subv in v.items():
                                flat_features[f"{k}_{subk}"] = subv
                        else:
                            flat_features[k] = v
                    features = flat_features
                # Defensive: Convert features dict to a 2D array for sklearn
                if hasattr(model, "predict") and callable(model.predict):
                    import numpy as np
                    if hasattr(model, "feature_names_in_"):
                        feature_names = list(model.feature_names_in_)
                    else:
                        feature_names = [
                            "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
                            "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
                            "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength",
                            "distance_from_tp", "minutes_left_session", "atr_squeeze", "atr_burst",
                            "macd", "macd_signal", "macd_hist", "obv", "divergence"
                        ][:model.n_features_in_ if hasattr(model, "n_features_in_") else 20]
                    X = np.array([[features.get(k, 0) for k in feature_names]])
                    # If model is a custom model (like MockMLModel), pass features dict, not X
                    if hasattr(model, "is_custom") and model.is_custom:
                        signal, confidence = model.predict(features)
                    else:
                        pred = model.predict(X)
                        if hasattr(model, "predict_proba"):
                            proba = model.predict_proba(X)[0]
                            pred_idx = pred[0] if hasattr(pred, "__getitem__") else pred
                            if isinstance(pred_idx, str):
                                label_map = getattr(model, "label_map", {"hold": 0, "buy": 1, "sell": 2})
                                pred_idx = label_map.get(pred_idx, 0)
                            confidence = proba[int(pred_idx)] if int(pred_idx) < len(proba) else max(proba)
                            signal = getattr(model, "label_map", {0: "hold", 1: "buy", 2: "sell"}).get(pred[0], pred[0])
                        else:
                            signal, confidence = pred[0], 1.0
                else:
                    signal, confidence = model.predict(features)
                
                # Enforce ML confidence threshold before any trade
                CONFIDENCE_THRESHOLD = 0.60  # Set globally or pass as parameter

                # Trade decision
                if signal not in ("buy", "sell") or confidence < CONFIDENCE_THRESHOLD:
                    continue

                if custom_should_trade:
                    should_enter = custom_should_trade(signal, confidence, features, 0.0001)
                else:
                    should_enter, _ = should_trade_advanced(signal, confidence, features, 0.0001, symbol)

                if not should_enter:
                    continue
                
                # Entry and risk management
                atr = features.get("atr", 1.0)
                entry = close[i]
                min_stop_distance = 50  # You may want to fetch this from broker info for gold

                # Use .upper() and .startswith for .ecn gold symbols
                if symbol.upper().startswith("XAU"):
                    if signal == "buy":
                        sl = entry - max(atr * 1.5, min_stop_distance)
                        tp = entry + max(atr * 3.0, min_stop_distance)
                    else:
                        sl = entry + max(atr * 1.5, min_stop_distance)
                        tp = entry - max(atr * 3.0, min_stop_distance)
                else:
                    sl = entry - SL_ATR_MULTIPLIER * atr if signal == "buy" else entry + SL_ATR_MULTIPLIER * atr
                    tp = entry + TP_ATR_MULTIPLIER * atr if signal == "buy" else entry - TP_ATR_MULTIPLIER * atr


                # --- ENSURE SL IS NOT LARGER THAN TP ---
                if abs(entry - sl) > abs(tp - entry):
                    print(f"[WARNING] SL distance ({abs(entry-sl):.5f}) is greater than TP distance ({abs(tp-entry):.5f}). Adjusting TP to match SL for proper RR.")
                    if signal == "buy":
                        tp = entry + abs(entry - sl)
                    else:
                        tp = entry - abs(entry - sl)

                # --- ENSURE SL IS NOT LARGER THAN TP ---
                if abs(entry - sl) > abs(tp - entry):
                    print(f"[WARNING] SL distance ({abs(entry-sl):.5f}) is greater than TP distance ({abs(tp-entry):.5f}). Adjusting TP to match SL for proper RR.")
                    if signal == "buy":
                        tp = entry + abs(entry - sl)
                    else:
                        tp = entry - abs(entry - sl)

                if not risk_reward_ok(entry, sl, tp):
                    continue
                
                # Trade tracking
                trade = {
                    "entry": entry,
                    "sl": sl,
                    "tp": tp,
                    "direction": signal,
                    "open_time": window['time'].iloc[-1]
                }
                
                # Simulate trade exit
                if signal == "buy":
                    if low[i+1] <= sl:
                        trade['exit'] = sl
                        trade['result'] = sl - entry
                    elif high[i+1] >= tp:
                        trade['exit'] = tp
                        trade['result'] = tp - entry
                    else:
                        continue
                else:
                    if high[i+1] >= sl:
                        trade['exit'] = sl
                        trade['result'] = entry - sl
                    elif low[i+1] <= tp:
                        trade['exit'] = tp
                        trade['result'] = entry - tp
                    else:
                        continue
                
                trades.append(trade)
            
            except Exception as e:
                # Silent error handling to prevent backtest interruption
                continue
        
        return trades
    
    except Exception as e:
        # Minimal error reporting
        print(f"[BACKTEST ERROR] {symbol}: {e}")
        return []

def parallel_backtest(symbols, model, max_workers=None):
    """
    Parallel backtesting across multiple symbols.
    
    Args:
        symbols (list): List of trading symbols
        model: ML model for predictions
        max_workers (int, optional): Number of parallel processes
    
    Returns:
        dict: Performance metrics for each symbol
    """
    symbol_performances = {}
    
    with ProcessPoolExecutor(max_workers=max_workers) as executor:
        # Submit backtest jobs
        future_to_symbol = {
            executor.submit(optimized_backtest_symbol, symbol, model): symbol 
            for symbol in symbols
        }
        
        # Collect results
        for future in as_completed(future_to_symbol):
            symbol = future_to_symbol[future]
            try:
                trades = future.result()
                
                # Performance calculation
                if trades:
                    symbol_performances[symbol] = {
                        'trades': len(trades),
                        'total_profit': sum(trade['result'] for trade in trades),
                        'win_rate': sum(1 for trade in trades if trade['result'] > 0) / len(trades) * 100,
                        'avg_win': np.mean([trade['result'] for trade in trades if trade['result'] > 0]),
                        'avg_loss': np.mean([trade['result'] for trade in trades if trade['result'] <= 0])
                    }
                else:
                    symbol_performances[symbol] = {
                        'trades': 0,
                        'total_profit': 0,
                        'win_rate': 0,
                        'avg_win': 0,
                        'avg_loss': 0
                    }
            
            except Exception as e:
                print(f"[BACKTEST ERROR] Processing {symbol}: {e}")
                symbol_performances[symbol] = {
                    'trades': 0,
                    'total_profit': 0,
                    'win_rate': 0,
                    'avg_win': 0,
                    'avg_loss': 0
                }
    
    return symbol_performances

def analyze_strategy_performance(symbols, model):
    """
    Analyze strategy performance using parallel backtesting.
    
    Args:
        symbols (list): Trading symbols
        model: ML model for predictions
    
    Returns:
        tuple: Overall performance summary and symbol-specific performances
    """
    # Parallel backtest
    symbol_performances = parallel_backtest(symbols, model)
    
    # Aggregate performance
    performance_summary = {
        'total_trades': sum(perf['trades'] for perf in symbol_performances.values()),
        'total_profit': sum(perf['total_profit'] for perf in symbol_performances.values()),
        'avg_win_rate': np.mean([perf['win_rate'] for perf in symbol_performances.values()]),
        'avg_trade_profit': np.mean([perf['total_profit'] / max(perf['trades'], 1) for perf in symbol_performances.values()])
    }
    
    return performance_summary, symbol_performances

def optimize_parameters_for_each_symbol(backtest_func, param_grid, symbols):
    """
    Grid search parameter optimization for each symbol using backtest analytics.
    param_grid: dict of param_name -> list of values
    """
    import itertools
    best_params_per_symbol = {}
    for symbol in symbols:
        best_score = -float("inf")
        best_params = None
        print(f"\n[OPTIMIZE] Optimizing for {symbol} ...")
        for values in itertools.product(*param_grid.values()):
            params = dict(zip(param_grid.keys(), values))
            score = backtest_func(symbol, **params)
            print(f"[OPTIMIZE] {symbol} Params: {params} | Score: {score}")
            if score > best_score:
                best_score = score
                best_params = params
        best_params_per_symbol[symbol] = (best_params, best_score)
        print(f"[OPTIMIZE] {symbol} Best Params: {best_params} | Best Score: {best_score}")
    return best_params_per_symbol

class ScalpingOrderFlowLiquidityStrategy(StrategyBase):
    def __init__(self):
        super().__init__("ScalpingOrderFlowLiquidity")

    def check(self, df, features):
        if len(df) < 52:
            return None
        close = df['close'].iloc[-1]
        ema20 = features['ema20']
        ema50 = features['ema50']
        ema200 = features['ema200']
        rsi = features['rsi']
        atr = features['atr']

        if close > ema20 > ema50 > ema200 and rsi > 60:
            return 'buy'
        if close < ema20 < ema50 < ema200 and rsi < 40:
            return 'sell'
        return None
# === 5. Log ML Model Accuracy on Recent Bars ===
def log_model_accuracy(models, df, profit_pips=10, lookahead=5):
    """
    Logs ML accuracy using profit-based labeling:
    - "buy" if next N bars move up by at least X pips
    - "sell" if next N bars move down by at least X pips
    - "hold" otherwise
    """
    if df is None or len(df) < 21 + lookahead:
        print(f"[ML ACCURACY] Not enough data to calculate accuracy. Data rows: {0 if df is None else len(df)} (need at least {21 + lookahead})")
        print("[ML ACCURACY] HINT: If you see this with 250+ rows, check that your DataFrame is not missing required columns (like 'close'), and that your get_features and labeling logic are correct.")
        return
    correct = 0
    total = 0
    # Robustly get the symbol name for pip size calculation
    symbol_name = None
    if isinstance(df, pd.DataFrame):
        if "symbol" in df.columns and not df["symbol"].empty:
            symbol_name = str(df["symbol"].iloc[-1])
        else:
            # fallback: try to use the first symbol in the DataFrame if present
            symbol_name = str(df.get("symbol", [""])[0]) if "symbol" in df else ""
    else:
        symbol_name = ""
    pip_size = 0.0001 if "JPY" not in symbol_name else 0.01

    # --- BUILD X, y for accuracy evaluation ---
    X = []
    y = []
    for i in range(20, len(df) - lookahead):
        window = df.iloc[:i+1]
        features = get_features_fixed(window)
        # Labeling logic: profit-based
        close_now = df['close'].iloc[i]
        close_future = df['close'].iloc[i + lookahead]
        if close_future - close_now >= profit_pips * pip_size:
            label = "buy"
        elif close_now - close_future >= profit_pips * pip_size:
            label = "sell"
        else:
            label = "hold"
        X.append(features)
        y.append(label)

    # Evaluate accuracy for each symbol
    for symbol in SYMBOLS:
        df = get_data_for_accuracy(symbol, bars=250)
        if df is None or len(df) < 21 + lookahead:
            print(f"[ML ACCURACY] Not enough data to calculate accuracy for {symbol}. Data rows: {0 if df is None else len(df)} (need at least {21 + lookahead})")
            continue
        pip_size = 0.0001 if "JPY" not in symbol else 0.01
        X = []
        y = []
        for i in range(20, len(df) - lookahead):
            window = df.iloc[:i+1]
            features = get_features_fixed(window)
            close_now = df['close'].iloc[i]
            close_future = df['close'].iloc[i + lookahead]
            if close_future - close_now >= profit_pips * pip_size:
                label = "buy"
            elif close_now - close_future >= profit_pips * pip_size:
                label = "sell"
            else:
                label = "hold"
            X.append(features)
            y.append(label)
        correct = 0
        total = 0
        for i, (features, true_label) in enumerate(zip(X, y)):
            try:
                pred = models[symbol].predict(features)
                # FIX: robust prediction format handling
                if isinstance(pred, dict):
                    pred_label = pred.get("label", "hold")
                    pred_conf = pred.get("confidence", 0.0)
                elif isinstance(pred, tuple):
                    pred_label, pred_conf = pred
                elif isinstance(pred, str):
                    pred_label = pred
                    pred_conf = 1.0
                else:
                    print(f"[ERROR] Unexpected prediction format at i={i}: {type(pred)} → {pred}")
                    pred_label = "hold"
                    pred_conf = 0.0

                # --- FIX: If pred_conf is a dict, extract the float value ---
                if isinstance(pred_conf, dict):
                    if "confidence" in pred_conf:
                        pred_conf = float(pred_conf["confidence"])
                    else:
                        pred_conf = float(list(pred_conf.values())[0])
                else:
                    pred_conf = float(pred_conf)

                # Now use pred_label and pred_conf for your accuracy logic
                if pred_label == true_label:
                    correct += 1
                total += 1

            except Exception as e:
                print(f"[ERROR] Accuracy eval error at i={i}: {e}")
                continue
        if total == 0:
            print(f"[ML ACCURACY] Accuracy loop ran but produced no results for {symbol}. Check for exceptions above.")
        else:
            acc = correct / total
            print(f"[ML ACCURACY] {symbol} recent profit-based prediction accuracy: {acc:.2%} (profit_pips={profit_pips}, lookahead={lookahead})")


# --- ADD THIS FUNCTION DEFINITION ---
def get_daily_pnl():
    """Return today's realized PnL from closed trades (in account currency)."""
    today = datetime.now(timezone.utc).date()
    deals = mt5.history_deals_get(
        datetime(today.year, today.month, today.day, 0, 0, 0, tzinfo=timezone.utc),
        datetime(today.year, today.month, today.day, 23, 59, 59, tzinfo=timezone.utc)
    )
    if deals is None:
        return 0
    df = pd.DataFrame(list(deals))
    if df.empty or "profit" not in df:
        return 0

    # Keep last 6 months for training relevance
    if len(df) > (24*4*30*6):  # M15 candles in ~6 months
        df = df.tail(24*4*30*6)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
    return df["profit"].sum()

def get_daily_trade_count():
    """Return today's number of executed trades (buy/sell deals)."""
    today = datetime.now(timezone.utc).date()
    deals = mt5.history_deals_get(
        datetime(today.year, today.month, today.day, 0, 0, 0, tzinfo=timezone.utc),
        datetime(today.year, today.month, today.day, 23, 59, 59, tzinfo=timezone.utc)
    )
    if deals is None:
        return 0
    df = pd.DataFrame(list(deals))
    if df.empty or "type" not in df:
        return 0
    # Count only buy (0) and sell (1) deals
    return len(df[df['type'].isin([0, 1])])

def get_data_for_accuracy(symbol, bars=250):
    """
    Try to get enough data for ML accuracy check, with robust fallback.
    """
    max_bars_6m = 24 * 4 * 30 * 6  # M15 candles in ~6 months

    # --- Try live price data first ---
    df = get_price_data(symbol, bars=bars)
    if df is not None and len(df) >= 21:
        if len(df) > max_bars_6m:
            df = df.tail(max_bars_6m)
            print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
        return df

    # --- Fallback: try backtest data ---
    df = get_backtest_data(symbol, bars=bars)
    if df is not None and len(df) >= 21:
        if len(df) > max_bars_6m:
            df = df.tail(max_bars_6m)
            print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")
        return df

    # --- No data found ---
    print(f"[WARNING] Not enough data for ML accuracy check on {symbol}.")
    return None

