import numpy as np
from collections import Counter
from sklearn.ensemble import RandomForestClassifier
from sklearn.utils import shuffle
import joblib

import os
import time

# --- VotingMLModel Implementation ---
class VotingMLModel:
    """
    Ensemble model: RandomForest + LSTM + CNN majority vote.
    Usage:
        model = VotingMLModel.train(X, y)
        label, confidence = model.predict_vote(X_test)
    """
    def __init__(self, rf_model, lstm_model, cnn_model, label_map=None, feature_names=None):
        self.rf_model = rf_model
        self.lstm_model = lstm_model
        self.cnn_model = cnn_model
        self.label_map = label_map or {0: "hold", 1: "buy", 2: "sell"}
        self.feature_names_in_ = feature_names

    @staticmethod
    def train(X, y, feature_names=None):
        # Train RandomForest
        rf = RandomForestClassifier(
            n_estimators=100,
            max_depth=8,
            min_samples_leaf=3,
            class_weight="balanced_subsample",
            random_state=42,
            n_jobs=-1
        )
        rf.fit(X, y)

        # Train LSTM (simple wrapper, use sklearn for demo)
        from sklearn.neural_network import MLPClassifier
        lstm = MLPClassifier(hidden_layer_sizes=(32,), max_iter=200, random_state=42)
        lstm.fit(X, y)

        # Train CNN (simple wrapper, use sklearn for demo)
        cnn = MLPClassifier(hidden_layer_sizes=(64, 32), max_iter=200, random_state=42)
        cnn.fit(X, y)

        return VotingMLModel(rf, lstm, cnn, feature_names=feature_names)

    def predict_vote(self, X):
        """
        Predict with all models, return majority vote and confidence.
        X: np.array or pd.DataFrame, shape (n_samples, n_features)
        Returns: (label, confidence)
        """
        if hasattr(X, "values"):
            X = X.values
        rf_pred = self.rf_model.predict(X)
        lstm_pred = self.lstm_model.predict(X)
        cnn_pred = self.cnn_model.predict(X)
        preds = [rf_pred[0], lstm_pred[0], cnn_pred[0]]
        # Majority vote
        vote = Counter(preds).most_common(1)[0][0]
        # Confidence: fraction of models that agree
        confidence = preds.count(vote) / 3.0
        label = self.label_map.get(vote, vote)
        return label, confidence

    @classmethod
    def get(cls, regime):
        """
        Load pre-trained ensemble model for a regime.
        For demo, just load from disk or retrain.
        """
        model_path = f"models/voting_model_{regime}.pkl"
        if os.path.exists(model_path):
            return joblib.load(model_path)
        else:
            # Fallback: train a dummy model
            # ONLY PROFITABLE SYMBOLS
            X, y = get_training_data_for_walkforward(symbols=["XAUUSD.m", "AUDUSD.m", "NZDUSD.m"])
            if len(X) == 0:
                raise RuntimeError(f"No training data for regime {regime}")
            model = cls.train(X, y)
            joblib.dump(model, model_path)
            return model

# --- Live Model Retraining & Rollback ---
def live_model_retrain_and_rollback(
    symbols=None,
    min_samples_per_symbol=200,
    min_total_samples=1000,
    model_dir="models/",
    feature_order=None,
    lookahead=5,
    price_col="close",
    verbose=True,
    keep_last_n=7
):
    """
    Retrain ensemble model daily, keep last N models for rollback.
    If new model performs worse than previous, rollback.
    """
    import os
    import joblib
    from datetime import datetime

    os.makedirs(model_dir, exist_ok=True)
    today = datetime.now(timezone.utc).strftime("%Y%m%d")
    model_path = os.path.join(model_dir, f"voting_model_trend_{today}.pkl")

    # Get training data
    X, y = get_training_data_for_walkforward(symbols=symbols)
    if len(X) == 0:
        print("[MODEL] No training data found, aborting retrain.")
        return None

    # Train new ensemble model
    new_model = VotingMLModel.train(X, y)
    joblib.dump(new_model, model_path)
    print(f"[MODEL] Ensemble model retrained and saved to {model_path}")

    # Keep only last N models
    models = sorted([f for f in os.listdir(model_dir) if f.startswith("voting_model_trend_") and f.endswith(".pkl")])
    if len(models) > keep_last_n:
        for old_model in models[:-keep_last_n]:
            os.remove(os.path.join(model_dir, old_model))
            print(f"[MODEL] Removed old model: {old_model}")

    # Rollback logic: compare new model accuracy to previous
    prev_model_path = os.path.join(model_dir, models[-2]) if len(models) > 1 else None
    if prev_model_path:
        prev_model = joblib.load(prev_model_path)
        # Evaluate both models on recent validation data
        X_val, y_val = get_training_data_for_walkforward(symbols=symbols)
        new_acc = np.mean([VotingMLModel.train(X_val, y_val).rf_model.score(X_val, y_val)])
        prev_acc = np.mean([prev_model.rf_model.score(X_val, y_val)])
        print(f"[MODEL] New model accuracy: {new_acc:.3f}, Previous: {prev_acc:.3f}")
        if new_acc < prev_acc - 0.01:  # If new model is worse by >1%
            print("[MODEL] New model underperforms, rolling back to previous model.")
            joblib.dump(prev_model, os.path.join(model_dir, f"voting_model_trend_{today}_rollback.pkl"))
            return prev_model
    return new_model

