def retrain_and_save_model_on_start(
    symbols=None,
    min_samples_per_symbol=200,
    min_total_samples=1000,
    model_path="model_ecn.pkl",
    feature_order=None,
    lookahead=5,
    price_col="close",
    verbose=True
):
    """
    Loads model if <24h old, else retrains and saves a new one.
    Fixes: 
    - If no data is found for any symbol, aborts and prints a clear error.
    - If no features are generated for any symbol, aborts and prints a clear error.
    - If all features are zero or NaN, aborts and prints a clear error.
    """
    import joblib
    from datetime import datetime

    # Always retrain a new model (ignore any previous model)
    # Only EURUSD.ecn is allowed for training
    if symbols is None:
        symbols = ["XAUUSD.m",  "EURUSD.m"]

    if feature_order is None:
        feature_order = [
            "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
            "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
            "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength",
            "distance_from_tp", "minutes_left_session", "atr_squeeze", "atr_burst",
            "macd", "macd_signal", "macd_hist", "obv", "divergence"
        ][:20]

    X_all, y_all = [], []
    symbol_counts = {}

    any_data_found = False

    # --- SPEEDUP: Limit the number of bars processed per symbol for faster training ---
    MAX_BARS_PER_SYMBOL = 10000  # <-- You can tune this value (e.g., 2000, 5000, 10000)
    for symbol in symbols:
        if symbol != "XAUUSD.ecn":
            continue  # Only process XAUUSD.ecn
        df = get_backtest_data(symbol, timeframe="M15", from_year=2023)
        print(f"[DEBUG] {symbol}: loaded {0 if df is None else len(df)} rows")

        if df is None or len(df) < min_samples_per_symbol:
            if verbose:
                print(f"[MODEL] Not enough data for {symbol}, skipping.")
            continue

        any_data_found = True
        count = 0
        # Only use the last MAX_BARS_PER_SYMBOL bars for training
        if len(df) > MAX_BARS_PER_SYMBOL:
            df = df.iloc[-MAX_BARS_PER_SYMBOL:].reset_index(drop=True)
        for i in range(50, len(df) - lookahead):
            if i % 1000 == 0:
                print(f"[MODEL] {symbol}: Processing bar {i}/{len(df)}")
            window = df.iloc[:i+1]
            try:
                features = get_features_fixed(window)
                if i < 55:  # Print first few feature vectors for debugging
                    print(f"[DEBUG] {symbol} i={i} features: {features}")
            except Exception as e:
                if verbose:
                    print(f"[MODEL] Feature error at {symbol} i={i}: {e}")
                continue
            if features.get("is_no_trade_zone"):
                continue
            label = 0
            close_now = df[price_col].iloc[i]
            future = df[price_col].iloc[i+1:i+1+lookahead]
            if len(future) < lookahead:
                continue
            try:
                max_up = max(future - close_now)
                max_down = min(future - close_now)
            except Exception as e:
                if verbose:
                    print(f"[MODEL] Future price error at {symbol} i={i}: {e}")
                continue
            if max_up > 0.001:
                label = 1
            elif max_down < -0.001:
                label = 2
            feature_vec = [features.get(k, 0) for k in feature_order]
            if count < 5:  # Only print first 5 for brevity
                print(f"[DEBUG] {symbol} i={i} features: {feature_vec}")
            X_all.append(feature_vec)
            y_all.append(label)
            count += 1
        symbol_counts[symbol] = count
        if verbose:
            print(f"[MODEL] {symbol}: {count} samples added.")

    if not any_data_found:
        print(f"[MODEL ERROR] No data found for XAUUSD.ecn. Please check your data files and paths.")
        return None

    if len(X_all) < min_total_samples:
        print(f"[MODEL ERROR] Not enough total samples to train ({len(X_all)}).")
        print(f"[MODEL ERROR] Please check your data files and ensure you have enough historical data for EURUSD.ecn.")
        return None

    import numpy as np
    from collections import Counter
    from sklearn.ensemble import RandomForestClassifier 
    from sklearn.utils import shuffle

    X_all = np.array(X_all)
    y_all = np.array(y_all)
    # Remove samples where all features are zero or NaN
    mask = ~np.all((X_all == 0) | np.isnan(X_all), axis=1)
    X_all = X_all[mask]
    y_all = y_all[mask]

    if len(X_all) == 0:
        print(f"[MODEL ERROR] All features are zero or NaN after filtering. Please check your get_features() logic and data quality.")
        return None

    # if len(X_all) > 1000:
    #     from scipy.stats import zscore
    #     z = np.abs(zscore(X_all, nan_policy='omit'))
    #     mask = (z < 5).all(axis=1)
    #     X_all, y_all = X_all[mask], y_all[mask]
    #     if verbose:
    #         print(f"[MODEL] Removed outliers, {len(X_all)} samples remain.")

    X_all, y_all = shuffle(X_all, y_all, random_state=42)

    class_counts = Counter(y_all)
    print(f"[MODEL] Class distribution: {class_counts}")

    if verbose:
        print(f"[MODEL] Feature means: {np.mean(X_all, axis=0)}")
        print(f"[MODEL] Feature stds: {np.std(X_all, axis=0)}")

    if X_all.shape[0] == 0:
        raise RuntimeError("[TRAINING ERROR] Model training failed due to empty dataset.")

    model = RandomForestClassifier(
        n_estimators=200,
        max_depth=10,
        min_samples_leaf=3,
        max_features="sqrt",
        class_weight="balanced_subsample",
        random_state=42,
        n_jobs=-1
    )
    model.fit(X_all, y_all)
    joblib.dump(model, model_path)
    print(f"[MODEL] Model retrained on EURUSD.ecn and saved to {model_path}")

    model.label_map = {0: "hold", 1: "buy", 2: "sell"}
    model.feature_names_in_ = np.array(feature_order)

    if verbose:
        print(f"[MODEL] Per-symbol sample counts: {symbol_counts}")

    return model

# --- Live Model Retraining & Rollback ---
def live_model_retrain_and_rollback(
    symbols=None,
    min_samples_per_symbol=200,
    min_total_samples=1000,
    model_dir="models/",
    feature_order=None,
    lookahead=5,
    price_col="close",
    verbose=True,
    keep_last_n=7
):
    """
    Retrain ensemble model daily, keep last N models for rollback.
    If new model performs worse than previous, rollback.
    """
    import os
    import joblib
    from datetime import datetime

    os.makedirs(model_dir, exist_ok=True)
    today = datetime.now(timezone.utc).strftime("%Y%m%d")
    model_path = os.path.join(model_dir, f"model_{today}.pkl")

    # Train new ensemble model (VotingMLModel/StackingMLModel)
    new_model = VotingMLModel.train(
        symbols=symbols,
        min_samples_per_symbol=min_samples_per_symbol,
        min_total_samples=min_total_samples,
        feature_order=feature_order,
        lookahead=lookahead,
        price_col=price_col,
        verbose=verbose
    )
    joblib.dump(new_model, model_path)
    print(f"[MODEL] Ensemble model retrained and saved to {model_path}")

    # Keep only last N models
    models = sorted([f for f in os.listdir(model_dir) if f.startswith("model_") and f.endswith(".pkl")])
    if len(models) > keep_last_n:
        for old_model in models[:-keep_last_n]:
            os.remove(os.path.join(model_dir, old_model))
            print(f"[MODEL] Removed old model: {old_model}")

    # Rollback logic: compare new model accuracy to previous
    prev_model_path = os.path.join(model_dir, models[-2]) if len(models) > 1 else None
    if prev_model_path:
        prev_model = joblib.load(prev_model_path)
        # Evaluate both models on recent validation data
        X_val, y_val = get_training_data_for_walkforward(symbols=symbols)
        # Fix: If your model's .score expects (X, y), but your y is a tuple/list of tuples, unpack correctly
        try:
            if len(y_val) > 0 and hasattr(y_val[0], "__iter__") and not isinstance(y_val[0], (str, bytes, int, float)):
                # If y_val is a list of tuples, unpack to get the first value
                y_val = [y[0] for y in y_val]
        except Exception as e:
            print(f"[ERROR] Accuracy eval error during y_val unpack: {e}")

        try:
            new_acc = new_model.score(X_val, y_val)
        except Exception as e:
            print(f"[ERROR] Accuracy eval error for new_model: {e}")
            new_acc = 0.0
        try:
            prev_acc = prev_model.score(X_val, y_val)
        except Exception as e:
            print(f"[ERROR] Accuracy eval error for prev_model: {e}")
            prev_acc = 0.0

        print(f"[MODEL] New model accuracy: {new_acc:.3f}, Previous: {prev_acc:.3f}")
        if new_acc < prev_acc - 0.01:  # If new model is worse by >1%
            print("[MODEL] New model underperforms, rolling back to previous model.")
            joblib.dump(prev_model, os.path.join(model_dir, f"model_{today}_rollback.pkl"))
            return prev_model
    return new_model

