# === HISTORY DOWNLOADER AND TRAINING DATA PIPELINE ===
def get_history_data(symbol, timeframe=mt5.TIMEFRAME_M15, from_year=2023, to_year=2025,
                     save_dir="history_data", max_retries=3):
    """
    Downloads historical data for a symbol from MT5 and saves it to CSV.
    Tries multiple suffixes, retries if no data, and trims to last 6 months.
    """
    import os
    import time
    import pandas as pd
    from datetime import datetime, timezone

    os.makedirs(save_dir, exist_ok=True)
    from_date = datetime(from_year, 1, 1, tzinfo=timezone.utc)
    to_date = datetime(to_year, 12, 31, 23, 59, tzinfo=timezone.utc)
    max_bars_6m = 24 * 4 * 30 * 6  # M15 candles in ~6 months

    # --- Try to select symbol ---
    tried = []
    if not mt5.symbol_select(symbol, True):
        tried.append(symbol)
        for suf in [".ecn", ".m", ".pro", ".mini", ".std", ".fx", ".i", ".r", ".s", ""]:
            candidate = symbol + suf
            if candidate != symbol and mt5.symbol_select(candidate, True):
                print(f"[{symbol}] Resolved to {candidate} in Market Watch.")
                symbol = candidate
                break
            tried.append(candidate)
        else:
            print(f"[{symbol}] Could not select symbol in Market Watch. Tried: {tried}")
            return None

    # --- Retry loop for history download ---
    df = None
    for attempt in range(1, max_retries + 1):
        rates = mt5.copy_rates_range(symbol, timeframe, from_date, to_date)
        if rates is not None and len(rates) > 0:
            df = pd.DataFrame(rates)
            df['time'] = pd.to_datetime(df['time'], unit='s')
            csv_path = os.path.join(save_dir, f"{symbol}_history.csv")
            df.to_csv(csv_path, index=False)
            print(f"[{symbol}] Downloaded and saved {len(df)} bars to {csv_path}")
            break  # Exit loop if successful
        else:
            print(f"[{symbol}] Attempt {attempt}/{max_retries}: No data returned for date range {from_date.date()} to {to_date.date()}.")
            print(f"[{symbol}] USER ACTION REQUIRED: Open a chart for {symbol} in MT5 terminal, set to M15, and scroll back as far as possible to download history.")
            if attempt < max_retries:
                print(f"[{symbol}] Waiting 10 seconds before retrying...")
                time.sleep(10)

    # --- Fallback: Try smaller date range if no data ---
    if df is None:
        from_date_recent = datetime(to_year, 1, 1, tzinfo=timezone.utc)
        rates_recent = mt5.copy_rates_range(symbol, timeframe, from_date_recent, to_date)
        if rates_recent is not None and len(rates_recent) > 0:
            df = pd.DataFrame(rates_recent)
            df['time'] = pd.to_datetime(df['time'], unit='s')
            csv_path = os.path.join(save_dir, f"{symbol}_history.csv")
            df.to_csv(csv_path, index=False)
            print(f"[{symbol}] Partial history downloaded ({len(df)} bars). Please scroll back further in MT5 for more.")
        else:
            print(f"[{symbol}] ERROR: No data could be downloaded after {max_retries} attempts.")
            return None

    # --- Trim to last 6 months ---
    if len(df) > max_bars_6m:
        df = df.tail(max_bars_6m)
        print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")

    return df



def get_training_data_for_walkforward(symbols=None, data_dir=None):
    import os
    import pandas as pd
    import numpy as np

    if data_dir is None:
        data_dir = os.path.dirname(os.path.abspath(__file__))
    
    if symbols is None:
        symbols = [ "XAUUSD.m",  "EURUSD.m"]

    all_features = []
    all_labels = []

    for symbol in symbols:
        # Allow processing of all provided symbols. CSV files are expected
        # to follow the `<symbol-with-.ecn>_M15.csv` naming convention.
        csv_path = os.path.join(data_dir, f"{symbol.replace('.m', '.ecn')}_M15.csv")
        if not os.path.exists(csv_path):
            print(f"[TRAIN] Training CSV not found for {symbol}: {csv_path}")
            continue
        # Read with tab or whitespace separator and rename columns
        df = pd.read_csv(csv_path, sep=None, engine='python')
        # Rename columns to standard names
        df.rename(columns={
            '<DATE>': 'date',
            '<TIME>': 'time',
            '<OPEN>': 'open',
            '<HIGH>': 'high',
            '<LOW>': 'low',
            '<CLOSE>': 'close',
            '<TICKVOL>': 'tick_volume',
            '<VOL>': 'real_volume',
            '<SPREAD>': 'spread'
        }, inplace=True)
        # Combine date and time into a single datetime column
        if 'date' in df.columns and 'time' in df.columns:
            df['time'] = pd.to_datetime(df['date'] + ' ' + df['time'], format='%Y.%m.%d %H:%M:%S')
            df.drop(columns=['date'], inplace=True)
        if 'time' not in df.columns:
            print(f"[ERROR] 'time' column missing in {csv_path}. Columns found: {df.columns.tolist()}")
            return None
        df = df[df['time'] >= pd.Timestamp('2023-01-01')]

        if len(df) < 200:
            continue
        df = df.iloc[-2000:]  # Use last 2000 bars (increase as needed)

        for i in range(50, len(df)):
            window = df.iloc[:i+1]
            try:
                features = get_features_fixed(window)
                if df['close'].iloc[i] > df['close'].iloc[i-1]:
                    label = 1  # buy
                elif df['close'].iloc[i] < df['close'].iloc[i-1]:
                    label = 2  # sell
                else:
                    label = 0  # hold
                all_features.append([features.get(k, 0) for k in [
                    "atr", "rsi", "ema200", "ema50", "ema20", "ema200_dist",
                    "prev_body", "prev_wick", "prev_bull", "std20", "hour", "volume",
                    "pattern_score", "bullish_pattern_strength", "bearish_pattern_strength",
                    "distance_from_tp", "minutes_left_session", "atr_squeeze", "atr_burst",
                    "macd", "macd_signal", "macd_hist", "obv", "divergence"
                ][:20]])
                all_labels.append(label)
            except Exception:
                pass

    if not all_features or not all_labels:
        print("[TRAIN] No features or labels generated for any symbol.")
        return np.array([]), np.array([])

    X = np.array(all_features)
    y = np.array(all_labels)
    print(f"[TRAIN] Total samples: {len(X)}, Features: {X.shape[1]}")
    return X, y
