# === Auto-Backtesting and Strategy Comparison ===
import pandas as pd
import time
from datetime import datetime, timedelta

def auto_backtest_and_report():
    # ONLY PROFITABLE SYMBOLS
    SYMBOLS = ["XAUUSD.m", "AUDUSD.m", "NZDUSD.m"]
    bars = 1000  # Number of bars for backtest
    report = []
    now = datetime.utcnow()
    today_str = now.strftime("%Y-%m-%d")
    results = {}

    for strategy in ALL_STRATEGIES:
        strat_name = getattr(strategy, "name", strategy.__class__.__name__)
        strat_results = []
        for symbol in SYMBOLS:
            df = get_price_data(symbol, bars=bars)
            if df is None or len(df) < 100:
                continue
            features = get_features_fixed(df)
            wins, losses, pnl = 0, 0, 0
            for i in range(50, len(df)-10):
                price = df['close'].iloc[i]
                # Only call check if it's implemented
                if type(strategy).check is StrategyBase.check:
                    continue  # Skip base class or unimplemented strategies
                strat_signal = strategy.check(df.iloc[:i+1], features)
                if strat_signal not in ("buy", "sell"):
                    continue
                atr = features.get("atr", 0.001)
                sl = price - atr if strat_signal == "buy" else price + atr
                tp = price + atr * 2 if strat_signal == "buy" else price - atr * 2
                future = df['close'].iloc[i+1:i+10]
                if len(future) < 1:
                    continue
                if strat_signal == "buy":
                    if future.max() >= tp:
                        wins += 1
                        pnl += (tp - price)
                    elif future.min() <= sl:
                        losses += 1
                        pnl += (sl - price)
                elif strat_signal == "sell":
                    if future.min() <= tp:
                        wins += 1
                        pnl += (price - tp)
                    elif future.max() >= sl:
                        losses += 1
                        pnl += (price - sl)
            total_trades = wins + losses
            winrate = wins / total_trades if total_trades > 0 else 0
            profit_factor = (pnl / abs(pnl - losses)) if losses != 0 else pnl
            strat_results.append({
                "symbol": symbol,
                "trades": total_trades,
                "winrate": winrate,
                "profit_factor": profit_factor,
                "net_pnl": pnl
            })
        results[strat_name] = strat_results

    # Generate report
    report_lines = [f"=== Strategy Backtest Report ({today_str}) ==="]
    for strat_name, strat_results in results.items():
        report_lines.append(f"\nStrategy: {strat_name}")
        for res in strat_results:
            report_lines.append(
                f"  {res['symbol']}: Trades={res['trades']}, Winrate={res['winrate']:.2f}, PF={res['profit_factor']:.2f}, NetPnL={res['net_pnl']:.2f}"
            )
    report_text = "\n".join(report_lines)

    # Save to file
    with open(f"strategy_backtest_report_{today_str}.txt", "w") as f:
        f.write(report_text)

    # --- Email + Telegram sending function ---
    # Send report via email and Telegram using unified signal function
    send_signal_to_all_channels("Daily Strategy Backtest Report", report_text)

    print(report_text)

# --- Schedule auto-backtest once per day ---
def schedule_auto_backtest():
    last_run = None
    while True:
        now = datetime.utcnow()
        if last_run is None or (now - last_run) > timedelta(hours=23):
            auto_backtest_and_report()
            last_run = now
        time.sleep(60 * 30)  # Check every 30 minutes

# --- Start auto-backtesting in a background thread ---
import threading
threading.Thread(target=schedule_auto_backtest, daemon=True).start()
# === ML Model Tuning Utility ===


def execute_eurusd_trade(symbol, model, df, features):
    if symbol != "EURUSD":
        return

    ml_signal, ml_confidence = model.predict(features)
    gps_trend_strength = features.get("trend_strength", 0.0)
    volatility_score = features.get("volatility_cluster", 0.0)

    take_trade, reason = relaxed_eurusd_decision_logic(
        ml_signal.upper(), ml_confidence, gps_trend_strength, volatility_score
    )

    print(f"\n=== {symbol} (EURUSD Decision) ===")
    print(f"    ML Signal: {ml_signal.upper()} | Confidence: {ml_confidence:.2f}")
    print(f"    GPS Trend Strength: {gps_trend_strength:.2f}")
    print(f"    Volatility Score: {volatility_score:.2f}")
    print(f"    Trade Decision: {take_trade} ({reason})")

    if not take_trade:
        return

    # Get price and set basic SL/TP using ATR and symbol-specific logic
    atr = features["atr"]
    entry_price = get_current_price(symbol)[0] if ml_signal.lower() == "buy" else get_current_price(symbol)[1]

    # Symbol-specific multipliers and point value
    if "XAUUSD" in symbol:
        SL_ATR_MULTIPLIER = 2.5
        TP_ATR_MULTIPLIER = 4.0
        MIN_SL = 2.0  # $2 minimum stop
        point_value = 0.1
    else:
        SL_ATR_MULTIPLIER = 1.0
        TP_ATR_MULTIPLIER = 3.0
        MIN_SL = 0.002  # 20 pips for forex
        point_value = 0.0001

    sl_dist = max(abs(atr * SL_ATR_MULTIPLIER), MIN_SL)
    tp_dist = abs(atr * TP_ATR_MULTIPLIER)

    if ml_signal.lower() == "buy":
        sl = entry_price - sl_dist
        tp = entry_price + tp_dist
    else:
        sl = entry_price + sl_dist
        tp = entry_price - tp_dist
    # Risk check
    if not risk_reward_ok(entry_price, sl, tp, symbol, features):
        print(f"    [{symbol}] RR check failed. Skipping trade.")
        return

    # --- Lower lot size until it fits free margin ---
    symbol_info = mt5.symbol_info(symbol)
    if symbol_info is not None:
        min_lot = symbol_info.volume_min
        lot_step = symbol_info.volume_step
        # Defensive: round to 2 decimals for most brokers
        while not has_sufficient_balance(LOT_SIZE, symbol) and LOT_SIZE > min_lot:
            LOT_SIZE -= lot_step
            LOT_SIZE = round(LOT_SIZE, 2)
        if LOT_SIZE < min_lot or not has_sufficient_balance(LOT_SIZE, symbol):
            print(f"[{symbol}] Trade not placed: Not enough free margin even at minimum lot size.")
            return
    else:
        print(f"[{symbol}] Trade not placed: Could not get symbol info for lot size validation.")
        return

    # Place the trade WITH MODEL SELECTION
    result = place_trade_with_model_selection(
        symbol,
        ml_signal.lower(),
        LOT_SIZE,
        sl,
        tp,
        strategy_votes={"EURUSD_ML": ml_signal},
        context={'symbol': symbol, 'signal': ml_signal.lower(), 'price': (sl+tp)/2}
    )
    if hasattr(result, "retcode") and result.retcode == mt5.TRADE_RETCODE_DONE:
        print(f"    [{symbol}] EURUSD trade placed successfully")
    else:
        print(f"    [{symbol}] Failed to place EURUSD trade")


