class BreakoutStrategy(StrategyBase):
    def __init__(self):
        super().__init__("Breakout")

    def check(self, df, features):
        # Existing advanced breakout logic
        breakout = breakout_logic(df)
        if breakout is not None:
            return breakout
        # --- ADDITIONAL ENTRY PATTERNS FOR BREAKOUT ---
        # Inside bar breakout (last 2 bars)
        if len(df) >= 3:
            prev_high = df['high'].iloc[-3]
            prev_low = df['low'].iloc[-3]
            last_high = df['high'].iloc[-2]
            last_low = df['low'].iloc[-2]
            if last_high < prev_high and last_low > prev_low:
                if df['close'].iloc[-1] > prev_high:
                    #print("    [DEBUG] Inside bar breakout up.")
                    return 'buy'
                if df['close'].iloc[-1] < prev_low:
                    #print("    [DEBUG] Inside bar breakout down.")
                    return 'sell'
        # Volatility expansion (ATR spike)
        if len(df) >= 20:
            atr_now = calculate_atr(df)
            atr_prev = calculate_atr(df.iloc[:-1])
            if atr_now > atr_prev * 1.5:
                if df['close'].iloc[-1] > df['open'].iloc[-1]:
                    #print("    [DEBUG] ATR spike breakout up.")
                    return 'buy'
                elif df['close'].iloc[-1] < df['open'].iloc[-1]:
                    #print("    [DEBUG] ATR spike breakout down.")
                    return 'sell'
        # New: Three-bar breakout
        if len(df) >= 4:
            if df['close'].iloc[-2] > max(df['high'].iloc[-5:-2]):
                #print("    [DEBUG] Three-bar breakout up.")
                return 'buy'
            if df['close'].iloc[-2] < min(df['low'].iloc[-5:-2]):
                #print("    [DEBUG] Three-bar breakout down.")
                return 'sell'
        return None

class TrendMomentumStrategy(StrategyBase):
    def __init__(self):
        super().__init__("TrendMomentum")

    def check(self, df, features):
        if len(df) < 52:
            print("    [DEBUG] Not enough bars for pattern logic.")
            return None

        # Volatility regime filter (adaptive and ultra-permissive)
        returns = df['close'].pct_change().dropna()
        volatility_cluster = returns.rolling(10).std().iloc[-1]
        regime = "trend"
        if volatility_cluster < 0.0005:
            regime = "range"
           # print("    [DEBUG] Volatility low: switching to range regime (relaxing filters).")
        # Relax filter: allow entries in range regime
        if regime == "trend" and volatility_cluster < 0.0005:
            #print("    [DEBUG] Volatility too low for momentum trading.")
            return None
        elif regime == "range":
            # In range regime, allow ultra-permissive entries
            close = df['close'].iloc[-1]
            ema20 = features["ema20"]
            rsi = features["rsi"]
            atr = features["atr"]
            # EMA bounce or RSI reversal
            if abs(close - ema20) < atr and 35 < rsi < 65:
                #print("    [DEBUG] Range regime: EMA bounce or RSI reversal (ultra-permissive).")
                return 'buy' if close > ema20 else 'sell'
            # Simple candle color (green/red) as entry
            last_close = df['close'].iloc[-2]
            last_open = df['open'].iloc[-2]
            if last_close > last_open:
                #print("    [DEBUG] Range regime: Green candle, ultra-permissive buy.")
                return 'buy'
            if last_close < last_open:
                #print("    [DEBUG] Range regime: RSI reversal buy.")
                return 'buy'
            if rsi > 65:
                #print("    [DEBUG] Range regime: RSI reversal sell.")
                return 'sell'
            # Lower ML confidence threshold in range regime
            if features.get("ml_confidence", 0) > 0.25:
                #print("    [DEBUG] Range regime: ML confidence override, ultra-permissive entry.")
                return 'buy' if features.get("ml_signal") == "buy" else 'sell'

        close = df['close'].iloc[-1]
        ema200 = features["ema200"]
        trend_up = close > ema200
        trend_down = close < ema200

        # Momentum breakout (20-bar high/low with strong candle)
        high20 = df['high'].iloc[-21:-1].max()
        low20 = df['low'].iloc[-21:-1].min()
        last_close = df['close'].iloc[-2]
        last_open = df['open'].iloc[-2]
        last_body = abs(last_close - last_open)
        atr = features["atr"]
        momentum = last_body > atr * 0.7

        if trend_up and last_close > high20 and momentum:
            #print("    [DEBUG] Bullish momentum breakout detected.")
            return 'buy'
        if trend_down and last_close < low20 and momentum:
            #print("    [DEBUG] Bearish momentum breakout detected.")
            return 'sell'

        # Trend pullback entry (RSI pullback in trend direction)
        rsi = features["rsi"]
        if trend_up and rsi < 45 and last_close > last_open:
            #print("    [DEBUG] Trend pullback buy detected.")
            return 'buy'
        if trend_down and rsi > 55 and last_close < last_open:
            #print("    [DEBUG] Trend pullback sell detected.")
            return 'sell'

        # ADDITIONAL ENTRY PATTERNS FOR TREND/MOMENTUM
        # EMA20/EMA50 bounce in trend direction
        if trend_up and abs(close - features["ema20"]) < atr * 0.5 and close > features["ema50"]:
            #print("    [DEBUG] EMA20 bounce in uptrend.")
            return 'buy'
        if trend_down and abs(close - features["ema20"]) < atr * 0.5 and close < features["ema50"]:
            #print("    [DEBUG] EMA20 bounce in downtrend.")
            return 'sell'
        # RSI momentum surge
        if trend_up and rsi > 60 and last_close > last_open:
            #print("    [DEBUG] RSI momentum surge up.")
            return 'buy'
        if trend_down and rsi < 40 and last_close < last_open:
            #print("    [DEBUG] RSI momentum surge down.")
            return 'sell'
        # Consecutive higher highs/lows (trend continuation)
        if len(df) >= 5:
            highs = df['high'].iloc[-5:]
            lows = df['low'].iloc[-5:]
            if all(x < y for x, y in zip(highs, highs[1:])) and trend_up:
                #print("    [DEBUG] Consecutive higher highs (trend continuation up).")
                return 'buy'
            if all(x > y for x, y in zip(lows, lows[1:])) and trend_down:
                #print("    [DEBUG] Consecutive lower lows (trend continuation down).")
                return 'sell'
        # New: MACD zero line cross
        if len(df) >= 35:
            ema12 = calculate_ema(df, 12)
            ema26 = calculate_ema(df, 26)
            macd = ema12 - ema26
            macd_prev = calculate_ema(df.iloc[:-1], 12) - calculate_ema(df.iloc[:-1], 26)
            if macd_prev < 0 and macd > 0 and trend_up:
                #print("    [DEBUG] MACD zero line cross up.")
                return 'buy'
            if macd_prev > 0 and macd < 0 and trend_down:
                #print("    [DEBUG] MACD zero line cross down.")
                return 'sell'
        # New: Strong candle in trend direction
        if trend_up and last_close > last_open and (last_close - last_open) > atr:
            #print("    [DEBUG] Strong bullish candle in uptrend.")
            return 'buy'
        if trend_down and last_close < last_open and (last_open - last_close) > atr:
            #print("    [DEBUG] Strong bearish candle in downtrend.")
            return 'sell'
        return None

