# === Strategy Switching Logic ===

class StrategySwitcher:
    def __init__(self, strategies):
        self.strategies = strategies
        self.active_idx = 0  # Start with the first strategy
        self.performance = [0 for _ in strategies]  # Track PnL or win rate per strategy
        self.switch_cooldown = 10  # Number of trades before considering a switch
        self.trade_counts = [0 for _ in strategies]
        self.last_switch_trade = 0

    def select_strategy(self):
        return self.strategies[self.active_idx]

    def update_performance(self, idx, trade_result):
        self.performance[idx] += trade_result
        self.trade_counts[idx] += 1

    def maybe_switch(self, total_trades):
        # Switch if current strategy underperforms and cooldown passed
        if self.trade_counts[self.active_idx] >= self.switch_cooldown:
            # Find best performing strategy
            best_idx = int(np.argmax(self.performance))
            if best_idx != self.active_idx:
                print(f"[STRATEGY SWITCH] Switching from {self.strategies[self.active_idx].name} to {self.strategies[best_idx].name}")
                self.active_idx = best_idx
            # Reset counters for next evaluation window
            self.performance = [0 for _ in self.strategies]
            self.trade_counts = [0 for _ in self.strategies]
            self.last_switch_trade = total_trades

# --- Multi-timeframe trend confirmation ---

def get_trend(symbol):
    """
    Returns the overall trend direction ('buy', 'sell', or None) based on H4 and H1 timeframes.
    Uses EMA200 as the trend filter.
    """
    # Get H4 data
    h4_rates = mt5.copy_rates_from_pos(symbol, mt5.TIMEFRAME_H4, 0, 200)
    h1_rates = mt5.copy_rates_from_pos(symbol, mt5.TIMEFRAME_H1, 0, 200)
    if h4_rates is None or len(h4_rates) < 50 or h1_rates is None or len(h1_rates) < 50:
        return None

    import pandas as pd
    h4_df = pd.DataFrame(h4_rates)
    h1_df = pd.DataFrame(h1_rates)

    def ema(series, period):
        return series.ewm(span=period, adjust=False).mean()

    h4_ema200 = ema(h4_df['close'], 200).iloc[-1]
    h1_ema200 = ema(h1_df['close'], 200).iloc[-1]
    h4_close = h4_df['close'].iloc[-1]
    h1_close = h1_df['close'].iloc[-1]

    h4_trend = "buy" if h4_close > h4_ema200 else "sell"
    h1_trend = "buy" if h1_close > h1_ema200 else "sell"

    if h4_trend == h1_trend:
        return h4_trend
    return None

# --- Permissive pattern resolution + strategy votes ---

def resolve_pattern_signal(df, features):
    """
    Returns (pattern_signal, bullish_score, bearish_score, pattern_source)
    pattern_source ∈ {"features", "price_action", "strategy", None}
    """
    # 1) Feature-based scores (fast path)
    bullish_keys = [
        "cdl_bullish_engulfing","cdl_three_white_soldiers","cdl_hammer","cdl_morning_star",
        "is_bullish_engulfing","is_hammer","is_pin_bar","is_tweezer_bottom"
    ]
    bearish_keys = [
        "cdl_bearish_engulfing","cdl_three_black_crows","cdl_hanging_man","cdl_evening_star",
        "is_bearish_engulfing","is_tweezer_top","is_pin_bar"
    ]
    bull = sum(float(features.get(k, 0)) for k in bullish_keys)
    bear = sum(float(features.get(k, 0)) for k in bearish_keys)

    if bull > bear and bull >= 1:
        return "buy", bull, bear, "features"
    if bear > bull and bear >= 1:
        return "sell", bull, bear, "features"

    # 2) Price-action fallback (maps to buy/sell)
    try:
        pa = detect_price_action_pattern(df)  # your gold-tuned detector
        if pa == "bullish":
            return "buy", bull, bear, "price_action"
        if pa == "bearish":
            return "sell", bull, bear, "price_action"
    except Exception:
        pass

    # 3) Strategy fallback (first hit wins; still recorded)
    for strat in ALL_STRATEGIES:
        sig = strat.check(df, features)
        if sig in ("buy","sell"):
            return sig, bull, bear, getattr(strat, "name", strat.__class__.__name__)

    # Nothing conclusive
    return None, bull, bear, None


def collect_strategy_votes(df, features, ml_signal=None):
    """
    Returns dict of {strategy_name: signal} for visibility, plus agree_list.
    """
    votes = {}
    agree = []
    for strat in ALL_STRATEGIES:
        name = getattr(strat, "name", strat.__class__.__name__)
        sig = strat.check(df, features)
        if sig in ("buy","sell"):
            votes[name] = sig
            if ml_signal and sig == ml_signal:
                agree.append(name)
    return votes, agree

