# --- Risk Management Settings ---


def get_dynamic_atr_multiplier(atr, trend_strength, volatility_score):
    """
    Dynamically adjust ATR multiplier for SL/TP based on market regime.
    - Higher in high volatility/trending markets.
    - Lower in low volatility/range markets.
    """
    # Default multipliers
    min_mult = 0.7
    max_mult = 2.5

    # Example logic: combine trend and volatility
    # You can tune these thresholds for your market
    if volatility_score > 1.5 and abs(trend_strength) > 0.5:
        return max_mult  # Strong trend + high vol: wide stops
    elif volatility_score > 1.2 or abs(trend_strength) > 0.3:
        return 1.8
    elif volatility_score < 0.7 and abs(trend_strength) < 0.2:
        return min_mult  # Range/quiet: tight stops
    else:
        return 1.3  # Default

def get_dynamic_lot_size(symbol_info, regime):
    """
    Returns a dynamic lot size based on regime.
    Smaller lot in range/chop, larger in trend/high volatility.
    """
    min_lot = symbol_info.volume_min
    max_lot = symbol_info.volume_max
    step = symbol_info.volume_step
    if regime == "range":
        return min_lot  # Smallest lot in range/chop
    elif regime == "trend":
        return min(max_lot, min_lot + 2 * step)  # Slightly larger lot in trend
    else:
        return min_lot + step  # Default
# --- Trailing Stop and Break-Even Management ---
def manage_trailing_stop(symbol, entry_price, direction, atr, lot, break_even_pips=10, break_even_points=1000, trail_atr_mult=1.0):
    """
    Move SL only when price is at least 1000 points in profit from entry,
    then trail SL by trail_atr_mult * ATR as price continues in your favor.
    Ensures SL is always at least stop_level away from entry (required by broker).
    """
    import MetaTrader5 as mt5
    symbol_info = mt5.symbol_info(symbol)
    if not symbol_info:
        return
    point_size = symbol_info.point
    stop_level = symbol_info.stop_level if hasattr(symbol_info, "stop_level") else 0
    # Use break_even_points if provided, else convert break_even_pips to points
    min_profit_distance = break_even_points * point_size if break_even_points else break_even_pips * 10 * point_size

    positions = mt5.positions_get(symbol=symbol)
    if not positions:
        return
    for pos in positions:
        if (direction == "buy" and pos.type == mt5.ORDER_TYPE_BUY) or (direction == "sell" and pos.type == mt5.ORDER_TYPE_SELL):
            tick = mt5.symbol_info_tick(symbol)
            if not tick:
                continue
            current_price = tick.bid if direction == "buy" else tick.ask
            profit_distance = (current_price - entry_price) if direction == "buy" else (entry_price - current_price)
            # Only move SL if at least min_profit_distance in profit
            if profit_distance >= min_profit_distance:
                # Calculate minimum allowed SL distance from current price
                min_sl_distance = stop_level * point_size
                if direction == "buy":
                    trailed_sl = max(entry_price, current_price - trail_atr_mult * atr)
                    # Ensure SL is at least stop_level away from current price
                    trailed_sl = min(trailed_sl, current_price - min_sl_distance)
                    # Only update if new SL is better for the trade and not below entry
                    if (pos.sl is None or trailed_sl > pos.sl) and trailed_sl >= entry_price and (current_price - trailed_sl) >= min_sl_distance:
                        request = {
                            "action": mt5.TRADE_ACTION_SLTP,
                            "position": pos.ticket,
                            "sl": trailed_sl,
                            "tp": pos.tp,
                            "symbol": symbol,
                        }
                        mt5.order_send(request)
                else:
                    trailed_sl = min(entry_price, current_price + trail_atr_mult * atr)
                    trailed_sl = max(trailed_sl, current_price + min_sl_distance)
                    if (pos.sl is None or trailed_sl < pos.sl) and trailed_sl <= entry_price and (trailed_sl - current_price) >= min_sl_distance:
                        request = {
                            "action": mt5.TRADE_ACTION_SLTP,
                            "position": pos.ticket,
                            "sl": trailed_sl,
                            "tp": pos.tp,
                            "symbol": symbol,
                        }
                        mt5.order_send(request)
# --- ENSURE THIS FUNCTION IS DEFINED BEFORE trade_symbol ---
def risk_management(symbol, direction, lot, sl, tp, entry):
    """
    Strict risk management for safe live trading.
    Enforces a maximum number of open trades per symbol.
    """
    daily_pnl = get_daily_pnl()
    if daily_pnl <= MAX_DAILY_LOSS:
        return False, f"Max daily loss reached ({daily_pnl:.2f} <= {MAX_DAILY_LOSS})."
    
    # 🚨 HARD STOP: If loss exceeds -$150, EMERGENCY BLOCK
    if daily_pnl <= -MAX_DAILY_LOSS_HARD:
        return False, f"🚨 HARD LOSS LIMIT HIT: {daily_pnl:.2f} <= -${MAX_DAILY_LOSS_HARD}. NO MORE TRADES ALLOWED."
    
    if daily_pnl >= MAX_DAILY_PROFIT:
        return False, f"Max daily profit reached ({daily_pnl:.2f} >= {MAX_DAILY_PROFIT})."
    daily_trades = get_daily_trade_count()
    if daily_trades >= MAX_DAILY_TRADES:
        return False, f"Max daily trades reached ({daily_trades} >= {MAX_DAILY_TRADES})."
    if not has_sufficient_balance(lot, symbol):
        account_info = mt5.account_info()
        symbol_info = mt5.symbol_info(symbol)
        margin_required = None
        if account_info and symbol_info:
            margin_required = mt5.order_calc_margin(
                mt5.ORDER_TYPE_BUY, symbol, lot, symbol_info.ask
            )
        print(f"[RISK] Free margin: {account_info.margin_free if account_info else 'N/A'} | "
                f"Required margin: {margin_required if margin_required is not None else 'N/A'} | "
                f"Lot: {lot} | Symbol: {symbol}")
        return False, "Not enough free margin to open trade."
    if not risk_reward_ok(entry, sl, tp):
        return False, "Risk-reward ratio below threshold."
    if not is_symbol_tradable(symbol):
        return False, "Market is closed or not tradable."
    open_positions = mt5.positions_get(symbol=symbol)

    # --- BLOCK OPPOSITE DIRECTION ENTRIES ---
    if open_positions:
        for pos in open_positions:
            # MT5: pos.type == 0 is BUY, pos.type == 1 is SELL
            if (direction == "buy" and getattr(pos, "type", None) == 1) or (direction == "sell" and getattr(pos, "type", None) == 0):
                print(f"[RISK] Opposite position already open for {symbol}. Blocking {direction.upper()} entry.")
                return False, f"Opposite position already open for {symbol}."

    # --- ENFORCE MAX OPEN TRADES PER SYMBOL ---
    # Set your max open trades per symbol here:
    MAX_OPEN_TRADES_PER_SYMBOL = 4  # <--- Change this value as desired (e.g., 1 for only 1 trade per symbol)

    if open_positions and len(open_positions) >= MAX_OPEN_TRADES_PER_SYMBOL:
        print(f"[RISK] Max open trades reached for {symbol}: {len(open_positions)} >= {MAX_OPEN_TRADES_PER_SYMBOL}")
        return False, f"Too many open trades for {symbol} ({len(open_positions)} >= {MAX_OPEN_TRADES_PER_SYMBOL})"


    # --- ENFORCE GLOBAL MAX OPEN POSITIONS ---
    MAX_GLOBAL_OPEN_POSITIONS = 10  # Set to your broker/account limit
    all_positions = mt5.positions_get()
    if all_positions and len(all_positions) >= MAX_GLOBAL_OPEN_POSITIONS:
        print(f"[RISK] Max global open positions reached: {len(all_positions)} >= {MAX_GLOBAL_OPEN_POSITIONS}")
        return False, f"Too many open positions globally ({len(all_positions)} >= {MAX_GLOBAL_OPEN_POSITIONS})"


    account_info = mt5.account_info()
    if account_info:
        balance = account_info.balance
        # --- DYNAMIC RISK PER TRADE LOGIC ---
        symbol_risk_pct = MAX_RISK_PER_TRADE_PCT
        if "XAU" in symbol or "JPY" in symbol:
            symbol_risk_pct = 0.02  # Allow up to 2% risk per trade for these symbols (legacy override)
        # Enforce global hard cap so no symbol can exceed HARD_RISK_MAX_PCT
        if 'HARD_RISK_MAX_PCT' in globals():
            try:
                symbol_risk_pct = min(float(symbol_risk_pct), HARD_RISK_MAX_PCT)
            except Exception:
                symbol_risk_pct = float(HARD_RISK_MAX_PCT)

        risk_amount = abs(entry - sl) * lot * 100000
        max_risk = balance * symbol_risk_pct
        if risk_amount > max_risk:
            print(f"    [RISK] Overriding max risk for {symbol}: {risk_amount:.2f} > {max_risk:.2f} (allowed {symbol_risk_pct*100:.1f}% of balance)")
            # Optionally, allow anyway, or just warn and allow

        total_open_risk = 0
        positions = safe_positions_get() if 'safe_positions_get' in globals() else (mt5.positions_get() if mt5 else None)
        for pos in positions or []:
            if hasattr(pos, "sl") and pos.sl:
                open_risk = abs(pos.price_open - pos.sl) * pos.volume * 100000
                total_open_risk += open_risk
        total_open_risk += abs(entry - sl) * lot * 100000
        max_total_risk = account_info.balance * MAX_TOTAL_OPEN_RISK_PCT
        if total_open_risk > max_total_risk:
            print(f"    [RISK] Overriding max total open risk for {symbol}: {total_open_risk:.2f} > {max_total_risk:.2f} (allowed {MAX_TOTAL_OPEN_RISK_PCT*100:.1f}% of balance)")
            # Optionally, allow anyway, or just warn and allow
    return True, ""
def relaxed_eurusd_decision_logic(ml_signal, ml_confidence, gps_trend_strength, volatility_score):
    # Make EURUSD much more permissive for trade entry
    TREND_THRESHOLD = 0.3
    ML_CONFIDENCE_OVERRIDE = 0.5
    VOLATILITY_OVERRIDE = 0.4
    CONFIDENCE_MIN = 0.35
    SCORE_THRESHOLD = 0.40

    take_trade = False
    reason = "No trade"

    combined_score = (ml_confidence * 0.6) + (gps_trend_strength * 0.4)

    if ml_confidence < CONFIDENCE_MIN:
        reason = "ML confidence too low"
    elif gps_trend_strength >= TREND_THRESHOLD:
        take_trade = True
        reason = "GPS trend strong enough"
    elif ml_confidence >= ML_CONFIDENCE_OVERRIDE:
        take_trade = True
        reason = "ML confidence override"
    elif volatility_score >= VOLATILITY_OVERRIDE and ml_confidence >= 0.4:
        take_trade = True
        reason = "High volatility override"
    elif combined_score >= SCORE_THRESHOLD:
        take_trade = True
        reason = "Combined score passed threshold"
    else:
        reason = "Filters too weak"

    return take_trade, reason
    if not take_trade:
        print(f"    [{symbol}] {reason}")
        print("=" * 40)
        return


