    def load_historical_buffer_live(symbol, bars=2000, timeframe="M5"):
        """
        Loads historical OHLCV data for a symbol robustly, with debug print.
        Dynamically resolves any prefix/suffix for the symbol.
        """
        full_symbol = resolve_symbol_live(symbol)
        if not full_symbol:
            print(f"[DATA] Could not resolve symbol {symbol} for historical data.")
            print("[HINT] Ensure the symbol is visible in Market Watch and history is loaded.")
            return None

        tf_map = {
            "M1": mt5.TIMEFRAME_M1,
            "M5": mt5.TIMEFRAME_M5,
            "M15": mt5.TIMEFRAME_M15,
            "H1": mt5.TIMEFRAME_H1,
            "H4": mt5.TIMEFRAME_H4,
            "D1": mt5.TIMEFRAME_D1,
        }
        mt5_tf = tf_map.get(timeframe.upper(), mt5.TIMEFRAME_M5)

        try:
            rates = mt5.copy_rates_from_pos(full_symbol, mt5_tf, 0, bars)
            if rates is None or len(rates) == 0:
                print(f"[ERROR] Error fetching price data for {full_symbol}: Not enough bars found (needed {bars})")
                print("[HINT] Ensure the symbol is visible in Market Watch and history is loaded.")
                return None

            df = pd.DataFrame(rates)
            df['time'] = pd.to_datetime(df['time'], unit='s')

            # Keep last 6 months for training relevance
            if len(df) > (24 * 4 * 30 * 6):
                df = df.tail(24 * 4 * 30 * 6)
                print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")

            return df

        except Exception as e:
            print(f"[DATA] Exception loading data for {full_symbol}: {e}")
            print("[HINT] Ensure the symbol is visible in Market Watch and history is loaded.")
            return None


    def get_price_data_live(symbol, bars=1, timeframe="M5"):
        """
        Get latest price data for a symbol, robustly, with debug print.
        Dynamically resolves any prefix/suffix for the symbol.
        timeframe: "M1", "M5", "M15", "H1", etc.
        """
        full_symbol = resolve_symbol_live(symbol)
        if not full_symbol:
            print(f"[DATA] Could not resolve symbol {symbol} for price data.")
            return None

        tf_map = {
            "M1": mt5.TIMEFRAME_M1,
            "M5": mt5.TIMEFRAME_M5,
            "M15": mt5.TIMEFRAME_M15,
            "H1": mt5.TIMEFRAME_H1,
            "H4": mt5.TIMEFRAME_H4,
            "D1": mt5.TIMEFRAME_D1,
        }
        mt5_tf = tf_map.get(timeframe.upper(), mt5.TIMEFRAME_M5)

        try:
            rates = mt5.copy_rates_from_pos(full_symbol, mt5_tf, 0, bars)
            if rates is None or len(rates) == 0:
                print(f"[DATA] No price data for {full_symbol}. rates={rates}")
                return None

            df = pd.DataFrame(rates)
            df['time'] = pd.to_datetime(df['time'], unit='s')

            # Keep last 6 months for training relevance
            if len(df) > (24 * 4 * 30 * 6):
                df = df.tail(24 * 4 * 30 * 6)
                print(f"[DATA] Trimmed dataset to last 6 months ({len(df)} bars).")

            return df

        except Exception as e:
            print(f"[DATA] Exception getting price data for {full_symbol}: {e}")
            return None


