    def last_n_bars_confirm_signal(df, n, direction):
        """
        Returns True if the last n bars confirm the given direction.
        For 'buy', checks if each close > open; for 'sell', checks if each close < open.
        """
        if len(df) < n:
            return False
        bars = df.iloc[-n:]
        if direction == "buy":
            return all(bars['close'] > bars['open'])
        elif direction == "sell":
            return all(bars['close'] < bars['open'])
