            def get_regime_features(df):
                # Assumes df has columns: 'close', 'ema20', 'ema50', 'ema200', 'atr'
                if len(df) < 60:
                    return None
                atr = df['atr'].iloc[-1]
                atr_50 = df['atr'].rolling(50).mean().iloc[-1]
                std20 = df['close'].rolling(20).std().iloc[-1]
                std20_prev = df['close'].rolling(20).std().iloc[-2]
                atr_prev = df['atr'].iloc[-2]
                ema20 = df['ema20'].iloc[-1]
                ema50 = df['ema50'].iloc[-1]
                ema200 = df['ema200'].iloc[-1]
                # Expansion/squeeze
                atr_squeeze = atr < 0.6 * atr_50
                atr_expansion = atr > 1.3 * atr_50
                std20_expanding = std20 > std20_prev
                trending_up = ema20 > ema50 > ema200
                trending_down = ema20 < ema50 < ema200
                choppy = std20 / atr < 0.7
                return {
                    "atr": atr,
                    "atr_50": atr_50,
                    "atr_squeeze": atr_squeeze,
                    "atr_expansion": atr_expansion,
                    "std20": std20,
                    "std20_expanding": std20_expanding,
                    "ema20": ema20,
                    "ema50": ema50,
                    "ema200": ema200,
                    "trending_up": trending_up,
                    "trending_down": trending_down,
                    "choppy": choppy,
                }

            # ═══════════════════════════════════════════════════════════════════════════════
            # DYNAMIC LOT SIZING FUNCTION (Account Balance > $200)
            # ═══════════════════════════════════════════════════════════════════════════════
            def calculate_dynamic_lot_size(base_lot_size=0.02, min_balance_threshold=200):
                """
                Calculate dynamic lot size based on account balance.
                If balance > $200, scale lot size proportionally.
                If balance <= $200, use base lot size (conservative).
                
                Formula:
                  If balance > 200: dynamic_lot = base_lot * (balance / 200)
                  If balance <= 200: dynamic_lot = base_lot
                
                Example:
                  - Balance $100: use 0.01 (base)
                  - Balance $200: use 0.01 (base)
                  - Balance $300: use 0.015 (0.01 * 300/200)
                  - Balance $500: use 0.025 (0.01 * 500/200)
                  - Balance $1000: use 0.05 (0.01 * 1000/200)
                """
                try:
                    acct = mt5.account_info()
                    if acct is None:
                        return base_lot_size
                    
                    balance = float(acct.balance or 0.0)
                    
                    if balance <= 0:
                        return base_lot_size
                    
                    # If balance is above threshold, scale lot size
                    if balance > min_balance_threshold:
                        # Scale proportionally: balance/threshold * base_lot
                        dynamic_lot = base_lot_size * (balance / min_balance_threshold)
                        # Cap at reasonable maximum (e.g., 0.5 lots to avoid excessive risk)
                        dynamic_lot = min(dynamic_lot, 0.5)
                        return round(dynamic_lot, 4)  # Round to 4 decimals
                    else:
                        # Below threshold, use base lot size
                        return base_lot_size
                
                except Exception as e:
                    print(f"[LOT SIZING ERROR] {str(e)} - Using base lot size")
                    return base_lot_size
            
            # Get initial dynamic lot size for this cycle
            LOT_SIZE = calculate_dynamic_lot_size(base_lot_size=0.02, min_balance_threshold=200)

