            # --- Midnight Pause Handling ---
            # --- Rollover Pause Handling (for all session rollovers, not just midnight) ---
            def is_near_rollover_pause(window_minutes=15):
                """
                Returns True if current broker/server time is within window_minutes before a major session rollover.
                Typical rollovers: 00:00, 05:00, 09:00, 13:00, 17:00, 21:00 (MT5 server time, adjust as needed).
                """
                now = dtmod.datetime.now()
                # Define all session rollover times (24h format, adjust for your broker/server time zone)
                rollover_hours = [0, 5, 9, 13, 17, 21]
                for hour in rollover_hours:
                    rollover = now.replace(hour=hour, minute=0, second=0, microsecond=0)
                    # If rollover already passed today, check next day's rollover
                    if rollover < now:
                        rollover += dtmod.timedelta(days=1)
                    minutes_to_rollover = (rollover - now).total_seconds() / 60.0
                    if 0 <= minutes_to_rollover <= window_minutes:
                        return True
                return False

