                    def evaluate_4h_ema_structure_local(df_4h, min_bars=50):
                        out = {'decision': 'neutral', 'score': 0.0, 'ema20': None, 'ema50': None, 'ema200': None,
                               'ema20_slope': None, 'ema50_slope': None, 'ema200_slope': None, 'structure': None, 'reasons': []}
