                            out['ema200'] = float(close.ewm(span=200, adjust=False).mean().iloc[-1])
                            def slope(series, n=3):
                                if len(series) < n+1:
                                    return 0.0
                                return float((series.iloc[-1] - series.iloc[-1-n]) / (series.iloc[-1-n] + 1e-12))
                            out['ema20_slope'] = slope(close.ewm(span=20, adjust=False).mean())
                            out['ema50_slope'] = slope(close.ewm(span=50, adjust=False).mean())
                            out['ema200_slope'] = slope(close.ewm(span=200, adjust=False).mean())
