                            score = 0.0
                            if out['ema20'] > out['ema50'] > out['ema200']:
                                score += 3.0; out['reasons'].append('ema_ribbon_bull')
                            if out['ema20'] < out['ema50'] < out['ema200']:
                                score += 3.0; out['reasons'].append('ema_ribbon_bear')
                            if out['structure'] == 'uptrend':
                                score += 2.0; out['reasons'].append('hh_hl')
                            if out['structure'] == 'downtrend':
                                score += 2.0; out['reasons'].append('ll_lh')
                            if out['ema20_slope'] and abs(out['ema20_slope']) > 0.0002:
                                score += 1.0
                            try:
                                dist = abs(out['ema50'] - out['ema200']) / (out['ema200'] + 1e-12)
                                if dist > 0.005:
                                    score += 1.0; out['reasons'].append('ema_distance')
                            except Exception:
                                pass
                            out['score'] = round(score, 2)
                            if score >= 4.0 and out['ema20'] > out['ema50'] > out['ema200'] and out['structure'] == 'uptrend':
                                out['decision'] = 'long'
                            elif score >= 4.0 and out['ema20'] < out['ema50'] < out['ema200'] and out['structure'] == 'downtrend':
                                out['decision'] = 'short'
