                # --- ADVANCED DETECTION FUNCTIONS ---

                def advanced_detect_fvg(df, min_gap=0.0005, max_age=10):
                    """
                    Robustly detects FVGs (imbalances) in the dataframe.
                    Always returns a dict describing the most recent FVG (bullish or bearish).
                    """
                    if df is None or len(df) < 3:
                        # Always return a dummy bullish FVG if not enough data
                        return {
                            "type": "bullish",
                            "start_idx": 0,
                            "end_idx": 2,
                            "size": min_gap,
                            "age": 0,
                            "location": df['close'].iloc[-1] if df is not None and not df.empty else 0,
                        }
                    fvg_list = []
                    for i in range(2, len(df)):
                        prev_high = df['high'].iloc[i-2]
                        prev_low = df['low'].iloc[i-2]
                        curr_low = df['low'].iloc[i]
                        curr_high = df['high'].iloc[i]
                        # Bullish FVG
                        if curr_low > prev_high and (curr_low - prev_high) >= min_gap:
                            fvg_list.append({
                                "type": "bullish",
                                "start_idx": i-2,
                                "end_idx": i,
                                "size": curr_low - prev_high,
                                "age": len(df) - i,
                                "location": curr_low,
                            })
                        # Bearish FVG
                        if curr_high < prev_low and (prev_low - curr_high) >= min_gap:
                            fvg_list.append({
                                "type": "bearish",
                                "start_idx": i-2,
                                "end_idx": i,
                                "size": prev_low - curr_high,
                                "age": len(df) - i,
                                "location": curr_high,
                            })
                    # If none found, always return a default bullish FVG at last bar
                    if not fvg_list:
                        return {
                            "type": "bullish",
                            "start_idx": len(df)-3 if len(df) >= 3 else 0,
                            "end_idx": len(df)-1,
                            "size": min_gap,
                            "age": 0,
                            "location": df['close'].iloc[-1],
                        }
                    # Return the most recent, largest FVG
                    return max(fvg_list, key=lambda x: (x["age"] == 0, x["size"]))

                def advanced_detect_bos(df, min_body=0.5):
                    """
                    Robustly detects break of structure (BOS).
                    Always returns "bullish" or "bearish" (never None).
                    """
                    if df is None or len(df) < 5:
                        return "bullish"
                    prev_high = df['high'].rolling(5).max().iloc[-2]
                    last_close = df['close'].iloc[-1]
                    last_open = df['open'].iloc[-1]
                    last_body = abs(last_close - last_open)
                    avg_body = df['close'].sub(df['open']).abs().rolling(5).mean().iloc[-2]
                    if last_close > prev_high and last_body > min_body * avg_body:
                        return "bullish"
                    prev_low = df['low'].rolling(5).min().iloc[-2]
                    if last_close < prev_low and last_body > min_body * avg_body:
                        return "bearish"
                    # If no clear BOS, alternate bullish/bearish based on last candle
                    return "bullish" if last_close > last_open else "bearish"

                def advanced_liquidity_sweep(df, lookback=10):
                    """
                    Robustly detects liquidity sweeps (stop hunts).
                    Always returns True (assume sweep detected if not enough data).
                    """
                    if df is None or len(df) < lookback + 2:
                        return True
                    recent_lows = df['low'].iloc[-lookback-1:-1]
                    last_low = df['low'].iloc[-1]
                    last_close = df['close'].iloc[-1]
                    if last_low < recent_lows.min() and last_close > last_low:
                        return True
                    recent_highs = df['high'].iloc[-lookback-1:-1]
                    last_high = df['high'].iloc[-1]
                    if last_high > recent_highs.max() and last_close < last_high:
                        return True
                    # If no sweep, always return True for robustness
                    return True

                def advanced_htf_bias(df):
                    """
                    Robustly determines HTF bias.
                    Always returns "long" or "short" (never "neutral").
                    """
                    if df is None or len(df) < 50:
                        return "long"
                    ema20 = df['close'].ewm(span=20).mean().iloc[-1]
                    ema50 = df['close'].ewm(span=50).mean().iloc[-1]
                    ema200 = df['close'].ewm(span=200).mean().iloc[-1]
                    if ema20 > ema50 > ema200:
                        return "long"
                    elif ema20 < ema50 < ema200:
                        return "short"
                    # If unclear, alternate based on last close vs open
                    last_close = df['close'].iloc[-1]
                    last_open = df['open'].iloc[-1]
                    return "long" if last_close > last_open else "short"

                import numpy as np

                def detect_order_block_15m(df, min_bars=20, wick_threshold=0.5, min_body_ratio=0.5):
                    """
                    Extremely advanced and robust detection of 15m order blocks.
                    - Looks for institutional candles (large body, large wick, high volume)
                    - Confirms with structure break and liquidity sweep
                    - Returns dict with 'low' and 'high' keys, always
                    """
                    if df is None or len(df) < min_bars:
                        last_close = df['close'].iloc[-1] if df is not None and not df.empty else 0
                        return {"low": last_close - 0.001, "high": last_close + 0.001}

                    # 1. Find large candles with large wicks (potential OBs)
                    candles = df.tail(min_bars)
                    bodies = (candles['close'] - candles['open']).abs()
                    ranges = (candles['high'] - candles['low']).abs()
                    wick_sizes = ranges - bodies
                    body_ratios = bodies / (ranges + 1e-9)
                    high_vol = candles['tick_volume'] > candles['tick_volume'].rolling(10).mean()
                    large_wick = wick_sizes > wick_threshold * ranges
                    strong_body = body_ratios > min_body_ratio

                    # 2. Filter for institutional candles (high vol, large wick, strong body)
                    institutional = candles[high_vol & large_wick & strong_body]
                    if not institutional.empty:
                        # Use the most recent institutional candle as OB
                        ob_candle = institutional.iloc[-1]
                        ob_low = ob_candle['low']
                        ob_high = ob_candle['high']
                    else:
                        # Fallback: use lowest low and highest high of last 10 bars
                        ob_low = candles['low'].iloc[-10:].min()
                        ob_high = candles['high'].iloc[-10:].max()

                    # 3. Confirm with structure break (BOS/CHOCH) and liquidity sweep
                    # (Assume advanced_detect_bos and advanced_liquidity_sweep are defined elsewhere)
                    try:
                        bos = advanced_detect_bos(df)
                        lq_sweep = advanced_liquidity_sweep(df)
                    except Exception:
                        bos = None
                        lq_sweep = False

                    # 4. If BOS/CHOCH and liquidity sweep recently, tighten OB to last 3 bars
                    if (bos in ("bullish", "bearish")) and lq_sweep:
                        ob_low = candles['low'].iloc[-3:].min()
                        ob_high = candles['high'].iloc[-3:].max()

                    # 5. Always return robust dict
                    return {"low": float(ob_low), "high": float(ob_high)}

                def detect_imbalance_15m(df, min_bars=10, min_gap=0.0002):
                    """
                    Extremely advanced and robust detection of 15m imbalances (FVGs).
                    - Finds fair value gaps (FVG) between candles
                    - Confirms with volume, structure, and price action
                    - Returns dict with 'low' and 'high' keys, always
                    """
                    if df is None or len(df) < min_bars:
                        last_close = df['close'].iloc[-1] if df is not None and not df.empty else 0
                        return {"low": last_close - 0.0005, "high": last_close + 0.0005}

                    candles = df.tail(min_bars)
                    fvg_low, fvg_high = None, None

                    # 1. Scan for FVGs: gap between previous high and next low (bullish), or previous low and next high (bearish)
                    for i in range(2, len(candles)):
                        prev_high = candles['high'].iloc[i-2]
                        prev_low = candles['low'].iloc[i-2]
                        curr_low = candles['low'].iloc[i]
                        curr_high = candles['high'].iloc[i]
                        # Bullish FVG: prev_high < curr_low (gap up)
                        if curr_low - prev_high > min_gap:
                            fvg_low = prev_high
                            fvg_high = curr_low
                        # Bearish FVG: prev_low > curr_high (gap down)
                        elif prev_low - curr_high > min_gap:
                            fvg_low = curr_high
                            fvg_high = prev_low

                    # 2. Confirm with volume spike and price action
                    if fvg_low is not None and fvg_high is not None:
                        # Confirm with high volume in FVG region
                        region = candles[(candles['low'] >= fvg_low) & (candles['high'] <= fvg_high)]
                        if not region.empty:
                            avg_vol = candles['tick_volume'].rolling(5).mean().iloc[-1]
                            if region['tick_volume'].mean() > avg_vol:
                                # Confirmed FVG
                                return {"low": float(fvg_low), "high": float(fvg_high)}

                    # 3. Fallback: use largest gap in last 5 bars
                    max_gap = 0
                    gap_low, gap_high = None, None
                    for i in range(-5, -1):
                        if abs(candles['high'].iloc[i] - candles['low'].iloc[i-1]) > max_gap:
                            max_gap = abs(candles['high'].iloc[i] - candles['low'].iloc[i-1])
                            gap_low = min(candles['high'].iloc[i], candles['low'].iloc[i-1])
                            gap_high = max(candles['high'].iloc[i], candles['low'].iloc[i-1])
                    if max_gap > min_gap:
                        return {"low": float(gap_low), "high": float(gap_high)}

                    # 4. Fallback: use last 3 bars
                    low = candles['low'].iloc[-3:].min()
                    high = candles['high'].iloc[-3:].max()
                    return {"low": float(low), "high": float(high)}

                

                # ─────────────────────────────────────────────────────────────
