                def detect_htf_sr_from_bos(df, direction=None, lookback=80, min_swing=3):
                    """
                    Refined HTF Support/Resistance detection using your BOS/swing logic.
                    - For direction == "long": returns resistance 'R' just above current price
                    - For direction == "short": returns support 'S' just below current price
                    - Uses swing highs/lows and closes in a lookback window.
                    Returns float or None.
                    """
                    if df is None or len(df) < lookback:
                        return None

                    window = df.tail(lookback)
                    highs = window["high"].values
                    lows = window["low"].values
                    closes = window["close"].values

                    swing_highs = []
                    swing_lows = []
                    for i in range(min_swing, len(window) - min_swing):
                        if highs[i] == max(highs[i - min_swing : i + min_swing + 1]):
                            swing_highs.append(i)
                        if lows[i] == min(lows[i - min_swing : i + min_swing + 1]):
                            swing_lows.append(i)

                    current_price = closes[-1]

                    if direction == "long":
                        # Nearest swing high ABOVE current price
                        candidates = [highs[i] for i in swing_highs if highs[i] > current_price]
                        if candidates:
                            return float(min(candidates))  # closest above
                        # fallback: max high in window
                        return float(highs.max())
                    elif direction == "short":
                        # Nearest swing low BELOW current price
                        candidates = [lows[i] for i in swing_lows if lows[i] < current_price]
                        if candidates:
                            return float(max(candidates))  # closest below
                        # fallback: min low in window
                        return float(lows.min())
                    else:
                        # neutral: just return last swing high/low pair mid if available
                        if swing_highs and swing_lows:
                            return float((highs[swing_highs[-1]] + lows[swing_lows[-1]]) / 2.0)
                        return float((highs.max() + lows.min()) / 2.0)

                def confirm_break_and_close_above(df, level, min_body_ratio=1.1, lookback_bars=3):
                    """
                    Confirm a clean bullish breakout ABOVE 'level'.
                    Conditions:
                      - Last candle close > level
                      - Previous close <= level
                      - Body >= min_body_ratio * avg_body(last N bars)
                    """
                    if df is None or len(df) < lookback_bars + 2 or level is None:
                        return False

                    c = float(df["close"].iloc[-1])
                    o = float(df["open"].iloc[-1])
                    prev_close = float(df["close"].iloc[-2])

                    if not (c > level and prev_close <= level):
                        return False

                    body = abs(c - o)
                    bodies = df["close"].sub(df["open"]).abs().tail(lookback_bars + 1).iloc[:-1]
                    avg_body = bodies.mean()
                    if avg_body <= 0 or np.isnan(avg_body):
                        return False

                    return body >= min_body_ratio * avg_body

                def confirm_break_and_close_below(df, level, min_body_ratio=1.1, lookback_bars=3):
                    """
                    Confirm a clean bearish breakout BELOW 'level'.
                    Conditions:
                      - Last candle close < level
                      - Previous close >= level
                      - Body >= min_body_ratio * avg_body(last N bars)
                    """
                    if df is None or len(df) < lookback_bars + 2 or level is None:
                        return False

                    c = float(df["close"].iloc[-1])
                    o = float(df["open"].iloc[-1])
                    prev_close = float(df["close"].iloc[-2])

                    if not (c < level and prev_close >= level):
                        return False

                    body = abs(c - o)
                    bodies = df["close"].sub(df["open"]).abs().tail(lookback_bars + 1).iloc[:-1]
                    avg_body = bodies.mean()
                    if avg_body <= 0 or np.isnan(avg_body):
                        return False

                    return body >= min_body_ratio * avg_body

                def price_retests_level(df, level, buffer_ratio=0.25):
                    """
                    Detects a retest of 'level' on the latest candle.
                    Uses dynamic buffer from recent ATR/range.
                    Returns (retested: bool, retest_low: float, retest_high: float).
                    """
                    if df is None or len(df) < 5 or level is None:
                        return (False, None, None)

                    last = df.iloc[-1]
                    high = float(last["high"])
                    low = float(last["low"])

                    recent_range = (df["high"] - df["low"]).rolling(10).mean().iloc[-1]
                    if np.isnan(recent_range) or recent_range <= 0:
                        recent_range = (df["high"].iloc[-10:] - df["low"].iloc[-10:]).mean()

                    buf = recent_range * buffer_ratio
                    retest_low = level - buf
                    retest_high = level + buf

                    touched = (low <= retest_high) and (high >= retest_low)
                    return (touched, retest_low, retest_high)

                def bullish_retest_confirmation(df):
                    """
                    Confirms bullish intent on retest:
                      - Last candle closes bullish
                      - Body >= 50% of range (avoid doji)
                    """
                    if df is None or len(df) < 2:
                        return False
                    last = df.iloc[-1]
                    o, c, h, l = map(float, [last["open"], last["close"], last["high"], last["low"]])
                    if c <= o:
                        return False
                    rng = max(h - l, 1e-9)
                    body = abs(c - o)
                    return body >= 0.5 * rng

                def bearish_retest_confirmation(df):
                    """
                    Confirms bearish intent on retest:
                      - Last candle closes bearish
                      - Body >= 50% of range
                    """
                    if df is None or len(df) < 2:
                        return False
                    last = df.iloc[-1]
                    o, c, h, l = map(float, [last["open"], last["close"], last["high"], last["low"]])
                    if c >= o:
                        return False
                    rng = max(h - l, 1e-9)
                    body = abs(c - o)
                    return body >= 0.5 * rng

                def simple_atr(df, period=14):
                    """
                    Lightweight ATR approximation using candle ranges.
                    df must have 'high', 'low', 'close'.
                    """
                    if df is None or len(df) < period:
                        return None
                    ranges = (df["high"] - df["low"]).tail(period)
                    atr = ranges.mean()
                    try:
                        return float(atr)
                    except Exception:
                        return None

                def build_partial_tp_plan(entry, direction, R2, atr, point_value, risk_R=1.0):

                    """
                    Builds an advanced partial TP + runner plan.
                    Returns dict: {'tp1', 'tp2', 'tp1_size', 'tp2_size'}.
                    """
                    if entry is None or direction not in ("buy", "sell"):
                        return None

                    runner_R_multiple = 2.5

                    if R2 is not None:
                        buffer_points = int(max(atr * 0.3 / point_value, 5))
                        if direction == "buy":
                            tp1 = R2 - buffer_points * point_value
                        else:
                            tp1 = R2 + buffer_points * point_value
                    else:
                        tp1 = entry + (atr * risk_R if direction == "buy" else -atr * risk_R)

                    tp2 = entry + (atr * runner_R_multiple * (1 if direction == "buy" else -1))

                    return {
                        "tp1": tp1,
                        "tp2": tp2,
                        "tp1_size": 0.65,
                        "tp2_size": 0.35,
                    }

