                    print(f"  M15 Trend   : {ctx.get('m15_trend')} (pullback={ctx.get('m15_pullback')}, pattern={ctx.get('m15_pattern_confirmed')})")
                    print(f"  M5 Timing   : {'READY' if ctx.get('m5_entry_ready') else 'WAIT'} (at_zone={ctx.get('m5_at_zone')}, BOS={ctx.get('m5_bos')})")
                    reasons = ctx.get("reasons") or []
