                                #         session_block = True
                                #         session_reason = (
                                #             f"Session filter: avoiding fresh buys late in session (hour={hour:02d})."
                                #         )

                                # Symmetric: for sells, be extra strict in late sessions too
                                # if not session_block and direction_for_filters == "sell":
                                #     if (hour >= london_end and hour < ny_start) or (hour >= ny_end - 1):
                                #         session_block = True
