                                # (Optional) 3) After making a London session high/low, apply caution instead of blocking
                                # DISABLED: Too many false blocks on valid breakouts - now advisory only
                                if not session_block and direction_for_filters == "buy":
                                    same_day = df_15m["time"].dt.date == now_ts.date()
