                    # Check LTF structure (M5 or M15)
                    ltf_df = df_m5 if 'df_m5' in locals() and df_m5 is not None else (df_m15 if 'df_m15' in locals() and df_m15 is not None else None)
                    if ltf_df is not None and len(ltf_df) >= 10:
                        ltf_result = ltf_structure_confirmation(ltf_df, ml_signal)
                        signal_data['ltf_choch'] = ltf_result['confirmed']
                    
                    # Validate entry based on mode
                    entry_allowed_by_mode = False
