                def detect_trendline_break(df, lookback=30):
                    highs = df['high'].iloc[-lookback:]
                    lows = df['low'].iloc[-lookback:]
                    trendline_up = lows.min()
                    trendline_down = highs.max()
                    close = df['close'].iloc[-1]
                    if close > trendline_down:
                        return "break_up"
                    elif close < trendline_up:
                        return "break_down"
                    return None

                # 2. Support & Resistance
                def detect_sr_levels(df, window=50):
                    highs = df['high'].rolling(window).max()
