                # 6. Momentum Indicators (RSI, MACD, Stochastics)
                def calculate_rsi(df, period=14):
                    delta = df['close'].diff()
                    up = delta.clip(lower=0)
                    down = -delta.clip(upper=0)
                    roll_up = up.rolling(period).mean()
                    roll_down = down.rolling(period).mean()
                    rs = roll_up / (roll_down + 1e-9)
                    rsi = 100 - (100 / (1 + rs))
                    return rsi

                def calculate_macd(df, fast=12, slow=26, signal=9):
                    ema_fast = df['close'].ewm(span=fast, adjust=False).mean()
                    ema_slow = df['close'].ewm(span=slow, adjust=False).mean()
                    macd = ema_fast - ema_slow
                    signal_line = macd.ewm(span=signal, adjust=False).mean()
                    return macd, signal_line

                def calculate_stochastic(df, k_period=14, d_period=3):
                    low_min = df['low'].rolling(window=k_period).min()
                    high_max = df['high'].rolling(window=k_period).max()
                    k = 100 * (df['close'] - low_min) / (high_max - low_min + 1e-9)
                    d = k.rolling(window=d_period).mean()
                    return k, d

                # 7. Moving Average Crossovers
                def ma_crossover(df, fast=9, slow=21):
                    ema_fast = df['close'].ewm(span=fast, adjust=False).mean()
                    ema_slow = df['close'].ewm(span=slow, adjust=False).mean()
                    if ema_fast.iloc[-2] < ema_slow.iloc[-2] and ema_fast.iloc[-1] > ema_slow.iloc[-1]:
                        return "bullish"
                    elif ema_fast.iloc[-2] > ema_slow.iloc[-2] and ema_fast.iloc[-1] < ema_slow.iloc[-1]:
                        return "bearish"
                    return None

