                # 1. Machine Learning Model Stacking/Ensemble
                # Use multiple ML models (e.g., XGBoost, LSTM, RandomForest) and combine their predictions for more robust signals.
                def stacked_ml_signal(features, models):
                    votes = []
                    confidences = []
                    for model in models:
                        pred = model.predict(features)
                        if isinstance(pred, dict):
                            label = pred.get("label") or pred.get("signal") or "hold"
                            conf = pred.get("confidence", 0.0)
