                    price_bins = np.linspace(df['low'].min(), df['high'].max(), bins)
                    df['price_bin'] = np.digitize(df['close'], price_bins)
                    volume_profile = df.groupby('price_bin')['tick_volume'].sum()
                    # Return price bin with highest volume (point of control)
                    poc_bin = volume_profile.idxmax()
                    poc_price = price_bins[poc_bin-1] if poc_bin > 0 else price_bins[0]
                    return poc_price

