# These functions detect SMC patterns: BOS, liquidity sweeps, FVG, displacement.
# Used as ENTRY CONFIRMATION on top of EMA bias (not replacement).
import threading
import time

def interruptible_sleep(total_seconds, chunk=0.5):
    """
    Sleep in small chunks so Ctrl+C (SIGINT) can be handled quickly.
    Respects the global STOP_REQUESTED flag.
    """
    global STOP_REQUESTED
    elapsed = 0.0
    while elapsed < total_seconds and not STOP_REQUESTED:
        time.sleep(chunk)
        elapsed += chunk
def detect_bos(df, is_bullish=True, window=3):
    """
    Detect Break of Structure (BOS) on current timeframe.
    
    Bullish BOS: Recent swing high broken to upside
    Bearish BOS: Recent swing low broken to downside
    
    Returns: "bullish" | "bearish" | False
    """
    try:
        if df is None or len(df) < window + 5:
            return False
        
        highs = df['high'].values
        lows = df['low'].values
        
        if is_bullish:
            # Bullish BOS: Price breaks above recent swing high
            recent_high = np.max(highs[-window-5:-1])
            if highs[-1] > recent_high:
                return "bullish"
        else:
            # Bearish BOS: Price breaks below recent swing low
            recent_low = np.min(lows[-window-5:-1])
            if lows[-1] < recent_low:
                return "bearish"
        
        return False
    except Exception:
        return False


def detect_liquidity_sweep(df, lookback=10, types=("swing", "equal")):
    """
    Detect Liquidity Sweeps (SSL/BSL).
    
    SSL (Sell Side Liquidity): Recent swing highs swept
    BSL (Buy Side Liquidity): Recent swing lows swept
    
    Returns: dict with 'high_sweep' (True/False) and 'low_sweep' (True/False)
    """
    try:
        if df is None or len(df) < lookback + 5:
            return {"high_sweep": False, "low_sweep": False}
        
        highs = df['high'].values
        lows = df['low'].values
        
        # Find recent swing high and low
        recent_swing_high = np.max(highs[-lookback:-1])
        recent_swing_low = np.min(lows[-lookback:-1])
        
        # Detect sweep (recent extreme exceeded)
        high_sweep = highs[-1] > recent_swing_high
        low_sweep = lows[-1] < recent_swing_low
        
        return {
            "high_sweep": high_sweep,
            "low_sweep": low_sweep,
            "swing_high": recent_swing_high,
            "swing_low": recent_swing_low,
            "current_high": highs[-1],
            "current_low": lows[-1]
        }
    except Exception:
        return {"high_sweep": False, "low_sweep": False}


def detect_fvg(df, htf_bias=None, zone_low=None, zone_high=None):
    """
    Detect Fair Value Gap (FVG) / Imbalance.
    
    Bullish FVG: Gap up (prev_high < curr_low)
    Bearish FVG: Gap down (prev_low > curr_high)
    
    Returns: dict with 'type' (bullish/bearish), 'level', 'confidence' or None
    """
    try:
        if df is None or len(df) < 3:
            return None
        
        highs = df['high'].values
        lows = df['low'].values
        closes = df['close'].values
        
        # Look at last 3 candles
        prev_high = highs[-3]
        prev_low = lows[-3]
        curr_high = highs[-1]
        curr_low = lows[-1]
        
        # Bullish FVG: Gap up
        if prev_high < curr_low:
            confidence = min(0.95, 0.6 + (curr_low - prev_high) / (closes[-1] + 1e-10) * 0.3)
            return {
                "type": "bullish",
                "level": (prev_high + curr_low) / 2,
                "zone_low": prev_high,
                "zone_high": curr_low,
                "confidence": confidence
            }
        
        # Bearish FVG: Gap down
        elif prev_low > curr_high:
            confidence = min(0.95, 0.6 + (prev_low - curr_high) / (closes[-1] + 1e-10) * 0.3)
            return {
                "type": "bearish",
                "level": (prev_low + curr_high) / 2,
                "zone_low": curr_high,
                "zone_high": prev_low,
                "confidence": confidence
            }
        
        return None
    except Exception:
        return None


def detect_displacement(df, ema_period=20, atr_mult=1.5):
    """
    Detect Displacement (price moved sharply from EMA).
    Entry confirmation: Price bounces back to EMA after displacement.
    
    Returns: dict with 'displaced' (True/False), 'direction', 'distance_atr'
    """
    try:
        if df is None or len(df) < ema_period + 5:
            return {"displaced": False, "direction": None, "distance_atr": 0}
        
        closes = df['close'].values
        ema = df['ema20'].values if 'ema20' in df.columns else pd.Series(closes).ewm(span=ema_period).mean().values
        atr = df['atr'].values if 'atr' in df.columns else pd.Series(closes).rolling(14).std().mean()
        
        current_price = closes[-1]
        current_ema = ema[-1]
        distance = abs(current_price - current_ema) / (atr + 1e-10)
        
        # Displacement when price >1.5 ATR from EMA
        if distance > atr_mult:
            if current_price > current_ema:
                return {"displaced": True, "direction": "above", "distance_atr": distance}
            else:
                return {"displaced": True, "direction": "below", "distance_atr": distance}
        
        return {"displaced": False, "direction": None, "distance_atr": distance}
    except Exception:
        return {"displaced": False, "direction": None, "distance_atr": 0}


