def is_perfect_setup(symbol, entry_signal, confidence, htf_bias_dir, df, smc_ict, 
                     entry_price, sl_price, tp_price, spread=0.0, atr_value=None):
    """
    ═══════════════════════════════════════════════════════════════════════════════
    🔥 NO-TRADE MINDSET: Reject 80-90% of setups
    ═══════════════════════════════════════════════════════════════════════════════
    
    Professional traders skip MOST market conditions.
    This function enforces:
    ✅ Only PERFECT setups pass
    
    Perfect setup = ALL of:
    1. Gates 1-4 pass (HTF, BOS, POI, Risk)
    2. Session is London or NY
    3. SL distance is within MIN-MAX ATR bounds
    4. RR ratio >= 2.0 (not just 1.5)
    5. No news within 15 mins
    6. Spread is reasonable
    
    Returns: (is_perfect: bool, reason: str, setup_quality: float)
    """
    
    reasons = []
    checks_passed = 0
    checks_total = 7
    
    try:
        # Check 1: 4-gate validation
        gates_passed, gate_results, gate_reason = validate_entry_hierarchical_4gate(
            symbol, entry_signal, confidence, htf_bias_dir, df, smc_ict, spread, atr_value
        )
        if not gates_passed:
            return False, f"❌ GATES FAILED: {gate_reason}", 0.0
        checks_passed += 1
        reasons.append("✅ All 4 gates passed")
        
        # Check 2: Session check (strict)
        try:
            now_utc = datetime.now(timezone.utc)
            utc_hour = now_utc.hour
            london_session = 8 <= utc_hour < 12
            ny_session = 16 <= utc_hour < 21
            
            if not (london_session or ny_session):
                reasons.append(f"❌ Session: {utc_hour}:00 UTC - only London (8-12) or NY (16-21)")
                # Not perfect, but log where we are
            else:
                checks_passed += 1
                session_name = "London" if london_session else "NY"
                reasons.append(f"✅ Session: {session_name} open")
        except Exception:
            reasons.append("⚠️  Session check failed")
        
        # Check 3: SL distance MIN/MAX validation
        if atr_value is None or atr_value <= 0:
            try:
                atr_value = calculate_atr(df, 14)
            except Exception:
                atr_value = 0.0001
        
        sl_valid, sl_reason = validate_sl_distance(symbol, entry_price, sl_price, atr_value)
        if not sl_valid:
            reasons.append(f"❌ {sl_reason}")
        else:
            checks_passed += 1
            reasons.append(f"✅ {sl_reason}")
        
        # Check 4: RR ratio >= 2.0 (strict, not 1.5)
        if tp_price is not None and sl_price is not None:
            rr = abs(tp_price - entry_price) / abs(entry_price - sl_price) if abs(entry_price - sl_price) > 0 else 0
            if rr < 2.0:
                reasons.append(f"❌ RR {rr:.2f}:1 < 2.0:1 (strict requirement for perfect setup)")
            else:
                checks_passed += 1
                reasons.append(f"✅ RR {rr:.2f}:1 >= 2.0:1")
        else:
            reasons.append("⚠️  RR not yet calculated")
        
        # Check 5: Spread check
        if spread <= 0:
            checks_passed += 1
            reasons.append("✅ Spread OK")
        else:
            if symbol.upper().startswith("XAU"):
                max_spread = 0.50
            elif "JPY" in symbol.upper():
                max_spread = 0.08
            else:
                max_spread = 0.0008
            
            if spread > max_spread:
                reasons.append(f"❌ Spread {spread:.5f} > {max_spread} max")
            else:
                checks_passed += 1
                reasons.append(f"✅ Spread {spread:.5f} OK")
        
        # Check 6: Confidence >= 0.80
        if confidence < 0.80:
            reasons.append(f"❌ Confidence {confidence:.0%} < 80%")
        else:
            checks_passed += 1
            reasons.append(f"✅ Confidence {confidence:.0%}")
        
        # Check 7: ML and HTF aligned (already checked in Gate 1, but reinforce)
        # If we got here, Gate 1 passed, so HTF is aligned
        checks_passed += 1
        reasons.append(f"✅ HTF {htf_bias_dir.upper()} aligned with signal")
        
        # Calculate quality score: (checks_passed / checks_total) * 100
        setup_quality = (checks_passed / checks_total) * 100
        
        # PERFECT = all or almost all checks pass
        is_perfect = checks_passed >= 6  # at least 6 of 7
        
        reason_text = " | ".join(reasons)
        
        if is_perfect:
            return True, f"✅ PERFECT SETUP ({checks_passed}/7): {reason_text}", setup_quality
        else:
            return False, f"❌ Not perfect ({checks_passed}/7): {reason_text}", setup_quality
        
    except Exception as e:
        return False, f"Setup validation error: {str(e)}", 0.0


def validate_smc_entry_legacy(df, ema_bias, signal_direction, confidence=0.7):
    """
    UNIFIED SMC ENTRY RULE (from video logic + your bot).
    
    Entry = EMA bias + BOS + liquidity sweep + FVG + displacement
    
    Confidence-based threshold:
    - confidence >= 0.85: threshold = 2.0 (relax SMC requirements for high-confidence signals)
    - confidence >= 0.75: threshold = 2.5
    - confidence < 0.75: threshold = 3.5 (strict SMC requirements)
    
    Returns: (entry_approved: bool, reasons: list, score: float)
    """
    reasons = []
    score = 0.0
    
    if df is None or len(df) < 50:
        return False, ["Insufficient data"], 0.0
    
    # Dynamic threshold based on ML confidence
    if confidence >= 0.85:
        threshold = 2.0
        threshold_reason = "High ML confidence (≥0.85) → relaxed SMC threshold"
    elif confidence >= 0.75:
        threshold = 2.5
        threshold_reason = "Good ML confidence (≥0.75) → moderate SMC threshold"
    else:
        threshold = 3.5
        threshold_reason = "Standard ML confidence → strict SMC threshold"
    
    reasons.append(f"ℹ️ {threshold_reason}")
    
    # 1. EMA BIAS CHECK (HTF filter) ✓
    if ema_bias == "bullish" and signal_direction == "buy":
        score += 2.0
        reasons.append("✅ EMA bias bullish + buy signal aligned")
    elif ema_bias == "bearish" and signal_direction == "sell":
        score += 2.0
        reasons.append("✅ EMA bias bearish + sell signal aligned")
    elif ema_bias == "neutral":
        reasons.append("⚠️ EMA bias neutral (requires strong confluence)")
    else:
        reasons.append("❌ EMA bias conflicts with signal")
        return False, reasons, 0.0
    
    # 2. BOS DETECTION ✓
    bos_result = detect_bos(df, is_bullish=(signal_direction == "buy"))
    if bos_result:
        score += 1.5
        reasons.append(f"✅ BOS detected: {bos_result}")
    else:
        reasons.append("⚠️ No BOS detected (looser entry)")
    
    # 3. LIQUIDITY SWEEP ✓
    sweep = detect_liquidity_sweep(df, lookback=10)
    if signal_direction == "buy" and sweep.get("low_sweep"):
        score += 1.5
        reasons.append("✅ BSL (buy-side liquidity) swept - bullish entry")
    elif signal_direction == "sell" and sweep.get("high_sweep"):
        score += 1.5
        reasons.append("✅ SSL (sell-side liquidity) swept - bearish entry")
    else:
        reasons.append("⚠️ No liquidity sweep (but not disqualifying)")
    
    # 4. FVG DETECTION ✓
    fvg = detect_fvg(df)
    if fvg:
        if signal_direction == "buy" and fvg["type"] == "bullish":
            score += 1.5
            reasons.append(f"✅ Bullish FVG at {fvg['level']:.5f}")
        elif signal_direction == "sell" and fvg["type"] == "bearish":
            score += 1.5
            reasons.append(f"✅ Bearish FVG at {fvg['level']:.5f}")
        else:
            reasons.append("ℹ️ FVG detected but opposite direction")
    else:
        reasons.append("⚠️ No FVG (displacement may be present)")
    
    # 5. DISPLACEMENT CONFIRMATION ✓
    disp = detect_displacement(df)
    if disp["displaced"]:
        if signal_direction == "buy" and disp["direction"] == "above":
            score += 1.0
            reasons.append(f"✅ Bullish displacement {disp['distance_atr']:.2f}x ATR")
        elif signal_direction == "sell" and disp["direction"] == "below":
            score += 1.0
            reasons.append(f"✅ Bearish displacement {disp['distance_atr']:.2f}x ATR")
    
    # FINAL DECISION
    # Minimum score with high confidence: 2.0 (HTF bias 2.0 only)
    # Minimum score with good confidence: 2.5 (HTF bias 2.0 + partial confirmation)
    # Minimum score with standard: 3.5 (HTF bias 2.0 + BOS 1.5)
    
    entry_approved = score >= threshold
    
    reasons.append(f"\n📊 SMC Entry Score: {score:.1f}/7.5 (threshold: {threshold:.1f})")
    
    return entry_approved, reasons, score


# --- SMC/ICT Feature Extraction ---
def calculate_smc_ict_features(df, symbol=None, get_price_data_func=None):
    """
    ADVANCED SMC/ICT feature extraction using improved detectors.
    Uses new robust BOS, CHOCH, Liquidity Sweep, and FVG detection.
    Returns dict with CHOCH, BOS, BSL, SSL, Inducement, OB, POI, LQ Sweep.
    """
    features = {
        "CHOCH": False,
        "BOS": False,
        "BSL": None,
        "SSL": None,
        "Inducement": False,
        "OB": None,
        "POI": None,
        "LQ Sweep": False,
        "HTF_BOS": None,
        "HTF_LQ_Sweep": False,
        "HTF_BOS_Direction": None,
        "FVG_Detected": False,
        "FVG_Quality": "none",  # none, weak, moderate, strong
    }
    if df is None or len(df) < 50:
        return features

    # === Use ADVANCED detectors ONLY ===
    
    # 1) **UNIFIED** BOS Detection - Uses detect_advanced_m15_bos (STRICT)
    try:
        bos_detected, bos_direction, bos_strength, bos_reason = validate_smc_entry(df, None, None)
        if bos_detected:
            features["BOS"] = bos_direction
        else:
            features["BOS"] = False
    except Exception:
        features["BOS"] = False

    # 2) ADVANCED CHOCH Detection (SIBI/BISI)
    try:
        choch_result = detect_sibi_bisi(df, direction=None, atr_mult=1.5, use_std=True, window=10)
        features["CHOCH"] = bool(choch_result)
    except Exception:
        features["CHOCH"] = False

    # 3) ADVANCED Liquidity Sweep Detection (volume + wick validation)
    try:
        lq_sweep = advanced_liquidity_sweep(df, direction=None, lookback=20, volume_mult=1.2, wick_threshold=0.4)
        features["LQ Sweep"] = bool(lq_sweep)
    except Exception:
        features["LQ Sweep"] = False

    # 4) ADVANCED FVG Detection (6-step validation: displacement + imbalance + structure + momentum + HTF + confidence)
    try:
        fvg_result = detect_fvg(df, htf_bias=None, zone_low=None, zone_high=None)
        if fvg_result:
            features["FVG_Detected"] = True
            confidence = fvg_result.get('confidence', 0.5)
            if confidence >= 0.85:
                features["FVG_Quality"] = "strong"
            elif confidence >= 0.70:
                features["FVG_Quality"] = "moderate"
            elif confidence >= 0.60:
                features["FVG_Quality"] = "weak"
        else:
            features["FVG_Detected"] = False
    except Exception:
        features["FVG_Detected"] = False

    # 5) BSL/SSL: Buy/Sell Side Liquidity (Swing Extremes)
    try:
        highs = df['high']
        lows = df['low']
        recent_lows = lows.iloc[-25:-1]
        recent_highs = highs.iloc[-25:-1]
        
        if lows.iloc[-1] < recent_lows.min():
            features["BSL"] = lows.iloc[-1]
        if highs.iloc[-1] > recent_highs.max():
            features["SSL"] = highs.iloc[-1]
    except Exception:
        pass

    # 6) DISPLACEMENT: Institutional strength candle (body > 60% + ATR > 1.2x)
    try:
        is_displacement = is_displacement_candle(df)
        features["Displacement"] = is_displacement
    except Exception:
        features["Displacement"] = False

    # 7) ORDER BLOCK Detection (Advanced: OB + confluence with FVG)
    try:
        ob_zone = detect_breaker_block_fvg_confluence(df)
        if ob_zone:
            features["OB"] = ob_zone
    except Exception:
        features["OB"] = None

    # 8) POI (Point of Interest): Entry Zone
    try:
        poi = calculate_entry_zone(df)
        if poi:
            features["POI"] = poi
    except Exception:
        features["POI"] = None

    return features


def analyze_fvg_confluence(context):

    features["POI"] = features["OB"]

    # --- LQ Sweep: Only allow if HTF LQ Sweep or LTF LQ Sweep ---
    ltf_lq_sweep = False
    if features["BSL"] and closes.iloc[-1] > opens.iloc[-1]:
        ltf_lq_sweep = True
    if features["SSL"] and closes.iloc[-1] < opens.iloc[-1]:
        ltf_lq_sweep = True

    if htf_lq_sweep or ltf_lq_sweep:
        features["LQ Sweep"] = True

    return features

