# --- TELEGRAM SIGNAL UTILITY ---
import requests

TELEGRAM_BOT_TOKEN = (getattr(config, 'TELEGRAM_BOT_TOKEN', None) if config is not None else None)
TELEGRAM_CHAT_ID = (getattr(config, 'TELEGRAM_CHAT_ID', None) if config is not None else None)

def send_telegram_signal(message, symbol=None):
    """
    Send a message to your Telegram chat using the bot.
    Enforces per-symbol cooldown if symbol is provided.
    """
    now = datetime.utcnow()
    if symbol:
        last_time = last_signal_time.get(symbol)
        if last_time and (now - last_time) < timedelta(minutes=SIGNAL_COOLDOWN_MINUTES):
            print(f"[TELEGRAM] Signal for {symbol} skipped due to cooldown.")
            return
        last_signal_time[symbol] = now

    if not TELEGRAM_BOT_TOKEN or not TELEGRAM_CHAT_ID:
        print("[TELEGRAM] Bot token or chat id not configured; skipping telegram signal.")
        return
    url = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/sendMessage"
    payload = {
        "chat_id": TELEGRAM_CHAT_ID,
        "text": message,
        "parse_mode": "HTML"
    }
    try:
        response = requests.post(url, data=payload)
        if response.status_code == 200:
            print("[TELEGRAM] Signal sent successfully.")
        else:
            print(f"[TELEGRAM ERROR] {response.status_code}: {response.text}")
    except Exception as e:
        print(f"[TELEGRAM ERROR] {e}")

