def ensemble_predict(features, model_list):
    """
    Combine predictions from multiple models using weighted average or majority vote.
    Returns (signal, confidence)
    """
    preds = []
    confs = []

    for model in model_list:
        try:
            # Use model's feature order if available
            if hasattr(model, "feature_names_in_"):
                import numpy as np
                fv = np.array([[features.get(k, 0) for k in model.feature_names_in_]])
                pred = model.predict(fv)
                if hasattr(model, "predict_proba"):
                    proba = model.predict_proba(fv)[0]
                    pred_idx = pred[0] if hasattr(pred, "__getitem__") else pred
                    # If label is string, map to index
                    if isinstance(pred_idx, str):
                        label_map = getattr(model, "label_map", {"hold": 0, "buy": 1, "sell": 2})
                        pred_idx = label_map.get(pred_idx, 0)
                    conf = proba[int(pred_idx)] if int(pred_idx) < len(proba) else max(proba)
                    signal = getattr(model, "label_map", {0: "hold", 1: "buy", 2: "sell"}).get(pred[0], pred[0])
                else:
                    signal, conf = pred[0], 1.0
            else:
                # Fallback: try generic predict
                pred = model.predict(features)
                # If pred is tuple (signal, confidence)
                if isinstance(pred, tuple) and len(pred) == 2:
                    signal, conf = pred
                else:
                    signal, conf = pred, 1.0
            preds.append(signal)
            confs.append(conf)
        except Exception:
            continue

    # Voting: majority for signal, mean for confidence
    if preds:
        from collections import Counter
        signal = Counter(preds).most_common(1)[0][0]
        confidence = sum(confs) / len(confs) if confs else 0.5
        return signal, confidence
    else:
        return "hold", 0.0

def update_online_model(features, outcome):
    """
    Update the online learning model with the latest trade outcome.
    outcome: 1 for win, 0 for loss
    """
    if model_online is not None:
        # Assume binary classification: "buy"=1, "sell"=0, "hold"=0
        y = int(outcome > 0)
        model_online.learn_one(features, y)

# Thread-safe model hot-swap using a lock
def get_model():
    global model
    global model_lock
    with model_lock:
        return model

def set_model(new_model):
    global model
    global model_lock
    with model_lock:
        model = new_model



