# --- HTF Trend Filter Utilities ---
def get_htf_trend(symbol, time_frame="H1", bars=250):
    """
    Returns 'bull', 'bear', or 'neutral' for the higher timeframe trend.
    Uses swing high/low detection (aligned with detect_trend()) as PRIMARY method.
    Falls back to EMA50/EMA200 if swing detection is inconclusive.
    """
    df_htf = get_price_data(symbol, timeframe=time_frame, bars=bars)
    if df_htf is None or len(df_htf) < 10:
        return "neutral"
    
    # PRIMARY: Swing high/low detection (multi-bar lookback for robustness)
    highs = df_htf['high'].values
    lows = df_htf['low'].values
    
    # Look back 5 bars to detect trend direction
    if len(df_htf) >= 5:
        # Check last 5 bars: if all recent lows < previous lows = downtrend
        # Check last 5 bars: if all recent highs > previous highs = uptrend
        recent_lows = lows[-5:]
        recent_highs = highs[-5:]
        
        # Count how many times price made higher highs and higher lows (bullish)
        bull_count = sum(1 for i in range(1, len(recent_highs)) if recent_highs[i] > recent_highs[i-1] and recent_lows[i] > recent_lows[i-1])
        # Count how many times price made lower highs and lower lows (bearish)
        bear_count = sum(1 for i in range(1, len(recent_highs)) if recent_highs[i] < recent_highs[i-1] and recent_lows[i] < recent_lows[i-1])
        
        if bear_count >= 2:  # At least 2 instances of lower highs/lows = strong downtrend
            return "bear"
        elif bull_count >= 2:  # At least 2 instances of higher highs/lows = strong uptrend
            return "bull"
    
    # FALLBACK: Use EMA50/EMA200 if swing detection is unclear
    if len(df_htf) >= 200:
        ema50 = df_htf['close'].ewm(span=50, adjust=False).mean().iloc[-1]
        ema200 = df_htf['close'].ewm(span=200, adjust=False).mean().iloc[-1]
        if ema50 > ema200:
            return "bull"
        elif ema50 < ema200:
            return "bear"
    
    # FALLBACK 2: Use EMA20/EMA50 if not enough bars for EMA200
    if len(df_htf) >= 50:
        ema20 = df_htf['close'].ewm(span=20, adjust=False).mean().iloc[-1]
        ema50 = df_htf['close'].ewm(span=50, adjust=False).mean().iloc[-1]
        if ema20 > ema50:
            return "bull"
        elif ema20 < ema50:
            return "bear"
    
    return "neutral"

def htf_trend_allows_trade(signal, htf_trend, confidence=None, reversal_threshold=0.85, range_threshold=0.65):
    """
    Allow 'buy' if HTF is bull, 'sell' if HTF is bear.
    Allow reversal trades only if ML confidence is very high.
    Allow both in range/neutral if confidence is decent.
    """
    if htf_trend == "bull":
        if signal == "buy":
            return True
        if signal == "sell" and confidence is not None and confidence >= reversal_threshold:
            return True
    elif htf_trend == "bear":
        if signal == "sell":
            return True
        if signal == "buy" and confidence is not None and confidence >= reversal_threshold:
            return True
    else:  # range/neutral
        if confidence is not None and confidence >= range_threshold:
            return True
    return False

# --- Advanced Support & Resistance Detection ---

def detect_sr_levels(df, window=100, tolerance=0.001, min_touches=2):
    """
    Detects key support and resistance levels using swing highs/lows and clustering.
    Returns a dict: {'support': [levels], 'resistance': [levels]}
    """
    highs = df['high'].rolling(window=5, center=True).max()
    lows = df['low'].rolling(window=5, center=True).min()
    swing_highs = df['high'][(df['high'] == highs)]
    swing_lows = df['low'][(df['low'] == lows)]

    # Cluster levels that are close together
    def cluster_levels(levels, tol):
        levels = sorted(set(levels.dropna()))
        clusters = []
        current = []
        for lvl in levels:
            if not current or abs(lvl - current[-1]) <= tol:
                current.append(lvl)
            else:
                clusters.append(np.mean(current))
                current = [lvl]
        if current:
            clusters.append(np.mean(current))
        return clusters

    resistance_levels = cluster_levels(swing_highs, tolerance)
    support_levels = cluster_levels(swing_lows, tolerance)

    # Filter levels by number of touches
    def count_touches(level, prices, tol):
        return np.sum(np.abs(prices - level) < tol)

    resistance_levels = [lvl for lvl in resistance_levels if count_touches(lvl, df['high'], tolerance) >= min_touches]
    support_levels = [lvl for lvl in support_levels if count_touches(lvl, df['low'], tolerance) >= min_touches]

    return {'support': support_levels, 'resistance': resistance_levels}

