# ====================================================================
# 🎯 ADVANCED SNIPER ENTRY VALIDATOR (REMOVED DUPLICATE WEAK FUNCTIONS)
# ====================================================================
def validate_sniper_entry(symbol, direction, price, confidence, features, spread, atr, fib_level=None):
    """
    🎯 INSTITUTIONAL-GRADE SNIPER VALIDATOR
    
    Determines if an entry qualifies as a TRUE sniper entry (precision shot).
    
    Criteria:
    - Confidence >= 0.75+ (already filtered by main bot)
    - Spread at optimal levels (tight)
    - ATR in normal range (not news spike)
    - At/Near key level (Fib, S/R, POI, Order Block)
    - Multi-timeframe confluence (HTF trend aligned)
    - Structure confirmation (BOS, CHOCH, or Liquidity Sweep)
    - Entry score >= 8.0 from combined filters
    
    Returns: (is_sniper: bool, sniper_type: str, reason: str, score: float)
    """
    sniper_type = "NORMAL"  # Default
    reasons = []
    sniper_score = 0.0
    
    try:
        # Check 1: Confidence level (high bar for sniper)
        if confidence >= 0.85:
            sniper_score += 1.5
            reasons.append("Elite confidence (0.85+)")
        elif confidence >= 0.80:
            sniper_score += 1.0
            reasons.append("High confidence (0.80+)")
        elif confidence >= 0.75:
            sniper_score += 0.5
            reasons.append("Good confidence (0.75+)")
        else:
            return False, "NORMAL", "Confidence too low", 0.0
        
        # Check 2: Spread (must be tight for sniper)
        max_spread = get_spread_threshold(symbol) if 'get_spread_threshold' in globals() else 30
        spread_ratio = spread / max_spread
        if spread_ratio < 0.3:  # Top 30% tightest spreads
            sniper_score += 1.5
            reasons.append("Optimal spread")
        elif spread_ratio < 0.6:  # Top 60%
            sniper_score += 1.0
            reasons.append("Good spread")
        elif spread_ratio < 1.0:
            sniper_score += 0.5
            reasons.append("Acceptable spread")
        else:
            return False, "NORMAL", "Spread too wide for sniper", sniper_score
        
        # Check 3: ATR volatility (avoid news spikes)
        atr_quantile = features.get('atr_quantile', 0.5)  # 0-1 scale
        if atr_quantile < 0.75:  # Below 75th percentile = stable conditions
            sniper_score += 1.0
            reasons.append("Low volatility")
        elif atr_quantile < 0.90:
            sniper_score += 0.5
            reasons.append("Normal volatility")
        else:
            reasons.append("⚠️ High volatility (news?)")
        
        # Check 4: Key level proximity (Fibonacci, S/R, POI)
        at_key_level = False
        level_reason = ""
        
        if fib_level is not None:
            level_distance = abs(price - fib_level)
            tolerance = atr * 0.5  # Within half an ATR = at level
            if level_distance <= tolerance:
                sniper_score += 2.0
                at_key_level = True
                level_reason = f"At Fib level (dist: {level_distance*1e4:.0f}pts)"
                reasons.append(f"🎯 {level_reason}")
        
        if not at_key_level and 'sr_levels' in features:
            sr = features.get('sr_levels', {})
            support_levels = sr.get('support', [])
            resistance_levels = sr.get('resistance', [])
            
            # Check if near support (for buy) or resistance (for sell)
            if direction == "buy":
                near_level = any(abs(price - s) < atr * 0.5 for s in support_levels)
            else:
                near_level = any(abs(price - r) < atr * 0.5 for r in resistance_levels)
            
            if near_level:
                sniper_score += 1.5
                at_key_level = True
                level_reason = "At S/R level"
                reasons.append(f"🎯 {level_reason}")
        
        if not at_key_level and fib_level is None:
            # Check POI/OB proximity
            poi = features.get('poi', None)
            if poi:
                poi_low = float(poi.get('low', -1e9))
                poi_high = float(poi.get('high', 1e9))
                if poi_low <= price <= poi_high:
                    sniper_score += 1.5
                    reasons.append("🎯 At POI/Order Block")
        
        # Check 5: Structure confirmation
        has_structure = False
        
        bos = features.get('bos', None)
        if bos and ((direction == "buy" and bos == "bullish") or (direction == "sell" and bos == "bearish")):
            sniper_score += 1.5
            has_structure = True
            reasons.append("✓ BOS confirmed")
        
        choch = features.get('choch', None)
        if choch and ((direction == "buy" and choch == "bullish") or (direction == "sell" and choch == "bearish")):
            sniper_score += 1.5
            has_structure = True
            reasons.append("✓ CHOCH confirmed")
        
        lq_sweep = features.get('liquidity_sweep', False)
        if lq_sweep:
            sniper_score += 1.5
            has_structure = True
            reasons.append("✓ Liquidity Sweep")
        
        # Check 6: Multi-timeframe alignment
        htf_trend = features.get('htf_trend', None)
        if htf_trend:
            if (direction == "buy" and htf_trend in ("bullish", "up")) or \
               (direction == "sell" and htf_trend in ("bearish", "down")):
                sniper_score += 1.0
                reasons.append("✓ HTF aligned")
        
        # ====================================================================
        # SNIPER CLASSIFICATION
        # ====================================================================
        is_sniper = sniper_score >= 7.0  # High bar for "sniper" classification
        
        if is_sniper and at_key_level and has_structure and confidence >= 0.80:
            sniper_type = "SNIPER_ELITE"  # Best of the best
            sniper_score = min(sniper_score, 10.0)  # Cap at 10
        elif is_sniper:
            sniper_type = "SNIPER"  # Precision entry
        else:
            sniper_type = "NORMAL"
        
        final_reason = " | ".join(reasons)
        return is_sniper, sniper_type, final_reason, sniper_score
        
    except Exception as e:
        print(f"[SNIPER VALIDATOR ERROR] {symbol}: {e}")
        return False, "NORMAL", f"Validation error: {e}", 0.0
    return True, ""

def meta_filter(symbol, confidence, spread, regime, session):
    """
    Unified filter: blend ML, session, regime, and spread before entry.
    """
    CONFIDENCE_THRESHOLD = 0.75  # or use your config value
    if confidence < CONFIDENCE_THRESHOLD:
        return False, "Confidence below threshold"
    if spread > get_spread_threshold(symbol):
        return False, "Spread too high"
    if regime == "unknown":
        return False, "Regime unknown"
    if session not in ("London", "New York", "Asia"):
        return False, "Session not tradable"
    if check_and_pause_on_loss():
        return False, "Paused due to loss"
    return True, ""

