def has_opposite_position(symbol, entry_signal):
    """
    Returns True if there is an open position on the symbol in the opposite direction.
    """
    import MetaTrader5 as mt5
    positions = mt5.positions_get(symbol=symbol)
    if not positions:
        return False
    for pos in positions:
        # mt5.ORDER_TYPE_BUY = 0, mt5.ORDER_TYPE_SELL = 1
        if entry_signal == "buy" and pos.type == mt5.ORDER_TYPE_SELL:
            return True
        if entry_signal == "sell" and pos.type == mt5.ORDER_TYPE_BUY:
            return True
    return False

def can_open_trade(lot_size, sl_pips, symbol, entry_signal=None):
    """
    Limit trades per instrument per X minutes and concurrent trades per symbol.
    Prevents opening opposite entries on the same symbol at the same time.
    """
    import MetaTrader5 as mt5
    # Limit: 1 trade per symbol, and max 1 trade per 10 minutes
    positions = mt5.positions_get(symbol=symbol)
    if positions and len(positions) > 0:
        return False
    # Prevent opposite entries
    if entry_signal is not None and has_opposite_position(symbol, entry_signal):
        return False
    # You can add a time-based throttle here if you track last trade time
    return True

