def estimate_margin_buffer(symbol):
    """
    Estimate extra margin buffer for safety.
    """
    import MetaTrader5 as mt5
    symbol_info = mt5.symbol_info(symbol)
    if symbol_info is not None:
        return symbol_info.margin_initial * 0.1
    return 0.0001

def get_atr_bounds(symbol):
    """
    Return min/max ATR for volatility regime filter.
    """
    # Use historical ATR percentiles for the symbol
    df = get_price_data(symbol, timeframe="H1", bars=500)
    if df is None or "atr" not in df.columns:
        return (0.0005, 0.005)
    atrs = df["atr"].dropna()
    if len(atrs) < 50:
        return (0.0005, 0.005)
    min_atr = atrs.quantile(0.10)
    max_atr = atrs.quantile(0.90)
    return (min_atr, max_atr)

