def position_sizing_ok(symbol, features):
    """
    Check if position sizing is within risk limits.
    """
    import MetaTrader5 as mt5
    account_info = mt5.account_info()
    if account_info is None or account_info.balance <= 0:
        return False
    # Example: risk per trade <= 2% of balance
    risk_per_trade = features.get("risk_per_trade", 0.01)
    lot_size = features.get("lot_size", 0.01)
    symbol_info = mt5.symbol_info(symbol)
    if symbol_info is None:
        return False
    # Estimate pip value and SL distance
    pip_size = 0.01 if "JPY" in symbol else 0.0001
    sl = features.get("sl", None)
    entry = features.get("entry", None)
    if sl is not None and entry is not None:
        sl_pips = abs(entry - sl) / pip_size
    else:
        sl_pips = 20
    tick_value = symbol_info.trade_tick_value
    risk = lot_size * sl_pips * tick_value
    if risk > account_info.balance * risk_per_trade:
        return False
    return True

def get_max_mid_deviation(symbol):
    """
    Return max allowed deviation from mid-price.
    """
    if "XAU" in symbol:
        return 0.5
    elif "JPY" in symbol:
        return 0.05
    else:
        return 0.0005

def backtest_symbol(symbol, model, custom_should_trade=None, from_year=2023, use_htf_trend=True):
    # --- Skip GBPUSD and EURUSD in backtests as well ---

    try:
        df = get_backtest_data(symbol, bars=None, from_year=from_year)
        # Print/log DataFrame info for debugging
        if df is None:
            print(f"[BACKTEST ERROR] No DataFrame returned for {symbol}.")
            return []
        print(f"[BACKTEST DEBUG] {symbol}: DataFrame loaded with {len(df)} rows.")
        if df.empty:
            print(f"[BACKTEST ERROR] DataFrame for {symbol} is empty.")
            return []
        # Optionally, print the first few rows for inspection
        print(df.head())

        trades = []
        open_trade = None
        equity_curve = []
        max_drawdown = 0
        peak = 0

        # --- Recovery mode state for backtest ---
        recovery_mode = {"active": False, "direction": None}

        for i in range(200, len(df)-1):  # start after enough bars for indicators
            window = df.iloc[:i+1]
            features = get_features_fixed(window)
            atr = features["atr"]
            ema50 = features["ema50"]
            ema200 = features["ema200"]
            last_close = window['close' ].iloc[-1]
            spread = window['ask'].iloc[-1] - window['bid'].iloc[-1] if 'ask' in window and 'bid' in window else 0.0001

            # --- HTF Trend Filter ---
            htf_trend = "neutral"
            if use_htf_trend:
                # For 5m chart, use 1H trend; for 1H, use 4H, etc.
                htf_trend = get_htf_trend(symbol, time_frame="H4")

            # --- Robust ML model signal extraction (ENSEMBLE) ---
            ml_signal, confidence = ensemble_predict(features)
            print(f"[BACKTEST DEBUG] {symbol} bar {i}: ML={ml_signal}, conf={confidence:.2f}, HTF={htf_trend}")


            # Only trade if ML gives "buy" or "sell" AND aligns with HTF trend
            if ml_signal not in ("buy", "sell") or not htf_trend_allows_trade(ml_signal, htf_trend):
                equity_curve.append(equity_curve[-1] if equity_curve else 0)
                continue

            signal = ml_signal

            # Use custom should_trade function if provided, otherwise use default
            if custom_should_trade:
                should_enter = custom_should_trade(signal, confidence, features, spread)
            else:
                should_enter, _ = should_trade_advanced(signal, confidence, features, spread, symbol)

            print(f"[BACKTEST DEBUG] {symbol} bar {i}: should_enter={should_enter}")

            if not should_enter:
                equity_curve.append(equity_curve[-1] if equity_curve else 0)
                continue

            # Only one trade at a time for simplicity
            if open_trade is not None:
                # Check if SL or TP hit
                trade = open_trade
                high = window['high'].iloc[-1]
                low = window['low'].iloc[-1]
                trade_closed = False
                # --- Trailing stop and break-even for backtest ---
                if trade['direction'] == 'buy':
                    # Move SL to break-even if price moves in favor
                    if high >= trade['entry'] + 10 * (0.0001 if "JPY" not in symbol else 0.01):
                        trade['sl'] = max(trade['sl'], trade['entry'])
                    # Trail SL by ATR
                    if high >= trade['entry'] + 2 * atr:
                        trade['sl'] = max(trade['sl'], high - 1.0 * atr)
                    if low <= trade['sl']:
                        trade['exit'] = trade['sl']
                        trade['result'] = trade['sl'] - trade['entry']
                        trades.append(trade)
                        update_online_model(features, trade['result'])
                        open_trade = None
                        trade_closed = True
                    elif high >= trade['tp']:
                        trade['exit'] = trade['tp']
                        trade['result'] = trade['tp'] - trade['entry']
                        trades.append(trade)
                        update_online_model(features, trade['result'])
                        open_trade = None
                        trade_closed = True
                else:
                    if low <= trade['entry'] - 10 * (0.0001 if "JPY" not in symbol else 0.01):
                        trade['sl'] = min(trade['sl'], trade['entry'])
                    if low <= trade['entry'] - 2 * atr:
                        trade['sl'] = min(trade['sl'], low + 1.0 * atr)
                    if high >= trade['sl']:
                        trade['exit'] = trade['sl']
                        trade['result'] = trade['entry'] - trade['sl']
                        trades.append(trade)
                        update_online_model(features, trade['result'])
                        open_trade = None
                        trade_closed = True
                    elif low <= trade['tp']:
                        trade['exit'] = trade['tp']
                        trade['result'] = trade['entry'] - trade['tp']
                        trades.append(trade)
                        update_online_model(features, trade['result'])
                        open_trade = None
                        trade_closed = True
                # FIX: Only append to equity_curve if trades is not empty
                if trades:
                    equity_curve.append(equity_curve[-1] + trades[-1]['result'] if equity_curve else trades[-1]['result'])
                else:
                    equity_curve.append(equity_curve[-1] if equity_curve else 0)
                # Drawdown calculation
                peak = max(peak, equity_curve[-1])
                dd = peak - equity_curve[-1]
                max_drawdown = max(max_drawdown, dd)
                # --- Recovery mode update: if last trade was a loss, activate recovery mode ---
                if trade_closed:
                    last_result = trades[-1]['result']
                    last_direction = trades[-1]['direction']
                    if last_result < 0:
                        recovery_mode["active"] = True
                        recovery_mode["direction"] = "sell" if last_direction == "buy" else "buy"
                    else:
                        recovery_mode["active"] = False
                        recovery_mode["direction"] = None
                continue

            # Open new trade
            entry = window['close'].iloc[-1]
            atr = features.get("atr", 0.0)
            # --- Dynamic ATR-based SL/TP per symbol ---
            base = symbol.replace(".m", "").replace(".ecn", "").replace(".pro", "")
            pip_size = 0.1 if "XAU" in base else (0.01 if "JPY" in base else 0.0001)
            # Define multipliers per symbol
            if base == "XAUUSD":
                sl_mult, tp_mult = 1.5, 3.0
            elif base in ["GBPUSD"]:
                sl_mult, tp_mult = 1.2, 2.5
            else:  # EURUSD, AUDUSD, etc.
                sl_mult, tp_mult = 1.0, 2.0
            # Calculate adaptive SL/TP
            sl_dist = atr * sl_mult
            tp_dist = atr * tp_mult
            # Clamp SL/TP to recommended min/max for each symbol
            if base == "XAUUSD":
                sl_dist = min(max(sl_dist, 100 * pip_size), 250 * pip_size)
                tp_dist = min(max(tp_dist, 200 * pip_size), 500 * pip_size)
            elif base == "GBPUSD":
                sl_dist = min(max(sl_dist, 20 * pip_size), 30 * pip_size)
                tp_dist = min(max(tp_dist, 40 * pip_size), 70 * pip_size)
            elif base == "AUDUSD":
                sl_dist = min(max(sl_dist, 15 * pip_size), 25 * pip_size)
                tp_dist = min(max(tp_dist, 30 * pip_size), 50 * pip_size)
            else:  # EURUSD, fallback
                sl_dist = min(max(sl_dist, 15 * pip_size), 25 * pip_size)
                tp_dist = min(max(tp_dist, 30 * pip_size), 50 * pip_size)
            if signal == "buy":
                sl = entry - sl_dist
                tp = entry + tp_dist
            else:
                sl = entry + sl_dist
                tp = entry - tp_dist

            # Check risk-reward
            if not risk_reward_ok(entry, sl, tp):
                equity_curve.append(equity_curve[-1] if equity_curve else 0)
                continue

            open_trade = {
                "entry": entry,
                "sl": sl,
                "tp": tp,
                "direction": signal,
                "open_time": window['time'].iloc[-1]
            }
            equity_curve.append(equity_curve[-1] if equity_curve else 0)

        # Close any open trade at the end
        if open_trade is not None:
            open_trade['exit'] = df['close'].iloc[-1]
            if open_trade['direction'] == 'buy':
                open_trade['result'] = open_trade['exit'] - open_trade['entry']
            else:
                open_trade['result'] = open_trade['entry'] - open_trade['exit']
            trades.append(open_trade)
            equity_curve.append(equity_curve[-1] + open_trade['result'] if equity_curve else open_trade['result'])

        return trades
    except Exception as e:
        print(f"[ERROR] Backtest failed for {symbol}: {e}")
        import traceback
        traceback.print_exc()
        return []

