# --- 1. Expected Value (EV) Calculator per Trade using historical outcomes of similar setups ---

# Store historical trade outcomes for EV calculation
historical_trade_outcomes = {}

def calculate_expected_value(symbol, features, predicted_return, total_cost, window=100):
    """
    Calculate expected value (EV) for a trade using historical outcomes of similar setups.
    Uses rolling window of last N similar trades.
    """
    # Define a "setup signature" (e.g., discretized features)
    setup_key = get_setup_signature(features)
    if symbol not in historical_trade_outcomes:
        historical_trade_outcomes[symbol] = {}
    if setup_key not in historical_trade_outcomes[symbol]:
        historical_trade_outcomes[symbol][setup_key] = deque(maxlen=window)
    # Retrieve similar outcomes
    outcomes = historical_trade_outcomes[symbol][setup_key]
    if len(outcomes) >= 10:
        win_rate = sum(1 for r in outcomes if r > 0) / len(outcomes)
        avg_win = np.mean([r for r in outcomes if r > 0]) if any(r > 0 for r in outcomes) else 0
        avg_loss = np.mean([r for r in outcomes if r <= 0]) if any(r <= 0 for r in outcomes) else 0
        # EV = win_rate * avg_win + (1-win_rate) * avg_loss - total_cost
        ev = win_rate * avg_win + (1 - win_rate) * avg_loss - total_cost
        return ev
    else:
        # Fallback: predicted_return - total_cost
        return predicted_return - total_cost

def record_trade_outcome(symbol, features, result):
    """
    Record the outcome of a trade for EV calculation.
    """
    setup_key = get_setup_signature(features)
    if symbol not in historical_trade_outcomes:
        historical_trade_outcomes[symbol] = {}
    if setup_key not in historical_trade_outcomes[symbol]:
        historical_trade_outcomes[symbol][setup_key] = deque(maxlen=100)
    historical_trade_outcomes[symbol][setup_key].append(result)

def get_setup_signature(features):
    """
    Create a discretized signature of the setup for grouping similar trades.
    Example: round ATR, RSI, and ML confidence to nearest bucket.
    """
    atr = round(features.get("atr", 0) * 1000) // 5  # bucket ATR
    rsi = round(features.get("rsi", 0) // 5)         # bucket RSI
    conf = round(features.get("confidence", 0) * 10) # bucket confidence
    return (atr, rsi, conf)

# --- 2. Bayesian updating of your model’s prior based on recent outcomes ---

bayesian_beliefs = {}

def update_bayesian_belief(symbol, window=50, prior=0.6):
    """
    Bayesian update of belief in model's edge based on recent trade outcomes.
    Returns a value between 0 and 1 (higher = stronger belief).
    """
    if symbol not in bayesian_beliefs:
        bayesian_beliefs[symbol] = deque(maxlen=window)
    outcomes = bayesian_beliefs[symbol]
    # Use 1 for win, 0 for loss
    if len(outcomes) < 5:
        return prior
    alpha = 1 + sum(1 for r in outcomes if r > 0)
    beta = 1 + sum(1 for r in outcomes if r <= 0)
    # Posterior mean of Beta(alpha, beta)
    belief = alpha / (alpha + beta)
    return belief

def record_bayesian_outcome(symbol, result):
    """
    Record the outcome of a trade for Bayesian updating.
    """
    if symbol not in bayesian_beliefs:
        bayesian_beliefs[symbol] = deque(maxlen=50)
    bayesian_beliefs[symbol].append(result)

# --- 3. Reinforcement learning meta-controller that chooses between aggressive vs. conservative rules ---

rl_meta_state = {}

def rl_meta_controller(symbol, window=10):
    """
    RL meta-controller: chooses between aggressive and conservative rule sets based on recent PnL.
    If last N trades net profit > 0, be aggressive, else conservative.
    """
    if symbol not in rl_meta_state:
        rl_meta_state[symbol] = deque(maxlen=window)
    pnl = rl_meta_state[symbol]
    if len(pnl) < 3:
        return "conservative"
    recent_pnl = sum(pnl)
    if recent_pnl > 0:
        return "aggressive"
    return "conservative"

def record_rl_pnl(symbol, result):
    """
    Record PnL for RL meta-controller.
    """
    if symbol not in rl_meta_state:
        rl_meta_state[symbol] = deque(maxlen=10)
    rl_meta_state[symbol].append(result)

# --- 4. Adaptive thresholds: when volatility increases, automatically raise ENTRY_THRESHOLD or widen SLs. ---

def get_adaptive_thresholds(symbol, atr):
    """
    Adapt entry threshold and SL/TP multipliers based on volatility (ATR).
    """
    # Example: If ATR is high, increase thresholds
    base_entry = 0.6
    base_sl = 1.0
    base_tp = 2.0
    # Use historical ATR percentiles for the symbol
    df = get_price_data(symbol, timeframe="H1", bars=500)
    if df is not None and "atr" in df.columns:
        atrs = df["atr"].dropna()
        if len(atrs) >= 50:
            high_vol = atr > atrs.quantile(0.85)
            if high_vol:
                return base_entry + 0.1, base_sl * 1.2, base_tp * 1.2
    return base_entry, base_sl, base_tp

# --- Hook into trade execution to record outcomes for learning ---

def on_trade_closed(symbol, features, result):
    """
    Call this function whenever a trade is closed to update all learning modules.
    """
    record_trade_outcome(symbol, features, result)
    record_bayesian_outcome(symbol, result)
    record_rl_pnl(symbol, result)

