def all_symbols_reached_max_trades(symbols):
    return all(symbol_trade_counts[symbol] >= MAX_TRADES_PER_SYMBOL_PER_RUN for symbol in symbols)





def get_exit_label_for_ml(df, entry_idx, exit_idx, sl, tp, lookahead=10):
    """
    Label for ML exit: 1=good exit (market reversed after exit), 0=bad exit (market kept going).
    Checks if after exit, price would have hit SL if held for 'lookahead' more bars.
    """
    if exit_idx + 1 >= len(df):
        return 0
    future = df.iloc[exit_idx+1:exit_idx+1+lookahead]
    if len(future) == 0:
        return 0
    # If price would have hit SL after exit, label as good exit
    if any((future['low'] <= sl) if tp > sl else (future['high'] >= sl)):
        return 1
    return 0


