def _create_stop_file():
    try:
        stop_path = os.path.join(os.path.dirname(__file__), 'dashboard', 'stop.signal')
        os.makedirs(os.path.dirname(stop_path), exist_ok=True)
        with open(stop_path, 'w') as f:
            f.write('stop requested')
        return True
    except Exception:
        return False


def _clear_stop_file():
    try:
        stop_path = os.path.join(os.path.dirname(__file__), 'dashboard', 'stop.signal')
        if os.path.exists(stop_path):
            os.remove(stop_path)
        return True
    except Exception:
        return False


