                    def get_htf_trend(symbol, time_frame="H1", bars=250):
                        """
                        Returns 'bull', 'bear', or 'neutral' for the higher timeframe trend.
                        Uses EMA50/EMA200 cross on the HTF, with fallback to EMA20/EMA50 if not enough bars.
                        """
                        df_htf = get_price_data(symbol, timeframe=time_frame, bars=bars)
                        if df_htf is None or len(df_htf) < 50:
                            return "neutral"
                        if len(df_htf) >= 200:
                            ema50 = df_htf['close'].ewm(span=50, adjust=False).mean().iloc[-1]
                            ema200 = df_htf['close'].ewm(span=200, adjust=False).mean().iloc[-1]
                            if ema50 > ema200:
                                return "bull"
                            elif ema50 < ema200:
                                return "bear"
                        # Fallback: use EMA20/EMA50 if not enough bars for EMA200
                        if len(df_htf) >= 50:
                            ema20 = df_htf['close'].ewm(span=20, adjust=False).mean().iloc[-1]
                            ema50 = df_htf['close'].ewm(span=50, adjust=False).mean().iloc[-1]
                            if ema20 > ema50:
                                return "bull"
                            elif ema20 < ema50:
                                return "bear"
                        return "neutral"

                    def htf_trend_allows_trade(signal, htf_trend, confidence=None, reversal_threshold=0.85, range_threshold=0.65):
                        """
                        Allow 'buy' if HTF is bull, 'sell' if HTF is bear.
                        Allow reversal trades only if ML confidence is very high.
                        Allow both in range/neutral if confidence is decent.
                        """
                        if htf_trend == "bull":
                            if signal == "buy":
                                return True
                            if signal == "sell" and confidence is not None and confidence >= reversal_threshold:
                                return True
                        elif htf_trend == "bear":
                            if signal == "sell":
                                return True
                            if signal == "buy" and confidence is not None and confidence >= reversal_threshold:
                                return True
                        else:  # range/neutral
                            if confidence is not None and confidence >= range_threshold:
                                return True
                        return False

