                            zone_high = entry_zone.get('high')
                            
                            if zone_low is not None and zone_high is not None:
                                buffer = 0.0001 if "JPY" not in symbol else 0.01
                                
                                # Check if price is IN the zone
                                if zone_low - buffer <= price <= zone_high + buffer:
                                    entry = price
                                    print(f"[FVG ENTRY] Price {price:.5f} IS IN zone {zone_low:.5f}-{zone_high:.5f}")
                                    
                                    # Detect price action confirmation within zone
