    def get_upcoming_news_events(symbol, window_minutes=15):
        """
        Returns a list of dicts: [{'title': str, 'time': datetime}]
        Uses Forex Factory API or similar. Includes retry logic and fallback.
        """
        import pytz
        from datetime import datetime, timedelta
        import json

        # Map symbol to currency
        currency_map = {
            "EURUSD": ["EUR", "USD"],
            "GBPUSD": ["GBP", "USD"],
            "USDJPY": ["USD", "JPY"],
            "XAUUSD": ["USD"],
            "AUDUSD": ["AUD", "USD"],
            "NZDUSD": ["NZD", "USD"],
            "USDCAD": ["USD", "CAD"],
            "USDCHF": ["USD", "CHF"],
        }
        base = symbol.replace(".m", "").replace(".ecn", "").replace(".pro", "")
        currencies = currency_map.get(base, [])
        now = datetime.utcnow().replace(tzinfo=pytz.UTC)
        window_start = now
        window_end = now + timedelta(minutes=window_minutes)
        
        # Try multiple endpoints with fallback
        urls = [
            "https://nfs.faireconomy.media/ff_calendar_thisweek.json",
            "https://api.forexfactory.com/calendar.json",
        ]
        
        for url in urls:
            try:
                resp = requests.get(url, timeout=5)
                
                if resp.status_code != 200:
                    continue
                
                if not resp.text or resp.text.strip() == '':
                    continue
                
                try:
                    events = resp.json()
                except (ValueError, json.JSONDecodeError):
                    continue
                
                if not events or not isinstance(events, list):
                    continue
                    
                result = []
                for event in events:
                    try:
                        date_str = event.get('date', '')
                        time_str = event.get('time', '00:00')
                        event_time = pd.to_datetime(f"{date_str} {time_str}", utc=True, errors='coerce')
                        if event_time is pd.NaT or pd.isna(event_time):
                            continue
                        if event_time >= window_start and event_time <= window_end:
                            currency = event.get('currency', '')
                            impact = event.get('impact', '')
                            if currency in currencies and impact in ("High", "Medium"):
                                result.append({
                                    "title": event.get('event', 'Unknown'),
                                    "time": event_time
                                })
                    except (KeyError, TypeError):
                        continue
                return result
            except (requests.ConnectionError, requests.Timeout):
                continue
            except Exception as e:
                continue
        
        # If all APIs fail, return empty list
        return []

    def get_correlated_symbols(symbol):
        """
        Returns a list of correlated symbols for the given symbol.
        Uses rolling correlation on historical price data.
        """
        # You must have a function get_price_data(symbol, timeframe, bars)
        # We'll use 500 bars of 1H data for correlation
        all_symbols = ["EURUSD", "GBPUSD",   "NZDUSD", "USDCAD", "USDCHF", "XAUUSD"]
        base = symbol.replace(".m", "").replace(".ecn", "").replace(".pro", "")
        df_main = get_price_data(base, timeframe="H1", bars=500)
        if df_main is None or df_main.empty:
            return []
        corrs = {}
        for s in all_symbols:
            if s == base:
                continue
            df_other = get_price_data(s, timeframe="H1", bars=500)
            if df_other is None or df_other.empty:
                continue
            merged = pd.DataFrame({
                "main": df_main['close'].values[-500:],
                "other": df_other['close'].values[-500:]
            })
            corr = merged['main'].corr(merged['other'])
            corrs[s] = abs(corr)
        # Return symbols with correlation > 0.7
        try:
            return [s for s, c in corrs.items() if c > 0.7]
        except Exception as e:
            print(f"[CORR] Error: {e}")
            return []

    def get_total_exposure(symbols):
        """
        Returns total notional exposure for a list of symbols.
        Sums up open positions for those symbols.
        """
        import MetaTrader5 as mt5
        total = 0.0
        positions = mt5.positions_get()
        if positions is None:
            return 0.0
        for pos in positions:
            if pos.symbol in symbols:
                # Exposure = lots * contract size * direction
                direction = 1 if pos.type == mt5.ORDER_TYPE_BUY else -1
                total += pos.volume * direction
        return abs(total)

