    # --- Only run live trading if not in backtest mode and model is valid ---
    try:
        if not BACKTEST_MODE and get_model() is not None:
            print("[LIVE] Starting live trading loop...")
            if not mt5.initialize():
                print(f"[ERROR] MT5 initialization failed. Error code: {mt5.last_error()}")
                raise RuntimeError("MT5 initialization failed")

            # --- Generalized BOS + Pullback Entry Logic for All Symbols ---
            # Note: BOS is computed dynamically in bos_pullback_entry().
            # This map only defines pullback zones and preferred direction.
            BOS_PULLBACK_PARAMS = {
                "GBPUSD.m": {"direction": "auto"},
                "EURUSD.m": {"direction": "auto"},
                "USDJPY.m": {"direction": "auto"},
                "AUDUSD.m": {"direction": "auto"},
                "XAUUSD.m": {"direction": "auto"}
            }

            # Structure state for BOS-based entries (single-entry-per-BOS + reconfirmation)
            BOS_STRUCTURE_STATE = {}

            def bos_pullback_entry(symbol, bos_level=None, pullback_zone=None, direction=None):
                timeframe = mt5.TIMEFRAME_M5
                # Ensure the symbol is resolved / visible in Market Watch for this broker
                try:
                    resolved = resolve_symbol_live(symbol) if 'resolve_symbol_live' in globals() else symbol
                except Exception:
                    resolved = symbol

                if not resolved:
                    print(f"[{symbol} BOS] could not resolve symbol for broker (resolved={resolved}). Ensure symbol is visible in Market Watch.")
                    return

                try:
                    rates = mt5.copy_rates_from_pos(resolved, timeframe, 0, 50)
                except Exception as e:
                    print(f"[{symbol} BOS] mt5.copy_rates_from_pos exception: {e}")
                    rates = None
                # Fallback: try copy_rates_from with current time if copy_rates_from_pos returned nothing
                if (rates is None or len(rates) < 10) and mt5 is not None:
                    try:
                        from datetime import datetime
                        now = datetime.now()
                        rates = mt5.copy_rates_from(resolved, timeframe, now, 50)
                    except Exception as e:
                        print(f"[{symbol} BOS] fallback copy_rates_from exception: {e}")
                        rates = rates or []
                if rates is None or len(rates) < 10:
                    print(f"[{symbol} BOS] no rates or insufficient bars (len={0 if rates is None else len(rates)})")
                    return
                import pandas as pd
                price_data = pd.DataFrame(rates)
                # --- Dynamic BOS (no hard-coded levels) ---
                bos_triggered = False
                new_bos = False
                dyn_bos_level = None
                try:
                    lookback = 40
                    if len(price_data) < lookback + 2:
                        print(f"[{symbol} BOS] insufficient bars for BOS calc (len={len(price_data)})")
                        return

                    prev_close = float(price_data['close'].iloc[-2])
                    last_close = float(price_data['close'].iloc[-1])

                    if direction in (None, "auto"):
                        buy_bos_level = float(price_data['high'].iloc[-(lookback+1):-1].max())
                        sell_bos_level = float(price_data['low'].iloc[-(lookback+1):-1].min())
                        buy_trigger = last_close > buy_bos_level and prev_close <= buy_bos_level
                        sell_trigger = last_close < sell_bos_level and prev_close >= sell_bos_level

                        if buy_trigger and not sell_trigger:
                            direction = "buy"
                            dyn_bos_level = buy_bos_level
                        elif sell_trigger and not buy_trigger:
                            direction = "sell"
                            dyn_bos_level = sell_bos_level
                        elif buy_trigger and sell_trigger:
                            buy_dist = last_close - buy_bos_level
                            sell_dist = sell_bos_level - last_close
                            if buy_dist >= sell_dist:
                                direction = "buy"
                                dyn_bos_level = buy_bos_level
                            else:
                                direction = "sell"
                                dyn_bos_level = sell_bos_level
                        else:
                            print(f"[{symbol} BOS] No BOS trigger for auto direction. Skipping.")
                            return

                    if direction == "buy":
                        dyn_bos_level = float(price_data['high'].iloc[-(lookback+1):-1].max())
                        bos_triggered = last_close > dyn_bos_level
                        new_bos = bos_triggered and prev_close <= dyn_bos_level
                    elif direction == "sell":
                        dyn_bos_level = float(price_data['low'].iloc[-(lookback+1):-1].min())
                        bos_triggered = last_close < dyn_bos_level
                        new_bos = bos_triggered and prev_close >= dyn_bos_level
                except Exception as e:
                    print(f"[{symbol} BOS] error computing dynamic BOS: {e}")
                    return

                # --- Structure lock: single-entry-per-BOS ---
                state = BOS_STRUCTURE_STATE.setdefault(symbol, {
                    "bos_used": False,
                    "last_bos_time": None,
                    "last_bos_level": None,
                    "require_reconfirm": False
                })

                if new_bos:
                    state["bos_used"] = False
                    state["last_bos_time"] = price_data['time'].iloc[-1]
                    state["last_bos_level"] = dyn_bos_level
                    # keep reconfirmation requirement from last trade until satisfied
                    print(f"[{symbol} BOS] New BOS detected at {dyn_bos_level:.5f} (direction={direction})")

                if state.get("bos_used"):
                    print(f"[{symbol} BOS] Structure locked (BOS already used). Waiting for new BOS.")
                    return
                # Dynamic pullback zone if not provided
                if pullback_zone is None:
                    try:
                        pb_lookback = 30
                        if len(price_data) >= pb_lookback + 2:
                            swing_high = float(price_data['high'].iloc[-(pb_lookback+1):-1].max())
                            swing_low = float(price_data['low'].iloc[-(pb_lookback+1):-1].min())
                            rng = swing_high - swing_low
                            if rng > 0:
                                if direction == "buy":
                                    zone_high = swing_high - (0.618 * rng)
                                    zone_low = swing_high - (0.786 * rng)
                                else:  # sell
                                    zone_low = swing_low + (0.618 * rng)
                                    zone_high = swing_low + (0.786 * rng)
                                pullback_zone = (min(zone_low, zone_high), max(zone_low, zone_high))
                                print(f"[{symbol} BOS] Dynamic pullback zone set: {pullback_zone}")
                    except Exception as e:
                        print(f"[{symbol} BOS] Dynamic pullback zone error: {e}")

                # Wait for pullback into zone
                last_close = price_data['close'].iloc[-1]
                # Block trades near recent highs/lows (prevents buying at resistance or selling at support)
                try:
                    recent_high = price_data['high'].iloc[-50:-1].max() if len(price_data) > 50 else price_data['high'].iloc[:-1].max()
                except Exception:
                    recent_high = None
                try:
                    recent_low = price_data['low'].iloc[-50:-1].min() if len(price_data) > 50 else price_data['low'].iloc[:-1].min()
                except Exception:
                    recent_low = None
                if direction == "buy" and recent_high is not None and last_close > recent_high * 0.995:
                    print(f"[{symbol}] Too close to resistance — skipping buy.")
                    return
                if direction == "sell" and recent_low is not None and last_close < recent_low * 1.005:
                    print(f"[{symbol}] Too close to support — skipping sell.")
                    return
                # Require real breakout beyond BOS level
                try:
                    atr_for_breakout = price_data['high'].subtract(price_data['low']).rolling(window=14).mean().iloc[-1]
                except Exception:
                    atr_for_breakout = (price_data['high'] - price_data['low']).mean() if len(price_data) > 0 else None
                if direction == "buy" and dyn_bos_level is not None and atr_for_breakout is not None:
                    if last_close < dyn_bos_level + (atr_for_breakout * 0.2):
                        print(f"[{symbol}] Breakout too small — waiting.")
                        return
                if pullback_zone is None:
                    print(f"[{symbol} BOS] No pullback zone available. Skipping.")
                    return
                in_pullback_zone = pullback_zone[0] <= last_close <= pullback_zone[1]
                print(f"[{symbol} BOS] rates_len={len(rates)}, last_close={last_close}, dyn_bos={dyn_bos_level}, bos_triggered={bos_triggered}, in_pullback_zone={in_pullback_zone}")

                # Impulsive pullback filter (reject impulsive candles)
                try:
                    last_candle = price_data.iloc[-1]
                    avg_range = (price_data['high'] - price_data['low']).rolling(10).mean().iloc[-1]
                    last_range = float(last_candle['high'] - last_candle['low'])
                    if avg_range and last_range > 1.5 * avg_range:
                        print(f"[{symbol} BOS] Impulsive candle detected (range={last_range:.5f} > 1.5x avg {avg_range:.5f}). Skipping.")
                        return
                except Exception as e:
                    print(f"[{symbol} BOS] Impulsive candle check error: {e}")

                # CHoCH proximity guard
                def get_last_higher_low(df, lookback=40):
                    lows = df['low'].values
                    swing_lows = []
                    for i in range(2, len(lows) - 2):
                        if lows[i] < lows[i-1] and lows[i] < lows[i+1]:
                            swing_lows.append((i, lows[i]))
                    if len(swing_lows) < 2:
                        return None
                    for j in range(len(swing_lows) - 1, 0, -1):
                        if swing_lows[j][1] > swing_lows[j-1][1]:
                            return swing_lows[j][1]
                    return swing_lows[-1][1]

                def get_last_lower_high(df, lookback=40):
                    highs = df['high'].values
                    swing_highs = []
                    for i in range(2, len(highs) - 2):
                        if highs[i] > highs[i-1] and highs[i] > highs[i+1]:
                            swing_highs.append((i, highs[i]))
                    if len(swing_highs) < 2:
                        return None
                    for j in range(len(swing_highs) - 1, 0, -1):
                        if swing_highs[j][1] < swing_highs[j-1][1]:
                            return swing_highs[j][1]
                    return swing_highs[-1][1]

                try:
                    atr_guard = (price_data['high'] - price_data['low']).rolling(window=14).mean().iloc[-1]
                    if direction == "buy":
                        last_hl = get_last_higher_low(price_data)
                        if last_hl is not None and last_close <= last_hl + atr_guard * 0.2:
                            print(f"[{symbol} BOS] CHoCH proximity guard: price too close to last HL ({last_hl:.5f}). Skipping.")
                            return
                    elif direction == "sell":
                        last_lh = get_last_lower_high(price_data)
                        if last_lh is not None and last_close >= last_lh - atr_guard * 0.2:
                            print(f"[{symbol} BOS] CHoCH proximity guard: price too close to last LH ({last_lh:.5f}). Skipping.")
                            return
                except Exception as e:
                    print(f"[{symbol} BOS] CHoCH guard error: {e}")

                # Reconfirmation after first buy/sell
                def is_bullish_engulfing(df):
                    if len(df) < 2:
                        return False
                    prev = df.iloc[-2]
                    curr = df.iloc[-1]
                    return (curr['close'] > curr['open'] and prev['close'] < prev['open'] and
                            curr['close'] >= prev['open'] and curr['open'] <= prev['close'])

                def is_bearish_engulfing(df):
                    if len(df) < 2:
                        return False
                    prev = df.iloc[-2]
                    curr = df.iloc[-1]
                    return (curr['close'] < curr['open'] and prev['close'] > prev['open'] and
                            curr['open'] >= prev['close'] and curr['close'] <= prev['open'])

                if state.get("require_reconfirm"):
                    confirmed = is_bullish_engulfing(price_data) if direction == "buy" else is_bearish_engulfing(price_data)
                    if not confirmed:
                        print(f"[{symbol} BOS] Reconfirmation required (no engulfing). Skipping.")
                        return
                    state["require_reconfirm"] = False
                # Spread check
                try:
                    spread = get_spread(resolved) if 'get_spread' in globals() else 0
                    max_spread = get_spread_threshold(resolved) if 'get_spread_threshold' in globals() else SPREAD_THRESHOLD
                    if spread > max_spread:
                        print(f"[{symbol} BOS] Spread too high ({spread} > {max_spread}). Skipping entry.")
                        return
                except Exception as e:
                    print(f"[{symbol} BOS] Spread check error: {e}")
                # HTF trend alignment check
                try:
                    htf = get_htf_trend(resolved, time_frame="H4") if 'get_htf_trend' in globals() else None
                    if htf is not None and not htf_trend_allows_trade(direction, htf):
                        print(f"[{symbol} BOS] HTF ({htf}) blocks trade for direction {direction}. Skipping.")
                        return
                except Exception as e:
                    print(f"[{symbol} BOS] HTF check error: {e}")
                # Only trade if BOS triggered and price in pullback zone
                if bos_triggered and in_pullback_zone:
                    entry_price = last_close
                    # Use ATR-based SL/TP and dynamic lot sizing
                    try:
                        atr = price_data['high'].subtract(price_data['low']).rolling(window=14).mean().iloc[-1]
                    except Exception:
                        atr = (price_data['high'] - price_data['low']).mean()
                    try:
                        acct = mt5.account_info()
                        balance = acct.balance if acct else 1000
                    except Exception:
                        balance = 1000
                    sl, tp, lot = get_trade_params(resolved, entry_price, atr, balance, direction=direction)
                    # Gather enriched sniper context (POI/FVG/M1 data)
                    sniper_ctx_pb = gather_sniper_context(symbol, price_data, direction)
                    
                    allow, score, checklist = sniper_entry_checklist(symbol, direction, price_data, None, {"low":pullback_zone[0], "high":pullback_zone[1]}, sniper_ctx_pb["fvg"], sniper_ctx_pb["low_tf"])
                    if allow:
                        print(f"[{symbol} BOS] Placing {direction} entry at {entry_price} (score={score})")
                        place_sniper_entry(symbol, direction, entry_price, sl, tp, lot, 1, comment=f"{symbol}_BOS", pattern_name="BOS+Pullback", price_data=price_data)
                        # Lock structure after entry + require reconfirmation before next entry
                        state["bos_used"] = True
                        state["require_reconfirm"] = True
                    else:
                        print(f"[{symbol} BOS] Entry blocked by checklist (score={score}). checklist={checklist}")

            # Use the existing main live trading loop instead of the temporary BOS runner

            # --- FIX: Define load_historical_buffer_live if missing ---
            def load_historical_buffer_live(symbol, bars=2000):
                """
                Stub for load_historical_buffer_live.
                Replace with actual implementation to load historical data for live trading.
                """
                import pandas as pd
                # Return an empty DataFrame or raise NotImplementedError if you want to catch missing logic
                return pd.DataFrame()

            run_live_trading_loop()
        else:
            print("[INFO] Skipping live trading (BACKTEST_MODE or model is None).")

    except Exception as e:
        print(f"[ERROR] Exception in live trading loop: {e}")
        import traceback
        traceback.print_exc()
    finally:
        # Save final state and shutdown gracefully
        print("[BOT] Saving final state and shutting down...")
        save_bot_state_to_file()
        if mt5:
            mt5.shutdown()
        print("[BOT] Shutdown complete.")





