def run_one_candle_demo():
    """Run the standalone one-candle confirmation demo (non-intrusive)."""
    try:
        import runpy
        print("[INTEGRATION] Running one_candle_confirmation demo...")
        # Execute the module as a script so its internal demo runs
        runpy.run_path(os.path.join(os.path.dirname(__file__), "one_candle_confirmation.py"), run_name="__main__")
    except Exception as e:
        print(f"[INTEGRATION] Error running one-candle demo: {e}")


def run_one_candle_live(symbol: str, timeframe: str = "M5", bars: int = 200):
    """Fetch live bars and generate a suggested order using the one-candle confirmation logic.

    This function is read-only: it will not place or send any live orders. It prints the suggested order.
    """
    try:
        from one_candle_confirmation import get_live_signal, build_order_from_signal
    except Exception as e:
        print(f"[INTEGRATION] Could not import one_candle_confirmation: {e}")
        return None

    try:
        sig = get_live_signal(symbol, timeframe=timeframe, bars=bars)
        if not sig:
            print(f"[INTEGRATION] No one-candle signal for {symbol} (MT5 may be unavailable or no trigger).")
            return None
        order = build_order_from_signal(symbol, sig, lot=0.01, direction="buy")
        print(f"[INTEGRATION] Suggested order for {symbol}: {order}")
        return order
    except Exception as e:
        print(f"[INTEGRATION] Error generating live one-candle signal for {symbol}: {e}")
        return None


